def _bl_version_string():
    v = bl_info.get("version", (0, 0, 0))
    return f"v{v[0]}.{v[1]}.{v[2]}"


# Re-entrancy guard for auto-update (avoid recursion from generate() bumping properties)
_AUTO_UPDATE_RUNNING = False


def _apply_sv_quality_preset(self, context):
    """Set sv_resolution and sv_complexity based on the quality preset enum."""
    quality_map = {
        'LOW':    (0.5, 0.5),
        'MEDIUM': (1.0, 1.0),
        'HIGH':   (1.7, 1.5),
        'ULTRA':  (2.5, 2.2),
    }
    if hasattr(self, 'sv_quality_preset'):
        res, cpx = quality_map.get(self.sv_quality_preset, (1.0, 1.0))
        self.sv_resolution = res
        self.sv_complexity = cpx


def auto_update_callback(self, context):
    """
    Property update callback — auto-regenerates geometry when properties change
    if `auto_update` is enabled. Skipped during operator execution.

    v2.43 fix: detect "specialty" objects (SurrealRoof, SurrealLib, etc.)
    that were created by direct-bmesh operators rather than GN trees, and
    DO NOT rebuild them as a generic SurrealArch tower — that wipes the
    user's work.
    """
    global _AUTO_UPDATE_RUNNING
    if _AUTO_UPDATE_RUNNING:
        return
    if not getattr(self, "auto_update", False):
        return
    obj = context.active_object
    if not obj or obj.type != 'MESH' or not hasattr(obj, 'surreal_arch_props'):
        return
    # v2.43: skip specialty objects to prevent overwrite-with-tower bug
    n = obj.name
    if n.startswith(("SurrealRoof_", "_lib_", "Terrain_", "SurrealPlan_",
                     "Tree", "_sv_")) or n.endswith(("_World", "_Pieces",
                                                       "_Split", "_Composed",
                                                       "_Stairs", "_baked")):
        return
    # Also skip if the object has any non-SurrealArch heavy modifier indicating
    # it's a post-processed result rather than a base spawn
    has_specialty_mod = any(
        m.name.startswith(("Aest_", "SciFi_", "__SA"))
        or "GothicBuilding" in (m.node_group.name if (m.type == 'NODES' and m.node_group) else "")
        for m in obj.modifiers
    )
    if has_specialty_mod:
        return
    try:
        _AUTO_UPDATE_RUNNING = True
        bpy.ops.surreal_arch.generate()
    except Exception:
        pass
    finally:
        _AUTO_UPDATE_RUNNING = False


def roof_update_callback(self, context):
    """v2.43: Dedicated update callback for roof_* props.
    Only rebuilds the curved roof on objects that ARE roofs (SurrealRoof_*).
    Falls through silently for any other object so changing roof sliders
    doesn't wipe towers, walls, or other base architecture."""
    global _AUTO_UPDATE_RUNNING
    if _AUTO_UPDATE_RUNNING:
        return
    if not getattr(self, "auto_update", False):
        return
    obj = context.active_object
    if not obj or obj.type != 'MESH':
        return
    if not obj.name.startswith("SurrealRoof_"):
        # User is editing roof sliders on a non-roof object — wait until
        # they explicitly click 🏠 Build Roof.
        return
    try:
        _AUTO_UPDATE_RUNNING = True
        _build_curved_roof(obj, self)
        _add_roof_modifier_stack(obj, self)
    except Exception as e:
        print(f"[SurrealArch] roof live-update failed: {e}")
    finally:
        _AUTO_UPDATE_RUNNING = False


