def sync_water_drivers(material, obj):
    """Wire water material's harmonic Value nodes to obj.surreal_arch_props."""
    nt = material.node_tree
    for n in nt.nodes:
        if n.type == 'VALUE' and n.label == "Harmonic A":
            n.outputs[0].driver_remove("default_value")
            fc = n.outputs[0].driver_add("default_value")
            fc.driver.expression = "var * 8 * tempo"
            v = fc.driver.variables.new(); v.name = "var"
            v.targets[0].id_type = 'OBJECT'; v.targets[0].id = obj
            v.targets[0].data_path = 'surreal_arch_props.musical_freq_a'
            v2 = fc.driver.variables.new(); v2.name = "tempo"
            v2.targets[0].id_type = 'OBJECT'; v2.targets[0].id = obj
            v2.targets[0].data_path = 'surreal_arch_props.tempo_factor'
        elif n.type == 'VALUE' and n.label == "Harmonic B":
            n.outputs[0].driver_remove("default_value")
            fc = n.outputs[0].driver_add("default_value")
            fc.driver.expression = "var * 8 * tempo"
            v = fc.driver.variables.new(); v.name = "var"
            v.targets[0].id_type = 'OBJECT'; v.targets[0].id = obj
            v.targets[0].data_path = 'surreal_arch_props.musical_freq_b'
            v2 = fc.driver.variables.new(); v2.name = "tempo"
            v2.targets[0].id_type = 'OBJECT'; v2.targets[0].id = obj
            v2.targets[0].data_path = 'surreal_arch_props.tempo_factor'


def sync_world_drivers(world, obj):
    """Wire world's Night Blend value to obj.surreal_arch_props.night_blend."""
    nt = world.node_tree
    for n in nt.nodes:
        if n.type == 'VALUE' and n.label == "Night Blend":
            n.outputs[0].driver_remove("default_value")
            fc = n.outputs[0].driver_add("default_value")
            fc.driver.expression = "var"
            v = fc.driver.variables.new(); v.name = "var"
            v.targets[0].id_type = 'OBJECT'; v.targets[0].id = obj
            v.targets[0].data_path = 'surreal_arch_props.night_blend'
        if n.type == 'TEX_SKY':
            try:
                fc = n.driver_add("sun_elevation")
                fc.driver.expression = "(tod / 24.0) * 3.14159 - 1.57"  # 0h=-π/2, 12h=π/2
                v = fc.driver.variables.new(); v.name = "tod"
                v.targets[0].id_type = 'OBJECT'; v.targets[0].id = obj
                v.targets[0].data_path = 'surreal_arch_props.time_of_day'
            except Exception:
                pass
            try:
                fc = n.driver_add("sun_rotation")
                fc.driver.expression = "(tod / 24.0) * 6.28318"  # full rotation per day
                v = fc.driver.variables.new(); v.name = "tod"
                v.targets[0].id_type = 'OBJECT'; v.targets[0].id = obj
                v.targets[0].data_path = 'surreal_arch_props.time_of_day'
            except Exception:
                pass


