# ----------------------------------------------------------------------
# UTILITY: NODE COLORING
# ----------------------------------------------------------------------

def color_node(node, key):
    if key in COLORS:
        node.use_custom_color = True
        node.color = COLORS[key]


# ----------------------------------------------------------------------
# REUSABLE BUILDER HELPERS
# ----------------------------------------------------------------------

def add_taper_chain(tree, in_geom, height, taper, x=0, y=-300):
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, y); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x+200, y)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    map_range = tree.nodes.new('ShaderNodeMapRange'); map_range.location = (x+400, y)
    map_range.inputs['From Min'].default_value = -height/2
    map_range.inputs['From Max'].default_value =  height/2
    map_range.inputs['To Min'].default_value   =  1.0
    map_range.inputs['To Max'].default_value   =  max(0.05, 1.0 - taper)
    tree.links.new(sep.outputs['Z'], map_range.inputs['Value'])
    color_node(map_range, "tower")

    combine = tree.nodes.new('ShaderNodeCombineXYZ'); combine.location = (x+600, y)
    tree.links.new(map_range.outputs['Result'], combine.inputs['X'])
    tree.links.new(map_range.outputs['Result'], combine.inputs['Y'])
    combine.inputs['Z'].default_value = 1.0

    mul = tree.nodes.new('ShaderNodeVectorMath'); mul.location = (x+800, y+100); mul.operation = 'MULTIPLY'
    tree.links.new(pos.outputs['Position'], mul.inputs[0])
    tree.links.new(combine.outputs['Vector'], mul.inputs[1])

    sub = tree.nodes.new('ShaderNodeVectorMath'); sub.location = (x+1000, y+100); sub.operation = 'SUBTRACT'
    tree.links.new(mul.outputs['Vector'], sub.inputs[0])
    tree.links.new(pos.outputs['Position'], sub.inputs[1])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+1200, 0); color_node(set_pos, "deform")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(sub.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


def add_noise_displace(tree, in_geom, scale, detail, strength, seed, x=0, y=300):
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, y); color_node(pos, "input")
    noise = tree.nodes.new('ShaderNodeTexNoise'); noise.location = (x+200, y)
    noise.noise_dimensions = '4D'
    noise.inputs['W'].default_value = float(seed) * 0.1
    noise.inputs['Scale'].default_value = scale
    noise.inputs['Detail'].default_value = detail
    noise.inputs['Roughness'].default_value = 0.55
    noise.inputs['Distortion'].default_value = 0.4
    tree.links.new(pos.outputs['Position'], noise.inputs['Vector'])
    color_node(noise, "noise")

    center = tree.nodes.new('ShaderNodeVectorMath'); center.location = (x+450, y); center.operation = 'SUBTRACT'
    center.inputs[1].default_value = (0.5, 0.5, 0.5)
    tree.links.new(noise.outputs['Color'], center.inputs[0])

    sc = tree.nodes.new('ShaderNodeVectorMath'); sc.location = (x+650, y); sc.operation = 'SCALE'
    sc.inputs['Scale'].default_value = strength
    tree.links.new(center.outputs['Vector'], sc.inputs[0])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+850, 0); color_node(set_pos, "deform")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(sc.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


def add_wave_bulge(tree, in_geom, frequency, flow, bulge, x=0, y=300):
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, y); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x+200, y)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    z_freq = tree.nodes.new('ShaderNodeMath'); z_freq.location = (x+400, y); z_freq.operation = 'MULTIPLY'
    z_freq.inputs[1].default_value = frequency
    tree.links.new(sep.outputs['Z'], z_freq.inputs[0])

    sine = tree.nodes.new('ShaderNodeMath'); sine.location = (x+600, y); sine.operation = 'SINE'
    tree.links.new(z_freq.outputs['Value'], sine.inputs[0])
    color_node(sine, "organic")

    flow_mult = tree.nodes.new('ShaderNodeMath'); flow_mult.location = (x+800, y); flow_mult.operation = 'MULTIPLY'
    flow_mult.inputs[1].default_value = flow + bulge
    tree.links.new(sine.outputs['Value'], flow_mult.inputs[0])

    bvec = tree.nodes.new('ShaderNodeCombineXYZ'); bvec.location = (x+1000, y)
    tree.links.new(flow_mult.outputs['Value'], bvec.inputs['X'])
    tree.links.new(flow_mult.outputs['Value'], bvec.inputs['Y'])
    bvec.inputs['Z'].default_value = 0.0

    pos_xy = tree.nodes.new('ShaderNodeCombineXYZ'); pos_xy.location = (x+600, y-200)
    tree.links.new(sep.outputs['X'], pos_xy.inputs['X'])
    tree.links.new(sep.outputs['Y'], pos_xy.inputs['Y'])
    pos_xy.inputs['Z'].default_value = 0.0

    apply_b = tree.nodes.new('ShaderNodeVectorMath'); apply_b.location = (x+1200, y-100); apply_b.operation = 'MULTIPLY'
    tree.links.new(pos_xy.outputs['Vector'], apply_b.inputs[0])
    tree.links.new(bvec.outputs['Vector'], apply_b.inputs[1])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+1400, 0); color_node(set_pos, "deform")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(apply_b.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


def add_twist(tree, in_geom, twist_angle, height, x=0, y=300):
    if abs(twist_angle) < 0.001:
        return in_geom

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, y); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x+200, y)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    map_range = tree.nodes.new('ShaderNodeMapRange'); map_range.location = (x+400, y)
    map_range.inputs['From Min'].default_value = -height/2
    map_range.inputs['From Max'].default_value =  height/2
    map_range.inputs['To Min'].default_value   = 0.0
    map_range.inputs['To Max'].default_value   = twist_angle
    tree.links.new(sep.outputs['Z'], map_range.inputs['Value'])

    rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (x+600, y)
    rvec.inputs['X'].default_value = 0.0
    rvec.inputs['Y'].default_value = 0.0
    tree.links.new(map_range.outputs['Result'], rvec.inputs['Z'])

    rotate = tree.nodes.new('ShaderNodeVectorRotate'); rotate.location = (x+800, y)
    rotate.rotation_type = 'EULER_XYZ'
    tree.links.new(pos.outputs['Position'], rotate.inputs['Vector'])
    tree.links.new(rvec.outputs['Vector'], rotate.inputs['Rotation'])
    color_node(rotate, "organic")

    sub = tree.nodes.new('ShaderNodeVectorMath'); sub.location = (x+1000, y); sub.operation = 'SUBTRACT'
    tree.links.new(rotate.outputs['Vector'], sub.inputs[0])
    tree.links.new(pos.outputs['Position'], sub.inputs[1])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+1200, 0); color_node(set_pos, "deform")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(sub.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


# ----------------------------------------------------------------------
# WHIMSY: musical/harmonic modulation helpers
# ----------------------------------------------------------------------

def make_harmonic_value(tree, index_socket, freq_a, freq_b, layers, x, y):
    """
    Compose layered sine waves driven by point index → musical/harmonic factor.
    Returns a Math output socket (value in roughly [-2..2]).
    """
    # Layer 1
    m1 = tree.nodes.new('ShaderNodeMath'); m1.location = (x, y); m1.operation = 'MULTIPLY'
    m1.inputs[1].default_value = freq_a
    tree.links.new(index_socket, m1.inputs[0])
    s1 = tree.nodes.new('ShaderNodeMath'); s1.location = (x+200, y); s1.operation = 'SINE'
    tree.links.new(m1.outputs['Value'], s1.inputs[0])
    color_node(s1, "ornament")

    if layers <= 1:
        return s1.outputs['Value']

    # Layer 2
    m2 = tree.nodes.new('ShaderNodeMath'); m2.location = (x, y-200); m2.operation = 'MULTIPLY'
    m2.inputs[1].default_value = freq_b
    tree.links.new(index_socket, m2.inputs[0])
    s2 = tree.nodes.new('ShaderNodeMath'); s2.location = (x+200, y-200); s2.operation = 'SINE'
    tree.links.new(m2.outputs['Value'], s2.inputs[0])
    color_node(s2, "ornament")

    add = tree.nodes.new('ShaderNodeMath'); add.location = (x+400, y-100); add.operation = 'ADD'
    tree.links.new(s1.outputs['Value'], add.inputs[0])
    tree.links.new(s2.outputs['Value'], add.inputs[1])

    if layers <= 2:
        return add.outputs['Value']

    # Layer 3 (octave-up of A)
    m3 = tree.nodes.new('ShaderNodeMath'); m3.location = (x, y-400); m3.operation = 'MULTIPLY'
    m3.inputs[1].default_value = freq_a * 2.0
    tree.links.new(index_socket, m3.inputs[0])
    s3 = tree.nodes.new('ShaderNodeMath'); s3.location = (x+200, y-400); s3.operation = 'SINE'
    tree.links.new(m3.outputs['Value'], s3.inputs[0])
    color_node(s3, "ornament")
    add2 = tree.nodes.new('ShaderNodeMath'); add2.location = (x+400, y-300); add2.operation = 'ADD'
    tree.links.new(add.outputs['Value'], add2.inputs[0])
    tree.links.new(s3.outputs['Value'], add2.inputs[1])
    final = add2

    # Optional layers 4 & 5
    for i, fmul in enumerate([3.0, 5.0][:layers-3], start=4):
        mn = tree.nodes.new('ShaderNodeMath'); mn.location = (x, y-200*i-200); mn.operation = 'MULTIPLY'
        mn.inputs[1].default_value = freq_b * fmul / 3.0
        tree.links.new(index_socket, mn.inputs[0])
        sn = tree.nodes.new('ShaderNodeMath'); sn.location = (x+200, y-200*i-200); sn.operation = 'SINE'
        tree.links.new(mn.outputs['Value'], sn.inputs[0])
        addn = tree.nodes.new('ShaderNodeMath'); addn.location = (x+400, y-200*i-100); addn.operation = 'ADD'
        tree.links.new(final.outputs['Value'], addn.inputs[0])
        tree.links.new(sn.outputs['Value'], addn.inputs[1])
        final = addn

    return final.outputs['Value']


# ----------------------------------------------------------------------
# BUILDERS — TOWER / ORGANIC / HYBRID (existing)
# ----------------------------------------------------------------------

def build_tower(tree, props, base_x=-1400):
    cyl = tree.nodes.new('GeometryNodeMeshCylinder')
    cyl.location = (base_x, 0); color_node(cyl, "tower")
    cyl.inputs['Vertices'].default_value      = max(8, props.complexity_level * 8)
    cyl.inputs['Side Segments'].default_value = max(2, props.recursion_depth * 4)
    cyl.inputs['Fill Segments'].default_value = 1
    cyl.inputs['Radius'].default_value        = props.base_radius
    cyl.inputs['Depth'].default_value         = props.height

    geom = cyl.outputs['Mesh']
    geom = add_taper_chain(tree, geom, props.height, props.taper_ratio, x=base_x+300, y=-400)
    geom = add_twist(tree, geom, props.twist_angle, props.height, x=base_x+1600, y=-400)
    strength = props.variation_intensity * 0.5 + props.symmetry_break * 0.3
    geom = add_noise_displace(
        tree, geom,
        scale=1.5 + props.complexity_level * 0.5,
        detail=float(props.complexity_level),
        strength=strength,
        seed=props.seed,
        x=base_x+2900, y=400,
    )
    return geom


def build_organic(tree, props, base_x=-1400):
    sphere = tree.nodes.new('GeometryNodeMeshUVSphere')
    sphere.location = (base_x, 0); color_node(sphere, "organic")
    sphere.inputs['Segments'].default_value = max(16, props.complexity_level * 8)
    sphere.inputs['Rings'].default_value    = max(8,  props.complexity_level * 4)
    sphere.inputs['Radius'].default_value   = props.base_radius

    geom = sphere.outputs['Mesh']

    # Stretch sphere to height
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (base_x+300, -400); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (base_x+500, -400)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])
    z_str = tree.nodes.new('ShaderNodeMath'); z_str.location = (base_x+700, -400); z_str.operation = 'MULTIPLY'
    z_str.inputs[1].default_value = props.height / max(0.1, props.base_radius * 2)
    tree.links.new(sep.outputs['Z'], z_str.inputs[0])
    new_pos = tree.nodes.new('ShaderNodeCombineXYZ'); new_pos.location = (base_x+900, -400)
    tree.links.new(sep.outputs['X'], new_pos.inputs['X'])
    tree.links.new(sep.outputs['Y'], new_pos.inputs['Y'])
    tree.links.new(z_str.outputs['Value'], new_pos.inputs['Z'])
    delta = tree.nodes.new('ShaderNodeVectorMath'); delta.location = (base_x+1100, -400); delta.operation = 'SUBTRACT'
    tree.links.new(new_pos.outputs['Vector'], delta.inputs[0])
    tree.links.new(pos.outputs['Position'], delta.inputs[1])
    set_str = tree.nodes.new('GeometryNodeSetPosition'); set_str.location = (base_x+1300, 0); color_node(set_str, "deform")
    tree.links.new(geom, set_str.inputs['Geometry'])
    tree.links.new(delta.outputs['Vector'], set_str.inputs['Offset'])
    geom = set_str.outputs['Geometry']

    geom = add_wave_bulge(tree, geom, props.wave_frequency, props.flow_amount, props.bulge_amount, x=base_x+1600, y=400)
    geom = add_twist(tree, geom, props.twist_angle, props.height, x=base_x+3100, y=400)
    strength = props.flow_amount * 0.3 + props.variation_intensity * 0.2
    geom = add_noise_displace(tree, geom, scale=2.0, detail=3.0, strength=strength, seed=props.seed,
                              x=base_x+4400, y=400)
    return geom


def build_hybrid(tree, props):
    tower_geom   = build_tower(tree, props, base_x=-2400)
    organic_geom = build_organic(tree, props, base_x=2200)

    join = tree.nodes.new('GeometryNodeJoinGeometry')
    join.location = (5800, 0); color_node(join, "output")
    tree.links.new(tower_geom,   join.inputs['Geometry'])
    tree.links.new(organic_geom, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: RAILING
# ----------------------------------------------------------------------

def build_railing(tree, props, x_offset=0, y_offset=0, length=None, height=None):
    """AAA railing — curve-swept balusters + proper horizontal rails aligned to piece.

    v2.49 overhaul:
    • Balusters are vertical CurvePrimitiveLine segments swept with a decorative
      profile (round / ogee / fluted) — no more MeshCube / MeshCylinder instances.
    • Top and bottom rails are horizontal CurvePrimitiveLine segments swept with
      a slightly larger matching profile — seamless cap geometry, no floating cubes.
    • Balusters start at z=0 (piece floor), top rail sits at z=H — zero Z-gap.
    • Harmonic height modulation kept for musical whimsy.
    """
    L  = length if length is not None else props.rail_length
    H  = height if height is not None else props.rail_height
    br = getattr(props, 'rail_baluster_radius', 0.04)
    ts = getattr(props, 'rail_top_size',        0.07)
    n  = max(2, getattr(props, 'rail_baluster_count', 8))
    bx = -1400 + x_offset
    spacing = L / max(1, n - 1)
    parts   = []

    # ── Shared baluster profile (picked from props.aest_profile) ──────────
    bal_prof = _make_circle_profile(tree, br, resolution=10,
                                    loc=(bx - 300, -300), props=props)
    if bal_prof is None:
        # Fallback: plain circle
        bal_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (bx - 300, -300))
        if bal_prof:
            try:
                bal_prof.inputs['Resolution'].default_value = 10
                bal_prof.inputs['Radius'].default_value     = br
            except Exception:
                pass

    # ── Rail profile (slightly larger, always round for clean cap) ────────
    rail_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (bx - 300, -600))
    if rail_prof:
        try:
            rail_prof.inputs['Resolution'].default_value = 10
            rail_prof.inputs['Radius'].default_value     = ts * 0.55
        except Exception:
            pass
    color_node(rail_prof, "railing") if rail_prof else None

    # ── Individual swept balusters ─────────────────────────────────────────
    # Use InstanceOnPoints so baluster count is a real parameter.
    # Each baluster: vertical CurvePrimitiveLine from (x, 0, 0) to (x, 0, H),
    # assembled as a single instance and placed along a point line.
    bal_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (bx, 0))
    if bal_line:
        try:
            bal_line.inputs['Start'].default_value = (0, 0, 0)
            bal_line.inputs['End'].default_value   = (0, 0, H)
        except Exception:
            pass
        color_node(bal_line, "railing")

    if bal_line and bal_prof:
        bal_sweep = _safe_node(tree, 'GeometryNodeCurveToMesh', (bx + 250, 0))
        if bal_sweep:
            _link(tree, bal_line.outputs['Curve'], bal_sweep.inputs['Curve'])
            _link(tree, bal_prof.outputs['Curve'], bal_sweep.inputs['Profile Curve'])
            try: bal_sweep.inputs['Fill Caps'].default_value = True
            except Exception: pass
            color_node(bal_sweep, "railing")
            bal_geom_out = bal_sweep.outputs['Mesh']
        else:
            bal_geom_out = None
    else:
        bal_geom_out = None

    # Point distribution along the railing length
    pt_line = _safe_node(tree, 'GeometryNodeMeshLine', (bx, 400))
    if pt_line:
        try:
            pt_line.mode = 'END_POINTS'
            pt_line.inputs['Count'].default_value          = n
            pt_line.inputs['Start Location'].default_value = (-L / 2, 0, 0)
            pt_line.inputs['Offset'].default_value         = (L, 0, 0)
        except Exception:
            pass
        color_node(pt_line, "railing")

    if pt_line and bal_geom_out is not None:
        iop = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (bx + 500, 300))
        if iop:
            _link(tree, pt_line.outputs['Mesh'], iop.inputs['Points'])
            _link(tree, bal_geom_out, iop.inputs['Instance'])
            color_node(iop, "railing")

            # Musical height modulation — scale Z per baluster
            idx = _safe_node(tree, 'GeometryNodeInputIndex', (bx, -300))
            if idx:
                try:
                    harmonic = make_harmonic_value(
                        tree, idx.outputs['Index'],
                        props.musical_freq_a, props.musical_freq_b,
                        props.harmonic_layers, bx + 200, -300)
                    mpr = _safe_node(tree, 'ShaderNodeMapRange', (bx + 900, -300))
                    if mpr:
                        try:
                            mpr.inputs['From Min'].default_value = -2.0
                            mpr.inputs['From Max'].default_value  =  2.0
                            mpr.inputs['To Min'].default_value    =  1.0 - props.ornament_density * 0.35
                            mpr.inputs['To Max'].default_value    =  1.0 + props.ornament_density * 0.35
                        except Exception: pass
                        _link(tree, harmonic, mpr.inputs['Value'])
                        svec = _safe_node(tree, 'ShaderNodeCombineXYZ', (bx + 1100, -300))
                        if svec:
                            try:
                                svec.inputs['X'].default_value = 1.0
                                svec.inputs['Y'].default_value = 1.0
                            except Exception: pass
                            _link(tree, mpr.outputs['Result'], svec.inputs['Z'])
                            si = _safe_node(tree, 'GeometryNodeScaleInstances', (bx + 1300, 300))
                            if si:
                                _link(tree, iop.outputs['Instances'], si.inputs['Instances'])
                                _link(tree, svec.outputs['Vector'],   si.inputs['Scale'])
                                iop_out = si.outputs['Instances']
                            else:
                                iop_out = iop.outputs['Instances']
                        else:
                            iop_out = iop.outputs['Instances']
                except Exception:
                    iop_out = iop.outputs['Instances']
            else:
                iop_out = iop.outputs['Instances']

            rea = _safe_node(tree, 'GeometryNodeRealizeInstances', (bx + 1600, 300))
            if rea:
                _link(tree, iop_out, rea.inputs['Geometry'])
                parts.append(rea.outputs['Geometry'])

    # ── Top rail — horizontal sweep ────────────────────────────────────────
    top_curve = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (bx, 700))
    if top_curve:
        try:
            top_curve.inputs['Start'].default_value = (-L / 2, 0, H)
            top_curve.inputs['End'].default_value   = ( L / 2, 0, H)
        except Exception:
            pass
        color_node(top_curve, "railing")
        if rail_prof:
            top_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (bx + 250, 700))
            if top_sw:
                _link(tree, top_curve.outputs['Curve'], top_sw.inputs['Curve'])
                _link(tree, rail_prof.outputs['Curve'], top_sw.inputs['Profile Curve'])
                try: top_sw.inputs['Fill Caps'].default_value = True
                except Exception: pass
                color_node(top_sw, "railing")
                parts.append(top_sw.outputs['Mesh'])

    # ── Bottom rail — horizontal sweep ────────────────────────────────────
    bot_curve = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (bx, 900))
    if bot_curve:
        try:
            bot_curve.inputs['Start'].default_value = (-L / 2, 0, ts * 0.5)
            bot_curve.inputs['End'].default_value   = ( L / 2, 0, ts * 0.5)
        except Exception:
            pass
        color_node(bot_curve, "railing")
        if rail_prof:
            bot_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (bx + 250, 900))
            if bot_sw:
                _link(tree, bot_curve.outputs['Curve'], bot_sw.inputs['Curve'])
                _link(tree, rail_prof.outputs['Curve'], bot_sw.inputs['Profile Curve'])
                try: bot_sw.inputs['Fill Caps'].default_value = True
                except Exception: pass
                color_node(bot_sw, "railing")
                parts.append(bot_sw.outputs['Mesh'])

    # ── Mid rail (optional decorative) at 40% height ──────────────────────
    if n > 4:
        mid_curve = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (bx, 1100))
        if mid_curve:
            try:
                mid_curve.inputs['Start'].default_value = (-L / 2, 0, H * 0.4)
                mid_curve.inputs['End'].default_value   = ( L / 2, 0, H * 0.4)
            except Exception:
                pass
            color_node(mid_curve, "railing")
            if rail_prof:
                mid_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (bx + 250, 1100))
                if mid_sw:
                    _link(tree, mid_curve.outputs['Curve'], mid_sw.inputs['Curve'])
                    _link(tree, rail_prof.outputs['Curve'], mid_sw.inputs['Profile Curve'])
                    try: mid_sw.inputs['Fill Caps'].default_value = True
                    except Exception: pass
                    color_node(mid_sw, "railing")
                    parts.append(mid_sw.outputs['Mesh'])

    # ── Join all parts ─────────────────────────────────────────────────────
    if not parts:
        return None
    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (bx + 2000, 0))
    if join is None:
        return parts[0] if parts else None
    for p in parts:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    geom = join.outputs['Geometry']

    # Optional Z offset for alignment to parent piece surface
    if y_offset != 0:
        off_t = _safe_node(tree, 'GeometryNodeTransform', (bx + 2200, 0))
        if off_t:
            try: off_t.inputs['Translation'].default_value = (0, 0, y_offset)
            except Exception: pass
            _link(tree, geom, off_t.inputs['Geometry'])
            geom = off_t.outputs['Geometry']

    return geom


def build_curved_wall(tree, props, base_x=-1400):
    """Curved wall segment — a horizontal bezier arc swept with a rectangle profile.

    v2.49 new function:
    Produces a proper curved wall section (1/4 to full circle arc) with:
    • Bezier arc spine (arc angle controlled by props.wall_arc_angle)
    • Rectangular cross-section sweep (wall thickness × wall height)
    • Optional crenellations on top (reuses crenel props)
    • Returns geometry socket for joining into any building
    """
    import math
    arc_deg  = getattr(props, 'wall_arc_angle',    90.0)
    thickness= getattr(props, 'wall_thickness',     0.4)
    h        = getattr(props, 'wall_height',        3.0)
    radius   = getattr(props, 'wall_arc_radius',    5.0)
    crenels  = getattr(props, 'crenel_merlon_count', 8)
    parts    = []

    arc_rad  = math.radians(arc_deg)
    half_ang = arc_rad / 2.0

    # ── Arc spine as a BezierSegment ─────────────────────────────────────
    # Start: (cos(-half_ang)*radius, sin(-half_ang)*radius, 0)
    # End:   (cos( half_ang)*radius, sin( half_ang)*radius, 0)
    # Cubic bezier approximation of a circular arc:
    #   tangent length ≈ (4/3)*tan(arc/4)*radius
    tan_len = (4.0 / 3.0) * math.tan(arc_rad / 4.0) * radius

    sx = math.cos(-half_ang) * radius
    sy = math.sin(-half_ang) * radius
    ex = math.cos( half_ang) * radius
    ey = math.sin( half_ang) * radius
    # Tangent directions: perpendicular to radius at start/end
    stx = -math.sin(-half_ang) * tan_len
    sty =  math.cos(-half_ang) * tan_len
    etx = -math.sin( half_ang) * tan_len
    ety =  math.cos( half_ang) * tan_len

    spine = _safe_node(tree, 'GeometryNodeCurvePrimitiveBezierSegment', (base_x, 0))
    if spine:
        try:
            spine.inputs['Resolution'].default_value  = 32
            spine.inputs['Start'].default_value       = (sx, sy, 0)
            spine.inputs['Start Handle'].default_value= (sx + stx, sy + sty, 0)
            spine.inputs['End Handle'].default_value  = (ex - etx, ey - ety, 0)
            spine.inputs['End'].default_value         = (ex, ey, 0)
        except Exception:
            pass
        color_node(spine, "wall")

    # ── Rectangular cross-section profile (width=thickness, height=wall_h) ─
    rect_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveQuadrilateral', (base_x - 300, -200))
    if rect_prof:
        try:
            rect_prof.mode = 'RECTANGLE'
            rect_prof.inputs['Width'].default_value  = thickness
            rect_prof.inputs['Height'].default_value = h
        except Exception:
            rect_prof = None

    if spine and rect_prof:
        wall_sweep = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 300, 0))
        if wall_sweep:
            _link(tree, spine.outputs['Curve'], wall_sweep.inputs['Curve'])
            _link(tree, rect_prof.outputs['Curve'], wall_sweep.inputs['Profile Curve'])
            try: wall_sweep.inputs['Fill Caps'].default_value = True
            except Exception: pass
            color_node(wall_sweep, "wall")
            parts.append(wall_sweep.outputs['Mesh'])

    # ── Optional crenellations on top ─────────────────────────────────────
    if crenels > 0 and spine:
        # Resample arc to N merlon positions
        resample = _safe_node(tree, 'GeometryNodeResampleCurve', (base_x + 300, -400))
        if resample:
            try:
                resample.mode = 'COUNT'
            except Exception:
                try: resample.inputs['Mode'].default_value = 'Count'
                except Exception: pass
            try: resample.inputs['Count'].default_value = crenels * 2 + 1
            except Exception: pass
            _link(tree, spine.outputs['Curve'], resample.inputs['Curve'])
            color_node(resample, "ornament")

            crv_to_pts = _safe_node(tree, 'GeometryNodeCurveToPoints', (base_x + 500, -400))
            if crv_to_pts:
                try:
                    crv_to_pts.mode = 'EVALUATED'
                except Exception: pass
                _link(tree, resample.outputs['Curve'], crv_to_pts.inputs['Curve'])
                color_node(crv_to_pts, "ornament")

                merlon = _safe_node(tree, 'GeometryNodeMeshCube', (base_x - 200, -600))
                if merlon:
                    merlon.inputs['Size'].default_value = (thickness * 1.2,
                                                           thickness * 1.2,
                                                           h * 0.18)
                    color_node(merlon, "ornament")

                    iop = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (base_x + 700, -400))
                    if iop:
                        _link(tree, crv_to_pts.outputs['Points'], iop.inputs['Points'])
                        _link(tree, merlon.outputs['Mesh'], iop.inputs['Instance'])
                        _link(tree, crv_to_pts.outputs['Rotation'], iop.inputs['Rotation'])

                        tr_up = _safe_node(tree, 'GeometryNodeTranslateInstances',
                                           (base_x + 900, -400))
                        if tr_up:
                            try: tr_up.inputs['Translation'].default_value = (0, 0, h * 0.5 + h * 0.09)
                            except Exception: pass
                            _link(tree, iop.outputs['Instances'], tr_up.inputs['Instances'])
                            rea = _safe_node(tree, 'GeometryNodeRealizeInstances',
                                             (base_x + 1100, -400))
                            if rea:
                                _link(tree, tr_up.outputs['Instances'], rea.inputs['Geometry'])
                                parts.append(rea.outputs['Geometry'])

    # ── Join ───────────────────────────────────────────────────────────────
    if not parts:
        return None
    if len(parts) == 1:
        return parts[0]
    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 1400, 0))
    if join:
        for p in parts:
            _link(tree, p, join.inputs['Geometry'])
        color_node(join, "output")
        return join.outputs['Geometry']
    return parts[0]


# ======================================================================
# GREYBOX / LEVEL-DESIGN LIBRARY  (v2.49)
# Parametric blockout pieces for rapid AAA level prototyping.
# Every piece is built from clean boxes + boolean cuts so it imports into
# Unreal / Unity as game-ready greybox geometry. All parametric.
# ======================================================================

def _gb_box(tree, size, loc_xyz, x, y, label="level"):
    """Helper: a MeshCube of `size`=(sx,sy,sz) translated to `loc_xyz`.
    Returns the translated geometry socket."""
    cube = _safe_node(tree, 'GeometryNodeMeshCube', (x, y))
    if cube is None:
        return None
    try:
        cube.inputs['Size'].default_value = size
    except Exception:
        pass
    color_node(cube, label)
    tr = _safe_node(tree, 'GeometryNodeTransform', (x + 200, y))
    if tr is None:
        return cube.outputs['Mesh']
    try:
        tr.inputs['Translation'].default_value = loc_xyz
    except Exception:
        pass
    _link(tree, cube.outputs['Mesh'], tr.inputs['Geometry'])
    color_node(tr, label)
    return tr.outputs['Geometry']


def _gb_box_node(tree, size, loc_xyz, rot_xyz, x, y, label="level"):
    """Helper: a MeshCube with translation AND rotation. Returns geom socket."""
    cube = _safe_node(tree, 'GeometryNodeMeshCube', (x, y))
    if cube is None:
        return None
    try:
        cube.inputs['Size'].default_value = size
    except Exception:
        pass
    color_node(cube, label)
    tr = _safe_node(tree, 'GeometryNodeTransform', (x + 200, y))
    if tr is None:
        return cube.outputs['Mesh']
    try:
        tr.inputs['Translation'].default_value = loc_xyz
        tr.inputs['Rotation'].default_value = rot_xyz
    except Exception:
        pass
    _link(tree, cube.outputs['Mesh'], tr.inputs['Geometry'])
    color_node(tr, label)
    return tr.outputs['Geometry']


def _gb_join(tree, parts, x, y=0, label="output"):
    """Join a list of geometry sockets. Returns a single socket (or None)."""
    parts = [p for p in parts if p is not None]
    if not parts:
        return None
    if len(parts) == 1:
        return parts[0]
    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (x, y))
    if join is None:
        return parts[0]
    for p in parts:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, label)
    return join.outputs['Geometry']


def _gb_bool_diff(tree, base_geom, cutters, x, y=0):
    """Boolean DIFFERENCE: base_geom minus the list of cutter sockets.
    Falls back to returning base_geom if the boolean node is unavailable."""
    cutters = [c for c in cutters if c is not None]
    if base_geom is None or not cutters:
        return base_geom
    boolean = _safe_node(tree, 'GeometryNodeMeshBoolean', (x, y))
    if boolean is None:
        return base_geom
    try:
        boolean.operation = 'DIFFERENCE'
    except Exception:
        pass
    # In 5.1, DIFFERENCE has 'Mesh 1' (single) + 'Mesh 2' (multi)
    linked = False
    try:
        _link(tree, base_geom, boolean.inputs['Mesh 1'])
        for c in cutters:
            _link(tree, c, boolean.inputs['Mesh 2'])
        linked = True
    except Exception:
        linked = False
    if not linked:
        # Fallback: some builds expose a single 'Mesh' multi-input
        try:
            _link(tree, base_geom, boolean.inputs['Mesh'])
            for c in cutters:
                _link(tree, c, boolean.inputs['Mesh'])
        except Exception:
            return base_geom
    color_node(boolean, "level")
    try:
        return boolean.outputs['Mesh']
    except Exception:
        return base_geom


def _gb_trim_mode(props):
    return getattr(props, 'gb_trim_mode', 'RECESS')


def _gb_trim_depth(props, wall_t):
    return max(0.005, getattr(props, 'gb_trim_recess', 0.04))


def _gb_doorway_frame_trim(tree, props, base_x, dw, dh, t, node_y=0):
    """Lintels/jambs with recess or offset — never coplanar with uncut wall face."""
    if not getattr(props, 'gb_frame', True):
        return []
    mode = _gb_trim_mode(props)
    if mode == 'NONE':
        return []
    recess = _gb_trim_depth(props, t)
    ft = max(t * 0.35, 0.06)
    fw = dw + ft * 2
    if mode == 'OFFSET':
        y_pos = t * 0.5 + recess + ft * 0.5
    else:
        y_pos = t * 0.5 - recess - ft * 0.5
    parts = [
        _gb_box(tree, (fw, ft, ft), (0, y_pos, dh + ft * 0.5),
                base_x + 1000, node_y + 200, "trim"),
    ]
    for sx in (-1, 1):
        parts.append(_gb_box(
            tree, (ft, ft, dh + ft),
            (sx * (dw * 0.5 + ft * 0.5), y_pos, (dh + ft) * 0.5),
            base_x + 1000, node_y + 400 + (sx + 1) * 150, "trim",
        ))
    return [p for p in parts if p is not None]


def _gb_corridor_rib_offset(props, wall_t):
    """Inward pilaster inset from corridor wall inner face."""
    rib_mode = getattr(props, 'gb_corridor_rib_mode', None)
    if rib_mode == 'NONE':
        return 0.0
    if rib_mode == 'OFFSET':
        return -_gb_trim_depth(props, wall_t) * 0.5
    if rib_mode == 'INSET':
        return _gb_trim_depth(props, wall_t)
    mode = _gb_trim_mode(props)
    if mode == 'NONE':
        return 0.0
    return _gb_trim_depth(props, wall_t) if mode == 'RECESS' else _gb_trim_depth(props, wall_t) * 0.5


_GB_PROFILE_WIDTH = {
    'SINGLE': 1.8,
    'DOUBLE': 3.0,
    'MAINTENANCE': 1.2,
}


def _gb_resolve_corridor_width(props):
    profile = getattr(props, 'gb_corridor_profile', 'DOUBLE')
    if profile in _GB_PROFILE_WIDTH:
        return _GB_PROFILE_WIDTH[profile]
    return getattr(props, 'gb_width', 3.0)


def _gb_corridor_dims(props):
    L = getattr(props, 'gb_length', 8.0)
    W = _gb_resolve_corridor_width(props)
    H = getattr(props, 'gb_height', 3.5)
    t = getattr(props, 'gb_wall_thick', 0.3)
    return L, W, H, t


def _gb_ceiling_mode(props):
    return getattr(props, 'gb_corridor_ceiling', 'FULL')


def _gb_ceiling_active(props):
    mode = _gb_ceiling_mode(props)
    if mode == 'OPEN':
        return False
    if mode in ('FULL', 'PARTIAL_GRID'):
        return True
    return getattr(props, 'gb_ceiling', True)


def _gb_add_corridor_ceiling(tree, props, base_x, span_w, span_l, H, t, cx, cy,
                             node_y, along_x=False):
    """Full slab or T-bar grid — trim-sheet friendly ceiling bays."""
    if not _gb_ceiling_active(props):
        return []
    mode = _gb_ceiling_mode(props)
    parts = []
    if mode == 'PARTIAL_GRID':
        beam_t = max(t * 0.55, 0.07)
        n_main = max(2, int(span_l / 2.0))
        for i in range(n_main + 1):
            frac = i / max(1, n_main)
            if along_x:
                yy = cy - span_l * 0.5 + frac * span_l
                bx = _gb_box(tree, (span_w, beam_t, beam_t), (cx, yy, H + beam_t * 0.5),
                             base_x, node_y + i * 35, "ceiling")
            else:
                xx = cx - span_l * 0.5 + frac * span_l
                bx = _gb_box(tree, (beam_t, span_w, beam_t), (xx, cy, H + beam_t * 0.5),
                             base_x, node_y + i * 35, "ceiling")
            if bx:
                parts.append(bx)
        n_cross = max(1, int(span_w / 2.0))
        for j in range(n_cross + 1):
            frac = j / max(1, n_cross)
            if along_x:
                xx = cx - span_w * 0.5 + frac * span_w
                bx = _gb_box(tree, (beam_t, span_l, beam_t), (xx, cy, H + beam_t * 0.5),
                             base_x, node_y + 800 + j * 35, "ceiling")
            else:
                yy = cy - span_l * 0.5 + frac * span_l
                bx = _gb_box(tree, (span_l, beam_t, beam_t), (cx, yy, H + beam_t * 0.5),
                             base_x, node_y + 800 + j * 35, "ceiling")
            if bx:
                parts.append(bx)
        return parts
    if along_x:
        bx = _gb_box(tree, (span_l, span_w, t), (cx, cy, H + t * 0.5), base_x, node_y, "ceiling")
    else:
        bx = _gb_box(tree, (span_w, span_l, t), (cx, cy, H + t * 0.5), base_x, node_y, "ceiling")
    return [bx] if bx else []


def _gb_corridor_ribs(tree, props, base_x, span_l, W, H, t, cx, cy, along_x, node_y):
    if getattr(props, 'gb_corridor_rib_mode', 'INSET') == 'NONE':
        if not getattr(props, 'gb_ribs', True):
            return []
    elif not getattr(props, 'gb_ribs', True):
        return []
    n_ribs = max(1, int(span_l / 2.5))
    rib_w = t * 1.4
    rib_inset = _gb_corridor_rib_offset(props, t)
    parts = []
    for i in range(n_ribs + 1):
        frac = i / max(1, n_ribs)
        wall_z = t + (H - t) * 0.5
        if along_x:
            xx = cx - span_l * 0.5 + frac * span_l
            for sy in (-1, 1):
                ry = cy + sy * (W * 0.5 - t - rib_inset)
                rib = _gb_box(tree, (rib_w, rib_w, H - t), (xx, ry, wall_z),
                              base_x, node_y + i * 50, "trim")
                if rib:
                    parts.append(rib)
        else:
            yy = cy - span_l * 0.5 + frac * span_l
            for sx in (-1, 1):
                rx = cx + sx * (W * 0.5 - t - rib_inset)
                rib = _gb_box(tree, (rib_w, rib_w, H - t), (rx, yy, wall_z),
                              base_x, node_y + i * 50, "trim")
                if rib:
                    parts.append(rib)
    return parts


def _gb_corridor_wainscot(tree, props, base_x, span_l, W, H, t, cx, cy,
                          along_x, node_y, side_sign=1):
    """Recessed wainscot + baseboard bands — flat panels for trim sheets."""
    wh = getattr(props, 'gb_wainscot_height', 0.0)
    bb = getattr(props, 'gb_baseboard_height', 0.0)
    if wh < 0.01 and bb < 0.01:
        return []
    recess = max(_gb_trim_depth(props, t) * 0.5, 0.015)
    panel_t = max(t * 0.12, 0.02)
    parts = []
    if along_x:
        wall_x = cx + side_sign * (W * 0.5 - t * 0.5 + recess - panel_t * 0.5)
        if wh > 0.01:
            parts.append(_gb_box(tree, (span_l, panel_t, wh), (cx, wall_x, bb + wh * 0.5),
                                 base_x, node_y, "trim"))
        if bb > 0.01:
            parts.append(_gb_box(tree, (span_l, panel_t, bb), (cx, wall_x, bb * 0.5),
                                 base_x, node_y + 100, "trim"))
    else:
        wall_y = cy + side_sign * (W * 0.5 - t * 0.5 + recess - panel_t * 0.5)
        if wh > 0.01:
            parts.append(_gb_box(tree, (panel_t, span_l, wh), (wall_y, cx, bb + wh * 0.5),
                                 base_x, node_y, "trim"))
        if bb > 0.01:
            parts.append(_gb_box(tree, (panel_t, span_l, bb), (wall_y, cx, bb * 0.5),
                                 base_x, node_y + 100, "trim"))
    return [p for p in parts if p is not None]


def _gb_junction_column(tree, props, base_x, cx, cy, W, H, t, node_y):
    if not getattr(props, 'gb_junction_column', False):
        return []
    col_w = max(W * 0.22, t * 2.5, 0.35)
    col = _gb_box(tree, (col_w, col_w, H - t), (cx, cy, t + (H - t) * 0.5),
                  base_x, node_y, "trim")
    return [col] if col else []


def _gb_corner_sleeve_bend(tree, props, base_x, W, L, H, t, node_y):
    """L-bend inner corner sleeve — quarter floor + return walls (not solid infill)."""
    parts = []
    sleeve = min(W, L) * 0.5
    wh = H - t
    wz = t + wh * 0.5
    icx = W * 0.5 - t
    icy = L - sleeve * 0.5
    qf = _gb_box(tree, (sleeve, sleeve, t), (icx - sleeve * 0.5, icy, t * 0.5),
                 base_x, node_y, "floor")
    if qf:
        parts.append(qf)
    rw_a = _gb_box(tree, (t, sleeve, wh),
                   (W * 0.5 - t * 1.5, icy, wz), base_x, node_y + 80, "wall")
    rw_b = _gb_box(tree, (sleeve, t, wh),
                   (icx - sleeve * 0.5, L - t * 1.5, wz), base_x, node_y + 160, "wall")
    if rw_a:
        parts.append(rw_a)
    if rw_b:
        parts.append(rw_b)
    chamfer = max(t * 0.9, 0.14)
    ch = _gb_box(tree, (chamfer, chamfer, wh),
                 (W * 0.5 - t - chamfer * 0.5, L - t - chamfer * 0.5, wz),
                 base_x, node_y + 240, "trim")
    if ch:
        parts.append(ch)
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, sleeve, sleeve, H, t,
                                          icx - sleeve * 0.5, icy, node_y + 320))
    return parts


def _gb_opening_cutter_depth(t, mult=4.0):
    """Deep cutter through wall thickness — prevents boolean clipping in UE blockout."""
    return t * mult


def _gb_collect_door_cutters_for_rect(tree, props, rw, rd, t, dh, dw, base_x, node_y,
                                      rx=0.0, ry=0.0):
    """Door cutters for a rect room centered at (rx, ry). Returns (ns_list, ew_list) of (side, cutter)."""
    door_z = t + dh * 0.5
    depth = _gb_opening_cutter_depth(t)
    cutters_ns, cutters_ew = [], []
    if getattr(props, 'gb_door_n', True):
        cutters_ns.append(('N', _gb_box(tree, (dw, depth, dh),
                                        (rx, ry + rd * 0.5, door_z), base_x, node_y + 300, "door")))
    if getattr(props, 'gb_door_s', False):
        cutters_ns.append(('S', _gb_box(tree, (dw, depth, dh),
                                        (rx, ry - rd * 0.5, door_z), base_x, node_y + 600, "door")))
    if getattr(props, 'gb_door_e', False):
        cutters_ew.append(('E', _gb_box(tree, (depth, dw, dh),
                                        (rx + rw * 0.5, ry, door_z), base_x, node_y + 900, "door")))
    if getattr(props, 'gb_door_w', False):
        cutters_ew.append(('W', _gb_box(tree, (depth, dw, dh),
                                        (rx - rw * 0.5, ry, door_z), base_x, node_y + 1200, "door")))
    return cutters_ns, cutters_ew


def _gb_collect_window_cutters_for_rect(tree, props, rw, rd, t, H, base_x, node_y,
                                        rx=0.0, ry=0.0):
    """Window cutters — v2.58 count props or legacy per-side toggles."""
    cutters_ns, cutters_ew = [], []
    depth = _gb_opening_cutter_depth(t)
    if getattr(props, 'gb_windows_enabled', False):
        win_w = getattr(props, 'gb_window_width', 0.8)
        win_h = getattr(props, 'gb_window_height', 0.8)
        sill = getattr(props, 'gb_window_sill', 1.0)
        win_z = t + sill + win_h * 0.5
        n_ns = max(0, getattr(props, 'gb_window_count_ns', 0))
        n_ew = max(0, getattr(props, 'gb_window_count_ew', 0))
        for i in range(n_ns):
            frac = (i + 1) / (n_ns + 1)
            wx = rx - rw * 0.5 + frac * rw
            cutters_ns.append(('N', _gb_box(tree, (win_w, depth, win_h),
                                            (wx, ry + rd * 0.5, win_z), base_x, node_y + 1500 + i, "door")))
            cutters_ns.append(('S', _gb_box(tree, (win_w, depth, win_h),
                                            (wx, ry - rd * 0.5, win_z), base_x, node_y + 1600 + i, "door")))
        for i in range(n_ew):
            frac = (i + 1) / (n_ew + 1)
            wy = ry - rd * 0.5 + frac * rd
            cutters_ew.append(('E', _gb_box(tree, (depth, win_w, win_h),
                                            (rx + rw * 0.5, wy, win_z), base_x, node_y + 1700 + i, "door")))
            cutters_ew.append(('W', _gb_box(tree, (depth, win_w, win_h),
                                            (rx - rw * 0.5, wy, win_z), base_x, node_y + 1800 + i, "door")))
    else:
        win_w = getattr(props, 'gb_window_width', getattr(props, 'gb_door_width', 1.0) * 0.8)
        win_h = getattr(props, 'gb_window_height', 1.4)
        wn = getattr(props, 'gb_window_count', 2)
        win_z = t + H * 0.58
        for (do_win, wall_dir, w_dir_x, w_dir_y) in [
            (getattr(props, 'gb_window_n', False), 'N', 0, rd * 0.5),
            (getattr(props, 'gb_window_s', False), 'S', 0, -rd * 0.5),
            (getattr(props, 'gb_window_e', True), 'E', rw * 0.5, 0),
            (getattr(props, 'gb_window_w', True), 'W', -rw * 0.5, 0),
        ]:
            if not do_win:
                continue
            wall_len = rw if wall_dir in ('N', 'S') else rd
            for wi in range(wn):
                frac = (wi + 0.5) / wn
                if wall_dir in ('N', 'S'):
                    wx = rx - rw * 0.5 + wall_len * frac
                    wy = ry + w_dir_y
                    cutters_ns.append((wall_dir, _gb_box(tree, (win_w, depth, win_h),
                                                         (wx, wy, win_z), base_x, node_y + 1900 + wi, "door")))
                else:
                    wx = rx + w_dir_x
                    wy = ry - rd * 0.5 + wall_len * frac
                    cutters_ew.append((wall_dir, _gb_box(tree, (depth, win_w, win_h),
                                                         (wx, wy, win_z), base_x, node_y + 2000 + wi, "door")))
    return cutters_ns, cutters_ew


def _gb_collect_window_cutters_elevator_walls(tree, props, W, D, t, fh, floors, base_x, node_y):
    """Per-floor window cutters on N/E/W shaft panels when gb_windows_enabled (v2.59.27)."""
    cutters_ns, cutters_ew = [], []
    if not getattr(props, 'gb_windows_enabled', False):
        return cutters_ns, cutters_ew
    depth = _gb_opening_cutter_depth(t)
    win_w = getattr(props, 'gb_window_width', 0.8)
    win_h = getattr(props, 'gb_window_height', 0.8)
    sill = getattr(props, 'gb_window_sill', 1.0)
    n_ns = max(0, getattr(props, 'gb_window_count_ns', 0))
    n_ew = max(0, getattr(props, 'gb_window_count_ew', 0))
    idx = 0
    for f in range(floors):
        z0 = f * fh
        win_z = z0 + t + sill + win_h * 0.5
        for i in range(n_ns):
            frac = (i + 1) / (n_ns + 1)
            wx = -W * 0.5 + frac * W
            cutters_ns.append(('N', _gb_box(tree, (win_w, depth, win_h),
                                            (wx, D * 0.5, win_z), base_x, node_y + 1500 + idx, "door")))
            idx += 1
        for i in range(n_ew):
            frac = (i + 1) / (n_ew + 1)
            wy = -D * 0.5 + frac * D
            cutters_ew.append(('E', _gb_box(tree, (depth, win_w, win_h),
                                            (W * 0.5, wy, win_z), base_x, node_y + 1700 + idx, "door")))
            cutters_ew.append(('W', _gb_box(tree, (depth, win_w, win_h),
                                            (-W * 0.5, wy, win_z), base_x, node_y + 1800 + idx, "door")))
            idx += 1
    return cutters_ns, cutters_ew


def _gb_apply_openings_to_wall(tree, wall_geom, side, cutters_ns, cutters_ew, base_x, node_y):
    """Boolean-cut one wall mesh for the given compass side."""
    if wall_geom is None:
        return None
    pool = cutters_ns if side in ('N', 'S') else cutters_ew
    cutters = [c for s, c in pool if s == side and c is not None]
    if not cutters:
        return wall_geom
    return _gb_bool_diff(tree, wall_geom, cutters, base_x + 1000, node_y)


def _gb_rect_room_shell(tree, props, rw, rd, H, t, base_x, node_y,
                        rx=0.0, ry=0.0, with_ceiling=None,
                        with_doors=True, with_windows=True):
    """Rectangular room shell: floor + 4 boolean-cut perimeter walls + optional ceiling."""
    parts = []
    wz = t + (H - t) * 0.5
    wh = H - t
    floor = _gb_box(tree, (rw, rd, t), (rx, ry, t * 0.5), base_x, node_y)
    if floor:
        parts.append(floor)

    ns_wall = _gb_box(tree, (rw, t, wh), (rx, ry + rd * 0.5 - t * 0.5, wz), base_x, node_y + 300)
    ss_wall = _gb_box(tree, (rw, t, wh), (rx, ry - rd * 0.5 + t * 0.5, wz), base_x, node_y + 600)
    ew_wall = _gb_box(tree, (t, rd, wh), (rx + rw * 0.5 - t * 0.5, ry, wz), base_x, node_y + 900)
    ww_wall = _gb_box(tree, (t, rd, wh), (rx - rw * 0.5 + t * 0.5, ry, wz), base_x, node_y + 1200)

    cutters_ns, cutters_ew = [], []
    if with_doors:
        d_ns, d_ew = _gb_collect_door_cutters_for_rect(
            tree, props, rw, rd, t, getattr(props, 'gb_door_height', 2.4),
            getattr(props, 'gb_door_width', 1.6), base_x, node_y, rx, ry)
        cutters_ns.extend(d_ns)
        cutters_ew.extend(d_ew)
    if with_windows:
        w_ns, w_ew = _gb_collect_window_cutters_for_rect(
            tree, props, rw, rd, t, H, base_x, node_y, rx, ry)
        cutters_ns.extend(w_ns)
        cutters_ew.extend(w_ew)

    for wall, side, ny in (
        (ns_wall, 'N', 300), (ss_wall, 'S', 600),
        (ew_wall, 'E', 900), (ww_wall, 'W', 1200),
    ):
        cut = _gb_apply_openings_to_wall(tree, wall, side, cutters_ns, cutters_ew, base_x, node_y + ny)
        if cut:
            parts.append(cut)

    if with_ceiling is None:
        with_ceiling = getattr(props, 'gb_ceiling', False)
    if with_ceiling:
        ceil = _gb_box(tree, (rw, rd, t), (rx, ry, H + t * 0.5), base_x, node_y + 700, "ceiling")
        if ceil:
            parts.append(ceil)
    return parts


def build_greybox_room(tree, props, base_x=-1400):
    """Parametric room shell: floor slab + 4 perimeter walls + optional ceiling.
    Door/window openings are boolean-cut on selected sides (N/S/E/W)."""
    W = getattr(props, 'gb_width', 8.0)
    D = getattr(props, 'gb_depth', 6.0)
    H = getattr(props, 'gb_height', 3.5)
    t = getattr(props, 'gb_wall_thick', 0.3)
    parts = _gb_rect_room_shell(tree, props, W, D, H, t, base_x, 0)
    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_corridor(tree, props, base_x=-1400):
    """Straight corridor segment: floor + 2 side walls + ceiling kit + trim bands.
    Tileable along Y for chaining into longer halls."""
    L, W, H, t = _gb_corridor_dims(props)
    parts = []

    floor = _gb_box(tree, (W, L, t), (0, 0, t * 0.5), base_x, 0)
    if floor:
        parts.append(floor)

    wall_z = t + (H - t) * 0.5
    wall_h = H - t
    lw = _gb_box(tree, (t, L, wall_h), (-W * 0.5 + t * 0.5, 0, wall_z), base_x, 300)
    rw = _gb_box(tree, (t, L, wall_h), ( W * 0.5 - t * 0.5, 0, wall_z), base_x, 600)
    if lw:
        parts.append(lw)
    if rw:
        parts.append(rw)

    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, L, H, t, 0, 0, 900))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, L, W, H, t, 0, 0, False, 1200))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, 0, 0, False, 2000, -1))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, 0, 0, False, 2100, 1))

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_ramp(tree, props, base_x=-1400):
    """Inclined ramp blockout: a tilted slab + optional side curbs.
    Rise is parametric; the ramp sits with its low end at z=0."""
    import math as _m
    L = getattr(props, 'gb_length',     6.0)
    W = getattr(props, 'gb_width',      3.0)
    rise = getattr(props, 'gb_rise',    3.0)
    t = getattr(props, 'gb_wall_thick', 0.35)
    parts = []

    angle = _m.atan2(rise, L)
    slab_len = _m.sqrt(L * L + rise * rise)
    # Tilt the slab around X so +Y climbs
    slab = _gb_box_node(tree, (W, slab_len, t),
                        (0, 0, rise * 0.5),
                        (angle, 0, 0),
                        base_x, 0)
    if slab: parts.append(slab)

    # Side curbs
    if getattr(props, 'gb_curbs', True):
        curb_h = t * 2.2
        for sx in (-1, 1):
            curb = _gb_box_node(tree, (t, slab_len, curb_h),
                                (sx * (W * 0.5 - t * 0.5), 0, rise * 0.5 + curb_h * 0.4),
                                (angle, 0, 0),
                                base_x + 400, 300 + (sx + 1) * 200, "level")
            if curb: parts.append(curb)

    return _gb_join(tree, parts, base_x + 1200, 0)


def build_greybox_platform(tree, props, base_x=-1400):
    """Raised platform / mezzanine: top slab on 4 corner legs.
    Great for vertical level prototyping."""
    W = getattr(props, 'gb_width',      5.0)
    D = getattr(props, 'gb_depth',      5.0)
    H = getattr(props, 'gb_height',     3.0)
    t = getattr(props, 'gb_wall_thick', 0.3)
    leg = getattr(props, 'gb_leg_thick', 0.4)
    parts = []

    # Top deck
    deck = _gb_box(tree, (W, D, t), (0, 0, H - t * 0.5), base_x, 0)
    if deck: parts.append(deck)

    # 4 corner legs
    leg_h = H - t
    for i, (sx, sy) in enumerate([(-1, -1), (1, -1), (1, 1), (-1, 1)]):
        lg = _gb_box(tree, (leg, leg, leg_h),
                     (sx * (W * 0.5 - leg * 0.5),
                      sy * (D * 0.5 - leg * 0.5),
                      leg_h * 0.5),
                     base_x, 300 + i * 200)
        if lg: parts.append(lg)

    # Perimeter railings — all 4 edges at deck height
    style = getattr(props, 'gb_railing_style', 'ADVANCED')
    if style != 'NONE' and getattr(props, 'gb_railings', True):
        import math as _m
        rh = 1.0   # railing height above deck
        for edge_idx, (rl, tx, ty, rz, xo) in enumerate([
            (W, 0,       D * 0.5,  0,                  5000),   # +Y front
            (W, 0,      -D * 0.5,  _m.pi,              8000),   # -Y back
            (D, W * 0.5, 0,        _m.radians(-90),   11000),   # +X right
            (D,-W * 0.5, 0,        _m.radians( 90),   14000),   # -X left
        ]):
            if style == 'ADVANCED':
                r = build_railing(tree, props, x_offset=xo, length=rl, height=rh)
            else:   # SIMPLE: thin box
                r = _gb_box(tree, (rl, leg * 0.5, rh), (0, 0, rh * 0.5),
                            base_x + xo, 0, "railing")
            if r:
                rt = _safe_node(tree, 'GeometryNodeTransform',
                                (base_x + xo + 700, edge_idx * 200))
                if rt:
                    try:
                        rt.inputs['Translation'].default_value = (tx, ty, H)
                        rt.inputs['Rotation'].default_value    = (0, 0, rz)
                    except Exception: pass
                    _link(tree, r, rt.inputs['Geometry'])
                    parts.append(rt.outputs['Geometry'])

    return _gb_join(tree, parts, base_x + 1400, 0)


def build_greybox_cover(tree, props, base_x=-1400):
    """Cover block for shooter prototyping: parametric width + height ratio.
    Add a low lip on top so it reads as cover, not just a box."""
    W = getattr(props, 'gb_width',      2.0)
    H = getattr(props, 'gb_height',     1.2)   # waist-high default
    t = getattr(props, 'gb_wall_thick', 0.5)   # depth of the block
    parts = []

    body = _gb_box(tree, (W, t, H), (0, 0, H * 0.5), base_x, 0)
    if body: parts.append(body)
    # Top lip
    lip = _gb_box(tree, (W * 1.1, t * 1.25, H * 0.12),
                  (0, 0, H + H * 0.06), base_x, 300, "level")
    if lip: parts.append(lip)
    # Base foot
    foot = _gb_box(tree, (W * 1.08, t * 1.18, H * 0.10),
                   (0, 0, H * 0.05), base_x, 600, "level")
    if foot: parts.append(foot)

    return _gb_join(tree, parts, base_x + 1000, 0)


def build_greybox_catwalk(tree, props, base_x=-1400):
    """Industrial catwalk: grated deck + 2 railings + support posts."""
    L = getattr(props, 'gb_length',  8.0)
    W = getattr(props, 'gb_width',   1.6)
    H = getattr(props, 'gb_height',  3.0)   # deck elevation
    t = getattr(props, 'gb_wall_thick', 0.18)
    parts = []

    # Deck
    deck = _gb_box(tree, (W, L, t), (0, 0, H - t * 0.5), base_x, 0)
    if deck: parts.append(deck)

    # Support posts under each end + middle
    post_t = t * 1.6
    n_posts = max(2, int(L / 3.0) + 1)
    for i in range(n_posts):
        yy = -L * 0.5 + (i / max(1, n_posts - 1)) * L
        for sx in (-1, 1):
            post = _gb_box(tree, (post_t, post_t, H - t),
                           (sx * (W * 0.5 - post_t * 0.6), yy, (H - t) * 0.5),
                           base_x + 300, 300 + i * 80)
            if post: parts.append(post)

    # Railings down both long sides — properly aligned at deck edge
    style = getattr(props, 'gb_railing_style', 'ADVANCED')
    if style != 'NONE' and getattr(props, 'gb_railings', True):
        import math as _m
        for si, sx in enumerate((-1, 1)):
            xo = 5000 + si * 6000
            if style == 'ADVANCED':
                r = build_railing(tree, props, x_offset=xo, length=L, height=1.05)
            else:
                r = _gb_box(tree, (L, t * 0.6, 1.05), (0, 0, 0.525),
                            base_x + xo, 0, "railing")
            if r:
                rt = _safe_node(tree, 'GeometryNodeTransform',
                                (base_x + xo + 700, 700 + si * 200))
                if rt:
                    try:
                        rt.inputs['Rotation'].default_value    = (0, 0, _m.radians(90))
                        rt.inputs['Translation'].default_value = (sx * (W * 0.5), 0, H)
                    except Exception: pass
                    _link(tree, r, rt.inputs['Geometry'])
                    color_node(rt, "railing")
                    parts.append(rt.outputs['Geometry'])

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_pillar_hall(tree, props, base_x=-1400):
    """Hypostyle hall blockout: grid of columns + floor + flat roof slab.
    The classic 'big interior space' greybox."""
    cols_x = max(2, getattr(props, 'gb_cols_x', 4))
    cols_y = max(2, getattr(props, 'gb_cols_y', 6))
    spacing = getattr(props, 'gb_spacing', 3.0)
    H = getattr(props, 'gb_height', 5.0)
    t = getattr(props, 'gb_wall_thick', 0.3)
    col_r = getattr(props, 'gb_leg_thick', 0.5)
    parts = []

    span_x = (cols_x - 1) * spacing
    span_y = (cols_y - 1) * spacing
    pad = spacing * 0.8
    fw = span_x + pad * 2
    fd = span_y + pad * 2

    # Floor + roof — v2.60.2 walk-plane: floor top at Z=0
    floor = _gb_box(tree, (fw, fd, t), (0, 0, -t * 0.5), base_x, 0)
    if floor: parts.append(floor)
    roof = _gb_box(tree, (fw, fd, t), (0, 0, H - t * 0.5), base_x, 300, "ceiling")
    if roof: parts.append(roof)

    # Column grid — octagonal columns via fill+extrude for nicer silhouette
    import math as _m
    idx = 0
    for ix in range(cols_x):
        for iy in range(cols_y):
            cx = -span_x * 0.5 + ix * spacing
            cy = -span_y * 0.5 + iy * spacing
            circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle',
                              (base_x + 600, 600 + idx * 40))
            col_geom = None
            if circ:
                try:
                    circ.inputs['Resolution'].default_value = 8
                    circ.inputs['Radius'].default_value = col_r
                except Exception: pass
                fill = _safe_node(tree, 'GeometryNodeFillCurve',
                                  (base_x + 750, 600 + idx * 40))
                if fill:
                    try: fill.mode = 'NGONS'
                    except Exception: pass
                    _link(tree, circ.outputs['Curve'], fill.inputs['Curve'])
                    ext = _safe_node(tree, 'GeometryNodeExtrudeMesh',
                                     (base_x + 900, 600 + idx * 40))
                    if ext:
                        ext.mode = 'FACES'
                        try: ext.inputs['Offset Scale'].default_value = H
                        except Exception: pass
                        _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
                        tr = _safe_node(tree, 'GeometryNodeTransform',
                                        (base_x + 1100, 600 + idx * 40))
                        if tr:
                            try: tr.inputs['Translation'].default_value = (cx, cy, 0)
                            except Exception: pass
                            _link(tree, ext.outputs['Mesh'], tr.inputs['Geometry'])
                            color_node(tr, "pillar")
                            col_geom = tr.outputs['Geometry']
            if col_geom is None:
                col_geom = _gb_box(tree, (col_r * 1.6, col_r * 1.6, H),
                                   (cx, cy, H * 0.5), base_x + 600, 600 + idx * 40,
                                   "pillar")
            if col_geom: parts.append(col_geom)
            idx += 1

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_stair_block(tree, props, base_x=-1400):
    """Blockout staircase: solid stepped wedge + side stringer walls + top
    landing. Wider/cleaner than the spiral STAIRCASE — for level traversal."""
    steps = max(2, getattr(props, 'gb_steps', 10))
    rise  = getattr(props, 'gb_rise', 0.2)
    run_  = getattr(props, 'gb_run',  0.3)
    W     = getattr(props, 'gb_width', 2.4)
    t     = getattr(props, 'gb_wall_thick', 0.25)
    parts = []

    total_rise = steps * rise
    total_run  = steps * run_

    # Each step is a box; box extends down to the floor (solid look)
    for i in range(steps):
        z_top = (i + 1) * rise
        y0 = i * run_
        step_box = _gb_box(tree, (W, run_, z_top),
                           (0, y0 + run_ * 0.5 - total_run * 0.5, z_top * 0.5),
                           base_x, i * 90)
        if step_box: parts.append(step_box)

    # Side stringer walls (triangular look via tilted slab)
    if getattr(props, 'gb_curbs', True):
        import math as _m
        ang = _m.atan2(total_rise, total_run)
        slab_len = _m.sqrt(total_run ** 2 + total_rise ** 2)
        for sx in (-1, 1):
            sw = _gb_box_node(tree, (t, slab_len, rise * 1.5),
                              (sx * (W * 0.5 + t * 0.5), 0, total_rise * 0.5),
                              (ang, 0, 0),
                              base_x + 400, 1000 + (sx + 1) * 150, "level")
            if sw: parts.append(sw)

    # v2.60.2 — walk-plane entry pad (top at Z=0) + landing top at upper walk plane
    pad_y = -total_run * 0.5 - run_ * 0.5
    entry_pad = _gb_box(tree, (W + t * 2, run_ * 2, t),
                        (0, pad_y, -t * 0.5), base_x - 50, 0, "level")
    if entry_pad:
        parts.insert(0, entry_pad)

    # Top landing — top surface at total_rise + t (upper walk plane)
    if getattr(props, 'gb_landing', True):
        land_y = total_run * 0.5 + run_ * 1.5
        land = _gb_box(tree, (W, run_ * 3, t),
                       (0, land_y, total_rise + t * 0.5),
                       base_x, 1400, "level")
        if land:
            parts.append(land)
        # Optional back wall at landing (+Y) with door boolean
        if getattr(props, 'gb_landing_back_wall', False):
            dw = getattr(props, 'gb_door_width', 1.2)
            dh = getattr(props, 'gb_door_height', 2.4)
            wall_h = max(dh + 0.6, total_rise + t + 0.5)
            back_y = land_y + run_ * 1.5 + t * 0.5
            wall = _gb_box(tree, (W, t, wall_h),
                           (0, back_y, wall_h * 0.5), base_x + 500, 1400, "wall")
            cutter = _gb_box(tree, (dw, t * 4, dh),
                             (0, back_y, dh * 0.5), base_x + 700, 1400, "door")
            cut = _gb_bool_diff(tree, wall, [cutter], base_x + 900, 1400)
            if cut:
                parts.append(cut)

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_doorway(tree, props, base_x=-1400):
    """Freestanding doorway / portal frame: a wall slab with a door-shaped
    boolean cut. Drop between rooms for a clean opening."""
    W  = getattr(props, 'gb_width',       3.0)
    H  = getattr(props, 'gb_height',      3.5)
    t  = getattr(props, 'gb_wall_thick',  0.4)
    dw = getattr(props, 'gb_door_width',  1.6)
    dh = getattr(props, 'gb_door_height', 2.6)

    slab = _gb_box(tree, (W, t, H), (0, 0, H * 0.5), base_x, 0)
    cutter = _gb_box(tree, (dw, t * 3, dh), (0, 0, dh * 0.5), base_x + 400, 0, "door")
    cut = _gb_bool_diff(tree, slab, [cutter], base_x + 800, 0)

    parts = [cut] if cut else []
    parts.extend(_gb_doorway_frame_trim(tree, props, base_x, dw, dh, t))

    return _gb_join(tree, parts, base_x + 1400, 0)


def build_greybox_arena(tree, props, base_x=-1400):
    """Tiered amphitheater / arena blockout: concentric stepped rings around
    a central floor. Polygonal sides parameter for round vs faceted."""
    import math as _m
    R      = getattr(props, 'gb_radius', 8.0)
    tiers  = max(1, getattr(props, 'gb_tiers', 5))
    sides  = max(3, getattr(props, 'gb_sides', 16))
    rise   = getattr(props, 'gb_rise', 0.6)
    depth  = getattr(props, 'gb_run',  1.0)   # tier tread depth
    parts = []

    # Central arena floor slab — top at Z=0 (v2.60.1 walk-plane alignment)
    floor_t = max(0.2, rise * 0.35)
    circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, 0))
    if circ:
        try:
            circ.inputs['Resolution'].default_value = sides
            circ.inputs['Radius'].default_value = R
        except Exception: pass
        fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, 0))
        if fill:
            try: fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, circ.outputs['Curve'], fill.inputs['Curve'])
            ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 350, 0))
            if ext:
                ext.mode = 'FACES'
                try: ext.inputs['Offset Scale'].default_value = floor_t
                except Exception: pass
                _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
                color_node(ext, "level")
                floor_mesh = _move(tree, ext.outputs['Mesh'], (base_x + 550, 0),
                                   translation=(0, 0, -floor_t), label="level")
                if floor_mesh:
                    parts.append(floor_mesh)
            else:
                color_node(fill, "level")
                parts.append(fill.outputs['Mesh'])

    # Concentric stepped tiers (each is a ring = outer poly minus inner poly,
    # extruded up). Build as a flat ring band per tier via two fills + boolean.
    for ti in range(tiers):
        r_in  = R + ti * depth
        r_out = R + (ti + 1) * depth
        z = (ti + 1) * rise
        # Outer filled poly
        oc = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x + 500, 300 + ti * 200))
        ring_geom = None
        if oc:
            try:
                oc.inputs['Resolution'].default_value = sides
                oc.inputs['Radius'].default_value = r_out
            except Exception: pass
            of = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 650, 300 + ti * 200))
            if of:
                try: of.mode = 'NGONS'
                except Exception: pass
                _link(tree, oc.outputs['Curve'], of.inputs['Curve'])
                oe = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 800, 300 + ti * 200))
                if oe:
                    oe.mode = 'FACES'
                    try: oe.inputs['Offset Scale'].default_value = z
                    except Exception: pass
                    _link(tree, of.outputs['Mesh'], oe.inputs['Mesh'])
                    color_node(oe, "level")
                    ring_geom = oe.outputs['Mesh']
        if ring_geom:
            # Cut the inner cylinder out to make a seating step
            ic = _safe_node(tree, 'GeometryNodeMeshCylinder', (base_x + 500, 450 + ti * 200))
            if ic:
                try:
                    ic.inputs['Vertices'].default_value = sides
                    ic.inputs['Radius'].default_value = r_in
                    ic.inputs['Depth'].default_value = z * 4
                except Exception: pass
                ict = _safe_node(tree, 'GeometryNodeTransform', (base_x + 700, 450 + ti * 200))
                if ict:
                    try: ict.inputs['Translation'].default_value = (0, 0, z)
                    except Exception: pass
                    _link(tree, ic.outputs['Mesh'], ict.inputs['Geometry'])
                    ring_geom = _gb_bool_diff(tree, ring_geom, [ict.outputs['Geometry']],
                                              base_x + 1000, 450 + ti * 200)
            parts.append(ring_geom)

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_tower(tree, props, base_x=-1400):
    """Multi-floor tower blockout: outer shell + internal floor slabs +
    window openings per floor. Walk-in-ready vertical greybox."""
    floors = max(1, getattr(props, 'gb_floors', 4))
    fh     = getattr(props, 'gb_height', 3.2)   # per-floor height
    W      = getattr(props, 'gb_width', 6.0)
    D      = getattr(props, 'gb_depth', 6.0)
    t      = getattr(props, 'gb_wall_thick', 0.35)
    ww     = getattr(props, 'gb_door_width', 1.4)   # window width
    wh     = getattr(props, 'gb_door_height', 1.4)  # window height
    parts = []
    total_h = floors * fh

    # Outer shell: 4 walls
    cutters = []
    wall_z_center = total_h * 0.5
    # Build 4 walls
    walls = {
        'N': _gb_box(tree, (W, t, total_h), (0,  D * 0.5 - t * 0.5, wall_z_center), base_x, 0),
        'S': _gb_box(tree, (W, t, total_h), (0, -D * 0.5 + t * 0.5, wall_z_center), base_x, 300),
        'E': _gb_box(tree, (t, D, total_h), ( W * 0.5 - t * 0.5, 0, wall_z_center), base_x, 600),
        'W': _gb_box(tree, (t, D, total_h), (-W * 0.5 + t * 0.5, 0, wall_z_center), base_x, 900),
    }

    # Window cutters per floor on N & S walls; door at ground on S
    import math as _m
    win_cut_n, win_cut_s = [], []
    for f in range(floors):
        cz = f * fh + fh * 0.55
        if f == 0:
            # Ground-floor door on S
            dcut = _gb_box(tree, (ww * 1.3, t * 3, fh * 0.8),
                           (0, -D * 0.5, (fh * 0.8) * 0.5), base_x + 500, 300, "door")
            win_cut_s.append(dcut)
        else:
            wcut_n = _gb_box(tree, (ww, t * 3, wh), (0,  D * 0.5, cz), base_x + 500, f * 120, "window")
            wcut_s = _gb_box(tree, (ww, t * 3, wh), (0, -D * 0.5, cz), base_x + 500, 300 + f * 120, "window")
            win_cut_n.append(wcut_n)
            win_cut_s.append(wcut_s)

    walls['N'] = _gb_bool_diff(tree, walls['N'], win_cut_n, base_x + 900, 0)
    walls['S'] = _gb_bool_diff(tree, walls['S'], win_cut_s, base_x + 900, 300)
    for k in walls:
        if walls[k]: parts.append(walls[k])

    # Internal floor slabs (skip ground; floor slab at each upper level)
    for f in range(1, floors):
        slab = _gb_box(tree, (W - t * 2, D - t * 2, t),
                       (0, 0, f * fh + t * 0.5), base_x, 1200 + f * 120, "level")
        if slab: parts.append(slab)
    # Base floor + roof cap
    base_floor = _gb_box(tree, (W, D, t), (0, 0, t * 0.5), base_x, 1100, "level")
    if base_floor: parts.append(base_floor)
    roof = _gb_box(tree, (W, D, t), (0, 0, total_h + t * 0.5), base_x, 1150, "ceiling")
    if roof: parts.append(roof)

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_greybox_pipe_run(tree, props, base_x=-1400):
    """Sci-fi pipe run: a bent poly-curve swept into a tube with flange rings
    at each joint. Parametric segment count + radius for industrial blockout."""
    import math as _m
    segs   = max(2, getattr(props, 'gb_segments', 4))
    radius = getattr(props, 'gb_radius', 0.25)
    seg_len = getattr(props, 'gb_length', 2.5)
    parts = []

    # Build a zig-zag poly path of points, alternating up/forward bends
    pts = []
    x, y, z = 0.0, 0.0, radius * 2
    pts.append((x, y, z))
    for i in range(segs):
        if i % 2 == 0:
            y += seg_len
        else:
            z += seg_len * 0.6
        pts.append((x, y, z))

    # Create the curve via a Mesh Line we reposition, then Mesh→Curve.
    # Simpler robust route: build bezier-less poly by chaining CurveLine sweeps.
    prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 300, 0))
    if prof:
        try:
            prof.inputs['Resolution'].default_value = 12
            prof.inputs['Radius'].default_value = radius
        except Exception: pass

    for i in range(len(pts) - 1):
        a, b = pts[i], pts[i + 1]
        line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, i * 150))
        if line:
            try:
                line.inputs['Start'].default_value = a
                line.inputs['End'].default_value = b
            except Exception: pass
            if prof:
                sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, i * 150))
                if sw:
                    _link(tree, line.outputs['Curve'], sw.inputs['Curve'])
                    _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
                    try: sw.inputs['Fill Caps'].default_value = True
                    except Exception: pass
                    color_node(sw, "level")
                    parts.append(sw.outputs['Mesh'])
        # Flange ring (torus) at each joint
        flange = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x + 500, i * 150))
        if flange:
            try:
                flange.inputs['Major Radius'].default_value = radius * 1.5
                flange.inputs['Minor Radius'].default_value = radius * 0.35
                flange.inputs['Major Segments'].default_value = 16
                flange.inputs['Minor Segments'].default_value = 8
            except Exception: pass
            ft = _safe_node(tree, 'GeometryNodeTransform', (base_x + 700, i * 150))
            if ft:
                try: ft.inputs['Translation'].default_value = a
                except Exception: pass
                _link(tree, flange.outputs['Mesh'], ft.inputs['Geometry'])
                color_node(ft, "level")
                parts.append(ft.outputs['Geometry'])

    return _gb_join(tree, parts, base_x + 1200, 0)


# ==============================================================================
# 🏗  EXTENDED GREYBOX BUILDERS  (v2.52)
#   Corridor bends/crosses, recursive branching, combat rooms, elevator shafts,
#   composite room shapes. All properly aligned with the advanced railing system.
# ==============================================================================

def _gb_railing_edge(tree, props, length, deck_z, tx, ty, rot_z, x_offset, idx):
    """Place one AAA railing segment at world position (tx, ty, deck_z) with
    Z-rotation rot_z.  Returns a geometry socket or None."""
    import math as _m
    style = getattr(props, 'gb_railing_style', 'ADVANCED')
    if style == 'NONE':
        return None
    if style == 'ADVANCED':
        r = build_railing(tree, props, x_offset=x_offset, length=length, height=0.95)
    else:
        r = _gb_box(tree, (length, 0.08, 0.95), (0, 0, 0.475),
                    -1400 + x_offset, idx * 200, "railing")
    if r is None:
        return None
    rt = _safe_node(tree, 'GeometryNodeTransform',
                    (-1400 + x_offset + 800, idx * 200))
    if rt is None:
        return r
    try:
        rt.inputs['Translation'].default_value = (tx, ty, deck_z)
        rt.inputs['Rotation'].default_value    = (0, 0, rot_z)
    except Exception: pass
    _link(tree, r, rt.inputs['Geometry'])
    color_node(rt, "railing")
    return rt.outputs['Geometry']


def build_greybox_corridor_bend(tree, props, base_x=-1400):
    """90° bent (L-shaped) corridor: Arm A along +Y, Arm B along +X.
    Inner corner sleeve (quarter floor + return walls) — kitbash, not solid infill."""
    L, W, H, t = _gb_corridor_dims(props)
    parts = []
    wz = t + (H - t) * 0.5
    wh = H - t

    parts.append(_gb_box(tree, (W, L, t), (0, L * 0.5, t * 0.5), base_x, 0))
    parts.append(_gb_box(tree, (t, L, wh), (-W * 0.5 + t * 0.5, L * 0.5, wz), base_x, 300))
    parts.append(_gb_box(tree, (t, L, wh), ( W * 0.5 - t * 0.5, L * 0.5, wz), base_x, 600))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, L, H, t, 0, L * 0.5, 900))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, L, W, H, t, 0, L * 0.5, False, 1000))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, 0, L * 0.5, False, 1100, -1))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, 0, L * 0.5, False, 1150, 1))

    ox = W * 0.5 + L * 0.5
    oy = L
    parts.append(_gb_box(tree, (L, W, t), (ox, oy, t * 0.5), base_x, 1200))
    parts.append(_gb_box(tree, (L, t, wh), (ox, oy - W * 0.5 + t * 0.5, wz), base_x, 1500))
    parts.append(_gb_box(tree, (L, t, wh), (ox, oy + W * 0.5 - t * 0.5, wz), base_x, 1800))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, L, H, t, ox, oy, 2100, along_x=True))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, L, W, H, t, ox, oy, True, 2200))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, ox, oy, True, 2300, -1))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, L, W, H, t, ox, oy, True, 2350, 1))

    parts.extend(_gb_corner_sleeve_bend(tree, props, base_x, W, L, H, t, 2400))

    return _gb_join(tree, parts, base_x + 3200, 0)


def build_greybox_corridor_cross(tree, props, base_x=-1400):
    """4-way cross intersection with optional hub column and ceiling kit."""
    L, W, H, t = _gb_corridor_dims(props)
    parts = []
    wz = t + (H - t) * 0.5
    wh = H - t

    parts.append(_gb_box(tree, (W, W, t), (0, 0, t * 0.5), base_x, 0))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, W, H, t, 0, 0, 300))
    parts.extend(_gb_junction_column(tree, props, base_x, 0, 0, W, H, t, 350))

    arms = [
        (L * 0.5 + W * 0.5, 0, True),
        (-(L * 0.5 + W * 0.5), 0, True),
        (0, L * 0.5 + W * 0.5, False),
        (0, -(L * 0.5 + W * 0.5), False),
    ]
    for ai, (ax, ay, along_x) in enumerate(arms):
        ny = 600 + ai * 500
        if along_x:
            fw, fd = L, W
            wall_off = W * 0.5 - t * 0.5
            parts.append(_gb_box(tree, (fw, fd, t), (ax, ay, t * 0.5), base_x, ny))
            parts.append(_gb_box(tree, (fw, t, wh), (ax, ay - wall_off, wz), base_x, ny + 100))
            parts.append(_gb_box(tree, (fw, t, wh), (ax, ay + wall_off, wz), base_x, ny + 200))
            parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, fd, fw, H, t, ax, ay,
                                                  ny + 300, along_x=True))
            parts.extend(_gb_corridor_ribs(tree, props, base_x, fw, fd, H, t, ax, ay, True, ny + 400))
        else:
            fw, fd = W, L
            wall_off = W * 0.5 - t * 0.5
            parts.append(_gb_box(tree, (fw, fd, t), (ax, ay, t * 0.5), base_x, ny))
            parts.append(_gb_box(tree, (t, fd, wh), (ax - wall_off, ay, wz), base_x, ny + 100))
            parts.append(_gb_box(tree, (t, fd, wh), (ax + wall_off, ay, wz), base_x, ny + 200))
            parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, fw, fd, H, t, ax, ay, ny + 300))
            parts.extend(_gb_corridor_ribs(tree, props, base_x, fd, fw, H, t, ax, ay, False, ny + 400))

    return _gb_join(tree, parts, base_x + 2600, 0)


def build_greybox_corridor_t(tree, props, base_x=-1400):
    """T-junction corridor: main hall along Y + side arm along +X."""
    L, W, H, t = _gb_corridor_dims(props)
    arm_len = L * 0.6
    parts = []
    wz = t + (H - t) * 0.5
    wh = H - t

    parts.append(_gb_box(tree, (W, L, t), (0, 0, t * 0.5), base_x, 0))
    parts.append(_gb_box(tree, (t, L, wh), (-W * 0.5 + t * 0.5, 0, wz), base_x, 300))
    parts.append(_gb_box(tree, (t, L, wh), ( W * 0.5 - t * 0.5, 0, wz), base_x, 600))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, L, H, t, 0, 0, 900))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, L, W, H, t, 0, 0, False, 1000))
    parts.extend(_gb_junction_column(tree, props, base_x, 0, 0, W, H, t, 1050))

    ax = W * 0.5 + arm_len * 0.5
    ay = 0
    parts.append(_gb_box(tree, (arm_len, W, t), (ax, ay, t * 0.5), base_x, 1200))
    parts.append(_gb_box(tree, (arm_len, t, wh), (ax, ay - W * 0.5 + t * 0.5, wz), base_x, 1500))
    parts.append(_gb_box(tree, (arm_len, t, wh), (ax, ay + W * 0.5 - t * 0.5, wz), base_x, 1800))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, arm_len, H, t, ax, ay,
                                          2100, along_x=True))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, arm_len, W, H, t, ax, ay, True, 2200))

    return _gb_join(tree, parts, base_x + 2800, 0)


def build_greybox_corridor_door_end(tree, props, base_x=-1400):
    """Corridor end cap: short tileable run + end wall with door boolean + recess trim."""
    L, W, H, t = _gb_corridor_dims(props)
    dw = getattr(props, 'gb_door_width', 1.6)
    dh = getattr(props, 'gb_door_height', 2.6)
    stub = min(L, max(W * 1.5, 2.0))
    parts = []
    wz = t + (H - t) * 0.5
    wh = H - t
    end_y = stub * 0.5

    parts.append(_gb_box(tree, (W, stub, t), (0, 0, t * 0.5), base_x, 0))
    parts.append(_gb_box(tree, (t, stub, wh), (-W * 0.5 + t * 0.5, 0, wz), base_x, 200))
    parts.append(_gb_box(tree, (t, stub, wh), ( W * 0.5 - t * 0.5, 0, wz), base_x, 400))
    parts.extend(_gb_add_corridor_ceiling(tree, props, base_x, W, stub, H, t, 0, 0, 600))
    parts.extend(_gb_corridor_ribs(tree, props, base_x, stub, W, H, t, 0, 0, False, 700))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, stub, W, H, t, 0, 0, False, 800, -1))
    parts.extend(_gb_corridor_wainscot(tree, props, base_x, stub, W, H, t, 0, 0, False, 850, 1))

    slab = _gb_box(tree, (W, t, H), (0, end_y, H * 0.5), base_x, 1000)
    cutter = _gb_box(tree, (dw, t * 4, dh), (0, end_y, dh * 0.5), base_x + 400, 1000, "door")
    cut = _gb_bool_diff(tree, slab, [cutter], base_x + 800, 1000)
    if cut:
        parts.append(cut)
    parts.extend(_gb_doorway_frame_trim(tree, props, base_x + 1200, dw, dh, t, node_y=1000))

    return _gb_join(tree, parts, base_x + 2000, 0)


