def build_greybox_room_composite(tree, props, base_x=-1400):
    """Composite room: RECTANGLE + optional L/T/U extension wings.
    Primary wing uses boolean door/window cuts; extension wings are solid shells."""
    W = getattr(props, 'gb_width', 8.0)
    D = getattr(props, 'gb_depth', 6.0)
    H = getattr(props, 'gb_height', 3.5)
    t = getattr(props, 'gb_wall_thick', 0.3)
    shape = getattr(props, 'gb_room_shape', 'RECTANGLE')
    parts = []

    parts.extend(_gb_rect_room_shell(
        tree, props, W, D, H, t, base_x, 0,
        rx=0.0, ry=0.0, with_doors=True, with_windows=True))

    if shape == 'L_SHAPE':
        W2, D2 = W * 0.7, D * 0.7
        parts.extend(_gb_rect_room_shell(
            tree, props, W2, D2, H, t, base_x, 1200,
            rx=W * 0.5 + W2 * 0.5, ry=-D * 0.5 + D2 * 0.5,
            with_doors=False, with_windows=False))
    elif shape == 'T_SHAPE':
        Ww, Dw = W * 0.5, D * 0.55
        parts.extend(_gb_rect_room_shell(
            tree, props, Ww, Dw, H, t, base_x, 1200,
            rx=W * 0.5 + Ww * 0.5, ry=D * 0.5 - Dw * 0.5,
            with_doors=False, with_windows=False))
        parts.extend(_gb_rect_room_shell(
            tree, props, Ww, Dw, H, t, base_x, 2400,
            rx=-W * 0.5 - Ww * 0.5, ry=D * 0.5 - Dw * 0.5,
            with_doors=False, with_windows=False))
    elif shape == 'U_SHAPE':
        Ww, Dw = W * 0.5, D * 0.6
        parts.extend(_gb_rect_room_shell(
            tree, props, Ww, Dw, H, t, base_x, 1200,
            rx=W * 0.5 + Ww * 0.5, ry=D * 0.5 - Dw * 0.5,
            with_doors=False, with_windows=False))
        parts.extend(_gb_rect_room_shell(
            tree, props, Ww, Dw, H, t, base_x, 2400,
            rx=-W * 0.5 - Ww * 0.5, ry=D * 0.5 - Dw * 0.5,
            with_doors=False, with_windows=False))
        bar_w = W + Ww * 2
        parts.append(_gb_box(tree, (bar_w, t, H - t), (0, D * 0.5 - t * 0.5, t + (H - t) * 0.5),
                             base_x, 3600))

    if getattr(props, 'gb_interior_walls', False):
        pw_h = H * 0.6
        parts.append(_gb_box(tree, (W * 0.7, t, pw_h), (0, 0, pw_h * 0.5 + t),
                             base_x + 12000, 0, "level"))

    return _gb_join(tree, parts, base_x + 4000, 0)


def build_greybox_elevator_shaft(tree, props, base_x=-1400):
    """Vertical elevator shaft: outer tube + floor landings per level.
    Each landing has a door cutout and optional railing at edge.
    Optional window booleans on N/E/W shaft panels when gb_windows_enabled (v2.59.27)."""
    floors  = max(2, getattr(props, 'gb_floors',    4))
    fh      = getattr(props, 'gb_height',   3.0)     # floor-to-floor height
    W       = getattr(props, 'gb_width',    3.5)      # shaft width
    D       = getattr(props, 'gb_depth',    3.5)      # shaft depth
    t       = getattr(props, 'gb_wall_thick', 0.3)
    dw      = getattr(props, 'gb_door_width', 1.2)
    dh      = getattr(props, 'gb_door_height', 2.4)
    parts   = []
    total_h = floors * fh
    depth = _gb_opening_cutter_depth(t)

    n_wall = _gb_box(tree, (W, t, total_h), (0, D * 0.5 - t * 0.5, total_h * 0.5), base_x, 0)
    s_wall = _gb_box(tree, (W, t, total_h), (0, -D * 0.5 + t * 0.5, total_h * 0.5), base_x, 200)
    e_wall = _gb_box(tree, (t, D, total_h), (W * 0.5 - t * 0.5, 0, total_h * 0.5), base_x, 400)
    w_wall = _gb_box(tree, (t, D, total_h), (-W * 0.5 + t * 0.5, 0, total_h * 0.5), base_x, 600)

    door_cutters = []
    for f in range(floors):
        z0 = f * fh
        slab = _gb_box(tree, (W - t * 2, D - t * 2, t), (0, 0, z0 + t * 0.5), base_x, 1200 + f * 120)
        if slab:
            parts.append(slab)
        dcut = _gb_box(tree, (dw, depth, dh), (0, -D * 0.5, z0 + dh * 0.5),
                       base_x + 600, 1200 + f * 120, "door")
        if dcut:
            door_cutters.append(dcut)
        if f > 0:
            rail_style = getattr(props, 'gb_railing_style', 'ADVANCED')
            if rail_style != 'NONE':
                for edge_side in (-1, 1):
                    r = _gb_railing_edge(tree, props, D - t * 2, z0,
                                         edge_side * (W * 0.5 - t), 0,
                                         0 if edge_side > 0 else 3.14159,
                                         20000 + f * 3000 + (edge_side + 1) * 1000, f)
                    if r:
                        parts.append(r)

    cutters_ns, cutters_ew = _gb_collect_window_cutters_elevator_walls(
        tree, props, W, D, t, fh, floors, base_x, 800)
    if n_wall:
        n_wall = _gb_apply_openings_to_wall(tree, n_wall, 'N', cutters_ns, cutters_ew, base_x, 1000)
        parts.append(n_wall)
    if e_wall:
        e_wall = _gb_apply_openings_to_wall(tree, e_wall, 'E', cutters_ns, cutters_ew, base_x, 1100)
        parts.append(e_wall)
    if w_wall:
        w_wall = _gb_apply_openings_to_wall(tree, w_wall, 'W', cutters_ns, cutters_ew, base_x, 1200)
        parts.append(w_wall)
    if s_wall:
        s_wall = _gb_bool_diff(tree, s_wall, door_cutters, base_x + 2000, 600)
        parts.append(s_wall)

    return _gb_join(tree, parts, base_x + 2400, 0)


def build_greybox_combat_room(tree, props, base_x=-1400):
    """FPS combat room: boolean-cut shell (4 doors) + optional window booleans (v2.59.25)
    + elevated area + cover blocks."""
    W  = getattr(props, 'gb_width',       14.0)
    D  = getattr(props, 'gb_depth',       10.0)
    H  = getattr(props, 'gb_height',       4.5)
    t  = getattr(props, 'gb_wall_thick',   0.4)
    dw = getattr(props, 'gb_door_width',   2.0)
    dh = getattr(props, 'gb_door_height',  2.8)
    n_cover = getattr(props, 'gb_cover_count', 4)
    has_elev= getattr(props, 'gb_elevated_area', True)
    parts   = []

    wz = t + (H - t) * 0.5
    wh = H - t
    floor = _gb_box(tree, (W, D, t), (0, 0, t * 0.5), base_x, 0)
    if floor:
        parts.append(floor)

    door_z = t + dh * 0.5
    depth = _gb_opening_cutter_depth(t)
    cutters_ns = [
        ('N', _gb_box(tree, (dw, depth, dh), (0, D * 0.5, door_z), base_x, 100, "door")),
        ('S', _gb_box(tree, (dw, depth, dh), (0, -D * 0.5, door_z), base_x, 200, "door")),
    ]
    cutters_ew = [
        ('E', _gb_box(tree, (depth, dw, dh), (W * 0.5, 0, door_z), base_x, 300, "door")),
        ('W', _gb_box(tree, (depth, dw, dh), (-W * 0.5, 0, door_z), base_x, 400, "door")),
    ]
    if getattr(props, 'gb_windows_enabled', False):
        w_ns, w_ew = _gb_collect_window_cutters_for_rect(
            tree, props, W, D, t, H, base_x, 450)
        cutters_ns.extend(w_ns)
        cutters_ew.extend(w_ew)
    ns_wall = _gb_box(tree, (W, t, wh), (0, D * 0.5 - t * 0.5, wz), base_x, 500)
    ss_wall = _gb_box(tree, (W, t, wh), (0, -D * 0.5 + t * 0.5, wz), base_x, 600)
    ew_wall = _gb_box(tree, (t, D, wh), (W * 0.5 - t * 0.5, 0, wz), base_x, 700)
    ww_wall = _gb_box(tree, (t, D, wh), (-W * 0.5 + t * 0.5, 0, wz), base_x, 800)
    for wall, side in ((ns_wall, 'N'), (ss_wall, 'S'), (ew_wall, 'E'), (ww_wall, 'W')):
        cut = _gb_apply_openings_to_wall(tree, wall, side, cutters_ns, cutters_ew, base_x, 900)
        if cut:
            parts.append(cut)

    # Elevated area (+X side, full width on D, raised platform)
    if has_elev:
        elev_h  = H * 0.35
        elev_w  = W * 0.3
        elev_cx = W * 0.5 - elev_w * 0.5
        parts.append(_gb_box(tree, (elev_w, D - t*2, elev_h),
                             (elev_cx, 0, elev_h * 0.5 + t), base_x, 1200, "level"))
        # Ramp up to elevated area
        import math as _m
        ramp_run = elev_w * 0.5
        ang = _m.atan2(elev_h, ramp_run)
        ramp_len = _m.sqrt(ramp_run**2 + elev_h**2)
        parts.append(_gb_box_node(tree, (D * 0.4, ramp_len, t),
                                  (elev_cx - elev_w*0.5 - ramp_run*0.5, 0, elev_h*0.5 + t*0.5),
                                  (ang, 0, 0), base_x, 1400, "level"))
        # Railing on elevated edge
        rail_style = getattr(props, 'gb_railing_style', 'ADVANCED')
        if rail_style != 'NONE':
            r = _gb_railing_edge(tree, props, D - t*2, elev_h + t,
                                  elev_cx, 0, 0, 25000, 0)
            if r: parts.append(r)

    # Cover blocks in tactical positions (distributed across the floor)
    import random
    rng = random.Random(getattr(props, 'seed', 1) + 99)
    cover_positions = [
        (-W*0.25, -D*0.25), (W*0.25, -D*0.25),
        (0,        D*0.1),
        (-W*0.25,  D*0.15), (W*0.25,  D*0.15),
        (0,       -D*0.3),  (-W*0.1,  0), (W*0.1,  0),
        (-W*0.35,  0),      (W*0.35,   0), (0,  D*0.3), (0, -D*0.1),
    ]
    cover_h = H * 0.28   # waist-high
    for i in range(min(n_cover, len(cover_positions))):
        cx, cy = cover_positions[i]
        cw = rng.uniform(0.8, 1.8)
        cd = rng.uniform(0.4, 0.9)
        parts.append(_gb_box(tree, (cw, cd, cover_h), (cx, cy, cover_h*0.5 + t),
                             base_x, 2000 + i*120, "level"))
        # Top lip
        parts.append(_gb_box(tree, (cw*1.12, cd*1.2, cover_h*0.1),
                             (cx, cy, cover_h + cover_h*0.05 + t),
                             base_x, 2060 + i*120, "level"))

    return _gb_join(tree, parts, base_x + 3000, 0)


def build_greybox_corridor_recursive(tree, props, base_x=-1400):
    """Branching corridor network: main hall + recursive sub-corridors.
    gb_recursive_depth controls levels (0=straight, 1=one branch level, 2=two).
    gb_branch_count controls forks per level (2=binary, 3=trifork).
    All corridors share the same W/H/t; sub-corridors are 80% of parent length."""
    L       = getattr(props, 'gb_length',       8.0)
    W       = getattr(props, 'gb_width',        3.0)
    H       = getattr(props, 'gb_height',       3.5)
    t       = getattr(props, 'gb_wall_thick',   0.3)
    depth   = getattr(props, 'gb_recursive_depth', 1)
    branches= getattr(props, 'gb_branch_count',    2)
    parts   = []

    import math as _m

    def _add_corridor_segment(cx, cy, seg_len, seg_w, angle_rad, level, node_y_base):
        """Add one corridor segment at world position (cx, cy), oriented along angle_rad."""
        dx = _m.cos(angle_rad)
        dy = _m.sin(angle_rad)
        # Local-space: runs along +Y of a rotated transform
        floor = _gb_box_node(tree, (seg_w, seg_len, t),
                             (cx + dx * seg_len * 0.5, cy + dy * seg_len * 0.5, t * 0.5),
                             (0, 0, angle_rad + _m.pi / 2),
                             base_x, node_y_base)
        if floor: parts.append(floor)
        # Left wall
        lw = _gb_box_node(tree, (t, seg_len, H - t),
                          (cx + dx * seg_len * 0.5 + (-dy) * (seg_w * 0.5 - t * 0.5),
                           cy + dy * seg_len * 0.5 + dx * (seg_w * 0.5 - t * 0.5),
                           t + (H - t) * 0.5),
                          (0, 0, angle_rad + _m.pi / 2),
                          base_x, node_y_base + 200)
        if lw: parts.append(lw)
        # Right wall
        rw = _gb_box_node(tree, (t, seg_len, H - t),
                          (cx + dx * seg_len * 0.5 + dy * (seg_w * 0.5 - t * 0.5),
                           cy + dy * seg_len * 0.5 - dx * (seg_w * 0.5 - t * 0.5),
                           t + (H - t) * 0.5),
                          (0, 0, angle_rad + _m.pi / 2),
                          base_x, node_y_base + 400)
        if rw: parts.append(rw)
        if getattr(props, 'gb_ceiling', True):
            ceil = _gb_box_node(tree, (seg_w, seg_len, t),
                                (cx + dx * seg_len * 0.5, cy + dy * seg_len * 0.5, H + t * 0.5),
                                (0, 0, angle_rad + _m.pi / 2),
                                base_x, node_y_base + 600)
            if ceil: parts.append(ceil)
        return (cx + dx * seg_len, cy + dy * seg_len)  # end point

    def _recurse(ox, oy, seg_len, angle, level, node_counter):
        if level < 0 or seg_len < W * 2:
            return node_counter
        end_x, end_y = _add_corridor_segment(ox, oy, seg_len, W, angle, level, node_counter)
        node_counter += 800
        if level > 0:
            sub_len = seg_len * 0.75
            spread  = _m.pi / max(2, branches)
            start_ang = angle - spread * (branches - 1) * 0.5
            for bi in range(branches):
                sub_ang = start_ang + bi * spread
                node_counter = _recurse(end_x, end_y, sub_len, sub_ang, level - 1, node_counter)
        return node_counter

    _recurse(0, 0, L, _m.pi / 2, depth, 0)

    return _gb_join(tree, parts, base_x + 5000, 0)


# ==============================================================================
# 🌀  CURVED ROOM GREYBOX  (v2.55)
#   Arc-plan rooms and corridors. Built from CurveArc→fill+extrude rings
#   so walls follow true circular geometry. All pieces sit at z=0, bottom-center.
# ==============================================================================

def _arc_wall_ring(tree, r_inner, r_outer, h, start_ang, sweep_ang, t_floor, base_x, y_off, label="wall"):
    """Extrude a filled annular sector from r_inner to r_outer, height h.
    Uses CurveArc → offset → fill → extrude. Returns geometry socket."""
    import math as _m
    # Outer arc
    arc_o = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, y_off))
    if arc_o is None:
        return None
    try:
        arc_o.mode = 'RADIUS'
        arc_o.inputs['Radius'].default_value      = r_outer
        arc_o.inputs['Start Angle'].default_value = start_ang
        arc_o.inputs['Sweep Angle'].default_value = sweep_ang
        arc_o.inputs['Resolution'].default_value  = max(8, int(abs(sweep_ang) / _m.pi * 16))
    except Exception: pass
    # Inner arc (reversed)
    arc_i = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, y_off - 200))
    if arc_i:
        try:
            arc_i.mode = 'RADIUS'
            arc_i.inputs['Radius'].default_value      = r_inner
            arc_i.inputs['Start Angle'].default_value = start_ang + sweep_ang
            arc_i.inputs['Sweep Angle'].default_value = -sweep_ang
            arc_i.inputs['Resolution'].default_value  = max(8, int(abs(sweep_ang) / _m.pi * 16))
        except Exception: pass
    # Join the two arcs into a closed curve (annular sector profile)
    jc = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 200, y_off))
    if jc and arc_o and arc_i:
        _link(tree, arc_o.outputs['Curve'], jc.inputs['Geometry'])
        _link(tree, arc_i.outputs['Curve'], jc.inputs['Geometry'])
        color_node(jc, label)
        # Fill → Extrude
        fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 400, y_off))
        if fill:
            try: fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, jc.outputs['Geometry'], fill.inputs['Curve'])
            color_node(fill, label)
            ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 600, y_off))
            if ext:
                ext.mode = 'FACES'
                try: ext.inputs['Offset Scale'].default_value = h
                except Exception: pass
                _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
                color_node(ext, label)
                # Translate up by t_floor so wall sits on floor
                tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 800, y_off))
                if tr:
                    try: tr.inputs['Translation'].default_value = (0, 0, t_floor)
                    except Exception: pass
                    _link(tree, ext.outputs['Mesh'], tr.inputs['Geometry'])
                    color_node(tr, label)
                    return tr.outputs['Geometry']
                return ext.outputs['Mesh']
    return None


def _arc_floor_disc(tree, radius, t, start_ang, sweep_ang, base_x, y_off, label="level"):
    """Filled arc sector slab of thickness t."""
    import math as _m
    arc = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, y_off))
    if arc is None:
        return None
    try:
        arc.mode = 'RADIUS'
        arc.inputs['Radius'].default_value      = radius
        arc.inputs['Start Angle'].default_value = start_ang
        arc.inputs['Sweep Angle'].default_value = sweep_ang
        arc.inputs['Resolution'].default_value  = max(12, int(abs(sweep_ang) / _m.pi * 20))
    except Exception: pass
    fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, y_off))
    if fill is None: return None
    try: fill.mode = 'NGONS'
    except Exception: pass
    _link(tree, arc.outputs['Curve'], fill.inputs['Curve'])
    color_node(fill, label)
    ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, y_off))
    if ext:
        ext.mode = 'FACES'
        try: ext.inputs['Offset Scale'].default_value = t
        except Exception: pass
        _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
        color_node(ext, label)
        # v2.60.1 — floor top at Z=0 (walk plane); extrude rises +Z from curve plane
        if t > 0:
            floor_z = _move(tree, ext.outputs['Mesh'], (base_x + 600, y_off),
                            translation=(0, 0, -t), label=label)
            if floor_z:
                return floor_z
        return ext.outputs['Mesh']
    return fill.outputs['Mesh']


def _arc_floor_ring(tree, r_inner, r_outer, t, start_ang, sweep_ang, base_x, y_off, label="level"):
    """Annular sector floor slab of thickness t; top surface at Z=0 (walk plane)."""
    import math as _m
    arc_o = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, y_off))
    if arc_o is None:
        return None
    try:
        arc_o.mode = 'RADIUS'
        arc_o.inputs['Radius'].default_value = r_outer
        arc_o.inputs['Start Angle'].default_value = start_ang
        arc_o.inputs['Sweep Angle'].default_value = sweep_ang
        arc_o.inputs['Resolution'].default_value = max(8, int(abs(sweep_ang) / _m.pi * 16))
    except Exception:
        pass
    arc_i = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, y_off - 200))
    if arc_i:
        try:
            arc_i.mode = 'RADIUS'
            arc_i.inputs['Radius'].default_value = r_inner
            arc_i.inputs['Start Angle'].default_value = start_ang + sweep_ang
            arc_i.inputs['Sweep Angle'].default_value = -sweep_ang
            arc_i.inputs['Resolution'].default_value = max(8, int(abs(sweep_ang) / _m.pi * 16))
        except Exception:
            pass
    jc = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 200, y_off))
    if not (jc and arc_o and arc_i):
        return None
    _link(tree, arc_o.outputs['Curve'], jc.inputs['Geometry'])
    _link(tree, arc_i.outputs['Curve'], jc.inputs['Geometry'])
    color_node(jc, label)
    fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 400, y_off))
    if not fill:
        return None
    try:
        fill.mode = 'NGONS'
    except Exception:
        pass
    _link(tree, jc.outputs['Geometry'], fill.inputs['Curve'])
    color_node(fill, label)
    ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 600, y_off))
    if not ext:
        return fill.outputs['Mesh']
    ext.mode = 'FACES'
    try:
        ext.inputs['Offset Scale'].default_value = t
    except Exception:
        pass
    _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
    color_node(ext, label)
    if t > 0:
        floor_z = _move(tree, ext.outputs['Mesh'], (base_x + 800, y_off),
                        translation=(0, 0, -t), label=label)
        if floor_z:
            return floor_z
    return ext.outputs['Mesh']


def _gb_collect_door_cutter_circular(tree, props, R, t, base_x, node_y):
    """South-facing door cutter for circular drum wall (boolean through radial depth)."""
    dw = getattr(props, 'gb_door_width', 1.4)
    dh = getattr(props, 'gb_door_height', 2.4)
    depth = _gb_opening_cutter_depth(t)
    door_z = t + dh * 0.5
    door_y = -(R - t * 0.5)
    cutter = _gb_box(tree, (dw, depth, dh), (0, door_y, door_z), base_x, node_y, "door")
    return [cutter] if cutter else []


def _gb_collect_window_cutters_circular(tree, props, R, t, H, base_x, node_y):
    """Evenly spaced window cutters on circular drum — skips south door sector."""
    import math as _m
    if not getattr(props, 'gb_windows_enabled', False):
        return []
    win_w = getattr(props, 'gb_window_width', 0.8)
    win_h = getattr(props, 'gb_window_height', 0.8)
    sill = getattr(props, 'gb_window_sill', 1.0)
    win_z = t + sill + win_h * 0.5
    depth = _gb_opening_cutter_depth(t)
    n = max(1, getattr(props, 'gb_window_count', 2))
    dw = getattr(props, 'gb_door_width', 1.4)
    door_half_ang = _m.asin(min(0.99, (dw * 0.5) / max(0.1, R)))
    door_ang = -_m.pi * 0.5
    skip = door_half_ang * 2.5
    cutters = []
    for i in range(n):
        ang = _m.tau * (i + 0.5) / n
        if abs(((ang - door_ang + _m.pi) % _m.tau) - _m.pi) < skip:
            continue
        cx = _m.cos(ang) * (R - t * 0.5)
        cy = _m.sin(ang) * (R - t * 0.5)
        box_w = max(win_w, depth)
        box_d = max(win_w, depth)
        c = _gb_box(tree, (box_w, box_d, win_h), (cx, cy, win_z), base_x, node_y + i * 40, "door")
        if c:
            cutters.append(c)
    return cutters


def _gb_collect_door_cutter_arc_inner(tree, props, R_inner, t, base_x, node_y, door_ang=0.0):
    """Door cutter at given angle on inner arc corridor wall (default sweep start)."""
    import math as _m
    dw = getattr(props, 'gb_door_width', 1.4)
    dh = getattr(props, 'gb_door_height', 2.4)
    depth = _gb_opening_cutter_depth(t)
    door_z = t + dh * 0.5
    R_mid = R_inner + t * 0.5
    if abs(door_ang) < 1e-9:
        cutter = _gb_box(tree, (depth, dw, dh), (R_mid, 0, door_z), base_x, node_y, "door")
    else:
        cx = _m.cos(door_ang) * R_mid
        cy = _m.sin(door_ang) * R_mid
        cutter = _gb_box_node(tree, (depth, dw, dh), (cx, cy, door_z), (0, 0, door_ang),
                              base_x, node_y, "door")
    return [cutter] if cutter else []


def _gb_collect_window_cutters_arc_inner(tree, props, R_inner, t, H, sweep, base_x, node_y,
                                         door_ang=0.0):
    """Evenly spaced window cutters on arc corridor inner wall — skips door sector."""
    import math as _m
    if not getattr(props, 'gb_windows_enabled', False):
        return []
    win_w = getattr(props, 'gb_window_width', 0.8)
    win_h = getattr(props, 'gb_window_height', 0.8)
    sill = getattr(props, 'gb_window_sill', 1.0)
    win_z = t + sill + win_h * 0.5
    depth = _gb_opening_cutter_depth(t)
    n = max(1, getattr(props, 'gb_window_count', 2))
    dw = getattr(props, 'gb_door_width', 1.4)
    R_mid = R_inner + t * 0.5
    door_half_ang = _m.asin(min(0.99, (dw * 0.5) / max(0.1, R_mid)))
    skip = door_half_ang * 2.5
    arc_span = max(0.0, sweep - 2 * skip)
    if arc_span < 1e-6:
        return []
    cutters = []
    for i in range(n):
        ang = door_ang + skip + arc_span * (i + 0.5) / n
        cx = _m.cos(ang) * R_mid
        cy = _m.sin(ang) * R_mid
        box_w = max(win_w, depth)
        box_d = max(win_w, depth)
        if abs(ang) < 1e-9:
            c = _gb_box(tree, (box_w, box_d, win_h), (R_mid, 0, win_z), base_x, node_y + i * 40, "door")
        else:
            c = _gb_box_node(tree, (depth, win_w, win_h), (cx, cy, win_z), (0, 0, ang),
                             base_x, node_y + i * 40, "door")
        if c:
            cutters.append(c)
    return cutters


def _gb_apply_arc_inner_openings(tree, wall_geom, props, R_inner, t, base_x, node_y, door_ang=0.0,
                                 H=None, sweep=None):
    """Boolean door + optional windows on arc corridor inner wall."""
    cutters = _gb_collect_door_cutter_arc_inner(tree, props, R_inner, t, base_x, node_y, door_ang)
    if H is not None and sweep is not None:
        cutters.extend(_gb_collect_window_cutters_arc_inner(
            tree, props, R_inner, t, H, sweep, base_x, node_y + 100, door_ang))
    if wall_geom is None or not cutters:
        return wall_geom
    return _gb_bool_diff(tree, wall_geom, cutters, base_x + 1000, node_y)


def _gb_apply_circular_openings(tree, wall_geom, props, R, t, H, base_x, node_y):
    """Boolean door + optional windows on full circular drum wall ring."""
    cutters = _gb_collect_door_cutter_circular(tree, props, R, t, base_x, node_y)
    cutters.extend(_gb_collect_window_cutters_circular(tree, props, R, t, H, base_x, node_y + 100))
    if wall_geom is None or not cutters:
        return wall_geom
    return _gb_bool_diff(tree, wall_geom, cutters, base_x + 1000, node_y)


def _gb_collect_window_cutters_outer_ring(tree, props, R_outer, t, H, base_x, node_y, R_inner=None):
    """Evenly spaced circular window cutters on gallery outer wall face (v2.59.24).

    Gallery annulus spans R_inner to R_outer; cutters sit on the outer wall midline."""
    import math as _m
    if not getattr(props, 'gb_windows_enabled', False):
        return []
    win_w = getattr(props, 'gb_window_width', 0.8)
    win_h = getattr(props, 'gb_window_height', 0.8)
    sill = getattr(props, 'gb_window_sill', 1.0)
    win_z = t + sill + win_h * 0.5
    depth = _gb_opening_cutter_depth(t)
    n = max(1, getattr(props, 'gb_window_count', 2))
    if R_inner is not None and R_inner >= R_outer:
        return []
    R_mid = R_outer - t * 0.5
    cutters = []
    for i in range(n):
        ang = _m.tau * (i + 0.5) / n
        cx = _m.cos(ang) * R_mid
        cy = _m.sin(ang) * R_mid
        box_w = max(win_w, depth)
        box_d = max(win_w, depth)
        c = _gb_box(tree, (box_w, box_d, win_h), (cx, cy, win_z), base_x, node_y + i * 40, "door")
        if c:
            cutters.append(c)
    return cutters


def _gb_apply_gallery_openings(tree, wall_geom, props, R_outer, gallery_w, t, H, base_x, node_y):
    """Boolean window cuts on upper gallery outer wall ring (v2.59.24).

    Gallery annulus: R_inner = R_outer - gallery_w through R_outer."""
    R_inner = R_outer - gallery_w
    cutters = _gb_collect_window_cutters_outer_ring(
        tree, props, R_outer, t, H, base_x, node_y, R_inner=R_inner)
    if wall_geom is None or not cutters:
        return wall_geom
    return _gb_bool_diff(tree, wall_geom, cutters, base_x + 1000, node_y)


def build_gb_room_circular(tree, props, base_x=-1400):
    """Circular greybox room: curved perimeter wall + floor disc + optional ceiling.
    Door opening on the south face via boolean cutters (v2.59.12). Perfect for towers,
    rotundas, arena centres.
    Parameters: gb_width=diameter, gb_height=wall height, gb_wall_thick, gb_door_width."""
    import math as _m
    R   = getattr(props, 'gb_width', 6.0) * 0.5   # radius
    H   = getattr(props, 'gb_height', 3.5)
    t   = getattr(props, 'gb_wall_thick', 0.3)
    parts = []

    # Floor disc
    floor = _arc_floor_disc(tree, R, t, 0, _m.tau, base_x, 0)
    if floor: parts.append(floor)

    # Perimeter wall — full ring, door/windows boolean-cut (replaces arc gap v2.55)
    wall = _arc_wall_ring(tree, R - t, R, H, 0, _m.tau, t, base_x, -400)
    wall = _gb_apply_circular_openings(tree, wall, props, R, t, H, base_x, -400)
    if wall: parts.append(wall)

    # Optional ceiling
    if getattr(props, 'gb_ceiling', True):
        ceil = _arc_floor_disc(tree, R, t, 0, _m.tau, base_x, -800, "ceiling")
        tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 650, -800))
        if tr and ceil:
            try: tr.inputs['Translation'].default_value = (0, 0, H + t)
            except Exception: pass
            _link(tree, ceil, tr.inputs['Geometry'])
            color_node(tr, "ceiling")
            parts.append(tr.outputs['Geometry'])

    return _gb_join(tree, parts, base_x + 1400, 0)


def build_gb_room_apsidal(tree, props, base_x=-1400):
    """Apsidal Room: rectangular nave with one semicircular apse end.
    The classic cathedral / Roman basilica plan. Door on south (flat) wall.
    Parameters: gb_width=nave width, gb_depth=nave length, gb_height."""
    import math as _m
    W   = getattr(props, 'gb_width',  6.0)
    D   = getattr(props, 'gb_depth',  W * 1.4) if hasattr(props, 'gb_depth') else W * 1.4
    H   = getattr(props, 'gb_height', 4.0)
    t   = getattr(props, 'gb_wall_thick', 0.3)
    dw  = getattr(props, 'gb_door_width', 1.4)
    dh  = getattr(props, 'gb_door_height', 2.6)
    R   = W * 0.5   # apse radius = half nave width
    parts = []

    wh  = H - t
    wz  = t + wh * 0.5

    # ── Rectangular nave portion ─────────────────────────────────────
    # Nave starts at y=0, ends at y=D
    # N wall (top of nave, where apse begins) — no door, full width
    parts.append(_gb_box(tree, (W + t*2, t, wh), (0, D*0.5+t*0.5, wz), base_x, 200))
    # S wall (entry) — boolean door cut through solid wall (v2.59.14)
    door_z = t + dh * 0.5
    depth = _gb_opening_cutter_depth(t)
    sw_wall = _gb_box(tree, (W, t, wh), (0, -D*0.5 - t*0.5, wz), base_x, 350)
    cutters_ns = [
        ('S', _gb_box(tree, (dw, depth, dh), (0, -D*0.5, door_z), base_x, 380, "door")),
    ]
    sw_cut = _gb_apply_openings_to_wall(tree, sw_wall, 'S', cutters_ns, [], base_x, 400)
    if sw_cut:
        parts.append(sw_cut)
    # E and W walls — optional boolean window cuts (v2.59.17)
    if getattr(props, 'gb_windows_enabled', False):
        class _ApsidalWinProps:
            pass
        win_props = _ApsidalWinProps()
        win_props.gb_windows_enabled = True
        win_props.gb_window_width = getattr(props, 'gb_window_width', 0.8)
        win_props.gb_window_height = getattr(props, 'gb_window_height', 0.8)
        win_props.gb_window_sill = getattr(props, 'gb_window_sill', 1.0)
        win_props.gb_window_count_ns = 0
        win_props.gb_window_count_ew = max(1, getattr(props, 'gb_window_count', 2))
        _, cutters_ew = _gb_collect_window_cutters_for_rect(
            tree, win_props, W, D, t, H, base_x, 500, 0, 0)
        for sx, side in ((-1, 'W'), (1, 'E')):
            ew_wall = _gb_box(tree, (t, D, wh), (sx * (W * 0.5 + t * 0.5), 0, wz),
                              base_x, 700 + (sx + 1) * 100)
            ew_cut = _gb_apply_openings_to_wall(
                tree, ew_wall, side, [], cutters_ew, base_x, 750 + (sx + 1) * 100)
            if ew_cut:
                parts.append(ew_cut)
    else:
        for sx in (-1, 1):
            parts.append(_gb_box(tree, (t, D, wh), (sx * (W * 0.5 + t * 0.5), 0, wz),
                                 base_x, 700 + (sx + 1) * 100))
    # Nave floor
    parts.append(_gb_box(tree, (W, D, t), (0, 0, t*0.5), base_x, 900))

    # ── Semicircular apse (north end) ────────────────────────────────
    apse_y_ctr = D * 0.5   # apse centre = top of nave
    # Apse wall ring
    apse_wall = _arc_wall_ring(tree, R - t, R, H, 0, _m.pi, 0, base_x, -600)
    if apse_wall:
        tr_aw = _safe_node(tree, 'GeometryNodeTransform', (base_x + 1050, -600))
        if tr_aw:
            try: tr_aw.inputs['Translation'].default_value = (0, apse_y_ctr, 0)
            except Exception: pass
            _link(tree, apse_wall, tr_aw.inputs['Geometry'])
            color_node(tr_aw, "wall")
            parts.append(tr_aw.outputs['Geometry'])
    # Apse floor
    apse_floor = _arc_floor_disc(tree, R, t, 0, _m.pi, base_x, -800)
    if apse_floor:
        tr_af = _safe_node(tree, 'GeometryNodeTransform', (base_x + 650, -800))
        if tr_af:
            try: tr_af.inputs['Translation'].default_value = (0, apse_y_ctr, 0)
            except Exception: pass
            _link(tree, apse_floor, tr_af.inputs['Geometry'])
            color_node(tr_af, "level")
            parts.append(tr_af.outputs['Geometry'])

    # Optional ceiling
    if getattr(props, 'gb_ceiling', False):
        parts.append(_gb_box(tree, (W, D, t), (0, 0, H+t*0.5), base_x, 1300, "ceiling"))
        ceil_apse = _arc_floor_disc(tree, R, t, 0, _m.pi, base_x, -1000, "ceiling")
        if ceil_apse:
            tr_ca = _safe_node(tree, 'GeometryNodeTransform', (base_x + 650, -1000))
            if tr_ca:
                try: tr_ca.inputs['Translation'].default_value = (0, apse_y_ctr, H+t)
                except Exception: pass
                _link(tree, ceil_apse, tr_ca.inputs['Geometry'])
                color_node(tr_ca, "ceiling")
                parts.append(tr_ca.outputs['Geometry'])

    return _gb_join(tree, parts, base_x + 2000, 0)


def build_gb_corridor_arc(tree, props, base_x=-1400):
    """Arc Corridor: a curved hallway that sweeps through a configurable angle.
    Plan is an annular sector. Inner wall: full sector + boolean door at sweep start (v2.59.21)
    + optional window booleans (v2.59.24).
    Parameters: gb_width=corridor clear width, gb_height, gb_wall_thick,
    gb_radius (inner radius), gb_steps (arc sweep degrees, default 90), gb_door_width."""
    import math as _m
    W       = getattr(props, 'gb_width',     2.8)   # clear interior width
    H       = getattr(props, 'gb_height',    3.5)
    t       = getattr(props, 'gb_wall_thick',0.3)
    R_inner = getattr(props, 'gb_radius',    5.0)   # inner wall radius
    sweep   = _m.radians(getattr(props, 'gb_steps', 90))   # arc angle
    R_outer = R_inner + W + t * 2
    parts   = []

    # Floor slab (annular sector)
    floor = _arc_floor_disc(tree, R_outer, t, 0, sweep, base_x, 0)
    # Cut inner disc — approximate with full floor - inner void
    # (true boolean not available in GN, so build floor as ring)
    floor_ring = _arc_floor_ring(tree, R_inner + t, R_outer - t, t, 0, sweep, base_x, 200, "level")
    if floor_ring: parts.append(floor_ring)

    # Inner curved wall — full sector + boolean door/windows (v2.59.21 / v2.59.24)
    inner_wall = _arc_wall_ring(tree, R_inner, R_inner + t, H, 0, sweep, t, base_x, -200)
    inner_wall = _gb_apply_arc_inner_openings(
        tree, inner_wall, props, R_inner, t, base_x, -200, door_ang=0.0, H=H, sweep=sweep)
    if inner_wall: parts.append(inner_wall)

    # Outer curved wall
    outer_wall = _arc_wall_ring(tree, R_outer - t, R_outer, H, 0, sweep, t, base_x, -500)
    if outer_wall: parts.append(outer_wall)

    # Flat end caps at both ends of the arc
    for ang in [0, sweep]:
        cos_a = _m.cos(ang)
        sin_a = _m.sin(ang)
        cap_cx = ((R_inner + R_outer) * 0.5) * cos_a
        cap_cy = ((R_inner + R_outer) * 0.5) * sin_a
        cap_len = R_outer - R_inner
        parts.append(_gb_box_node(tree, (cap_len, t, H),
                                  (cap_cx, cap_cy, t + H * 0.5),
                                  (0, 0, ang),
                                  base_x, -800 + int(ang * 100), "wall"))

    # Optional ceiling ring
    if getattr(props, 'gb_ceiling', True):
        ceil_ring = _arc_wall_ring(tree, R_inner + t, R_outer - t, t, 0, sweep, H, base_x, -1100, "ceiling")
        if ceil_ring: parts.append(ceil_ring)

    return _gb_join(tree, parts, base_x + 1600, 0)


def build_gb_room_rotunda(tree, props, base_x=-1400):
    """Rotunda: multi-story circular room with an upper gallery ring.
    Ground floor: full-radius open drum with boolean door + optional windows (v2.59.20).
    Upper gallery: narrow annular ring (R - gallery_w to R) with optional outer-wall
    window booleans when gb_windows_enabled (v2.59.24).
    Central open shaft connects the floors. Inspired by the Pantheon + neoclassical domed halls.
    Parameters: gb_width=outer diameter, gb_height=per-floor height, gb_floors, gb_wall_thick,
    gb_run (gallery depth ratio 0.1-0.4), gb_windows_enabled + window dims for ground + gallery."""
    import math as _m
    R       = getattr(props, 'gb_width', 8.0) * 0.5
    fh      = getattr(props, 'gb_height', 4.0)
    floors  = min(4, max(2, getattr(props, 'gb_floors', 2)))
    t       = getattr(props, 'gb_wall_thick', 0.35)
    gallery = getattr(props, 'gb_run', 0.25)   # gallery depth as fraction of R
    gallery_w = R * gallery
    parts   = []

    for f in range(floors):
        z0 = f * fh
        is_ground = (f == 0)
        r_inner_wall = R - t if is_ground else R - gallery_w - t
        r_outer_wall = R

        # Wall ring — ground: door/windows; upper gallery: outer-wall window booleans (v2.59.24)
        ring = _arc_wall_ring(tree, r_inner_wall, r_outer_wall, fh, 0, _m.tau, 0 if is_ground else z0, base_x, -f*600)
        if is_ground:
            ring = _gb_apply_circular_openings(tree, ring, props, R, t, fh, base_x, -f*600)
        else:
            ring = _gb_apply_gallery_openings(tree, ring, props, R, gallery_w, t, fh, base_x, -f*600)
        if ring:
            if f > 0:
                tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 1000, -f*600))
                if tr:
                    try: tr.inputs['Translation'].default_value = (0, 0, z0)
                    except Exception: pass
                    _link(tree, ring, tr.inputs['Geometry'])
                    color_node(tr, "tower")
                    parts.append(tr.outputs['Geometry'])
            else:
                parts.append(ring)

        # Floor slab
        if is_ground:
            fl = _arc_floor_disc(tree, R, t, 0, _m.tau, base_x, -f*600 - 300)
            if fl:
                tr2 = _safe_node(tree, 'GeometryNodeTransform', (base_x + 650, -f*600-300))
                if tr2:
                    try: tr2.inputs['Translation'].default_value = (0, 0, z0)
                    except Exception: pass
                    _link(tree, fl, tr2.inputs['Geometry'])
                    color_node(tr2, "level")
                    parts.append(tr2.outputs['Geometry'])
        else:
            # Gallery floor ring (annular) — v2.60.3: _arc_floor_ring for walk-plane top at Z=0
            gfl = _arc_floor_ring(
                tree, R - gallery_w, R, t, 0, _m.tau, base_x, -f*600-400, "level")
            if gfl:
                tr3 = _safe_node(tree, 'GeometryNodeTransform', (base_x + 1000, -f*600-400))
                if tr3:
                    try: tr3.inputs['Translation'].default_value = (0, 0, z0)
                    except Exception: pass
                    _link(tree, gfl, tr3.inputs['Geometry'])
                    color_node(tr3, "level")
                    parts.append(tr3.outputs['Geometry'])

    # Central oculus dome cap (flattened sphere top)
    dome = _safe_node(tree, 'GeometryNodeMeshUVSphere', (base_x, -floors*600 - 200))
    if dome:
        try:
            dome.inputs['Radius'].default_value   = R * 0.85
            dome.inputs['Segments'].default_value = 32
            dome.inputs['Rings'].default_value    = 12
        except Exception: pass
        color_node(dome, "ceiling")
        dome_t = _move(tree, dome.outputs['Mesh'], (base_x + 200, -floors*600-200),
                       translation=(0, 0, floors * fh + R * 0.4), label="ceiling")
        if dome_t: parts.append(dome_t)

    return _gb_join(tree, parts, base_x + 2000, 0)


def build_gb_corridor_arc_cross(tree, props, base_x=-1400):
    """Curved Cross: four arc corridor arms meeting at a circular hub room.
    The hub is a small circular room; each arm sweeps 90°. Together they make
    a rounded X-junction — great for sci-fi space stations, castle roundels.
    Inner arm walls: full sector rings + boolean door at hub junction (v2.59.22)
    + optional window booleans when gb_windows_enabled (v2.59.24).
    Parameters: gb_width (arm width), gb_radius (arm curve radius), gb_height,
    gb_door_width, gb_door_height."""
    import math as _m
    W   = getattr(props, 'gb_width',      2.4)
    H   = getattr(props, 'gb_height',     3.5)
    t   = getattr(props, 'gb_wall_thick', 0.3)
    R   = getattr(props, 'gb_radius',     4.0)
    parts = []

    # Central hub (small circular room)
    hub_r = W * 0.8
    hub_wall = _arc_wall_ring(tree, hub_r - t, hub_r, H, 0, _m.tau, 0, base_x, 0)
    if hub_wall: parts.append(hub_wall)
    hub_floor = _arc_floor_disc(tree, hub_r, t, 0, _m.tau, base_x, -300)
    if hub_floor: parts.append(hub_floor)

    # Four arms at N/S/E/W — annular 90° sectors rooted at hub_r (v2.60: no double offset)
    arm_len = max(W * 2.0, R)
    arm_configs = [(0, 0), (_m.pi * 0.5, 0), (_m.pi, 0), (_m.pi * 1.5, 0)]
    for ai, (yaw, _) in enumerate(arm_configs):
        R_in = hub_r
        sweep = _m.pi * 0.5
        start = yaw - sweep * 0.5

        in_w = _arc_wall_ring(tree, R_in, R_in + t, H, start, sweep, 0, base_x, -600 - ai * 500)
        in_w = _gb_apply_arc_inner_openings(
            tree, in_w, props, R_in, t, base_x, -600 - ai * 500,
            door_ang=yaw, H=H, sweep=sweep)
        out_w = _arc_wall_ring(
            tree, R_in + arm_len, R_in + arm_len + t, H, start, sweep, 0,
            base_x, -800 - ai * 500)
        fl = _arc_floor_ring(
            tree, R_in, R_in + arm_len + t, t, start, sweep,
            base_x, -1000 - ai * 500, "level")
        for g in (in_w, out_w, fl):
            if g:
                parts.append(g)

    return _gb_join(tree, parts, base_x + 2200, 0)


# ==============================================================================
# 🪝  M.C. ESCHER GREYBOX PRESETS  (v2.52)
#   Solid, traversable level geometry inspired by Escher's impossible architecture.
#   Each piece works as a standalone room/connector in a game level.
# ==============================================================================

def build_gb_escher_relativity(tree, props, base_x=-1400):
    """Relativity Room: a chamber where 3 gravity directions coexist.
    Three staircases occupy the floor, one side wall, and the ceiling.
    Based on Escher's 'Relativity' (1953)."""
    import math as _m
    S    = getattr(props, 'gb_width',    10.0)    # room size (cube room)
    t    = getattr(props, 'gb_wall_thick', 0.3)
    H    = S                                       # cubic chamber
    n    = getattr(props, 'gb_steps',    8)
    rise = H * 0.6 / max(1, n)
    run  = S * 0.5 / max(1, n)
    parts = []

    # ── Outer chamber shell (floor + 4 walls + ceiling) ─────────────
    parts.append(_gb_box(tree, (S, S, t),  (0, 0, t*0.5),     base_x, 0))           # floor
    parts.append(_gb_box(tree, (S, S, t),  (0, 0, H+t*0.5),   base_x, 200, "ceiling"))  # ceiling
    parts.append(_gb_box(tree, (S, t, H),  (0,  S*0.5, H*0.5), base_x, 400))        # N wall
    parts.append(_gb_box(tree, (S, t, H),  (0, -S*0.5, H*0.5), base_x, 600))        # S wall
    parts.append(_gb_box(tree, (t, S, H),  ( S*0.5, 0, H*0.5), base_x, 800))        # E wall
    parts.append(_gb_box(tree, (t, S, H),  (-S*0.5, 0, H*0.5), base_x, 1000))       # W wall

    # ── Central landing hub ──────────────────────────────────────────
    hub_s = S * 0.25
    parts.append(_gb_box(tree, (hub_s, hub_s, t*2), (0, 0, H*0.5), base_x, 1200, "level"))

    # ── Staircase A: normal gravity — floor, running +Y ──────────────
    stair_w = S * 0.28
    ox_a, oy_a = -S*0.2, -S*0.3
    for i in range(n):
        sz_top = t + (i + 1) * rise
        sy_c   = oy_a + i * run + run * 0.5
        parts.append(_gb_box(tree, (stair_w, run, sz_top),
                             (ox_a, sy_c, sz_top * 0.5),
                             base_x, 1400 + i * 80, "level"))

    # ── Staircase B: E-wall gravity — climbs up the +X wall ──────────
    # In E-wall-gravity, "floor" = east wall. Steps climb toward -Z as
    # seen from the room, but along the wall surface toward +Z of room.
    # We rotate step blocks: each step is a _gb_box_node rotated 90° around Y.
    for i in range(n):
        step_depth = t + (i + 1) * rise
        sy_b = S*0.1 + i * run + run * 0.5
        # Step block lying against the E wall, rotated so its "up" is +X
        parts.append(_gb_box_node(tree,
            (step_depth, stair_w, run),
            (S*0.5 - step_depth*0.5, sy_b, H*0.55 - i*rise),
            (0, _m.radians(90), 0),
            base_x, 2200 + i * 80, "level"))

    # ── Staircase C: ceiling gravity — hangs from the ceiling, runs -Y ─
    # Ceiling gravity: upside-down. Steps hang down from ceiling,
    # each slightly lower. Rotated 180° around the X axis.
    for i in range(n):
        sz_hang = t + (i + 1) * rise
        sy_c2   = S*0.3 - i * run - run * 0.5
        parts.append(_gb_box_node(tree,
            (stair_w, run, sz_hang),
            (S*0.15, sy_c2, H - sz_hang*0.5),
            (_m.pi, 0, 0),
            base_x, 3000 + i * 80, "ceiling"))

    # ── Arch connectors from each staircase top to hub ───────────────
    for (ax, ay, az) in [(-S*0.2, oy_a + n*run, t + n*rise),
                          (S*0.5 - (t + n*rise), S*0.1 + n*run, H*0.55 - n*rise + run),
                          (S*0.15, S*0.3 - n*run, H - t - n*rise)]:
        dx = -ax;  dy = -ay;  dz = H*0.5 - az
        ln = _m.sqrt(dx*dx + dy*dy + dz*dz)
        if ln > 0.1:
            parts.append(_gb_box(tree, (0.2, 0.2, max(0.2, ln)),
                                 ((ax + 0)/2, (ay + 0)/2, (az + H*0.5)/2),
                                 base_x, 3800, "level"))

    return _gb_join(tree, parts, base_x + 4500, 0)


def build_gb_escher_penrose_loop(tree, props, base_x=-1400):
    """Penrose Loop: a square rooftop ring of ascending stairs that paradoxically
    returns to its own starting height. Solid walkable step blocks arranged on a
    rooftop shell. Based on Escher's 'Ascending and Descending' (1960).
    In-game use: rooftop of a keep, puzzle level, impossible citadel."""
    import math as _m
    side   = getattr(props, 'gb_width',   8.0)     # outer side length
    W_cor  = getattr(props, 'gb_depth',   2.5)     # corridor/stair width
    n      = getattr(props, 'gb_steps',   10)      # steps per side
    rise   = getattr(props, 'gb_rise',    0.22)    # step rise
    run    = (side - W_cor * 2) / n                # step run
    t      = getattr(props, 'gb_wall_thick', 0.28)
    H_base = getattr(props, 'gb_height',  0.4)     # floor thickness under stairs
    outer_wall_h = 1.4                             # parapet height
    parts  = []

    # ── Rooftop base slab ────────────────────────────────────────────
    inner = side - W_cor * 2
    parts.append(_gb_box(tree, (side, side, t), (0, 0, t*0.5), base_x, 0, "level"))
    # Inner courtyard void (leave open — no geometry inside the ring)

    # ── Four staircase arms, each climbing n*rise ────────────────────
    # Arm 0: +Y face, steps go +X (CW when viewed from above)
    # Arm 1: +X face, steps go -Y
    # Arm 2: -Y face, steps go -X
    # Arm 3: -X face, steps go +Y
    # Z offset per arm: each arm starts where the previous one left off
    arm_configs = [
        # (arm_cx, arm_cy, step_dx, step_dy, corner_x, corner_y, rot_z)
        ( 0,        side*0.5 - W_cor*0.5,   run, 0,   side*0.5,  side*0.5,  0),
        ( side*0.5 - W_cor*0.5,  0,    0,  -run,  side*0.5, -side*0.5,  _m.pi*0.5),
        ( 0,       -side*0.5 + W_cor*0.5,  -run, 0,  -side*0.5, -side*0.5,  _m.pi),
        (-side*0.5 + W_cor*0.5,  0,    0,   run, -side*0.5,  side*0.5,  _m.pi*1.5),
    ]
    for ai, (cx, cy, sdx, sdy, crn_x, crn_y, rot_z) in enumerate(arm_configs):
        base_z = ai * n * rise   # each arm starts higher

        # Step solids for this arm
        for si in range(n):
            step_z_top = base_z + (si + 1) * rise
            sx = cx + sdx * (si + 0.5 if abs(sdx) > 0 else 0)
            sy = cy + sdy * (si + 0.5 if abs(sdy) > 0 else 0)

            # Step box: extends from z=0 to z=step_z_top (solid wedge effect)
            if abs(sdx) > 0:
                bw, bd = run, W_cor
                bx_c, by_c = cx + sdx * (si + 0.5), cy
            else:
                bw, bd = W_cor, run
                bx_c, by_c = cx, cy + sdy * (si + 0.5)

            parts.append(_gb_box(tree, (bw, bd, step_z_top),
                                 (bx_c, by_c, step_z_top * 0.5),
                                 base_x, ai * 2000 + si * 80, "level"))

        # Corner landing block
        corner_z = base_z + n * rise + rise
        parts.append(_gb_box(tree, (W_cor, W_cor, corner_z),
                             (crn_x - _m.copysign(W_cor*0.5, crn_x),
                              crn_y - _m.copysign(W_cor*0.5, crn_y),
                              corner_z * 0.5),
                             base_x, 8100 + ai * 100, "level"))

    # ── Outer parapet (4 short walls around loop perimeter) ──────────
    total_z = 4 * n * rise
    for (pw, pd, px, py) in [
        (side, t, 0,       side*0.5),   # N
        (side, t, 0,      -side*0.5),   # S
        (t, side, side*0.5, 0),         # E
        (t, side,-side*0.5, 0),         # W
    ]:
        parts.append(_gb_box(tree, (pw, pd, outer_wall_h),
                             (px, py, total_z + outer_wall_h*0.5),
                             base_x, 9000 + len(parts)*50, "wall"))

    # ── Supporting structure below (tower walls) ─────────────────────
    if getattr(props, 'gb_ceiling', True):   # repurpose ceiling flag = add tower walls
        tower_h = getattr(props, 'gb_height', 6.0)
        for (tw, td, tx, ty) in [
            (side, t, 0,       side*0.5),
            (side, t, 0,      -side*0.5),
            (t, side, side*0.5, 0),
            (t, side,-side*0.5, 0),
        ]:
            parts.append(_gb_box(tree, (tw, td, tower_h),
                                 (tx, ty, -tower_h*0.5),
                                 base_x, 10000 + len(parts)*50, "wall"))

    return _gb_join(tree, parts, base_x + 5000, 0)


def build_gb_escher_gravity_shift(tree, props, base_x=-1400):
    """Gravity Shift Corridor: a corridor that progressively rotates 90° around
    its own travel axis. You enter with the floor underfoot; you exit with the
    original floor as the left wall. 5 discrete sections.
    In-game use: portal room, anti-gravity zone, puzzle transition."""
    import math as _m
    L    = getattr(props, 'gb_length',   12.0)    # total length
    W    = getattr(props, 'gb_width',     3.0)    # corridor cross-section
    H    = getattr(props, 'gb_height',    3.0)    # corridor cross-section (= W for square)
    t    = getattr(props, 'gb_wall_thick', 0.25)
    n_segs = 5                                     # 5 rotation steps: 0°,22.5°,45°,67.5°,90°
    seg_l  = L / n_segs
    parts  = []

    for si in range(n_segs):
        ang   = si * (_m.pi / 2) / (n_segs - 1)   # 0° → 90° over 5 steps
        cos_a = _m.cos(ang)
        sin_a = _m.sin(ang)
        y_ctr = -L*0.5 + seg_l * (si + 0.5)

        # The corridor cross-section at this point:
        # Floor, ceiling, left wall, right wall — all rotated by `ang` around Y (travel axis)
        for (role, lx, lz, bw, bh, color) in [
            # (role, local_x_center, local_z_center, box_W, box_H, color)
            ("floor",   0,        -H*0.5,  W,    t,    "level"),
            ("ceiling", 0,         H*0.5,  W,    t,    "ceiling"),
            ("left",   -W*0.5,     0,      t,    H,    "level"),
            ("right",   W*0.5,     0,      t,    H,    "level"),
        ]:
            # Rotate this panel around Y (the travel axis through the corridor centre)
            # Local: (lx, 0, lz) → rotated → (lx*cos_a - lz*sin_a, 0, lx*sin_a + lz*cos_a)
            rx = lx * cos_a - lz * sin_a
            rz = lx * sin_a + lz * cos_a + H*0.5  # shift up so z=0 is ground

            # Box dimensions also rotate: swap W/H for the panel
            if abs(ang - _m.pi/4) < 0.1 or abs(ang - _m.pi*3/4) < 0.1:
                box_sz = (max(bw, bh), seg_l, max(bw, bh))
            else:
                box_sz = (bw, seg_l, bh)

            piece = _gb_box_node(tree, box_sz,
                                 (rx, y_ctr, rz),
                                 (0, ang, 0),
                                 base_x, si * 400 + len(parts) * 60, color)
            if piece: parts.append(piece)

    # ── Entry label: floor markers ────────────────────────────────────
    # Arrow hint on entry floor (thin dark slab)
    parts.append(_gb_box(tree, (W*0.3, seg_l*0.4, t*0.5),
                         (0, -L*0.5 + seg_l*0.25, t*1.05),
                         base_x, 9000, "door"))

    return _gb_join(tree, parts, base_x + 3600, 0)


def build_gb_escher_belvedere(tree, props, base_x=-1400):
    """Belvedere: a 2-story open loggia where the upper floor's columns connect
    to the WRONG corners of the lower floor. The X-crossing beams at the top
    create Escher's canonical impossible building frame.
    Based on Escher's 'Belvedere' (1958).
    In-game use: courtyard, impossible castle courtyard, puzzle hub."""
    import math as _m
    W   = getattr(props, 'gb_width',   6.0)
    D   = getattr(props, 'gb_depth',   6.0) if hasattr(props, 'gb_depth') else W
    H1  = getattr(props, 'gb_height',  3.5)    # lower floor height
    H2  = H1                                    # upper floor height (= lower)
    t   = getattr(props, 'gb_wall_thick', 0.35)
    col_s = t * 1.5
    parts = []

    # ── Ground floor slab + upper floor slab ────────────────────────
    parts.append(_gb_box(tree, (W, D, t), (0, 0,         t*0.5),        base_x,  0))
    parts.append(_gb_box(tree, (W, D, t), (0, 0, H1    + t*0.5),        base_x, 200, "level"))
    parts.append(_gb_box(tree, (W, D, t), (0, 0, H1+H2 + t*0.5),        base_x, 400, "ceiling"))

    # ── Lower floor: 4 normal columns at corners ─────────────────────
    corners = [(-W*0.5+col_s*0.5, -D*0.5+col_s*0.5),
               ( W*0.5-col_s*0.5, -D*0.5+col_s*0.5),
               ( W*0.5-col_s*0.5,  D*0.5-col_s*0.5),
               (-W*0.5+col_s*0.5,  D*0.5-col_s*0.5)]
    for i, (cx, cy) in enumerate(corners):
        parts.append(_gb_box(tree, (col_s, col_s, H1),
                             (cx, cy, H1*0.5 + t),
                             base_x, 600 + i*100, "pillar"))

    # ── Upper floor: 4 columns connecting to OPPOSITE corners ────────
    # Escher's twist: column at NW bottom connects to SE top, etc.
    # Pairs: (0→2), (1→3), (2→0), (3→1) — each column is diagonal
    opp_corners = [corners[2], corners[3], corners[0], corners[1]]
    for i, ((bx_lo, by_lo), (bx_hi, by_hi)) in enumerate(zip(corners, opp_corners)):
        # Diagonal column from (bx_lo, by_lo, H1+t) to (bx_hi, by_hi, H1+H2+t)
        mx, my = (bx_lo + bx_hi) * 0.5, (by_lo + by_hi) * 0.5
        mz = H1 + H2*0.5 + t
        dx, dy = bx_hi - bx_lo, by_hi - by_lo
        horiz_len = _m.sqrt(dx*dx + dy*dy)
        col_len   = _m.sqrt(horiz_len**2 + H2**2)
        tilt_x    = _m.atan2(H2, horiz_len)   # tilt toward vertical
        yaw       = _m.atan2(dy, dx) if horiz_len > 0.001 else 0
        parts.append(_gb_box_node(tree,
            (col_s, col_s, col_len),
            (mx, my, mz),
            (tilt_x, 0, yaw),
            base_x, 1000 + i*120, "pillar"))

    # ── The impossible cross-beams at mid-level ───────────────────────
    # Two horizontal beams at H1+H2/2, crossing at the centre
    beam_h = t * 1.8
    for ang in [0, _m.pi*0.5]:
        beam_len = _m.sqrt(W**2 + D**2) * 0.9
        parts.append(_gb_box_node(tree,
            (beam_len, col_s, beam_h),
            (0, 0, H1 + H2*0.5),
            (0, 0, ang),
            base_x, 1500 + int(ang*100), "pillar"))

    # ── Perimeter balustrade on upper level ───────────────────────────
    for (bw, bd, bx2, by2) in [
        (W, t,  0,       D*0.5-t*0.5),
        (W, t,  0,      -D*0.5+t*0.5),
        (t, D,  W*0.5-t*0.5,  0),
        (t, D, -W*0.5+t*0.5,  0),
    ]:
        parts.append(_gb_box(tree, (bw, bd, H2*0.3),
                             (bx2, by2, H1 + H2 + t + H2*0.15),
                             base_x, 1700 + len(parts)*40, "wall"))

    return _gb_join(tree, parts, base_x + 2400, 0)


def build_gb_escher_waterfall(tree, props, base_x=-1400):
    """Impossible Waterfall: three elevated aqueduct channels arranged in a
    triangle. Each channel tilts slightly downward, but the loop closes at the
    top — the water appears to flow down yet return to the source.
    Based on Escher's 'Waterfall' (1961).
    In-game use: puzzle room, impossible cistern, magical water feature."""
    import math as _m
    span  = getattr(props, 'gb_width',   8.0)     # triangle leg length
    W_ch  = getattr(props, 'gb_depth',   0.9) if hasattr(props, 'gb_depth') else 0.9
    t_ch  = 0.25                                   # channel wall thickness
    rise  = getattr(props, 'gb_rise',    0.5)     # total fall per arm
    H_col = getattr(props, 'gb_height',  4.0)     # support column height
    parts = []

    # Three channel arms, 120° apart, each tilted by (rise/span) downward
    # The tilt angle is gentle — mostly horizontal
    tilt = _m.atan2(rise, span)   # ~3–6° depending on props
    ch_len = _m.sqrt(span**2 + rise**2)

    for ai in range(3):
        yaw = ai * _m.tau / 3    # 0°, 120°, 240°

        # Channel arm centre in XY, elevation drops from rise→0 along arm
        cx = _m.cos(yaw) * span * 0.5
        cy = _m.sin(yaw) * span * 0.5
        cz = H_col + rise * (1 - ai / 3)   # each arm at different height for visual

        # Channel floor slab (tilted)
        parts.append(_gb_box_node(tree,
            (W_ch, ch_len, t_ch),
            (cx, cy, cz),
            (tilt, 0, yaw + _m.pi*0.5),
            base_x, ai * 800, "level"))
        # Channel left wall
        parts.append(_gb_box_node(tree,
            (t_ch, ch_len, W_ch * 0.6),
            (cx + _m.cos(yaw + _m.pi*0.5) * W_ch*0.5,
             cy + _m.sin(yaw + _m.pi*0.5) * W_ch*0.5,
             cz + W_ch*0.3),
            (tilt, 0, yaw + _m.pi*0.5),
            base_x, ai * 800 + 200, "level"))
        # Channel right wall
        parts.append(_gb_box_node(tree,
            (t_ch, ch_len, W_ch * 0.6),
            (cx - _m.cos(yaw + _m.pi*0.5) * W_ch*0.5,
             cy - _m.sin(yaw + _m.pi*0.5) * W_ch*0.5,
             cz + W_ch*0.3),
            (tilt, 0, yaw + _m.pi*0.5),
            base_x, ai * 800 + 400, "level"))

        # Support column below each arm midpoint
        parts.append(_gb_box(tree,
            (t_ch * 2.5, t_ch * 2.5, cz),
            (cx, cy, cz * 0.5),
            base_x, ai * 800 + 600, "pillar"))

    # ── Corner junction blocks (where arms meet) ─────────────────────
    for ai in range(3):
        yaw_a = ai * _m.tau / 3
        yaw_b = ((ai + 1) % 3) * _m.tau / 3
        jx = _m.cos((yaw_a + yaw_b) * 0.5) * span * 0.85
        jy = _m.sin((yaw_a + yaw_b) * 0.5) * span * 0.85
        jz = H_col + rise * 0.5 + W_ch * 0.4
        parts.append(_gb_box(tree, (W_ch * 1.4, W_ch * 1.4, W_ch * 0.8),
                             (jx, jy, jz),
                             base_x, 2400 + ai * 100, "level"))

    # ── Base platform ────────────────────────────────────────────────
    parts.append(_gb_box(tree, (span * 2.2, span * 2.2, t_ch),
                         (0, 0, t_ch * 0.5),
                         base_x, 2700, "level"))

    return _gb_join(tree, parts, base_x + 3200, 0)


def build_gb_escher_recursive_room(tree, props, base_x=-1400):
    """Recursive Room: concentric square rooms of decreasing scale, each rotated
    slightly and connected by doorway passages — suggesting infinite regression.
    Based on Escher's 'Smaller and Smaller' / 'Print Gallery' concepts.
    In-game use: hub room for recursive puzzle levels, magical library, void antechamber."""
    import math as _m
    W0   = getattr(props, 'gb_width',   12.0)   # outermost room width
    H    = getattr(props, 'gb_height',   3.5)
    t    = getattr(props, 'gb_wall_thick', 0.3)
    dw   = getattr(props, 'gb_door_width', 1.4)
    dh   = getattr(props, 'gb_door_height', 2.4)
    depth= min(4, getattr(props, 'gb_recursive_depth', 3))
    twist= _m.radians(getattr(props, 'gb_steps', 15))  # rotation per level
    scale= 0.62                                          # size ratio per level
    parts = []

    for di in range(depth):
        W = W0 * (scale ** di)
        rot = twist * di
        wh  = H - t
        wz  = t + wh * 0.5
        cos_r = _m.cos(rot)
        sin_r = _m.sin(rot)

        # Floor of this ring (annular — outer square minus inner square)
        # Approximate with 4 floor strips
        Wn = W0 * (scale ** (di + 1)) if di + 1 < depth else W * 0.1
        margin = (W - Wn) * 0.5

        # 4 floor strips around the ring
        for (sw, sd, sx, sy) in [
            (W,      margin, 0,          (W - margin) * 0.5),     # +Y strip
            (W,      margin, 0,         -(W - margin) * 0.5),     # -Y strip
            (margin, Wn,     (W - margin)*0.5,  0),                # +X strip
            (margin, Wn,    -(W - margin)*0.5,  0),                # -X strip
        ]:
            rx = sx * cos_r - sy * sin_r
            ry = sx * sin_r + sy * cos_r
            parts.append(_gb_box_node(tree, (sw, sd, t),
                                      (rx, ry, t * 0.5),
                                      (0, 0, rot),
                                      base_x, di * 3000 + len(parts) * 60, "level"))

        # 4 walls for this ring level (with door gap in +Y wall)
        for (bw, bd, bx2, by2, is_door) in [
            (W, t,  0,       W*0.5-t*0.5,  True),    # N wall — door
            (W, t,  0,      -W*0.5+t*0.5,  False),   # S wall
            (t, W,  W*0.5-t*0.5,  0,       False),   # E wall
            (t, W, -W*0.5+t*0.5,  0,       False),   # W wall
        ]:
            rx  = bx2 * cos_r - by2 * sin_r
            ry  = bx2 * sin_r + by2 * cos_r
            if is_door:
                # Two segments flanking door opening
                seg_len = (bw - dw) * 0.5
                for sx2 in (-1, 1):
                    cx2 = sx2 * (seg_len * 0.5 + dw * 0.5)
                    rx2 = cx2 * cos_r - by2 * sin_r
                    ry2 = cx2 * sin_r + by2 * cos_r
                    parts.append(_gb_box_node(tree, (seg_len, bd, wh),
                                              (rx2, ry2, wz),
                                              (0, 0, rot),
                                              base_x, di * 3000 + len(parts) * 60, "wall"))
            else:
                parts.append(_gb_box_node(tree, (bw, bd, wh),
                                          (rx, ry, wz),
                                          (0, 0, rot),
                                          base_x, di * 3000 + len(parts) * 60, "wall"))

    # Innermost solid cube / altar
    W_inner = W0 * (scale ** depth)
    parts.append(_gb_box(tree, (W_inner, W_inner, H * 0.8),
                         (0, 0, H * 0.4),
                         base_x, 15000, "pillar"))

    return _gb_join(tree, parts, base_x + 6000, 0)


# ==============================================================================
# 🏚  LEBBEUS WOODS GREYBOX  (v2.53)
#   Parametric greybox geometry inspired by Woods' impossible, post-conflict,
#   harvested and parasite architecture. All pieces are walkable game geometry.
# ==============================================================================

def _gb_parasite_inner_opening(tree, par_geom, pw, pd, ph, t, dw, dh, face_key, base_x, node_y):
    """Boolean doorway on the parasite face that faces the host (v2.59.29)."""
    depth = _gb_opening_cutter_depth(t)
    open_z = ph * 0.35
    if face_key == 'x_pos':
        pos = (pw * 0.5, 0, open_z)
        size = (depth, dw, dh)
    elif face_key == 'x_neg':
        pos = (-pw * 0.5, 0, open_z)
        size = (depth, dw, dh)
    elif face_key == 'y_pos':
        pos = (0, pd * 0.5, open_z)
        size = (dw, depth, dh)
    else:  # y_neg
        pos = (0, -pd * 0.5, open_z)
        size = (dw, depth, dh)
    cutter = _gb_box(tree, size, pos, base_x, node_y, "door")
    return _gb_bool_diff(tree, par_geom, [cutter], base_x + 120, node_y)


def build_gb_woods_parasite(tree, props, base_x=-1400):
    """Parasite Structure: a rectangular host building with 2-4 angled parasitic
    volumes bolted onto its exterior faces at 15-35° angles — the Lebbeus Woods
    'colonization' of dead architecture. The parasite volumes are inhabitable
    (open on their inner face where they meet the host via gb_door_width/height).
    In-game use: slum add-on rooms, post-collapse habitat modules, sci-fi bolt-ons."""
    import math as _m, random
    W  = getattr(props, 'gb_width',      8.0)
    D  = getattr(props, 'gb_depth', W * 0.7) if hasattr(props, 'gb_depth') else W * 0.7
    H  = getattr(props, 'gb_height',     5.0)
    t  = getattr(props, 'gb_wall_thick', 0.3)
    dw = getattr(props, 'gb_door_width', 1.6)
    dh = getattr(props, 'gb_door_height', 2.6)
    cut_openings = getattr(props, 'gb_door_n', True)
    rng = random.Random(getattr(props, 'seed', 1) + 77)
    parts = []

    # ── Host volume (thick-walled box, open top) ─────────────────────
    # Use NTRounded Cube for softer brutalist silhouette if Higgsas available
    host = _higg_node(tree, 'NTRounded Cube', (base_x, 0))
    if host is not None:
        _higg_input(host, 'Size',       (W, D, H))
        _higg_input(host, 'Resoliution', 2)
        _higg_input(host, 'Radius',     t * 0.4)
        host_geom = host.outputs['Mesh']
    else:
        host_geom = _cube(tree, (base_x, 0), W, D, H, "tower")
    host_t = _move(tree, host_geom, (base_x + 200, 0), translation=(0, 0, H * 0.5), label="tower")
    if host_t: parts.append(host_t)

    # ── Parasitic bolt-on volumes (2-4 angled rooms) ─────────────────
    n_parasites = getattr(props, 'gb_cover_count', 3)  # repurpose cover_count
    n_parasites = max(1, min(4, n_parasites))

    # Candidate attachment points on each face
    face_configs = [
        ( W * 0.5, 0,       0,  _m.pi * 0.5),   # +X face
        (-W * 0.5, 0,       0, -_m.pi * 0.5),   # -X face
        (0,  D * 0.5,       0,  0),              # +Y face
        (0, -D * 0.5,       0,  _m.pi),          # -Y face
    ]
    rng.shuffle(face_configs)

    for pi_idx in range(n_parasites):
        fx, fy, fz, face_yaw = face_configs[pi_idx]
        # Parasite size: 30-60% of host
        pw = rng.uniform(W * 0.28, W * 0.48)
        pd = rng.uniform(D * 0.25, D * 0.42)
        ph = rng.uniform(H * 0.35, H * 0.65)
        # Random tilt in 2 axes — the Woods signature diagonal
        tilt_x = rng.uniform(_m.radians(8), _m.radians(28))
        tilt_z = rng.uniform(-_m.radians(20), _m.radians(20))

        # Parasite box (use NTRounded Cube if available)
        par = _higg_node(tree, 'NTRounded Cube', (base_x, -800 - pi_idx * 300))
        if par is not None:
            _higg_input(par, 'Size',       (pw, pd, ph))
            _higg_input(par, 'Resoliution', 2)
            _higg_input(par, 'Radius',     t * 0.25)
            par_geom = par.outputs['Mesh']
        else:
            par_geom = _cube(tree, (base_x, -800 - pi_idx * 300), pw, pd, ph, "wall")

        if cut_openings and par_geom:
            if abs(fx) > abs(fy):
                face_key = 'x_neg' if fx > 0 else 'x_pos'
            else:
                face_key = 'y_neg' if fy > 0 else 'y_pos'
            par_geom = _gb_parasite_inner_opening(
                tree, par_geom, pw, pd, ph, t, dw, dh, face_key,
                base_x, -600 - pi_idx * 300)

        # Position: attach to the face, offset outward, apply tilts
        outset = pw * 0.5 if abs(fx) > abs(fy) else pd * 0.5
        tx = fx + _m.cos(face_yaw) * outset * 0.4
        ty = fy + _m.sin(face_yaw) * outset * 0.4
        tz = rng.uniform(H * 0.1, H * 0.6)

        par_t = _safe_node(tree, 'GeometryNodeTransform',
                           (base_x + 400, -800 - pi_idx * 300))
        if par_t:
            try:
                par_t.inputs['Translation'].default_value = (tx, ty, tz + ph * 0.5)
                par_t.inputs['Rotation'].default_value    = (tilt_x, 0, face_yaw + tilt_z)
            except Exception: pass
            _link(tree, par_geom, par_t.inputs['Geometry'])
            color_node(par_t, "wall")
            parts.append(par_t.outputs['Geometry'])

        # Connecting strut (diagonal tube from host face to parasite)
        strut = _cube(tree, (base_x, -1400 - pi_idx * 300),
                      t * 1.2, t * 1.2, outset * 0.9, "ornament")
        strut_t = _safe_node(tree, 'GeometryNodeTransform',
                             (base_x + 200, -1400 - pi_idx * 300))
        if strut_t:
            try:
                strut_t.inputs['Translation'].default_value = (
                    (fx + tx) * 0.5, (fy + ty) * 0.5, tz + ph * 0.35)
                strut_t.inputs['Rotation'].default_value = (tilt_x * 0.5, 0, face_yaw)
            except Exception: pass
            _link(tree, strut, strut_t.inputs['Geometry'])
            color_node(strut_t, "ornament")
            parts.append(strut_t.outputs['Geometry'])

    # ── Gash / scar line across the host (Woods' war mark) ────────────
    scar = _cube(tree, (base_x, -2800), W * 1.05, t * 0.5, H * 0.06, "ornament")
    scar_t = _move(tree, scar, (base_x + 200, -2800),
                   translation=(0, -D * 0.5 - 0.01, H * rng.uniform(0.35, 0.55)),
                   label="ornament")
    if scar_t: parts.append(scar_t)

    return _finalize_building(tree, parts, (base_x + 3000, 0))


def build_gb_woods_freespace(tree, props, base_x=-1400):
    """Freespace: two rectangular volumes interpenetrating at an angle.
    The inhabitable zone is the gap/overlap between them — a void created by
    structural collision, lit from oblique openings. Inspired by Woods' 'Freespaces
    between buildings in the city' (Zagreb Free Zone, 1991).
    In-game use: tight urban combat space, tension-filled connector, impossible alley."""
    import math as _m
    W  = getattr(props, 'gb_width',      7.0)
    D  = getattr(props, 'gb_depth', W * 0.65) if hasattr(props, 'gb_depth') else W * 0.65
    H  = getattr(props, 'gb_height',     4.0)
    t  = getattr(props, 'gb_wall_thick', 0.35)
    ang = _m.radians(getattr(props, 'gb_steps', 22))   # interpenetration angle
    parts = []

    # ── Volume A (upright, standard orientation) ──────────────────────
    for (bw, bd, bx2, by2, label) in [
        (W, t, 0,       D*0.5-t*0.5, "tower"),  # N wall
        (W, t, 0,      -D*0.5+t*0.5, "tower"),  # S wall
        (t, D, W*0.5-t*0.5, 0,       "tower"),  # E wall
        (t, D,-W*0.5+t*0.5, 0,       "tower"),  # W wall
        (W, D, 0,       0,            "level"),  # floor
    ]:
        bh = H if label == "tower" else t
        tz = H * 0.5 if label == "tower" else t * 0.5
        parts.append(_move(tree, _cube(tree, (base_x, len(parts)*150), bw, bd, bh, label),
                           (base_x + 200, len(parts)*150),
                           translation=(bx2, by2, tz), label=label))

    # ── Volume B (angled, offset — crashes into Volume A) ─────────────
    cos_a, sin_a = _m.cos(ang), _m.sin(ang)
    offx = W * 0.35    # how far B is shifted relative to A
    offy = D * 0.25
    offz = H * 0.15    # B sits slightly higher — creates the freespace gap

    for (bw, bd, bx2, by2, label) in [
        (W, t, 0,       D*0.5-t*0.5, "wall"),
        (W, t, 0,      -D*0.5+t*0.5, "wall"),
        (t, D, W*0.5-t*0.5, 0,       "wall"),
        (t, D,-W*0.5+t*0.5, 0,       "wall"),
        (W, D, 0,       0,            "level"),
    ]:
        bh = H if label == "wall" else t
        tz = H * 0.5 if label == "wall" else t * 0.5
        # Rotate position around the origin then offset
        rx = bx2 * cos_a - by2 * sin_a + offx
        ry = bx2 * sin_a + by2 * cos_a + offy
        parts.append(_gb_box_node(tree, (bw, bd, bh),
                                  (rx, ry, tz + offz),
                                  (0, 0, ang),
                                  base_x, 900 + len(parts) * 120, label))

    # ── Freespace floor (the inhabitable void between the volumes) ─────
    # Thin slab in the gap between the two volumes
    gap_w = W * 0.4
    gap_d = D * 0.35
    parts.append(_gb_box(tree, (gap_w, gap_d, t),
                         (offx * 0.5, offy * 0.5, offz + t * 0.5), base_x, 2200, "level"))

    # ── Tension cables connecting the two volumes (thin diagonal bars) ─
    for cable_i in range(3):
        frac = (cable_i + 0.5) / 3
        cx1 = -W * 0.3 + frac * W * 0.6
        cx2 = cx1 + offx * 0.5
        cy2 = offy * 0.6
        cz1 = H * 0.7
        cz2 = offz + H * 0.55
        dl = _m.sqrt((cx2-cx1)**2 + cy2**2 + (cz2-cz1)**2)
        if dl < 0.1: continue
        ang_x = _m.atan2(cz2 - cz1, cy2)
        ang_z = _m.atan2(cy2, cx2 - cx1)
        cable = _cube(tree, (base_x, 2500 + cable_i * 80),
                      t * 0.4, dl, t * 0.4, "ornament")
        cable_t = _safe_node(tree, 'GeometryNodeTransform',
                             (base_x + 200, 2500 + cable_i * 80))
        if cable_t:
            try:
                cable_t.inputs['Translation'].default_value = (
                    (cx1 + cx2) * 0.5, cy2 * 0.5, (cz1 + cz2) * 0.5)
                cable_t.inputs['Rotation'].default_value = (ang_x, 0, ang_z)
            except Exception: pass
            _link(tree, cable, cable_t.inputs['Geometry'])
            parts.append(cable_t.outputs['Geometry'])

    return _finalize_building(tree, parts, (base_x + 3200, 0))


def build_gb_woods_ribs(tree, props, base_x=-1400):
    """Rib Cage Room: a rectangular volume whose structural system is a series of
    exposed angled rib frames — each rib runs floor-to-ceiling diagonally. Like
    a building where the skeleton is the architecture. Inspired by Woods' harvested
    and rebuilt structural systems.
    In-game use: ruins interior, cave-like corridor, sci-fi organic structure."""
    import math as _m
    L    = getattr(props, 'gb_length',    10.0)
    W    = getattr(props, 'gb_width',      4.0)
    H    = getattr(props, 'gb_height',     4.5)
    t    = getattr(props, 'gb_wall_thick', 0.28)
    n    = max(3, getattr(props, 'gb_cover_count', 6))   # number of ribs
    parts = []

    # ── Floor slab ───────────────────────────────────────────────────
    parts.append(_move(tree, _cube(tree, (base_x, 0), W, L, t, "level"),
                       (base_x + 200, 0), translation=(0, 0, t * 0.5), label="level"))

    # ── Rib frames — each a quadrilateral portal frame ────────────────
    # Each rib: 2 side columns angled inward at the top (Gothic-rib style)
    # + a curved crown at the apex
    rib_thickness = t * 1.4
    for ri in range(n):
        ry = -L * 0.5 + (ri + 0.5) * (L / n)
        # Each rib leans inward at a varying angle (alternating for Woods' rhythm)
        lean = _m.radians(8 + (ri % 2) * 12)   # 8° or 20° lean
        rib_h = _m.sqrt(H**2 + (W * 0.5 * _m.tan(lean))**2)

        for sx in (-1, 1):
            # Side column
            col_x = sx * (W * 0.5 - rib_thickness * 0.6)
            parts.append(_gb_box_node(tree,
                (rib_thickness, rib_thickness, rib_h),
                (col_x * _m.cos(sx * lean), ry, rib_h * 0.5),
                (sx * lean, 0, 0),
                base_x, ri * 600 + (sx + 1) * 200 + 1000, "ornament"))

        # Crown beam across the top (horizontal bar at peak)
        parts.append(_move(tree,
            _cube(tree, (base_x, ri * 600 + 1400), W * 0.6, rib_thickness, rib_thickness, "ornament"),
            (base_x + 200, ri * 600 + 1400),
            translation=(0, ry, H + rib_thickness * 0.2), label="ornament"))

    # ── Side membrane walls (thin infill between ribs — perforated) ───
    for sx in (-1, 1):
        wall_x = sx * (W * 0.5 - t * 0.5)
        # Two panels above and below the mid-height void
        for zi, (zb, zh) in enumerate([(0, H * 0.3), (H * 0.6, H * 0.4)]):
            parts.append(_gb_box(tree, (t, L, zh),
                                 (wall_x, 0, zb + zh * 0.5), base_x, 8000 + zi * 300 + (sx+1)*200, "wall"))

    # ── Tension cable spine (from first to last rib at crown) ─────────
    spine = _move(tree,
        _cube(tree, (base_x, 9000), t * 0.6, L, t * 0.6, "ornament"),
        (base_x + 200, 9000),
        translation=(0, 0, H + rib_thickness * 0.3), label="ornament")
    if spine: parts.append(spine)

    return _finalize_building(tree, parts, (base_x + 3500, 0))


def build_gb_woods_harpsichord(tree, props, base_x=-1400):
    """Harpsichord Tower: a slender vertical tower with blade fins extending
    outward at each floor level, angled like harp strings. The fins create
    outdoor traversal opportunities and give the tower its distinctive silhouette.
    Inspired by Woods' 'Harpsichord House' concept sketches.
    In-game use: watchtower, antenna mast, surreal landmark, radio tower."""
    import math as _m
    R       = getattr(props, 'base_radius', 0.8)
    floors  = getattr(props, 'gb_floors',   5)
    fh      = getattr(props, 'gb_height',   3.0)
    t       = getattr(props, 'gb_wall_thick', 0.25)
    n_fins  = getattr(props, 'gb_cover_count', 4)   # fins per floor
    total_h = floors * fh
    parts   = []

    # ── Core shaft (octagonal — use NTRounded Cube if available) ──────
    core = _higg_node(tree, 'NTRounded Cube', (base_x, 0))
    if core is not None:
        _higg_input(core, 'Size',       (R * 2, R * 2, total_h))
        _higg_input(core, 'Resoliution', 3)
        _higg_input(core, 'Radius',     R * 0.2)
        core_geom = core.outputs['Mesh']
    else:
        cyl = _safe_node(tree, 'GeometryNodeMeshCylinder', (base_x, 0))
        if cyl:
            try:
                cyl.inputs['Vertices'].default_value = 8
                cyl.inputs['Radius'].default_value   = R
                cyl.inputs['Depth'].default_value    = total_h
            except Exception: pass
            core_geom = cyl.outputs['Mesh']
        else:
            core_geom = _cube(tree, (base_x, 0), R*2, R*2, total_h, "tower")
    core_t = _move(tree, core_geom, (base_x + 200, 0),
                   translation=(0, 0, total_h * 0.5), label="tower")
    if core_t: parts.append(core_t)

    # ── Blade fins per floor ───────────────────────────────────────────
    fin_w  = R * 3.5      # fin length (horizontal reach)
    fin_h  = fh * 0.08    # fin thickness
    fin_d  = t * 1.2      # fin depth
    for f in range(floors):
        z_fin = f * fh + fh * 0.7
        for fi in range(n_fins):
            ang = fi * _m.tau / n_fins + f * (_m.pi / n_fins)  # rotated per floor
            # Each fin sweeps outward from the core
            # Lean angle: alternates +/- 15° per floor (harpsichord string feel)
            lean = _m.radians(12 + (fi % 2) * 18) * (-1 if f % 2 else 1)
            fin_len = fin_w * (0.7 + fi / n_fins * 0.5)

            fin = _gb_box_node(tree,
                (fin_len, fin_d, fin_h),
                (R * 0.9 * _m.cos(ang) + _m.cos(ang) * fin_len * 0.5,
                 R * 0.9 * _m.sin(ang) + _m.sin(ang) * fin_len * 0.5,
                 z_fin),
                (lean, 0, ang + _m.pi * 0.5),
                base_x, f * 800 + fi * 100 + 3000, "ornament")
            if fin: parts.append(fin)

    # ── Floor plate rings at each level ────────────────────────────────
    for f in range(floors):
        ring_z = f * fh
        ring = _safe_node(tree, 'GeometryNodeMeshTorus',
                          (base_x, f * 100 + 8000))
        if ring:
            try:
                ring.inputs['Major Radius'].default_value = R * 1.6
                ring.inputs['Minor Radius'].default_value = t * 0.6
                ring.inputs['Major Segments'].default_value = 16
                ring.inputs['Minor Segments'].default_value = 4
            except Exception: pass
            color_node(ring, "ornament")
            ring_t = _move(tree, ring.outputs['Mesh'],
                           (base_x + 200, f * 100 + 8000),
                           translation=(0, 0, ring_z), label="ornament")
            if ring_t: parts.append(ring_t)

    return _finalize_building(tree, parts, (base_x + 3000, 0))


def build_gb_woods_war_scar(tree, props, base_x=-1400):
    """War Scar / Stratigraphic Cut: a building facade with a diagonal slice
    revealing its interior layers — like geology of habitation exposed by conflict.
    Each stratum is a different material/era. Inspired by Woods' Berlin and Sarajevo
    interventions showing 'archaeological sections' of living.
    In-game use: bombed building face, portal into history, ruin cross-section."""
    import math as _m
    W   = getattr(props, 'gb_width',      8.0)
    H   = getattr(props, 'gb_height',     6.0)
    t   = getattr(props, 'gb_wall_thick', 0.4)
    n_strata = getattr(props, 'gb_floors', 4)   # horizontal layers visible
    scar_ang = _m.radians(getattr(props, 'gb_steps', 30))  # diagonal cut angle
    parts    = []

    stratum_h = H / n_strata
    stratum_labels = ["tower", "wall", "ornament", "level"] * 4

    # ── Stratum layers — each a horizontal band with different depth ───
    for si in range(n_strata):
        z_bot = si * stratum_h
        depth = t * (1.0 + si * 0.4)   # deeper layers are thicker
        label = stratum_labels[si % len(stratum_labels)]

        # Cut point: the diagonal scar reduces visible width per stratum
        scar_cut_x = W * 0.5 - (si / n_strata) * W * 0.6 * _m.tan(scar_ang)
        visible_w  = max(0.3, scar_cut_x + W * 0.5)

        # Full stratum slab
        slab = _cube(tree, (base_x, si * 300), visible_w, depth, stratum_h * 0.92, label)
        slab_t = _move(tree, slab, (base_x + 200, si * 300),
                       translation=(- (W * 0.5 - visible_w * 0.5), 0, z_bot + stratum_h * 0.46),
                       label=label)
        if slab_t: parts.append(slab_t)

        # Interior furniture (thin slab hinting at floors/ceilings inside)
        if si < n_strata - 1:
            floor_slab = _cube(tree, (base_x, si * 300 + 150),
                               visible_w * 0.85, depth * 0.7, t * 0.15, "level")
            fs_t = _move(tree, floor_slab, (base_x + 200, si * 300 + 150),
                         translation=(- (W * 0.5 - visible_w * 0.42), 0, z_bot + stratum_h),
                         label="level")
            if fs_t: parts.append(fs_t)

        # Exposed rebar stubs on the scar face
        n_rebar = max(1, int(visible_w / 0.6))
        for ri in range(n_rebar):
            rx = - W * 0.5 + (ri + 0.5) * visible_w / n_rebar
            rebar_len = t * rng_val(si + ri * 7)
            rebar = _cube(tree, (base_x, 2000 + si * 200 + ri * 40),
                          t * 0.04, rebar_len, t * 0.04, "ornament")
            rebar_t = _move(tree, rebar, (base_x + 200, 2000 + si * 200 + ri * 40),
                            translation=(rx, depth * 0.5 + rebar_len * 0.5, z_bot + stratum_h * 0.4),
                            label="ornament")
            if rebar_t: parts.append(rebar_t)

    # ── Diagonal cut plane marker (thin slab at the scar angle) ───────
    cut_h = _m.sqrt(H**2 + (H * _m.tan(scar_ang))**2) * 0.8
    cut = _gb_box_node(tree, (cut_h * _m.cos(scar_ang) * 0.9, t * 0.08, cut_h),
                       (W * 0.1, 0, H * 0.45),
                       (0, scar_ang, 0),
                       base_x, 5000, "ornament")
    if cut: parts.append(cut)

    return _finalize_building(tree, parts, (base_x + 3000, 0))


def rng_val(seed):
    """Tiny seeded float 0–1 for rebar length variation."""
    import math
    return abs(math.sin(seed * 9301 + 49297) % 1.0) * 0.8 + 0.2


# ==============================================================================
# 🏗  DAVID UMEMOTO GREYBOX  (v2.53)
#   Brutal, geometric, repetitive concrete forms. Thick walls, deep recesses,
#   stacked terraces, vault clusters. Umemoto's architecture is the language of
#   the impenetrable — every piece reads as monumental, compressed, earthbound.
# ==============================================================================

def build_gb_umemoto_terrace(tree, props, base_x=-1400):
    """Terraced Brutalist Tower: stacked receding rectangular floors — each level
    smaller than the one below, set back progressively to create outdoor terraces.
    Thick walls, deep window slots. Umemoto's characteristic stepped mass.
    In-game use: brutalist tower, Mayan temple, sci-fi habitat stack."""
    import math as _m
    W0      = getattr(props, 'gb_width',      10.0)
    D0      = getattr(props, 'gb_depth', W0 * 0.7) if hasattr(props, 'gb_depth') else W0 * 0.7
    fh      = getattr(props, 'gb_height',      3.0)   # floor height
    floors  = getattr(props, 'gb_floors',      4)
    t       = getattr(props, 'gb_wall_thick',  0.6)   # thick brutalist walls
    setback = getattr(props, 'gb_run',         0.8)   # setback per floor
    dw      = getattr(props, 'gb_door_width',  0.5)   # window slot width
    dh      = getattr(props, 'gb_door_height', 1.4)   # window slot height
    parts   = []

    for f in range(floors):
        W  = W0  - f * setback * 2
        D  = D0  - f * setback * 2
        z0 = f * fh
        wz = t + (fh - t) * 0.5
        wh = fh - t

        if W < t * 3 or D < t * 3: break

        # ── Four thick walls ─────────────────────────────────────────
        for (bw, bd, bx2, by2) in [
            (W, t, 0,       D*0.5-t*0.5),
            (W, t, 0,      -D*0.5+t*0.5),
            (t, D, W*0.5-t*0.5,  0),
            (t, D,-W*0.5+t*0.5,  0),
        ]:
            parts.append(_move(tree, _cube(tree, (base_x, len(parts)*80), bw, bd, wh, "tower"),
                               (base_x + 200, len(parts)*80),
                               translation=(bx2, by2, z0 + wz), label="tower"))

        # ── Floor slab ────────────────────────────────────────────────
        parts.append(_move(tree, _cube(tree, (base_x, len(parts)*80), W, D, t, "level"),
                           (base_x + 200, len(parts)*80),
                           translation=(0, 0, z0 + t * 0.5), label="level"))

        # ── Terrace ledge (at the setback line of lower floor) ────────
        if f > 0:
            terrace_w = setback
            terrace_d = D0 - (f-1) * setback * 2
            for sx in (-1, 1):
                parts.append(_move(tree,
                    _cube(tree, (base_x, len(parts)*80), terrace_w, terrace_d, t, "level"),
                    (base_x + 200, len(parts)*80),
                    translation=(sx * (W * 0.5 + terrace_w * 0.5 - setback * 0.1), 0, z0 + t * 0.5),
                    label="level"))

        # ── Deep window slots — 2 per N/S face ────────────────────────
        slot_z = z0 + wz
        for side_y in (D*0.5-t*0.5, -D*0.5+t*0.5):
            for wx_frac in (-0.25, 0.25):
                slot = _cube(tree, (base_x, len(parts)*80), dw, t*2, dh, "door")
                slot_t = _move(tree, slot, (base_x + 200, len(parts)*80),
                               translation=(wx_frac * W, side_y, slot_z), label="door")
                if slot_t: parts.append(slot_t)

        # ── NTTaper: taper each floor slab for entasis-like bulge ─────
        # (Applied as a deform on the wall geometry via Higgsas if available)
        if f == 0:
            higg_taper = _higg_node(tree, 'NTTaper', (base_x + 2000, 0))
            if higg_taper is not None:
                _higg_input(higg_taper, 'Upper Factor', 0.96)
                _higg_input(higg_taper, 'Lower Factor', 1.03)
                # This would ideally be applied to the joined geometry — skip for now
                # (Higgsas deformers need proper linking; use the node as decoration)

    return _finalize_building(tree, parts, (base_x + 4000, 0))


def build_gb_umemoto_vault_cluster(tree, props, base_x=-1400):
    """Vault Cluster: a grid of barrel vaulted chambers — Umemoto's signature.
    N×M vaults in a grid, each with thick walls and a semi-circular ceiling.
    The thick piers between vaults create deep recesses. Inhabitable from below.
    In-game use: undercroft, bunker interior, warehouse, temple crypt."""
    import math as _m
    cols    = max(2, getattr(props, 'gb_cols_x',   3))
    rows    = max(1, getattr(props, 'gb_cols_y',   2))
    vault_w = getattr(props, 'gb_spacing',    3.0)    # interior width per vault
    vault_h = getattr(props, 'gb_height',     3.5)    # wall height to spring
    t       = getattr(props, 'gb_wall_thick', 0.7)    # thick brutalist piers
    vault_d = getattr(props, 'gb_length',     4.0)    # vault depth (length)
    res     = 16
    parts   = []

    bay_w = vault_w + t
    bay_d = vault_d + t

    for ri in range(rows):
        for ci in range(cols):
            ox = ci * bay_w - (cols - 1) * bay_w * 0.5
            oy = ri * bay_d - (rows - 1) * bay_d * 0.5

            # Floor slab — v2.60.2 walk-plane: floor top at Z=0
            parts.append(_move(tree,
                _cube(tree, (base_x, len(parts)*60), vault_w + t * 2, vault_d + t * 2, t, "level"),
                (base_x + 200, len(parts)*60),
                translation=(ox, oy, -t * 0.5), label="level"))

            # Side walls (piers)
            for sx in (-1, 1):
                parts.append(_move(tree,
                    _cube(tree, (base_x, len(parts)*60), t, vault_d, vault_h, "tower"),
                    (base_x + 200, len(parts)*60),
                    translation=(ox + sx * (vault_w * 0.5 + t * 0.5), oy, vault_h * 0.5),
                    label="tower"))

            # End walls
            for sy in (-1, 1):
                parts.append(_move(tree,
                    _cube(tree, (base_x, len(parts)*60), vault_w + t * 2, t, vault_h, "tower"),
                    (base_x + 200, len(parts)*60),
                    translation=(ox, oy + sy * (vault_d * 0.5 + t * 0.5), vault_h * 0.5),
                    label="tower"))

            # Barrel vault arc (CurveArc → rect profile → CurveToMesh)
            arc = _safe_node(tree, 'GeometryNodeCurveArc',
                             (base_x + 600, len(parts) * 40))
            if arc:
                try:
                    arc.mode = 'RADIUS'
                    arc.inputs['Radius'].default_value      = vault_w * 0.5
                    arc.inputs['Start Angle'].default_value = 0.0
                    arc.inputs['Sweep Angle'].default_value = _m.pi
                    arc.inputs['Resolution'].default_value  = res
                except Exception: pass
                # Rotate arc to face +Z
                arc_rot = _safe_node(tree, 'GeometryNodeTransform',
                                     (base_x + 800, len(parts) * 40))
                if arc_rot:
                    try:
                        arc_rot.inputs['Rotation'].default_value    = (_m.radians(90), 0, 0)
                        arc_rot.inputs['Translation'].default_value = (ox, oy, vault_h)
                    except Exception: pass
                    _link(tree, arc.outputs['Curve'], arc_rot.inputs['Geometry'])
                    # Rect profile for vault shell thickness
                    prof = _rect_profile(tree, (base_x + 400, len(parts) * 40),
                                         vault_d + t, t * 0.8, "wall")
                    c2m = _safe_node(tree, 'GeometryNodeCurveToMesh',
                                     (base_x + 1000, len(parts) * 40))
                    if c2m and prof:
                        _link(tree, arc_rot.outputs['Geometry'], c2m.inputs['Curve'])
                        _link(tree, prof, c2m.inputs['Profile Curve'])   # prof is already a socket
                        try: c2m.inputs['Fill Caps'].default_value = True
                        except Exception: pass
                        color_node(c2m, "wall")
                        parts.append(c2m.outputs['Mesh'])

    return _finalize_building(tree, parts, (base_x + 4000, 0))


def build_gb_umemoto_lattice_block(tree, props, base_x=-1400):
    """Lattice Block: a solid rectangular block perforated by a regular grid
    of square through-openings. Umemoto's lattice facades as pure geometry.
    The remaining solid defines a precise geometric rhythm of light and shadow.
    Uses Higgsas NTArray for the opening grid when available.
    In-game use: brutalist facade, concrete screen wall, decorative partition."""
    import math as _m
    W    = getattr(props, 'gb_width',       5.0)
    H    = getattr(props, 'gb_height',      4.0)
    T    = getattr(props, 'gb_wall_thick',  0.55)
    cell = getattr(props, 'gb_spacing',     0.7)   # opening cell size
    pier = getattr(props, 'gb_wall_thick',  0.55) * 0.35  # pier between openings
    parts = []

    # ── Outer monolithic slab ─────────────────────────────────────────
    slab = _move(tree, _cube(tree, (base_x, 0), W, T, H, "tower"),
                 (base_x + 200, 0), translation=(0, 0, H * 0.5), label="tower")
    if slab: parts.append(slab)

    # ── Opening grid (boolean-style markers — or NTArray if Higgsas) ──
    opening_w = cell * 0.65    # width of each square opening
    grid_cols = max(1, int((W - pier) / (cell + pier)))
    grid_rows = max(1, int((H - pier) / (cell + pier)))
    col_step  = (W - pier) / grid_cols
    row_step  = (H - pier) / grid_rows

    arr_node = _higg_node(tree, 'NTArray', (base_x + 600, 0))
    if arr_node is not None:
        # Build single opening marker and array it via NTArray
        opening = _cube(tree, (base_x + 400, 0), opening_w, T * 2, opening_w, "door")
        opening_t = _move(tree, opening, (base_x + 450, 0),
                          translation=(- W * 0.5 + col_step * 0.5 + pier * 0.5, 0, row_step * 0.5 + pier * 0.5),
                          label="door")
        try:
            _higg_input(arr_node, 'X Count', grid_cols)
            _link(tree, opening_t, arr_node.inputs['Geometry'])
            # Realize and add
            real = _safe_node(tree, 'GeometryNodeRealizeInstances', (base_x + 900, 0))
            if real:
                _link(tree, arr_node.outputs['Geometry'], real.inputs['Geometry'])
                parts.append(real.outputs['Geometry'])
        except Exception:
            # Manual grid fallback
            pass
    else:
        # Manual grid of opening cubes
        for ci in range(grid_cols):
            for ri in range(grid_rows):
                ox = -W * 0.5 + (ci + 0.5) * col_step + pier * 0.5
                oz =  pier * 0.5 + (ri + 0.5) * row_step
                opening = _cube(tree, (base_x, 800 + ci * 200 + ri * 30),
                                opening_w, T * 2.5, opening_w, "door")
                op_t = _move(tree, opening, (base_x + 200, 800 + ci * 200 + ri * 30),
                             translation=(ox, 0, oz), label="door")
                if op_t: parts.append(op_t)

    # ── Surround frame (thick border around entire block) ────────────
    border_t = T * 0.4
    for (bw, bd, bx2, bz) in [
        (W + border_t * 2, border_t, 0, border_t * 0.5),            # bottom
        (W + border_t * 2, border_t, 0, H + border_t * 0.5 + t if False else H - border_t * 0.5),  # top
        (border_t, T + 0.1, -W * 0.5 - border_t * 0.5, H * 0.5),  # left
        (border_t, T + 0.1,  W * 0.5 + border_t * 0.5, H * 0.5),  # right
    ]:
        parts.append(_move(tree, _cube(tree, (base_x, len(parts)*60), bw, bd, border_t, "tower"),
                           (base_x + 200, len(parts)*60),
                           translation=(bx2, 0, bz), label="tower"))

    return _finalize_building(tree, parts, (base_x + 3000, 0))


def build_gb_umemoto_fortress_room(tree, props, base_x=-1400):
    """Fortress Room: Umemoto's monumental thick-walled room. Walls are 3-4× normal
    thickness, with deep orthogonal insets for windows/doors. Interior buttresses
    create alcoves. The floor is raised on a thick plinth. Oppressive and powerful.
    Uses Higgsas NTInset Face for window/niche recesses when available.
    In-game use: boss room, interrogation cell, vaulted crypt, keep interior."""
    W    = getattr(props, 'gb_width',       8.0)
    D    = getattr(props, 'gb_depth', W * 0.75) if hasattr(props, 'gb_depth') else W * 0.75
    H    = getattr(props, 'gb_height',      4.5)
    T    = getattr(props, 'gb_wall_thick',  0.9)   # very thick walls
    dw   = getattr(props, 'gb_door_width',  0.8)
    dh   = getattr(props, 'gb_door_height', 2.0)
    n_niches = getattr(props, 'gb_cover_count', 3)  # wall niches per long wall
    parts = []

    wh = H - T
    wz = T + wh * 0.5

    # ── Massive walls ─────────────────────────────────────────────────
    for (bw, bd, bx2, by2) in [
        (W + T*2, T, 0,       D*0.5+T*0.5),    # N exterior
        (W + T*2, T, 0,      -D*0.5-T*0.5),    # S exterior
        (T, D + T*2, W*0.5+T*0.5,  0),         # E exterior
        (T, D + T*2,-W*0.5-T*0.5,  0),         # W exterior
    ]:
        parts.append(_move(tree, _cube(tree, (base_x, len(parts)*80), bw, bd, wh, "tower"),
                           (base_x + 200, len(parts)*80),
                           translation=(bx2, by2, wz), label="tower"))

    # ── Raised plinth floor ───────────────────────────────────────────
    plinth_h = T * 0.6
    parts.append(_move(tree,
        _cube(tree, (base_x, len(parts)*80), W + T*2, D + T*2, plinth_h, "level"),
        (base_x + 200, len(parts)*80),
        translation=(0, 0, plinth_h * 0.5), label="level"))
    # Interior floor (thinner, on top of plinth)
    parts.append(_move(tree,
        _cube(tree, (base_x, len(parts)*80), W, D, T * 0.3, "level"),
        (base_x + 200, len(parts)*80),
        translation=(0, 0, plinth_h + T * 0.15), label="level"))

    # ── Door passage (S wall, centred) ───────────────────────────────
    door_slot = _move(tree,
        _cube(tree, (base_x, len(parts)*80), dw, T * 3, dh, "door"),
        (base_x + 200, len(parts)*80),
        translation=(0, -D*0.5 - T*0.5, plinth_h + dh * 0.5), label="door")
    if door_slot: parts.append(door_slot)

    # ── Wall niches / recessed panels (N wall + 2 side walls) ─────────
    niche_d = T * 0.55    # depth of recess into wall
    niche_w = min(dw * 1.6, W / (n_niches + 1) * 0.7)
    niche_h = H * 0.45

    for ni in range(n_niches):
        frac = (ni + 1) / (n_niches + 1)
        nx   = -W * 0.5 + frac * W
        # N wall niches
        niche = _move(tree,
            _cube(tree, (base_x, len(parts)*80), niche_w, niche_d, niche_h, "door"),
            (base_x + 200, len(parts)*80),
            translation=(nx, D*0.5 + T - niche_d*0.5, plinth_h + niche_h * 0.5 + T * 0.25),
            label="door")
        if niche: parts.append(niche)

    # ── Interior buttress piers (massive diagonal blocks at corners) ──
    bsize = T * 0.85
    for (sx, sy) in [(-1,-1),(1,-1),(1,1),(-1,1)]:
        butt = _move(tree,
            _cube(tree, (base_x, len(parts)*80), bsize, bsize, wh, "tower"),
            (base_x + 200, len(parts)*80),
            translation=(sx*(W*0.5-bsize*0.5), sy*(D*0.5-bsize*0.5), wz), label="tower")
        if butt: parts.append(butt)

    return _finalize_building(tree, parts, (base_x + 4000, 0))


# ----------------------------------------------------------------------
# BUILDER: STAIRCASE
# ----------------------------------------------------------------------

def build_staircase(tree, props, base_x=-1400):
    rise  = props.stair_rise
    run_  = props.stair_run
    width = props.stair_width
    spiral= math.radians(props.stair_spiral_deg)
    count = max(2, props.stair_step_count)

    # Step path line
    line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x, 200); color_node(line, "stair")
    line.mode = 'OFFSET'
    line.inputs['Count'].default_value = count
    line.inputs['Start Location'].default_value = (0, 0, 0)
    line.inputs['Offset'].default_value = (run_, 0, rise)

    # Step block
    step = tree.nodes.new('GeometryNodeMeshCube'); step.location = (base_x, -200); color_node(step, "stair")
    step.inputs['Size'].default_value = (run_, width, rise * 0.9)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+300, 0)
    tree.links.new(line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(step.outputs['Mesh'], inst.inputs['Instance'])

    # Spiral rotation
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, -500)
    rot_mul = tree.nodes.new('ShaderNodeMath'); rot_mul.location = (base_x+200, -500); rot_mul.operation = 'MULTIPLY'
    rot_mul.inputs[1].default_value = spiral
    tree.links.new(idx.outputs['Index'], rot_mul.inputs[0])
    rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+400, -500)
    rvec.inputs['X'].default_value = 0; rvec.inputs['Y'].default_value = 0
    tree.links.new(rot_mul.outputs['Value'], rvec.inputs['Z'])
    rot_inst = tree.nodes.new('GeometryNodeRotateInstances'); rot_inst.location = (base_x+600, 0)
    tree.links.new(inst.outputs['Instances'], rot_inst.inputs['Instances'])
    tree.links.new(rvec.outputs['Vector'], rot_inst.inputs['Rotation'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+900, 0)
    tree.links.new(rot_inst.outputs['Instances'], realize.inputs['Geometry'])

    geom = realize.outputs['Geometry']

    # Optional side balusters (whimsical)
    if props.stair_with_rails:
        baluster_line = tree.nodes.new('GeometryNodeMeshLine'); baluster_line.location = (base_x, 600)
        baluster_line.mode = 'OFFSET'
        baluster_line.inputs['Count'].default_value = count
        baluster_line.inputs['Start Location'].default_value = (0, width/2, rise*0.5)
        baluster_line.inputs['Offset'].default_value = (run_, 0, rise)
        color_node(baluster_line, "ornament")

        bal = tree.nodes.new('GeometryNodeMeshCylinder'); bal.location = (base_x, 800)
        bal.inputs['Vertices'].default_value = 6
        bal.inputs['Radius'].default_value = 0.04
        bal.inputs['Depth'].default_value = 0.5
        color_node(bal, "ornament")

        inst_b = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst_b.location = (base_x+300, 700)
        tree.links.new(baluster_line.outputs['Mesh'], inst_b.inputs['Points'])
        tree.links.new(bal.outputs['Mesh'], inst_b.inputs['Instance'])

        # Musical height modulation
        idx2 = tree.nodes.new('GeometryNodeInputIndex'); idx2.location = (base_x, 1000)
        h_val = make_harmonic_value(tree, idx2.outputs['Index'],
                                     props.musical_freq_a, props.musical_freq_b,
                                     props.harmonic_layers, base_x+200, 1000)
        map_h = tree.nodes.new('ShaderNodeMapRange'); map_h.location = (base_x+1000, 1000)
        map_h.inputs['From Min'].default_value = -2; map_h.inputs['From Max'].default_value = 2
        map_h.inputs['To Min'].default_value = 1.0 - props.ornament_density * 0.5
        map_h.inputs['To Max'].default_value = 1.0 + props.ornament_density * 0.5
        tree.links.new(h_val, map_h.inputs['Value'])

        sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+1200, 1000)
        sv.inputs['X'].default_value = 1; sv.inputs['Y'].default_value = 1
        tree.links.new(map_h.outputs['Result'], sv.inputs['Z'])

        scale_b = tree.nodes.new('GeometryNodeScaleInstances'); scale_b.location = (base_x+1400, 700)
        tree.links.new(inst_b.outputs['Instances'], scale_b.inputs['Instances'])
        tree.links.new(sv.outputs['Vector'], scale_b.inputs['Scale'])

        realize_b = tree.nodes.new('GeometryNodeRealizeInstances'); realize_b.location = (base_x+1600, 700)
        tree.links.new(scale_b.outputs['Instances'], realize_b.inputs['Geometry'])

        # Mirror on the other side too
        mirror_trans = tree.nodes.new('GeometryNodeTransform'); mirror_trans.location = (base_x+1800, 900)
        mirror_trans.inputs['Translation'].default_value = (0, -width, 0)
        tree.links.new(realize_b.outputs['Geometry'], mirror_trans.inputs['Geometry'])

        # Join sides
        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2100, 300); color_node(join, "output")
        tree.links.new(geom, join.inputs['Geometry'])
        tree.links.new(realize_b.outputs['Geometry'], join.inputs['Geometry'])
        tree.links.new(mirror_trans.outputs['Geometry'], join.inputs['Geometry'])
        geom = join.outputs['Geometry']

    return geom


# ----------------------------------------------------------------------
# BUILDER: ARCH
# ----------------------------------------------------------------------

def build_arch(tree, props, base_x=-1400):
    R = props.arch_radius
    sweep = math.radians(props.arch_sweep_deg)

    # Base arc
    curve = tree.nodes.new('GeometryNodeCurveArc'); curve.location = (base_x, 200); color_node(curve, "arch")
    curve.mode = 'RADIUS'
    curve.inputs['Resolution'].default_value = 32
    curve.inputs['Radius'].default_value = R
    curve.inputs['Sweep Angle'].default_value = sweep

    # Profile
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -200); color_node(profile, "arch")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.arch_thickness

    # Sweep
    sweep_node = tree.nodes.new('GeometryNodeCurveToMesh'); sweep_node.location = (base_x+300, 0); color_node(sweep_node, "arch")
    tree.links.new(curve.outputs['Curve'], sweep_node.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], sweep_node.inputs['Profile Curve'])
    sweep_node.inputs['Fill Caps'].default_value = True

    # Musical wave deformation on sweep
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, -500)
    harmonic = make_harmonic_value(tree, idx.outputs['Index'],
                                    props.musical_freq_a, props.musical_freq_b,
                                    props.harmonic_layers, base_x+200, -500)
    sc = tree.nodes.new('ShaderNodeMath'); sc.location = (base_x+1000, -500); sc.operation = 'MULTIPLY'
    sc.inputs[1].default_value = props.ornament_density * 0.1
    tree.links.new(harmonic, sc.inputs[0])

    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1200, -500)
    ovec.inputs['X'].default_value = 0; ovec.inputs['Y'].default_value = 0
    tree.links.new(sc.outputs['Value'], ovec.inputs['Z'])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (base_x+1400, 0); color_node(set_pos, "deform")
    tree.links.new(sweep_node.outputs['Mesh'], set_pos.inputs['Geometry'])
    tree.links.new(ovec.outputs['Vector'], set_pos.inputs['Offset'])

    geom = set_pos.outputs['Geometry']

    # Ribs
    if props.arch_rib_count > 0:
        sample = tree.nodes.new('GeometryNodeResampleCurve'); sample.location = (base_x+300, 500); color_node(sample, "ornament")
        sample.inputs['Mode'].default_value = 'Count'
        sample.inputs['Count'].default_value = props.arch_rib_count
        tree.links.new(curve.outputs['Curve'], sample.inputs['Curve'])

        c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+500, 500)
        c2p.mode = 'EVALUATED'
        tree.links.new(sample.outputs['Curve'], c2p.inputs['Curve'])

        rib = tree.nodes.new('GeometryNodeMeshCylinder'); rib.location = (base_x+500, 700); color_node(rib, "ornament")
        rib.inputs['Vertices'].default_value = 12
        rib.inputs['Radius'].default_value = props.arch_rib_radius
        rib.inputs['Depth'].default_value = max(0.05, props.arch_thickness * 0.6)

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+800, 500)
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(rib.outputs['Mesh'], inst.inputs['Instance'])
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

        # Musical scale modulation
        idx2 = tree.nodes.new('GeometryNodeInputIndex'); idx2.location = (base_x+500, 1000)
        h2 = make_harmonic_value(tree, idx2.outputs['Index'],
                                  props.musical_freq_a, props.musical_freq_b,
                                  props.harmonic_layers, base_x+700, 1000)
        sm = tree.nodes.new('ShaderNodeMapRange'); sm.location = (base_x+1500, 1000)
        sm.inputs['From Min'].default_value = -2; sm.inputs['From Max'].default_value = 2
        sm.inputs['To Min'].default_value = 1.0 - props.ornament_density * 0.4
        sm.inputs['To Max'].default_value = 1.0 + props.ornament_density * 0.4
        tree.links.new(h2, sm.inputs['Value'])
        sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+1700, 1000)
        tree.links.new(sm.outputs['Result'], sv.inputs['X'])
        tree.links.new(sm.outputs['Result'], sv.inputs['Y'])
        tree.links.new(sm.outputs['Result'], sv.inputs['Z'])

        scale_inst = tree.nodes.new('GeometryNodeScaleInstances'); scale_inst.location = (base_x+1900, 500)
        tree.links.new(inst.outputs['Instances'], scale_inst.inputs['Instances'])
        tree.links.new(sv.outputs['Vector'], scale_inst.inputs['Scale'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+2100, 500)
        tree.links.new(scale_inst.outputs['Instances'], realize.inputs['Geometry'])

        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2400, 0); color_node(join, "output")
        tree.links.new(geom, join.inputs['Geometry'])
        tree.links.new(realize.outputs['Geometry'], join.inputs['Geometry'])
        geom = join.outputs['Geometry']

    return geom


# ----------------------------------------------------------------------
# BUILDER: BUTTRESS
# ----------------------------------------------------------------------

def build_buttress(tree, props, base_x=-1400):
    span = props.buttress_span
    height = props.buttress_height
    bow = props.buttress_arch_bow

    # Curve from base to wall
    line = tree.nodes.new('GeometryNodeCurvePrimitiveLine'); line.location = (base_x, 200); color_node(line, "buttress")
    line.mode = 'POINTS'
    line.inputs['Start'].default_value = (0, 0, 0)
    line.inputs['End'].default_value = (span, 0, height)

    # Resample
    sample = tree.nodes.new('GeometryNodeResampleCurve'); sample.location = (base_x+300, 200); color_node(sample, "buttress")
    sample.inputs['Mode'].default_value = 'Count'
    sample.inputs['Count'].default_value = 32
    tree.links.new(line.outputs['Curve'], sample.inputs['Curve'])

    # Arch bow: Set Position with sin(π*t)
    param = tree.nodes.new('GeometryNodeSplineParameter'); param.location = (base_x+300, -200)
    mul_pi = tree.nodes.new('ShaderNodeMath'); mul_pi.location = (base_x+500, -200); mul_pi.operation = 'MULTIPLY'
    mul_pi.inputs[1].default_value = math.pi
    tree.links.new(param.outputs['Factor'], mul_pi.inputs[0])
    sine = tree.nodes.new('ShaderNodeMath'); sine.location = (base_x+700, -200); sine.operation = 'SINE'
    tree.links.new(mul_pi.outputs['Value'], sine.inputs[0])
    bow_h = tree.nodes.new('ShaderNodeMath'); bow_h.location = (base_x+900, -200); bow_h.operation = 'MULTIPLY'
    bow_h.inputs[1].default_value = bow
    tree.links.new(sine.outputs['Value'], bow_h.inputs[0])

    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1100, -200)
    ovec.inputs['X'].default_value = 0; ovec.inputs['Y'].default_value = 0
    tree.links.new(bow_h.outputs['Value'], ovec.inputs['Z'])

    set_arch = tree.nodes.new('GeometryNodeSetPosition'); set_arch.location = (base_x+600, 200); color_node(set_arch, "deform")
    tree.links.new(sample.outputs['Curve'], set_arch.inputs['Geometry'])
    tree.links.new(ovec.outputs['Vector'], set_arch.inputs['Offset'])

    # Profile
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "buttress")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 6
    profile.inputs['Radius'].default_value = 0.15

    sweep = tree.nodes.new('GeometryNodeCurveToMesh'); sweep.location = (base_x+1300, 0); color_node(sweep, "buttress")
    tree.links.new(set_arch.outputs['Geometry'], sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], sweep.inputs['Profile Curve'])
    sweep.inputs['Fill Caps'].default_value = True

    geom = sweep.outputs['Mesh']

    # Decorative bands
    if props.buttress_rib_count > 0:
        sample2 = tree.nodes.new('GeometryNodeResampleCurve'); sample2.location = (base_x+1300, 500); color_node(sample2, "ornament")
        sample2.inputs['Mode'].default_value = 'Count'
        sample2.inputs['Count'].default_value = props.buttress_rib_count
        tree.links.new(set_arch.outputs['Geometry'], sample2.inputs['Curve'])

        c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+1500, 500)
        c2p.mode = 'EVALUATED'
        tree.links.new(sample2.outputs['Curve'], c2p.inputs['Curve'])

        band = tree.nodes.new('GeometryNodeMeshCylinder'); band.location = (base_x+1500, 700); color_node(band, "ornament")
        band.inputs['Vertices'].default_value = 12
        band.inputs['Radius'].default_value = 0.22
        band.inputs['Depth'].default_value = 0.08

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+1800, 500)
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(band.outputs['Mesh'], inst.inputs['Instance'])
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

        # Musical scale modulation per band
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x+1500, 900)
        h = make_harmonic_value(tree, idx.outputs['Index'],
                                 props.musical_freq_a, props.musical_freq_b,
                                 props.harmonic_layers, base_x+1700, 900)
        mr = tree.nodes.new('ShaderNodeMapRange'); mr.location = (base_x+2500, 900)
        mr.inputs['From Min'].default_value = -2; mr.inputs['From Max'].default_value = 2
        mr.inputs['To Min'].default_value = 1.0 - props.ornament_density * 0.5
        mr.inputs['To Max'].default_value = 1.0 + props.ornament_density * 0.5
        tree.links.new(h, mr.inputs['Value'])
        sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+2700, 900)
        tree.links.new(mr.outputs['Result'], sv.inputs['X'])
        tree.links.new(mr.outputs['Result'], sv.inputs['Y'])
        sv.inputs['Z'].default_value = 1.0

        scale_b = tree.nodes.new('GeometryNodeScaleInstances'); scale_b.location = (base_x+2900, 500)
        tree.links.new(inst.outputs['Instances'], scale_b.inputs['Instances'])
        tree.links.new(sv.outputs['Vector'], scale_b.inputs['Scale'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+3100, 500)
        tree.links.new(scale_b.outputs['Instances'], realize.inputs['Geometry'])

        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+3400, 0); color_node(join, "output")
        tree.links.new(geom, join.inputs['Geometry'])
        tree.links.new(realize.outputs['Geometry'], join.inputs['Geometry'])
        geom = join.outputs['Geometry']

    # Finial at top of buttress
    if props.buttress_finial_size > 0.01:
        finial = tree.nodes.new('GeometryNodeMeshCone'); finial.location = (base_x+1300, 900); color_node(finial, "ornament")
        finial.inputs['Vertices'].default_value = 16  # bumped from 12 in v2.31
        finial.inputs['Radius Top'].default_value = 0
        finial.inputs['Radius Bottom'].default_value = props.buttress_finial_size * 0.4
        finial.inputs['Depth'].default_value = props.buttress_finial_size

        ftrans = tree.nodes.new('GeometryNodeTransform'); ftrans.location = (base_x+1600, 900)
        ftrans.inputs['Translation'].default_value = (span, 0, height + props.buttress_finial_size/2)
        tree.links.new(finial.outputs['Mesh'], ftrans.inputs['Geometry'])

        join2 = tree.nodes.new('GeometryNodeJoinGeometry'); join2.location = (base_x+3700, 0); color_node(join2, "output")
        tree.links.new(geom, join2.inputs['Geometry'])
        tree.links.new(ftrans.outputs['Geometry'], join2.inputs['Geometry'])
        geom = join2.outputs['Geometry']

    return geom


# ----------------------------------------------------------------------
# BUILDER: BUILDING (composite)
# ----------------------------------------------------------------------

def build_building(tree, props):
    """Composite building: tower body + railings on top + side arches + buttress."""
    parts = []

    # 1. Tower body (override height = floors * floor_height)
    total_h = props.building_floors * props.building_floor_height
    # Temp swap height
    saved_h = props.height
    saved_taper = props.taper_ratio
    props.height = total_h
    props.taper_ratio = max(0.1, props.taper_ratio * 0.6)  # less tapered for building
    tower_geom = build_tower(tree, props, base_x=-3500)
    props.height = saved_h
    props.taper_ratio = saved_taper

    parts.append(tower_geom)

    # 2. Top railing — computed at the actual tapered radius of the tower's top
    if props.building_with_railings:
        # tower top radius after taper (build_tower applies max(0.05, 1.0 - taper) at top)
        top_radius = props.base_radius * max(0.05, 1.0 - props.taper_ratio * 0.6)
        rail_len = max(1.0, top_radius * 2 * 1.05)  # snap to outer wall + tiny lip

        rail_geom = build_railing(
            tree, props, x_offset=4500, y_offset=0,
            length=rail_len,
            height=props.rail_height,
        )
        # Translate railing to top of tower (center)
        trans = tree.nodes.new('GeometryNodeTransform'); trans.location = (5500, 1500); color_node(trans, "railing")
        trans.inputs['Translation'].default_value = (0, 0, total_h/2)
        tree.links.new(rail_geom, trans.inputs['Geometry'])
        parts.append(trans.outputs['Geometry'])

        # Add 3 more rotated copies for all 4 sides of square top
        for side in range(1, 4):
            ang = math.radians(side * 90)
            rail_extra_geom = build_railing(
                tree, props, x_offset=4500 + side * 3000, y_offset=0,
                length=rail_len, height=props.rail_height,
            )
            trans2 = tree.nodes.new('GeometryNodeTransform'); trans2.location = (5500 + side*1500, 1500); color_node(trans2, "railing")
            trans2.inputs['Translation'].default_value = (0, 0, total_h/2)
            trans2.inputs['Rotation'].default_value = (0, 0, ang)
            tree.links.new(rail_extra_geom, trans2.inputs['Geometry'])
            parts.append(trans2.outputs['Geometry'])

    # 3. Side arches at each floor — placed around all 4 faces, snapped to outer wall
    if props.building_with_arches:
        # Compute the outer radius at top (after taper) so arches snap correctly
        # Tower body uses props.base_radius * (1 - 0.6 * taper_ratio) at top.
        # We'll position arches at the AVERAGE radius (mid-height of each floor)
        arch_geom = build_arch(tree, props, base_x=4500)

        # Place arches on all 4 faces × N per face × M floors
        per_face = max(1, props.building_arches_per_face)
        for floor in range(props.building_floors):
            # Compute Z and radius at this floor's center
            floor_t = (floor + 0.5) / max(1, props.building_floors)  # 0..1
            taper_factor = 1.0 - max(0.05, props.taper_ratio * 0.6) * floor_t
            radius_at_floor = props.base_radius * taper_factor * (1.05 if props.building_align_to_radius else 1.2)
            z = -total_h/2 + props.building_floor_height * (floor + 0.5)

            for face in range(4):
                face_angle = math.radians(face * 90)
                for slot in range(per_face):
                    # Spread slots along this face: -0.5*face_width .. +0.5*face_width
                    slot_t = (slot + 0.5) / per_face - 0.5  # -0.5..0.5
                    # face has tangent direction; for face 0 (+X): tangent = +Y
                    cx = math.cos(face_angle) * radius_at_floor + math.sin(face_angle) * slot_t * radius_at_floor * 1.4
                    cy = math.sin(face_angle) * radius_at_floor - math.cos(face_angle) * slot_t * radius_at_floor * 1.4

                    trans = tree.nodes.new('GeometryNodeTransform'); trans.location = (8000, 800 + (floor*4 + face)*120); color_node(trans, "arch")
                    trans.inputs['Translation'].default_value = (cx, cy, z)
                    # Face the arch outward
                    trans.inputs['Rotation'].default_value = (0, 0, face_angle)
                    tree.links.new(arch_geom, trans.inputs['Geometry'])
                    parts.append(trans.outputs['Geometry'])

    # 4. Flying buttress
    if props.building_with_buttress:
        but_geom = build_buttress(tree, props, base_x=8500)
        trans_b = tree.nodes.new('GeometryNodeTransform'); trans_b.location = (12000, -1000); color_node(trans_b, "buttress")
        trans_b.inputs['Translation'].default_value = (
            -props.base_radius - props.buttress_span,
            0,
            -total_h/2,
        )
        tree.links.new(but_geom, trans_b.inputs['Geometry'])
        parts.append(trans_b.outputs['Geometry'])

    # Join everything
    if len(parts) == 1:
        return parts[0]

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (13000, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: PENROSE IMPOSSIBLE STAIRS (M.C. Escher)
# ----------------------------------------------------------------------

def build_penrose(tree, props, base_x=-1400):
    """Penrose impossible stairs: 4 staircases joined in a square loop, ascending subtly."""
    steps_per_side = max(2, props.penrose_steps_per_side)
    total_steps = steps_per_side * 4
    side_length = props.penrose_side_length
    step_run = side_length / steps_per_side
    rise = props.penrose_rise

    line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x, 0); color_node(line, "penrose")
    line.mode = 'OFFSET'
    line.inputs['Count'].default_value = total_steps
    line.inputs['Offset'].default_value = (1, 0, 0)

    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, -300)

    div = tree.nodes.new('ShaderNodeMath'); div.location = (base_x+200, -300); div.operation = 'DIVIDE'
    div.inputs[1].default_value = float(steps_per_side)
    tree.links.new(idx.outputs['Index'], div.inputs[0])
    floor_div = tree.nodes.new('ShaderNodeMath'); floor_div.location = (base_x+400, -300); floor_div.operation = 'FLOOR'
    tree.links.new(div.outputs['Value'], floor_div.inputs[0])

    mod_n = tree.nodes.new('ShaderNodeMath'); mod_n.location = (base_x+200, -500); mod_n.operation = 'MODULO'
    mod_n.inputs[1].default_value = float(steps_per_side)
    tree.links.new(idx.outputs['Index'], mod_n.inputs[0])

    rot_a = tree.nodes.new('ShaderNodeMath'); rot_a.location = (base_x+600, -300); rot_a.operation = 'MULTIPLY'
    rot_a.inputs[1].default_value = math.pi / 2
    tree.links.new(floor_div.outputs['Value'], rot_a.inputs[0])

    x_pos = tree.nodes.new('ShaderNodeMath'); x_pos.location = (base_x+600, -500); x_pos.operation = 'MULTIPLY'
    x_pos.inputs[1].default_value = step_run
    tree.links.new(mod_n.outputs['Value'], x_pos.inputs[0])

    sub_xc = tree.nodes.new('ShaderNodeMath'); sub_xc.location = (base_x+800, -500); sub_xc.operation = 'SUBTRACT'
    sub_xc.inputs[1].default_value = side_length / 2
    tree.links.new(x_pos.outputs['Value'], sub_xc.inputs[0])

    local_pos = tree.nodes.new('ShaderNodeCombineXYZ'); local_pos.location = (base_x+1000, -500)
    tree.links.new(sub_xc.outputs['Value'], local_pos.inputs['X'])
    local_pos.inputs['Y'].default_value = side_length / 2
    local_pos.inputs['Z'].default_value = 0

    rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+800, -300)
    rvec.inputs['X'].default_value = 0; rvec.inputs['Y'].default_value = 0
    tree.links.new(rot_a.outputs['Value'], rvec.inputs['Z'])

    rotate = tree.nodes.new('ShaderNodeVectorRotate'); rotate.location = (base_x+1200, -400)
    rotate.rotation_type = 'EULER_XYZ'
    tree.links.new(local_pos.outputs['Vector'], rotate.inputs[0])
    tree.links.new(rvec.outputs['Vector'], rotate.inputs[4])

    z_height = tree.nodes.new('ShaderNodeMath'); z_height.location = (base_x+1200, -600); z_height.operation = 'MULTIPLY'
    z_height.inputs[1].default_value = rise
    tree.links.new(idx.outputs['Index'], z_height.inputs[0])

    add_z = tree.nodes.new('ShaderNodeCombineXYZ'); add_z.location = (base_x+1400, -600)
    add_z.inputs['X'].default_value = 0; add_z.inputs['Y'].default_value = 0
    tree.links.new(z_height.outputs['Value'], add_z.inputs['Z'])

    final_pos = tree.nodes.new('ShaderNodeVectorMath'); final_pos.location = (base_x+1600, -500); final_pos.operation = 'ADD'
    tree.links.new(rotate.outputs[0], final_pos.inputs[0])
    tree.links.new(add_z.outputs['Vector'], final_pos.inputs[1])

    cur_pos = tree.nodes.new('GeometryNodeInputPosition'); cur_pos.location = (base_x+1600, -300)
    delta = tree.nodes.new('ShaderNodeVectorMath'); delta.location = (base_x+1800, -400); delta.operation = 'SUBTRACT'
    tree.links.new(final_pos.outputs[0], delta.inputs[0])
    tree.links.new(cur_pos.outputs['Position'], delta.inputs[1])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (base_x+2000, 0); color_node(set_pos, "deform")
    tree.links.new(line.outputs['Mesh'], set_pos.inputs['Geometry'])
    tree.links.new(delta.outputs[0], set_pos.inputs['Offset'])

    step = tree.nodes.new('GeometryNodeMeshCube'); step.location = (base_x+1600, 200); color_node(step, "penrose")
    step.inputs['Size'].default_value = (step_run * 0.95, 0.5, max(rise, 0.05) * 0.9 + 0.05)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+2200, 0)
    tree.links.new(set_pos.outputs['Geometry'], inst.inputs['Points'])
    tree.links.new(step.outputs['Mesh'], inst.inputs['Instance'])

    rot_inst = tree.nodes.new('GeometryNodeRotateInstances'); rot_inst.location = (base_x+2400, 0)
    tree.links.new(inst.outputs['Instances'], rot_inst.inputs['Instances'])
    tree.links.new(rvec.outputs['Vector'], rot_inst.inputs['Rotation'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+2600, 0)
    tree.links.new(rot_inst.outputs['Instances'], realize.inputs['Geometry'])

    return realize.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: PILLAR / COLUMN
# ----------------------------------------------------------------------

def build_pillar(tree, props, base_x=-1400):
    """Classical fluted pillar with capital + base.
    v2.52: When Higgsas is available, uses NTSpin to lathe a custom profile
    (wider at base, entasis bulge at 1/3) → NTTaper for classical entasis.
    Falls back to cylinder + cosine-flute deform when Higgsas is absent."""
    R = props.pillar_radius
    H = props.pillar_height
    n_flutes = props.pillar_flutes

    # ── Higgsas path: NTSpin profile + NTTaper entasis ─────────────────
    higg_spin = _higg_node(tree, 'NTSpin', (base_x, 0))
    if higg_spin is not None:
        # Build a half-profile curve (quarter of a circle for the shaft cross-section)
        # Use a CurveArc for the shaft silhouette, then spin 360°
        profile_arc = _safe_node(tree, 'GeometryNodeCurveArc', (base_x - 300, 0))
        if profile_arc:
            try:
                profile_arc.mode = 'RADIUS'
                profile_arc.inputs['Radius'].default_value      = R
                profile_arc.inputs['Start Angle'].default_value = 0
                profile_arc.inputs['Sweep Angle'].default_value = math.pi / 2
                profile_arc.inputs['Resolution'].default_value  = 8
            except Exception: pass
            fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x - 100, 0))
            if fill:
                _link(tree, profile_arc.outputs['Curve'], fill.inputs['Curve'])
                _higg_input(higg_spin, 'Angle', math.tau)   # full 360°
                _higg_input(higg_spin, 'Steps', max(16, n_flutes * 2))
                try:
                    _link(tree, fill.outputs['Mesh'], higg_spin.inputs['Mesh'])
                except Exception: pass
        # Apply Higgsas NTTaper for entasis (slight bulge at mid-height)
        higg_taper = _higg_node(tree, 'NTTaper', (base_x + 400, 0))
        geom_out = higg_spin.outputs.get('Mesh') or higg_spin.outputs[0]
        if higg_taper is not None:
            _higg_input(higg_taper, 'Upper Factor', 0.90)
            _higg_input(higg_taper, 'Lower Factor', 1.08)
            try:
                _link(tree, geom_out, higg_taper.inputs['Geometry'])
                geom_out = higg_taper.outputs['Geometry']
            except Exception: pass
        # Extrude to height
        ext_t = _safe_node(tree, 'GeometryNodeTransform', (base_x + 700, 0))
        if ext_t:
            try: ext_t.inputs['Scale'].default_value = (1, 1, H)
            except Exception: pass
            _link(tree, geom_out, ext_t.inputs['Geometry'])
            geom_out = ext_t.outputs['Geometry']
        color_node(higg_spin, 'pillar')
        # Still add native capital + base on top
        # Fall through to capital code below with geom = geom_out
        geom = geom_out
        # Skip the cylinder+flute section — jump straight to capital
        # (done via goto-equivalent: just don't define shaft; set n_flutes=0 for capital section)
        shaft = None
        n_flutes_orig = n_flutes
        n_flutes = 0   # suppress flute deform (already handled by NTSpin)
        # Rerun capital section inline
        cap = tree.nodes.new('GeometryNodeMeshCone'); cap.location = (base_x+300, 700); color_node(cap, "pillar")
        cap.inputs['Vertices'].default_value     = max(16, n_flutes_orig * 2)
        cap.inputs['Radius Top'].default_value   = props.pillar_capital_size
        cap.inputs['Radius Bottom'].default_value= R + 0.05
        cap.inputs['Depth'].default_value        = 0.4
        cap_t = tree.nodes.new('GeometryNodeTransform'); cap_t.location = (base_x+600, 700)
        cap_t.inputs['Translation'].default_value = (0, 0, H/2 + 0.2)
        tree.links.new(cap.outputs['Mesh'], cap_t.inputs['Geometry'])
        parts = [geom, cap_t.outputs['Geometry']]
        for layer in range(props.pillar_capital_layers):
            ring = tree.nodes.new('GeometryNodeMeshCylinder'); ring.location = (base_x+600, 700 + layer*200); color_node(ring, "ornament")
            ring.inputs['Vertices'].default_value = 16
            ring.inputs['Radius'].default_value  = props.pillar_capital_size * (1.0 - layer*0.08)
            ring.inputs['Depth'].default_value   = 0.06
            ring_t = tree.nodes.new('GeometryNodeTransform'); ring_t.location = (base_x+900, 700 + layer*200)
            ring_t.inputs['Translation'].default_value = (0, 0, H/2 + 0.4 + layer*0.1)
            tree.links.new(ring.outputs['Mesh'], ring_t.inputs['Geometry'])
            parts.append(ring_t.outputs['Geometry'])
        base_cone = tree.nodes.new('GeometryNodeMeshCone'); base_cone.location = (base_x+300, -1000); color_node(base_cone, "pillar")
        base_cone.inputs['Vertices'].default_value    = max(16, n_flutes_orig * 2)
        base_cone.inputs['Radius Top'].default_value  = R + 0.05
        base_cone.inputs['Radius Bottom'].default_value = props.pillar_capital_size
        base_cone.inputs['Depth'].default_value       = 0.4
        base_t = tree.nodes.new('GeometryNodeTransform'); base_t.location = (base_x+600, -1000)
        base_t.inputs['Translation'].default_value = (0, 0, -H/2 - 0.2)
        tree.links.new(base_cone.outputs['Mesh'], base_t.inputs['Geometry'])
        parts.append(base_t.outputs['Geometry'])
        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1700, 0); color_node(join, "output")
        for p in parts: tree.links.new(p, join.inputs['Geometry'])
        return join.outputs['Geometry']

    # ── Native fallback: cylinder + cosine-flute deform ────────────────
    shaft = tree.nodes.new('GeometryNodeMeshCylinder'); shaft.location = (base_x, 0); color_node(shaft, "pillar")
    shaft.inputs['Vertices'].default_value = max(16, n_flutes * 2)
    shaft.inputs['Side Segments'].default_value = 8
    shaft.inputs['Radius'].default_value = R
    shaft.inputs['Depth'].default_value = H

    geom = shaft.outputs['Mesh']

    # Flutes via radial cosine on radius
    if n_flutes > 0 and props.pillar_flute_depth > 0.001:
        pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (base_x, -400); color_node(pos, "input")
        sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (base_x+200, -400)
        tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

        atan2 = tree.nodes.new('ShaderNodeMath'); atan2.location = (base_x+400, -400); atan2.operation = 'ARCTAN2'
        tree.links.new(sep.outputs['Y'], atan2.inputs[0])
        tree.links.new(sep.outputs['X'], atan2.inputs[1])

        flute_freq = tree.nodes.new('ShaderNodeMath'); flute_freq.location = (base_x+600, -400); flute_freq.operation = 'MULTIPLY'
        flute_freq.inputs[1].default_value = float(n_flutes)
        tree.links.new(atan2.outputs['Value'], flute_freq.inputs[0])

        flute_cos = tree.nodes.new('ShaderNodeMath'); flute_cos.location = (base_x+800, -400); flute_cos.operation = 'COSINE'
        tree.links.new(flute_freq.outputs['Value'], flute_cos.inputs[0])
        color_node(flute_cos, "ornament")

        flute_amp = tree.nodes.new('ShaderNodeMath'); flute_amp.location = (base_x+1000, -400); flute_amp.operation = 'MULTIPLY'
        flute_amp.inputs[1].default_value = props.pillar_flute_depth
        tree.links.new(flute_cos.outputs['Value'], flute_amp.inputs[0])

        rad_vec = tree.nodes.new('ShaderNodeCombineXYZ'); rad_vec.location = (base_x+800, -200)
        tree.links.new(sep.outputs['X'], rad_vec.inputs['X'])
        tree.links.new(sep.outputs['Y'], rad_vec.inputs['Y'])
        rad_vec.inputs['Z'].default_value = 0

        norm = tree.nodes.new('ShaderNodeVectorMath'); norm.location = (base_x+1000, -200); norm.operation = 'NORMALIZE'
        tree.links.new(rad_vec.outputs['Vector'], norm.inputs[0])

        flute_offset = tree.nodes.new('ShaderNodeVectorMath'); flute_offset.location = (base_x+1200, -300); flute_offset.operation = 'SCALE'
        tree.links.new(norm.outputs['Vector'], flute_offset.inputs[0])
        tree.links.new(flute_amp.outputs['Value'], flute_offset.inputs['Scale'])

        set_flute = tree.nodes.new('GeometryNodeSetPosition'); set_flute.location = (base_x+1400, 0); color_node(set_flute, "deform")
        tree.links.new(geom, set_flute.inputs['Geometry'])
        tree.links.new(flute_offset.outputs[0], set_flute.inputs['Offset'])
        geom = set_flute.outputs['Geometry']

    # Capital — tapered cone
    cap = tree.nodes.new('GeometryNodeMeshCone'); cap.location = (base_x, 700); color_node(cap, "pillar")
    cap.inputs['Vertices'].default_value = max(16, n_flutes * 2)
    cap.inputs['Radius Top'].default_value    = props.pillar_capital_size
    cap.inputs['Radius Bottom'].default_value = R + 0.05
    cap.inputs['Depth'].default_value         = 0.4

    cap_t = tree.nodes.new('GeometryNodeTransform'); cap_t.location = (base_x+300, 700); color_node(cap_t, "pillar")
    cap_t.inputs['Translation'].default_value = (0, 0, H/2 + 0.2)
    tree.links.new(cap.outputs['Mesh'], cap_t.inputs['Geometry'])

    # Capital decorative rings
    parts = [geom, cap_t.outputs['Geometry']]
    for layer in range(props.pillar_capital_layers):
        ring = tree.nodes.new('GeometryNodeMeshCylinder'); ring.location = (base_x+600, 700 + layer * 200); color_node(ring, "ornament")
        ring.inputs['Vertices'].default_value = 16
        ring.inputs['Radius'].default_value = props.pillar_capital_size * (1.0 - layer * 0.08)
        ring.inputs['Depth'].default_value = 0.06

        ring_t = tree.nodes.new('GeometryNodeTransform'); ring_t.location = (base_x+900, 700 + layer * 200)
        ring_t.inputs['Translation'].default_value = (0, 0, H/2 + 0.4 + layer * 0.1)
        tree.links.new(ring.outputs['Mesh'], ring_t.inputs['Geometry'])
        parts.append(ring_t.outputs['Geometry'])

    # Base (mirror of capital)
    base = tree.nodes.new('GeometryNodeMeshCone'); base.location = (base_x, -1000); color_node(base, "pillar")
    base.inputs['Vertices'].default_value = max(16, n_flutes * 2)
    base.inputs['Radius Top'].default_value    = R + 0.05
    base.inputs['Radius Bottom'].default_value = props.pillar_capital_size
    base.inputs['Depth'].default_value         = 0.4

    base_t = tree.nodes.new('GeometryNodeTransform'); base_t.location = (base_x+300, -1000); color_node(base_t, "pillar")
    base_t.inputs['Translation'].default_value = (0, 0, -H/2 - 0.2)
    tree.links.new(base.outputs['Mesh'], base_t.inputs['Geometry'])
    parts.append(base_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1700, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: DOME
# ----------------------------------------------------------------------

def build_dome(tree, props, base_x=-1400):
    """Hemispherical dome with longitudinal ribs and optional spire."""
    R = props.dome_radius

    # Top half of UV sphere via boolean cut
    sphere = tree.nodes.new('GeometryNodeMeshUVSphere'); sphere.location = (base_x, 0); color_node(sphere, "dome")
    sphere.inputs['Segments'].default_value = props.dome_segments
    sphere.inputs['Rings'].default_value    = props.dome_rings
    sphere.inputs['Radius'].default_value   = R

    cutter = tree.nodes.new('GeometryNodeMeshCube'); cutter.location = (base_x, -300); color_node(cutter, "dome")
    cutter.inputs['Size'].default_value = (R * 4, R * 4, R * 4)
    cut_t = tree.nodes.new('GeometryNodeTransform'); cut_t.location = (base_x+300, -300)
    cut_t.inputs['Translation'].default_value = (0, 0, -R * 2)
    tree.links.new(cutter.outputs['Mesh'], cut_t.inputs['Geometry'])

    bool_n = tree.nodes.new('GeometryNodeMeshBoolean'); bool_n.location = (base_x+600, 0); color_node(bool_n, "dome")
    bool_n.operation = 'DIFFERENCE'
    tree.links.new(sphere.outputs['Mesh'], bool_n.inputs[0])
    tree.links.new(cut_t.outputs['Geometry'], bool_n.inputs[1])

    parts = [bool_n.outputs[0]]

    # Ribs
    if props.dome_rib_count > 0:
        # Rib profile
        rib_profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); rib_profile.location = (base_x, 600); color_node(rib_profile, "ornament")
        rib_profile.mode = 'RADIUS'
        rib_profile.inputs['Resolution'].default_value = 6
        rib_profile.inputs['Radius'].default_value = 0.04

        # Single arc that spans dome
        arc = tree.nodes.new('GeometryNodeCurveArc'); arc.location = (base_x, 900); color_node(arc, "dome")
        arc.mode = 'RADIUS'
        arc.inputs['Resolution'].default_value = 32
        arc.inputs['Radius'].default_value = R
        arc.inputs['Sweep Angle'].default_value = math.radians(180)

        arc_orient = tree.nodes.new('GeometryNodeTransform'); arc_orient.location = (base_x+300, 900)
        arc_orient.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
        tree.links.new(arc.outputs['Curve'], arc_orient.inputs['Geometry'])

        rib_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); rib_sweep.location = (base_x+600, 800); color_node(rib_sweep, "ornament")
        tree.links.new(arc_orient.outputs['Geometry'], rib_sweep.inputs['Curve'])
        tree.links.new(rib_profile.outputs['Curve'], rib_sweep.inputs['Profile Curve'])
        rib_sweep.inputs['Fill Caps'].default_value = True

        # Instance ribs around dome
        n_ribs = props.dome_rib_count
        circle = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); circle.location = (base_x+900, 600)
        circle.mode = 'RADIUS'
        circle.inputs['Resolution'].default_value = n_ribs
        circle.inputs['Radius'].default_value = 0.01

        c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+1100, 600)
        c2p.mode = 'EVALUATED'
        tree.links.new(circle.outputs['Curve'], c2p.inputs['Curve'])

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+1300, 600)
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(rib_sweep.outputs['Mesh'], inst.inputs['Instance'])

        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x+1100, 900)
        rmul = tree.nodes.new('ShaderNodeMath'); rmul.location = (base_x+1300, 900); rmul.operation = 'MULTIPLY'
        rmul.inputs[1].default_value = math.tau / n_ribs
        tree.links.new(idx.outputs['Index'], rmul.inputs[0])

        rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+1500, 900)
        rvec.inputs['X'].default_value = 0; rvec.inputs['Y'].default_value = 0
        tree.links.new(rmul.outputs['Value'], rvec.inputs['Z'])

        rot_inst = tree.nodes.new('GeometryNodeRotateInstances'); rot_inst.location = (base_x+1700, 600)
        tree.links.new(inst.outputs['Instances'], rot_inst.inputs['Instances'])
        tree.links.new(rvec.outputs['Vector'], rot_inst.inputs['Rotation'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1900, 600)
        tree.links.new(rot_inst.outputs['Instances'], realize.inputs['Geometry'])

        parts.append(realize.outputs['Geometry'])

    # Spire
    if props.dome_spire > 0.01:
        spire = tree.nodes.new('GeometryNodeMeshCone'); spire.location = (base_x, 1300); color_node(spire, "ornament")
        spire.inputs['Vertices'].default_value = 16  # bumped from 12 in v2.31
        spire.inputs['Radius Top'].default_value = 0.0
        spire.inputs['Radius Bottom'].default_value = props.dome_spire * 0.2
        spire.inputs['Depth'].default_value = props.dome_spire

        spire_t = tree.nodes.new('GeometryNodeTransform'); spire_t.location = (base_x+300, 1300)
        spire_t.inputs['Translation'].default_value = (0, 0, R + props.dome_spire / 2)
        tree.links.new(spire.outputs['Mesh'], spire_t.inputs['Geometry'])
        parts.append(spire_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2200, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: CRENELLATION (Castle Battlements)
# ----------------------------------------------------------------------

def build_crenellation(tree, props, base_x=-1400):
    """Castle wall with merlons (alternating high/low tops)."""
    L = props.crenel_length
    H = props.crenel_height
    T = props.crenel_thickness
    n_merlons = max(2, props.crenel_merlon_count)
    merlon_h = props.crenel_merlon_height
    gap = props.crenel_gap_ratio

    # Wall body
    wall = tree.nodes.new('GeometryNodeMeshCube'); wall.location = (base_x, 0); color_node(wall, "crenel")
    wall.inputs['Size'].default_value = (L, T, H)

    # Merlon block dimensions
    merlon_period = L / n_merlons
    merlon_width = merlon_period * (1.0 - gap)

    # Line of points for merlons
    line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x, 400); color_node(line, "crenel")
    line.mode = 'OFFSET'
    line.inputs['Count'].default_value = n_merlons
    line.inputs['Start Location'].default_value = (-L/2 + merlon_period/2, 0, H/2 + merlon_h/2)
    line.inputs['Offset'].default_value = (merlon_period, 0, 0)

    # Merlon block
    merlon = tree.nodes.new('GeometryNodeMeshCube'); merlon.location = (base_x, 700); color_node(merlon, "crenel")
    merlon.inputs['Size'].default_value = (merlon_width, T, merlon_h)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+300, 500)
    tree.links.new(line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(merlon.outputs['Mesh'], inst.inputs['Instance'])

    # Whimsical: musical height variation per merlon
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 900)
    h_val = make_harmonic_value(tree, idx.outputs['Index'],
                                 props.musical_freq_a * NOTE_PATTERNS.get(props.note_pattern, 4.0) * props.tempo_factor / 4.0,
                                 props.musical_freq_b * NOTE_PATTERNS.get(props.note_pattern, 4.0) * props.tempo_factor / 4.0,
                                 props.harmonic_layers, base_x+200, 900)
    mr = tree.nodes.new('ShaderNodeMapRange'); mr.location = (base_x+1000, 900)
    mr.inputs['From Min'].default_value = -2; mr.inputs['From Max'].default_value = 2
    mr.inputs['To Min'].default_value = 1.0 - props.ornament_density * 0.5
    mr.inputs['To Max'].default_value = 1.0 + props.ornament_density * 0.5
    tree.links.new(h_val, mr.inputs['Value'])

    sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+1200, 900); color_node(sv, "ornament")
    sv.inputs['X'].default_value = 1; sv.inputs['Y'].default_value = 1
    tree.links.new(mr.outputs['Result'], sv.inputs['Z'])

    scale_m = tree.nodes.new('GeometryNodeScaleInstances'); scale_m.location = (base_x+1400, 500)
    tree.links.new(inst.outputs['Instances'], scale_m.inputs['Instances'])
    tree.links.new(sv.outputs['Vector'], scale_m.inputs['Scale'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1600, 500)
    tree.links.new(scale_m.outputs['Instances'], realize.inputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1900, 0); color_node(join, "output")
    tree.links.new(wall.outputs['Mesh'], join.inputs['Geometry'])
    tree.links.new(realize.outputs['Geometry'], join.inputs['Geometry'])

    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: FRACTAL TOWER (recursive self-similar)
# ----------------------------------------------------------------------

def build_fractal(tree, props, base_x=-2400):
    """Self-similar recursive tower stack. Each iteration scales smaller and offsets."""
    iterations = props.fractal_iterations
    scale_per  = props.fractal_scale
    offset_per = props.fractal_offset
    twist_per  = math.radians(props.fractal_twist_per)

    # Build base tower (use existing build_tower)
    base_geom = build_tower(tree, props, base_x=base_x)

    parts = [base_geom]
    accumulated_height = props.height

    for i in range(1, iterations):
        s = scale_per ** i
        # Re-instance / re-create scaled-down copy at progressive height
        # Simpler: use Transform on the same geometry
        trans = tree.nodes.new('GeometryNodeTransform'); trans.location = (base_x + 4000, -300 - i * 200); color_node(trans, "fractal")
        # Stack on top with diminishing radius/height
        stack_z = (accumulated_height + props.height * s) / 2 + 0.1
        trans.inputs['Translation'].default_value = (offset_per * i * 0.4, 0, stack_z)
        trans.inputs['Rotation'].default_value = (0, 0, twist_per * i)
        trans.inputs['Scale'].default_value = (s, s, s)
        tree.links.new(base_geom, trans.inputs['Geometry'])
        parts.append(trans.outputs['Geometry'])
        accumulated_height += props.height * s

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x + 4500, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: TREBLE CLEF (musical notation)
# ----------------------------------------------------------------------

def build_treble_clef(tree, props, base_x=-1400):
    """
    Properly-shaped G-clef ornament:
      • Flat 2D spiral curl (not a helix) — sits in the XZ plane facing forward
      • S-curve stem above the spiral (Bezier — captures the iconic clef shape)
      • Tail loop below the spiral
      • Finial dots at top and bottom
    """
    s = props.clef_size / 2.0  # scale (default size 2 → unit scale)
    thick = props.clef_thickness

    # === Profile circle for sweeping (small radius for thin lines) ===
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -300); color_node(profile, "music")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = thick

    # === Belly spiral — FLAT 2D curl in XY (not helical) ===
    spiral = tree.nodes.new('GeometryNodeCurveSpiral'); spiral.location = (base_x, 0); color_node(spiral, "music")
    spiral.inputs['Resolution'].default_value = 96
    spiral.inputs['Rotations'].default_value = props.clef_curls
    spiral.inputs['Start Radius'].default_value = 0.08 * s
    spiral.inputs['End Radius'].default_value = 0.45 * s
    spiral.inputs['Height'].default_value = 0.0  # ← FLAT, no helix

    # Rotate spiral 90° around X so it stands up in XZ plane (facing forward),
    # then translate down to the belly position
    spiral_t = tree.nodes.new('GeometryNodeTransform'); spiral_t.location = (base_x+300, 0); color_node(spiral_t, "music")
    spiral_t.inputs['Translation'].default_value = (0, 0, -0.05 * s)
    spiral_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(spiral.outputs['Curve'], spiral_t.inputs['Geometry'])

    spiral_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); spiral_sweep.location = (base_x+600, 0); color_node(spiral_sweep, "music")
    tree.links.new(spiral_t.outputs['Geometry'], spiral_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], spiral_sweep.inputs['Profile Curve'])
    spiral_sweep.inputs['Fill Caps'].default_value = True

    # === Stem — Bezier S-curve from spiral top going up & slightly right then back ===
    # The clef stem starts at the top of the spiral (~+0.45s above belly center)
    # and goes up and slightly to the right, then back left at the top
    stem = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); stem.location = (base_x, 600); color_node(stem, "music")
    stem.inputs['Resolution'].default_value = 48
    # In XZ plane (Bezier defaults to XY, so we'll rotate 90° around X afterwards)
    stem.inputs['Start'].default_value         = (0.0,        0.45 * s, 0)   # belly top
    stem.inputs['Start Handle'].default_value  = (0.4  * s,   0.95 * s, 0)   # bulge right & up
    stem.inputs['End Handle'].default_value    = (0.15 * s,   1.55 * s, 0)   # come back toward center
    stem.inputs['End'].default_value           = (-0.15 * s,  1.65 * s, 0)   # tip slightly left

    stem_t = tree.nodes.new('GeometryNodeTransform'); stem_t.location = (base_x+300, 600); color_node(stem_t, "music")
    stem_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)  # XY → XZ plane
    tree.links.new(stem.outputs['Curve'], stem_t.inputs['Geometry'])

    stem_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); stem_sweep.location = (base_x+600, 600); color_node(stem_sweep, "music")
    tree.links.new(stem_t.outputs['Geometry'], stem_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], stem_sweep.inputs['Profile Curve'])
    stem_sweep.inputs['Fill Caps'].default_value = True

    # === Tail — Bezier S-curve below the spiral (the descending loop of a G clef) ===
    tail = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); tail.location = (base_x, -600); color_node(tail, "music")
    tail.inputs['Resolution'].default_value = 32
    tail.inputs['Start'].default_value         = (0.0,        -0.45 * s, 0)
    tail.inputs['Start Handle'].default_value  = (-0.30 * s,  -0.85 * s, 0)
    tail.inputs['End Handle'].default_value    = (-0.10 * s,  -1.05 * s, 0)
    tail.inputs['End'].default_value           = (0.05 * s,   -1.10 * s, 0)

    tail_t = tree.nodes.new('GeometryNodeTransform'); tail_t.location = (base_x+300, -600); color_node(tail_t, "music")
    tail_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(tail.outputs['Curve'], tail_t.inputs['Geometry'])

    tail_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); tail_sweep.location = (base_x+600, -600); color_node(tail_sweep, "music")
    tree.links.new(tail_t.outputs['Geometry'], tail_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], tail_sweep.inputs['Profile Curve'])
    tail_sweep.inputs['Fill Caps'].default_value = True

    # === Top finial — small sphere at the tip of the stem ===
    finial = tree.nodes.new('GeometryNodeMeshUVSphere'); finial.location = (base_x, 1000); color_node(finial, "ornament")
    finial.inputs['Radius'].default_value = thick * 2.2
    finial.inputs['Segments'].default_value = 16
    finial.inputs['Rings'].default_value = 12
    finial_t = tree.nodes.new('GeometryNodeTransform'); finial_t.location = (base_x+300, 1000); color_node(finial_t, "ornament")
    finial_t.inputs['Translation'].default_value = (-0.15 * s, 0, 1.65 * s)
    tree.links.new(finial.outputs['Mesh'], finial_t.inputs['Geometry'])

    # === Bottom dot — at the tail end (the iconic dot below the G-clef) ===
    bd = tree.nodes.new('GeometryNodeMeshUVSphere'); bd.location = (base_x, -1000); color_node(bd, "ornament")
    bd.inputs['Radius'].default_value = thick * 2.0
    bd.inputs['Segments'].default_value = 16
    bd.inputs['Rings'].default_value = 12
    bd_t = tree.nodes.new('GeometryNodeTransform'); bd_t.location = (base_x+300, -1000); color_node(bd_t, "ornament")
    bd_t.inputs['Translation'].default_value = (0.05 * s, 0, -1.10 * s)
    tree.links.new(bd.outputs['Mesh'], bd_t.inputs['Geometry'])

    # === Join all ===
    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+900, 0); color_node(join, "output")
    tree.links.new(spiral_sweep.outputs['Mesh'], join.inputs['Geometry'])
    tree.links.new(stem_sweep.outputs['Mesh'], join.inputs['Geometry'])
    tree.links.new(tail_sweep.outputs['Mesh'], join.inputs['Geometry'])
    tree.links.new(finial_t.outputs['Geometry'], join.inputs['Geometry'])
    tree.links.new(bd_t.outputs['Geometry'], join.inputs['Geometry'])

    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: NOTE HEAD
# ----------------------------------------------------------------------

def build_note_head(tree, props, base_x=-1400):
    """A musical note head with optional stem. Whole/half are hollow, quarter/eighth are filled."""
    s = props.note_size
    kind = props.note_kind

    # Note head — flattened oval (UV sphere with non-uniform scale)
    head = tree.nodes.new('GeometryNodeMeshUVSphere'); head.location = (base_x, 0); color_node(head, "music")
    head.inputs['Radius'].default_value = s * 0.5
    head.inputs['Segments'].default_value = 24
    head.inputs['Rings'].default_value = 12

    # Tilt and flatten the head (Italian style)
    head_t = tree.nodes.new('GeometryNodeTransform'); head_t.location = (base_x+300, 0)
    head_t.inputs['Scale'].default_value = (1.2, 0.85, 0.45)  # flatter on Y, rounded
    head_t.inputs['Rotation'].default_value = (0, math.radians(-15), 0)
    tree.links.new(head.outputs['Mesh'], head_t.inputs['Geometry'])

    parts = [head_t.outputs['Geometry']]

    # Stem — for half/quarter/eighth notes
    if kind in {'HALF_NOTE', 'QUARTER', 'EIGHTH_NOTE'}:
        stem = tree.nodes.new('GeometryNodeMeshCube'); stem.location = (base_x, 300); color_node(stem, "music")
        stem.inputs['Size'].default_value = (0.05 * s, 0.05 * s, props.note_stem_len)

        stem_t = tree.nodes.new('GeometryNodeTransform'); stem_t.location = (base_x+300, 300)
        stem_t.inputs['Translation'].default_value = (s * 0.55, 0, props.note_stem_len / 2)
        tree.links.new(stem.outputs['Mesh'], stem_t.inputs['Geometry'])
        parts.append(stem_t.outputs['Geometry'])

    # Flag — for eighth notes
    if kind == 'EIGHTH_NOTE':
        flag_curve = tree.nodes.new('GeometryNodeCurveArc'); flag_curve.location = (base_x, 600); color_node(flag_curve, "music")
        flag_curve.mode = 'RADIUS'
        flag_curve.inputs['Resolution'].default_value = 16
        flag_curve.inputs['Radius'].default_value = 0.3 * s
        flag_curve.inputs['Sweep Angle'].default_value = math.radians(120)

        flag_profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); flag_profile.location = (base_x, 800)
        flag_profile.mode = 'RADIUS'
        flag_profile.inputs['Resolution'].default_value = 6
        flag_profile.inputs['Radius'].default_value = 0.04 * s

        flag_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); flag_sweep.location = (base_x+300, 600)
        tree.links.new(flag_curve.outputs['Curve'], flag_sweep.inputs['Curve'])
        tree.links.new(flag_profile.outputs['Curve'], flag_sweep.inputs['Profile Curve'])

        flag_t = tree.nodes.new('GeometryNodeTransform'); flag_t.location = (base_x+600, 600)
        flag_t.inputs['Translation'].default_value = (s * 0.55, 0, props.note_stem_len)
        flag_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
        tree.links.new(flag_sweep.outputs['Mesh'], flag_t.inputs['Geometry'])
        parts.append(flag_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+900, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: STAFF (5 lines + arrayed notes)
# ----------------------------------------------------------------------

def build_staff(tree, props, base_x=-1400):
    """Five-line musical staff with arrayed note heads at musical-rhythm positions."""
    L = props.staff_length
    n_notes = props.staff_note_count
    line_thick = props.staff_line_thickness

    # Five horizontal staff lines
    parts = []
    for i in range(5):
        z = (i - 2) * 0.25  # spacing 0.25 between lines, centered at 0
        ln = tree.nodes.new('GeometryNodeMeshCube'); ln.location = (base_x, i * 100); color_node(ln, "music")
        ln.inputs['Size'].default_value = (L, line_thick, line_thick)
        lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x+200, i * 100)
        lt.inputs['Translation'].default_value = (0, 0, z)
        tree.links.new(ln.outputs['Mesh'], lt.inputs['Geometry'])
        parts.append(lt.outputs['Geometry'])

    # Note positions along the staff
    note_line = tree.nodes.new('GeometryNodeMeshLine'); note_line.location = (base_x, 700); color_node(note_line, "music")
    note_line.mode = 'END_POINTS'
    note_line.inputs['Count'].default_value = max(1, n_notes)
    note_line.inputs['Start Location'].default_value = (-L * 0.4, 0, 0)
    note_line.inputs['Offset'].default_value = (L * 0.8, 0, 0)

    # Note head primitive
    note_head = tree.nodes.new('GeometryNodeMeshUVSphere'); note_head.location = (base_x, 900); color_node(note_head, "music")
    note_head.inputs['Radius'].default_value = 0.18
    note_head.inputs['Segments'].default_value = 16
    note_head.inputs['Rings'].default_value = 12

    # Flatten note
    note_flat = tree.nodes.new('GeometryNodeTransform'); note_flat.location = (base_x+200, 900)
    note_flat.inputs['Scale'].default_value = (1.2, 0.6, 0.5)
    tree.links.new(note_head.outputs['Mesh'], note_flat.inputs['Geometry'])

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+500, 700)
    tree.links.new(note_line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(note_flat.outputs['Geometry'], inst.inputs['Instance'])

    # Vary note Z position (pitch) using harmonic — creates a melody
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 1100)
    h = make_harmonic_value(tree, idx.outputs['Index'],
                             props.musical_freq_a, props.musical_freq_b,
                             props.harmonic_layers, base_x+200, 1100)
    map_z = tree.nodes.new('ShaderNodeMapRange'); map_z.location = (base_x+1000, 1100)
    map_z.inputs['From Min'].default_value = -2; map_z.inputs['From Max'].default_value = 2
    map_z.inputs['To Min'].default_value = -0.5; map_z.inputs['To Max'].default_value = 0.5
    tree.links.new(h, map_z.inputs['Value'])

    note_offset = tree.nodes.new('ShaderNodeCombineXYZ'); note_offset.location = (base_x+1200, 1100); color_node(note_offset, "ornament")
    note_offset.inputs['X'].default_value = 0
    note_offset.inputs['Y'].default_value = 0
    tree.links.new(map_z.outputs['Result'], note_offset.inputs['Z'])

    trans_inst = tree.nodes.new('GeometryNodeTranslateInstances'); trans_inst.location = (base_x+1400, 700)
    tree.links.new(inst.outputs['Instances'], trans_inst.inputs['Instances'])
    tree.links.new(note_offset.outputs['Vector'], trans_inst.inputs['Translation'])

    # Add stems
    stem = tree.nodes.new('GeometryNodeMeshCube'); stem.location = (base_x, 1500); color_node(stem, "music")
    stem.inputs['Size'].default_value = (0.04, 0.04, 1.2)
    stem_t = tree.nodes.new('GeometryNodeTransform'); stem_t.location = (base_x+200, 1500)
    stem_t.inputs['Translation'].default_value = (0.18, 0, 0.6)  # offset right of note head, up
    tree.links.new(stem.outputs['Mesh'], stem_t.inputs['Geometry'])

    inst_stems = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst_stems.location = (base_x+500, 1500)
    tree.links.new(note_line.outputs['Mesh'], inst_stems.inputs['Points'])
    tree.links.new(stem_t.outputs['Geometry'], inst_stems.inputs['Instance'])

    trans_stems = tree.nodes.new('GeometryNodeTranslateInstances'); trans_stems.location = (base_x+1400, 1500)
    tree.links.new(inst_stems.outputs['Instances'], trans_stems.inputs['Instances'])
    tree.links.new(note_offset.outputs['Vector'], trans_stems.inputs['Translation'])

    realize_n = tree.nodes.new('GeometryNodeRealizeInstances'); realize_n.location = (base_x+1700, 700)
    tree.links.new(trans_inst.outputs['Instances'], realize_n.inputs['Geometry'])

    realize_s = tree.nodes.new('GeometryNodeRealizeInstances'); realize_s.location = (base_x+1700, 1500)
    tree.links.new(trans_stems.outputs['Instances'], realize_s.inputs['Geometry'])

    parts.append(realize_n.outputs['Geometry'])
    parts.append(realize_s.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2000, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: SHEET MUSIC RAILING
# A horizontal railing styled as a 5-line musical staff with note heads,
# bar lines, optional clef, and support posts. Note pitches driven by
# harmonic params (so the railing literally encodes a melody!).
# ----------------------------------------------------------------------

def build_sheet_music_railing(tree, props, base_x=-1400):
    L = props.sheet_length
    H = props.sheet_height       # staff total vertical span
    line_t = props.sheet_line_thickness
    n_notes = props.sheet_note_count
    note_s = props.sheet_note_size
    parts = []

    line_spacing = H / 4  # 5 lines → 4 gaps

    # === 5 horizontal staff lines (cylinders along X) ===
    for i in range(5):
        z = (i - 2) * line_spacing  # centered around 0, range = -H/2..+H/2
        ln = tree.nodes.new('GeometryNodeMeshCylinder'); ln.location = (base_x, i * 100); color_node(ln, "sheet_music")
        ln.inputs['Vertices'].default_value = 8
        ln.inputs['Radius'].default_value = line_t
        ln.inputs['Depth'].default_value = L
        lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x+200, i * 100)
        lt.inputs['Translation'].default_value = (0, 0, z)
        lt.inputs['Rotation'].default_value = (0, math.radians(90), 0)  # cylinder along X
        tree.links.new(ln.outputs['Mesh'], lt.inputs['Geometry'])
        parts.append(lt.outputs['Geometry'])

    # === Bar lines (vertical) splitting the staff into measures ===
    if props.sheet_bar_count > 0:
        bl = tree.nodes.new('GeometryNodeMeshLine'); bl.location = (base_x, 600); color_node(bl, "sheet_music")
        bl.mode = 'OFFSET'
        bl.inputs['Count'].default_value = props.sheet_bar_count
        bl.inputs['Start Location'].default_value = (-L/2 + L/(props.sheet_bar_count + 1), 0, 0)
        bl.inputs['Offset'].default_value = (L/(props.sheet_bar_count + 1), 0, 0)

        bar = tree.nodes.new('GeometryNodeMeshCube'); bar.location = (base_x, 800); color_node(bar, "sheet_music")
        bar.inputs['Size'].default_value = (line_t * 1.5, line_t * 1.5, H + line_t * 4)

        bi = tree.nodes.new('GeometryNodeInstanceOnPoints'); bi.location = (base_x+300, 600)
        tree.links.new(bl.outputs['Mesh'], bi.inputs['Points'])
        tree.links.new(bar.outputs['Mesh'], bi.inputs['Instance'])
        br = tree.nodes.new('GeometryNodeRealizeInstances'); br.location = (base_x+600, 600)
        tree.links.new(bi.outputs['Instances'], br.inputs['Geometry'])
        parts.append(br.outputs['Geometry'])

    # === Note heads — array along the staff with harmonic-driven Z position ===
    note_line = tree.nodes.new('GeometryNodeMeshLine'); note_line.location = (base_x, 1000); color_node(note_line, "sheet_music")
    note_line.mode = 'END_POINTS'
    note_line.inputs['Count'].default_value = n_notes
    # Reserve start space for clef
    start_x = -L * 0.35 if props.sheet_with_clef else -L * 0.45
    note_line.inputs['Start Location'].default_value = (start_x, 0, 0)
    note_line.inputs['Offset'].default_value = (L * 0.85 if props.sheet_with_clef else L * 0.9, 0, 0)

    # Note head: flattened oval (UV sphere with non-uniform scale)
    head = tree.nodes.new('GeometryNodeMeshUVSphere'); head.location = (base_x, 1200); color_node(head, "sheet_music")
    head.inputs['Radius'].default_value = note_s
    head.inputs['Segments'].default_value = 18
    head.inputs['Rings'].default_value = 12
    flat = tree.nodes.new('GeometryNodeTransform'); flat.location = (base_x+200, 1200)
    flat.inputs['Scale'].default_value = (1.3, 0.6, 0.85)  # flatten Y, slight tilt
    flat.inputs['Rotation'].default_value = (0, math.radians(-15), 0)
    tree.links.new(head.outputs['Mesh'], flat.inputs['Geometry'])

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+500, 1000)
    tree.links.new(note_line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(flat.outputs['Geometry'], inst.inputs['Instance'])

    # Pitch-driven Z displacement (a real melody if enabled)
    if props.sheet_pitch_driven:
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 1500)
        h_val = make_harmonic_value(tree, idx.outputs['Index'],
                                     props.musical_freq_a, props.musical_freq_b,
                                     props.harmonic_layers, base_x+200, 1500)
        map_z = tree.nodes.new('ShaderNodeMapRange'); map_z.location = (base_x+1000, 1500)
        map_z.inputs['From Min'].default_value = -2
        map_z.inputs['From Max'].default_value = 2
        map_z.inputs['To Min'].default_value = -H/2 - line_spacing/2  # below bottom line
        map_z.inputs['To Max'].default_value = H/2 + line_spacing/2   # above top line
        tree.links.new(h_val, map_z.inputs['Value'])

        ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1200, 1500); color_node(ovec, "sheet_music")
        ovec.inputs['X'].default_value = 0
        ovec.inputs['Y'].default_value = 0
        tree.links.new(map_z.outputs['Result'], ovec.inputs['Z'])

        ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+1500, 1000)
        tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])
        tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])
        notes_inst = ti.outputs['Instances']
    else:
        notes_inst = inst.outputs['Instances']

    notes_real = tree.nodes.new('GeometryNodeRealizeInstances'); notes_real.location = (base_x+1800, 1000); color_node(notes_real, "sheet_music")
    tree.links.new(notes_inst, notes_real.inputs['Geometry'])
    parts.append(notes_real.outputs['Geometry'])

    # === Note stems (vertical sticks on each note) ===
    if props.sheet_with_stems:
        stem = tree.nodes.new('GeometryNodeMeshCube'); stem.location = (base_x, 1900); color_node(stem, "sheet_music")
        stem.inputs['Size'].default_value = (note_s * 0.18, note_s * 0.18, note_s * 5)
        stem_t = tree.nodes.new('GeometryNodeTransform'); stem_t.location = (base_x+200, 1900)
        stem_t.inputs['Translation'].default_value = (note_s * 1.0, 0, note_s * 2.5)
        tree.links.new(stem.outputs['Mesh'], stem_t.inputs['Geometry'])

        si = tree.nodes.new('GeometryNodeInstanceOnPoints'); si.location = (base_x+500, 1900)
        tree.links.new(note_line.outputs['Mesh'], si.inputs['Points'])
        tree.links.new(stem_t.outputs['Geometry'], si.inputs['Instance'])

        if props.sheet_pitch_driven:
            ti2 = tree.nodes.new('GeometryNodeTranslateInstances'); ti2.location = (base_x+1500, 1900)
            tree.links.new(si.outputs['Instances'], ti2.inputs['Instances'])
            tree.links.new(ovec.outputs['Vector'], ti2.inputs['Translation'])
            stems_inst = ti2.outputs['Instances']
        else:
            stems_inst = si.outputs['Instances']

        sr = tree.nodes.new('GeometryNodeRealizeInstances'); sr.location = (base_x+1800, 1900); color_node(sr, "sheet_music")
        tree.links.new(stems_inst, sr.inputs['Geometry'])
        parts.append(sr.outputs['Geometry'])

    # === Treble clef at the start of the railing ===
    if props.sheet_with_clef:
        saved = (props.clef_size, props.clef_thickness, props.clef_curls)
        props.clef_size = H * 0.9
        props.clef_thickness = line_t * 1.5
        props.clef_curls = 1.5
        clef_geom = build_treble_clef(tree, props, base_x=base_x+2200)
        props.clef_size, props.clef_thickness, props.clef_curls = saved

        clef_t = tree.nodes.new('GeometryNodeTransform'); clef_t.location = (base_x+3500, 0); color_node(clef_t, "sheet_music")
        clef_t.inputs['Translation'].default_value = (-L/2 + H * 0.25, 0, -H * 0.1)
        clef_t.inputs['Scale'].default_value = (0.6, 0.6, 0.6)
        tree.links.new(clef_geom, clef_t.inputs['Geometry'])
        parts.append(clef_t.outputs['Geometry'])

    # === Support posts under the staff ===
    if props.sheet_post_count > 0:
        pl = tree.nodes.new('GeometryNodeMeshLine'); pl.location = (base_x, 2300); color_node(pl, "sheet_music")
        pl.mode = 'OFFSET'
        pl.inputs['Count'].default_value = props.sheet_post_count
        pl.inputs['Start Location'].default_value = (-L/2 + L/(props.sheet_post_count + 1), 0, -H/2 - 0.5)
        pl.inputs['Offset'].default_value = (L/(props.sheet_post_count + 1), 0, 0)

        post = tree.nodes.new('GeometryNodeMeshCylinder'); post.location = (base_x, 2500); color_node(post, "sheet_music")
        post.inputs['Vertices'].default_value = 8
        post.inputs['Radius'].default_value = props.sheet_post_radius
        post.inputs['Depth'].default_value = 1.0  # to ground

        pi = tree.nodes.new('GeometryNodeInstanceOnPoints'); pi.location = (base_x+300, 2300)
        tree.links.new(pl.outputs['Mesh'], pi.inputs['Points'])
        tree.links.new(post.outputs['Mesh'], pi.inputs['Instance'])
        pr = tree.nodes.new('GeometryNodeRealizeInstances'); pr.location = (base_x+600, 2300)
        tree.links.new(pi.outputs['Instances'], pr.inputs['Geometry'])
        parts.append(pr.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+4000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: GOTHIC POINTED ARCH
# ----------------------------------------------------------------------

def build_gothic_arch(tree, props, base_x=-1400):
    """Pointed Gothic arch: two intersecting circle arcs."""
    W = props.gothic_width
    R = max(W / 2 + 0.001, props.gothic_radius)  # must be ≥ half-width
    half_W = W / 2

    # peak angle from horizontal at arc center
    peak_angle = math.acos(min(1.0, max(-1.0, (R - half_W) / R)))

    # Right-side arc — center at (-half_W + R, 0)
    right_arc = tree.nodes.new('GeometryNodeCurveArc'); right_arc.location = (base_x, 200); color_node(right_arc, "gothic")
    right_arc.mode = 'RADIUS'
    right_arc.inputs['Resolution'].default_value = 32
    right_arc.inputs['Radius'].default_value = R
    right_arc.inputs['Start Angle'].default_value = math.pi - peak_angle
    right_arc.inputs['Sweep Angle'].default_value = peak_angle

    right_t = tree.nodes.new('GeometryNodeTransform'); right_t.location = (base_x+300, 200)
    right_t.inputs['Translation'].default_value = (-half_W + R, 0, 0)
    right_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(right_arc.outputs['Curve'], right_t.inputs['Geometry'])

    # Left-side arc
    left_arc = tree.nodes.new('GeometryNodeCurveArc'); left_arc.location = (base_x, -200); color_node(left_arc, "gothic")
    left_arc.mode = 'RADIUS'
    left_arc.inputs['Resolution'].default_value = 32
    left_arc.inputs['Radius'].default_value = R
    left_arc.inputs['Start Angle'].default_value = 0
    left_arc.inputs['Sweep Angle'].default_value = peak_angle

    left_t = tree.nodes.new('GeometryNodeTransform'); left_t.location = (base_x+300, -200)
    left_t.inputs['Translation'].default_value = (half_W - R, 0, 0)
    left_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(left_arc.outputs['Curve'], left_t.inputs['Geometry'])

    # Profile
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "gothic")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.gothic_thickness

    right_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); right_sweep.location = (base_x+600, 200)
    tree.links.new(right_t.outputs['Geometry'], right_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], right_sweep.inputs['Profile Curve'])
    right_sweep.inputs['Fill Caps'].default_value = True

    left_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); left_sweep.location = (base_x+600, -200)
    tree.links.new(left_t.outputs['Geometry'], left_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], left_sweep.inputs['Profile Curve'])
    left_sweep.inputs['Fill Caps'].default_value = True

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+900, 0); color_node(join, "output")
    tree.links.new(right_sweep.outputs['Mesh'], join.inputs['Geometry'])
    tree.links.new(left_sweep.outputs['Mesh'], join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: TREFOIL / QUATREFOIL / CINQUEFOIL
# ----------------------------------------------------------------------

def build_trefoil(tree, props, base_x=-1400):
    """N-lobed Gothic ornament: N circles arranged radially around a center."""
    n_lobes = props.trefoil_lobes
    R_lobe = props.trefoil_radius
    R_outer = props.trefoil_outer

    # Each lobe: a swept circle
    lobe_curve = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); lobe_curve.location = (base_x, 0); color_node(lobe_curve, "gothic")
    lobe_curve.mode = 'RADIUS'
    lobe_curve.inputs['Resolution'].default_value = 32
    lobe_curve.inputs['Radius'].default_value = R_lobe

    lobe_t = tree.nodes.new('GeometryNodeTransform'); lobe_t.location = (base_x+200, 0)
    lobe_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(lobe_curve.outputs['Curve'], lobe_t.inputs['Geometry'])

    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -300); color_node(profile, "gothic")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 6
    profile.inputs['Radius'].default_value = props.gothic_thickness

    lobe_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); lobe_sweep.location = (base_x+500, 0)
    tree.links.new(lobe_t.outputs['Geometry'], lobe_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], lobe_sweep.inputs['Profile Curve'])

    # Place lobes on circle of points
    points_circle = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); points_circle.location = (base_x, 300); color_node(points_circle, "gothic")
    points_circle.mode = 'RADIUS'
    points_circle.inputs['Resolution'].default_value = n_lobes
    points_circle.inputs['Radius'].default_value = R_outer

    pc_t = tree.nodes.new('GeometryNodeTransform'); pc_t.location = (base_x+300, 300)
    pc_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(points_circle.outputs['Curve'], pc_t.inputs['Geometry'])

    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+600, 300)
    c2p.mode = 'EVALUATED'
    tree.links.new(pc_t.outputs['Geometry'], c2p.inputs['Curve'])

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+900, 0)
    tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(lobe_sweep.outputs['Mesh'], inst.inputs['Instance'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1200, 0)
    tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])

    # Outer ring
    outer = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); outer.location = (base_x, -600); color_node(outer, "gothic")
    outer.mode = 'RADIUS'
    outer.inputs['Resolution'].default_value = 64
    outer.inputs['Radius'].default_value = R_outer + R_lobe

    outer_t = tree.nodes.new('GeometryNodeTransform'); outer_t.location = (base_x+300, -600)
    outer_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(outer.outputs['Curve'], outer_t.inputs['Geometry'])

    outer_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); outer_sweep.location = (base_x+600, -600)
    tree.links.new(outer_t.outputs['Geometry'], outer_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], outer_sweep.inputs['Profile Curve'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1500, 0); color_node(join, "output")
    tree.links.new(realize.outputs['Geometry'], join.inputs['Geometry'])
    tree.links.new(outer_sweep.outputs['Mesh'], join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: ROSE WINDOW
# ----------------------------------------------------------------------

def build_rose_window(tree, props, base_x=-1400):
    """Radial Gothic rose window. Petal count = musical time signature top."""
    R_outer = props.rose_outer_radius
    R_inner = props.rose_inner_radius
    n_petals = props.rose_petal_count
    n_spokes = props.rose_spoke_count
    petal_R = props.rose_petal_radius

    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "tracery")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 6
    profile.inputs['Radius'].default_value = props.gothic_thickness * 0.5

    # Outer ring
    outer = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); outer.location = (base_x, 200); color_node(outer, "gothic")
    outer.mode = 'RADIUS'
    outer.inputs['Resolution'].default_value = 64
    outer.inputs['Radius'].default_value = R_outer

    outer_t = tree.nodes.new('GeometryNodeTransform'); outer_t.location = (base_x+200, 200)
    outer_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(outer.outputs['Curve'], outer_t.inputs['Geometry'])

    outer_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); outer_sweep.location = (base_x+500, 200)
    tree.links.new(outer_t.outputs['Geometry'], outer_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], outer_sweep.inputs['Profile Curve'])

    # Inner ring
    inner = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); inner.location = (base_x, 0); color_node(inner, "gothic")
    inner.mode = 'RADIUS'
    inner.inputs['Resolution'].default_value = 24
    inner.inputs['Radius'].default_value = R_inner

    inner_t = tree.nodes.new('GeometryNodeTransform'); inner_t.location = (base_x+200, 0)
    inner_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(inner.outputs['Curve'], inner_t.inputs['Geometry'])

    inner_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); inner_sweep.location = (base_x+500, 0)
    tree.links.new(inner_t.outputs['Geometry'], inner_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], inner_sweep.inputs['Profile Curve'])

    # Petals (small circles)
    petal = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); petal.location = (base_x, -200); color_node(petal, "tracery")
    petal.mode = 'RADIUS'
    petal.inputs['Resolution'].default_value = 24
    petal.inputs['Radius'].default_value = petal_R

    petal_t = tree.nodes.new('GeometryNodeTransform'); petal_t.location = (base_x+200, -200)
    petal_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(petal.outputs['Curve'], petal_t.inputs['Geometry'])

    petal_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); petal_sweep.location = (base_x+500, -200)
    tree.links.new(petal_t.outputs['Geometry'], petal_sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], petal_sweep.inputs['Profile Curve'])

    # Place petals on circle
    petal_dist = (R_outer + R_inner) / 2 + 0.05
    pc = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); pc.location = (base_x, 500)
    pc.mode = 'RADIUS'
    pc.inputs['Resolution'].default_value = max(2, n_petals)
    pc.inputs['Radius'].default_value = petal_dist

    pc_t = tree.nodes.new('GeometryNodeTransform'); pc_t.location = (base_x+200, 500)
    pc_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(pc.outputs['Curve'], pc_t.inputs['Geometry'])

    pc2p = tree.nodes.new('GeometryNodeCurveToPoints'); pc2p.location = (base_x+500, 500)
    pc2p.mode = 'EVALUATED'
    tree.links.new(pc_t.outputs['Geometry'], pc2p.inputs['Curve'])

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+800, -200)
    tree.links.new(pc2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(petal_sweep.outputs['Mesh'], inst.inputs['Instance'])

    realize_p = tree.nodes.new('GeometryNodeRealizeInstances'); realize_p.location = (base_x+1100, -200)
    tree.links.new(inst.outputs['Instances'], realize_p.inputs['Geometry'])

    parts = [outer_sweep.outputs['Mesh'], inner_sweep.outputs['Mesh'], realize_p.outputs['Geometry']]

    # Spokes
    if n_spokes > 0:
        sp = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); sp.location = (base_x, 800); color_node(sp, "tracery")
        sp.mode = 'RADIUS'
        sp.inputs['Resolution'].default_value = n_spokes
        sp.inputs['Radius'].default_value = (R_outer + R_inner) / 2

        sp_t = tree.nodes.new('GeometryNodeTransform'); sp_t.location = (base_x+200, 800)
        sp_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
        tree.links.new(sp.outputs['Curve'], sp_t.inputs['Geometry'])

        sp2p = tree.nodes.new('GeometryNodeCurveToPoints'); sp2p.location = (base_x+500, 800)
        sp2p.mode = 'EVALUATED'
        tree.links.new(sp_t.outputs['Geometry'], sp2p.inputs['Curve'])

        spoke = tree.nodes.new('GeometryNodeMeshCylinder'); spoke.location = (base_x, 1100); color_node(spoke, "tracery")
        spoke.inputs['Vertices'].default_value = 6
        spoke.inputs['Radius'].default_value = props.gothic_thickness * 0.4
        spoke.inputs['Depth'].default_value = max(0.05, R_outer - R_inner)

        sp_inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); sp_inst.location = (base_x+800, 800)
        tree.links.new(sp2p.outputs['Points'], sp_inst.inputs['Points'])
        tree.links.new(spoke.outputs['Mesh'], sp_inst.inputs['Instance'])
        tree.links.new(sp2p.outputs['Rotation'], sp_inst.inputs['Rotation'])

        sp_realize = tree.nodes.new('GeometryNodeRealizeInstances'); sp_realize.location = (base_x+1100, 800)
        tree.links.new(sp_inst.outputs['Instances'], sp_realize.inputs['Geometry'])
        parts.append(sp_realize.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1500, 0); color_node(join, "output")
    for p in parts:
        tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: LANCET WINDOW (tall pointed window, 1+ side-by-side)
# ----------------------------------------------------------------------

def build_lancet(tree, props, base_x=-1400):
    """Tall slender Gothic pointed window. lancet_count > 1 makes a side-by-side group."""
    W = props.lancet_width
    H = props.lancet_height
    pointiness = props.lancet_pointiness
    half_W = W / 2
    R = pointiness * half_W
    peak_angle = math.acos(min(1.0, max(-1.0, (R - half_W) / R)))

    # Profile
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "gothic")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.gothic_thickness

    # Build a single lancet shape: vertical sides (lines) + Gothic arch top
    # Right side (vertical bar)
    r_side = tree.nodes.new('GeometryNodeCurvePrimitiveLine'); r_side.location = (base_x, 200); color_node(r_side, "gothic")
    r_side.mode = 'POINTS'
    r_side.inputs['Start'].default_value = (half_W, 0, 0)
    r_side.inputs['End'].default_value = (half_W, 0, H - half_W * pointiness * 0.5)

    l_side = tree.nodes.new('GeometryNodeCurvePrimitiveLine'); l_side.location = (base_x, 0); color_node(l_side, "gothic")
    l_side.mode = 'POINTS'
    l_side.inputs['Start'].default_value = (-half_W, 0, 0)
    l_side.inputs['End'].default_value = (-half_W, 0, H - half_W * pointiness * 0.5)

    # Bottom sill
    sill = tree.nodes.new('GeometryNodeCurvePrimitiveLine'); sill.location = (base_x, -200); color_node(sill, "gothic")
    sill.mode = 'POINTS'
    sill.inputs['Start'].default_value = (-half_W, 0, 0)
    sill.inputs['End'].default_value = (half_W, 0, 0)

    # Right arc (top of arch)
    r_arc = tree.nodes.new('GeometryNodeCurveArc'); r_arc.location = (base_x, 500); color_node(r_arc, "gothic")
    r_arc.mode = 'RADIUS'
    r_arc.inputs['Resolution'].default_value = 24
    r_arc.inputs['Radius'].default_value = R
    r_arc.inputs['Start Angle'].default_value = math.pi - peak_angle
    r_arc.inputs['Sweep Angle'].default_value = peak_angle

    r_arc_t = tree.nodes.new('GeometryNodeTransform'); r_arc_t.location = (base_x+200, 500)
    r_arc_t.inputs['Translation'].default_value = (-half_W + R, 0, H - half_W * pointiness * 0.5)
    r_arc_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(r_arc.outputs['Curve'], r_arc_t.inputs['Geometry'])

    l_arc = tree.nodes.new('GeometryNodeCurveArc'); l_arc.location = (base_x, 700); color_node(l_arc, "gothic")
    l_arc.mode = 'RADIUS'
    l_arc.inputs['Resolution'].default_value = 24
    l_arc.inputs['Radius'].default_value = R
    l_arc.inputs['Start Angle'].default_value = 0
    l_arc.inputs['Sweep Angle'].default_value = peak_angle

    l_arc_t = tree.nodes.new('GeometryNodeTransform'); l_arc_t.location = (base_x+200, 700)
    l_arc_t.inputs['Translation'].default_value = (half_W - R, 0, H - half_W * pointiness * 0.5)
    l_arc_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(l_arc.outputs['Curve'], l_arc_t.inputs['Geometry'])

    # Sweep all curves
    parts = []
    for curve_out, y in [(r_side.outputs['Curve'], 200),
                          (l_side.outputs['Curve'], 0),
                          (sill.outputs['Curve'], -200),
                          (r_arc_t.outputs['Geometry'], 500),
                          (l_arc_t.outputs['Geometry'], 700)]:
        sw = tree.nodes.new('GeometryNodeCurveToMesh'); sw.location = (base_x+500, y)
        tree.links.new(curve_out, sw.inputs['Curve'])
        tree.links.new(profile.outputs['Curve'], sw.inputs['Profile Curve'])
        sw.inputs['Fill Caps'].default_value = True
        parts.append(sw.outputs['Mesh'])

    join_one = tree.nodes.new('GeometryNodeJoinGeometry'); join_one.location = (base_x+800, 0); color_node(join_one, "output")
    for p in parts:
        tree.links.new(p, join_one.inputs['Geometry'])

    geom = join_one.outputs['Geometry']

    # If multiple lancets, instance them side by side
    if props.lancet_count > 1:
        # Create line of points
        line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x+800, 1000); color_node(line, "gothic")
        line.mode = 'OFFSET'
        line.inputs['Count'].default_value = props.lancet_count
        spacing = W * 1.1
        start_x = -spacing * (props.lancet_count - 1) / 2 + half_W * 0  # center the row
        line.inputs['Start Location'].default_value = (start_x, 0, 0)
        line.inputs['Offset'].default_value = (spacing, 0, 0)

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+1100, 0)
        tree.links.new(line.outputs['Mesh'], inst.inputs['Points'])
        tree.links.new(geom, inst.inputs['Instance'])

        # vary lancet height with musical harmonic for whimsy
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x+800, 1300)
        h = make_harmonic_value(tree, idx.outputs['Index'],
                                 props.musical_freq_a, props.musical_freq_b,
                                 props.harmonic_layers, base_x+1000, 1300)
        mr = tree.nodes.new('ShaderNodeMapRange'); mr.location = (base_x+1700, 1300)
        mr.inputs['From Min'].default_value = -2; mr.inputs['From Max'].default_value = 2
        mr.inputs['To Min'].default_value = 1.0 - props.ornament_density * 0.3
        mr.inputs['To Max'].default_value = 1.0 + props.ornament_density * 0.3
        tree.links.new(h, mr.inputs['Value'])

        sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+1900, 1300); color_node(sv, "ornament")
        sv.inputs['X'].default_value = 1; sv.inputs['Y'].default_value = 1
        tree.links.new(mr.outputs['Result'], sv.inputs['Z'])

        scale_inst = tree.nodes.new('GeometryNodeScaleInstances'); scale_inst.location = (base_x+2100, 0)
        tree.links.new(inst.outputs['Instances'], scale_inst.inputs['Instances'])
        tree.links.new(sv.outputs['Vector'], scale_inst.inputs['Scale'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+2400, 0)
        tree.links.new(scale_inst.outputs['Instances'], realize.inputs['Geometry'])
        geom = realize.outputs['Geometry']

    return geom


# ----------------------------------------------------------------------
# VENETIAN GOTHIC BUILDERS
# (after Boscarino et al., 3D Geometric Analysis of the Façades of
#  Gothic Buildings in Venice — academia.edu/3354616)
# ----------------------------------------------------------------------

def _ogee_curve_pair(tree, half_W, height, swell, shoulder, base_x=0, base_y=0):
    """
    Build the two Bezier curves of an ogee arch (right + left).
    Returns (right_curve_socket, left_curve_socket).
    Curves are in the XZ plane (rotated from default XY).
    """
    rb = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment')
    rb.location = (base_x, base_y + 200); color_node(rb, "ogee")
    rb.inputs['Resolution'].default_value = 32
    rb.inputs['Start'].default_value         = (half_W, 0, 0)
    rb.inputs['Start Handle'].default_value  = (half_W + swell, shoulder, 0)
    rb.inputs['End Handle'].default_value    = (half_W * 0.3, height - 0.3, 0)
    rb.inputs['End'].default_value           = (0, height, 0)

    lb = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment')
    lb.location = (base_x, base_y - 200); color_node(lb, "ogee")
    lb.inputs['Resolution'].default_value = 32
    lb.inputs['Start'].default_value         = (-half_W, 0, 0)
    lb.inputs['Start Handle'].default_value  = (-half_W - swell, shoulder, 0)
    lb.inputs['End Handle'].default_value    = (-half_W * 0.3, height - 0.3, 0)
    lb.inputs['End'].default_value           = (0, height, 0)

    rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x + 300, base_y + 200)
    rt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(rb.outputs['Curve'], rt.inputs['Geometry'])

    lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x + 300, base_y - 200)
    lt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(lb.outputs['Curve'], lt.inputs['Geometry'])

    return rt.outputs['Geometry'], lt.outputs['Geometry']


def build_ogee_arch(tree, props, base_x=-1400):
    """Iconic Venetian Gothic ogee arch with S-curve sides + finial pinnacle."""
    half_W = props.ogee_width / 2
    H = props.ogee_height
    rc, lc = _ogee_curve_pair(tree, half_W, H, props.ogee_swell, props.ogee_shoulder,
                               base_x=base_x, base_y=0)

    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "ogee")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.gothic_thickness

    rsw = tree.nodes.new('GeometryNodeCurveToMesh'); rsw.location = (base_x+700, 200); color_node(rsw, "ogee")
    tree.links.new(rc, rsw.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], rsw.inputs['Profile Curve'])
    rsw.inputs['Fill Caps'].default_value = True

    lsw = tree.nodes.new('GeometryNodeCurveToMesh'); lsw.location = (base_x+700, -200); color_node(lsw, "ogee")
    tree.links.new(lc, lsw.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], lsw.inputs['Profile Curve'])
    lsw.inputs['Fill Caps'].default_value = True

    parts = [rsw.outputs['Mesh'], lsw.outputs['Mesh']]

    # Finial pinnacle at apex
    if props.ogee_finial > 0.01:
        finial = tree.nodes.new('GeometryNodeMeshCone'); finial.location = (base_x, 600); color_node(finial, "ornament")
        finial.inputs['Vertices'].default_value = 16  # bumped from 8 in v2.31
        finial.inputs['Radius Top'].default_value = 0.0
        finial.inputs['Radius Bottom'].default_value = props.ogee_finial * 0.3
        finial.inputs['Depth'].default_value = props.ogee_finial

        ft = tree.nodes.new('GeometryNodeTransform'); ft.location = (base_x+300, 600)
        ft.inputs['Translation'].default_value = (0, 0, H + props.ogee_finial / 2)
        tree.links.new(finial.outputs['Mesh'], ft.inputs['Geometry'])
        parts.append(ft.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_bifora(tree, props, base_x=-1400):
    """Venetian bifora: 2+ pointed (or ogee) arches with central colonnettes + quatrefoil oculus."""
    n_lights = props.bifora_lights
    W_total = props.bifora_width
    H = props.bifora_height
    light_W = W_total / n_lights
    half_lw = light_W / 2

    parts = []

    # Profile
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -700); color_node(profile, "venetian")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.gothic_thickness

    # For each light, build an ogee or pointed arch on a vertical pair of side bars
    for i in range(n_lights):
        cx = -W_total / 2 + light_W * (i + 0.5)  # center X of this light

        if props.bifora_use_ogee:
            # Build ogee curves directly with offset
            rb = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); rb.location = (base_x + i * 200, 200 + i * 30)
            rb.inputs['Resolution'].default_value = 24
            rb.inputs['Start'].default_value         = (cx + half_lw, 0, 0)
            rb.inputs['Start Handle'].default_value  = (cx + half_lw + 0.2, H * 0.4, 0)
            rb.inputs['End Handle'].default_value    = (cx + half_lw * 0.3, H - 0.2, 0)
            rb.inputs['End'].default_value           = (cx, H * 0.85, 0)

            lb = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); lb.location = (base_x + i * 200, -200 - i * 30)
            lb.inputs['Resolution'].default_value = 24
            lb.inputs['Start'].default_value         = (cx - half_lw, 0, 0)
            lb.inputs['Start Handle'].default_value  = (cx - half_lw - 0.2, H * 0.4, 0)
            lb.inputs['End Handle'].default_value    = (cx - half_lw * 0.3, H - 0.2, 0)
            lb.inputs['End'].default_value           = (cx, H * 0.85, 0)

            rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x + i * 200 + 200, 200 + i * 30)
            rt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
            tree.links.new(rb.outputs['Curve'], rt.inputs['Geometry'])

            lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x + i * 200 + 200, -200 - i * 30)
            lt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
            tree.links.new(lb.outputs['Curve'], lt.inputs['Geometry'])

            for c_socket, y_off in [(rt.outputs['Geometry'], 100 + i * 50),
                                     (lt.outputs['Geometry'], -100 - i * 50)]:
                sw = tree.nodes.new('GeometryNodeCurveToMesh'); sw.location = (base_x + 800, y_off)
                tree.links.new(c_socket, sw.inputs['Curve'])
                tree.links.new(profile.outputs['Curve'], sw.inputs['Profile Curve'])
                sw.inputs['Fill Caps'].default_value = True
                parts.append(sw.outputs['Mesh'])
        else:
            # Plain pointed Gothic arches
            R = light_W * 0.7
            peak_angle = math.acos(min(1.0, max(-1.0, (R - half_lw) / R)))

            ra = tree.nodes.new('GeometryNodeCurveArc'); ra.location = (base_x + i * 200, 200 + i * 30); color_node(ra, "venetian")
            ra.mode = 'RADIUS'
            ra.inputs['Resolution'].default_value = 24
            ra.inputs['Radius'].default_value = R
            ra.inputs['Start Angle'].default_value = math.pi - peak_angle
            ra.inputs['Sweep Angle'].default_value = peak_angle

            rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x + i * 200 + 200, 200 + i * 30)
            rt.inputs['Translation'].default_value = (cx - half_lw + R, 0, H * 0.5)
            rt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
            tree.links.new(ra.outputs['Curve'], rt.inputs['Geometry'])

            la = tree.nodes.new('GeometryNodeCurveArc'); la.location = (base_x + i * 200, -200 - i * 30); color_node(la, "venetian")
            la.mode = 'RADIUS'
            la.inputs['Resolution'].default_value = 24
            la.inputs['Radius'].default_value = R
            la.inputs['Start Angle'].default_value = 0
            la.inputs['Sweep Angle'].default_value = peak_angle

            lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x + i * 200 + 200, -200 - i * 30)
            lt.inputs['Translation'].default_value = (cx + half_lw - R, 0, H * 0.5)
            lt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
            tree.links.new(la.outputs['Curve'], lt.inputs['Geometry'])

            for c_socket, y_off in [(rt.outputs['Geometry'], 100 + i * 50),
                                     (lt.outputs['Geometry'], -100 - i * 50)]:
                sw = tree.nodes.new('GeometryNodeCurveToMesh'); sw.location = (base_x + 800, y_off)
                tree.links.new(c_socket, sw.inputs['Curve'])
                tree.links.new(profile.outputs['Curve'], sw.inputs['Profile Curve'])
                sw.inputs['Fill Caps'].default_value = True
                parts.append(sw.outputs['Mesh'])

        # Vertical bars on each side of this light (sill + jambs)
        # Right jamb
        rj = tree.nodes.new('GeometryNodeMeshCube'); rj.location = (base_x + i * 200, 600); color_node(rj, "venetian")
        rj.inputs['Size'].default_value = (props.gothic_thickness * 1.5, props.gothic_thickness * 1.5, H * 0.5)
        rjt = tree.nodes.new('GeometryNodeTransform'); rjt.location = (base_x + i * 200 + 300, 600)
        rjt.inputs['Translation'].default_value = (cx + half_lw, 0, H * 0.25)
        tree.links.new(rj.outputs['Mesh'], rjt.inputs['Geometry'])
        parts.append(rjt.outputs['Geometry'])

    # Central colonnette(s) between lights
    for i in range(n_lights - 1):
        col_x = -W_total / 2 + light_W * (i + 1)
        col = tree.nodes.new('GeometryNodeMeshCylinder'); col.location = (base_x + i * 200, 1000); color_node(col, "venetian")
        col.inputs['Vertices'].default_value = 16
        col.inputs['Radius'].default_value = props.gothic_thickness * 1.8
        col.inputs['Depth'].default_value = H * 0.85
        ct = tree.nodes.new('GeometryNodeTransform'); ct.location = (base_x + i * 200 + 300, 1000)
        ct.inputs['Translation'].default_value = (col_x, 0, H * 0.42)
        tree.links.new(col.outputs['Mesh'], ct.inputs['Geometry'])
        parts.append(ct.outputs['Geometry'])

        # Capital on top of colonnette
        cap = tree.nodes.new('GeometryNodeMeshCone'); cap.location = (base_x + i * 200, 1300); color_node(cap, "venetian")
        cap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading  # bumped from 12 in v2.31
        cap.inputs['Radius Top'].default_value = props.gothic_thickness * 3
        cap.inputs['Radius Bottom'].default_value = props.gothic_thickness * 2
        cap.inputs['Depth'].default_value = H * 0.05
        capt = tree.nodes.new('GeometryNodeTransform'); capt.location = (base_x + i * 200 + 300, 1300)
        capt.inputs['Translation'].default_value = (col_x, 0, H * 0.85 + H * 0.025)
        tree.links.new(cap.outputs['Mesh'], capt.inputs['Geometry'])
        parts.append(capt.outputs['Geometry'])

    # Quatrefoil oculus above (if enabled)
    if props.bifora_quatrefoil:
        quat = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); quat.location = (base_x, 1600); color_node(quat, "tracery")
        quat.mode = 'RADIUS'
        quat.inputs['Resolution'].default_value = 32
        quat.inputs['Radius'].default_value = light_W * 0.25

        quat_rot = tree.nodes.new('GeometryNodeTransform'); quat_rot.location = (base_x + 300, 1600)
        quat_rot.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
        quat_rot.inputs['Translation'].default_value = (0, 0, H * 0.92)
        tree.links.new(quat.outputs['Curve'], quat_rot.inputs['Geometry'])

        quat_sw = tree.nodes.new('GeometryNodeCurveToMesh'); quat_sw.location = (base_x + 600, 1600)
        tree.links.new(quat_rot.outputs['Geometry'], quat_sw.inputs['Curve'])
        tree.links.new(profile.outputs['Curve'], quat_sw.inputs['Profile Curve'])
        parts.append(quat_sw.outputs['Mesh'])

        # 4 small lobes inside the quatrefoil
        for ang_deg in (0, 90, 180, 270):
            lobe = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); lobe.location = (base_x, 1900); color_node(lobe, "tracery")
            lobe.mode = 'RADIUS'
            lobe.inputs['Resolution'].default_value = 20
            lobe.inputs['Radius'].default_value = light_W * 0.10

            ang = math.radians(ang_deg)
            lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x + 300, 1900)
            lt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
            lt.inputs['Translation'].default_value = (light_W * 0.13 * math.cos(ang), 0, H * 0.92 + light_W * 0.13 * math.sin(ang))
            tree.links.new(lobe.outputs['Curve'], lt.inputs['Geometry'])

            ls = tree.nodes.new('GeometryNodeCurveToMesh'); ls.location = (base_x + 600, 1900)
            tree.links.new(lt.outputs['Geometry'], ls.inputs['Curve'])
            tree.links.new(profile.outputs['Curve'], ls.inputs['Profile Curve'])
            parts.append(ls.outputs['Mesh'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x + 1200, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_cusped_arch(tree, props, base_x=-1400):
    """Pointed arch with multi-lobed (foiled) inner edge — Venetian Gothic detail."""
    W = props.cusped_width
    H = props.cusped_height
    n_cusps = props.cusped_lobes
    cusp_d = props.cusped_lobe_depth
    half_W = W / 2

    # Outer arch — same as Gothic arch
    R = max(half_W + 0.001, half_W * 1.4)
    peak_angle = math.acos(min(1.0, max(-1.0, (R - half_W) / R)))

    parts = []

    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -700); color_node(profile, "venetian")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 8
    profile.inputs['Radius'].default_value = props.gothic_thickness

    # Outer right arc
    ra = tree.nodes.new('GeometryNodeCurveArc'); ra.location = (base_x, 200); color_node(ra, "venetian")
    ra.mode = 'RADIUS'
    ra.inputs['Resolution'].default_value = 32
    ra.inputs['Radius'].default_value = R
    ra.inputs['Start Angle'].default_value = math.pi - peak_angle
    ra.inputs['Sweep Angle'].default_value = peak_angle
    rat = tree.nodes.new('GeometryNodeTransform'); rat.location = (base_x + 300, 200)
    rat.inputs['Translation'].default_value = (-half_W + R, 0, 0)
    rat.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(ra.outputs['Curve'], rat.inputs['Geometry'])
    rsw = tree.nodes.new('GeometryNodeCurveToMesh'); rsw.location = (base_x + 600, 200)
    tree.links.new(rat.outputs['Geometry'], rsw.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], rsw.inputs['Profile Curve'])
    parts.append(rsw.outputs['Mesh'])

    # Outer left arc
    la = tree.nodes.new('GeometryNodeCurveArc'); la.location = (base_x, -200); color_node(la, "venetian")
    la.mode = 'RADIUS'
    la.inputs['Resolution'].default_value = 32
    la.inputs['Radius'].default_value = R
    la.inputs['Start Angle'].default_value = 0
    la.inputs['Sweep Angle'].default_value = peak_angle
    lat = tree.nodes.new('GeometryNodeTransform'); lat.location = (base_x + 300, -200)
    lat.inputs['Translation'].default_value = (half_W - R, 0, 0)
    lat.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(la.outputs['Curve'], lat.inputs['Geometry'])
    lsw = tree.nodes.new('GeometryNodeCurveToMesh'); lsw.location = (base_x + 600, -200)
    tree.links.new(lat.outputs['Geometry'], lsw.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], lsw.inputs['Profile Curve'])
    parts.append(lsw.outputs['Mesh'])

    # Inner cusps: small circles arrayed along the inside of the arch
    # Arc length parameterization: place lobes evenly on a sample of the outer arc
    # We sample n_cusps points on the right arc and mirror
    # Use a half-arc that goes all the way around for sampling
    full_arc = tree.nodes.new('GeometryNodeCurveArc'); full_arc.location = (base_x, 700); color_node(full_arc, "tracery")
    full_arc.mode = 'RADIUS'
    full_arc.inputs['Resolution'].default_value = 64
    full_arc.inputs['Radius'].default_value = R - cusp_d
    full_arc.inputs['Start Angle'].default_value = -peak_angle
    full_arc.inputs['Sweep Angle'].default_value = 2 * peak_angle

    fa_t = tree.nodes.new('GeometryNodeTransform'); fa_t.location = (base_x + 300, 700)
    fa_t.inputs['Translation'].default_value = (0, 0, 0)
    fa_t.inputs['Rotation'].default_value = (math.radians(90), 0, math.radians(90))
    # We need to position so the arc spans the full width.
    # Actually simpler: build inner curve by sampling the right arc & mirroring.
    tree.links.new(full_arc.outputs['Curve'], fa_t.inputs['Geometry'])

    sample = tree.nodes.new('GeometryNodeResampleCurve'); sample.location = (base_x + 600, 700); color_node(sample, "tracery")
    sample.inputs['Mode'].default_value = 'Count'
    sample.inputs['Count'].default_value = n_cusps
    tree.links.new(fa_t.outputs['Geometry'], sample.inputs['Curve'])

    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x + 800, 700)
    c2p.mode = 'EVALUATED'
    tree.links.new(sample.outputs['Curve'], c2p.inputs['Curve'])

    # Lobe sphere
    lobe = tree.nodes.new('GeometryNodeMeshUVSphere'); lobe.location = (base_x, 1000); color_node(lobe, "tracery")
    lobe.inputs['Radius'].default_value = max(0.08, cusp_d * 0.8)
    lobe.inputs['Segments'].default_value = 16
    lobe.inputs['Rings'].default_value = 12

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x + 1100, 700)
    tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(lobe.outputs['Mesh'], inst.inputs['Instance'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x + 1400, 700)
    tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
    parts.append(realize.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x + 1700, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_palazzo(tree, props):
    """
    Venetian palazzo: arcade ground floor + bifora piano nobile + upper floors + roofline.
    Uses ogee/bifora/cusped/gothic arches per `palazzo_arch_style`.
    Following Boscarino: includes optional entropiombo lean & subsidence.
    """
    floors = props.palazzo_floors
    W = props.palazzo_width
    floor_h = props.palazzo_floor_h
    arches_per = props.palazzo_arches_per_floor
    style = props.palazzo_arch_style

    parts = []
    base_x = -3500
    total_h = floors * floor_h

    # Back wall — only if user wants it (default OFF — façade-only is the Venetian look)
    if getattr(props, "palazzo_back_wall", False):
        back_wall = tree.nodes.new('GeometryNodeMeshCube'); back_wall.location = (base_x, 0); color_node(back_wall, "palazzo")
        # Make it a true thin façade plane, not a solid box
        back_wall.inputs['Size'].default_value = (W, 0.15, total_h)
        bwt = tree.nodes.new('GeometryNodeTransform'); bwt.location = (base_x + 300, 0)
        bwt.inputs['Translation'].default_value = (0, -0.075, total_h / 2)
        tree.links.new(back_wall.outputs['Mesh'], bwt.inputs['Geometry'])
        parts.append(bwt.outputs['Geometry'])

    # For each floor, build an arch, then instance it across the floor width
    saved = {
        'ogee_width': props.ogee_width, 'ogee_height': props.ogee_height,
        'gothic_width': props.gothic_width, 'gothic_radius': props.gothic_radius,
        'cusped_width': props.cusped_width, 'cusped_height': props.cusped_height,
        'bifora_width': props.bifora_width, 'bifora_height': props.bifora_height,
        'bifora_lights': props.bifora_lights,
    }

    arch_W = W / arches_per

    for floor in range(floors):
        z = floor_h * (floor + 0.5) - total_h / 2  # center Z of this floor

        # Set arch size to fit within one bay
        if style == 'OGEE':
            props.ogee_width = arch_W * 0.85
            props.ogee_height = floor_h * 0.85
            arch_geom = build_ogee_arch(tree, props, base_x=base_x + 1500 + floor * 4500)
        elif style == 'BIFORA':
            props.bifora_width = arch_W * 0.85
            props.bifora_height = floor_h * 0.85
            props.bifora_lights = 2
            arch_geom = build_bifora(tree, props, base_x=base_x + 1500 + floor * 4500)
        elif style == 'CUSPED':
            props.cusped_width = arch_W * 0.85
            props.cusped_height = floor_h * 0.85
            arch_geom = build_cusped_arch(tree, props, base_x=base_x + 1500 + floor * 4500)
        else:  # GOTHIC
            props.gothic_width = arch_W * 0.85
            props.gothic_radius = arch_W * 0.7
            arch_geom = build_gothic_arch(tree, props, base_x=base_x + 1500 + floor * 4500)

        # Build a line of points along this floor for instancing
        line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x + 5000, floor * 600); color_node(line, "palazzo")
        line.mode = 'OFFSET'
        line.inputs['Count'].default_value = arches_per
        line.inputs['Start Location'].default_value = (-W / 2 + arch_W / 2, 0, z)
        line.inputs['Offset'].default_value = (arch_W, 0, 0)

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x + 5300, floor * 600)
        tree.links.new(line.outputs['Mesh'], inst.inputs['Points'])
        tree.links.new(arch_geom, inst.inputs['Instance'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x + 5600, floor * 600)
        tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
        parts.append(realize.outputs['Geometry'])

    # Restore saved props
    for k, v in saved.items():
        setattr(props, k, v)

    # Horizontal string courses between floors
    if props.palazzo_string_courses:
        for floor in range(1, floors):
            sc = tree.nodes.new('GeometryNodeMeshCube'); sc.location = (base_x + 200 + floor * 200, 1500); color_node(sc, "palazzo")
            sc.inputs['Size'].default_value = (W * 1.05, 0.6, 0.15)
            sct = tree.nodes.new('GeometryNodeTransform'); sct.location = (base_x + 500 + floor * 200, 1500)
            sct.inputs['Translation'].default_value = (0, 0, floor_h * floor - total_h / 2)
            tree.links.new(sc.outputs['Mesh'], sct.inputs['Geometry'])
            parts.append(sct.outputs['Geometry'])

        # Top crowning string course
        top = tree.nodes.new('GeometryNodeMeshCube'); top.location = (base_x + 200, 1800); color_node(top, "palazzo")
        top.inputs['Size'].default_value = (W * 1.1, 0.7, 0.25)
        topt = tree.nodes.new('GeometryNodeTransform'); topt.location = (base_x + 500, 1800)
        topt.inputs['Translation'].default_value = (0, 0, total_h / 2 + 0.1)
        tree.links.new(top.outputs['Mesh'], topt.inputs['Geometry'])
        parts.append(topt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x + 6500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# DEFORMATION PASSES — Venetian "imperfection" after Boscarino
# ----------------------------------------------------------------------

def add_entropiombo_pass(tree, in_geom, lean, x=11000):
    """
    Inward-lean deformation: top of structure tilts inward.
    Lean is a fraction (0.05 = 5% inward at top). Negative leans outward.
    Following Boscarino: this is INTENTIONAL in Venetian construction.
    """
    if abs(lean) < 0.001:
        return in_geom

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, 200); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x + 200, 200)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    # Mock bbox: assume Z range -10..+10 → normalize to [-1, 1] roughly
    z_norm = tree.nodes.new('ShaderNodeMath'); z_norm.location = (x + 400, 200); z_norm.operation = 'MULTIPLY'
    z_norm.inputs[1].default_value = 0.1
    tree.links.new(sep.outputs['Z'], z_norm.inputs[0])

    # Lateral pull: x_offset = -x * (z_norm + 0.5) * lean
    z_plus = tree.nodes.new('ShaderNodeMath'); z_plus.location = (x + 600, 200); z_plus.operation = 'ADD'
    z_plus.inputs[1].default_value = 0.5
    tree.links.new(z_norm.outputs['Value'], z_plus.inputs[0])

    pull_factor = tree.nodes.new('ShaderNodeMath'); pull_factor.location = (x + 800, 200); pull_factor.operation = 'MULTIPLY'
    pull_factor.inputs[1].default_value = lean
    tree.links.new(z_plus.outputs['Value'], pull_factor.inputs[0])

    # x_offset = -x * pull_factor
    x_offset = tree.nodes.new('ShaderNodeMath'); x_offset.location = (x + 1000, 0); x_offset.operation = 'MULTIPLY'
    x_offset.inputs[1].default_value = -1.0
    tree.links.new(sep.outputs['X'], x_offset.inputs[0])
    final_x = tree.nodes.new('ShaderNodeMath'); final_x.location = (x + 1200, 0); final_x.operation = 'MULTIPLY'
    tree.links.new(x_offset.outputs['Value'], final_x.inputs[0])
    tree.links.new(pull_factor.outputs['Value'], final_x.inputs[1])

    # Same for Y
    y_offset = tree.nodes.new('ShaderNodeMath'); y_offset.location = (x + 1000, -200); y_offset.operation = 'MULTIPLY'
    y_offset.inputs[1].default_value = -1.0
    tree.links.new(sep.outputs['Y'], y_offset.inputs[0])
    final_y = tree.nodes.new('ShaderNodeMath'); final_y.location = (x + 1200, -200); final_y.operation = 'MULTIPLY'
    tree.links.new(y_offset.outputs['Value'], final_y.inputs[0])
    tree.links.new(pull_factor.outputs['Value'], final_y.inputs[1])

    offset_vec = tree.nodes.new('ShaderNodeCombineXYZ'); offset_vec.location = (x + 1400, 0); color_node(offset_vec, "entropiombo")
    tree.links.new(final_x.outputs['Value'], offset_vec.inputs['X'])
    tree.links.new(final_y.outputs['Value'], offset_vec.inputs['Y'])
    offset_vec.inputs['Z'].default_value = 0.0

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x + 1600, 0); color_node(set_pos, "entropiombo")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(offset_vec.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


def add_subsidence_pass(tree, in_geom, amount, x=12500):
    """Bottom-heavy settling deformation — sags lower, rises slightly mid."""
    if amount < 0.001:
        return in_geom

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, 200); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x + 200, 200)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    # Sagging: at low Z, more downward; near the top, less. Use exp decay
    # offset_z = -amount * exp(-z/3)
    div = tree.nodes.new('ShaderNodeMath'); div.location = (x + 400, 200); div.operation = 'DIVIDE'
    div.inputs[1].default_value = 3.0
    tree.links.new(sep.outputs['Z'], div.inputs[0])
    neg = tree.nodes.new('ShaderNodeMath'); neg.location = (x + 600, 200); neg.operation = 'MULTIPLY'
    neg.inputs[1].default_value = -1.0
    tree.links.new(div.outputs['Value'], neg.inputs[0])

    expo = tree.nodes.new('ShaderNodeMath'); expo.location = (x + 800, 200); expo.operation = 'POWER'
    expo.inputs[0].default_value = 2.71828
    tree.links.new(neg.outputs['Value'], expo.inputs[1])

    sag = tree.nodes.new('ShaderNodeMath'); sag.location = (x + 1000, 200); sag.operation = 'MULTIPLY'
    sag.inputs[1].default_value = -amount
    tree.links.new(expo.outputs['Value'], sag.inputs[0])

    offset_vec = tree.nodes.new('ShaderNodeCombineXYZ'); offset_vec.location = (x + 1200, 0); color_node(offset_vec, "entropiombo")
    offset_vec.inputs['X'].default_value = 0
    offset_vec.inputs['Y'].default_value = 0
    tree.links.new(sag.outputs['Value'], offset_vec.inputs['Z'])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x + 1400, 0); color_node(set_pos, "entropiombo")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(offset_vec.outputs['Vector'], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: BRICK WALL (Venetian terracotta masonry)
# ----------------------------------------------------------------------

def build_brick_wall(tree, props, base_x=-1400):
    """Staggered brick masonry wall.
    v2.52: Uses Higgsas NTBricks Grid + NTSolidify when available for a
    proper parametric brick surface with accurate mortar gaps and UV.
    Falls back to the native GN stagger-grid approach when Higgsas is absent."""
    W      = props.brick_wall_width
    H      = props.brick_wall_height
    bw     = props.brick_size_x
    bh_    = props.brick_size_z
    bd     = props.brick_depth
    mortar = props.brick_mortar_gap

    # ── Higgsas path: NTBricks Grid → NTSolidify → orient ─────────────
    higg_bricks = _higg_node(tree, 'NTBricks Grid', (base_x, 0))
    if higg_bricks is not None:
        _higg_input(higg_bricks, 'X Grid Size',        W)
        _higg_input(higg_bricks, 'Y Grid Size',        H)
        _higg_input(higg_bricks, 'Absolute Grid Size', False)
        # NTBricks Grid outputs a flat (XY) grid — solidify for depth
        higg_solid = _higg_node(tree, 'NTSolidify', (base_x + 400, 0))
        geom_out = higg_bricks.outputs[0]
        if higg_solid is not None:
            _higg_input(higg_solid, 'Even Thickness', True)
            _higg_input(higg_solid, 'Thickness',      bd)
            _link(tree, higg_bricks.outputs[0], higg_solid.inputs['Mesh'])
            geom_out = higg_solid.outputs['Mesh']
        # Rotate to stand up (XZ plane) + shift up so base is at z=0
        rot = _safe_node(tree, 'GeometryNodeTransform', (base_x + 800, 0))
        if rot:
            try:
                rot.inputs['Rotation'].default_value    = (math.radians(90), 0, 0)
                rot.inputs['Translation'].default_value = (0, 0, H * 0.5)
            except Exception: pass
            _link(tree, geom_out, rot.inputs['Geometry'])
            color_node(rot, "brick")
            return rot.outputs['Geometry']
        return geom_out

    # ── Native fallback: stagger-grid (original approach) ─────────────
    cols = max(2, int(W / (bw + mortar)))
    rows = max(2, int(H / (bh_ + mortar)))

    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (base_x, 0); color_node(grid, "brick")
    grid.inputs['Size X'].default_value = W
    grid.inputs['Size Y'].default_value = H
    grid.inputs['Vertices X'].default_value = cols
    grid.inputs['Vertices Y'].default_value = rows

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (base_x, -300); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (base_x+200, -300)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    norm_y = tree.nodes.new('ShaderNodeMath'); norm_y.location = (base_x+400, -300); norm_y.operation = 'DIVIDE'
    norm_y.inputs[1].default_value = bh_ + mortar
    tree.links.new(sep.outputs['Y'], norm_y.inputs[0])
    floor_y = tree.nodes.new('ShaderNodeMath'); floor_y.location = (base_x+600, -300); floor_y.operation = 'FLOOR'
    tree.links.new(norm_y.outputs['Value'], floor_y.inputs[0])
    mod2 = tree.nodes.new('ShaderNodeMath'); mod2.location = (base_x+800, -300); mod2.operation = 'MODULO'
    mod2.inputs[1].default_value = 2.0
    tree.links.new(floor_y.outputs['Value'], mod2.inputs[0])
    stagger = tree.nodes.new('ShaderNodeMath'); stagger.location = (base_x+1000, -300); stagger.operation = 'MULTIPLY'
    stagger.inputs[1].default_value = (bw + mortar) / 2
    tree.links.new(mod2.outputs['Value'], stagger.inputs[0])
    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1200, -300); color_node(ovec, "brick")
    tree.links.new(stagger.outputs['Value'], ovec.inputs['X'])
    ovec.inputs['Y'].default_value = 0; ovec.inputs['Z'].default_value = 0

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (base_x+1400, 0); color_node(set_pos, "deform")
    tree.links.new(grid.outputs['Mesh'], set_pos.inputs['Geometry'])
    tree.links.new(ovec.outputs['Vector'], set_pos.inputs['Offset'])

    brick = tree.nodes.new('GeometryNodeMeshCube'); brick.location = (base_x, 400); color_node(brick, "brick")
    brick.inputs['Size'].default_value = (bw, bd, bh_)
    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+1700, 0)
    tree.links.new(set_pos.outputs['Geometry'], inst.inputs['Points'])
    tree.links.new(brick.outputs['Mesh'], inst.inputs['Instance'])
    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+2000, 0)
    tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
    trans = tree.nodes.new('GeometryNodeTransform'); trans.location = (base_x+2300, 0); color_node(trans, "brick")
    trans.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(realize.outputs['Geometry'], trans.inputs['Geometry'])
    return trans.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: VENETIAN BRIDGE (Rialto-style multi-arch)
# ----------------------------------------------------------------------

def build_venetian_bridge(tree, props, base_x=-1400):
    """Multi-arch bridge over a span. Pier walls + ogee/gothic arches + walkway + railings."""
    L = props.bridge_length
    H = props.bridge_height
    n = max(1, props.bridge_arches)
    style = props.bridge_arch_style

    parts = []
    pier_W = L * 0.05
    arch_W = (L - pier_W * (n + 1)) / n

    # Build a single arch sized for one bay
    saved_ogee = (props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial)
    saved_goth = (props.gothic_width, props.gothic_radius)
    saved_cusp = (props.cusped_width, props.cusped_height)

    if style == 'OGEE':
        props.ogee_width  = arch_W
        props.ogee_height = H
        props.ogee_swell  = 0.2
        props.ogee_finial = 0.0
        arch_geom = build_ogee_arch(tree, props, base_x=base_x)
    elif style == 'CUSPED':
        props.cusped_width  = arch_W
        props.cusped_height = H
        arch_geom = build_cusped_arch(tree, props, base_x=base_x)
    else:
        props.gothic_width  = arch_W
        props.gothic_radius = arch_W * 0.7
        arch_geom = build_gothic_arch(tree, props, base_x=base_x)

    # Restore
    props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial = saved_ogee
    props.gothic_width, props.gothic_radius = saved_goth
    props.cusped_width, props.cusped_height = saved_cusp

    # Instance arches across the span
    arch_line = tree.nodes.new('GeometryNodeMeshLine'); arch_line.location = (base_x+3000, 0); color_node(arch_line, "bridge")
    arch_line.mode = 'OFFSET'
    arch_line.inputs['Count'].default_value = n
    arch_x_start = -L/2 + pier_W + arch_W/2
    arch_line.inputs['Start Location'].default_value = (arch_x_start, 0, 0)
    arch_line.inputs['Offset'].default_value = (arch_W + pier_W, 0, 0)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+3300, 0)
    tree.links.new(arch_line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(arch_geom, inst.inputs['Instance'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+3600, 0)
    tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
    parts.append(realize.outputs['Geometry'])

    # === Pier walls — FULL HEIGHT (z=0 → z=H) so the walkway sits directly on top ===
    pier_depth_y = 1.0  # match walkway depth so piers and deck align in Y
    pier_line = tree.nodes.new('GeometryNodeMeshLine'); pier_line.location = (base_x+3000, 400); color_node(pier_line, "bridge")
    pier_line.mode = 'OFFSET'
    pier_line.inputs['Count'].default_value = n + 1
    pier_line.inputs['Start Location'].default_value = (-L/2 + pier_W/2, 0, 0)
    pier_line.inputs['Offset'].default_value = (arch_W + pier_W, 0, 0)

    pier = tree.nodes.new('GeometryNodeMeshCube'); pier.location = (base_x+3000, 700); color_node(pier, "bridge")
    pier.inputs['Size'].default_value = (pier_W, pier_depth_y, H)  # FULL HEIGHT (was H*0.9)

    pier_inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); pier_inst.location = (base_x+3300, 400)
    tree.links.new(pier_line.outputs['Mesh'], pier_inst.inputs['Points'])
    tree.links.new(pier.outputs['Mesh'], pier_inst.inputs['Instance'])

    pier_t = tree.nodes.new('GeometryNodeTranslateInstances'); pier_t.location = (base_x+3600, 400)
    pier_t.inputs['Translation'].default_value = (0, 0, H / 2)  # centered at H/2 → top at H
    tree.links.new(pier_inst.outputs['Instances'], pier_t.inputs['Instances'])

    pier_real = tree.nodes.new('GeometryNodeRealizeInstances'); pier_real.location = (base_x+3900, 400)
    tree.links.new(pier_t.outputs['Instances'], pier_real.inputs['Geometry'])
    parts.append(pier_real.outputs['Geometry'])

    # Spandrel walls — fill space between arch tops and walkway bottom (Venetian-style fillets)
    spandrel_h = 0.06  # thin band right under the walkway
    spandrel_line = tree.nodes.new('GeometryNodeMeshLine'); spandrel_line.location = (base_x+3000, 1700); color_node(spandrel_line, "bridge")
    spandrel_line.mode = 'OFFSET'
    spandrel_line.inputs['Count'].default_value = n
    spandrel_line.inputs['Start Location'].default_value = (-L/2 + pier_W + arch_W/2, 0, H - spandrel_h/2)
    spandrel_line.inputs['Offset'].default_value = (arch_W + pier_W, 0, 0)

    span_block = tree.nodes.new('GeometryNodeMeshCube'); span_block.location = (base_x+3000, 1900); color_node(span_block, "bridge")
    span_block.inputs['Size'].default_value = (arch_W * 0.5, pier_depth_y, spandrel_h)  # only fills part above arch peak

    span_inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); span_inst.location = (base_x+3300, 1700)
    tree.links.new(spandrel_line.outputs['Mesh'], span_inst.inputs['Points'])
    tree.links.new(span_block.outputs['Mesh'], span_inst.inputs['Instance'])

    span_real = tree.nodes.new('GeometryNodeRealizeInstances'); span_real.location = (base_x+3600, 1700)
    tree.links.new(span_inst.outputs['Instances'], span_real.inputs['Geometry'])
    parts.append(span_real.outputs['Geometry'])

    # === Walkway — sits directly on top of piers, snap-aligned ===
    deck_thick = 0.18
    if props.bridge_walkway:
        walkway = tree.nodes.new('GeometryNodeMeshCube'); walkway.location = (base_x+3000, 1000); color_node(walkway, "bridge")
        walkway.inputs['Size'].default_value = (L, pier_depth_y * 1.05, deck_thick)  # tiny eave overhang
        walk_t = tree.nodes.new('GeometryNodeTransform'); walk_t.location = (base_x+3300, 1000)
        walk_t.inputs['Translation'].default_value = (0, 0, H + deck_thick/2)  # bottom at H, top at H+thick
        tree.links.new(walkway.outputs['Mesh'], walk_t.inputs['Geometry'])
        parts.append(walk_t.outputs['Geometry'])

    # === Side railings — sit on TOP of walkway, with tiny inset ===
    if props.bridge_railings:
        rail_top = H + deck_thick  # top of walkway
        rail_height = 0.5
        rail_y_inset = 0.03
        for y_off in (-pier_depth_y/2 + rail_y_inset, pier_depth_y/2 - rail_y_inset):
            rail = tree.nodes.new('GeometryNodeMeshCube'); rail.location = (base_x+3000, 1300); color_node(rail, "bridge")
            rail.inputs['Size'].default_value = (L, 0.06, rail_height)
            r_t = tree.nodes.new('GeometryNodeTransform'); r_t.location = (base_x+3300, 1300 + (100 if y_off > 0 else 0))
            r_t.inputs['Translation'].default_value = (0, y_off, rail_top + rail_height/2)
            tree.links.new(rail.outputs['Mesh'], r_t.inputs['Geometry'])
            parts.append(r_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+4200, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: ESCHER PATH (curving impossible loop walkway)
# ----------------------------------------------------------------------

def build_escher_path(tree, props, base_x=-1400):
    """A circular path with sine-driven vertical wave (impossible Escher feel) + arch supports."""
    R = props.path_radius
    n = props.path_segments
    width = props.path_width
    thick = props.path_thickness
    amp = props.path_z_amplitude
    freq = props.path_z_freq

    # Curve circle for path
    circle = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); circle.location = (base_x, 0); color_node(circle, "path")
    circle.mode = 'RADIUS'
    circle.inputs['Resolution'].default_value = n
    circle.inputs['Radius'].default_value = R

    # Z-wave displacement on the curve (sin driven by spline parameter)
    param = tree.nodes.new('GeometryNodeSplineParameter'); param.location = (base_x, -400); color_node(param, "input")
    mul_freq = tree.nodes.new('ShaderNodeMath'); mul_freq.location = (base_x+200, -400); mul_freq.operation = 'MULTIPLY'
    mul_freq.inputs[1].default_value = freq * math.tau
    tree.links.new(param.outputs['Factor'], mul_freq.inputs[0])
    sine = tree.nodes.new('ShaderNodeMath'); sine.location = (base_x+400, -400); sine.operation = 'SINE'
    tree.links.new(mul_freq.outputs['Value'], sine.inputs[0])
    z_amp = tree.nodes.new('ShaderNodeMath'); z_amp.location = (base_x+600, -400); z_amp.operation = 'MULTIPLY'
    z_amp.inputs[1].default_value = amp
    tree.links.new(sine.outputs['Value'], z_amp.inputs[0])
    color_node(z_amp, "ornament")
    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+800, -400)
    ovec.inputs['X'].default_value = 0; ovec.inputs['Y'].default_value = 0
    tree.links.new(z_amp.outputs['Value'], ovec.inputs['Z'])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (base_x+1000, 0); color_node(set_pos, "deform")
    tree.links.new(circle.outputs['Curve'], set_pos.inputs['Geometry'])
    tree.links.new(ovec.outputs['Vector'], set_pos.inputs['Offset'])

    # Sweep with rectangular profile (path width × thickness)
    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, 400); color_node(profile, "path")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 4   # 4 = square-ish
    profile.inputs['Radius'].default_value = max(width, thick) * 0.5

    sweep = tree.nodes.new('GeometryNodeCurveToMesh'); sweep.location = (base_x+1300, 0); color_node(sweep, "path")
    tree.links.new(set_pos.outputs['Geometry'], sweep.inputs['Curve'])
    tree.links.new(profile.outputs['Curve'], sweep.inputs['Profile Curve'])
    sweep.inputs['Fill Caps'].default_value = True

    parts = [sweep.outputs['Mesh']]

    # Arch supports below
    if props.path_with_arches and props.path_arch_count > 0:
        # Sample points around the path circle for arch placement
        sample = tree.nodes.new('GeometryNodeResampleCurve'); sample.location = (base_x+1300, 600); color_node(sample, "ornament")
        sample.inputs['Mode'].default_value = 'Count'
        sample.inputs['Count'].default_value = props.path_arch_count
        tree.links.new(set_pos.outputs['Geometry'], sample.inputs['Curve'])

        c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+1500, 600)
        c2p.mode = 'EVALUATED'
        tree.links.new(sample.outputs['Curve'], c2p.inputs['Curve'])

        # Build a small ogee arch as the support
        saved_o = (props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial)
        props.ogee_width = R * 0.3
        props.ogee_height = R * 0.5
        props.ogee_swell = 0.1
        props.ogee_finial = 0.0
        small_arch = build_ogee_arch(tree, props, base_x=base_x+1700)
        props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial = saved_o

        # Translate small arch downward (so its top is at path height)
        # Arches will be placed at points along the path with their tops touching
        arch_lower = tree.nodes.new('GeometryNodeTransform'); arch_lower.location = (base_x+2700, 600); color_node(arch_lower, "path")
        arch_lower.inputs['Translation'].default_value = (0, 0, -R * 0.5)
        tree.links.new(small_arch, arch_lower.inputs['Geometry'])

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+3000, 600)
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(arch_lower.outputs['Geometry'], inst.inputs['Instance'])

        # Rotate each arch to face outward radially (use point's tangent rotation)
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

        realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+3300, 600)
        tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
        parts.append(realize.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+3700, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# MODULAR BUILDING PIECES — Window/Door/Balcony/Cornice/Fountain/Tile/Roof/Lantern
# ----------------------------------------------------------------------

def build_window(tree, props, base_x=-1400):
    """Window opening: rectangular frame with optional ogee top + sill."""
    W = props.window_width
    H = props.window_height
    fw = props.window_frame_width
    parts = []

    # Two vertical jambs
    for x_off in (-W/2, W/2):
        jamb = tree.nodes.new('GeometryNodeMeshCube'); jamb.location = (base_x, 0); color_node(jamb, "window")
        jamb.inputs['Size'].default_value = (fw, fw, H)
        jt = tree.nodes.new('GeometryNodeTransform'); jt.location = (base_x+200, 0)
        jt.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(jamb.outputs['Mesh'], jt.inputs['Geometry'])
        parts.append(jt.outputs['Geometry'])

    # Bottom sill (extends past the jambs slightly)
    sill = tree.nodes.new('GeometryNodeMeshCube'); sill.location = (base_x, 300); color_node(sill, "window")
    sill.inputs['Size'].default_value = (W + fw*2 + 0.05, fw + props.window_sill_depth, fw)
    st = tree.nodes.new('GeometryNodeTransform'); st.location = (base_x+200, 300)
    st.inputs['Translation'].default_value = (0, props.window_sill_depth/2, fw/2)
    tree.links.new(sill.outputs['Mesh'], st.inputs['Geometry'])
    parts.append(st.outputs['Geometry'])

    # Top — either flat header or ogee arch
    if props.window_arch_top:
        # Reuse build_ogee_arch with this window's dimensions
        saved = (props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial)
        props.ogee_width = W
        props.ogee_height = H * 0.4
        props.ogee_swell = 0.15
        props.ogee_finial = 0.0
        arch_geom = build_ogee_arch(tree, props, base_x=base_x+1500)
        props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial = saved

        at = tree.nodes.new('GeometryNodeTransform'); at.location = (base_x+3000, 600)
        at.inputs['Translation'].default_value = (0, 0, H)
        tree.links.new(arch_geom, at.inputs['Geometry'])
        parts.append(at.outputs['Geometry'])
    else:
        head = tree.nodes.new('GeometryNodeMeshCube'); head.location = (base_x, 600); color_node(head, "window")
        head.inputs['Size'].default_value = (W + fw*2, fw, fw)
        ht = tree.nodes.new('GeometryNodeTransform'); ht.location = (base_x+200, 600)
        ht.inputs['Translation'].default_value = (0, 0, H + fw/2)
        tree.links.new(head.outputs['Mesh'], ht.inputs['Geometry'])
        parts.append(ht.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+3500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_door(tree, props, base_x=-1400):
    """Door opening with frame + optional steps below + optional ogee arch."""
    W = props.door_width
    H = props.door_height
    fw = props.door_frame_width
    parts = []

    # Two jambs
    for x_off in (-W/2, W/2):
        jamb = tree.nodes.new('GeometryNodeMeshCube'); jamb.location = (base_x, 0); color_node(jamb, "door")
        jamb.inputs['Size'].default_value = (fw, fw*1.5, H)
        jt = tree.nodes.new('GeometryNodeTransform'); jt.location = (base_x+200, 0)
        jt.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(jamb.outputs['Mesh'], jt.inputs['Geometry'])
        parts.append(jt.outputs['Geometry'])

    # Header / arch top
    if props.door_arch_top:
        saved = (props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial)
        props.ogee_width = W
        props.ogee_height = H * 0.45
        props.ogee_swell = 0.2
        props.ogee_finial = 0.0
        arch_geom = build_ogee_arch(tree, props, base_x=base_x+1500)
        props.ogee_width, props.ogee_height, props.ogee_swell, props.ogee_finial = saved
        at = tree.nodes.new('GeometryNodeTransform'); at.location = (base_x+3000, 600)
        at.inputs['Translation'].default_value = (0, 0, H)
        tree.links.new(arch_geom, at.inputs['Geometry'])
        parts.append(at.outputs['Geometry'])
    else:
        lintel = tree.nodes.new('GeometryNodeMeshCube'); lintel.location = (base_x, 600); color_node(lintel, "door")
        lintel.inputs['Size'].default_value = (W + fw*2, fw*1.5, fw*1.2)
        lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x+200, 600)
        lt.inputs['Translation'].default_value = (0, 0, H + fw*0.6)
        tree.links.new(lintel.outputs['Mesh'], lt.inputs['Geometry'])
        parts.append(lt.outputs['Geometry'])

    # Steps below
    if props.door_step_count > 0:
        for i in range(props.door_step_count):
            step = tree.nodes.new('GeometryNodeMeshCube'); step.location = (base_x, -200 - i*100); color_node(step, "door")
            sw = W + fw*2 + (props.door_step_count - i) * 0.12
            sd = fw*1.5 + (props.door_step_count - i) * 0.12
            step.inputs['Size'].default_value = (sw, sd, 0.12)
            stt = tree.nodes.new('GeometryNodeTransform'); stt.location = (base_x+200, -200 - i*100)
            stt.inputs['Translation'].default_value = (0, 0, -0.06 - i*0.12)
            tree.links.new(step.outputs['Mesh'], stt.inputs['Geometry'])
            parts.append(stt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+3500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_balcony(tree, props, base_x=-1400):
    """Small balcony platform with a railing on three sides."""
    W = props.balcony_width
    D = props.balcony_depth
    T = props.balcony_thickness
    parts = []

    # Slab
    slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, 0); color_node(slab, "modular")
    slab.inputs['Size'].default_value = (W, D, T)
    parts.append(slab.outputs['Mesh'])

    # Front railing (along +X face — actually use Y direction: front = +Y/2)
    saved = (props.rail_length, props.rail_baluster_count, props.rail_height)
    props.rail_length = W
    props.rail_baluster_count = props.balcony_baluster_count
    props.rail_height = 0.9
    rail_front = build_railing(tree, props, x_offset=2500)
    props.rail_length, props.rail_baluster_count, props.rail_height = saved

    # Position front railing at +Y edge of slab
    rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+5000, 200); color_node(rt, "modular")
    rt.inputs['Translation'].default_value = (0, D/2 - 0.03, T/2)
    tree.links.new(rail_front, rt.inputs['Geometry'])
    parts.append(rt.outputs['Geometry'])

    # Side railings (two, perpendicular)
    for x_off, dir_sign in ((-W/2 + 0.03, 1), (W/2 - 0.03, -1)):
        saved = (props.rail_length, props.rail_baluster_count)
        props.rail_length = D - 0.05
        props.rail_baluster_count = max(3, props.balcony_baluster_count // 3)
        side_rail = build_railing(tree, props, x_offset=2500 + (x_off + W/2) * 100)
        props.rail_length, props.rail_baluster_count = saved

        srt = tree.nodes.new('GeometryNodeTransform'); srt.location = (base_x+5000, 500); color_node(srt, "modular")
        srt.inputs['Translation'].default_value = (x_off, 0, T/2)
        srt.inputs['Rotation'].default_value = (0, 0, math.radians(90))
        tree.links.new(side_rail, srt.inputs['Geometry'])
        parts.append(srt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+5500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_cornice(tree, props, base_x=-1400):
    """Layered horizontal molding — multiple bands of decreasing depth."""
    L = props.cornice_length
    H = props.cornice_height
    D = props.cornice_depth
    layers = props.cornice_layers
    parts = []

    band_h = H / max(1, layers)
    for i in range(layers):
        scale = 1.0 - (i * 0.12)
        b = tree.nodes.new('GeometryNodeMeshCube'); b.location = (base_x, i * 200); color_node(b, "modular")
        b.inputs['Size'].default_value = (L * scale, D * scale, band_h)
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, i * 200)
        bt.inputs['Translation'].default_value = (0, 0, band_h * (i + 0.5))
        tree.links.new(b.outputs['Mesh'], bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

    # Crown molding on top — rounded edge cylinder
    crown = tree.nodes.new('GeometryNodeMeshCylinder'); crown.location = (base_x, layers * 200); color_node(crown, "modular")
    crown.inputs['Vertices'].default_value = 16
    crown.inputs['Radius'].default_value = D * 0.4
    crown.inputs['Depth'].default_value = L
    ct = tree.nodes.new('GeometryNodeTransform'); ct.location = (base_x+200, layers * 200)
    ct.inputs['Translation'].default_value = (0, 0, H)
    ct.inputs['Rotation'].default_value = (0, math.radians(90), 0)
    tree.links.new(crown.outputs['Mesh'], ct.inputs['Geometry'])
    parts.append(ct.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_fountain(tree, props, base_x=-1400):
    """Tiered fountain: stacked bowls with central column."""
    R = props.fountain_radius
    tiers = props.fountain_tiers
    tier_scale = props.fountain_tier_scale
    H = props.fountain_height
    parts = []

    tier_h = H / (tiers + 1)
    cur_r = R
    cur_z = 0
    for i in range(tiers):
        # Bowl: cylinder with smaller cylinder hollowed (use cone with high top radius)
        bowl = tree.nodes.new('GeometryNodeMeshCylinder'); bowl.location = (base_x, i * 200); color_node(bowl, "fountain")
        bowl.inputs['Vertices'].default_value = 32
        bowl.inputs['Radius'].default_value = cur_r
        bowl.inputs['Depth'].default_value = tier_h * 0.4
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, i * 200)
        bt.inputs['Translation'].default_value = (0, 0, cur_z + tier_h * 0.2)
        tree.links.new(bowl.outputs['Mesh'], bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

        # Inner bowl rim (smaller cylinder on top)
        rim = tree.nodes.new('GeometryNodeMeshCylinder'); rim.location = (base_x, i * 200 + 100); color_node(rim, "fountain")
        rim.inputs['Vertices'].default_value = 32
        rim.inputs['Radius'].default_value = cur_r * 0.92
        rim.inputs['Depth'].default_value = tier_h * 0.05
        rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+200, i * 200 + 100)
        rt.inputs['Translation'].default_value = (0, 0, cur_z + tier_h * 0.42)
        tree.links.new(rim.outputs['Mesh'], rt.inputs['Geometry'])
        parts.append(rt.outputs['Geometry'])

        # Central column between this tier and next
        col = tree.nodes.new('GeometryNodeMeshCylinder'); col.location = (base_x, i * 200 + 200); color_node(col, "fountain")
        col.inputs['Vertices'].default_value = 16
        col.inputs['Radius'].default_value = cur_r * 0.18
        col.inputs['Depth'].default_value = tier_h * 0.6
        cot = tree.nodes.new('GeometryNodeTransform'); cot.location = (base_x+200, i * 200 + 200)
        cot.inputs['Translation'].default_value = (0, 0, cur_z + tier_h * 0.7)
        tree.links.new(col.outputs['Mesh'], cot.inputs['Geometry'])
        parts.append(cot.outputs['Geometry'])

        cur_r *= tier_scale
        cur_z += tier_h

    # Tip finial sphere
    tip = tree.nodes.new('GeometryNodeMeshUVSphere'); tip.location = (base_x, tiers * 200); color_node(tip, "fountain")
    tip.inputs['Radius'].default_value = cur_r * 0.5
    tip.inputs['Segments'].default_value = 16
    tip.inputs['Rings'].default_value = 12
    tt = tree.nodes.new('GeometryNodeTransform'); tt.location = (base_x+200, tiers * 200)
    tt.inputs['Translation'].default_value = (0, 0, cur_z + cur_r * 0.5)
    tree.links.new(tip.outputs['Mesh'], tt.inputs['Geometry'])
    parts.append(tt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_floor_tile(tree, props, base_x=-1400):
    """Decorative floor tile — single, grid, checkerboard, or randomized."""
    s = props.tile_size
    t = props.tile_thickness
    pat = props.tile_pattern
    n = max(1, props.tile_grid_count)

    if pat == 'SOLID':
        tile = tree.nodes.new('GeometryNodeMeshCube'); tile.location = (base_x, 0); color_node(tile, "tile")
        tile.inputs['Size'].default_value = (s, s, t)
        return tile.outputs['Mesh']

    # Grid of points
    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (base_x, 0); color_node(grid, "tile")
    grid.inputs['Size X'].default_value = s * n
    grid.inputs['Size Y'].default_value = s * n
    grid.inputs['Vertices X'].default_value = n
    grid.inputs['Vertices Y'].default_value = n

    tile_proto = tree.nodes.new('GeometryNodeMeshCube'); tile_proto.location = (base_x, 300); color_node(tile_proto, "tile")
    tile_proto.inputs['Size'].default_value = (s * 0.95, s * 0.95, t)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+300, 0)
    tree.links.new(grid.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(tile_proto.outputs['Mesh'], inst.inputs['Instance'])

    if pat == 'CHECKER':
        # Vary Z by index parity
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 600)
        mod_n = tree.nodes.new('ShaderNodeMath'); mod_n.location = (base_x+200, 600); mod_n.operation = 'MODULO'
        mod_n.inputs[1].default_value = 2.0
        tree.links.new(idx.outputs['Index'], mod_n.inputs[0])
        z_off = tree.nodes.new('ShaderNodeMath'); z_off.location = (base_x+400, 600); z_off.operation = 'MULTIPLY'
        z_off.inputs[1].default_value = t
        tree.links.new(mod_n.outputs[0], z_off.inputs[0])
        ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+600, 600)
        ovec.inputs['X'].default_value = 0; ovec.inputs['Y'].default_value = 0
        tree.links.new(z_off.outputs[0], ovec.inputs['Z'])
        ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+800, 0)
        tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])
        tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])
        out_inst = ti.outputs['Instances']
    elif pat == 'VENETIAN':
        # Random Z rotation per tile
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 600)
        rmul = tree.nodes.new('ShaderNodeMath'); rmul.location = (base_x+200, 600); rmul.operation = 'MULTIPLY'
        rmul.inputs[1].default_value = 0.78  # ~45° per index, irrational ratio
        tree.links.new(idx.outputs['Index'], rmul.inputs[0])
        rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+400, 600)
        rvec.inputs['X'].default_value = 0; rvec.inputs['Y'].default_value = 0
        tree.links.new(rmul.outputs[0], rvec.inputs['Z'])
        ri = tree.nodes.new('GeometryNodeRotateInstances'); ri.location = (base_x+800, 0)
        tree.links.new(inst.outputs['Instances'], ri.inputs['Instances'])
        tree.links.new(rvec.outputs['Vector'], ri.inputs['Rotation'])
        out_inst = ri.outputs['Instances']
    else:  # GRID
        out_inst = inst.outputs['Instances']

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1100, 0)
    tree.links.new(out_inst, realize.inputs['Geometry'])
    return realize.outputs['Geometry']


def build_roof_tiles(tree, props, base_x=-1400):
    """Overlapping curved tiles on a sloped roof plane."""
    W = props.roof_width
    L = props.roof_length
    pitch = math.radians(props.roof_pitch_deg)
    nx = props.roof_tile_count_x
    ny = props.roof_tile_count_y

    # Grid of points
    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (base_x, 0); color_node(grid, "roof")
    grid.inputs['Size X'].default_value = W
    grid.inputs['Size Y'].default_value = L
    grid.inputs['Vertices X'].default_value = nx
    grid.inputs['Vertices Y'].default_value = ny

    # Curved tile prototype: small half-cylinder
    tile = tree.nodes.new('GeometryNodeMeshCylinder'); tile.location = (base_x, 300); color_node(tile, "roof")
    tile.inputs['Vertices'].default_value = 12
    tile.inputs['Radius'].default_value = (W / nx) * 0.5
    tile.inputs['Depth'].default_value = (L / ny) * 1.15  # overlap

    # Rotate tile to lie along Y axis
    tile_t = tree.nodes.new('GeometryNodeTransform'); tile_t.location = (base_x+200, 300)
    tile_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(tile.outputs['Mesh'], tile_t.inputs['Geometry'])

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+500, 0)
    tree.links.new(grid.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(tile_t.outputs['Geometry'], inst.inputs['Instance'])

    # Stagger every other row (X offset by half-tile)
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 600)
    div = tree.nodes.new('ShaderNodeMath'); div.location = (base_x+200, 600); div.operation = 'DIVIDE'
    div.inputs[1].default_value = float(nx)
    tree.links.new(idx.outputs['Index'], div.inputs[0])
    fl = tree.nodes.new('ShaderNodeMath'); fl.location = (base_x+400, 600); fl.operation = 'FLOOR'
    tree.links.new(div.outputs[0], fl.inputs[0])
    mod_n = tree.nodes.new('ShaderNodeMath'); mod_n.location = (base_x+600, 600); mod_n.operation = 'MODULO'
    mod_n.inputs[1].default_value = 2.0
    tree.links.new(fl.outputs[0], mod_n.inputs[0])
    stagger = tree.nodes.new('ShaderNodeMath'); stagger.location = (base_x+800, 600); stagger.operation = 'MULTIPLY'
    stagger.inputs[1].default_value = (W / nx) * 0.5
    tree.links.new(mod_n.outputs[0], stagger.inputs[0])
    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1000, 600)
    tree.links.new(stagger.outputs[0], ovec.inputs['X'])
    ovec.inputs['Y'].default_value = 0; ovec.inputs['Z'].default_value = 0

    ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+1200, 0)
    tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])
    tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1500, 0)
    tree.links.new(ti.outputs['Instances'], realize.inputs['Geometry'])

    # Apply pitch — rotate around X axis
    pitch_t = tree.nodes.new('GeometryNodeTransform'); pitch_t.location = (base_x+1800, 0); color_node(pitch_t, "roof")
    pitch_t.inputs['Rotation'].default_value = (pitch, 0, 0)
    tree.links.new(realize.outputs['Geometry'], pitch_t.inputs['Geometry'])

    return pitch_t.outputs['Geometry']


def build_lantern_post(tree, props, base_x=-1400):
    """Venetian lamppost: tall thin post + capital + glass enclosure + finial."""
    H = props.lantern_height
    pr = props.lantern_post_radius
    gs = props.lantern_glass_size
    parts = []

    # Post
    post = tree.nodes.new('GeometryNodeMeshCylinder'); post.location = (base_x, 0); color_node(post, "lantern")
    post.inputs['Vertices'].default_value = 12
    post.inputs['Radius'].default_value = pr
    post.inputs['Depth'].default_value = H * 0.85
    pt = tree.nodes.new('GeometryNodeTransform'); pt.location = (base_x+200, 0)
    pt.inputs['Translation'].default_value = (0, 0, H * 0.425)
    tree.links.new(post.outputs['Mesh'], pt.inputs['Geometry'])
    parts.append(pt.outputs['Geometry'])

    # Base — wider cylinder
    base = tree.nodes.new('GeometryNodeMeshCylinder'); base.location = (base_x, -200); color_node(base, "lantern")
    base.inputs['Vertices'].default_value = 12
    base.inputs['Radius'].default_value = pr * 4
    base.inputs['Depth'].default_value = pr * 4
    bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, -200)
    bt.inputs['Translation'].default_value = (0, 0, pr * 2)
    tree.links.new(base.outputs['Mesh'], bt.inputs['Geometry'])
    parts.append(bt.outputs['Geometry'])

    # Capital under the lamp
    cap = tree.nodes.new('GeometryNodeMeshCone'); cap.location = (base_x, 200); color_node(cap, "lantern")
    cap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading
    cap.inputs['Radius Top'].default_value = gs * 0.6
    cap.inputs['Radius Bottom'].default_value = pr * 1.5
    cap.inputs['Depth'].default_value = gs * 0.5
    capt = tree.nodes.new('GeometryNodeTransform'); capt.location = (base_x+200, 200)
    capt.inputs['Translation'].default_value = (0, 0, H * 0.85 + gs * 0.25)
    tree.links.new(cap.outputs['Mesh'], capt.inputs['Geometry'])
    parts.append(capt.outputs['Geometry'])

    # Glass cube
    glass = tree.nodes.new('GeometryNodeMeshCube'); glass.location = (base_x, 400); color_node(glass, "lantern")
    glass.inputs['Size'].default_value = (gs, gs, gs)
    gt = tree.nodes.new('GeometryNodeTransform'); gt.location = (base_x+200, 400)
    gt.inputs['Translation'].default_value = (0, 0, H * 0.85 + gs * 0.5 + gs * 0.5)
    tree.links.new(glass.outputs['Mesh'], gt.inputs['Geometry'])
    parts.append(gt.outputs['Geometry'])

    # Finial cap on top
    fin = tree.nodes.new('GeometryNodeMeshCone'); fin.location = (base_x, 600); color_node(fin, "lantern")
    fin.inputs['Vertices'].default_value = 16  # bumped from 12 in v2.31
    fin.inputs['Radius Top'].default_value = 0.0
    fin.inputs['Radius Bottom'].default_value = gs * 0.4
    fin.inputs['Depth'].default_value = gs * 0.6
    ft = tree.nodes.new('GeometryNodeTransform'); ft.location = (base_x+200, 600)
    ft.inputs['Translation'].default_value = (0, 0, H * 0.85 + gs + gs * 0.8)
    tree.links.new(fin.outputs['Mesh'], ft.inputs['Geometry'])
    parts.append(ft.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# REUSABLE INSTANCE-PIECE PROTOTYPES
# Returns a small, generic mesh suitable for instancing on a curve / radial array.
# ----------------------------------------------------------------------

def build_piece_prototype(tree, props, kind, base_x=-1400):
    """Create a small mesh of the given kind, suitable for instancing along splines or radially."""
    if kind == 'BALUSTER':
        cyl = tree.nodes.new('GeometryNodeMeshCylinder'); cyl.location = (base_x, 0); color_node(cyl, "spline")
        cyl.inputs['Vertices'].default_value = 8
        cyl.inputs['Radius'].default_value = 0.06
        cyl.inputs['Depth'].default_value = 1.0
        # Bulge in the middle (classical baluster shape) by Set Position
        return cyl.outputs['Mesh']

    if kind == 'LANTERN':
        saved = (props.lantern_height,)
        props.lantern_height = 1.5
        g = build_lantern_post(tree, props, base_x=base_x)
        props.lantern_height = saved[0]
        return g

    if kind == 'CAPITAL':
        # Mini column with capital
        col = tree.nodes.new('GeometryNodeMeshCylinder'); col.location = (base_x, 0); color_node(col, "spline")
        col.inputs['Vertices'].default_value = 12
        col.inputs['Radius'].default_value = 0.1
        col.inputs['Depth'].default_value = 1.4
        cap = tree.nodes.new('GeometryNodeMeshCone'); cap.location = (base_x, 200); color_node(cap, "spline")
        cap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading  # bumped from 12 in v2.31
        cap.inputs['Radius Top'].default_value = 0.18
        cap.inputs['Radius Bottom'].default_value = 0.1
        cap.inputs['Depth'].default_value = 0.18
        cap_t = tree.nodes.new('GeometryNodeTransform'); cap_t.location = (base_x+200, 200)
        cap_t.inputs['Translation'].default_value = (0, 0, 0.79)
        tree.links.new(cap.outputs['Mesh'], cap_t.inputs['Geometry'])
        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "spline")
        tree.links.new(col.outputs['Mesh'], join.inputs['Geometry'])
        tree.links.new(cap_t.outputs['Geometry'], join.inputs['Geometry'])
        return join.outputs['Geometry']

    if kind == 'OGEE_ARCH':
        saved = (props.ogee_width, props.ogee_height, props.ogee_finial)
        props.ogee_width = 0.8; props.ogee_height = 1.2; props.ogee_finial = 0.0
        g = build_ogee_arch(tree, props, base_x=base_x)
        props.ogee_width, props.ogee_height, props.ogee_finial = saved
        return g

    if kind == 'TREFOIL':
        saved = (props.trefoil_outer, props.trefoil_radius)
        props.trefoil_outer = 0.4; props.trefoil_radius = 0.16
        g = build_trefoil(tree, props, base_x=base_x)
        props.trefoil_outer, props.trefoil_radius = saved
        return g

    if kind == 'WINDOW':
        saved = (props.window_width, props.window_height)
        props.window_width = 0.7; props.window_height = 1.2
        g = build_window(tree, props, base_x=base_x)
        props.window_width, props.window_height = saved
        return g

    # Default: small bevel-friendly cube
    cube = tree.nodes.new('GeometryNodeMeshCube'); cube.location = (base_x, 0); color_node(cube, "spline")
    cube.inputs['Size'].default_value = (0.3, 0.3, 0.3)
    return cube.outputs['Mesh']


# ----------------------------------------------------------------------
# BUILDER: INSTANCE TO SPLINE
# Array a chosen piece along a curve — input curve is either a scene object
# or the modifier's input geometry (set Object Info / Group Input chain).
# ----------------------------------------------------------------------

def build_spline_instance(tree, props, base_x=-1400, curve_socket=None):
    """Sample a curve at N evenly-spaced points and instance the chosen piece on each."""
    # Source curve geometry
    if curve_socket is not None:
        cgeom = curve_socket
    elif props.spline_target is not None and props.spline_target.type == 'CURVE':
        # Use Object Info node for an external curve object
        oi = tree.nodes.new('GeometryNodeObjectInfo'); oi.location = (base_x, 200); color_node(oi, "spline")
        oi.inputs['Object'].default_value = props.spline_target
        oi.transform_space = 'ORIGINAL'
        cgeom = oi.outputs['Geometry']
    else:
        # Fallback: a default circle if no source provided
        circ = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); circ.location = (base_x, 200); color_node(circ, "spline")
        circ.mode = 'RADIUS'
        circ.inputs['Resolution'].default_value = max(8, props.spline_count * 2)
        circ.inputs['Radius'].default_value = max(0.5, props.radial_radius)
        cgeom = circ.outputs['Curve']

    # Resample to N evenly-spaced points
    samp = tree.nodes.new('GeometryNodeResampleCurve'); samp.location = (base_x+300, 200); color_node(samp, "spline")
    samp.inputs['Mode'].default_value = 'Count'
    samp.inputs['Count'].default_value = props.spline_count
    tree.links.new(cgeom, samp.inputs['Curve'])

    # Curve to points (gives us per-point positions + tangent rotation)
    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+600, 200); color_node(c2p, "spline")
    c2p.mode = 'EVALUATED'
    tree.links.new(samp.outputs['Curve'], c2p.inputs['Curve'])

    # Build the prototype piece — either from a scene object or a built-in piece
    if props.spline_source_object is not None and props.spline_source_object.type == 'MESH':
        oi = tree.nodes.new('GeometryNodeObjectInfo'); oi.location = (base_x-300, -200); color_node(oi, "spline")
        oi.inputs['Object'].default_value = props.spline_source_object
        oi.transform_space = 'ORIGINAL'
        piece = oi.outputs['Geometry']
    else:
        piece = build_piece_prototype(tree, props, props.spline_piece_type, base_x=base_x-1500)

    # Instance on points
    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+900, 0); color_node(inst, "spline")
    tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(piece, inst.inputs['Instance'])

    # Optional rotation (tangent or normal-out)
    if props.spline_align_tangent or props.spline_align_normal:
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

    # Scale instances
    sv = tree.nodes.new('ShaderNodeCombineXYZ'); sv.location = (base_x+700, -300); color_node(sv, "spline")
    sv.inputs['X'].default_value = props.spline_scale
    sv.inputs['Y'].default_value = props.spline_scale
    sv.inputs['Z'].default_value = props.spline_scale
    si = tree.nodes.new('GeometryNodeScaleInstances'); si.location = (base_x+1100, 0)
    tree.links.new(inst.outputs['Instances'], si.inputs['Instances'])
    tree.links.new(sv.outputs['Vector'], si.inputs['Scale'])

    # Z offset
    if abs(props.spline_z_offset) > 0.001:
        ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1100, -300)
        ovec.inputs['X'].default_value = 0
        ovec.inputs['Y'].default_value = 0
        ovec.inputs['Z'].default_value = props.spline_z_offset
        ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+1300, 0)
        tree.links.new(si.outputs['Instances'], ti.inputs['Instances'])
        tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])
        out_inst = ti.outputs['Instances']
    else:
        out_inst = si.outputs['Instances']

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1500, 0); color_node(realize, "output")
    tree.links.new(out_inst, realize.inputs['Geometry'])
    return realize.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: RADIAL ARRAY (snap to tower edge)
# ----------------------------------------------------------------------

def build_radial_array(tree, props, base_x=-1400):
    """Array a piece around the Z axis at a fixed radius — perfect for railings on tower edges."""
    R = props.radial_radius
    n = props.radial_count
    z = props.radial_z

    # Build a curve circle as the placement path
    circ = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); circ.location = (base_x, 0); color_node(circ, "radial")
    circ.mode = 'RADIUS'
    circ.inputs['Resolution'].default_value = n
    circ.inputs['Radius'].default_value = R

    # Lift to z height
    circ_t = tree.nodes.new('GeometryNodeTransform'); circ_t.location = (base_x+250, 0); color_node(circ_t, "radial")
    circ_t.inputs['Translation'].default_value = (0, 0, z)
    tree.links.new(circ.outputs['Curve'], circ_t.inputs['Geometry'])

    # Curve to points (gives us tangent rotation)
    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+500, 0); color_node(c2p, "radial")
    c2p.mode = 'EVALUATED'
    tree.links.new(circ_t.outputs['Geometry'], c2p.inputs['Curve'])

    # Piece prototype — either from a scene object or a built-in piece
    if props.radial_source_object is not None and props.radial_source_object.type == 'MESH':
        oi = tree.nodes.new('GeometryNodeObjectInfo'); oi.location = (base_x-300, -200); color_node(oi, "radial")
        oi.inputs['Object'].default_value = props.radial_source_object
        oi.transform_space = 'ORIGINAL'
        piece = oi.outputs['Geometry']
    else:
        piece = build_piece_prototype(tree, props, props.radial_piece_type, base_x=base_x-1500)

    # Instance on points
    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+800, 0); color_node(inst, "radial")
    tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(piece, inst.inputs['Instance'])

    # Face outward (use curve's tangent — circle tangent is perpendicular to radial dir,
    # so rotate by 90° around Z if face_out is on)
    if props.radial_face_out:
        # Use the rotation output of CurveToPoints (which gives tangent-based rotation)
        # then add a 90° Z rotation so pieces face outward instead of along the curve
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])
        # Add an extra 90° Z rotation
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x+500, 300)
        ang = tree.nodes.new('ShaderNodeMath'); ang.location = (base_x+700, 300); ang.operation = 'MULTIPLY'
        ang.inputs[1].default_value = math.tau / max(1, n)
        tree.links.new(idx.outputs['Index'], ang.inputs[0])
        rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+900, 300); color_node(rvec, "radial")
        rvec.inputs['X'].default_value = 0
        rvec.inputs['Y'].default_value = 0
        tree.links.new(ang.outputs['Value'], rvec.inputs['Z'])
        ri = tree.nodes.new('GeometryNodeRotateInstances'); ri.location = (base_x+1100, 0); color_node(ri, "radial")
        tree.links.new(inst.outputs['Instances'], ri.inputs['Instances'])
        tree.links.new(rvec.outputs['Vector'], ri.inputs['Rotation'])
        out_inst = ri.outputs['Instances']
    else:
        out_inst = inst.outputs['Instances']

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1400, 0); color_node(realize, "output")
    tree.links.new(out_inst, realize.inputs['Geometry'])
    return realize.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: ESCHER TESSELLATION (interlocking grid with sine metamorphosis)
# ----------------------------------------------------------------------

def build_tessellation(tree, props, base_x=-1400):
    """
    Escher-style tessellation:
    A grid of small cells where each cell has:
      • per-cell sine-wave Z displacement (metamorphosis)
      • per-cell rotation variation
      • interlocking via slight overlap
    Driven by the harmonic params for cohesion with the rest of the system.
    """
    nx = props.tess_grid_x
    ny = props.tess_grid_y
    s = props.tess_size
    parts = []

    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (base_x, 0); color_node(grid, "tessellation")
    grid.inputs['Size X'].default_value = s * nx
    grid.inputs['Size Y'].default_value = s * ny
    grid.inputs['Vertices X'].default_value = nx
    grid.inputs['Vertices Y'].default_value = ny

    # Tile prototype — small box
    tile = tree.nodes.new('GeometryNodeMeshCube'); tile.location = (base_x, 300); color_node(tile, "tessellation")
    tile.inputs['Size'].default_value = (s * 1.05, s * 1.05, s * 0.4)  # slight overlap

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+300, 0); color_node(inst, "tessellation")
    tree.links.new(grid.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(tile.outputs['Mesh'], inst.inputs['Instance'])

    # Per-instance Z height variation via sine of (X + Y) → Escher metamorphosis pattern
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (base_x, -400); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (base_x+200, -400)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])
    sumxy = tree.nodes.new('ShaderNodeMath'); sumxy.location = (base_x+400, -400); sumxy.operation = 'ADD'
    tree.links.new(sep.outputs['X'], sumxy.inputs[0])
    tree.links.new(sep.outputs['Y'], sumxy.inputs[1])
    fmul = tree.nodes.new('ShaderNodeMath'); fmul.location = (base_x+600, -400); fmul.operation = 'MULTIPLY'
    fmul.inputs[1].default_value = props.musical_freq_a * NOTE_PATTERNS.get(props.note_pattern, 4.0) * props.tempo_factor / 4.0
    tree.links.new(sumxy.outputs[0], fmul.inputs[0])
    sn = tree.nodes.new('ShaderNodeMath'); sn.location = (base_x+800, -400); sn.operation = 'SINE'
    tree.links.new(fmul.outputs[0], sn.inputs[0])
    color_node(sn, "tessellation")
    h_amp = tree.nodes.new('ShaderNodeMath'); h_amp.location = (base_x+1000, -400); h_amp.operation = 'MULTIPLY'
    h_amp.inputs[1].default_value = props.tess_height_var
    tree.links.new(sn.outputs[0], h_amp.inputs[0])

    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+1200, -400); color_node(ovec, "tessellation")
    ovec.inputs['X'].default_value = 0
    ovec.inputs['Y'].default_value = 0
    tree.links.new(h_amp.outputs[0], ovec.inputs['Z'])

    ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+1400, 0); color_node(ti, "tessellation")
    tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])
    tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])

    # Optional rotation variation
    if props.tess_rotate_var > 0.001:
        idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x+1100, 200)
        # Pseudo-random rotation per index using sin
        rmul = tree.nodes.new('ShaderNodeMath'); rmul.location = (base_x+1300, 200); rmul.operation = 'MULTIPLY'
        rmul.inputs[1].default_value = 1.61803  # golden ratio for non-repeating
        tree.links.new(idx.outputs['Index'], rmul.inputs[0])
        rsin = tree.nodes.new('ShaderNodeMath'); rsin.location = (base_x+1500, 200); rsin.operation = 'SINE'
        tree.links.new(rmul.outputs[0], rsin.inputs[0])
        rscale = tree.nodes.new('ShaderNodeMath'); rscale.location = (base_x+1700, 200); rscale.operation = 'MULTIPLY'
        rscale.inputs[1].default_value = props.tess_rotate_var
        tree.links.new(rsin.outputs[0], rscale.inputs[0])
        rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+1900, 200); color_node(rvec, "tessellation")
        rvec.inputs['X'].default_value = 0
        rvec.inputs['Y'].default_value = 0
        tree.links.new(rscale.outputs[0], rvec.inputs['Z'])
        ri = tree.nodes.new('GeometryNodeRotateInstances'); ri.location = (base_x+2100, 0)
        tree.links.new(ti.outputs['Instances'], ri.inputs['Instances'])
        tree.links.new(rvec.outputs['Vector'], ri.inputs['Rotation'])
        final_inst = ri.outputs['Instances']
    else:
        final_inst = ti.outputs['Instances']

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+2400, 0); color_node(realize, "output")
    tree.links.new(final_inst, realize.inputs['Geometry'])
    return realize.outputs['Geometry']


# ----------------------------------------------------------------------
# BUILDER: HYPERBOLIC DISK (Escher's Circle Limit)
# ----------------------------------------------------------------------

def build_hyperbolic_disk(tree, props, base_x=-1400):
    """
    Poincaré disk — concentric rings of decreasing-arc tiles.
    True hyperbolic geometry has an infinite tiling that bends toward the boundary.
    Approximated here with: outer ring + N concentric rings + radial spokes.
    Curvature param mixes flat Euclidean (0) vs Poincaré projection (1).
    """
    R = props.hyperbolic_radius
    n_rings = props.hyperbolic_rings
    n_spokes = props.hyperbolic_petals
    curv = props.hyperbolic_curvature
    parts = []

    profile = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); profile.location = (base_x, -500); color_node(profile, "hyperbolic")
    profile.mode = 'RADIUS'
    profile.inputs['Resolution'].default_value = 6
    profile.inputs['Radius'].default_value = 0.04

    # Concentric rings — each smaller and lifted (Poincaré projection: tiles shrink toward boundary)
    for ring_i in range(n_rings):
        # Hyperbolic distance: r_i = R * (1 - 1/(1 + i*curv*0.5))
        # When curv=0: linear spacing R*i/n_rings. When curv=1: tighter near edge.
        t = (ring_i + 1) / n_rings
        r = R * t
        # If curv is high, push radii out toward R
        r = r * (1 - curv) + (R * (1 - 0.5 * (1 - t) ** 2)) * curv

        ring = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); ring.location = (base_x, ring_i * 200); color_node(ring, "hyperbolic")
        ring.mode = 'RADIUS'
        ring.inputs['Resolution'].default_value = max(16, n_spokes * 2)
        ring.inputs['Radius'].default_value = r

        # Lift by Poincaré projection (z = R * curv * (1 - sqrt(1 - (r/R)^2)))
        # This gives a lens-like dome shape when curv > 0
        z = R * curv * (1 - math.sqrt(max(0.0, 1 - (r/R)**2)))
        rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+250, ring_i * 200); color_node(rt, "hyperbolic")
        rt.inputs['Translation'].default_value = (0, 0, z)
        rt.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
        tree.links.new(ring.outputs['Curve'], rt.inputs['Geometry'])

        sw = tree.nodes.new('GeometryNodeCurveToMesh'); sw.location = (base_x+500, ring_i * 200)
        tree.links.new(rt.outputs['Geometry'], sw.inputs['Curve'])
        tree.links.new(profile.outputs['Curve'], sw.inputs['Profile Curve'])
        parts.append(sw.outputs['Mesh'])

    # Radial spokes — pieces from center to outer ring
    for spoke_i in range(n_spokes):
        ang = (spoke_i / n_spokes) * math.tau
        # Build a thin cylinder spoke from center to radius R
        spoke = tree.nodes.new('GeometryNodeMeshCylinder'); spoke.location = (base_x, (n_rings + spoke_i // 2) * 200); color_node(spoke, "hyperbolic")
        spoke.inputs['Vertices'].default_value = 6
        spoke.inputs['Radius'].default_value = 0.025
        spoke.inputs['Depth'].default_value = R

        st = tree.nodes.new('GeometryNodeTransform'); st.location = (base_x+250, (n_rings + spoke_i // 2) * 200)
        # Position spoke so one end is at center, other end at edge
        st.inputs['Translation'].default_value = (math.cos(ang) * R/2, math.sin(ang) * R/2, 0)
        # Rotate to lie along radial direction (default cylinder is along Z)
        st.inputs['Rotation'].default_value = (0, math.radians(90), ang)
        tree.links.new(spoke.outputs['Mesh'], st.inputs['Geometry'])
        parts.append(st.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# LEVEL DESIGN / GREYBOX BUILDERS — all snap to props.unit_size grid
# ----------------------------------------------------------------------

def _wall_baseboard_and_cornice(tree, props, length, base_x):
    """Helper: thin baseboard at floor + crown cornice at ceiling. Returns list of geometry sockets."""
    parts = []
    H = props.wall_height
    T = props.wall_thickness
    if props.wall_with_baseboard:
        bb = tree.nodes.new('GeometryNodeMeshCube'); bb.location = (base_x, 200); color_node(bb, "wall")
        bb.inputs['Size'].default_value = (length, T * 1.2, 0.12)
        bb_t = tree.nodes.new('GeometryNodeTransform'); bb_t.location = (base_x+200, 200)
        bb_t.inputs['Translation'].default_value = (0, 0, 0.06)
        tree.links.new(bb.outputs['Mesh'], bb_t.inputs['Geometry'])
        parts.append(bb_t.outputs['Geometry'])
    if props.wall_with_cornice:
        cv = tree.nodes.new('GeometryNodeMeshCube'); cv.location = (base_x, 400); color_node(cv, "wall")
        cv.inputs['Size'].default_value = (length, T * 1.4, 0.18)
        cv_t = tree.nodes.new('GeometryNodeTransform'); cv_t.location = (base_x+200, 400)
        cv_t.inputs['Translation'].default_value = (0, 0, H - 0.09)
        tree.links.new(cv.outputs['Mesh'], cv_t.inputs['Geometry'])
        parts.append(cv_t.outputs['Geometry'])
    return parts


def build_wall_straight(tree, props, base_x=-1400):
    """Standard wall segment — width = wall_segments × unit_size, height = wall_height."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness

    # Main wall slab
    slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, 0); color_node(slab, "wall")
    slab.inputs['Size'].default_value = (L, T, H)
    slab_t = tree.nodes.new('GeometryNodeTransform'); slab_t.location = (base_x+200, 0)
    slab_t.inputs['Translation'].default_value = (0, 0, H/2)
    tree.links.new(slab.outputs['Mesh'], slab_t.inputs['Geometry'])

    parts = [slab_t.outputs['Geometry']]
    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_wall_corner(tree, props, base_x=-1400):
    """L-shaped corner wall — two slabs meeting at 90°."""
    L = props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    parts = []

    # Wall A: along +X
    a = tree.nodes.new('GeometryNodeMeshCube'); a.location = (base_x, 0); color_node(a, "wall")
    a.inputs['Size'].default_value = (L, T, H)
    a_t = tree.nodes.new('GeometryNodeTransform'); a_t.location = (base_x+200, 0)
    a_t.inputs['Translation'].default_value = (L/2, 0, H/2)
    tree.links.new(a.outputs['Mesh'], a_t.inputs['Geometry'])
    parts.append(a_t.outputs['Geometry'])

    # Wall B: along +Y
    b = tree.nodes.new('GeometryNodeMeshCube'); b.location = (base_x, 300); color_node(b, "wall")
    b.inputs['Size'].default_value = (T, L, H)
    b_t = tree.nodes.new('GeometryNodeTransform'); b_t.location = (base_x+200, 300)
    b_t.inputs['Translation'].default_value = (0, L/2, H/2)
    tree.links.new(b.outputs['Mesh'], b_t.inputs['Geometry'])
    parts.append(b_t.outputs['Geometry'])

    # Corner column where they meet (decorative)
    if props.wall_with_cornice:
        cp = tree.nodes.new('GeometryNodeMeshCube'); cp.location = (base_x, 600); color_node(cp, "wall")
        cp.inputs['Size'].default_value = (T * 1.5, T * 1.5, H)
        cp_t = tree.nodes.new('GeometryNodeTransform'); cp_t.location = (base_x+200, 600)
        cp_t.inputs['Translation'].default_value = (0, 0, H/2)
        tree.links.new(cp.outputs['Mesh'], cp_t.inputs['Geometry'])
        parts.append(cp_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_wall_with_door(tree, props, base_x=-1400):
    """Wall with a door-shaped opening — built as 4 segments (left, top header, right, [no bottom])."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    DW = min(props.wall_door_width, L * 0.7)
    DH = min(props.wall_door_height, H * 0.85)

    # Left jamb wall: from -L/2 to -DW/2
    side_w = (L - DW) / 2
    parts = []
    for x_off in (-(L - side_w)/2, +(L - side_w)/2):
        slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, len(parts) * 200); color_node(slab, "wall")
        slab.inputs['Size'].default_value = (side_w, T, H)
        s_t = tree.nodes.new('GeometryNodeTransform'); s_t.location = (base_x+200, len(parts) * 200)
        s_t.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(slab.outputs['Mesh'], s_t.inputs['Geometry'])
        parts.append(s_t.outputs['Geometry'])

    # Header above the door
    header_h = H - DH
    header = tree.nodes.new('GeometryNodeMeshCube'); header.location = (base_x, 600); color_node(header, "wall")
    header.inputs['Size'].default_value = (DW, T, header_h)
    h_t = tree.nodes.new('GeometryNodeTransform'); h_t.location = (base_x+200, 600)
    h_t.inputs['Translation'].default_value = (0, 0, DH + header_h/2)
    tree.links.new(header.outputs['Mesh'], h_t.inputs['Geometry'])
    parts.append(h_t.outputs['Geometry'])

    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_wall_with_window(tree, props, base_x=-1400):
    """Wall with rectangular window opening (5 segments: L, R, top, bottom-sill, [no center])."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    WW = min(props.wall_window_width, L * 0.6)
    WH = min(props.wall_window_height, H * 0.6)
    sill = props.wall_window_sill
    parts = []

    side_w = (L - WW) / 2
    for x_off in (-(L - side_w)/2, +(L - side_w)/2):
        slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, len(parts) * 200); color_node(slab, "wall")
        slab.inputs['Size'].default_value = (side_w, T, H)
        s_t = tree.nodes.new('GeometryNodeTransform'); s_t.location = (base_x+200, len(parts) * 200)
        s_t.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(slab.outputs['Mesh'], s_t.inputs['Geometry'])
        parts.append(s_t.outputs['Geometry'])

    # Sill (below window)
    sill_h = sill
    if sill_h > 0.01:
        sill_block = tree.nodes.new('GeometryNodeMeshCube'); sill_block.location = (base_x, 500); color_node(sill_block, "wall")
        sill_block.inputs['Size'].default_value = (WW, T, sill_h)
        sb_t = tree.nodes.new('GeometryNodeTransform'); sb_t.location = (base_x+200, 500)
        sb_t.inputs['Translation'].default_value = (0, 0, sill_h/2)
        tree.links.new(sill_block.outputs['Mesh'], sb_t.inputs['Geometry'])
        parts.append(sb_t.outputs['Geometry'])

    # Header (above window)
    header_h = H - sill - WH
    if header_h > 0.01:
        head = tree.nodes.new('GeometryNodeMeshCube'); head.location = (base_x, 700); color_node(head, "wall")
        head.inputs['Size'].default_value = (WW, T, header_h)
        head_t = tree.nodes.new('GeometryNodeTransform'); head_t.location = (base_x+200, 700)
        head_t.inputs['Translation'].default_value = (0, 0, sill + WH + header_h/2)
        tree.links.new(head.outputs['Mesh'], head_t.inputs['Geometry'])
        parts.append(head_t.outputs['Geometry'])

    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_ceiling_tile(tree, props, base_x=-1400):
    """Ceiling tile — matches floor unit. Optional decorative coffer pattern."""
    L = props.unit_size
    parts = []

    slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, 0); color_node(slab, "ceiling")
    slab.inputs['Size'].default_value = (L, L, 0.1)
    parts.append(slab.outputs['Mesh'])

    # Coffer (decorative inset square)
    coffer = tree.nodes.new('GeometryNodeMeshCube'); coffer.location = (base_x, 200); color_node(coffer, "ceiling")
    coffer.inputs['Size'].default_value = (L * 0.7, L * 0.7, 0.04)
    c_t = tree.nodes.new('GeometryNodeTransform'); c_t.location = (base_x+200, 200)
    c_t.inputs['Translation'].default_value = (0, 0, -0.07)
    tree.links.new(coffer.outputs['Mesh'], c_t.inputs['Geometry'])
    parts.append(c_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_corner_pillar(tree, props, base_x=-1400):
    """Decorative corner column — base + fluted shaft + capital. Snaps to wall corners."""
    H = props.wall_height
    R = props.wall_thickness * 1.2
    parts = []

    # Square base
    base = tree.nodes.new('GeometryNodeMeshCube'); base.location = (base_x, 0); color_node(base, "wall")
    base.inputs['Size'].default_value = (R * 1.6, R * 1.6, 0.18)
    b_t = tree.nodes.new('GeometryNodeTransform'); b_t.location = (base_x+200, 0)
    b_t.inputs['Translation'].default_value = (0, 0, 0.09)
    tree.links.new(base.outputs['Mesh'], b_t.inputs['Geometry'])
    parts.append(b_t.outputs['Geometry'])

    # Fluted shaft (use saved pillar logic)
    saved = (props.pillar_radius, props.pillar_height, props.pillar_flutes,
             props.pillar_capital_size, props.pillar_capital_layers)
    props.pillar_radius = R
    props.pillar_height = H - 0.4
    props.pillar_flutes = 12
    props.pillar_capital_size = R * 1.6
    props.pillar_capital_layers = 2
    shaft = build_pillar(tree, props, base_x=base_x+500)
    props.pillar_radius, props.pillar_height, props.pillar_flutes, props.pillar_capital_size, props.pillar_capital_layers = saved

    sh_t = tree.nodes.new('GeometryNodeTransform'); sh_t.location = (base_x+2200, 0); color_node(sh_t, "wall")
    sh_t.inputs['Translation'].default_value = (0, 0, H/2)
    tree.links.new(shaft, sh_t.inputs['Geometry'])
    parts.append(sh_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# CASCADING BEAMS (Erindale-inspired) — N parallel beams with per-step offsets
# ----------------------------------------------------------------------

def build_cascading_beams(tree, props, base_x=-1400):
    """
    Erindale-style cascading beams: a line of points with per-index transforms.
    Each beam is offset Z (Escher staircase), X (perspective slip), and twisted.
    """
    n = props.beams_count
    L = props.beams_length
    T = props.beams_thickness
    sp = props.beams_spacing

    # Line of N points along Y axis
    line = tree.nodes.new('GeometryNodeMeshLine'); line.location = (base_x, 0); color_node(line, "beams")
    line.mode = 'OFFSET'
    line.inputs['Count'].default_value = n
    line.inputs['Start Location'].default_value = (0, -sp * (n - 1) / 2, 0)
    line.inputs['Offset'].default_value = (0, sp, 0)

    # Beam prototype — long thin cube
    beam = tree.nodes.new('GeometryNodeMeshCube'); beam.location = (base_x, 200); color_node(beam, "beams")
    beam.inputs['Size'].default_value = (L, T, T)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+300, 0); color_node(inst, "beams")
    tree.links.new(line.outputs['Mesh'], inst.inputs['Points'])
    tree.links.new(beam.outputs['Mesh'], inst.inputs['Instance'])

    # Per-beam Z + X cascade using Index → Translate Instances
    idx = tree.nodes.new('GeometryNodeInputIndex'); idx.location = (base_x, 400)
    z_step = tree.nodes.new('ShaderNodeMath'); z_step.location = (base_x+200, 400); z_step.operation = 'MULTIPLY'
    z_step.inputs[1].default_value = -props.beams_z_cascade  # downward cascade
    tree.links.new(idx.outputs['Index'], z_step.inputs[0])
    x_step = tree.nodes.new('ShaderNodeMath'); x_step.location = (base_x+200, 600); x_step.operation = 'MULTIPLY'
    x_step.inputs[1].default_value = props.beams_x_cascade
    tree.links.new(idx.outputs['Index'], x_step.inputs[0])

    ovec = tree.nodes.new('ShaderNodeCombineXYZ'); ovec.location = (base_x+450, 500); color_node(ovec, "beams")
    tree.links.new(x_step.outputs[0], ovec.inputs['X'])
    ovec.inputs['Y'].default_value = 0
    tree.links.new(z_step.outputs[0], ovec.inputs['Z'])

    ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+700, 0); color_node(ti, "beams")
    tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])
    tree.links.new(ovec.outputs['Vector'], ti.inputs['Translation'])

    # Per-beam twist (rotation around X) — accumulates per index
    if abs(props.beams_twist) > 0.001:
        rot_step = tree.nodes.new('ShaderNodeMath'); rot_step.location = (base_x+200, 800); rot_step.operation = 'MULTIPLY'
        rot_step.inputs[1].default_value = props.beams_twist
        tree.links.new(idx.outputs['Index'], rot_step.inputs[0])
        rvec = tree.nodes.new('ShaderNodeCombineXYZ'); rvec.location = (base_x+450, 800); color_node(rvec, "beams")
        tree.links.new(rot_step.outputs[0], rvec.inputs['X'])
        rvec.inputs['Y'].default_value = 0
        rvec.inputs['Z'].default_value = 0
        ri = tree.nodes.new('GeometryNodeRotateInstances'); ri.location = (base_x+900, 0)
        tree.links.new(ti.outputs['Instances'], ri.inputs['Instances'])
        tree.links.new(rvec.outputs['Vector'], ri.inputs['Rotation'])
        out_inst = ri.outputs['Instances']
    else:
        out_inst = ti.outputs['Instances']

    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+1200, 0); color_node(realize, "output")
    tree.links.new(out_inst, realize.inputs['Geometry'])
    return realize.outputs['Geometry']


# ----------------------------------------------------------------------
# MODULAR HOUSE — composite (4 walls + roof + door + windows on a unit grid)
# ----------------------------------------------------------------------

def build_modular_house(tree, props, base_x=-1400):
    """Composite house — uses unit_size grid. 4 walls (front has door, sides have windows), pitched roof, optional chimney."""
    U = props.unit_size
    Wx = props.house_units_x * U
    Wy = props.house_units_y * U
    H_per_floor = props.wall_height
    floors = props.house_floors
    total_h = floors * H_per_floor
    parts = []

    # Save and override wall properties for each face
    saved = (props.wall_segments, props.wall_door_width, props.wall_door_height,
             props.wall_window_width, props.wall_window_height, props.wall_height)

    for floor in range(floors):
        z_floor = floor * H_per_floor

        # FRONT (-Y face) — has door if floor 0
        props.wall_segments = props.house_units_x
        props.wall_height = H_per_floor
        if floor == 0 and props.house_with_door:
            front_geom = build_wall_with_door(tree, props, base_x=base_x + (1500 if floor == 0 else 0))
        else:
            front_geom = build_wall_straight(tree, props, base_x=base_x + 3000 + floor * 1500)
        ft = tree.nodes.new('GeometryNodeTransform'); ft.location = (base_x+5000, floor * 200); color_node(ft, "house")
        ft.inputs['Translation'].default_value = (0, -Wy/2, z_floor)
        tree.links.new(front_geom, ft.inputs['Geometry'])
        parts.append(ft.outputs['Geometry'])

        # BACK (+Y face) — plain
        back_geom = build_wall_straight(tree, props, base_x=base_x + 6000 + floor * 1500)
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+8000, floor * 200); color_node(bt, "house")
        bt.inputs['Translation'].default_value = (0, Wy/2, z_floor)
        bt.inputs['Rotation'].default_value = (0, 0, math.radians(180))
        tree.links.new(back_geom, bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

        # LEFT (-X face) — windows on upper floors
        props.wall_segments = props.house_units_y
        if floor > 0 and props.house_with_windows:
            left_geom = build_wall_with_window(tree, props, base_x=base_x + 9000 + floor * 1500)
        else:
            left_geom = build_wall_straight(tree, props, base_x=base_x + 11000 + floor * 1500)
        lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x+13000, floor * 200); color_node(lt, "house")
        lt.inputs['Translation'].default_value = (-Wx/2, 0, z_floor)
        lt.inputs['Rotation'].default_value = (0, 0, math.radians(90))
        tree.links.new(left_geom, lt.inputs['Geometry'])
        parts.append(lt.outputs['Geometry'])

        # RIGHT (+X face) — windows on upper floors
        if floor > 0 and props.house_with_windows:
            right_geom = build_wall_with_window(tree, props, base_x=base_x + 14000 + floor * 1500)
        else:
            right_geom = build_wall_straight(tree, props, base_x=base_x + 16000 + floor * 1500)
        rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+18000, floor * 200); color_node(rt, "house")
        rt.inputs['Translation'].default_value = (Wx/2, 0, z_floor)
        rt.inputs['Rotation'].default_value = (0, 0, math.radians(-90))
        tree.links.new(right_geom, rt.inputs['Geometry'])
        parts.append(rt.outputs['Geometry'])

    # Restore wall props
    (props.wall_segments, props.wall_door_width, props.wall_door_height,
     props.wall_window_width, props.wall_window_height, props.wall_height) = saved

    # Roof
    if props.house_with_roof:
        # Pitched roof — two angled cubes meeting at a ridge
        roof_pitch = math.radians(35)
        roof_h = (Wy / 2) * math.tan(roof_pitch)
        slope_len = (Wy / 2) / math.cos(roof_pitch)
        for sign in (-1, 1):
            slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x+19000, 200 + sign * 100); color_node(slab, "house")
            slab.inputs['Size'].default_value = (Wx, slope_len, 0.15)
            st = tree.nodes.new('GeometryNodeTransform'); st.location = (base_x+19500, 200 + sign * 100)
            st.inputs['Translation'].default_value = (0, sign * Wy/4, total_h + roof_h/2)
            # NEGATIVE pitch so eaves drop OUTWARD from ridge (apex on top).
            # Previously this was `sign * roof_pitch` which inverted the roof.
            st.inputs['Rotation'].default_value = (sign * -roof_pitch, 0, 0)
            tree.links.new(slab.outputs['Mesh'], st.inputs['Geometry'])
            parts.append(st.outputs['Geometry'])

    # Chimney
    if props.house_with_chimney:
        ch = tree.nodes.new('GeometryNodeMeshCube'); ch.location = (base_x+19000, 600); color_node(ch, "house")
        ch.inputs['Size'].default_value = (0.6, 0.6, 1.5)
        ch_t = tree.nodes.new('GeometryNodeTransform'); ch_t.location = (base_x+19500, 600)
        ch_t.inputs['Translation'].default_value = (Wx/3, Wy/4, total_h + 1.0)
        tree.links.new(ch.outputs['Mesh'], ch_t.inputs['Geometry'])
        parts.append(ch_t.outputs['Geometry'])

    # Floor slab at base
    floor_slab = tree.nodes.new('GeometryNodeMeshCube'); floor_slab.location = (base_x+19000, -200); color_node(floor_slab, "house")
    floor_slab.inputs['Size'].default_value = (Wx, Wy, 0.15)
    fs_t = tree.nodes.new('GeometryNodeTransform'); fs_t.location = (base_x+19500, -200)
    fs_t.inputs['Translation'].default_value = (0, 0, -0.075)
    tree.links.new(floor_slab.outputs['Mesh'], fs_t.inputs['Geometry'])
    parts.append(fs_t.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+20000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# CURVED BUILDING — palazzo facade following an arc
# ----------------------------------------------------------------------

def build_curved_building(tree, props, base_x=-1400):
    """Palazzo facade bent along an arc — instances arches around the curve."""
    R = props.curved_radius
    sweep = math.radians(props.curved_arc_deg)
    floors = props.curved_floors
    arches_per_unit = props.curved_arches_per_unit
    floor_h = props.wall_height

    # Total arches = arches_per_unit × ceil(arc_length / unit_size)
    arc_length = R * sweep
    total_arches = max(1, int(arc_length / props.unit_size * arches_per_unit))
    parts = []

    # Build arc curve
    arc = tree.nodes.new('GeometryNodeCurveArc'); arc.location = (base_x, 0); color_node(arc, "level")
    arc.mode = 'RADIUS'
    arc.inputs['Resolution'].default_value = total_arches
    arc.inputs['Radius'].default_value = R
    arc.inputs['Start Angle'].default_value = -sweep / 2
    arc.inputs['Sweep Angle'].default_value = sweep

    # Sample arc points (one per arch position)
    samp = tree.nodes.new('GeometryNodeResampleCurve'); samp.location = (base_x+200, 0); color_node(samp, "level")
    samp.inputs['Mode'].default_value = 'Count'
    samp.inputs['Count'].default_value = total_arches
    tree.links.new(arc.outputs['Curve'], samp.inputs['Curve'])

    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+450, 0); color_node(c2p, "level")
    c2p.mode = 'EVALUATED'
    tree.links.new(samp.outputs['Curve'], c2p.inputs['Curve'])

    # Per-floor: build an ogee arch piece, instance along the arc
    saved = (props.ogee_width, props.ogee_height, props.ogee_finial)
    for floor in range(floors):
        # Size arch to fit one segment
        arch_w = (arc_length / total_arches) * 0.85
        props.ogee_width  = arch_w
        props.ogee_height = floor_h * 0.85
        props.ogee_finial = 0.0
        arch_geom = build_ogee_arch(tree, props, base_x=base_x + 1500 + floor * 4500)

        # Position the arch at z = floor * floor_h, tangent to the arc
        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+5000, floor * 300); color_node(inst, "level")
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(arch_geom, inst.inputs['Instance'])
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

        ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+5300, floor * 300)
        ti.inputs['Translation'].default_value = (0, 0, floor * floor_h)
        tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])

        rl = tree.nodes.new('GeometryNodeRealizeInstances'); rl.location = (base_x+5600, floor * 300)
        tree.links.new(ti.outputs['Instances'], rl.inputs['Geometry'])
        parts.append(rl.outputs['Geometry'])
    props.ogee_width, props.ogee_height, props.ogee_finial = saved

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+6000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# RADIAL BUILDING — round palazzo (arches around a center axis)
# ----------------------------------------------------------------------

def build_radial_building(tree, props, base_x=-1400):
    """Round palazzo — N arches arrayed around a circle of given radius, optional crowning dome."""
    R = props.radial_building_radius
    floors = props.radial_building_floors
    n = props.radial_building_arches
    floor_h = props.wall_height
    parts = []

    # Sample points on a circle
    circ = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); circ.location = (base_x, 0); color_node(circ, "level")
    circ.mode = 'RADIUS'
    circ.inputs['Resolution'].default_value = n
    circ.inputs['Radius'].default_value = R

    c2p = tree.nodes.new('GeometryNodeCurveToPoints'); c2p.location = (base_x+250, 0); color_node(c2p, "level")
    c2p.mode = 'EVALUATED'
    tree.links.new(circ.outputs['Curve'], c2p.inputs['Curve'])

    saved = (props.ogee_width, props.ogee_height, props.ogee_finial)
    arch_w = (math.tau * R / n) * 0.85
    for floor in range(floors):
        props.ogee_width = arch_w
        props.ogee_height = floor_h * 0.85
        props.ogee_finial = 0.0
        arch_geom = build_ogee_arch(tree, props, base_x=base_x + 1500 + floor * 4500)

        inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+5000, floor * 300); color_node(inst, "level")
        tree.links.new(c2p.outputs['Points'], inst.inputs['Points'])
        tree.links.new(arch_geom, inst.inputs['Instance'])
        tree.links.new(c2p.outputs['Rotation'], inst.inputs['Rotation'])

        ti = tree.nodes.new('GeometryNodeTranslateInstances'); ti.location = (base_x+5300, floor * 300)
        ti.inputs['Translation'].default_value = (0, 0, floor * floor_h)
        tree.links.new(inst.outputs['Instances'], ti.inputs['Instances'])

        rl = tree.nodes.new('GeometryNodeRealizeInstances'); rl.location = (base_x+5600, floor * 300)
        tree.links.new(ti.outputs['Instances'], rl.inputs['Geometry'])
        parts.append(rl.outputs['Geometry'])
    props.ogee_width, props.ogee_height, props.ogee_finial = saved

    # Crowning dome on top
    if props.radial_building_dome:
        saved_d = (props.dome_radius, props.dome_spire)
        props.dome_radius = R + 0.2
        props.dome_spire = 0.5
        dome_geom = build_dome(tree, props, base_x=base_x + 8000)
        props.dome_radius, props.dome_spire = saved_d
        dt = tree.nodes.new('GeometryNodeTransform'); dt.location = (base_x+11000, 600); color_node(dt, "level")
        dt.inputs['Translation'].default_value = (0, 0, floors * floor_h)
        tree.links.new(dome_geom, dt.inputs['Geometry'])
        parts.append(dt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+12000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# TOPOLOGY CLEANUP — game-engine friendly final pass
# Adds: Merge by Distance + Recalc Normals + Smooth-by-Angle (Blender 5.0+ approach)
# ----------------------------------------------------------------------

def add_auto_align_pass(tree, in_geom, mode, x=14400):
    """
    Auto-align geometry to a consistent origin convention.
    Uses GeometryNodeBoundBox to compute an offset and applies it via Set Position.
      • GROUND: center X=Y=0, zmin=0 (sit on the ground — best for level design)
      • CENTER: center X=Y=Z=0 (decorative pieces, radial instances)
    Returns the aligned geometry socket.
    """
    if mode == 'NONE':
        return in_geom

    bbox = tree.nodes.new('GeometryNodeBoundBox'); bbox.location = (x, 200); color_node(bbox, "cleanup")
    tree.links.new(in_geom, bbox.inputs['Geometry'])

    # Min + Max → vector
    add_mm = tree.nodes.new('ShaderNodeVectorMath'); add_mm.location = (x+200, 200); add_mm.operation = 'ADD'
    tree.links.new(bbox.outputs['Min'], add_mm.inputs[0])
    tree.links.new(bbox.outputs['Max'], add_mm.inputs[1])

    # Half → -(min+max)/2 (this is the negative of the bbox center)
    half = tree.nodes.new('ShaderNodeVectorMath'); half.location = (x+400, 200); half.operation = 'SCALE'
    half.inputs['Scale'].default_value = -0.5
    tree.links.new(add_mm.outputs[0], half.inputs[0])

    if mode == 'CENTER':
        # Use full negated center for X, Y, AND Z
        offset = half.outputs[0]
    else:  # GROUND
        # X, Y from negated center; Z from -bbox.min.z (so zmin becomes 0)
        sep_min = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_min.location = (x+200, -100); color_node(sep_min, "cleanup")
        tree.links.new(bbox.outputs['Min'], sep_min.inputs['Vector'])

        neg_zmin = tree.nodes.new('ShaderNodeMath'); neg_zmin.location = (x+400, -100); neg_zmin.operation = 'MULTIPLY'
        neg_zmin.inputs[1].default_value = -1.0
        tree.links.new(sep_min.outputs['Z'], neg_zmin.inputs[0])

        sep_half = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_half.location = (x+600, 200); color_node(sep_half, "cleanup")
        tree.links.new(half.outputs[0], sep_half.inputs['Vector'])

        final_offset = tree.nodes.new('ShaderNodeCombineXYZ'); final_offset.location = (x+800, 100); color_node(final_offset, "cleanup")
        tree.links.new(sep_half.outputs['X'], final_offset.inputs['X'])
        tree.links.new(sep_half.outputs['Y'], final_offset.inputs['Y'])
        tree.links.new(neg_zmin.outputs[0], final_offset.inputs['Z'])
        offset = final_offset.outputs[0]

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+1000, 0); color_node(set_pos, "cleanup")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(offset, set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']


def add_cleanup_pass(tree, in_geom, props, x=13800):
    """
    Final cleanup for game-engine output.
    Uses edge-angle-based smooth shading (the Blender 5.0+ technique that replaces auto-smooth).
    """
    # Merge by Distance — clean up duplicate verts at seams
    merge = tree.nodes.new('GeometryNodeMergeByDistance'); merge.location = (x, 0); color_node(merge, "cleanup")
    merge.inputs['Distance'].default_value = props.cleanup_merge_distance
    tree.links.new(in_geom, merge.inputs['Geometry'])
    geom = merge.outputs['Geometry']

    # Smooth-by-Angle: select edges sharper than threshold → mark them sharp
    # Then Set Shade Smooth on faces. This is the modern Blender 5.0+ technique.
    edge_angle = tree.nodes.new('GeometryNodeInputMeshEdgeAngle'); edge_angle.location = (x, -300); color_node(edge_angle, "cleanup")

    threshold_rad = math.radians(props.cleanup_smooth_angle)
    cmp = tree.nodes.new('FunctionNodeCompare'); cmp.location = (x+200, -300); color_node(cmp, "cleanup")
    cmp.data_type = 'FLOAT'
    cmp.operation = 'GREATER_THAN'
    cmp.inputs[1].default_value = threshold_rad
    tree.links.new(edge_angle.outputs['Unsigned Angle'], cmp.inputs[0])

    # Set Shade Smooth — face mode, no selection (smooth all faces)
    smooth_face = tree.nodes.new('GeometryNodeSetShadeSmooth'); smooth_face.location = (x+200, 0); color_node(smooth_face, "cleanup")
    smooth_face.domain = 'FACE'
    smooth_face.inputs['Shade Smooth'].default_value = True
    tree.links.new(geom, smooth_face.inputs['Geometry'])
    geom = smooth_face.outputs['Geometry']

    # Set Shade Smooth — edge mode, with the comparison as selection (sharp edges become flat)
    smooth_edge = tree.nodes.new('GeometryNodeSetShadeSmooth'); smooth_edge.location = (x+500, 0); color_node(smooth_edge, "cleanup")
    smooth_edge.domain = 'EDGE'
    smooth_edge.inputs['Shade Smooth'].default_value = False  # sharp where selected
    tree.links.new(geom, smooth_edge.inputs['Geometry'])
    tree.links.new(cmp.outputs['Result'], smooth_edge.inputs['Selection'])
    geom = smooth_edge.outputs['Geometry']

    return geom


def add_procedural_uv_pass(tree, in_geom, props, x=14700):
    """
    Write a UVMap attribute inside the GeoNodes tree (no Apply Modifiers needed).
    TRIPLANAR — normal-weighted blend of YZ / XZ / XY projections (UE tiling).
    BOX       — normalized XZ footprint (good for vertical architecture).
    """
    mode = getattr(props, 'uv_unwrap_mode', 'TRIPLANAR')
    if not getattr(props, 'auto_uv_unwrap', True) or mode not in ('TRIPLANAR', 'BOX'):
        return in_geom

    uv_name = getattr(props, 'uv_map_name', 'UVMap') or 'UVMap'
    uv_scale = max(0.01, getattr(props, 'uv_scale', 1.0))

    bbox = tree.nodes.new('GeometryNodeBoundBox'); bbox.location = (x, 300); color_node(bbox, "cleanup")
    tree.links.new(in_geom, bbox.inputs['Geometry'])

    sep_min = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_min.location = (x + 200, 200); color_node(sep_min, "cleanup")
    sep_max = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_max.location = (x + 200, 400); color_node(sep_max, "cleanup")
    tree.links.new(bbox.outputs['Min'], sep_min.inputs['Vector'])
    tree.links.new(bbox.outputs['Max'], sep_max.inputs['Vector'])

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, 0); color_node(pos, "cleanup")
    sep_p = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_p.location = (x + 200, 0); color_node(sep_p, "cleanup")
    tree.links.new(pos.outputs['Position'], sep_p.inputs['Vector'])

    def _norm_axis(coord_out, min_out, max_out, loc_y):
        sub = tree.nodes.new('ShaderNodeMath'); sub.location = (x + 400, loc_y); sub.operation = 'SUBTRACT'
        tree.links.new(coord_out, sub.inputs[0]); tree.links.new(min_out, sub.inputs[1])
        rng = tree.nodes.new('ShaderNodeMath'); rng.location = (x + 580, loc_y); rng.operation = 'SUBTRACT'
        tree.links.new(max_out, rng.inputs[0]); tree.links.new(min_out, rng.inputs[1])
        div = tree.nodes.new('ShaderNodeMath'); div.location = (x + 760, loc_y); div.operation = 'DIVIDE'
        div.inputs[1].default_value = 1.0
        tree.links.new(sub.outputs[0], div.inputs[0])
        tree.links.new(rng.outputs[0], div.inputs[1])
        return div.outputs[0]

    nu = _norm_axis(sep_p.outputs['X'], sep_min.outputs['X'], sep_max.outputs['X'], 80)
    nv = _norm_axis(sep_p.outputs['Z'], sep_min.outputs['Z'], sep_max.outputs['Z'], -80)

    if mode == 'BOX':
        u_out, v_out = nu, nv
    else:
        nrm = tree.nodes.new('GeometryNodeInputNormal'); nrm.location = (x, -200); color_node(nrm, "cleanup")
        sep_n = tree.nodes.new('ShaderNodeSeparateXYZ'); sep_n.location = (x + 200, -200); color_node(sep_n, "cleanup")
        tree.links.new(nrm.outputs['Normal'], sep_n.inputs['Vector'])
        ax = tree.nodes.new('ShaderNodeMath'); ax.location = (x + 400, -120); ax.operation = 'ABSOLUTE'
        ay = tree.nodes.new('ShaderNodeMath'); ay.location = (x + 400, -220); ay.operation = 'ABSOLUTE'
        az = tree.nodes.new('ShaderNodeMath'); az.location = (x + 400, -320); az.operation = 'ABSOLUTE'
        tree.links.new(sep_n.outputs['X'], ax.inputs[0])
        tree.links.new(sep_n.outputs['Y'], ay.inputs[0])
        tree.links.new(sep_n.outputs['Z'], az.inputs[0])
        wsum = tree.nodes.new('ShaderNodeMath'); wsum.location = (x + 580, -220); wsum.operation = 'ADD'
        tree.links.new(ax.outputs[0], wsum.inputs[0])
        wsum2 = tree.nodes.new('ShaderNodeMath'); wsum2.location = (x + 580, -280); wsum2.operation = 'ADD'
        tree.links.new(wsum.outputs[0], wsum2.inputs[0]); tree.links.new(az.outputs[0], wsum2.inputs[1])
        wx = tree.nodes.new('ShaderNodeMath'); wx.location = (x + 760, -120); wx.operation = 'DIVIDE'
        wy = tree.nodes.new('ShaderNodeMath'); wy.location = (x + 760, -220); wy.operation = 'DIVIDE'
        wz = tree.nodes.new('ShaderNodeMath'); wz.location = (x + 760, -320); wz.operation = 'DIVIDE'
        tree.links.new(ax.outputs[0], wx.inputs[0]); tree.links.new(wsum2.outputs[0], wx.inputs[1])
        tree.links.new(ay.outputs[0], wy.inputs[0]); tree.links.new(wsum2.outputs[0], wy.inputs[1])
        tree.links.new(az.outputs[0], wz.inputs[0]); tree.links.new(wsum2.outputs[0], wz.inputs[1])
        u_yz = _norm_axis(sep_p.outputs['Y'], sep_min.outputs['Y'], sep_max.outputs['Y'], -400)
        v_yz = nv
        u_xz = nu
        v_xz = _norm_axis(sep_p.outputs['Y'], sep_min.outputs['Y'], sep_max.outputs['Y'], -500)
        u_xy = nu
        v_xy = _norm_axis(sep_p.outputs['Y'], sep_min.outputs['Y'], sep_max.outputs['Y'], -600)
        uw = tree.nodes.new('ShaderNodeMath'); uw.location = (x + 940, -80); uw.operation = 'MULTIPLY'
        tree.links.new(u_yz, uw.inputs[0]); tree.links.new(wx.outputs[0], uw.inputs[1])
        uw2 = tree.nodes.new('ShaderNodeMath'); uw2.location = (x + 1120, -80); uw2.operation = 'ADD'
        um = tree.nodes.new('ShaderNodeMath'); um.location = (x + 940, -180); um.operation = 'MULTIPLY'
        tree.links.new(u_xz, um.inputs[0]); tree.links.new(wy.outputs[0], um.inputs[1])
        tree.links.new(uw.outputs[0], uw2.inputs[0]); tree.links.new(um.outputs[0], uw2.inputs[1])
        uw3 = tree.nodes.new('ShaderNodeMath'); uw3.location = (x + 1300, -80); uw3.operation = 'ADD'
        um2 = tree.nodes.new('ShaderNodeMath'); um2.location = (x + 940, -280); um2.operation = 'MULTIPLY'
        tree.links.new(u_xy, um2.inputs[0]); tree.links.new(wz.outputs[0], um2.inputs[1])
        tree.links.new(uw2.outputs[0], uw3.inputs[0]); tree.links.new(um2.outputs[0], uw3.inputs[1])
        vw = tree.nodes.new('ShaderNodeMath'); vw.location = (x + 940, 120); vw.operation = 'MULTIPLY'
        tree.links.new(v_yz, vw.inputs[0]); tree.links.new(wx.outputs[0], vw.inputs[1])
        vw2 = tree.nodes.new('ShaderNodeMath'); vw2.location = (x + 1120, 120); vw2.operation = 'ADD'
        vm = tree.nodes.new('ShaderNodeMath'); vm.location = (x + 940, 20); vm.operation = 'MULTIPLY'
        tree.links.new(v_xz, vm.inputs[0]); tree.links.new(wy.outputs[0], vm.inputs[1])
        tree.links.new(vw.outputs[0], vw2.inputs[0]); tree.links.new(vm.outputs[0], vw2.inputs[1])
        vw3 = tree.nodes.new('ShaderNodeMath'); vw3.location = (x + 1300, 120); vw3.operation = 'ADD'
        vm2 = tree.nodes.new('ShaderNodeMath'); vm2.location = (x + 940, -80); vm2.operation = 'MULTIPLY'
        tree.links.new(v_xy, vm2.inputs[0]); tree.links.new(wz.outputs[0], vm2.inputs[1])
        tree.links.new(vw2.outputs[0], vw3.inputs[0]); tree.links.new(vm2.outputs[0], vw3.inputs[1])
        u_out, v_out = uw3.outputs[0], vw3.outputs[0]

    if abs(uv_scale - 1.0) > 0.001:
        us = tree.nodes.new('ShaderNodeMath'); us.location = (x + 1480, 40); us.operation = 'MULTIPLY'
        us.inputs[1].default_value = uv_scale
        tree.links.new(u_out, us.inputs[0])
        vs = tree.nodes.new('ShaderNodeMath'); vs.location = (x + 1480, -60); vs.operation = 'MULTIPLY'
        vs.inputs[1].default_value = uv_scale
        tree.links.new(v_out, vs.inputs[0])
        u_out, v_out = us.outputs[0], vs.outputs[0]

    uv_vec = tree.nodes.new('ShaderNodeCombineXYZ'); uv_vec.location = (x + 1660, 0); color_node(uv_vec, "cleanup")
    tree.links.new(u_out, uv_vec.inputs['X'])
    tree.links.new(v_out, uv_vec.inputs['Y'])
    uv_vec.inputs['Z'].default_value = 0.0

    store = tree.nodes.new('GeometryNodeStoreNamedAttribute'); store.location = (x + 1840, 0); color_node(store, "cleanup")
    store.domain = 'CORNER'
    try:
        store.data_type = 'FLOAT_VECTOR'
    except Exception:
        try:
            store.data_type = 'FLOAT2'
        except Exception:
            pass
    try:
        store.inputs['Name'].default_value = uv_name
    except Exception:
        pass
    tree.links.new(in_geom, store.inputs['Geometry'])
    tree.links.new(uv_vec.outputs['Vector'], store.inputs['Value'])
    return store.outputs['Geometry']


def apply_smart_uv_unwrap(obj, props, context):
    """Island-based Smart UV Project on mesh data (requires applied/real mesh)."""
    if not getattr(props, 'auto_uv_unwrap', True):
        return False
    if getattr(props, 'uv_unwrap_mode', 'TRIPLANAR') != 'SMART':
        return False
    if obj is None or obj.type != 'MESH':
        return False
    uv_name = getattr(props, 'uv_map_name', 'UVMap') or 'UVMap'
    angle = math.radians(getattr(props, 'uv_angle_limit', 66.0))
    margin = getattr(props, 'uv_island_margin', 0.02)
    prev_mode = obj.mode
    prev_active = context.view_layer.objects.active
    try:
        context.view_layer.objects.active = obj
        if uv_name not in obj.data.uv_layers:
            obj.data.uv_layers.new(name=uv_name)
        obj.data.uv_layers.active = obj.data.uv_layers[uv_name]
        bpy.ops.object.mode_set(mode='EDIT')
        bpy.ops.mesh.select_all(action='SELECT')
        bpy.ops.uv.smart_project(angle_limit=angle, island_margin=margin)
        bpy.ops.object.mode_set(mode='OBJECT')
        return True
    except Exception as e:
        print(f"[SurrealArch] Smart UV failed: {e}")
        try:
            if obj.mode != 'OBJECT':
                bpy.ops.object.mode_set(mode='OBJECT')
        except Exception:
            pass
        return False
    finally:
        context.view_layer.objects.active = prev_active


