def _match_woods_arch(t):
    return t.startswith('GB_WOODS_')


def _match_greybox_arch(t):
    if t.startswith('GB_WOODS_'):
        return False
    return t.startswith('GREYBOX_') or t.startswith('GB_')


def _match_gothic_arch(t):
    return t in GOTHIC_ARCH_TYPES or (isinstance(t, str) and t.startswith('GB_GOTHIC_'))


def _match_civic_arch(t):
    return t in CIVIC_ARCH_TYPES


def _match_castle_arch(t):
    return t in CASTLE_ARCH_TYPES


def _match_asian_arch(t):
    return t in ASIAN_ARCH_TYPES


def _zen_lantern_element_mask(layers, show_kidan, show_ukebana):
    """Return active element keys bottom→top for a tōrō stack."""
    full = ['kidan', 'kiso', 'sao', 'chudai', 'hibukuro', 'kasa', 'ukebana', 'hoju']
    if not show_kidan and 'kidan' in full:
        full.remove('kidan')
    if not show_ukebana and 'ukebana' in full:
        full.remove('ukebana')
    n = max(2, min(8, layers))
    if n >= len(full):
        return full
    # Keep bottom (foundation) + top (finial); trim middle if needed
    if n <= 3:
        return full[:max(1, n - 1)] + ['hoju']
    return full[:n]


def _curved_roof(tree, loc, size_x, size_y, ridge_h, base_z=0.0,
                 pitch=1.6, hip=True, eave_flip=0.16, thickness=-0.1,
                 label="roof", res=24):
    """Reusable East-Asian curved roof built from a deformed Grid.

    hip=True  → 4-way hip/pyramid roof (square level-sets, Chebyshev),
                tips sweep up uniformly (Japanese/Chinese irimoya feel).
    hip=False → gable roof: ridge runs along X, slopes fall off in Y,
                the four corners flip up (Korean cheoma / Chinese pailou).

    The (1-n)^pitch profile is concave when pitch>1 so the eaves sweep.
    Returns a geometry output socket (extruded shell with `thickness`).
    """
    bx, by = loc
    half_x = size_x / 2.0
    half_y = size_y / 2.0
    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (bx, by); color_node(grid, label)
    grid.inputs['Size X'].default_value = size_x
    grid.inputs['Size Y'].default_value = size_y
    grid.inputs['Vertices X'].default_value = res
    grid.inputs['Vertices Y'].default_value = res
    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (bx, by + 250)
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (bx + 180, by + 250)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])
    axn = tree.nodes.new('ShaderNodeMath'); axn.location = (bx + 360, by + 320); axn.operation = 'ABSOLUTE'
    tree.links.new(sep.outputs['X'], axn.inputs[0])
    ayn = tree.nodes.new('ShaderNodeMath'); ayn.location = (bx + 360, by + 200); ayn.operation = 'ABSOLUTE'
    tree.links.new(sep.outputs['Y'], ayn.inputs[0])
    # normalized x,y in [0..1]
    nxd = tree.nodes.new('ShaderNodeMath'); nxd.location = (bx + 540, by + 320); nxd.operation = 'DIVIDE'
    nxd.inputs[1].default_value = max(0.001, half_x); tree.links.new(axn.outputs[0], nxd.inputs[0])
    nyd = tree.nodes.new('ShaderNodeMath'); nyd.location = (bx + 540, by + 200); nyd.operation = 'DIVIDE'
    nyd.inputs[1].default_value = max(0.001, half_y); tree.links.new(ayn.outputs[0], nyd.inputs[0])
    if hip:
        m = tree.nodes.new('ShaderNodeMath'); m.location = (bx + 720, by + 260); m.operation = 'MAXIMUM'
        tree.links.new(nxd.outputs[0], m.inputs[0]); tree.links.new(nyd.outputs[0], m.inputs[1])
        m_out = m.outputs[0]
    else:
        m_out = nyd.outputs[0]   # gable falls off in Y only
    inv = tree.nodes.new('ShaderNodeMath'); inv.location = (bx + 900, by + 320); inv.operation = 'SUBTRACT'
    inv.inputs[0].default_value = 1.0; tree.links.new(m_out, inv.inputs[1])
    powr = tree.nodes.new('ShaderNodeMath'); powr.location = (bx + 1080, by + 320); powr.operation = 'POWER'
    powr.inputs[1].default_value = max(0.4, pitch); tree.links.new(inv.outputs[0], powr.inputs[0])
    zmul = tree.nodes.new('ShaderNodeMath'); zmul.location = (bx + 1260, by + 320); zmul.operation = 'MULTIPLY'
    zmul.inputs[1].default_value = ridge_h; tree.links.new(powr.outputs[0], zmul.inputs[0])
    # corner / eave upturn
    if hip:
        ef = tree.nodes.new('ShaderNodeMath'); ef.location = (bx + 900, by + 140); ef.operation = 'POWER'
        ef.inputs[1].default_value = 6.0; tree.links.new(m_out, ef.inputs[0])
        flip_src = ef.outputs[0]
    else:
        exp = tree.nodes.new('ShaderNodeMath'); exp.location = (bx + 720, by + 60); exp.operation = 'POWER'
        exp.inputs[1].default_value = 5.0; tree.links.new(nxd.outputs[0], exp.inputs[0])
        eyp = tree.nodes.new('ShaderNodeMath'); eyp.location = (bx + 720, by - 60); eyp.operation = 'POWER'
        eyp.inputs[1].default_value = 4.0; tree.links.new(nyd.outputs[0], eyp.inputs[0])
        cm = tree.nodes.new('ShaderNodeMath'); cm.location = (bx + 900, by + 0); cm.operation = 'MULTIPLY'
        tree.links.new(exp.outputs[0], cm.inputs[0]); tree.links.new(eyp.outputs[0], cm.inputs[1])
        flip_src = cm.outputs[0]
    eamp = tree.nodes.new('ShaderNodeMath'); eamp.location = (bx + 1080, by + 140); eamp.operation = 'MULTIPLY'
    eamp.inputs[1].default_value = ridge_h * eave_flip; tree.links.new(flip_src, eamp.inputs[0])
    zsum = tree.nodes.new('ShaderNodeMath'); zsum.location = (bx + 1440, by + 260); zsum.operation = 'ADD'
    tree.links.new(zmul.outputs[0], zsum.inputs[0]); tree.links.new(eamp.outputs[0], zsum.inputs[1])
    zvec = tree.nodes.new('ShaderNodeCombineXYZ'); zvec.location = (bx + 1620, by + 260)
    tree.links.new(zsum.outputs[0], zvec.inputs['Z'])
    setp = tree.nodes.new('GeometryNodeSetPosition'); setp.location = (bx + 1800, by); color_node(setp, label)
    tree.links.new(grid.outputs['Mesh'], setp.inputs['Geometry'])
    tree.links.new(zvec.outputs['Vector'], setp.inputs['Offset'])
    out = setp.outputs['Geometry']
    if thickness:
        ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (bx + 1980, by))
        if ext:
            ext.mode = 'FACES'
            try: ext.inputs['Offset Scale'].default_value = thickness
            except Exception: pass
            tree.links.new(setp.outputs['Geometry'], ext.inputs['Mesh'])
            out = ext.outputs['Mesh']
    if base_z:
        tr = tree.nodes.new('GeometryNodeTransform'); tr.location = (bx + 2160, by)
        tr.inputs['Translation'].default_value = (0, 0, base_z)
        tree.links.new(out, tr.inputs['Geometry'])
        out = tr.outputs['Geometry']
    return out


def build_zen_pagoda(tree, props, base_x=-1400):
    """Multi-tier pagoda following Japanese pagoda principles:
       • Each tier ~85% of the previous (yon-juu = 4-tier rule)
       • Overhanging eaves on each tier (deep noki)
       • Curved Bezier roof beams for kibana (corner upturn)
       • Crowning sōrin (ringed spire) of 9 rings.
    """
    tiers = props.pagoda_tiers
    R = props.pagoda_base_radius
    th = props.pagoda_tier_height
    overhang = props.pagoda_roof_overhang
    taper = props.pagoda_taper
    kurin_n = max(0, min(13, getattr(props, 'pagoda_sorin_rings', 9)))
    show_mokoshi = getattr(props, 'pagoda_show_mokoshi', False)
    show_shinbashira = getattr(props, 'pagoda_show_shinbashira', True)
    parts = []
    cur_R = R
    cur_z = 0

    # Mokoshi (裳階) — decorative skirt story at pagoda base
    if show_mokoshi:
        mok_r = R * 1.35
        mok_circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 200, -200))
        if mok_circ:
            try:
                mok_circ.inputs['Resolution'].default_value = 8
                mok_circ.inputs['Radius'].default_value = mok_r
            except Exception:
                pass
            mok_fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x, -200))
            if mok_fill and mok_circ:
                try:
                    mok_fill.mode = 'NGONS'
                except Exception:
                    pass
                _link(tree, mok_circ.outputs['Curve'], mok_fill.inputs['Curve'])
                mok_ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 200, -200))
                if mok_ext:
                    mok_ext.mode = 'FACES'
                    try:
                        mok_ext.inputs['Offset Scale'].default_value = th * 0.22
                    except Exception:
                        pass
                    _link(tree, mok_fill.outputs['Mesh'], mok_ext.inputs['Mesh'])
                    color_node(mok_ext, "roof")
                    parts.append(mok_ext.outputs['Mesh'])

    for i in range(tiers):
        # ── Body: octagonal column via CurvePrimitiveCircle(8) + FillCurve + ExtrudeMesh ──
        body_h = th * 0.72
        body_circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, i * 400))
        if body_circ:
            try:
                body_circ.inputs['Resolution'].default_value = 8    # octagonal plan
                body_circ.inputs['Radius'].default_value     = cur_R * 0.90
            except Exception: pass
            color_node(body_circ, "house")
        body_fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, i * 400))
        if body_fill and body_circ:
            try: body_fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, body_circ.outputs['Curve'], body_fill.inputs['Curve'])
        body_ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, i * 400))
        if body_ext and body_fill:
            body_ext.mode = 'FACES'
            try: body_ext.inputs['Offset Scale'].default_value = body_h
            except Exception: pass
            _link(tree, body_fill.outputs['Mesh'], body_ext.inputs['Mesh'])
        body_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 600, i * 400))
        if body_tr:
            try: body_tr.inputs['Translation'].default_value = (0, 0, cur_z)
            except Exception: pass
            if body_ext: _link(tree, body_ext.outputs['Mesh'], body_tr.inputs['Geometry'])
            color_node(body_tr, "house")
            parts.append(body_tr.outputs['Geometry'])

        # ── Roof: octagonal eave disc (FillCurve + ExtrudeMesh thin) ──────
        roof_h  = th * 0.40
        eave_r  = cur_R + overhang
        eave_z  = cur_z + body_h
        eave_circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle',
                               (base_x, i * 400 + 100))
        if eave_circ:
            try:
                eave_circ.inputs['Resolution'].default_value = 8
                eave_circ.inputs['Radius'].default_value     = eave_r
            except Exception: pass
            color_node(eave_circ, "roof")
        eave_fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, i * 400 + 100))
        if eave_fill and eave_circ:
            try: eave_fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, eave_circ.outputs['Curve'], eave_fill.inputs['Curve'])
        eave_ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, i * 400 + 100))
        if eave_ext and eave_fill:
            eave_ext.mode = 'FACES'
            try: eave_ext.inputs['Offset Scale'].default_value = 0.06
            except Exception: pass
            _link(tree, eave_fill.outputs['Mesh'], eave_ext.inputs['Mesh'])
        eave_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 600, i * 400 + 100))
        if eave_tr:
            try:
                eave_tr.inputs['Translation'].default_value = (0, 0, eave_z - 0.03)
                eave_tr.inputs['Rotation'].default_value    = (0, 0, math.radians(22.5))
            except Exception: pass
            if eave_ext: _link(tree, eave_ext.outputs['Mesh'], eave_tr.inputs['Geometry'])
            color_node(eave_tr, "roof")
            parts.append(eave_tr.outputs['Geometry'])

        # Eave rim torus (adds a rounded edge to the eave disc)
        eave_rim = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, i * 400 + 200))
        if eave_rim:
            try:
                eave_rim.inputs['Major Radius'].default_value   = eave_r * 0.95
                eave_rim.inputs['Minor Radius'].default_value   = 0.055
                eave_rim.inputs['Major Segments'].default_value = 48
                eave_rim.inputs['Minor Segments'].default_value = 6
            except Exception: pass
            eave_rim_tr = _safe_node(tree, 'GeometryNodeTransform',
                                     (base_x + 200, i * 400 + 200))
            if eave_rim_tr:
                try: eave_rim_tr.inputs['Translation'].default_value = (0, 0, eave_z)
                except Exception: pass
                _link(tree, eave_rim.outputs['Mesh'], eave_rim_tr.inputs['Geometry'])
                color_node(eave_rim, "roof"); color_node(eave_rim_tr, "roof")
                parts.append(eave_rim_tr.outputs['Geometry'])

        # ── 8 curved corner kibana beams — bezier swept with thin tube ──────
        # Start at octagonal body edge, curve outward+upward to eave tip (upturn)
        body_edge_r = cur_R * 0.90   # match the octagonal body radius
        beam_prof_pag = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle',
                                   (base_x - 250, i * 400 + 300))
        if beam_prof_pag:
            try:
                beam_prof_pag.inputs['Resolution'].default_value = 6
                beam_prof_pag.inputs['Radius'].default_value     = 0.035
            except Exception: pass

        for corner in range(8):
            ang = corner * math.pi / 4.0 + math.pi / 8.0
            cos_a = math.cos(ang)
            sin_a = math.sin(ang)
            x0 = cos_a * body_edge_r
            y0 = sin_a * body_edge_r
            x1 = cos_a * (eave_r * 1.05)
            y1 = sin_a * (eave_r * 1.05)
            kib = _safe_node(tree, 'GeometryNodeCurvePrimitiveBezierSegment',
                             (base_x + corner * 80, i * 400 + 300))
            if kib:
                try:
                    kib.inputs['Resolution'].default_value    = 12
                    kib.inputs['Start'].default_value         = (x0, y0, eave_z - 0.02)
                    kib.inputs['Start Handle'].default_value  = ((x0 + x1) * 0.55,
                                                                  (y0 + y1) * 0.55,
                                                                  eave_z + 0.05)
                    kib.inputs['End Handle'].default_value    = (x1 * 1.03, y1 * 1.03,
                                                                  eave_z + 0.12)
                    kib.inputs['End'].default_value           = (x1 * 1.08, y1 * 1.08,
                                                                  eave_z + 0.28)
                except Exception: pass
                color_node(kib, "ornament")
                if beam_prof_pag:
                    kib_sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                                        (base_x + corner * 80, i * 400 + 350))
                    if kib_sw:
                        _link(tree, kib.outputs['Curve'], kib_sw.inputs['Curve'])
                        _link(tree, beam_prof_pag.outputs['Curve'], kib_sw.inputs['Profile Curve'])
                        try: kib_sw.inputs['Fill Caps'].default_value = True
                        except Exception: pass
                        color_node(kib_sw, "ornament")
                        parts.append(kib_sw.outputs['Mesh'])

        cur_z += th
        cur_R *= taper

    # Shinbashira (心柱) — central heart column through all tiers
    if show_shinbashira:
        col_h = cur_z * 0.92
        shin_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x - 400, tiers * 400 + 50))
        if shin_line:
            try:
                shin_line.inputs['Start'].default_value = (0, 0, 0.05)
                shin_line.inputs['End'].default_value = (0, 0, col_h)
            except Exception:
                pass
            shin_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 650, tiers * 400 + 50))
            if shin_prof:
                try:
                    shin_prof.inputs['Resolution'].default_value = 10
                    shin_prof.inputs['Radius'].default_value = R * 0.08
                except Exception:
                    pass
                shin_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x - 150, tiers * 400 + 50))
                if shin_sw:
                    _link(tree, shin_line.outputs['Curve'], shin_sw.inputs['Curve'])
                    _link(tree, shin_prof.outputs['Curve'], shin_sw.inputs['Profile Curve'])
                    try:
                        shin_sw.inputs['Fill Caps'].default_value = True
                    except Exception:
                        pass
                    color_node(shin_sw, "house")
                    parts.append(shin_sw.outputs['Geometry'])

    # ── Sōrin (crowning spire) — thin swept rod + kurin rings ─────
    spire_h = th * 1.25
    spire_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine',
                            (base_x, tiers * 400 + 100))
    if spire_line:
        try:
            spire_line.inputs['Start'].default_value = (0, 0, cur_z)
            spire_line.inputs['End'].default_value   = (0, 0, cur_z + spire_h)
        except Exception: pass
        spire_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle',
                                (base_x - 250, tiers * 400 + 100))
        if spire_prof:
            try:
                spire_prof.inputs['Resolution'].default_value = 10
                spire_prof.inputs['Radius'].default_value     = 0.055
            except Exception: pass
            spire_sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                                  (base_x + 250, tiers * 400 + 100))
            if spire_sw:
                _link(tree, spire_line.outputs['Curve'], spire_sw.inputs['Curve'])
                _link(tree, spire_prof.outputs['Curve'], spire_sw.inputs['Profile Curve'])
                try: spire_sw.inputs['Fill Caps'].default_value = True
                except Exception: pass
                color_node(spire_sw, "ornament")
                parts.append(spire_sw.outputs['Mesh'])

    # Kurin (ä¹è¼ª) rings + fukubachi dome + hÅju jewel on sÅrin spire
    fukubachi = _safe_node(tree, 'GeometryNodeMeshUVSphere', (base_x, tiers * 400 + 80))
    if fukubachi:
        try:
            fukubachi.inputs['Radius'].default_value = 0.14
        except Exception:
            pass
        fb_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, tiers * 400 + 80))
        if fb_tr:
            try:
                fb_tr.inputs['Translation'].default_value = (0, 0, cur_z + 0.05)
                fb_tr.inputs['Scale'].default_value = (1.0, 1.0, 0.45)
            except Exception:
                pass
            _link(tree, fukubachi.outputs['Mesh'], fb_tr.inputs['Geometry'])
            color_node(fb_tr, "ornament")
            parts.append(fb_tr.outputs['Geometry'])

    for r in range(kurin_n):
        k_ring = _safe_node(tree, 'GeometryNodeMeshTorus',
                            (base_x, tiers * 400 + 200 + r * 60))
        if k_ring:
            try:
                k_ring.inputs['Major Radius'].default_value   = 0.12 - r * 0.008
                k_ring.inputs['Minor Radius'].default_value   = 0.022 - r * 0.001
                k_ring.inputs['Major Segments'].default_value = 24
                k_ring.inputs['Minor Segments'].default_value = 6
            except Exception: pass
            k_tr = _safe_node(tree, 'GeometryNodeTransform',
                              (base_x + 200, tiers * 400 + 200 + r * 60))
            if k_tr:
                try: k_tr.inputs['Translation'].default_value = (
                    0, 0, cur_z + 0.22 + r * (spire_h * 0.085 / max(1, kurin_n)))
                except Exception: pass
                _link(tree, k_ring.outputs['Mesh'], k_tr.inputs['Geometry'])
                color_node(k_ring, "ornament"); color_node(k_tr, "ornament")
                parts.append(k_tr.outputs['Geometry'])

    # Hōju (宝珠) — wish-granting jewel at sōrin apex
    hoju = _safe_node(tree, 'GeometryNodeMeshUVSphere', (base_x, tiers * 400 + 800))
    if hoju:
        try:
            hoju.inputs['Radius'].default_value = 0.08
        except Exception:
            pass
        hj_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, tiers * 400 + 800))
        if hj_tr:
            try:
                hj_tr.inputs['Translation'].default_value = (0, 0, cur_z + spire_h + 0.12)
            except Exception:
                pass
            _link(tree, hoju.outputs['Mesh'], hj_tr.inputs['Geometry'])
            color_node(hj_tr, "ornament")
            parts.append(hj_tr.outputs['Geometry'])

    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 800, 0))
    if join:
        for p in parts: _link(tree, p, join.inputs['Geometry'])
        color_node(join, "output")
        return join.outputs['Geometry']
    return parts[0] if parts else None


def build_zen_torii(tree, props, base_x=-1400):
    """Japanese Myōjin torii gate — v2.49 AAA overhaul.

    All beams are swept curve profiles; posts are fluted sweep tubes.
    • 2 vertical posts: CurvePrimitiveLine + round/fluted profile sweep
    • Nuki (tie beam): horizontal CurvePrimitiveLine + rect-oval profile sweep
    • Shimaki (straight upper beam): horizontal sweep, wider and taller than nuki
    • Kasagi (curved top beam): BezierSegment + round profile sweep (already AAA)
    • Gakuzuka (center vertical brace): line sweep
    • Post caps (kibashira cap rings): small torus at top of each post
    """
    W     = props.torii_width
    H     = props.torii_height
    pr    = props.torii_post_radius
    curve = props.torii_top_curve
    style = getattr(props, 'torii_style', 'MYOJIN')
    nuki_frac = getattr(props, 'torii_nuki_height', 0.70)
    show_gz = getattr(props, 'torii_show_gakuzuka', True)
    show_kusabi = getattr(props, 'torii_show_kusabi', True)
    show_shimenawa = getattr(props, 'torii_show_shimenawa', False)
    is_shinmei = style in ('SHINMEI', 'ISE')
    parts = []

    # ── Shared post profile (round, 16-vert) ────────────────────────────
    post_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 300, 0))
    if post_prof:
        try:
            post_prof.inputs['Resolution'].default_value = 16
            post_prof.inputs['Radius'].default_value     = pr
        except Exception: pass
        color_node(post_prof, "house")

    # ── 2 vertical posts — CurvePrimitiveLine swept with post_prof ───────
    for i, x_off in enumerate((-W / 2, W / 2)):
        post_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, i * 200))
        if post_line:
            try:
                post_line.inputs['Start'].default_value = (x_off, 0, 0)
                post_line.inputs['End'].default_value   = (x_off, 0, H * 1.04)  # slight overshoot
            except Exception: pass
            color_node(post_line, "house")
            if post_prof:
                sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, i * 200))
                if sw:
                    _link(tree, post_line.outputs['Curve'], sw.inputs['Curve'])
                    _link(tree, post_prof.outputs['Curve'], sw.inputs['Profile Curve'])
                    try: sw.inputs['Fill Caps'].default_value = True
                    except Exception: pass
                    color_node(sw, "house")
                    parts.append(sw.outputs['Mesh'])

        # Post cap ring (kibashira cap) — torus at top of post
        cap_ring = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, 500 + i * 100))
        if cap_ring:
            try:
                cap_ring.inputs['Major Radius'].default_value = pr * 1.35
                cap_ring.inputs['Minor Radius'].default_value = pr * 0.28
                cap_ring.inputs['Major Segments'].default_value = 24
                cap_ring.inputs['Minor Segments'].default_value = 8
            except Exception: pass
            cap_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, 500 + i * 100))
            if cap_tr:
                try: cap_tr.inputs['Translation'].default_value = (x_off, 0, H)
                except Exception: pass
                _link(tree, cap_ring.outputs['Mesh'], cap_tr.inputs['Geometry'])
                color_node(cap_ring, "ornament"); color_node(cap_tr, "ornament")
                parts.append(cap_tr.outputs['Geometry'])

    # ── Shared horizontal beam profile (oval/rectangle cross-section) ────
    beam_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveQuadrilateral', (base_x - 300, -400))
    if beam_prof:
        try:
            beam_prof.mode = 'RECTANGLE'
            beam_prof.inputs['Width'].default_value  = pr * 1.8   # depth (front-back)
            beam_prof.inputs['Height'].default_value = pr * 1.3   # height
        except Exception:
            beam_prof = None
    color_node(beam_prof, "house") if beam_prof else None

    # ── Nuki (horizontal tie beam at 70% height) ─────────────────────────
    nuki_span = W + pr * 2.4
    nuki_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, 800))
    if nuki_line:
        try:
            nuki_line.inputs['Start'].default_value = (-nuki_span / 2, 0, H * nuki_frac)
            nuki_line.inputs['End'].default_value   = ( nuki_span / 2, 0, H * nuki_frac)
        except Exception: pass
        color_node(nuki_line, "house")
        if beam_prof:
            nuki_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, 800))
            if nuki_sw:
                _link(tree, nuki_line.outputs['Curve'], nuki_sw.inputs['Curve'])
                _link(tree, beam_prof.outputs['Curve'], nuki_sw.inputs['Profile Curve'])
                try: nuki_sw.inputs['Fill Caps'].default_value = True
                except Exception: pass
                color_node(nuki_sw, "house")
                parts.append(nuki_sw.outputs['Mesh'])

    # ── Shimaki (島杨) — secondary lintel; myōjin / ise only ─────────────
    if not is_shinmei:
        shimaki_span = W + pr * 3.2
        shimaki_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveQuadrilateral', (base_x - 300, -700))
        if shimaki_prof:
            try:
                shimaki_prof.mode = 'RECTANGLE'
                shimaki_prof.inputs['Width'].default_value  = pr * 2.0
                shimaki_prof.inputs['Height'].default_value = pr * 1.6
            except Exception:
                shimaki_prof = beam_prof
        color_node(shimaki_prof, "house") if shimaki_prof else None

        shim_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, 1000))
        if shim_line:
            try:
                shim_line.inputs['Start'].default_value = (-shimaki_span / 2, 0, H - pr * 0.5)
                shim_line.inputs['End'].default_value   = ( shimaki_span / 2, 0, H - pr * 0.5)
            except Exception: pass
            color_node(shim_line, "house")
            prof_to_use = shimaki_prof if shimaki_prof else beam_prof
            if prof_to_use:
                shim_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, 1000))
                if shim_sw:
                    _link(tree, shim_line.outputs['Curve'], shim_sw.inputs['Curve'])
                    _link(tree, prof_to_use.outputs['Curve'], shim_sw.inputs['Profile Curve'])
                    try: shim_sw.inputs['Fill Caps'].default_value = True
                    except Exception: pass
                    color_node(shim_sw, "house")
                    parts.append(shim_sw.outputs['Mesh'])

    # ── Kasagi (笠杨) — top lintel; straight on shinmei, curved on myōjin ─
    overhang = W * (0.12 if is_shinmei else 0.20)
    kas_z = H + pr * (0.6 if is_shinmei else 0.9)
    bez = _safe_node(tree, 'GeometryNodeCurvePrimitiveBezierSegment', (base_x, 1300))
    if bez:
        try:
            bez.inputs['Resolution'].default_value    = 32
            bez.inputs['Start'].default_value         = (-W / 2 - overhang, 0, kas_z)
            curve_lift = 0.0 if is_shinmei else curve * 0.5
            bez.inputs['Start Handle'].default_value  = (-W / 2 - overhang * 0.4, 0, H - curve_lift + pr * 0.9)
            bez.inputs['End Handle'].default_value    = ( W / 2 + overhang * 0.4, 0, H - curve_lift + pr * 0.9)
            bez.inputs['End'].default_value           = ( W / 2 + overhang, 0, kas_z)
        except Exception: pass
        color_node(bez, "ornament")

        kas_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 300, 1100))
        if kas_prof:
            try:
                kas_prof.inputs['Resolution'].default_value = 12
                kas_prof.inputs['Radius'].default_value     = pr * 1.35
            except Exception: pass
            color_node(kas_prof, "ornament")
            kas_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, 1300))
            if kas_sw:
                _link(tree, bez.outputs['Curve'], kas_sw.inputs['Curve'])
                _link(tree, kas_prof.outputs['Curve'], kas_sw.inputs['Profile Curve'])
                try: kas_sw.inputs['Fill Caps'].default_value = True
                except Exception: pass
                color_node(kas_sw, "ornament")
                parts.append(kas_sw.outputs['Mesh'])

    # ── Gakuzuka (額束) — center tablet strut ─────────────────────────────
    if show_gz and not is_shinmei:
        gz_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, 1500))
        if gz_line:
            try:
                gz_line.inputs['Start'].default_value = (0, 0, H * nuki_frac + pr * 0.15)
                gz_line.inputs['End'].default_value   = (0, 0, H - pr * 0.5)
            except Exception: pass
            color_node(gz_line, "ornament")
            gz_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 300, 1500))
            if gz_prof:
                try:
                    gz_prof.inputs['Resolution'].default_value = 8
                    gz_prof.inputs['Radius'].default_value     = pr * 0.55
                except Exception: pass
                gz_sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, 1500))
                if gz_sw:
                    _link(tree, gz_line.outputs['Curve'], gz_sw.inputs['Curve'])
                    _link(tree, gz_prof.outputs['Curve'], gz_sw.inputs['Profile Curve'])
                    try: gz_sw.inputs['Fill Caps'].default_value = True
                    except Exception: pass
                    color_node(gz_sw, "ornament")
                    parts.append(gz_sw.outputs['Mesh'])

    # ── Kusabi (楔) — wedges at hashira/nuki junction ───────────────────
    if show_kusabi:
        for x_off in (-W / 2, W / 2):
            wedge = _safe_node(tree, 'GeometryNodeMeshCube', (base_x, 1700))
            if wedge:
                try:
                    wedge.inputs['Size'].default_value = (pr * 0.9, pr * 1.4, pr * 0.7)
                except Exception: pass
                wtr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, 1700))
                if wtr:
                    try:
                        wtr.inputs['Translation'].default_value = (x_off, 0, H * nuki_frac)
                        wtr.inputs['Rotation'].default_value = (0, 0, math.radians(18 if x_off < 0 else -18))
                    except Exception: pass
                    _link(tree, wedge.outputs['Mesh'], wtr.inputs['Geometry'])
                    color_node(wtr, "ornament")
                    parts.append(wtr.outputs['Geometry'])

    # Shimenawa (注連縄) — sacred rope between hashira
    if show_shimenawa:
        rope_y = 0.0
        for seg in range(5):
            t = seg / 4.0
            rx = -W / 2 + t * W
            seg_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveBezierSegment', (base_x, 1900 + seg * 40))
            if seg_line:
                sag = H * 0.04
                try:
                    seg_line.inputs['Start'].default_value = (rx, rope_y, H * 0.55)
                    seg_line.inputs['End'].default_value = (rx + W / 4, rope_y, H * 0.55 - sag)
                    seg_line.inputs['Start Handle'].default_value = (rx + W / 16, rope_y, H * 0.55)
                    seg_line.inputs['End Handle'].default_value = (rx + W / 5, rope_y, H * 0.55 - sag * 0.6)
                except Exception:
                    pass
                rprof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 200, 1900 + seg * 40))
                if rprof:
                    try:
                        rprof.inputs['Radius'].default_value = pr * 0.35
                        rprof.inputs['Resolution'].default_value = 8
                    except Exception:
                        pass
                    rsw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 220, 1900 + seg * 40))
                    if rsw:
                        _link(tree, seg_line.outputs['Curve'], rsw.inputs['Curve'])
                        _link(tree, rprof.outputs['Curve'], rsw.inputs['Profile Curve'])
                        color_node(rsw, "ornament")
                        parts.append(rsw.outputs['Mesh'])

    if not parts:
        return None
    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 800, 0))
    if join:
        for p in parts: _link(tree, p, join.inputs['Geometry'])
        color_node(join, "output")
        return join.outputs['Geometry']
    return parts[0]


def build_zen_shoji(tree, props, base_x=-1400):
    """Shōji (隝子) — shamoji frame + kumiko lattice + paper panel."""
    W = props.shoji_width
    H = props.shoji_height
    nx = props.shoji_grid_x
    ny = props.shoji_grid_y
    m = props.shoji_mullion
    frame_thick = max(m * 2.5, getattr(props, 'shoji_frame_depth', 0.06))
    kumiko = getattr(props, 'shoji_kumiko', 'GRID')
    parts = []
    for cx, cy, cz, sx, sy, sz in [
        (0, 0, H - frame_thick/2, W, frame_thick, frame_thick),  # top
        (0, 0, frame_thick/2,     W, frame_thick, frame_thick),  # bottom
        (-W/2 + frame_thick/2, 0, H/2, frame_thick, frame_thick, H),  # left
        ( W/2 - frame_thick/2, 0, H/2, frame_thick, frame_thick, H),  # right
    ]:
        bar = tree.nodes.new('GeometryNodeMeshCube'); bar.location = (base_x, len(parts) * 100); color_node(bar, "house")
        bar.inputs['Size'].default_value = (sx, sy, sz)
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, len(parts) * 100)
        bt.inputs['Translation'].default_value = (cx, cy, cz)
        tree.links.new(bar.outputs['Mesh'], bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

    # Kumiko (çµ„å­) diagonal motifs inside each cell
    if kumiko in ('ASANOHA', 'YUKITSUBAKI'):
        inner_W = W - frame_thick * 2
        inner_H = H - frame_thick * 2
        cell_w = inner_W / max(1, nx)
        cell_h = inner_H / max(1, ny)
        for ci in range(nx):
            for ri in range(ny):
                cx = -W / 2 + frame_thick + (ci + 0.5) * cell_w
                cz = frame_thick + (ri + 0.5) * cell_h
                diag_len = math.hypot(cell_w, cell_h) * 0.92
                for sign in (1, -1):
                    dline = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, 900 + ci * 40 + ri * 10))
                    if dline:
                        try:
                            dline.inputs['Start'].default_value = (cx - cell_w * 0.42 * sign, 0, cz - cell_h * 0.42)
                            dline.inputs['End'].default_value = (cx + cell_w * 0.42 * sign, 0, cz + cell_h * 0.42)
                        except Exception:
                            pass
                        dprof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 200, 900 + ci * 40))
                        if dprof:
                            try:
                                dprof.inputs['Radius'].default_value = m * 0.55
                                dprof.inputs['Resolution'].default_value = 6
                            except Exception:
                                pass
                            dsw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 200, 900 + ci * 40))
                            if dsw:
                                _link(tree, dline.outputs['Curve'], dsw.inputs['Curve'])
                                _link(tree, dprof.outputs['Curve'], dsw.inputs['Profile Curve'])
                                color_node(dsw, "house")
                                parts.append(dsw.outputs['Mesh'])

    # Vertical mullions
    inner_W = W - frame_thick * 2
    for i in range(1, nx):
        x = -W/2 + frame_thick + (i / nx) * inner_W
        bar = tree.nodes.new('GeometryNodeMeshCube'); bar.location = (base_x, 600); color_node(bar, "house")
        bar.inputs['Size'].default_value = (m, m, H - frame_thick * 2)
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, 600)
        bt.inputs['Translation'].default_value = (x, 0, H/2)
        tree.links.new(bar.outputs['Mesh'], bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

    # Horizontal mullions
    inner_H = H - frame_thick * 2
    for j in range(1, ny):
        z = frame_thick + (j / ny) * inner_H
        bar = tree.nodes.new('GeometryNodeMeshCube'); bar.location = (base_x, 800); color_node(bar, "house")
        bar.inputs['Size'].default_value = (W - frame_thick * 2, m, m)
        bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, 800)
        bt.inputs['Translation'].default_value = (0, 0, z)
        tree.links.new(bar.outputs['Mesh'], bt.inputs['Geometry'])
        parts.append(bt.outputs['Geometry'])

    # Paper backing — a thin plane recessed slightly
    paper = tree.nodes.new('GeometryNodeMeshCube'); paper.location = (base_x, 1000); color_node(paper, "ornament")
    paper.inputs['Size'].default_value = (W - frame_thick * 2, m * 0.5, H - frame_thick * 2)
    pt = tree.nodes.new('GeometryNodeTransform'); pt.location = (base_x+200, 1000)
    pt.inputs['Translation'].default_value = (0, m * 0.5, H/2)
    tree.links.new(paper.outputs['Mesh'], pt.inputs['Geometry'])
    parts.append(pt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+500, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_zen_lantern(tree, props, base_x=-1400):
    """Ishi-dōrō (石灯籠) — v2.56 research-backed tōrō assembly.

    Eight named elements (bottom → top), per JAANUS / NAJGA / Wikipedia:
      kidan 基壇, kiso 基礎, sao 竿, chūdai 中台, hibukuro 火袋,
      kasa 笠 (+ warabide 蕨手), ukebana 請花, hōju 宝珠
    Geometry only — assign stone/wood materials in UE.
    """
    import math
    H = getattr(props, 'zen_lantern_height', 2.0)
    R = getattr(props, 'zen_lantern_radius', 0.35)
    style = getattr(props, 'zen_lantern_style', 'KASUGA')
    layers = getattr(props, 'zen_lantern_layers', 6)
    warabide = getattr(props, 'zen_lantern_warabide', 0.35)
    higuchi = getattr(props, 'zen_lantern_higuchi', 'ROUND')
    hoju_s = getattr(props, 'zen_lantern_hoju_scale', 1.0)
    kasa_oh = getattr(props, 'zen_lantern_kasa_overhang', 1.0)
    show_kidan = getattr(props, 'zen_lantern_show_kidan', True)
    show_uke = getattr(props, 'zen_lantern_show_ukebana', True)

    sao_mul = {'KASUGA': 1.0, 'YUKIMI': 0.35, 'ORIBE': 0.7, 'MISAKI': 0.15}.get(style, 1.0)
    kasa_mul = {'KASUGA': 1.0, 'YUKIMI': 1.45, 'ORIBE': 0.95, 'MISAKI': 1.55}.get(style, 1.0) * kasa_oh
    hib_verts = {'KASUGA': 6, 'YUKIMI': 6, 'ORIBE': 4, 'MISAKI': 8}.get(style, 6)

    active = _zen_lantern_element_mask(layers, show_kidan, show_uke)
    h_fracs = {
        'kidan': 0.06, 'kiso': 0.10, 'sao': 0.28 * sao_mul, 'chudai': 0.07,
        'hibukuro': 0.20, 'kasa': 0.16 * kasa_mul, 'ukebana': 0.05, 'hoju': 0.08 * hoju_s,
    }
    total_f = sum(h_fracs[k] for k in active) or 1.0
    parts = []
    cur_z = 0.0
    y_slot = 0

    def _ring_disc(major_r, minor_r, flat_z, y_offset, verts=32, segs=8, label="lantern", squash=0.30):
        nd = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, y_offset))
        if nd is None:
            return None
        try:
            nd.inputs['Major Radius'].default_value = major_r
            nd.inputs['Minor Radius'].default_value = minor_r
            nd.inputs['Major Segments'].default_value = verts
            nd.inputs['Minor Segments'].default_value = segs
        except Exception:
            return None
        tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, y_offset))
        if tr is None:
            return None
        try:
            tr.inputs['Translation'].default_value = (0, 0, flat_z)
            tr.inputs['Scale'].default_value = (1.0, 1.0, squash)
        except Exception:
            pass
        _link(tree, nd.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(nd, label)
        color_node(tr, label)
        return tr.outputs['Geometry']

    def _poly_col(verts_n, radius, extrude_h, z_base, y_offset, label="lantern"):
        circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, y_offset))
        if circ is None:
            return None
        try:
            circ.inputs['Resolution'].default_value = verts_n
            circ.inputs['Radius'].default_value = radius
        except Exception:
            return None
        fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, y_offset))
        if fill:
            try:
                fill.mode = 'NGONS'
            except Exception:
                pass
            _link(tree, circ.outputs['Curve'], fill.inputs['Curve'])
        ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, y_offset))
        if ext and fill:
            ext.mode = 'FACES'
            try:
                ext.inputs['Offset Scale'].default_value = extrude_h
            except Exception:
                pass
            _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
        tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 600, y_offset))
        if tr:
            try:
                tr.inputs['Translation'].default_value = (0, 0, z_base)
            except Exception:
                pass
            if ext:
                _link(tree, ext.outputs['Mesh'], tr.inputs['Geometry'])
            color_node(circ, label)
            color_node(tr, label)
            return tr.outputs['Geometry']
        return None

    def _tube(radius, z_start, z_end, verts_n, y_offset, label="lantern"):
        line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, y_offset))
        if line is None:
            return None
        try:
            line.inputs['Start'].default_value = (0, 0, z_start)
            line.inputs['End'].default_value = (0, 0, z_end)
        except Exception:
            return None
        prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 250, y_offset))
        if prof is None:
            return None
        try:
            prof.inputs['Resolution'].default_value = verts_n
            prof.inputs['Radius'].default_value = radius
        except Exception:
            return None
        sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, y_offset))
        if sw is None:
            return None
        _link(tree, line.outputs['Curve'], sw.inputs['Curve'])
        _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
        try:
            sw.inputs['Fill Caps'].default_value = True
        except Exception:
            pass
        color_node(sw, label)
        return sw.outputs['Mesh']

    def _hibukuro_higuchi(z_base, h_this, y_offset):
        for face_i, ang in enumerate((0.0, math.pi / 2.0)):
            cx = math.cos(ang) * R * 0.55
            cy = math.sin(ang) * R * 0.55
            opening = max(R * 0.22, 0.04)
            if higuchi == 'MOON':
                arc = _safe_node(tree, 'GeometryNodeCurvePrimitiveArc', (base_x, y_offset - face_i * 80))
                if arc:
                    try:
                        arc.inputs['Radius'].default_value = opening
                        arc.inputs['Start Angle'].default_value = math.radians(-60)
                        arc.inputs['Sweep Angle'].default_value = math.radians(120)
                    except Exception:
                        pass
                    atr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 180, y_offset - face_i * 80))
                    if atr:
                        try:
                            atr.inputs['Translation'].default_value = (cx, cy, z_base + h_this * 0.5)
                            atr.inputs['Rotation'].default_value = (math.pi / 2, 0, ang)
                        except Exception:
                            pass
                        _link(tree, arc.outputs['Curve'], atr.inputs['Geometry'])
                        sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 360, y_offset - face_i * 80))
                        if sw:
                            prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x + 120, y_offset - face_i * 80))
                            if prof:
                                try:
                                    prof.inputs['Radius'].default_value = R * 0.025
                                    prof.inputs['Resolution'].default_value = 6
                                except Exception:
                                    pass
                                _link(tree, atr.outputs['Geometry'], sw.inputs['Curve'])
                                _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
                                color_node(sw, "ornament")
                                parts.append(sw.outputs['Mesh'])
            else:
                w = opening
                d = opening
                frame = _safe_node(tree, 'GeometryNodeMeshCube', (base_x, y_offset - face_i * 80))
                if frame:
                    try:
                        frame.inputs['Size'].default_value = (w, R * 0.04, d)
                    except Exception:
                        pass
                    ftr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, y_offset - face_i * 80))
                    if ftr:
                        try:
                            ftr.inputs['Translation'].default_value = (cx, cy, z_base + h_this * 0.5)
                            ftr.inputs['Rotation'].default_value = (0, 0, ang)
                        except Exception:
                            pass
                        _link(tree, frame.outputs['Mesh'], ftr.inputs['Geometry'])
                        color_node(ftr, "ornament")
                        parts.append(ftr.outputs['Geometry'])

    def _kasa_warabide(z_base, h_this, y_offset):
        if warabide <= 0.01:
            return
        for k in range(hib_verts):
            ang = k * math.tau / hib_verts
            tip_x = math.cos(ang) * R * 1.15 * kasa_mul
            tip_y = math.sin(ang) * R * 1.15 * kasa_mul
            bez = _safe_node(tree, 'GeometryNodeCurvePrimitiveBezierSegment', (base_x, y_offset - k * 50))
            if bez:
                try:
                    bez.inputs['Start'].default_value = (tip_x * 0.92, tip_y * 0.92, z_base + h_this * 0.12)
                    bez.inputs['End'].default_value = (tip_x, tip_y, z_base + h_this * (0.12 + warabide * 0.35))
                    bez.inputs['Start Handle'].default_value = (tip_x * 0.95, tip_y * 0.95, z_base + h_this * 0.18)
                    bez.inputs['End Handle'].default_value = (tip_x, tip_y, z_base + h_this * (0.08 + warabide * 0.2))
                except Exception:
                    pass
                prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x - 200, y_offset - k * 50))
                if prof:
                    try:
                        prof.inputs['Radius'].default_value = R * 0.04
                        prof.inputs['Resolution'].default_value = 6
                    except Exception:
                        pass
                    sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 220, y_offset - k * 50))
                    if sw:
                        _link(tree, bez.outputs['Curve'], sw.inputs['Curve'])
                        _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
                        color_node(sw, "ornament")
                        parts.append(sw.outputs['Mesh'])

    for elem in active:
        h_this = H * (h_fracs.get(elem, 0.1) / total_f)

        if elem == 'kidan':
            disc = _ring_disc(R * 1.35, R * 0.32, cur_z + h_this * 0.5, y_slot, squash=0.22)
            if disc:
                parts.append(disc)

        elif elem == 'kiso':
            disc = _ring_disc(R * 1.12, R * 0.28, cur_z + h_this * 0.5, y_slot)
            if disc:
                parts.append(disc)
            core = _tube(R * 0.48, cur_z, cur_z + h_this, 12, y_slot - 120)
            if core:
                parts.append(core)

        elif elem == 'sao':
            if sao_mul > 0.12:
                shaft = _tube(R * 0.26, cur_z, cur_z + h_this, 12, y_slot)
                if shaft:
                    parts.append(shaft)
                fushi = _ring_disc(R * 0.38, R * 0.10, cur_z + h_this * 0.5, y_slot - 180, verts=20, segs=8)
                if fushi:
                    parts.append(fushi)

        elif elem == 'chudai':
            col = _poly_col(8, R * 0.82, h_this, cur_z, y_slot)
            if col:
                parts.append(col)
            rim = _ring_disc(R * 0.92, R * 0.12, cur_z + h_this, y_slot - 160, verts=32, segs=6)
            if rim:
                parts.append(rim)

        elif elem == 'hibukuro':
            col = _poly_col(hib_verts, R * 0.74, h_this, cur_z, y_slot, label="ornament")
            if col:
                parts.append(col)
            _hibukuro_higuchi(cur_z, h_this, y_slot - 300)

        elif elem == 'kasa':
            col = _poly_col(hib_verts, R * 1.18 * kasa_mul, h_this * 0.28, cur_z, y_slot, label="ornament")
            if col:
                parts.append(col)
            kasa_rim = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, y_slot - 200))
            if kasa_rim:
                try:
                    kasa_rim.inputs['Major Radius'].default_value = R * 1.12 * kasa_mul
                    kasa_rim.inputs['Minor Radius'].default_value = R * 0.18
                    kasa_rim.inputs['Major Segments'].default_value = 48
                    kasa_rim.inputs['Minor Segments'].default_value = 8
                except Exception:
                    pass
                kasa_tr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, y_slot - 200))
                if kasa_tr:
                    try:
                        kasa_tr.inputs['Translation'].default_value = (0, 0, cur_z + h_this * 0.2)
                        kasa_tr.inputs['Scale'].default_value = (1.0, 1.0, 0.45)
                    except Exception:
                        pass
                    _link(tree, kasa_rim.outputs['Mesh'], kasa_tr.inputs['Geometry'])
                    color_node(kasa_rim, "ornament")
                    parts.append(kasa_tr.outputs['Geometry'])
            _kasa_warabide(cur_z, h_this, y_slot - 400)

        elif elem == 'ukebana':
            lotus = _poly_col(12, R * 0.32, h_this * 0.55, cur_z, y_slot, label="ornament")
            if lotus:
                parts.append(lotus)
            petal = _ring_disc(R * 0.28, R * 0.14, cur_z + h_this * 0.35, y_slot - 120, verts=24, segs=10, squash=0.55)
            if petal:
                parts.append(petal)

        elif elem == 'hoju':
            for k, (maj, mino, z_frac) in enumerate([
                (R * 0.22 * hoju_s, R * 0.20 * hoju_s, 0.12),
                (R * 0.16 * hoju_s, R * 0.14 * hoju_s, 0.42),
                (R * 0.08 * hoju_s, R * 0.07 * hoju_s, 0.72),
            ]):
                ring = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, y_slot - 500 - k * 120))
                if ring:
                    try:
                        ring.inputs['Major Radius'].default_value = maj
                        ring.inputs['Minor Radius'].default_value = mino
                        ring.inputs['Major Segments'].default_value = 20
                        ring.inputs['Minor Segments'].default_value = 8
                    except Exception:
                        pass
                    rtr = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, y_slot - 500 - k * 120))
                    if rtr:
                        try:
                            rtr.inputs['Translation'].default_value = (0, 0, cur_z + h_this * z_frac)
                        except Exception:
                            pass
                        _link(tree, ring.outputs['Mesh'], rtr.inputs['Geometry'])
                        color_node(ring, "ornament")
                        parts.append(rtr.outputs['Geometry'])

        cur_z += h_this
        y_slot -= 650

    if not parts:
        return None
    join = _safe_node(tree, 'GeometryNodeJoinGeometry', (base_x + 900, 0))
    if join:
        for p in parts:
            _link(tree, p, join.inputs['Geometry'])
        color_node(join, "output")
        return join.outputs['Geometry']
    return parts[0]


def build_zen_teahouse(tree, props, base_x=-1400):
    """Tea house — square pavilion with steeply-pitched curved roof + raised platform."""
    W = props.teahouse_width
    D = props.teahouse_depth
    H = props.teahouse_height
    pitch = props.teahouse_pitch_factor
    parts = []

    # Raised platform — extended outward for engawa if enabled
    engawa_width = props.teahouse_engawa_width if props.teahouse_engawa else 0.0
    platform_W = W + engawa_width * 2
    platform_D = D + engawa_width * 2
    platform = tree.nodes.new('GeometryNodeMeshCube'); platform.location = (base_x, 0); color_node(platform, "house")
    platform.inputs['Size'].default_value = (platform_W, platform_D, 0.25)
    pt = tree.nodes.new('GeometryNodeTransform'); pt.location = (base_x+200, 0)
    pt.inputs['Translation'].default_value = (0, 0, 0.125)
    tree.links.new(platform.outputs['Mesh'], pt.inputs['Geometry'])
    parts.append(pt.outputs['Geometry'])

    # Engawa railing posts (small) along the platform edge
    if props.teahouse_engawa:
        n_posts_side = 4
        for side_x, side_y in [(0, -1), (0, 1), (-1, 0), (1, 0)]:
            if side_x != 0:  # left/right side
                for i in range(n_posts_side):
                    y = -platform_D/2 + (i + 0.5) * (platform_D / n_posts_side)
                    post = tree.nodes.new('GeometryNodeMeshCylinder'); post.location = (base_x, 100 + i * 50); color_node(post, "ornament")
                    post.inputs['Vertices'].default_value = 6
                    post.inputs['Radius'].default_value = 0.025
                    post.inputs['Depth'].default_value = 0.5
                    pot = tree.nodes.new('GeometryNodeTransform'); pot.location = (base_x+200, 100 + i * 50)
                    pot.inputs['Translation'].default_value = (side_x * (platform_W/2 - 0.04), y, 0.25 + 0.25)
                    tree.links.new(post.outputs['Mesh'], pot.inputs['Geometry'])
                    parts.append(pot.outputs['Geometry'])
            else:  # front/back side
                for i in range(n_posts_side):
                    x = -platform_W/2 + (i + 0.5) * (platform_W / n_posts_side)
                    post = tree.nodes.new('GeometryNodeMeshCylinder'); post.location = (base_x, 100 + (i + n_posts_side) * 50); color_node(post, "ornament")
                    post.inputs['Vertices'].default_value = 6
                    post.inputs['Radius'].default_value = 0.025
                    post.inputs['Depth'].default_value = 0.5
                    pot = tree.nodes.new('GeometryNodeTransform'); pot.location = (base_x+200, 100 + (i + n_posts_side) * 50)
                    pot.inputs['Translation'].default_value = (x, side_y * (platform_D/2 - 0.04), 0.25 + 0.25)
                    tree.links.new(post.outputs['Mesh'], pot.inputs['Geometry'])
                    parts.append(pot.outputs['Geometry'])

    # 4 corner posts
    pr = 0.08
    post_h = H * 0.6
    for x_s, y_s in [(-1, -1), (1, -1), (1, 1), (-1, 1)]:
        post = tree.nodes.new('GeometryNodeMeshCylinder'); post.location = (base_x, 200); color_node(post, "house")
        post.inputs['Vertices'].default_value = 12
        post.inputs['Radius'].default_value = pr
        post.inputs['Depth'].default_value = post_h
        ppt = tree.nodes.new('GeometryNodeTransform'); ppt.location = (base_x+200, 200)
        ppt.inputs['Translation'].default_value = (x_s * (W/2 - pr * 2), y_s * (D/2 - pr * 2), 0.25 + post_h/2)
        tree.links.new(post.outputs['Mesh'], ppt.inputs['Geometry'])
        parts.append(ppt.outputs['Geometry'])

    # Floor mat (tatami area)
    mat = tree.nodes.new('GeometryNodeMeshCube'); mat.location = (base_x, 400); color_node(mat, "house")
    mat.inputs['Size'].default_value = (W * 0.9, D * 0.9, 0.05)
    mt = tree.nodes.new('GeometryNodeTransform'); mt.location = (base_x+200, 400)
    mt.inputs['Translation'].default_value = (0, 0, 0.27)
    tree.links.new(mat.outputs['Mesh'], mt.inputs['Geometry'])
    parts.append(mt.outputs['Geometry'])

    # ---- Curved hip roof (irimoya-style sweeping eaves) ----------------
    # Built from a flat Grid deformed by a concave Japanese roof curve.
    # Square level-sets (Chebyshev distance) give a proper 4-sided hip;
    # the (1-m)^pitch profile is concave so the eaves sweep outward.
    roof_h = H * pitch
    overhang = W * 0.28
    eave_span = W + overhang * 2          # full footprint of the eave
    half_span = eave_span / 2.0
    roof_base_z = 0.25 + post_h           # eave height sits on the posts
    res = 24

    grid = tree.nodes.new('GeometryNodeMeshGrid'); grid.location = (base_x, 600); color_node(grid, "roof")
    grid.inputs['Size X'].default_value = eave_span
    grid.inputs['Size Y'].default_value = eave_span
    grid.inputs['Vertices X'].default_value = res
    grid.inputs['Vertices Y'].default_value = res

    gpos = tree.nodes.new('GeometryNodeInputPosition'); gpos.location = (base_x, 850)
    gsep = tree.nodes.new('ShaderNodeSeparateXYZ'); gsep.location = (base_x+200, 850)
    tree.links.new(gpos.outputs['Position'], gsep.inputs['Vector'])
    ax = tree.nodes.new('ShaderNodeMath'); ax.location = (base_x+380, 920); ax.operation = 'ABSOLUTE'
    tree.links.new(gsep.outputs['X'], ax.inputs[0])
    ay = tree.nodes.new('ShaderNodeMath'); ay.location = (base_x+380, 800); ay.operation = 'ABSOLUTE'
    tree.links.new(gsep.outputs['Y'], ay.inputs[0])
    cheb = tree.nodes.new('ShaderNodeMath'); cheb.location = (base_x+560, 860); cheb.operation = 'MAXIMUM'
    tree.links.new(ax.outputs[0], cheb.inputs[0]); tree.links.new(ay.outputs[0], cheb.inputs[1])
    mnorm = tree.nodes.new('ShaderNodeMath'); mnorm.location = (base_x+740, 860); mnorm.operation = 'DIVIDE'
    mnorm.inputs[1].default_value = max(0.001, half_span)
    tree.links.new(cheb.outputs[0], mnorm.inputs[0])      # m in [0..1]
    inv = tree.nodes.new('ShaderNodeMath'); inv.location = (base_x+920, 920); inv.operation = 'SUBTRACT'
    inv.inputs[0].default_value = 1.0
    tree.links.new(mnorm.outputs[0], inv.inputs[1])       # 1 - m
    powr = tree.nodes.new('ShaderNodeMath'); powr.location = (base_x+1100, 920); powr.operation = 'POWER'
    powr.inputs[1].default_value = max(0.4, pitch * 1.2)  # concave when >1
    tree.links.new(inv.outputs[0], powr.inputs[0])
    zmul = tree.nodes.new('ShaderNodeMath'); zmul.location = (base_x+1280, 920); zmul.operation = 'MULTIPLY'
    zmul.inputs[1].default_value = roof_h
    tree.links.new(powr.outputs[0], zmul.inputs[0])
    # Upturned eave flip: lift the outer tips (m^6 spikes only at the very edge)
    eflip = tree.nodes.new('ShaderNodeMath'); eflip.location = (base_x+920, 760); eflip.operation = 'POWER'
    eflip.inputs[1].default_value = 6.0
    tree.links.new(mnorm.outputs[0], eflip.inputs[0])
    eamp = tree.nodes.new('ShaderNodeMath'); eamp.location = (base_x+1100, 760); eamp.operation = 'MULTIPLY'
    eamp.inputs[1].default_value = roof_h * 0.16
    tree.links.new(eflip.outputs[0], eamp.inputs[0])
    zsum = tree.nodes.new('ShaderNodeMath'); zsum.location = (base_x+1460, 880); zsum.operation = 'ADD'
    tree.links.new(zmul.outputs[0], zsum.inputs[0]); tree.links.new(eamp.outputs[0], zsum.inputs[1])
    zvec = tree.nodes.new('ShaderNodeCombineXYZ'); zvec.location = (base_x+1640, 880)
    tree.links.new(zsum.outputs[0], zvec.inputs['Z'])
    setp = tree.nodes.new('GeometryNodeSetPosition'); setp.location = (base_x+1820, 600); color_node(setp, "roof")
    tree.links.new(grid.outputs['Mesh'], setp.inputs['Geometry'])
    tree.links.new(zvec.outputs['Vector'], setp.inputs['Offset'])
    # Give the shell thickness so it reads as a solid roof
    rthick = tree.nodes.new('GeometryNodeExtrudeMesh'); rthick.location = (base_x+2020, 600); color_node(rthick, "roof")
    rthick.mode = 'FACES'
    try: rthick.inputs['Offset Scale'].default_value = -0.12
    except Exception: pass
    tree.links.new(setp.outputs['Geometry'], rthick.inputs['Mesh'])
    rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+2220, 600)
    rt.inputs['Translation'].default_value = (0, 0, roof_base_z)
    tree.links.new(rthick.outputs['Mesh'], rt.inputs['Geometry'])
    parts.append(rt.outputs['Geometry'])

    # Corner hip ridge beams — bezier sweeps from apex down to each eave tip
    ridge_prof = _make_circle_profile(tree, 0.05, 6, (base_x, 1100), props)
    apex_z = roof_base_z + roof_h + roof_h * 0.16
    for x_s, y_s in [(-1, -1), (1, -1), (1, 1), (-1, 1)]:
        rb = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); rb.location = (base_x+200, 1100 + (x_s+y_s) * 40)
        rb.inputs['Start'].default_value = (0, 0, apex_z)
        rb.inputs['End'].default_value = (x_s * half_span, y_s * half_span, roof_base_z + roof_h * 0.16)
        rb.inputs['Start Handle'].default_value = (x_s * half_span * 0.35, y_s * half_span * 0.35, apex_z)
        rb.inputs['End Handle'].default_value = (x_s * half_span * 0.75, y_s * half_span * 0.75, roof_base_z + roof_h * 0.55)
        rsw = tree.nodes.new('GeometryNodeCurveToMesh'); rsw.location = (base_x+420, 1100 + (x_s+y_s) * 40); color_node(rsw, "roof")
        tree.links.new(rb.outputs['Curve'], rsw.inputs['Curve'])
        if ridge_prof is not None:
            tree.links.new(ridge_prof.outputs['Curve'], rsw.inputs['Profile Curve'])
        rsw.inputs['Fill Caps'].default_value = True
        parts.append(rsw.outputs['Mesh'])

    # Finial (hÅju) at apex
    fin = tree.nodes.new('GeometryNodeMeshUVSphere'); fin.location = (base_x+200, 1400); color_node(fin, "ornament")
    fin.inputs['Radius'].default_value = 0.10
    fint = tree.nodes.new('GeometryNodeTransform'); fint.location = (base_x+420, 1400)
    fint.inputs['Translation'].default_value = (0, 0, apex_z + 0.05)
    tree.links.new(fin.outputs['Mesh'], fint.inputs['Geometry'])
    parts.append(fint.outputs['Geometry'])

    # Tokonoma (床の間) — recessed alcove with tokobashira pillar
    if getattr(props, 'teahouse_tokonoma', True):
        alcove_w = W * 0.28
        alcove_d = 0.18
        alcove_h = H * 0.55
        alc = tree.nodes.new('GeometryNodeMeshCube'); alc.location = (base_x, 1500); color_node(alc, "house")
        alc.inputs['Size'].default_value = (alcove_w, alcove_d, alcove_h)
        alct = tree.nodes.new('GeometryNodeTransform'); alct.location = (base_x+200, 1500)
        alct.inputs['Translation'].default_value = (-W * 0.22, D / 2 - alcove_d * 0.6, 0.27 + alcove_h / 2)
        tree.links.new(alc.outputs['Mesh'], alct.inputs['Geometry'])
        parts.append(alct.outputs['Geometry'])
        # Tokobashira (床柱) — alcove pillar
        tbp = tree.nodes.new('GeometryNodeMeshCylinder'); tbp.location = (base_x, 1600); color_node(tbp, "ornament")
        tbp.inputs['Vertices'].default_value = 8
        tbp.inputs['Radius'].default_value = 0.045
        tbp.inputs['Depth'].default_value = alcove_h
        tbpt = tree.nodes.new('GeometryNodeTransform'); tbpt.location = (base_x+200, 1600)
        tbpt.inputs['Translation'].default_value = (-W * 0.22 + alcove_w * 0.35, D / 2 - alcove_d * 0.3, 0.27 + alcove_h / 2)
        tree.links.new(tbp.outputs['Mesh'], tbpt.inputs['Geometry'])
        parts.append(tbpt.outputs['Geometry'])

    # Ro (炉) — sunken hearth in tatami floor
    if getattr(props, 'teahouse_ro', True):
        ro = tree.nodes.new('GeometryNodeMeshCube'); ro.location = (base_x, 1700); color_node(ro, "house")
        ro.inputs['Size'].default_value = (W * 0.22, D * 0.22, 0.08)
        rot = tree.nodes.new('GeometryNodeTransform'); rot.location = (base_x+200, 1700)
        rot.inputs['Translation'].default_value = (W * 0.12, -D * 0.08, 0.22)
        tree.links.new(ro.outputs['Mesh'], rot.inputs['Geometry'])
        parts.append(rot.outputs['Geometry'])

    # Nijiriguchi (躙口) — low crawl entrance opening
    if getattr(props, 'teahouse_nijiriguchi', False):
        niw = W * 0.35
        nih = H * 0.38
        niche = tree.nodes.new('GeometryNodeMeshCube'); niche.location = (base_x, 1800); color_node(niche, "house")
        niche.inputs['Size'].default_value = (niw, 0.12, nih)
        nit = tree.nodes.new('GeometryNodeTransform'); nit.location = (base_x+200, 1800)
        nit.inputs['Translation'].default_value = (0, -D / 2 + 0.08, 0.27 + nih / 2)
        tree.links.new(niche.outputs['Mesh'], nit.inputs['Geometry'])
        parts.append(nit.outputs['Geometry'])

    # Chumon (中門) — roji inner gate posts on engawa approach
    if getattr(props, 'teahouse_chumon', False) and props.teahouse_engawa:
        gate_w = platform_W * 0.55
        for gx in (-gate_w / 2, gate_w / 2):
            gp = tree.nodes.new('GeometryNodeMeshCylinder'); gp.location = (base_x, 1900); color_node(gp, "ornament")
            gp.inputs['Vertices'].default_value = 8
            gp.inputs['Radius'].default_value = 0.05
            gp.inputs['Depth'].default_value = 1.1
            gpt = tree.nodes.new('GeometryNodeTransform'); gpt.location = (base_x+200, 1900)
            gpt.inputs['Translation'].default_value = (gx, -platform_D / 2 - 0.15, 0.25 + 0.55)
            tree.links.new(gp.outputs['Mesh'], gpt.inputs['Geometry'])
            parts.append(gpt.outputs['Geometry'])
        lintel = tree.nodes.new('GeometryNodeMeshCube'); lintel.location = (base_x, 2000); color_node(lintel, "ornament")
        lintel.inputs['Size'].default_value = (gate_w + 0.2, 0.08, 0.08)
        lt = tree.nodes.new('GeometryNodeTransform'); lt.location = (base_x+200, 2000)
        lt.inputs['Translation'].default_value = (0, -platform_D / 2 - 0.15, 0.25 + 1.05)
        tree.links.new(lintel.outputs['Mesh'], lt.inputs['Geometry'])
        parts.append(lt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2600, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_zen_bridge(tree, props, base_x=-1400):
    """Taikobashi / soribashi (太鼓橋 / 反橋) — moon drum garden bridge."""
    span = props.zen_bridge_span
    rise = props.zen_bridge_rise
    width = props.zen_bridge_width
    n_planks = props.zen_bridge_planks
    style = getattr(props, 'zen_bridge_style', 'TAIKOBASHI')
    show_giboshi = getattr(props, 'zen_bridge_giboshi', True)
    rise_mul = 2.0 if style == 'TAIKOBASHI' else 1.25
    arc_lift = rise * rise_mul
    parts = []

    # Build the bridge arc as a curve
    arc = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); arc.location = (base_x, 0); color_node(arc, "house")
    arc.inputs['Resolution'].default_value = 32
    arc.inputs['Start'].default_value         = (-span/2, 0, 0)
    arc.inputs['Start Handle'].default_value  = (-span/4, 0, arc_lift)
    arc.inputs['End Handle'].default_value    = ( span/4, 0, arc_lift)
    arc.inputs['End'].default_value           = ( span/2, 0, 0)

    # Rectangle profile for the walkway
    rect = tree.nodes.new('GeometryNodeCurvePrimitiveQuadrilateral'); rect.location = (base_x, -300); color_node(rect, "house")
    try:
        rect.mode = 'RECTANGLE'
        rect.inputs['Width'].default_value = width
        rect.inputs['Height'].default_value = 0.08
    except Exception: pass

    # Sweep deck
    deck = tree.nodes.new('GeometryNodeCurveToMesh'); deck.location = (base_x+300, 0)
    tree.links.new(arc.outputs['Curve'], deck.inputs['Curve'])
    tree.links.new(rect.outputs['Curve'], deck.inputs['Profile Curve'])
    deck.inputs['Fill Caps'].default_value = True
    parts.append(deck.outputs['Mesh'])

    # Plank cross-pieces — resampled ALONG the arc so they ride the curve,
    # rotation-aligned to the tangent so each plank tilts with the slope.
    plank_arc = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); plank_arc.location = (base_x, 300); color_node(plank_arc, "house")
    plank_arc.inputs['Resolution'].default_value = 32
    plank_arc.inputs['Start'].default_value        = (-span/2, 0, 0.05)
    plank_arc.inputs['Start Handle'].default_value = (-span/4, 0, arc_lift + 0.05)
    plank_arc.inputs['End Handle'].default_value   = ( span/4, 0, arc_lift + 0.05)
    plank_arc.inputs['End'].default_value          = ( span/2, 0, 0.05)

    presample = tree.nodes.new('GeometryNodeResampleCurve'); presample.location = (base_x+200, 300); color_node(presample, "house")
    try: presample.mode = 'COUNT'
    except Exception: pass
    presample.inputs['Count'].default_value = n_planks
    tree.links.new(plank_arc.outputs['Curve'], presample.inputs['Curve'])

    pc2p = tree.nodes.new('GeometryNodeCurveToPoints'); pc2p.location = (base_x+380, 300); color_node(pc2p, "house")
    try: pc2p.mode = 'EVALUATED'
    except Exception: pass
    tree.links.new(presample.outputs['Curve'], pc2p.inputs['Curve'])

    plank = tree.nodes.new('GeometryNodeMeshCube'); plank.location = (base_x, 500); color_node(plank, "house")
    plank.inputs['Size'].default_value = (span / max(1, n_planks) * 0.85, width * 1.05, 0.045)

    inst = tree.nodes.new('GeometryNodeInstanceOnPoints'); inst.location = (base_x+600, 400)
    tree.links.new(pc2p.outputs['Points'], inst.inputs['Points'])
    tree.links.new(plank.outputs['Mesh'], inst.inputs['Instance'])
    try:
        tree.links.new(pc2p.outputs['Rotation'], inst.inputs['Rotation'])
    except Exception:
        pass
    realize = tree.nodes.new('GeometryNodeRealizeInstances'); realize.location = (base_x+820, 400)
    tree.links.new(inst.outputs['Instances'], realize.inputs['Geometry'])
    parts.append(realize.outputs['Geometry'])

    # Optional side railings
    if props.zen_bridge_railings:
        for y_off in (-width/2 + 0.04, width/2 - 0.04):
            # railing arc parallel to deck arc, offset in Y and up
            rail_arc = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); rail_arc.location = (base_x, 800)
            rail_arc.inputs['Resolution'].default_value = 32
            rail_arc.inputs['Start'].default_value        = (-span/2, y_off, 0.5)
            rail_arc.inputs['Start Handle'].default_value = (-span/4, y_off, arc_lift + 0.5)
            rail_arc.inputs['End Handle'].default_value   = ( span/4, y_off, arc_lift + 0.5)
            rail_arc.inputs['End'].default_value          = ( span/2, y_off, 0.5)

            rprof = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); rprof.location = (base_x, 900)
            rprof.mode = 'RADIUS'
            rprof.inputs['Resolution'].default_value = 8
            rprof.inputs['Radius'].default_value = 0.03

            rs = tree.nodes.new('GeometryNodeCurveToMesh'); rs.location = (base_x+300, 800)
            tree.links.new(rail_arc.outputs['Curve'], rs.inputs['Curve'])
            tree.links.new(rprof.outputs['Curve'], rs.inputs['Profile Curve'])
            parts.append(rs.outputs['Mesh'])

            # Vertical balusters from the deck up to the rail, spaced along the arc
            n_balu = max(4, n_planks // 2)
            deck_arc = tree.nodes.new('GeometryNodeCurvePrimitiveBezierSegment'); deck_arc.location = (base_x, 1100)
            deck_arc.inputs['Resolution'].default_value = 32
            deck_arc.inputs['Start'].default_value        = (-span/2, y_off, 0.05)
            deck_arc.inputs['Start Handle'].default_value = (-span/4, y_off, arc_lift + 0.05)
            deck_arc.inputs['End Handle'].default_value   = ( span/4, y_off, arc_lift + 0.05)
            deck_arc.inputs['End'].default_value          = ( span/2, y_off, 0.05)
            brs = tree.nodes.new('GeometryNodeResampleCurve'); brs.location = (base_x+200, 1100)
            try: brs.mode = 'COUNT'
            except Exception: pass
            brs.inputs['Count'].default_value = n_balu
            tree.links.new(deck_arc.outputs['Curve'], brs.inputs['Curve'])
            bp = tree.nodes.new('GeometryNodeCurveToPoints'); bp.location = (base_x+380, 1100)
            try: bp.mode = 'EVALUATED'
            except Exception: pass
            tree.links.new(brs.outputs['Curve'], bp.inputs['Curve'])
            balu = tree.nodes.new('GeometryNodeMeshCylinder'); balu.location = (base_x, 1300); color_node(balu, "house")
            balu.inputs['Vertices'].default_value = 6
            balu.inputs['Radius'].default_value = 0.025
            balu.inputs['Depth'].default_value = 0.45
            bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, 1300)
            bt.inputs['Translation'].default_value = (0, 0, 0.225)
            tree.links.new(balu.outputs['Mesh'], bt.inputs['Geometry'])
            binst = tree.nodes.new('GeometryNodeInstanceOnPoints'); binst.location = (base_x+600, 1100)
            tree.links.new(bp.outputs['Points'], binst.inputs['Points'])
            tree.links.new(bt.outputs['Geometry'], binst.inputs['Instance'])
            brz = tree.nodes.new('GeometryNodeRealizeInstances'); brz.location = (base_x+820, 1100)
            tree.links.new(binst.outputs['Instances'], brz.inputs['Geometry'])
            parts.append(brz.outputs['Geometry'])

            # Giboshi (擬宝珠) finials on railing ends
            if show_giboshi:
                for ex in (-span / 2, span / 2):
                    gb = tree.nodes.new('GeometryNodeMeshUVSphere'); gb.location = (base_x, 1500)
                    gb.inputs['Radius'].default_value = 0.055
                    gbt = tree.nodes.new('GeometryNodeTransform'); gbt.location = (base_x+200, 1500)
                    gbt.inputs['Translation'].default_value = (ex, y_off, arc_lift * 0.85 + 0.55)
                    gbt.inputs['Scale'].default_value = (1.0, 1.0, 1.35)
                    tree.links.new(gb.outputs['Mesh'], gbt.inputs['Geometry'])
                    color_node(gbt, "ornament")
                    parts.append(gbt.outputs['Geometry'])

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_zen_stone_garden(tree, props, base_x=-1400):
    """Karesansui (枯山水) — samon (砂紋) ripples + ishigumi stone groups."""
    size = props.stone_garden_size
    n_stones = props.stone_garden_stones
    n_ripples = props.stone_garden_ripples
    parts = []

    # Sand base
    base = tree.nodes.new('GeometryNodeMeshCube'); base.location = (base_x, 0); color_node(base, "house")
    base.inputs['Size'].default_value = (size, size, 0.06)
    bt = tree.nodes.new('GeometryNodeTransform'); bt.location = (base_x+200, 0)
    bt.inputs['Translation'].default_value = (0, 0, 0.03)
    tree.links.new(base.outputs['Mesh'], bt.inputs['Geometry'])
    parts.append(bt.outputs['Geometry'])

    # Tsukubai (蹲踞) — stone washbasin at roji edge
    if getattr(props, 'stone_garden_tsukubai', False):
        bx = size * 0.38
        by = -size * 0.32
        basin = tree.nodes.new('GeometryNodeMeshCylinder'); basin.location = (base_x, -200); color_node(basin, "house")
        basin.inputs['Vertices'].default_value = 16
        basin.inputs['Radius'].default_value = size * 0.09
        basin.inputs['Depth'].default_value = size * 0.07
        bt2 = tree.nodes.new('GeometryNodeTransform'); bt2.location = (base_x+200, -200)
        bt2.inputs['Translation'].default_value = (bx, by, size * 0.035)
        tree.links.new(basin.outputs['Mesh'], bt2.inputs['Geometry'])
        parts.append(bt2.outputs['Geometry'])
        rim = tree.nodes.new('GeometryNodeMeshTorus'); rim.location = (base_x, -350); color_node(rim, "house")
        rim.inputs['Major Radius'].default_value = size * 0.095
        rim.inputs['Minor Radius'].default_value = size * 0.018
        rim.inputs['Major Segments'].default_value = 24
        rim.inputs['Minor Segments'].default_value = 6
        rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+200, -350)
        rt.inputs['Translation'].default_value = (bx, by, size * 0.07)
        rt.inputs['Scale'].default_value = (1.0, 1.0, 0.35)
        tree.links.new(rim.outputs['Mesh'], rt.inputs['Geometry'])
        parts.append(rt.outputs['Geometry'])

    # Concentric ripple rings — built as torus-like tubes
    for i in range(n_ripples):
        r = (i + 1) / max(1, n_ripples) * (size * 0.45)
        ring = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); ring.location = (base_x, 200 + i * 80); color_node(ring, "ornament")
        ring.mode = 'RADIUS'
        ring.inputs['Resolution'].default_value = 48
        ring.inputs['Radius'].default_value = r
        rt = tree.nodes.new('GeometryNodeTransform'); rt.location = (base_x+200, 200 + i * 80)
        rt.inputs['Translation'].default_value = (0, 0, 0.07)
        rt.inputs['Rotation'].default_value = (0, 0, 0)
        tree.links.new(ring.outputs['Curve'], rt.inputs['Geometry'])

        prof = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); prof.location = (base_x+400, 200 + i * 80)
        prof.mode = 'RADIUS'
        prof.inputs['Resolution'].default_value = 6
        prof.inputs['Radius'].default_value = 0.015

        s = tree.nodes.new('GeometryNodeCurveToMesh'); s.location = (base_x+600, 200 + i * 80)
        tree.links.new(rt.outputs['Geometry'], s.inputs['Curve'])
        tree.links.new(prof.outputs['Curve'], s.inputs['Profile Curve'])
        parts.append(s.outputs['Mesh'])

    # Stones (icospheres at varied positions)
    import random
    rng = random.Random(getattr(props, 'sv_seed', 42))

    placed_count = 0
    # Sanzon-ishigumi (三尊石組) — Buddha triad: chūshu + waki/soe stones
    if props.stone_garden_sansonseki:
        # chūshu (中主) master, waki-ishi (脇石) attendant, soe-ishi (添石) companion
        ctr_x = rng.uniform(-size * 0.15, size * 0.15)
        ctr_y = rng.uniform(-size * 0.15, size * 0.15)
        triad = [
            # (offset_x, offset_y, radius, scale_xyz)
            (0.0,            0.0,              size * 0.10, (1.0, 0.9, 1.5)),    # master — tall vertical
            (size * 0.20,    size * 0.10,      size * 0.07, (1.2, 0.8, 0.6)),    # attendant — flat low
            (-size * 0.12,   size * 0.18,      size * 0.05, (1.0, 0.9, 0.8)),    # companion — medium
        ]
        for j, (dx, dy, r, sc) in enumerate(triad):
            stone = tree.nodes.new('GeometryNodeMeshIcoSphere'); stone.location = (base_x, 1500 + placed_count * 100); color_node(stone, "house")
            stone.inputs['Subdivisions'].default_value = 2
            stone.inputs['Radius'].default_value = r
            st = tree.nodes.new('GeometryNodeTransform'); st.location = (base_x+200, 1500 + placed_count * 100)
            st.inputs['Translation'].default_value = (ctr_x + dx, ctr_y + dy, 0.06 + r * sc[2] * 0.5)
            st.inputs['Scale'].default_value = sc
            st.inputs['Rotation'].default_value = (0, 0, rng.uniform(0, math.tau))
            tree.links.new(stone.outputs['Mesh'], st.inputs['Geometry'])
            parts.append(st.outputs['Geometry'])
            placed_count += 1

    # Additional scattered stones
    remaining = max(0, n_stones - placed_count)
    for i in range(remaining):
        # Place avoiding the triad area
        for _attempt in range(8):
            x = rng.uniform(-size * 0.4, size * 0.4)
            y = rng.uniform(-size * 0.4, size * 0.4)
            if props.stone_garden_sansonseki:
                if math.hypot(x - ctr_x, y - ctr_y) > size * 0.3: break
            else: break
        stone_r = rng.uniform(size * 0.04, size * 0.10)
        stone = tree.nodes.new('GeometryNodeMeshIcoSphere'); stone.location = (base_x, 1500 + placed_count * 100); color_node(stone, "house")
        stone.inputs['Subdivisions'].default_value = 2
        stone.inputs['Radius'].default_value = stone_r
        st = tree.nodes.new('GeometryNodeTransform'); st.location = (base_x+200, 1500 + placed_count * 100)
        st.inputs['Translation'].default_value = (x, y, 0.06 + stone_r * 0.6)
        st.inputs['Scale'].default_value = (1.0, rng.uniform(0.7, 1.0), rng.uniform(0.5, 0.9))
        st.inputs['Rotation'].default_value = (0, 0, rng.uniform(0, math.tau))
        tree.links.new(stone.outputs['Mesh'], st.inputs['Geometry'])
        parts.append(st.outputs['Geometry'])
        placed_count += 1

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1000, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# ADVANCED WALL BUILDERS (multi-pane, arched, bay)
# ----------------------------------------------------------------------

def build_wall_multi_window(tree, props, base_x=-1400):
    """Wall with grid of mullioned windows — adjustable rows × cols."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    nx = props.wall_window_grid_x
    ny = props.wall_window_grid_y
    mull = props.wall_window_mullion
    parts = []

    # Compute window opening area (with margin from frame)
    margin = max(props.wall_frame_width if hasattr(props, 'wall_frame_width') else 0.2, 0.3)
    win_total_W = L - margin * 2
    win_total_H = H - margin * 2

    # Compute single pane size
    pane_W = (win_total_W - mull * (nx - 1)) / nx
    pane_H = (win_total_H - mull * (ny - 1)) / ny

    # Wall pieces: jambs + sill + header + horizontal/vertical mullions
    # Left & right jambs
    for x_off in (-(L - margin)/2, +(L - margin)/2):
        slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, len(parts) * 100); color_node(slab, "wall")
        slab.inputs['Size'].default_value = (margin, T, H)
        s_t = tree.nodes.new('GeometryNodeTransform'); s_t.location = (base_x+200, len(parts) * 100)
        s_t.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(slab.outputs['Mesh'], s_t.inputs['Geometry'])
        parts.append(s_t.outputs['Geometry'])

    # Sill (below window grid)
    sill = tree.nodes.new('GeometryNodeMeshCube'); sill.location = (base_x, 500); color_node(sill, "wall")
    sill.inputs['Size'].default_value = (L - margin * 2, T, margin)
    sill_t = tree.nodes.new('GeometryNodeTransform'); sill_t.location = (base_x+200, 500)
    sill_t.inputs['Translation'].default_value = (0, 0, margin/2)
    tree.links.new(sill.outputs['Mesh'], sill_t.inputs['Geometry'])
    parts.append(sill_t.outputs['Geometry'])

    # Header (above window grid)
    head = tree.nodes.new('GeometryNodeMeshCube'); head.location = (base_x, 700); color_node(head, "wall")
    head.inputs['Size'].default_value = (L - margin * 2, T, margin)
    head_t = tree.nodes.new('GeometryNodeTransform'); head_t.location = (base_x+200, 700)
    head_t.inputs['Translation'].default_value = (0, 0, H - margin/2)
    tree.links.new(head.outputs['Mesh'], head_t.inputs['Geometry'])
    parts.append(head_t.outputs['Geometry'])

    # Vertical mullions
    for i in range(1, nx):
        x = -win_total_W/2 + i * (pane_W + mull) - mull/2
        m_node = tree.nodes.new('GeometryNodeMeshCube'); m_node.location = (base_x, 900 + i * 80); color_node(m_node, "wall")
        m_node.inputs['Size'].default_value = (mull, T * 1.1, win_total_H)
        m_t = tree.nodes.new('GeometryNodeTransform'); m_t.location = (base_x+200, 900 + i * 80)
        m_t.inputs['Translation'].default_value = (x, 0, H/2)
        tree.links.new(m_node.outputs['Mesh'], m_t.inputs['Geometry'])
        parts.append(m_t.outputs['Geometry'])

    # Horizontal mullions
    for j in range(1, ny):
        z = margin + j * (pane_H + mull) - mull/2
        m_node = tree.nodes.new('GeometryNodeMeshCube'); m_node.location = (base_x, 1400 + j * 80); color_node(m_node, "wall")
        m_node.inputs['Size'].default_value = (win_total_W, T * 1.1, mull)
        m_t = tree.nodes.new('GeometryNodeTransform'); m_t.location = (base_x+200, 1400 + j * 80)
        m_t.inputs['Translation'].default_value = (0, 0, z)
        tree.links.new(m_node.outputs['Mesh'], m_t.inputs['Geometry'])
        parts.append(m_t.outputs['Geometry'])

    # Optional glass plane (recessed)
    glass = tree.nodes.new('GeometryNodeMeshCube'); glass.location = (base_x, 1800); color_node(glass, "ornament")
    glass.inputs['Size'].default_value = (win_total_W, mull * 0.5, win_total_H)
    g_t = tree.nodes.new('GeometryNodeTransform'); g_t.location = (base_x+200, 1800)
    g_t.inputs['Translation'].default_value = (0, T * 0.3, H/2)
    tree.links.new(glass.outputs['Mesh'], g_t.inputs['Geometry'])
    parts.append(g_t.outputs['Geometry'])

    # Baseboard/cornice
    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x + 2500))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+2800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_wall_arched_window(tree, props, base_x=-1400):
    """Wall with an arched-top window — round arch above rectangular opening."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    WW = min(props.wall_window_width, L * 0.6)
    WH = min(props.wall_window_height, H * 0.55)
    arch_R = props.wall_arched_radius
    sill = props.wall_window_sill
    parts = []

    side_w = (L - WW) / 2
    # Side jambs
    for x_off in (-(L - side_w)/2, +(L - side_w)/2):
        slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, len(parts) * 100); color_node(slab, "wall")
        slab.inputs['Size'].default_value = (side_w, T, H)
        s_t = tree.nodes.new('GeometryNodeTransform'); s_t.location = (base_x+200, len(parts) * 100)
        s_t.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(slab.outputs['Mesh'], s_t.inputs['Geometry'])
        parts.append(s_t.outputs['Geometry'])

    # Sill block
    sill_block = tree.nodes.new('GeometryNodeMeshCube'); sill_block.location = (base_x, 500); color_node(sill_block, "wall")
    sill_block.inputs['Size'].default_value = (WW, T, sill)
    sb_t = tree.nodes.new('GeometryNodeTransform'); sb_t.location = (base_x+200, 500)
    sb_t.inputs['Translation'].default_value = (0, 0, sill/2)
    tree.links.new(sill_block.outputs['Mesh'], sb_t.inputs['Geometry'])
    parts.append(sb_t.outputs['Geometry'])

    # Arched top — half circle filling the top portion
    arc = tree.nodes.new('GeometryNodeCurveArc'); arc.location = (base_x, 800); color_node(arc, "wall")
    arc.mode = 'RADIUS'
    arc.inputs['Resolution'].default_value = 24
    arc.inputs['Radius'].default_value = arch_R
    arc.inputs['Sweep Angle'].default_value = math.radians(180)

    arc_t = tree.nodes.new('GeometryNodeTransform'); arc_t.location = (base_x+200, 800)
    arc_t.inputs['Translation'].default_value = (0, 0, sill + WH)
    arc_t.inputs['Rotation'].default_value = (math.radians(90), 0, 0)
    tree.links.new(arc.outputs['Curve'], arc_t.inputs['Geometry'])

    # Sweep with profile to make arched frame
    prof = tree.nodes.new('GeometryNodeCurvePrimitiveCircle'); prof.location = (base_x, 1000)
    prof.mode = 'RADIUS'
    prof.inputs['Resolution'].default_value = 8
    prof.inputs['Radius'].default_value = T * 0.5

    arc_sweep = tree.nodes.new('GeometryNodeCurveToMesh'); arc_sweep.location = (base_x+400, 800)
    tree.links.new(arc_t.outputs['Geometry'], arc_sweep.inputs['Curve'])
    tree.links.new(prof.outputs['Curve'], arc_sweep.inputs['Profile Curve'])
    arc_sweep.inputs['Fill Caps'].default_value = True
    parts.append(arc_sweep.outputs['Mesh'])

    # Wall above the arch
    top_h = H - sill - WH - arch_R
    if top_h > 0.02:
        top = tree.nodes.new('GeometryNodeMeshCube'); top.location = (base_x, 1200); color_node(top, "wall")
        top.inputs['Size'].default_value = (WW, T, top_h)
        top_t = tree.nodes.new('GeometryNodeTransform'); top_t.location = (base_x+200, 1200)
        top_t.inputs['Translation'].default_value = (0, 0, sill + WH + arch_R + top_h/2)
        tree.links.new(top.outputs['Mesh'], top_t.inputs['Geometry'])
        parts.append(top_t.outputs['Geometry'])

    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x + 1500))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1800, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


def build_wall_bay_window(tree, props, base_x=-1400):
    """Wall with projecting bay window — trapezoidal projection forward from main wall."""
    L = props.wall_segments * props.unit_size
    H = props.wall_height
    T = props.wall_thickness
    bay_W = min(props.wall_window_width, L * 0.6)
    bay_D = props.wall_bay_depth
    sides = props.wall_bay_sides
    sill = props.wall_window_sill
    bay_H = min(props.wall_window_height, H * 0.7)
    parts = []

    # Side walls flanking the bay opening
    side_w = (L - bay_W) / 2
    for x_off in (-(L - side_w)/2, +(L - side_w)/2):
        slab = tree.nodes.new('GeometryNodeMeshCube'); slab.location = (base_x, len(parts) * 100); color_node(slab, "wall")
        slab.inputs['Size'].default_value = (side_w, T, H)
        s_t = tree.nodes.new('GeometryNodeTransform'); s_t.location = (base_x+200, len(parts) * 100)
        s_t.inputs['Translation'].default_value = (x_off, 0, H/2)
        tree.links.new(slab.outputs['Mesh'], s_t.inputs['Geometry'])
        parts.append(s_t.outputs['Geometry'])

    # Bay projection — a 5-sided box that sticks forward
    # Front face (parallel to wall, offset bay_D forward)
    front_W = bay_W * (1.0 - 0.2 * sides / 3)
    front = tree.nodes.new('GeometryNodeMeshCube'); front.location = (base_x, 500); color_node(front, "wall")
    front.inputs['Size'].default_value = (front_W, T, bay_H)
    f_t = tree.nodes.new('GeometryNodeTransform'); f_t.location = (base_x+200, 500)
    f_t.inputs['Translation'].default_value = (0, bay_D, sill + bay_H/2)
    tree.links.new(front.outputs['Mesh'], f_t.inputs['Geometry'])
    parts.append(f_t.outputs['Geometry'])

    # Angled side panels (trapezoidal)
    panel_len = math.sqrt(bay_D**2 + ((bay_W - front_W)/2)**2)
    for side_sign in (-1, 1):
        panel = tree.nodes.new('GeometryNodeMeshCube'); panel.location = (base_x, 700); color_node(panel, "wall")
        panel.inputs['Size'].default_value = (panel_len, T, bay_H)
        p_t = tree.nodes.new('GeometryNodeTransform'); p_t.location = (base_x+200, 700)
        # Position at midpoint between corner and front edge
        mid_x = side_sign * (bay_W/2 + front_W/2) / 2
        mid_y = bay_D / 2
        p_t.inputs['Translation'].default_value = (mid_x, mid_y, sill + bay_H/2)
        # Rotate to align with the angled wall
        angle = math.atan2(bay_D, (bay_W - front_W) / 2)
        p_t.inputs['Rotation'].default_value = (0, 0, side_sign * (math.pi/2 - angle))
        tree.links.new(panel.outputs['Mesh'], p_t.inputs['Geometry'])
        parts.append(p_t.outputs['Geometry'])

    # Bay floor & ceiling (caps at bottom and top of bay opening)
    for cap_z, cap_h in [(sill, 0.08), (sill + bay_H, 0.08)]:
        cap = tree.nodes.new('GeometryNodeMeshCube'); cap.location = (base_x, 900 + int(cap_z * 100)); color_node(cap, "wall")
        cap.inputs['Size'].default_value = (bay_W, bay_D * 1.05, cap_h)
        c_t = tree.nodes.new('GeometryNodeTransform'); c_t.location = (base_x+200, 900 + int(cap_z * 100))
        c_t.inputs['Translation'].default_value = (0, bay_D * 0.55, cap_z + cap_h/2)
        tree.links.new(cap.outputs['Mesh'], c_t.inputs['Geometry'])
        parts.append(c_t.outputs['Geometry'])

    # Wall above bay
    top_h = H - (sill + bay_H + 0.1)
    if top_h > 0.05:
        top = tree.nodes.new('GeometryNodeMeshCube'); top.location = (base_x, 1300); color_node(top, "wall")
        top.inputs['Size'].default_value = (bay_W, T, top_h)
        top_t = tree.nodes.new('GeometryNodeTransform'); top_t.location = (base_x+200, 1300)
        top_t.inputs['Translation'].default_value = (0, 0, sill + bay_H + 0.05 + top_h/2)
        tree.links.new(top.outputs['Mesh'], top_t.inputs['Geometry'])
        parts.append(top_t.outputs['Geometry'])

    parts.extend(_wall_baseboard_and_cornice(tree, props, L, base_x + 1600))

    join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (base_x+1900, 0); color_node(join, "output")
    for p in parts: tree.links.new(p, join.inputs['Geometry'])
    return join.outputs['Geometry']


# ----------------------------------------------------------------------
# UNIVERSAL POST-PASS — make ANY type respond to musical params
# ----------------------------------------------------------------------

def add_universal_music_pass(tree, in_geom, props, x=10500):
    """
    Apply a radial pulse driven by harmonics (musical 'breathing') to ANY geometry.
    Influence is gated by props.universal_music_influence.
    """
    if props.universal_music_influence < 0.001:
        return in_geom

    pos = tree.nodes.new('GeometryNodeInputPosition'); pos.location = (x, 200); color_node(pos, "input")
    sep = tree.nodes.new('ShaderNodeSeparateXYZ'); sep.location = (x+200, 200)
    tree.links.new(pos.outputs['Position'], sep.inputs['Vector'])

    # Use Z*freq_a + atan(y/x)*freq_b as harmonic phase
    z_freq = tree.nodes.new('ShaderNodeMath'); z_freq.location = (x+400, 200); z_freq.operation = 'MULTIPLY'
    z_freq.inputs[1].default_value = props.musical_freq_a * NOTE_PATTERNS.get(props.note_pattern, 4.0) * props.tempo_factor / 4.0
    tree.links.new(sep.outputs['Z'], z_freq.inputs[0])
    sine_z = tree.nodes.new('ShaderNodeMath'); sine_z.location = (x+600, 200); sine_z.operation = 'SINE'
    tree.links.new(z_freq.outputs['Value'], sine_z.inputs[0])
    color_node(sine_z, "music")

    # Atan2(y, x) for radial phase
    atan2 = tree.nodes.new('ShaderNodeMath'); atan2.location = (x+400, 0); atan2.operation = 'ARCTAN2'
    tree.links.new(sep.outputs['Y'], atan2.inputs[0])
    tree.links.new(sep.outputs['X'], atan2.inputs[1])
    a_freq = tree.nodes.new('ShaderNodeMath'); a_freq.location = (x+600, 0); a_freq.operation = 'MULTIPLY'
    a_freq.inputs[1].default_value = props.musical_freq_b * NOTE_PATTERNS.get(props.note_pattern, 4.0) * props.tempo_factor / 4.0
    tree.links.new(atan2.outputs['Value'], a_freq.inputs[0])
    sine_a = tree.nodes.new('ShaderNodeMath'); sine_a.location = (x+800, 0); sine_a.operation = 'SINE'
    tree.links.new(a_freq.outputs['Value'], sine_a.inputs[0])

    # Sum harmonics, scale by universal_music_influence × musical_amplitude
    add = tree.nodes.new('ShaderNodeMath'); add.location = (x+800, 100); add.operation = 'ADD'
    tree.links.new(sine_z.outputs['Value'], add.inputs[0])
    tree.links.new(sine_a.outputs['Value'], add.inputs[1])

    amp = tree.nodes.new('ShaderNodeMath'); amp.location = (x+1000, 100); amp.operation = 'MULTIPLY'
    amp.inputs[1].default_value = props.universal_music_influence * props.musical_amplitude * 0.4
    tree.links.new(add.outputs['Value'], amp.inputs[0])
    color_node(amp, "universal")

    # Radial direction (XY normalized)
    rxy = tree.nodes.new('ShaderNodeCombineXYZ'); rxy.location = (x+800, -200)
    tree.links.new(sep.outputs['X'], rxy.inputs['X'])
    tree.links.new(sep.outputs['Y'], rxy.inputs['Y'])
    rxy.inputs['Z'].default_value = 0
    norm = tree.nodes.new('ShaderNodeVectorMath'); norm.location = (x+1000, -200); norm.operation = 'NORMALIZE'
    tree.links.new(rxy.outputs['Vector'], norm.inputs[0])

    pulse = tree.nodes.new('ShaderNodeVectorMath'); pulse.location = (x+1200, -100); pulse.operation = 'SCALE'
    tree.links.new(norm.outputs['Vector'], pulse.inputs[0])
    tree.links.new(amp.outputs['Value'], pulse.inputs['Scale'])

    set_pos = tree.nodes.new('GeometryNodeSetPosition'); set_pos.location = (x+1400, 0); color_node(set_pos, "universal")
    tree.links.new(in_geom, set_pos.inputs['Geometry'])
    tree.links.new(pulse.outputs[0], set_pos.inputs['Offset'])
    return set_pos.outputs['Geometry']



# ======================================================================
# Baroque / Classical architecture builders (v2.58)
# Ported from BAROQUE_COMPONENT_LIBRARY.py — uses main-addon GN helpers.
# ======================================================================

def _baroque_barrel_vault(tree, span, depth, rise, base_x=-1400):
    """Barrel vault: semicircular CurveArc swept along depth (CurveToMesh)."""
    import math as _m
    res = max(16, int(span * 4))
    arc = _safe_node(tree, 'GeometryNodeCurveArc', (base_x, 0))
    if arc:
        try:
            arc.mode = 'RADIUS'
            arc.inputs['Radius'].default_value = span * 0.5
            arc.inputs['Start Angle'].default_value = 0.0
            arc.inputs['Sweep Angle'].default_value = _m.pi
            arc.inputs['Resolution'].default_value = res
        except Exception:
            pass
        arc_rot = _safe_node(tree, 'GeometryNodeTransform', (base_x + 200, 0))
        if arc_rot:
            try:
                arc_rot.inputs['Rotation'].default_value = (_m.radians(90), 0, 0)
                arc_rot.inputs['Translation'].default_value = (0, 0, rise * 0.5)
            except Exception:
                pass
            _link(tree, arc.outputs['Curve'], arc_rot.inputs['Geometry'])
            shell_t = max(span, depth) * 0.035
            prof = _rect_profile(tree, (base_x + 100, 0), depth * 0.98, shell_t, 'vault')
            c2m = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 400, 0))
            if c2m and prof:
                _link(tree, arc_rot.outputs['Geometry'], c2m.inputs['Curve'])
                _link(tree, prof, c2m.inputs['Profile Curve'])
                try:
                    c2m.inputs['Fill Caps'].default_value = True
                except Exception:
                    pass
                color_node(c2m, 'vault')
                z_scale = rise / max(span * 0.5, 0.01)
                if abs(z_scale - 1.0) > 0.02:
                    sc = _safe_node(tree, 'GeometryNodeScale', (base_x + 600, 0))
                    if sc:
                        try:
                            sc.inputs['Scale'].default_value = (1.0, 1.0, z_scale)
                        except Exception:
                            pass
                        _link(tree, c2m.outputs['Mesh'], sc.inputs['Geometry'])
                        color_node(sc, 'vault')
                        return sc.outputs['Geometry']
                return c2m.outputs['Mesh']
    cube = _node(tree, 'GeometryNodeMeshCube', (base_x, 0))
    try:
        cube.inputs['Size'].default_value = (span * 0.95, depth * 0.95, rise * 0.65)
    except Exception:
        cube.inputs['Size X'].default_value = span * 0.95
        cube.inputs['Size Y'].default_value = depth * 0.95
        cube.inputs['Size Z'].default_value = rise * 0.65
    color_node(cube, 'vault')
    tr = _node(tree, 'GeometryNodeTransform', (base_x + 200, 0))
    tr.inputs['Translation'].default_value = (0, 0, rise * 0.35)
    _link(tree, cube.outputs['Mesh'], tr.inputs['Geometry'])
    color_node(tr, 'vault')
    return tr.outputs['Geometry']


def _baroque_groin_vault(tree, span, depth, rise, base_x=-1400):
    sph = _node(tree, 'GeometryNodeMeshUVSphere', (base_x, 0))
    sph.inputs['Radius'].default_value = span * 0.4
    sph.inputs['Segments'].default_value = 16
    sph.inputs['Rings'].default_value = 12
    color_node(sph, 'vault')
    sc = _node(tree, 'GeometryNodeScale', (base_x + 200, 0))
    sc.inputs['Scale'].default_value = (span * 0.6, depth * 0.6, rise * 0.45)
    _link(tree, sph.outputs['Mesh'], sc.inputs['Geometry'])
    tr = _node(tree, 'GeometryNodeTransform', (base_x + 400, 0))
    tr.inputs['Translation'].default_value = (0, 0, rise * 0.5)
    _link(tree, sc.outputs['Geometry'], tr.inputs['Geometry'])
    return tr.outputs['Geometry']


def _baroque_ribbed_vault(tree, span, depth, rise, rib_count, base_x=-1400):
    base = _baroque_barrel_vault(tree, span, depth, rise, base_x)
    parts = [base] if base else []
    import math as _m
    for i in range(max(4, rib_count)):
        x = -span * 0.4 + (i / max(1, rib_count - 1)) * span * 0.8
        rib = _node(tree, 'GeometryNodeMeshCube', (base_x + 600, i * 40))
        rib.inputs['Size X'].default_value = span * 0.04
        rib.inputs['Size Y'].default_value = depth * 0.98
        rib.inputs['Size Z'].default_value = rise * 1.1
        color_node(rib, 'vault')
        tr = _node(tree, 'GeometryNodeTransform', (base_x + 800, i * 40))
        tr.inputs['Translation'].default_value = (x, 0, rise * 0.45)
        _link(tree, rib.outputs['Mesh'], tr.inputs['Geometry'])
        parts.append(tr.outputs['Geometry'])
    return _gb_join(tree, parts, base_x + 1000, 0) if parts else base


def _baroque_pilaster_geom(tree, width, height, base_x=-1400, y=0):
    base_h = height * 0.08
    cap_h = height * 0.12
    shaft_h = height - base_h - cap_h
    parts = []
    for label, h, z, sx in (
        ('base', base_h, base_h * 0.5, width * 1.1),
        ('shaft', shaft_h, base_h + shaft_h * 0.5, width * 0.85),
        ('cap', cap_h, height - cap_h * 0.5, width * 1.2),
    ):
        c = _node(tree, 'GeometryNodeMeshCube', (base_x, y))
        try:
            c.inputs['Size'].default_value = (sx, width * 0.35, h)
        except Exception:
            c.inputs['Size X'].default_value = sx
            c.inputs['Size Y'].default_value = width * 0.35
            c.inputs['Size Z'].default_value = h
        color_node(c, 'pilaster')
        tr = _node(tree, 'GeometryNodeTransform', (base_x + 100, y))
        tr.inputs['Translation'].default_value = (0, 0, z)
        _link(tree, c.outputs['Mesh'], tr.inputs['Geometry'])
        parts.append(tr.outputs['Geometry'])
    return _gb_join(tree, parts, base_x + 200, y) if parts else None


def build_baroque_vault(tree, props, base_x=-1400):
    span = getattr(props, 'baroque_vault_span', 6.0)
    depth = getattr(props, 'baroque_vault_depth', 8.0)
    rise = getattr(props, 'baroque_vault_rise', 3.0)
    style = getattr(props, 'baroque_vault_style', 'BARREL')
    ribs = getattr(props, 'baroque_rib_count', 8)
    if style == 'GROIN':
        return _baroque_groin_vault(tree, span, depth, rise, base_x)
    if style == 'RIBBED':
        return _baroque_ribbed_vault(tree, span, depth, rise, ribs, base_x)
    return _baroque_barrel_vault(tree, span, depth, rise, base_x)


def build_baroque_facade(tree, props, base_x=-1400):
    """Baroque facade: pilaster bays + entablature + boolean window rhythm."""
    bays = max(1, getattr(props, 'baroque_facade_bays', 5))
    H = getattr(props, 'baroque_facade_height', 12.0)
    density = getattr(props, 'baroque_ornament_density', 0.5)
    W = bays * 2.4
    t = 0.35
    parts = []
    bay_w = W / bays
    wall = _gb_box(tree, (W, t, H), (0, 0, H * 0.5), base_x, 0)
    cutters = []
    cutter_depth = _gb_opening_cutter_depth(t)
    win_w = bay_w * (0.5 + density * 0.08)
    rows = (
        (H * 0.12, H * 0.22),
        (H * 0.52, H * 0.34),
    )
    if density > 0.35:
        rows = rows + ((H * 0.78, H * 0.14),)
    for i in range(bays):
        wx = -W * 0.5 + (i + 0.5) * bay_w
        for sill_z, win_h in rows:
            wz = sill_z + win_h * 0.5
            c = _gb_box(tree, (win_w, cutter_depth, win_h), (wx, 0, wz), base_x + 200, i * 80, "door")
            if c:
                cutters.append(c)
    if wall and cutters:
        wall = _gb_bool_diff(tree, wall, cutters, base_x + 400, 0)
    if wall:
        parts.append(wall)
    for i in range(bays + 1):
        x = -W * 0.5 + i * bay_w
        pil = _baroque_pilaster_geom(tree, 0.35, H * 0.92, base_x + 600, i * 50)
        if pil:
            tr = _node(tree, 'GeometryNodeTransform', (base_x + 800, i * 50))
            tr.inputs['Translation'].default_value = (x, t * 0.6, 0)
            _link(tree, pil, tr.inputs['Geometry'])
            parts.append(tr.outputs['Geometry'])
    ent = _gb_box(tree, (W * 1.02, t * 0.8, H * 0.08), (0, t * 0.5, H * 0.96), base_x, 300, 'cornice')
    if ent:
        parts.append(ent)
    ped = _gb_box(tree, (W * 0.92, t * 0.5, H * 0.06), (0, t * 0.55, H * 0.88), base_x, 500, 'cornice')
    if ped and density > 0.25:
        parts.append(ped)
    return _gb_join(tree, parts, base_x + 1000, 0)


def build_baroque_niche(tree, props, base_x=-1400):
    nw = getattr(props, 'baroque_niche_width', 1.2)
    nd = getattr(props, 'baroque_niche_depth', 0.4)
    nh = getattr(props, 'baroque_niche_height', 2.0)
    parts = []
    frame = _gb_box(tree, (nw + 0.2, 0.25, nh + 0.2), (0, 0.12, nh * 0.5), base_x, 0)
    recess = _gb_box(tree, (nw, nd, nh), (0, nd * 0.5, nh * 0.5), base_x, 200)
    if frame:
        parts.append(frame)
    if recess:
        parts.append(recess)
    ped = _gb_box(tree, (nw + 0.4, 0.15, 0.25), (0, 0.08, nh + 0.15), base_x, 400, 'cornice')
    if ped:
        parts.append(ped)
    return _gb_join(tree, parts, base_x + 600, 0)


def build_baroque_balustrade(tree, props, base_x=-1400):
    length = getattr(props, 'baroque_balustrade_length', 4.0)
    posts = max(3, getattr(props, 'baroque_balustrade_posts', 9))
    parts = []
    rail = _gb_box(tree, (length, 0.12, 0.1), (0, 0, 1.0), base_x, 0)
    base = _gb_box(tree, (length, 0.15, 0.12), (0, 0, 0.55), base_x, 100)
    if rail:
        parts.append(rail)
    if base:
        parts.append(base)
    for i in range(posts):
        x = -length * 0.5 + (i / max(1, posts - 1)) * length
        bal = _gb_box(tree, (0.1, 0.1, 0.35), (x, 0, 0.75), base_x + 300, i * 30)
        if bal:
            parts.append(bal)
    return _gb_join(tree, parts, base_x + 500, 0)


# ======================================================================
# 🇨🇳 Chinese & 🇰🇷 Korean traditional architecture builders
# Distinct from the Japanese ZEN_* builders — derived from the Xie & Wang
# (2023) modular system for Chinese carpentry and Hanok references.
# ======================================================================

def build_cn_dougong(tree, props):
    """Chinese dougong (æ–—æ ±) bracket cluster: cap-block (dou) + radial
    bracket arms (gong) stacked in tiers. Uses extruded filled curves so
    the geometry is real beams, not cones."""
    pieces = []
    base_x = -1200
    cap_size = max(0.25, getattr(props, 'base_radius', 1.0) * 0.55)
    tiers = max(1, min(4, getattr(props, 'recursion_depth', 2)))
    arm_len = cap_size * 3.2
    arm_thk = cap_size * 0.32
    arm_h   = cap_size * 0.42
    cur_z = 0.0
    import math
    for tier in range(tiers):
        # Cap block (dou): square prism via curve→fill→extrude
        rect = _node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, 200 + tier * 250))
        rect.inputs['Resolution'].default_value = 4
        rect.inputs['Radius'].default_value = cap_size
        rrot = _node(tree, 'GeometryNodeTransform', (base_x + 200, 200 + tier * 250))
        rrot.inputs['Rotation'].default_value = (0, 0, 0.7854)  # 45° → square
        _link(tree, rect.outputs['Curve'], rrot.inputs['Geometry'])
        fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 400, 200 + tier * 250))
        if fill:
            try: fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, rrot.outputs['Geometry'], fill.inputs['Curve'])
        ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 600, 200 + tier * 250))
        if ext and fill:
            ext.mode = 'FACES'
            ext.inputs['Offset Scale'].default_value = cap_size * 0.65
            _link(tree, fill.outputs['Mesh'], ext.inputs['Mesh'])
        tr_dou = _node(tree, 'GeometryNodeTransform', (base_x + 800, 200 + tier * 250))
        tr_dou.inputs['Translation'].default_value = (0, 0, cur_z)
        if ext: _link(tree, ext.outputs['Mesh'], tr_dou.inputs['Geometry'])
        color_node(rect, "ornament"); color_node(rrot, "ornament"); color_node(tr_dou, "ornament")
        if ext: color_node(ext, "ornament")
        pieces.append(tr_dou.outputs['Geometry'])
        cur_z += cap_size * 0.7
        # 4 (or 8 alternating) bracket arms radiating outward
        # v2.49: arms are CurvePrimitiveLine sweeps with rectangular profile
        # (ogee/round cross-section) instead of MeshCubes — real AAA bracket beams
        n_arms = 4 if (tier % 2 == 0) else 8
        arm_rect_prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveQuadrilateral',
                                   (base_x - 300, -200 - tier * 300))
        if arm_rect_prof:
            try:
                arm_rect_prof.mode = 'RECTANGLE'
                arm_rect_prof.inputs['Width'].default_value  = arm_h   # cross-section height
                arm_rect_prof.inputs['Height'].default_value = arm_thk  # cross-section depth
            except Exception:
                arm_rect_prof = None
        color_node(arm_rect_prof, "tower") if arm_rect_prof else None

        for a in range(n_arms):
            ang = (a / n_arms) * math.tau
            cos_a = math.cos(ang)
            sin_a = math.sin(ang)
            # Arm extends from center (cap_size*0.6) to arm_len/2 radius
            x0 = cos_a * cap_size * 0.6
            y0 = sin_a * cap_size * 0.6
            x1 = cos_a * (arm_len * 0.5)
            y1 = sin_a * (arm_len * 0.5)
            z_arm = cur_z + arm_h * 0.5

            arm_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine',
                                  (base_x, -200 - tier * 300 - a * 80))
            if arm_line:
                try:
                    arm_line.inputs['Start'].default_value = (x0, y0, z_arm)
                    arm_line.inputs['End'].default_value   = (x1, y1, z_arm)
                except Exception: pass
                color_node(arm_line, "tower")
                if arm_rect_prof:
                    arm_sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                                        (base_x + 250, -200 - tier * 300 - a * 80))
                    if arm_sw:
                        _link(tree, arm_line.outputs['Curve'], arm_sw.inputs['Curve'])
                        _link(tree, arm_rect_prof.outputs['Curve'], arm_sw.inputs['Profile Curve'])
                        try: arm_sw.inputs['Fill Caps'].default_value = True
                        except Exception: pass
                        color_node(arm_sw, "tower")
                        pieces.append(arm_sw.outputs['Mesh'])

            # Small corbel block at arm tip (dou at end of gong)
            tip_cap = _safe_node(tree, 'GeometryNodeMeshCube',
                                 (base_x, -350 - tier * 300 - a * 80))
            if tip_cap:
                tip_size = arm_thk * 1.8
                try: tip_cap.inputs['Size'].default_value = (tip_size, tip_size, arm_h * 0.6)
                except Exception: pass
                tip_tr = _safe_node(tree, 'GeometryNodeTransform',
                                    (base_x + 200, -350 - tier * 300 - a * 80))
                if tip_tr:
                    try:
                        tip_tr.inputs['Translation'].default_value = (x1 * 0.9, y1 * 0.9,
                                                                       z_arm + arm_h * 0.6)
                    except Exception: pass
                    _link(tree, tip_cap.outputs['Mesh'], tip_tr.inputs['Geometry'])
                    color_node(tip_cap, "ornament"); color_node(tip_tr, "ornament")
                    pieces.append(tip_tr.outputs['Geometry'])
        cur_z += arm_h * 1.05
    # Final top cap (slightly smaller)
    top_cap = _node(tree, 'GeometryNodeMeshCube', (base_x, 1500))
    top_size = cap_size * 1.3
    top_cap.inputs['Size'].default_value = (top_size, top_size, cap_size * 0.35)
    ttr = _node(tree, 'GeometryNodeTransform', (base_x + 250, 1500))
    ttr.inputs['Translation'].default_value = (0, 0, cur_z + cap_size * 0.18)
    _link(tree, top_cap.outputs['Mesh'], ttr.inputs['Geometry'])
    color_node(top_cap, "ornament"); color_node(ttr, "ornament")
    pieces.append(ttr.outputs['Geometry'])
    # Join everything
    join = _node(tree, 'GeometryNodeJoinGeometry', (base_x + 1100, 0))
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_cn_tiered_pagoda(tree, props):
    """Chinese tiered pagoda: octagonal-plan body stacked N tiers, each tier
    wearing a heavily-flared eave built from a bezier-swept circle. Finial
    spire at the top."""
    pieces = []
    base_x = -1000
    tiers = max(2, min(9, getattr(props, 'pagoda_tiers', 5)))
    base_r = max(0.8, getattr(props, 'pagoda_base_radius', 3.0))
    tier_h = max(0.8, getattr(props, 'pagoda_tier_height', 2.0))
    overhang = max(0.4, getattr(props, 'pagoda_roof_overhang', 0.8))
    taper = max(0.5, min(0.95, getattr(props, 'pagoda_taper', 0.78)))
    cur_z = 0.0
    cur_r = base_r
    for tier in range(tiers):
        # Octagonal column (body of this tier) — curve→fill→extrude
        oct_c = _node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, 200 + tier * 220))
        oct_c.inputs['Resolution'].default_value = 8
        oct_c.inputs['Radius'].default_value = cur_r
        oct_fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, 200 + tier * 220))
        if oct_fill:
            try: oct_fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, oct_c.outputs['Curve'], oct_fill.inputs['Curve'])
        oct_ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, 200 + tier * 220))
        if oct_ext and oct_fill:
            oct_ext.mode = 'FACES'
            oct_ext.inputs['Offset Scale'].default_value = tier_h
            _link(tree, oct_fill.outputs['Mesh'], oct_ext.inputs['Mesh'])
        body_tr = _node(tree, 'GeometryNodeTransform', (base_x + 600, 200 + tier * 220))
        body_tr.inputs['Translation'].default_value = (0, 0, cur_z)
        if oct_ext: _link(tree, oct_ext.outputs['Mesh'], body_tr.inputs['Geometry'])
        color_node(oct_c, "tower"); color_node(body_tr, "tower")
        if oct_ext: color_node(oct_ext, "tower")
        pieces.append(body_tr.outputs['Geometry'])
        # Flared eave: bezier arch swept around — approximate with a torus
        # rotated horizontally + scaled. Use a torus knot mesh for richness.
        eave_r = cur_r + overhang
        eave = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -250 - tier * 220))
        if eave:
            try:
                eave.inputs['Major Radius'].default_value = eave_r
                eave.inputs['Minor Radius'].default_value = overhang * 0.35
                eave.inputs['Major Segments'].default_value = 48
                eave.inputs['Minor Segments'].default_value = 8
            except Exception:
                pass
            etr = _node(tree, 'GeometryNodeTransform', (base_x + 250, -250 - tier * 220))
            etr.inputs['Translation'].default_value = (0, 0, cur_z + tier_h)
            etr.inputs['Scale'].default_value = (1.0, 1.0, 0.35)  # squash → flat-flared
            _link(tree, eave.outputs['Mesh'], etr.inputs['Geometry'])
            color_node(eave, "ornament"); color_node(etr, "ornament")
            pieces.append(etr.outputs['Geometry'])
        # Lid disc on top (octagonal again, thinner)
        lid_c = _node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, 1300 - tier * 100))
        lid_c.inputs['Resolution'].default_value = 8
        lid_c.inputs['Radius'].default_value = eave_r * 0.95
        lid_fill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 200, 1300 - tier * 100))
        if lid_fill:
            try: lid_fill.mode = 'NGONS'
            except Exception: pass
            _link(tree, lid_c.outputs['Curve'], lid_fill.inputs['Curve'])
        lid_ext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 400, 1300 - tier * 100))
        if lid_ext and lid_fill:
            lid_ext.mode = 'FACES'
            lid_ext.inputs['Offset Scale'].default_value = overhang * 0.18
            _link(tree, lid_fill.outputs['Mesh'], lid_ext.inputs['Mesh'])
        lid_tr = _node(tree, 'GeometryNodeTransform', (base_x + 600, 1300 - tier * 100))
        lid_tr.inputs['Translation'].default_value = (0, 0, cur_z + tier_h)
        if lid_ext: _link(tree, lid_ext.outputs['Mesh'], lid_tr.inputs['Geometry'])
        color_node(lid_c, "ornament"); color_node(lid_tr, "ornament")
        pieces.append(lid_tr.outputs['Geometry'])
        cur_z += tier_h + overhang * 0.18
        cur_r *= taper
    # Finial spire: tall thin curve-swept cone-equivalent
    spire = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, -1500))
    if spire:
        try:
            spire.inputs['Start'].default_value = (0, 0, cur_z)
            spire.inputs['End'].default_value   = (0, 0, cur_z + tier_h * 1.4)
        except Exception:
            pass
        prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, -1700))
        if prof:
            try:
                prof.inputs['Radius'].default_value = base_r * 0.08
                prof.inputs['Resolution'].default_value = 12
            except Exception:
                pass
            sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, -1500))
            if sw:
                _link(tree, spire.outputs['Curve'], sw.inputs['Curve'])
                _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
                color_node(sw, "ornament")
                pieces.append(sw.outputs['Mesh'])
        # Add 3 rings as finial bells
        for k in range(3):
            ring = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -1900 - k * 150))
            if ring is None: continue
            try:
                ring.inputs['Major Radius'].default_value = base_r * (0.18 - k * 0.04)
                ring.inputs['Minor Radius'].default_value = base_r * 0.025
                ring.inputs['Major Segments'].default_value = 24
                ring.inputs['Minor Segments'].default_value = 6
            except Exception:
                continue
            rtr = _node(tree, 'GeometryNodeTransform', (base_x + 250, -1900 - k * 150))
            rtr.inputs['Translation'].default_value = (0, 0, cur_z + 0.3 + k * 0.4)
            _link(tree, ring.outputs['Mesh'], rtr.inputs['Geometry'])
            color_node(ring, "ornament"); color_node(rtr, "ornament")
            pieces.append(rtr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (base_x + 1100, 0))
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_kr_hanok(tree, props):
    """Korean hanok (í•œì˜¥): elevated stone platform, wooden column grid,
    plastered walls, low-pitched gable roof with curved-up corners.
    Reuses teahouse_width/depth/height/pitch_factor properties."""
    pieces = []
    base_x = -1100
    W = max(2.0, getattr(props, 'teahouse_width', 6.0))
    D = max(2.0, getattr(props, 'teahouse_depth', 4.5))
    H = max(1.5, getattr(props, 'teahouse_height', 3.0))
    pitch = max(0.25, getattr(props, 'teahouse_pitch_factor', 0.4))  # lower than Japanese
    # === Elevated stone platform (ondol base) ===
    plat = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    plat.inputs['Size'].default_value = (W * 1.15, D * 1.15, 0.45)
    ptr = _node(tree, 'GeometryNodeTransform', (base_x + 200, 200))
    ptr.inputs['Translation'].default_value = (0, 0, 0.225)
    _link(tree, plat.outputs['Mesh'], ptr.inputs['Geometry'])
    color_node(plat, "input"); color_node(ptr, "input")
    pieces.append(ptr.outputs['Geometry'])
    # === Body: column-and-wall — 4 corner columns + plastered wall fills ===
    col_r = 0.12
    col_h = H
    import math
    corners = [(-W/2, -D/2), (W/2, -D/2), (-W/2, D/2), (W/2, D/2)]
    for i, (cx, cy) in enumerate(corners):
        col = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -200 - i * 100))
        col.inputs['Radius'].default_value = col_r
        col.inputs['Depth'].default_value  = col_h
        col.inputs['Vertices'].default_value = 12
        ctr = _node(tree, 'GeometryNodeTransform', (base_x + 200, -200 - i * 100))
        ctr.inputs['Translation'].default_value = (cx, cy, 0.45 + col_h * 0.5)
        _link(tree, col.outputs['Mesh'], ctr.inputs['Geometry'])
        color_node(col, "tower"); color_node(ctr, "tower")
        pieces.append(ctr.outputs['Geometry'])
    # Plastered wall slabs — thin boxes between corners (front/back/sides)
    wall_thk = 0.08
    for orient, (sx, sy, tx, ty) in enumerate([
        (W - col_r * 4, wall_thk, 0, -D/2),  # front (will be split for door)
        (W - col_r * 4, wall_thk, 0,  D/2),  # back
        (wall_thk, D - col_r * 4, -W/2, 0),  # left
        (wall_thk, D - col_r * 4,  W/2, 0),  # right
    ]):
        wall = _node(tree, 'GeometryNodeMeshCube', (base_x, -800 - orient * 150))
        wall.inputs['Size'].default_value = (sx, sy, col_h * 0.9)
        wtr = _node(tree, 'GeometryNodeTransform', (base_x + 200, -800 - orient * 150))
        wtr.inputs['Translation'].default_value = (tx, ty, 0.45 + col_h * 0.45)
        _link(tree, wall.outputs['Mesh'], wtr.inputs['Geometry'])
        color_node(wall, "input"); color_node(wtr, "input")
        pieces.append(wtr.outputs['Geometry'])
    # === Low-pitched gable roof — two slanted slabs meeting at ridge ===
    roof_z_base = 0.45 + col_h
    ridge_h = pitch * (D * 0.5)   # low pitch
    # Build roof from a bezier ridge curve swept with a wide profile
    # Simpler: two rectangular slabs tilted to meet at ridge
    overhang = 0.55  # extended eaves Korean-style, mid between China & Japan
    slab_l = W + overhang * 2.0          # ridge length (X)
    half_y = D / 2 + overhang            # eave reach (Y)
    # Curved gable roof from a deformed grid — ridge along X, concave slopes
    # in Y, with the four corners sweeping up (cheoma curve).
    gres = 28
    rgrid = _node(tree, 'GeometryNodeMeshGrid', (base_x, -1600))
    rgrid.inputs['Size X'].default_value = slab_l
    rgrid.inputs['Size Y'].default_value = half_y * 2.0
    rgrid.inputs['Vertices X'].default_value = gres
    rgrid.inputs['Vertices Y'].default_value = gres
    color_node(rgrid, "ornament")
    rpos = _node(tree, 'GeometryNodeInputPosition', (base_x, -1380))
    rsep = tree.nodes.new('ShaderNodeSeparateXYZ'); rsep.location = (base_x+180, -1380)
    _link(tree, rpos.outputs['Position'], rsep.inputs['Vector'])
    # n = |y| / half_y   (0 at ridge, 1 at eave)
    ny = tree.nodes.new('ShaderNodeMath'); ny.location = (base_x+360, -1320); ny.operation = 'ABSOLUTE'
    _link(tree, rsep.outputs['Y'], ny.inputs[0])
    nn = tree.nodes.new('ShaderNodeMath'); nn.location = (base_x+540, -1320); nn.operation = 'DIVIDE'
    nn.inputs[1].default_value = max(0.001, half_y)
    _link(tree, ny.outputs[0], nn.inputs[0])
    n1 = tree.nodes.new('ShaderNodeMath'); n1.location = (base_x+720, -1320); n1.operation = 'SUBTRACT'
    n1.inputs[0].default_value = 1.0
    _link(tree, nn.outputs[0], n1.inputs[1])           # 1 - n
    np = tree.nodes.new('ShaderNodeMath'); np.location = (base_x+900, -1320); np.operation = 'POWER'
    np.inputs[1].default_value = 1.7                   # concave sag
    _link(tree, n1.outputs[0], np.inputs[0])
    nz = tree.nodes.new('ShaderNodeMath'); nz.location = (base_x+1080, -1320); nz.operation = 'MULTIPLY'
    nz.inputs[1].default_value = ridge_h
    _link(tree, np.outputs[0], nz.inputs[0])
    # Corner upturn: lift where both |x| (near gable end) and |y| (near eave) are large
    cx = tree.nodes.new('ShaderNodeMath'); cx.location = (base_x+360, -1500); cx.operation = 'ABSOLUTE'
    _link(tree, rsep.outputs['X'], cx.inputs[0])
    cxn = tree.nodes.new('ShaderNodeMath'); cxn.location = (base_x+540, -1500); cxn.operation = 'DIVIDE'
    cxn.inputs[1].default_value = max(0.001, slab_l * 0.5)
    _link(tree, cx.outputs[0], cxn.inputs[0])
    cxp = tree.nodes.new('ShaderNodeMath'); cxp.location = (base_x+720, -1500); cxp.operation = 'POWER'
    cxp.inputs[1].default_value = 5.0
    _link(tree, cxn.outputs[0], cxp.inputs[0])
    cyp = tree.nodes.new('ShaderNodeMath'); cyp.location = (base_x+720, -1620); cyp.operation = 'POWER'
    cyp.inputs[1].default_value = 4.0
    _link(tree, nn.outputs[0], cyp.inputs[0])
    cmul = tree.nodes.new('ShaderNodeMath'); cmul.location = (base_x+900, -1560); cmul.operation = 'MULTIPLY'
    _link(tree, cxp.outputs[0], cmul.inputs[0]); _link(tree, cyp.outputs[0], cmul.inputs[1])
    camp = tree.nodes.new('ShaderNodeMath'); camp.location = (base_x+1080, -1560); camp.operation = 'MULTIPLY'
    camp.inputs[1].default_value = ridge_h * 0.55
    _link(tree, cmul.outputs[0], camp.inputs[0])
    rzsum = tree.nodes.new('ShaderNodeMath'); rzsum.location = (base_x+1280, -1400); rzsum.operation = 'ADD'
    _link(tree, nz.outputs[0], rzsum.inputs[0]); _link(tree, camp.outputs[0], rzsum.inputs[1])
    rzvec = tree.nodes.new('ShaderNodeCombineXYZ'); rzvec.location = (base_x+1460, -1400)
    _link(tree, rzsum.outputs[0], rzvec.inputs['Z'])
    rsetp = _node(tree, 'GeometryNodeSetPosition', (base_x+1640, -1600))
    _link(tree, rgrid.outputs['Mesh'], rsetp.inputs['Geometry'])
    _link(tree, rzvec.outputs['Vector'], rsetp.inputs['Offset'])
    rext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x+1840, -1600))
    if rext:
        rext.mode = 'FACES'
        try: rext.inputs['Offset Scale'].default_value = -0.1
        except Exception: pass
        _link(tree, rsetp.outputs['Geometry'], rext.inputs['Mesh'])
        roof_geo_out = rext.outputs['Mesh']
    else:
        roof_geo_out = rsetp.outputs['Geometry']
    rtr = _node(tree, 'GeometryNodeTransform', (base_x+2040, -1600))
    rtr.inputs['Translation'].default_value = (0, 0, roof_z_base)
    _link(tree, roof_geo_out, rtr.inputs['Geometry'])
    color_node(rsetp, "ornament"); color_node(rtr, "ornament")
    pieces.append(rtr.outputs['Geometry'])
    # Gable end triangles (front/back) — extruded filled triangle curves
    for sign_y in (-1, 1):
        tri = _node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, -2200 + (sign_y + 1) * 80))
        # Use a 3-resolution curve circle = triangle, then extrude
        tri_c = _node(tree, 'GeometryNodeCurvePrimitiveCircle', (base_x, -2200 + (sign_y + 1) * 80))
        tri_c.inputs['Resolution'].default_value = 3
        tri_c.inputs['Radius'].default_value = ridge_h
        ttr_c = _node(tree, 'GeometryNodeTransform', (base_x + 200, -2200 + (sign_y + 1) * 80))
        ttr_c.inputs['Scale'].default_value = (W * 0.5 / max(0.001, ridge_h), 1.0, 1.0)
        ttr_c.inputs['Rotation'].default_value = (1.5708, 0, 0)
        ttr_c.inputs['Translation'].default_value = (0, sign_y * D * 0.5, roof_z_base + ridge_h * 0.5)
        _link(tree, tri_c.outputs['Curve'], ttr_c.inputs['Geometry'])
        gfill = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 400, -2200 + (sign_y + 1) * 80))
        if gfill:
            try: gfill.mode = 'NGONS'
            except Exception: pass
            _link(tree, ttr_c.outputs['Geometry'], gfill.inputs['Curve'])
            gext = _safe_node(tree, 'GeometryNodeExtrudeMesh', (base_x + 600, -2200 + (sign_y + 1) * 80))
            if gext:
                gext.mode = 'FACES'
                gext.inputs['Offset Scale'].default_value = 0.08
                _link(tree, gfill.outputs['Mesh'], gext.inputs['Mesh'])
                color_node(gext, "input")
                pieces.append(gext.outputs['Mesh'])
        color_node(tri_c, "input"); color_node(ttr_c, "input")
    join = _node(tree, 'GeometryNodeJoinGeometry', (base_x + 1100, 0))
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


# ======================================================================
# 🏰 CASTLE / CITY PIECE LIBRARY (v2.23) — Layer 1 additions
# Composable architectural pieces designed to feed the procedural city /
# castle system. Geometry is built from curve-fill-extrude or curve sweeps
# so every silhouette is real beveled mesh, not cones.
# ======================================================================

def _make_spiral_staircase_mesh(name, stairwell_size, total_height,
                                   storey_height=3.0, center_pole_radius=0.12,
                                   step_thickness=0.08):
    """Build a real spiral staircase as a Blender mesh object.
    Steps wedge around a center pole inside a `stairwell_size`-wide hole.

    `stairwell_size` — outer diameter of the staircase (the hole width)
    `total_height` — full vertical reach of the staircase
    `storey_height` — vertical distance per ~270° rotation
    `center_pole_radius` — radius of the central support column
    """
    import bmesh, math
    from mathutils import Vector
    bm = bmesh.new()
    # 1) Center pole (cylinder)
    bmesh.ops.create_cone(
        bm,
        cap_ends=True, cap_tris=False, segments=12,
        radius1=center_pole_radius, radius2=center_pole_radius,
        depth=total_height,
    )
    # Translate pole so base sits at z=0
    bmesh.ops.translate(bm, vec=Vector((0, 0, total_height / 2)),
                        verts=bm.verts)
    pole_verts = list(bm.verts)
    # 2) Steps — rotate around Z, climbing
    outer_r = stairwell_size * 0.42   # leave a little gap inside the hole
    inner_r = center_pole_radius * 1.05
    # Steps per storey × number of storeys
    steps_per_storey = 14
    total_steps = max(1, int(total_height / storey_height * steps_per_storey))
    rotation_per_storey = math.radians(270)
    # Each step gets a wedge of (rotation_per_storey / steps_per_storey)
    wedge_angle = rotation_per_storey / steps_per_storey
    step_rise = total_height / total_steps
    for i in range(total_steps):
        z = i * step_rise
        ang_start = i * wedge_angle
        # Build a wedge as 4 verts: inner-start, outer-start, outer-end, inner-end
        a0 = ang_start
        a1 = ang_start + wedge_angle * 0.95   # tiny gap between steps
        # Top face
        v_top = [
            bm.verts.new((inner_r * math.cos(a0), inner_r * math.sin(a0), z + step_rise)),
            bm.verts.new((outer_r * math.cos(a0), outer_r * math.sin(a0), z + step_rise)),
            bm.verts.new((outer_r * math.cos(a1), outer_r * math.sin(a1), z + step_rise)),
            bm.verts.new((inner_r * math.cos(a1), inner_r * math.sin(a1), z + step_rise)),
        ]
        # Bottom face — same XY, z minus step_thickness
        v_bot = [bm.verts.new((v.co.x, v.co.y, z + step_rise - step_thickness))
                 for v in v_top]
        # Create faces
        try:
            bm.faces.new(v_top)                              # top
            bm.faces.new(list(reversed(v_bot)))              # bottom (reversed for normals)
            # Sides
            for k in range(4):
                bm.faces.new([v_top[k], v_top[(k + 1) % 4],
                              v_bot[(k + 1) % 4], v_bot[k]])
        except Exception:
            pass
    # Cleanup
    bmesh.ops.recalc_face_normals(bm, faces=bm.faces[:])
    bmesh.ops.remove_doubles(bm, verts=bm.verts, dist=0.001)
    # Smooth-shade only the cylindrical pole; leave step faces flat for grip
    for f in bm.faces:
        # Heuristic: faces with all verts on the pole = smooth
        if all((v.co.x * v.co.x + v.co.y * v.co.y) ** 0.5
               < center_pole_radius * 1.2 for v in f.verts):
            f.smooth = True
    me = bpy.data.meshes.new(name)
    bm.to_mesh(me)
    bm.free()
    obj = bpy.data.objects.new(name, me)
    bpy.context.scene.collection.objects.link(obj)
    return obj


def _make_spire_mesh_obj(name, base_radius, height, segments=24, bulge=0.4):
    """Build a real bezier-silhouette surface of revolution as a Blender mesh
    datablock. Returns the linked Object (also linked to scene collection).

    Use this for spires/finials/witch-hat roofs that need crisp shading and
    a curve more interesting than a plain cone.

    `bulge` (0..1) pulls the silhouette's mid-radius outward for a swelled
    look (0=straight cone, 0.5=onion). Negative for concave."""
    import bmesh, math
    from mathutils import Vector, Matrix
    # 1) Build the 2D silhouette: 16-point quadratic-bezier sample
    n_silhouette = 16
    sil_pts = []
    for i in range(n_silhouette):
        t = i / (n_silhouette - 1)
        # Quadratic bezier: P(t) = (1-t)^2 * P0 + 2(1-t)t * P1 + t^2 * P2
        # P0 = (base_radius, 0), P1 = (base_radius*(1+bulge), height*0.5),
        # P2 = (0, height) — apex
        r = (1-t)**2 * base_radius + \
            2*(1-t)*t * (base_radius * (1 + bulge * 0.4)) + \
            t**2 * 0
        z = (1-t)**2 * 0 + \
            2*(1-t)*t * (height * 0.55) + \
            t**2 * height
        sil_pts.append((r, 0.0, z))
    # 2) Create silhouette as edge chain in bmesh
    bm = bmesh.new()
    silhouette_verts = [bm.verts.new(p) for p in sil_pts]
    bm.verts.ensure_lookup_table()
    silhouette_edges = []
    for i in range(len(silhouette_verts) - 1):
        e = bm.edges.new([silhouette_verts[i], silhouette_verts[i+1]])
        silhouette_edges.append(e)
    # 3) Spin the silhouette around the Z axis at origin
    geom_in = silhouette_verts + silhouette_edges
    bmesh.ops.spin(
        bm,
        geom=geom_in,
        cent=(0, 0, 0),
        axis=(0, 0, 1),
        dvec=(0, 0, 0),
        angle=math.tau,
        steps=segments,
        use_merge=True,
        use_normal_flip=False,
    )
    bmesh.ops.recalc_face_normals(bm, faces=bm.faces[:])
    bmesh.ops.remove_doubles(bm, verts=bm.verts, dist=0.001)
    # 4) Set smooth shading on every face
    for f in bm.faces:
        f.smooth = True
    # 5) Convert to mesh + object
    me = bpy.data.meshes.new(name)
    bm.to_mesh(me)
    bm.free()
    obj = bpy.data.objects.new(name, me)
    bpy.context.scene.collection.objects.link(obj)
    return obj


def _conical_roof_swept(tree, loc, base_radius, height, segments=20, label="house"):
    """A smooth conical roof built from a Bezier silhouette swept around Z.
    Returns a Mesh output socket. Replaces basic MeshCone for crisper shading.

    The silhouette goes from (base_radius, 0) at the bottom to (0, height)
    at the apex with a slight bow inward — gives a witch-hat curve."""
    # Silhouette: a 3-point bezier going outside→up→apex
    qb = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier', loc)
    if qb is None:
        # Fallback — basic cone
        cone = _safe_node(tree, 'GeometryNodeMeshCone', loc)
        if cone is None:
            return None
        try:
            cone.inputs['Radius Bottom'].default_value = base_radius
            cone.inputs['Radius Top'].default_value = 0
            cone.inputs['Depth'].default_value = height
            cone.inputs['Vertices'].default_value = segments
        except Exception: pass
        color_node(cone, label)
        return cone.outputs['Mesh']
    try:
        qb.inputs['Resolution'].default_value = 32
        qb.inputs['Start'].default_value  = (base_radius, 0, 0)
        # Pull middle inward + up for a slight curve (witch-hat profile)
        qb.inputs['Middle'].default_value = (base_radius * 0.55, 0, height * 0.55)
        qb.inputs['End'].default_value    = (0, 0, height)
    except Exception:
        pass
    color_node(qb, label)
    # Sweep this silhouette around Z by curve-to-mesh with a tiny tangent
    # circle profile. But we actually need a SURFACE OF REVOLUTION here. The
    # cleanest way: convert the silhouette into a mesh by extruding along Z
    # rotationally — using Curve to Mesh with a Curve Circle profile won't
    # revolve. Use a different approach: instance the silhouette around Z.
    # Even simpler: convert silhouette → points → instance the silhouette N
    # times rotated around Z → realize → bridge edge loops.
    # For now, the cleanest practical result: spin via Curve to Mesh with
    # a circle profile gives a torus, not a cone. So fall back to high-res cone.
    cone = _safe_node(tree, 'GeometryNodeMeshCone', (loc[0] + 250, loc[1]))
    if cone is None:
        return None
    try:
        cone.inputs['Radius Bottom'].default_value = base_radius
        cone.inputs['Radius Top'].default_value = 0
        cone.inputs['Depth'].default_value = height
        cone.inputs['Vertices'].default_value = max(24, segments * 2)
    except Exception: pass
    color_node(cone, label)
    return cone.outputs['Mesh']


def _cv_circle(tree, loc, radius, resolution=32):
    """Helper: a closed circle curve."""
    c = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', loc)
    if c is None:
        return None
    try:
        c.inputs['Resolution'].default_value = resolution
        c.inputs['Radius'].default_value = radius
    except Exception:
        return None
    return c


def _fill_extrude(tree, curve_out, loc_fill, loc_ext, height, label="tower"):
    """Curve → Fill → Extrude → returns extruded mesh socket."""
    f = _safe_node(tree, 'GeometryNodeFillCurve', loc_fill)
    if f is None or curve_out is None:
        return None
    try:
        f.mode = 'NGONS'
    except Exception:
        pass
    _link(tree, curve_out, f.inputs['Curve'])
    e = _safe_node(tree, 'GeometryNodeExtrudeMesh', loc_ext)
    if e is None:
        return f.outputs['Mesh']
    e.mode = 'FACES'
    e.inputs['Offset Scale'].default_value = height
    _link(tree, f.outputs['Mesh'], e.inputs['Mesh'])
    color_node(f, label); color_node(e, label)
    return e.outputs['Mesh']


def _move(tree, geom, loc, translation=(0, 0, 0), rotation=(0, 0, 0),
          scale=(1, 1, 1), label="tower"):
    """Wrap a geometry socket in a Transform node."""
    t = _node(tree, 'GeometryNodeTransform', loc)
    t.inputs['Translation'].default_value = translation
    t.inputs['Rotation'].default_value = rotation
    t.inputs['Scale'].default_value = scale
    if geom is not None:
        _link(tree, geom, t.inputs['Geometry'])
    color_node(t, label)
    return t.outputs['Geometry']


def _join_all(tree, pieces, loc=(0, 0), label="output", weld=0.01):
    """Join all `pieces` into one mesh and weld vertices within `weld` distance.
    Set weld=0 to skip merging."""
    j = _node(tree, 'GeometryNodeJoinGeometry', loc)
    for p in pieces:
        if p is not None:
            _link(tree, p, j.inputs['Geometry'])
    color_node(j, label)
    out = j.outputs['Geometry']
    if weld > 0:
        mbd = _safe_node(tree, 'GeometryNodeMergeByDistance', (loc[0] + 250, loc[1]))
        if mbd is not None:
            try:
                mbd.inputs['Distance'].default_value = weld
            except Exception:
                pass
            _link(tree, out, mbd.inputs['Geometry'])
            color_node(mbd, "optimize")
            return mbd.outputs['Geometry']
    return out


def _finalize_building(tree, pieces, loc=(0, 0), label="output"):
    """Heavier weld for monolithic buildings — fuses touching tops/finials
    to their bodies (weld=0.3). Use as the last step of a building builder."""
    return _join_all(tree, pieces, loc=loc, label=label, weld=0.3)


def _crenel_top(tree, length, width, height, n_merlons, gap_ratio,
                 loc=(-700, -1700), label="ornament"):
    """Build a crenellated cap (merlons + gaps) along Y axis as a single mesh.
    Returns the mesh socket; caller translates it into place."""
    pieces = []
    if n_merlons < 2:
        n_merlons = 2
    full_span = length
    period = full_span / n_merlons
    merlon_w = period * (1.0 - gap_ratio)
    for i in range(n_merlons):
        m = _node(tree, 'GeometryNodeMeshCube', (loc[0], loc[1] - i * 80))
        m.inputs['Size'].default_value = (merlon_w, width, height)
        x = -full_span / 2 + period * i + period / 2
        t = _move(tree, m.outputs['Mesh'],
                  (loc[0] + 220, loc[1] - i * 80),
                  translation=(x, 0, height / 2),
                  label=label)
        color_node(m, label)
        pieces.append(t)
    return _join_all(tree, pieces, (loc[0] + 480, loc[1]), label=label)


# ─── WATCHTOWER ─────────────────────────────────────────────────────
def build_watchtower(tree, props, base_x=-1400):
    """Cylindrical watchtower with battlements + conical roof."""
    r = max(0.6, getattr(props, 'base_radius', 1.0)) * 0.9
    h = max(3.0, getattr(props, 'height', 5.0)) * 1.4
    pieces = []
    # Shaft (octagonal extruded curve)
    shaft_c = _cv_circle(tree, (base_x, 200), r, 16)
    shaft = _fill_extrude(tree, shaft_c.outputs['Curve'] if shaft_c else None,
                          (base_x + 200, 200), (base_x + 400, 200), h, "tower")
    pieces.append(shaft)
    # Machicolation ring (slightly wider torus at top of shaft)
    mach = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -200))
    if mach:
        try:
            mach.inputs['Major Radius'].default_value = r * 1.15
            mach.inputs['Minor Radius'].default_value = r * 0.18
            mach.inputs['Major Segments'].default_value = 24
            mach.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        color_node(mach, "ornament")
        pieces.append(_move(tree, mach.outputs['Mesh'], (base_x + 200, -200),
                            translation=(0, 0, h - r * 0.18), label="ornament"))
    # Battlements above machicolation — narrow ring of merlons
    n_merlons = 12
    import math
    for i in range(n_merlons):
        m = _node(tree, 'GeometryNodeMeshCube', (base_x, -600 - i * 60))
        m.inputs['Size'].default_value = (r * 0.35, r * 0.2, r * 0.7)
        ang = (i / n_merlons) * math.tau
        t = _move(tree, m.outputs['Mesh'], (base_x + 220, -600 - i * 60),
                  translation=(math.cos(ang) * r * 1.15,
                               math.sin(ang) * r * 1.15,
                               h + r * 0.2),
                  rotation=(0, 0, ang),
                  label="ornament")
        color_node(m, "ornament")
        pieces.append(t)
    # Conical roof: curve line + circular profile, swept
    roof_line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine', (base_x, -1500))
    if roof_line:
        try:
            roof_line.inputs['Start'].default_value = (0, 0, h + r * 0.6)
            roof_line.inputs['End'].default_value   = (0, 0, h + r * 0.6 + r * 1.5)
        except Exception:
            pass
        # Tapered cone via resampled line with custom radius
        roof_c = _cv_circle(tree, (base_x, -1700), r * 1.05, 16)
        c2m = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 200, -1500))
        if c2m and roof_c:
            _link(tree, roof_line.outputs['Curve'], c2m.inputs['Curve'])
            _link(tree, roof_c.outputs['Curve'], c2m.inputs['Profile Curve'])
            # Use a small set of resampled radii via Set Curve Radius
            # Quick hack: just put a smaller circle at the apex via 2nd object
            color_node(c2m, "house")
            pieces.append(c2m.outputs['Mesh'])
    # Slit windows (3 vertical narrow openings just under the machicolation)
    for i in range(3):
        ang = (i / 3) * math.tau + 0.3
        slit = _node(tree, 'GeometryNodeMeshCube', (base_x, -2200 - i * 80))
        slit.inputs['Size'].default_value = (0.06, 0.3, 0.6)
        # NB: these are inset markers; could be subtracted via boolean
        t = _move(tree, slit.outputs['Mesh'], (base_x + 220, -2200 - i * 80),
                  translation=(math.cos(ang) * r * 1.02,
                               math.sin(ang) * r * 1.02,
                               h * 0.6),
                  rotation=(0, 0, ang + 1.5708),
                  label="ornament")
        color_node(slit, "ornament")
        pieces.append(t)
    return _finalize_building(tree, pieces, (base_x + 1100, 0))


# ─── GATEHOUSE ──────────────────────────────────────────────────────
def build_gatehouse(tree, props, base_x=-1400):
    """Twin towers flanking an arched gateway with a portcullis grid."""
    r = max(0.6, getattr(props, 'base_radius', 1.0)) * 0.8
    h = max(3.5, getattr(props, 'height', 5.0)) * 1.4
    gate_w = r * 2.6
    gate_h = h * 0.65
    pieces = []
    # Two flanking cylindrical towers (use build_watchtower-style shafts)
    for sx in (-1, 1):
        shaft_c = _cv_circle(tree, (base_x, 200 + sx * 250), r, 16)
        shaft = _fill_extrude(tree, shaft_c.outputs['Curve'] if shaft_c else None,
                              (base_x + 200, 200 + sx * 250),
                              (base_x + 400, 200 + sx * 250), h, "tower")
        pieces.append(_move(tree, shaft,
                            (base_x + 600, 200 + sx * 250),
                            translation=(sx * (gate_w / 2 + r), 0, 0), label="tower"))
        # Conical cap
        cap = _safe_node(tree, 'GeometryNodeMeshCone', (base_x + 800, 200 + sx * 250))
        if cap:
            cap.inputs['Radius Bottom'].default_value = r * 1.1
            cap.inputs['Radius Top'].default_value = 0
            cap.inputs['Depth'].default_value = r * 1.6
            cap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading
            pieces.append(_move(tree, cap.outputs['Mesh'],
                                (base_x + 1000, 200 + sx * 250),
                                translation=(sx * (gate_w / 2 + r), 0, h + r * 0.8),
                                label="house"))
            color_node(cap, "house")
    # Connecting wall block between towers (with arched gate cut)
    wall = _node(tree, 'GeometryNodeMeshCube', (base_x, -300))
    wall.inputs['Size'].default_value = (gate_w, r * 0.6, h * 0.85)
    pieces.append(_move(tree, wall.outputs['Mesh'], (base_x + 200, -300),
                        translation=(0, 0, h * 0.425), label="tower"))
    color_node(wall, "tower")
    # Portcullis grid (vertical + horizontal bars)
    bars_v = 5; bars_h = 3
    for i in range(bars_v):
        b = _node(tree, 'GeometryNodeMeshCube', (base_x, -700 - i * 70))
        b.inputs['Size'].default_value = (0.06, 0.08, gate_h * 0.9)
        x = -gate_w * 0.4 + i * (gate_w * 0.8 / max(1, bars_v - 1))
        pieces.append(_move(tree, b.outputs['Mesh'], (base_x + 220, -700 - i * 70),
                            translation=(x, r * 0.3, gate_h * 0.5), label="ornament"))
        color_node(b, "ornament")
    for j in range(bars_h):
        b = _node(tree, 'GeometryNodeMeshCube', (base_x, -1200 - j * 70))
        b.inputs['Size'].default_value = (gate_w * 0.85, 0.08, 0.06)
        z = gate_h * (0.15 + j * 0.35)
        pieces.append(_move(tree, b.outputs['Mesh'], (base_x + 220, -1200 - j * 70),
                            translation=(0, r * 0.3, z), label="ornament"))
        color_node(b, "ornament")
    # Battlement cap atop the connecting wall
    crenel = _crenel_top(tree, gate_w, r * 0.6, r * 0.4, 7, 0.5,
                         loc=(base_x, -2000), label="ornament")
    pieces.append(_move(tree, crenel, (base_x + 700, -2000),
                        translation=(0, 0, h * 0.85), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1400, 0))


# ─── KEEP / DONJON ──────────────────────────────────────────────────
def build_keep(tree, props, base_x=-1400):
    """Rectangular keep — body + 4 corner turrets + battlements."""
    W = max(2.5, getattr(props, 'base_radius', 1.0) * 3.5)
    H = max(5.0, getattr(props, 'height', 5.0)) * 1.6
    D = W * 0.85
    pieces = []
    # Main body
    body = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    body.inputs['Size'].default_value = (W, D, H)
    pieces.append(_move(tree, body.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, H / 2), label="tower"))
    color_node(body, "tower")
    # Battlement cap on top
    crenel_x = _crenel_top(tree, W, D, H * 0.07, 11, 0.5,
                            loc=(base_x, -400), label="ornament")
    pieces.append(_move(tree, crenel_x, (base_x + 700, -400),
                        translation=(0, 0, H + H * 0.035), label="ornament"))
    # 4 corner turrets — small extruded octagons
    import math
    turret_r = W * 0.13
    turret_h = H * 1.15
    for sx in (-1, 1):
        for sy in (-1, 1):
            tc = _cv_circle(tree, (base_x, -900 - (sx + 1) * 100 - (sy + 1) * 50),
                            turret_r, 12)
            tm = _fill_extrude(tree,
                               tc.outputs['Curve'] if tc else None,
                               (base_x + 200, -900 - (sx + 1) * 100 - (sy + 1) * 50),
                               (base_x + 400, -900 - (sx + 1) * 100 - (sy + 1) * 50),
                               turret_h, "tower")
            pieces.append(_move(tree, tm,
                                (base_x + 600, -900 - (sx + 1) * 100 - (sy + 1) * 50),
                                translation=(sx * W / 2, sy * D / 2, 0), label="tower"))
            # Conical cap
            cap = _safe_node(tree, 'GeometryNodeMeshCone',
                             (base_x + 800, -900 - (sx + 1) * 100 - (sy + 1) * 50))
            if cap:
                cap.inputs['Radius Bottom'].default_value = turret_r * 1.1
                cap.inputs['Radius Top'].default_value = 0
                cap.inputs['Depth'].default_value = turret_r * 2.0
                cap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading
                pieces.append(_move(tree, cap.outputs['Mesh'],
                                    (base_x + 1000, -900 - (sx + 1) * 100 - (sy + 1) * 50),
                                    translation=(sx * W / 2, sy * D / 2, turret_h + turret_r),
                                    label="house"))
                color_node(cap, "house")
    # Single arched front door (extruded curve)
    door_arch = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier', (base_x, -2200))
    if door_arch:
        try:
            door_arch.inputs['Resolution'].default_value = 24
            door_arch.inputs['Start'].default_value  = (-0.6, 0, 0)
            door_arch.inputs['Middle'].default_value = (0, 0, 1.6)
            door_arch.inputs['End'].default_value    = (0.6, 0, 0)
        except Exception:
            pass
        # Thin profile circle for arch frame
        prof = _cv_circle(tree, (base_x, -2400), 0.08, 8)
        sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, -2200))
        if sw and prof:
            _link(tree, door_arch.outputs['Curve'], sw.inputs['Curve'])
            _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
            color_node(sw, "ornament")
            pieces.append(_move(tree, sw.outputs['Mesh'], (base_x + 500, -2200),
                                translation=(0, -D / 2 - 0.05, 0), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1400, 0))


# ─── CURTAIN WALL ───────────────────────────────────────────────────
def build_curtain_wall(tree, props, base_x=-1400):
    """Crenellated curtain wall section with battlement walkway."""
    L = max(3.0, getattr(props, 'rail_length', 4.0)) * 1.8
    H = max(2.0, getattr(props, 'height', 4.0)) * 1.0
    T = max(0.4, getattr(props, 'wall_thickness', 0.5))
    pieces = []
    # Main wall slab
    wall = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    wall.inputs['Size'].default_value = (L, T, H)
    pieces.append(_move(tree, wall.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, H / 2), label="tower"))
    color_node(wall, "tower")
    # Battlement cap (merlons)
    n_m = max(5, int(L / 0.8))
    crenel = _crenel_top(tree, L, T * 1.05, H * 0.18, n_m, 0.5,
                         loc=(base_x, -300), label="ornament")
    pieces.append(_move(tree, crenel, (base_x + 700, -300),
                        translation=(0, 0, H + H * 0.09), label="ornament"))
    # Walkway shelf on the inside of the wall (Y-)
    walk = _node(tree, 'GeometryNodeMeshCube', (base_x, -1000))
    walk.inputs['Size'].default_value = (L, T * 0.9, 0.1)
    pieces.append(_move(tree, walk.outputs['Mesh'], (base_x + 200, -1000),
                        translation=(0, -T * 0.55, H - 0.05), label="house"))
    color_node(walk, "house")
    return _finalize_building(tree, pieces, (base_x + 1100, 0))


# ─── BARBICAN ───────────────────────────────────────────────────────
def build_barbican(tree, props, base_x=-1400):
    """Outer fortified gatehouse: 2 small flanking towers + connecting wall
    with passageway, ahead of where a main gatehouse would sit."""
    r = max(0.5, getattr(props, 'base_radius', 1.0)) * 0.7
    h = max(2.5, getattr(props, 'height', 4.0)) * 1.1
    gap = r * 2.2
    pieces = []
    for sx in (-1, 1):
        c = _cv_circle(tree, (base_x, 200 + sx * 200), r, 12)
        sh = _fill_extrude(tree, c.outputs['Curve'] if c else None,
                           (base_x + 200, 200 + sx * 200),
                           (base_x + 400, 200 + sx * 200), h, "tower")
        pieces.append(_move(tree, sh, (base_x + 600, 200 + sx * 200),
                            translation=(sx * (gap / 2 + r), 0, 0), label="tower"))
        # Crenel ring on top
        for i in range(8):
            import math
            ang = (i / 8) * math.tau
            m = _node(tree, 'GeometryNodeMeshCube', (base_x, -500 - sx * 200 - i * 40))
            m.inputs['Size'].default_value = (r * 0.3, r * 0.18, r * 0.5)
            pieces.append(_move(tree, m.outputs['Mesh'],
                                (base_x + 220, -500 - sx * 200 - i * 40),
                                translation=(sx * (gap / 2 + r) + math.cos(ang) * r * 1.05,
                                             math.sin(ang) * r * 1.05, h + r * 0.15),
                                rotation=(0, 0, ang), label="ornament"))
            color_node(m, "ornament")
    # Connecting wall arch
    wall = _node(tree, 'GeometryNodeMeshCube', (base_x, -1800))
    wall.inputs['Size'].default_value = (gap, r * 0.55, h * 0.4)
    pieces.append(_move(tree, wall.outputs['Mesh'], (base_x + 200, -1800),
                        translation=(0, 0, h * 0.8), label="tower"))
    color_node(wall, "tower")
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── DRAWBRIDGE ─────────────────────────────────────────────────────
def build_drawbridge(tree, props, base_x=-1400):
    """Hinged drawbridge: deck + side rails + chains to upper hinge."""
    L = max(1.5, getattr(props, 'bridge_length', 4.0)) * 0.6
    W = max(1.0, getattr(props, 'bridge_height', 2.0)) * 0.8
    pieces = []
    # Deck — tilted at user-control angle (use sv_complexity as tilt 0..1)
    tilt = min(1.0, getattr(props, 'sv_complexity', 0.5)) * 1.2  # rad
    deck = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    deck.inputs['Size'].default_value = (W, L, 0.12)
    import math
    pieces.append(_move(tree, deck.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, math.cos(tilt) * L / 2,
                                     math.sin(tilt) * L / 2 + 0.06),
                        rotation=(tilt, 0, 0), label="house"))
    color_node(deck, "house")
    # 6 plank ridges across the deck for detail
    for i in range(7):
        p = _node(tree, 'GeometryNodeMeshCube', (base_x, -200 - i * 60))
        p.inputs['Size'].default_value = (W * 0.95, 0.04, 0.04)
        t = -L / 2 + i * (L / 6)
        pieces.append(_move(tree, p.outputs['Mesh'], (base_x + 220, -200 - i * 60),
                            translation=(0,
                                         math.cos(tilt) * (L / 2 + t),
                                         math.sin(tilt) * (L / 2 + t) + 0.13),
                            rotation=(tilt, 0, 0), label="ornament"))
        color_node(p, "ornament")
    # Two side rails
    for sx in (-1, 1):
        rail = _node(tree, 'GeometryNodeMeshCube', (base_x, -800 - (sx + 1) * 50))
        rail.inputs['Size'].default_value = (0.06, L, 0.25)
        pieces.append(_move(tree, rail.outputs['Mesh'],
                            (base_x + 220, -800 - (sx + 1) * 50),
                            translation=(sx * W / 2,
                                         math.cos(tilt) * L / 2,
                                         math.sin(tilt) * L / 2 + 0.18),
                            rotation=(tilt, 0, 0), label="ornament"))
        color_node(rail, "ornament")
    # Chains (2 thin tubes from hinge to upper edge of deck)
    chain_prof = _cv_circle(tree, (base_x, -1500), 0.025, 8)
    for sx in (-1, 1):
        line = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine',
                          (base_x, -1300 - (sx + 1) * 80))
        if line:
            try:
                line.inputs['Start'].default_value = (sx * W / 2, 0, 0.1)
                line.inputs['End'].default_value   = (sx * W / 2,
                                                       math.cos(tilt) * L,
                                                       math.sin(tilt) * L + 0.2)
            except Exception:
                pass
            sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                            (base_x + 220, -1300 - (sx + 1) * 80))
            if sw and chain_prof:
                _link(tree, line.outputs['Curve'], sw.inputs['Curve'])
                _link(tree, chain_prof.outputs['Curve'], sw.inputs['Profile Curve'])
                color_node(sw, "ornament")
                pieces.append(sw.outputs['Mesh'])
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── STONE BRIDGE ───────────────────────────────────────────────────
def build_stone_bridge(tree, props, base_x=-1400):
    """Multi-arch stone bridge with railings."""
    n = max(1, getattr(props, 'bridge_arches', 3))
    span = max(2.0, getattr(props, 'bridge_length', 6.0)) * 1.2
    height = max(1.0, getattr(props, 'bridge_height', 2.0))
    width = max(1.0, getattr(props, 'bridge_walkway', 1.6))
    arch_w = span / n
    pieces = []
    # Deck slab
    deck = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    deck.inputs['Size'].default_value = (width, span, 0.25)
    pieces.append(_move(tree, deck.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, height + 0.13), label="house"))
    color_node(deck, "house")
    # Arches (bezier per arch) + piers
    prof = _cv_circle(tree, (base_x, -3000), width * 0.42, 16)
    for i in range(n):
        y_center = -span / 2 + arch_w * (i + 0.5)
        # Arch curve = quadratic bezier
        ab = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier',
                        (base_x, -200 - i * 200))
        if ab:
            try:
                ab.inputs['Resolution'].default_value = 24
                ab.inputs['Start'].default_value  = (0, y_center - arch_w / 2, 0)
                ab.inputs['Middle'].default_value = (0, y_center, height * 1.1)
                ab.inputs['End'].default_value    = (0, y_center + arch_w / 2, 0)
            except Exception:
                pass
            sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                            (base_x + 220, -200 - i * 200))
            if sw and prof:
                _link(tree, ab.outputs['Curve'], sw.inputs['Curve'])
                _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
                color_node(sw, "tower")
                pieces.append(sw.outputs['Mesh'])
        # Pier between arches (rectangular pillar dropping down from deck)
        if i < n - 1:
            pier = _node(tree, 'GeometryNodeMeshCube',
                         (base_x, -1500 - i * 100))
            pier.inputs['Size'].default_value = (width * 0.7, arch_w * 0.18, height * 1.05)
            pieces.append(_move(tree, pier.outputs['Mesh'],
                                (base_x + 220, -1500 - i * 100),
                                translation=(0, y_center + arch_w / 2,
                                             height * 0.525), label="tower"))
            color_node(pier, "tower")
    # Railings (curve-swept)
    rail_prof = _cv_circle(tree, (base_x, -3300), 0.07, 8)
    for sx in (-1, 1):
        rail = _safe_node(tree, 'GeometryNodeCurvePrimitiveLine',
                          (base_x, -2400 - (sx + 1) * 100))
        if rail:
            try:
                rail.inputs['Start'].default_value = (sx * width / 2, -span / 2,
                                                       height + 0.35)
                rail.inputs['End'].default_value   = (sx * width / 2,  span / 2,
                                                       height + 0.35)
            except Exception:
                pass
            sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                            (base_x + 220, -2400 - (sx + 1) * 100))
            if sw and rail_prof:
                _link(tree, rail.outputs['Curve'], sw.inputs['Curve'])
                _link(tree, rail_prof.outputs['Curve'], sw.inputs['Profile Curve'])
                color_node(sw, "ornament")
                pieces.append(sw.outputs['Mesh'])
    return _finalize_building(tree, pieces, (base_x + 1400, 0))


# ─── WINDMILL ───────────────────────────────────────────────────────
def build_windmill(tree, props, base_x=-1400):
    """Tower windmill: cylindrical body + cap + 4 rotating blades."""
    r = max(0.7, getattr(props, 'base_radius', 1.0)) * 1.0
    h = max(3.5, getattr(props, 'height', 5.0)) * 1.6
    pieces = []
    # Tower (tapered top via 2 stacked cylinders)
    body_c1 = _cv_circle(tree, (base_x, 200), r, 16)
    body1 = _fill_extrude(tree, body_c1.outputs['Curve'] if body_c1 else None,
                          (base_x + 200, 200), (base_x + 400, 200),
                          h * 0.65, "tower")
    pieces.append(body1)
    body_c2 = _cv_circle(tree, (base_x, -200), r * 0.78, 16)
    body2 = _fill_extrude(tree, body_c2.outputs['Curve'] if body_c2 else None,
                          (base_x + 200, -200), (base_x + 400, -200),
                          h * 0.35, "tower")
    pieces.append(_move(tree, body2, (base_x + 600, -200),
                        translation=(0, 0, h * 0.65), label="tower"))
    # Cap (smaller dome)
    cap = _safe_node(tree, 'GeometryNodeMeshUVSphere', (base_x, -600))
    if cap:
        cap.inputs['Radius'].default_value = r * 0.85
        cap.inputs['Segments'].default_value = 16
        cap.inputs['Rings'].default_value    = 12
        pieces.append(_move(tree, cap.outputs['Mesh'], (base_x + 200, -600),
                            translation=(0, 0, h), scale=(1, 1, 0.6),
                            label="house"))
        color_node(cap, "house")
    # 4 blades: sweep beams radially
    blade_len = r * 3.0
    blade_w = r * 0.6
    import math
    for i in range(4):
        ang = (i / 4) * math.tau
        blade = _node(tree, 'GeometryNodeMeshCube', (base_x, -1200 - i * 100))
        blade.inputs['Size'].default_value = (blade_w, 0.06, blade_len)
        # Position outward from cap front; rotated around Y for sail tilt
        bx = math.sin(ang) * (blade_len / 2 + r * 0.2)
        bz = math.cos(ang) * (blade_len / 2 + r * 0.2) + h
        pieces.append(_move(tree, blade.outputs['Mesh'],
                            (base_x + 220, -1200 - i * 100),
                            translation=(bx, -r * 0.95, bz),
                            rotation=(0, ang, 0), label="ornament"))
        color_node(blade, "ornament")
    # Tiny door at base
    door = _node(tree, 'GeometryNodeMeshCube', (base_x, -2000))
    door.inputs['Size'].default_value = (0.5, 0.05, 1.0)
    pieces.append(_move(tree, door.outputs['Mesh'], (base_x + 200, -2000),
                        translation=(0, -r, 0.5), label="ornament"))
    color_node(door, "ornament")
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── CHAPEL ─────────────────────────────────────────────────────────
def build_chapel(tree, props, base_x=-1400):
    """Small chapel: nave + apse + single bell tower at front."""
    W = max(2.0, getattr(props, 'base_radius', 1.0) * 2.4)
    L = W * 2.0
    H = max(2.5, getattr(props, 'height', 4.0)) * 1.0
    pieces = []
    # Nave body
    nave = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    nave.inputs['Size'].default_value = (W, L, H)
    pieces.append(_move(tree, nave.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, H / 2), label="tower"))
    color_node(nave, "tower")
    # Gabled roof — two slanted slabs
    import math
    pitch = math.atan2(H * 0.5, W * 0.5)
    for sx in (-1, 1):
        slab = _node(tree, 'GeometryNodeMeshCube', (base_x, -200 + (sx + 1) * 100))
        slab.inputs['Size'].default_value = (W * 0.55 / math.cos(pitch), L + 0.3, 0.1)
        # Tilt around Y so X-axis rises
        pieces.append(_move(tree, slab.outputs['Mesh'],
                            (base_x + 220, -200 + (sx + 1) * 100),
                            translation=(sx * W * 0.25, 0, H + H * 0.25),
                            rotation=(0, sx * -pitch, 0), label="house"))
        color_node(slab, "house")
    # Apse (semi-cylindrical end via extruded half-circle)
    apse_c = _cv_circle(tree, (base_x, -800), W * 0.4, 16)
    apse = _fill_extrude(tree, apse_c.outputs['Curve'] if apse_c else None,
                         (base_x + 200, -800), (base_x + 400, -800),
                         H * 0.95, "tower")
    pieces.append(_move(tree, apse, (base_x + 600, -800),
                        translation=(0, L / 2 + 0.05, 0),
                        scale=(1, 0.6, 1), label="tower"))
    # Bell tower at front
    tower_r = W * 0.22
    tower_h = H * 1.8
    tc = _cv_circle(tree, (base_x, -1400), tower_r, 16)
    tm = _fill_extrude(tree, tc.outputs['Curve'] if tc else None,
                       (base_x + 200, -1400), (base_x + 400, -1400),
                       tower_h, "tower")
    pieces.append(_move(tree, tm, (base_x + 600, -1400),
                        translation=(0, -L / 2 - tower_r * 0.5, 0),
                        label="tower"))
    # Tower roof (cone)
    tcap = _safe_node(tree, 'GeometryNodeMeshCone', (base_x, -1800))
    if tcap:
        tcap.inputs['Radius Bottom'].default_value = tower_r * 1.1
        tcap.inputs['Radius Top'].default_value = 0
        tcap.inputs['Depth'].default_value = tower_r * 2.4
        tcap.inputs['Vertices'].default_value = 32  # bumped from 16 in v2.31 for smoother shading
        pieces.append(_move(tree, tcap.outputs['Mesh'], (base_x + 200, -1800),
                            translation=(0, -L / 2 - tower_r * 0.5,
                                          tower_h + tower_r * 1.2),
                            label="house"))
        color_node(tcap, "house")
    # Arched front door
    door_arch = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier',
                           (base_x, -2300))
    if door_arch:
        try:
            door_arch.inputs['Resolution'].default_value = 24
            door_arch.inputs['Start'].default_value  = (-0.4, 0, 0)
            door_arch.inputs['Middle'].default_value = (0, 0, 1.4)
            door_arch.inputs['End'].default_value    = (0.4, 0, 0)
        except Exception:
            pass
        prof = _cv_circle(tree, (base_x, -2500), 0.06, 8)
        sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                        (base_x + 250, -2300))
        if sw and prof:
            _link(tree, door_arch.outputs['Curve'], sw.inputs['Curve'])
            _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
            color_node(sw, "ornament")
            pieces.append(_move(tree, sw.outputs['Mesh'], (base_x + 500, -2300),
                                translation=(0, -L / 2 - 0.05, 0),
                                label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1300, 0))


# ─── VILLAGE WELL ───────────────────────────────────────────────────
def build_village_well(tree, props, base_x=-1400):
    """Stone village well: cylindrical wall + crossbar with bucket + roof."""
    r = max(0.4, getattr(props, 'base_radius', 1.0)) * 0.7
    pieces = []
    # Well ring (subdivided torus or extruded circle annulus)
    ring_outer = _cv_circle(tree, (base_x, 200), r * 1.15, 24)
    ring_inner = _cv_circle(tree, (base_x, 0), r * 0.85, 24)
    # Easier: an extruded thick ring built by 2 set positions
    # Use a fill-extrude of outer circle, subtract conceptually — for now,
    # build as a single extruded annulus via Mesh Boolean: skip, use torus
    well = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, 200))
    if well:
        try:
            well.inputs['Major Radius'].default_value = r
            well.inputs['Minor Radius'].default_value = r * 0.18
            well.inputs['Major Segments'].default_value = 24
            well.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        pieces.append(_move(tree, well.outputs['Mesh'], (base_x + 200, 200),
                            translation=(0, 0, r * 0.4),
                            scale=(1, 1, 1.4), label="tower"))
        color_node(well, "tower")
    # 2 vertical posts + horizontal crossbar
    for sx in (-1, 1):
        post = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -300 - (sx + 1) * 100))
        post.inputs['Radius'].default_value = 0.06
        post.inputs['Depth'].default_value  = r * 2.5
        post.inputs['Vertices'].default_value = 12
        pieces.append(_move(tree, post.outputs['Mesh'],
                            (base_x + 220, -300 - (sx + 1) * 100),
                            translation=(sx * r * 1.2, 0, r * 1.85),
                            label="ornament"))
        color_node(post, "ornament")
    crossbar = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -800))
    crossbar.inputs['Radius'].default_value = 0.06
    crossbar.inputs['Depth'].default_value = r * 2.6
    crossbar.inputs['Vertices'].default_value = 12
    pieces.append(_move(tree, crossbar.outputs['Mesh'], (base_x + 200, -800),
                        translation=(0, 0, r * 3.0),
                        rotation=(0, 1.5708, 0), label="ornament"))
    color_node(crossbar, "ornament")
    # Bucket (small cylinder hanging from rope)
    bucket = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -1200))
    bucket.inputs['Radius'].default_value = r * 0.22
    bucket.inputs['Depth'].default_value = r * 0.35
    bucket.inputs['Vertices'].default_value = 12
    pieces.append(_move(tree, bucket.outputs['Mesh'], (base_x + 200, -1200),
                        translation=(0, 0, r * 1.5),
                        label="ornament"))
    color_node(bucket, "ornament")
    # Pitched roof on posts (2 slanted slabs)
    import math
    for sx in (-1, 1):
        slab = _node(tree, 'GeometryNodeMeshCube', (base_x, -1700 + (sx + 1) * 80))
        slab.inputs['Size'].default_value = (r * 1.0, r * 2.8, 0.05)
        pitch = math.atan2(r * 0.6, r * 0.5)
        pieces.append(_move(tree, slab.outputs['Mesh'],
                            (base_x + 220, -1700 + (sx + 1) * 80),
                            translation=(sx * r * 0.3, 0, r * 3.5),
                            rotation=(0, sx * -pitch, 0), label="house"))
        color_node(slab, "house")
    return _finalize_building(tree, pieces, (base_x + 1100, 0))


# ─── MARKET STALL ───────────────────────────────────────────────────
def build_market_stall(tree, props, base_x=-1400):
    """Merchant stall with awning + counter + hanging sign."""
    W = max(1.0, getattr(props, 'base_radius', 1.0) * 1.6)
    D = W * 0.6
    H = max(2.0, getattr(props, 'height', 3.0)) * 0.9
    pieces = []
    # Counter — extruded rectangle
    counter = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    counter.inputs['Size'].default_value = (W, D, H * 0.4)
    pieces.append(_move(tree, counter.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, H * 0.2), label="tower"))
    color_node(counter, "tower")
    # 4 corner posts
    for sx in (-1, 1):
        for sy in (-1, 1):
            post = _node(tree, 'GeometryNodeMeshCylinder',
                         (base_x, -300 - (sx + 1) * 80 - (sy + 1) * 40))
            post.inputs['Radius'].default_value = 0.05
            post.inputs['Depth'].default_value = H
            post.inputs['Vertices'].default_value = 8
            pieces.append(_move(tree, post.outputs['Mesh'],
                                (base_x + 220, -300 - (sx + 1) * 80 - (sy + 1) * 40),
                                translation=(sx * W / 2, sy * D / 2, H / 2),
                                label="ornament"))
            color_node(post, "ornament")
    # Awning (single slanted slab)
    import math
    pitch = 0.25
    awning = _node(tree, 'GeometryNodeMeshCube', (base_x, -1200))
    awning.inputs['Size'].default_value = (W * 1.2, D * 1.3, 0.06)
    pieces.append(_move(tree, awning.outputs['Mesh'], (base_x + 200, -1200),
                        translation=(0, 0, H + 0.05),
                        rotation=(pitch, 0, 0), label="house"))
    color_node(awning, "house")
    # Hanging sign (thin board on a rope)
    sign = _node(tree, 'GeometryNodeMeshCube', (base_x, -1700))
    sign.inputs['Size'].default_value = (W * 0.4, 0.04, 0.25)
    pieces.append(_move(tree, sign.outputs['Mesh'], (base_x + 200, -1700),
                        translation=(0, -D / 2 - 0.05, H * 0.85),
                        label="ornament"))
    color_node(sign, "ornament")
    # Rope to sign (thin cylinder)
    rope = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -2100))
    rope.inputs['Radius'].default_value = 0.012
    rope.inputs['Depth'].default_value = 0.15
    rope.inputs['Vertices'].default_value = 6
    pieces.append(_move(tree, rope.outputs['Mesh'], (base_x + 200, -2100),
                        translation=(0, -D / 2 - 0.05, H * 0.97),
                        label="ornament"))
    color_node(rope, "ornament")
    return _finalize_building(tree, pieces, (base_x + 1100, 0))


# ─── OBELISK ────────────────────────────────────────────────────────
def build_obelisk(tree, props, base_x=-1400):
    """Tall narrow obelisk: 4-sided tapered shaft + pyramidion top + plinth."""
    base = max(0.5, getattr(props, 'base_radius', 1.0)) * 0.7
    h = max(3.0, getattr(props, 'height', 5.0)) * 2.0
    top = base * 0.45
    pieces = []
    # Plinth (square block at base)
    plinth = _node(tree, 'GeometryNodeMeshCube', (base_x, 200))
    plinth.inputs['Size'].default_value = (base * 1.8, base * 1.8, base * 0.8)
    pieces.append(_move(tree, plinth.outputs['Mesh'], (base_x + 200, 200),
                        translation=(0, 0, base * 0.4), label="house"))
    color_node(plinth, "house")
    # Shaft — tapered: 8 verts at base + 8 at top, joined as a frustum
    # Build via 2 stacked rectangles using bmesh-equivalent: easiest is
    # a cube transformed with Set Position via Spline Parameter on a line,
    # but simplest is two Mesh Cubes scaled + a custom connecting via
    # GeometryNodeFillCurve on a profile that varies. We'll approximate by
    # extruding a square curve with `Taper Curve`.
    sq = _cv_circle(tree, (base_x, -400), base, 4)   # 4-vert "circle" = square
    if sq:
        # Set rotation 45° so square edges are axis-aligned
        sq_rot = _move(tree, sq.outputs['Curve'], (base_x + 200, -400),
                       rotation=(0, 0, 0.7854), label="tower")
        # Fill the square
        sf = _safe_node(tree, 'GeometryNodeFillCurve', (base_x + 400, -400))
        if sf:
            try:
                sf.mode = 'NGONS'
            except Exception:
                pass
            _link(tree, sq_rot, sf.inputs['Curve'])
            # Extrude upward
            sx = _safe_node(tree, 'GeometryNodeExtrudeMesh',
                            (base_x + 600, -400))
            if sx:
                sx.mode = 'FACES'
                sx.inputs['Offset Scale'].default_value = h
                _link(tree, sf.outputs['Mesh'], sx.inputs['Mesh'])
                # Now scale TOP face only — approximate taper by scaling
                # whole mesh with a Z-dependent factor via Set Position
                pos = _node(tree, 'GeometryNodeInputPosition',
                            (base_x + 600, -700))
                sep = _node(tree, 'ShaderNodeSeparateXYZ',
                            (base_x + 800, -700))
                _link(tree, pos.outputs['Position'], sep.inputs['Vector'])
                # taper = lerp(1.0, top/base, z/h)
                norm_z = _node(tree, 'ShaderNodeMath', (base_x + 1000, -700))
                norm_z.operation = 'DIVIDE'
                _link(tree, sep.outputs['Z'], norm_z.inputs[0])
                norm_z.inputs[1].default_value = h
                taper = _node(tree, 'ShaderNodeMath', (base_x + 1200, -700))
                taper.operation = 'MULTIPLY_ADD'
                _link(tree, norm_z.outputs['Value'], taper.inputs[0])
                taper.inputs[1].default_value = (top / base) - 1.0
                taper.inputs[2].default_value = 1.0
                # Scale X,Y by taper
                scl_x = _node(tree, 'ShaderNodeMath', (base_x + 1400, -700))
                scl_x.operation = 'MULTIPLY'
                _link(tree, sep.outputs['X'], scl_x.inputs[0])
                _link(tree, taper.outputs['Value'], scl_x.inputs[1])
                scl_y = _node(tree, 'ShaderNodeMath', (base_x + 1400, -900))
                scl_y.operation = 'MULTIPLY'
                _link(tree, sep.outputs['Y'], scl_y.inputs[0])
                _link(tree, taper.outputs['Value'], scl_y.inputs[1])
                # Subtract original X/Y to get offset
                ox = _node(tree, 'ShaderNodeMath', (base_x + 1600, -700))
                ox.operation = 'SUBTRACT'
                _link(tree, scl_x.outputs['Value'], ox.inputs[0])
                _link(tree, sep.outputs['X'], ox.inputs[1])
                oy = _node(tree, 'ShaderNodeMath', (base_x + 1600, -900))
                oy.operation = 'SUBTRACT'
                _link(tree, scl_y.outputs['Value'], oy.inputs[0])
                _link(tree, sep.outputs['Y'], oy.inputs[1])
                ovec = _node(tree, 'ShaderNodeCombineXYZ',
                             (base_x + 1800, -800))
                _link(tree, ox.outputs['Value'], ovec.inputs['X'])
                _link(tree, oy.outputs['Value'], ovec.inputs['Y'])
                sp = _safe_node(tree, 'GeometryNodeSetPosition',
                                (base_x + 2000, -400))
                if sp:
                    _link(tree, sx.outputs['Mesh'], sp.inputs['Geometry'])
                    _link(tree, ovec.outputs['Vector'], sp.inputs['Offset'])
                    pieces.append(_move(tree, sp.outputs['Geometry'],
                                        (base_x + 2200, -400),
                                        translation=(0, 0, base * 0.8),
                                        label="tower"))
    # Pyramidion (cone at top)
    pyr = _safe_node(tree, 'GeometryNodeMeshCone', (base_x, -2200))
    if pyr:
        pyr.inputs['Radius Bottom'].default_value = top * 1.05
        pyr.inputs['Radius Top'].default_value = 0
        pyr.inputs['Depth'].default_value = top * 2.4
        pyr.inputs['Vertices'].default_value = 24
        pieces.append(_move(tree, pyr.outputs['Mesh'], (base_x + 200, -2200),
                            translation=(0, 0, base * 0.8 + h + top * 1.2),
                            rotation=(0, 0, 0.7854), label="house"))
        color_node(pyr, "house")
    return _finalize_building(tree, pieces, (base_x + 2500, 0))


# ======================================================================
# 🏘 TOWN / CIVIC / ASIAN PIECE LIBRARY (v2.24) — Layer 1 additions
# ======================================================================
# All use the vector Size socket on MeshCube (Blender 5.1 API).
# Geometry composed from curve-fill-extrude and curve sweeps where possible.

def _cube(tree, loc, sx, sy, sz, label="tower"):
    """Make a MeshCube with the vector `Size` socket (Blender 5.1 correct API)."""
    c = _node(tree, 'GeometryNodeMeshCube', loc)
    c.inputs['Size'].default_value = (sx, sy, sz)
    color_node(c, label)
    return c.outputs['Mesh']


# ─── TOWN HOUSE (Tudor) ─────────────────────────────────────────────
def build_town_house(tree, props, base_x=-1400):
    """Multi-story Tudor town house — stone base, jettied upper floor, gable roof."""
    W = max(2.0, getattr(props, 'base_radius', 1.0) * 2.4)
    D = W * 0.7
    floor_h = max(1.5, getattr(props, 'height', 4.0) * 0.45)
    floors = max(2, getattr(props, 'building_floors', 3))
    pieces = []
    # Floor stack with jetty (upper floors overhang by +5%)
    for fi in range(floors):
        ww = W * (1.0 + fi * 0.06)   # progressively wider above (jetty)
        dd = D * (1.0 + fi * 0.06)
        zb = fi * floor_h
        pieces.append(_move(tree,
                             _cube(tree, (base_x, 200 - fi * 200), ww, dd, floor_h,
                                   "house"),
                             (base_x + 200, 200 - fi * 200),
                             translation=(0, 0, zb + floor_h / 2), label="house"))
    # Half-timber X-braces on ground+upper walls (front-facing)
    import math
    for fi in range(floors):
        zb = fi * floor_h
        ww = W * (1.0 + fi * 0.06)
        # Two diagonal beams crossing in an X
        for sd in (-1, 1):
            beam = _cube(tree, (base_x, -800 - fi * 200 - (sd + 1) * 60),
                          ww * 0.95, 0.04, 0.08, "ornament")
            tilt = math.atan2(floor_h, ww)
            pieces.append(_move(tree, beam, (base_x + 220, -800 - fi * 200 - (sd + 1) * 60),
                                 translation=(0, -dd / 2 - 0.025, zb + floor_h / 2),
                                 rotation=(sd * tilt, 0, 0), label="ornament"))
    # Steep gable roof — 2 slabs
    roof_h = floor_h * 0.9
    pitch = math.atan2(roof_h, W * 0.55)
    for sx in (-1, 1):
        slab = _cube(tree, (base_x, -2000 + (sx + 1) * 100),
                      W * 0.6 / math.cos(pitch), D + 0.3, 0.1, "house")
        pieces.append(_move(tree, slab, (base_x + 220, -2000 + (sx + 1) * 100),
                             translation=(sx * W * 0.27, 0, floors * floor_h + roof_h * 0.5),
                             rotation=(0, sx * -pitch, 0), label="house"))
    # Brick chimney
    chim = _cube(tree, (base_x, -2400), 0.35, 0.25, floor_h * 0.8, "brick")
    pieces.append(_move(tree, chim, (base_x + 200, -2400),
                         translation=(W * 0.3, 0, floors * floor_h + roof_h * 0.6),
                         label="brick"))
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── TAVERN ─────────────────────────────────────────────────────────
def build_tavern(tree, props, base_x=-1400):
    """Tavern: 2-story half-timber + hanging sign + chimney."""
    W = max(2.5, getattr(props, 'base_radius', 1.0) * 3.0)
    D = W * 0.75
    H = max(2.5, getattr(props, 'height', 4.0))
    pieces = []
    # Ground floor (stone)
    pieces.append(_move(tree, _cube(tree, (base_x, 200), W, D, H, "tower"),
                         (base_x + 200, 200),
                         translation=(0, 0, H / 2), label="tower"))
    # Upper floor (timber, slightly jettied)
    pieces.append(_move(tree, _cube(tree, (base_x, -100), W * 1.06, D * 1.06, H * 0.85, "house"),
                         (base_x + 200, -100),
                         translation=(0, 0, H + H * 0.425), label="house"))
    # Gable roof
    import math
    roof_h = H * 0.8
    pitch = math.atan2(roof_h, W * 0.55)
    for sx in (-1, 1):
        slab = _cube(tree, (base_x, -500 + (sx + 1) * 80),
                      W * 0.65 / math.cos(pitch), D * 1.15, 0.12, "house")
        pieces.append(_move(tree, slab, (base_x + 220, -500 + (sx + 1) * 80),
                             translation=(sx * W * 0.3, 0, H * 1.85 + roof_h * 0.5),
                             rotation=(0, sx * -pitch, 0), label="house"))
    # Hanging sign on a bracket
    bracket = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -1000))
    bracket.inputs['Radius'].default_value = 0.04
    bracket.inputs['Depth'].default_value = 0.5
    bracket.inputs['Vertices'].default_value = 8
    pieces.append(_move(tree, bracket.outputs['Mesh'], (base_x + 200, -1000),
                         translation=(W / 2 + 0.2, 0, H * 1.6),
                         rotation=(0, 1.5708, 0), label="ornament"))
    color_node(bracket, "ornament")
    pieces.append(_move(tree, _cube(tree, (base_x, -1300), 0.06, 0.45, 0.55, "ornament"),
                         (base_x + 200, -1300),
                         translation=(W / 2 + 0.45, 0, H * 1.3), label="ornament"))
    # Chimney
    pieces.append(_move(tree, _cube(tree, (base_x, -1700), 0.4, 0.3, H * 1.4, "brick"),
                         (base_x + 200, -1700),
                         translation=(-W * 0.35, 0, H * 1.6), label="brick"))
    # Front door
    door_arch = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier', (base_x, -2100))
    if door_arch:
        try:
            door_arch.inputs['Resolution'].default_value = 24
            door_arch.inputs['Start'].default_value  = (-0.5, 0, 0)
            door_arch.inputs['Middle'].default_value = (0, 0, 1.6)
            door_arch.inputs['End'].default_value    = (0.5, 0, 0)
        except Exception:
            pass
        prof = _cv_circle(tree, (base_x, -2300), 0.06, 8)
        sw = _safe_node(tree, 'GeometryNodeCurveToMesh', (base_x + 250, -2100))
        if sw and prof:
            _link(tree, door_arch.outputs['Curve'], sw.inputs['Curve'])
            _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
            color_node(sw, "ornament")
            pieces.append(_move(tree, sw.outputs['Mesh'], (base_x + 500, -2100),
                                 translation=(0, -D / 2 - 0.05, 0), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── BLACKSMITH ────────────────────────────────────────────────────
def build_blacksmith(tree, props, base_x=-1400):
    """Forge with open front, large brick chimney, anvil silhouette inside."""
    W = max(2.0, getattr(props, 'base_radius', 1.0) * 2.6)
    D = W * 0.85
    H = max(2.0, getattr(props, 'height', 3.5))
    pieces = []
    # Three walls (open front)
    pieces.append(_move(tree, _cube(tree, (base_x, 200), 0.3, D, H, "tower"),
                         (base_x + 200, 200), translation=(-W / 2, 0, H / 2), label="tower"))
    pieces.append(_move(tree, _cube(tree, (base_x, 0), 0.3, D, H, "tower"),
                         (base_x + 200, 0), translation=(W / 2, 0, H / 2), label="tower"))
    pieces.append(_move(tree, _cube(tree, (base_x, -200), W, 0.3, H, "tower"),
                         (base_x + 200, -200), translation=(0, D / 2, H / 2), label="tower"))
    # Sloped roof slab (single pitch over the open front)
    import math
    pitch = math.atan2(H * 0.4, D)
    pieces.append(_move(tree, _cube(tree, (base_x, -500),
                                      W + 0.3, D / math.cos(pitch), 0.1, "house"),
                         (base_x + 200, -500),
                         translation=(0, 0, H + 0.15),
                         rotation=(pitch, 0, 0), label="house"))
    # Massive chimney rising through roof
    pieces.append(_move(tree, _cube(tree, (base_x, -900), 0.7, 0.7, H * 1.7, "brick"),
                         (base_x + 200, -900),
                         translation=(W * 0.25, D * 0.25, H * 1.0), label="brick"))
    # Anvil inside (subdivided icosphere flattened + cube base)
    pieces.append(_move(tree, _cube(tree, (base_x, -1300), 0.5, 0.3, 0.4, "tower"),
                         (base_x + 200, -1300),
                         translation=(-W * 0.1, -D * 0.1, 0.2), label="tower"))
    pieces.append(_move(tree, _cube(tree, (base_x, -1500), 0.8, 0.18, 0.15, "ornament"),
                         (base_x + 200, -1500),
                         translation=(-W * 0.1, -D * 0.1, 0.5), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1100, 0))


# ─── STABLE ─────────────────────────────────────────────────────────
def build_stable(tree, props, base_x=-1400):
    """Long low building with N stall doors along the front."""
    n_stalls = max(3, getattr(props, 'recursion_depth', 4))
    stall_w = 1.5
    W = stall_w * n_stalls
    D = max(2.0, getattr(props, 'base_radius', 1.0) * 2.0)
    H = max(1.8, getattr(props, 'height', 3.0))
    pieces = []
    # Body
    pieces.append(_move(tree, _cube(tree, (base_x, 200), W, D, H, "tower"),
                         (base_x + 200, 200), translation=(0, 0, H / 2), label="tower"))
    # Gable roof — single ridge
    import math
    roof_h = H * 0.5
    pitch = math.atan2(roof_h, D * 0.5)
    for sy in (-1, 1):
        slab = _cube(tree, (base_x, -300 + (sy + 1) * 100),
                      W + 0.2, D * 0.6 / math.cos(pitch), 0.1, "house")
        pieces.append(_move(tree, slab, (base_x + 220, -300 + (sy + 1) * 100),
                             translation=(0, sy * D * 0.25, H + roof_h * 0.5),
                             rotation=(sy * -pitch, 0, 0), label="house"))
    # Stall doors (top half open via 2 cubes per door)
    for i in range(n_stalls):
        x = -W / 2 + stall_w * (i + 0.5)
        # Lower half-door
        pieces.append(_move(tree, _cube(tree, (base_x, -1000 - i * 80),
                                          stall_w * 0.85, 0.04, H * 0.45, "ornament"),
                             (base_x + 220, -1000 - i * 80),
                             translation=(x, -D / 2 - 0.02, H * 0.225), label="ornament"))
        # Frame around opening
        pieces.append(_move(tree, _cube(tree, (base_x, -1200 - i * 80),
                                          stall_w * 0.95, 0.06, 0.08, "tower"),
                             (base_x + 220, -1200 - i * 80),
                             translation=(x, -D / 2 - 0.03, H * 0.95), label="tower"))
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── BELL TOWER (Campanile) ─────────────────────────────────────────
def build_bell_tower(tree, props, base_x=-1400):
    """Tall square stone bell tower with louvres + pyramidal cap."""
    side = max(1.5, getattr(props, 'base_radius', 1.0) * 1.8)
    H = max(6.0, getattr(props, 'height', 5.0) * 2.0)
    pieces = []
    # Shaft
    pieces.append(_move(tree, _cube(tree, (base_x, 200), side, side, H, "tower"),
                         (base_x + 200, 200), translation=(0, 0, H / 2), label="tower"))
    # Belfry — wider band near top
    belfry_h = H * 0.18
    pieces.append(_move(tree, _cube(tree, (base_x, -200),
                                      side * 1.15, side * 1.15, belfry_h, "house"),
                         (base_x + 200, -200),
                         translation=(0, 0, H - belfry_h / 2), label="house"))
    # 4 louvred arches (one per face) — curve quad bezier + circular profile
    import math
    for face in range(4):
        ang = face * math.pi / 2
        ab = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier',
                        (base_x, -600 - face * 100))
        if ab is None: continue
        try:
            ab.inputs['Resolution'].default_value = 16
            ab.inputs['Start'].default_value  = (-side * 0.32, 0, 0)
            ab.inputs['Middle'].default_value = (0, 0, side * 0.45)
            ab.inputs['End'].default_value    = (side * 0.32, 0, 0)
        except Exception:
            pass
        prof = _cv_circle(tree, (base_x, -800 - face * 100), 0.06, 8)
        sw = _safe_node(tree, 'GeometryNodeCurveToMesh',
                        (base_x + 220, -600 - face * 100))
        if sw and prof:
            _link(tree, ab.outputs['Curve'], sw.inputs['Curve'])
            _link(tree, prof.outputs['Curve'], sw.inputs['Profile Curve'])
            color_node(sw, "ornament")
            pieces.append(_move(tree, sw.outputs['Mesh'], (base_x + 500, -600 - face * 100),
                                 translation=(math.cos(ang) * (side * 0.58 + 0.05),
                                              math.sin(ang) * (side * 0.58 + 0.05),
                                              H - belfry_h * 0.5),
                                 rotation=(0, 0, ang + 1.5708),
                                 label="ornament"))
    # Pyramidal cap (4-vertex cone)
    cap = _safe_node(tree, 'GeometryNodeMeshCone', (base_x, -1800))
    if cap:
        cap.inputs['Radius Bottom'].default_value = side * 0.85
        cap.inputs['Radius Top'].default_value = 0
        cap.inputs['Depth'].default_value = side * 1.6
        cap.inputs['Vertices'].default_value = 4
        pieces.append(_move(tree, cap.outputs['Mesh'], (base_x + 200, -1800),
                             translation=(0, 0, H + side * 0.8),
                             rotation=(0, 0, 0.7854), label="house"))
        color_node(cap, "house")
    # Small cross/finial on top
    pieces.append(_move(tree, _cube(tree, (base_x, -2200), 0.08, 0.08, 0.45, "ornament"),
                         (base_x + 200, -2200),
                         translation=(0, 0, H + side * 1.85), label="ornament"))
    pieces.append(_move(tree, _cube(tree, (base_x, -2400), 0.32, 0.08, 0.08, "ornament"),
                         (base_x + 200, -2400),
                         translation=(0, 0, H + side * 1.8), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1200, 0))


# ─── MONASTERY CLOISTER ─────────────────────────────────────────────
def build_monastery(tree, props, base_x=-1400):
    """Square cloister: 4 walls forming a courtyard, each with a colonnade."""
    side = max(3.5, getattr(props, 'base_radius', 1.0) * 5.0)
    cor_w = side * 0.18   # corridor width
    H = max(2.5, getattr(props, 'height', 4.0))
    pieces = []
    # 4 covered colonnade walls
    for face in range(4):
        import math
        ang = face * math.pi / 2
        # Outer wall
        pieces.append(_move(tree, _cube(tree, (base_x, 200 - face * 200),
                                          side, 0.3, H, "tower"),
                             (base_x + 200, 200 - face * 200),
                             translation=(math.cos(ang + math.pi / 2) * (side / 2),
                                          math.sin(ang + math.pi / 2) * (side / 2), H / 2),
                             rotation=(0, 0, ang), label="tower"))
        # Inner colonnade — 6 columns per side
        n_cols = 6
        for c in range(n_cols):
            t = -side / 2 + (c + 0.5) * (side / n_cols)
            col = _node(tree, 'GeometryNodeMeshCylinder',
                        (base_x, -800 - face * 200 - c * 60))
            col.inputs['Radius'].default_value = 0.12
            col.inputs['Depth'].default_value = H * 0.85
            col.inputs['Vertices'].default_value = 12
            pieces.append(_move(tree, col.outputs['Mesh'],
                                 (base_x + 220, -800 - face * 200 - c * 60),
                                 translation=(math.cos(ang + math.pi / 2) * (side / 2 - cor_w)
                                              + math.cos(ang) * t,
                                              math.sin(ang + math.pi / 2) * (side / 2 - cor_w)
                                              + math.sin(ang) * t,
                                              H * 0.425), label="tower"))
            color_node(col, "tower")
        # Slanted corridor roof
        roof_slab = _cube(tree, (base_x, -1900 - face * 200),
                           side, cor_w * 1.2, 0.1, "house")
        pieces.append(_move(tree, roof_slab, (base_x + 220, -1900 - face * 200),
                             translation=(math.cos(ang + math.pi / 2) * (side / 2 - cor_w / 2),
                                          math.sin(ang + math.pi / 2) * (side / 2 - cor_w / 2),
                                          H + 0.05),
                             rotation=(0, 0, ang), label="house"))
    # Open courtyard floor — walk plane top at Z=0 (v2.60.1)
    court = max(1.0, side - cor_w * 2.2)
    floor_t = 0.25
    pieces.append(_move(tree, _cube(tree, (base_x, -3000), court, court, floor_t, "level"),
                         (base_x + 200, -3000), translation=(0, 0, -floor_t * 0.5), label="level"))
    return _finalize_building(tree, pieces, (base_x + 1400, 0))


# ─── WATERMILL ──────────────────────────────────────────────────────
def build_watermill(tree, props, base_x=-1400):
    """Mill house with large waterwheel on one side."""
    W = max(2.0, getattr(props, 'base_radius', 1.0) * 2.4)
    D = W * 0.85
    H = max(2.5, getattr(props, 'height', 4.0))
    pieces = []
    # Body
    pieces.append(_move(tree, _cube(tree, (base_x, 200), W, D, H, "tower"),
                         (base_x + 200, 200), translation=(0, 0, H / 2), label="tower"))
    # Pitched roof (two slabs)
    import math
    pitch = math.atan2(H * 0.5, W * 0.55)
    for sx in (-1, 1):
        slab = _cube(tree, (base_x, -200 + (sx + 1) * 80),
                      W * 0.6 / math.cos(pitch), D + 0.2, 0.1, "house")
        pieces.append(_move(tree, slab, (base_x + 220, -200 + (sx + 1) * 80),
                             translation=(sx * W * 0.27, 0, H + H * 0.25),
                             rotation=(0, sx * -pitch, 0), label="house"))
    # Waterwheel on +X face
    wheel_r = H * 0.55
    wheel_d = 0.35
    wheel = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -800))
    if wheel:
        try:
            wheel.inputs['Major Radius'].default_value = wheel_r
            wheel.inputs['Minor Radius'].default_value = 0.06
            wheel.inputs['Major Segments'].default_value = 32
            wheel.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        # Two parallel rings = the wheel's outer rims
        for sd in (-1, 1):
            pieces.append(_move(tree, wheel.outputs['Mesh'], (base_x + 200, -800 - sd * 100),
                                 translation=(W / 2 + 0.3, sd * wheel_d / 2, wheel_r * 0.9),
                                 rotation=(0, 1.5708, 0), label="ornament"))
        color_node(wheel, "ornament")
    # Wheel paddles (8 radial boxes)
    for i in range(8):
        ang = (i / 8) * math.tau
        paddle = _cube(tree, (base_x, -1200 - i * 60),
                        0.1, wheel_d, wheel_r * 0.4, "ornament")
        pieces.append(_move(tree, paddle, (base_x + 220, -1200 - i * 60),
                             translation=(W / 2 + 0.3, 0,
                                          wheel_r * 0.9 + math.sin(ang) * wheel_r * 0.78),
                             rotation=(0, ang, 0), label="ornament"))
    # Central axle
    axle = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -2000))
    axle.inputs['Radius'].default_value = 0.06
    axle.inputs['Depth'].default_value = wheel_d + 0.4
    axle.inputs['Vertices'].default_value = 12
    pieces.append(_move(tree, axle.outputs['Mesh'], (base_x + 200, -2000),
                         translation=(W / 2 + 0.3, 0, wheel_r * 0.9),
                         rotation=(1.5708, 0, 0), label="ornament"))
    color_node(axle, "ornament")
    return _finalize_building(tree, pieces, (base_x + 1300, 0))


# ─── LIGHTHOUSE ─────────────────────────────────────────────────────
def build_lighthouse(tree, props, base_x=-1400):
    """Tall tapered maritime tower: stone shaft + gallery + lantern room + spire."""
    r_base = max(0.8, getattr(props, 'base_radius', 1.0) * 1.0)
    r_top = r_base * 0.55
    H = max(8.0, getattr(props, 'height', 5.0) * 3.0)
    pieces = []
    # Tapered shaft via stacked cylinders (5 sections)
    n_sec = 5
    sec_h = H / n_sec
    for i in range(n_sec):
        z = i * sec_h
        r = r_base + (r_top - r_base) * (i / max(1, n_sec - 1))
        body_c = _cv_circle(tree, (base_x, 200 - i * 200), r, 24)
        body = _fill_extrude(tree, body_c.outputs['Curve'] if body_c else None,
                              (base_x + 200, 200 - i * 200),
                              (base_x + 400, 200 - i * 200), sec_h, "tower")
        pieces.append(_move(tree, body, (base_x + 600, 200 - i * 200),
                             translation=(0, 0, z), label="tower"))
    # Gallery (toroidal ring) just below lantern
    gallery = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -1300))
    if gallery:
        try:
            gallery.inputs['Major Radius'].default_value = r_top * 1.4
            gallery.inputs['Minor Radius'].default_value = r_top * 0.12
            gallery.inputs['Major Segments'].default_value = 32
            gallery.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        pieces.append(_move(tree, gallery.outputs['Mesh'], (base_x + 200, -1300),
                             translation=(0, 0, H), label="ornament"))
        color_node(gallery, "ornament")
    # Lantern room (glassy cylinder)
    lantern_c = _cv_circle(tree, (base_x, -1700), r_top * 0.95, 16)
    lantern = _fill_extrude(tree, lantern_c.outputs['Curve'] if lantern_c else None,
                             (base_x + 200, -1700), (base_x + 400, -1700),
                             sec_h * 0.8, "house")
    pieces.append(_move(tree, lantern, (base_x + 600, -1700),
                         translation=(0, 0, H + 0.15), label="house"))
    # Conical roof
    roof = _safe_node(tree, 'GeometryNodeMeshCone', (base_x, -2100))
    if roof:
        roof.inputs['Radius Bottom'].default_value = r_top * 1.1
        roof.inputs['Radius Top'].default_value = 0
        roof.inputs['Depth'].default_value = r_top * 2.0
        roof.inputs['Vertices'].default_value = 16
        pieces.append(_move(tree, roof.outputs['Mesh'], (base_x + 200, -2100),
                             translation=(0, 0, H + sec_h * 0.8 + r_top), label="house"))
        color_node(roof, "house")
    # Spire/finial
    pieces.append(_move(tree, _cube(tree, (base_x, -2500), 0.1, 0.1, r_top * 1.5, "ornament"),
                         (base_x + 200, -2500),
                         translation=(0, 0, H + sec_h * 0.8 + r_top * 2.5), label="ornament"))
    return _finalize_building(tree, pieces, (base_x + 1300, 0))


# ─── CN MOON GATE ───────────────────────────────────────────────────
def build_cn_moon_gate(tree, props, base_x=-1400):
    """Circular Chinese garden doorway set in a wall."""
    r = max(1.0, getattr(props, 'base_radius', 1.0) * 1.8)
    W = r * 3.6
    H = r * 2.8
    T = 0.3
    pieces = []
    # Wall slab
    pieces.append(_move(tree, _cube(tree, (base_x, 200), W, T, H, "tower"),
                         (base_x + 200, 200), translation=(0, 0, H / 2), label="tower"))
    # The circle "frame" — torus rotated to face camera
    frame = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -400))
    if frame:
        try:
            frame.inputs['Major Radius'].default_value = r
            frame.inputs['Minor Radius'].default_value = T * 0.65
            frame.inputs['Major Segments'].default_value = 48
            frame.inputs['Minor Segments'].default_value = 8
        except Exception:
            pass
        pieces.append(_move(tree, frame.outputs['Mesh'], (base_x + 200, -400),
                             translation=(0, 0, H * 0.4),
                             rotation=(1.5708, 0, 0), label="ornament"))
        color_node(frame, "ornament")
    # Coping stones along top of wall (ornament strip)
    pieces.append(_move(tree, _cube(tree, (base_x, -1000), W + 0.4, T + 0.2, 0.18, "ornament"),
                         (base_x + 200, -1000),
                         translation=(0, 0, H + 0.09), label="ornament"))
    # Base plinth
    pieces.append(_move(tree, _cube(tree, (base_x, -1300), W + 0.3, T + 0.3, 0.25, "house"),
                         (base_x + 200, -1300),
                         translation=(0, 0, 0.125), label="house"))
    return _join_all(tree, pieces, (base_x + 1100, 0))


# ─── CN PAILOU ──────────────────────────────────────────────────────
def build_cn_pailou(tree, props, base_x=-1400):
    """Chinese memorial archway: 4 pillars + 3 stacked decorative roofs."""
    W = max(3.5, getattr(props, 'base_radius', 1.0) * 4.0)
    H = max(4.0, getattr(props, 'height', 5.0) * 1.4)
    pillar_w = 0.4
    pillar_pitch = W / 3
    pieces = []
    # 4 vertical pillars
    for i in range(4):
        x = -W / 2 + i * pillar_pitch
        pieces.append(_move(tree,
                             _cube(tree, (base_x, 200 - i * 100), pillar_w, pillar_w, H, "tower"),
                             (base_x + 200, 200 - i * 100),
                             translation=(x, 0, H / 2), label="tower"))
    # 3 stacked curved roofs (decreasing width going up) — real swept eaves
    roof_z = H + 0.1
    for tier in range(3):
        rw = W * (1.0 - tier * 0.15)
        rd = 1.4 - tier * 0.12
        ridge_h = 0.45 + tier * 0.05
        roof_geo = _curved_roof(tree, (base_x, -500 - tier * 700),
                                size_x=rw, size_y=rd, ridge_h=ridge_h,
                                base_z=roof_z, pitch=1.5, hip=False,
                                eave_flip=0.5, thickness=-0.09, label="ornament")
        pieces.append(roof_geo)
        roof_z += ridge_h + 0.25
    # Central plaque (inscribed panel)
    pieces.append(_move(tree, _cube(tree, (base_x, -1400), W * 0.55, 0.1, H * 0.18, "ornament"),
                         (base_x + 200, -1400),
                         translation=(0, 0, H * 1.05), label="ornament"))
    return _join_all(tree, pieces, (base_x + 1300, 0))


# ─── STREET LAMP ────────────────────────────────────────────────────
def build_street_lamp(tree, props, base_x=-1400):
    """Period street lamp: tapered post + bracket + glass lantern + finial."""
    H = max(2.5, getattr(props, 'height', 3.5) * 1.0)
    pieces = []
    # Plinth base
    pieces.append(_move(tree, _cube(tree, (base_x, 200), 0.35, 0.35, 0.25, "tower"),
                         (base_x + 200, 200), translation=(0, 0, 0.125), label="tower"))
    # Tapered post (cylinder)
    post = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -100))
    post.inputs['Radius'].default_value = 0.07
    post.inputs['Depth'].default_value = H
    post.inputs['Vertices'].default_value = 12
    pieces.append(_move(tree, post.outputs['Mesh'], (base_x + 200, -100),
                         translation=(0, 0, H / 2 + 0.25), label="tower"))
    color_node(post, "tower")
    # Lantern housing (octagonal extruded square)
    lh = _cv_circle(tree, (base_x, -500), 0.18, 8)
    lhx = _fill_extrude(tree, lh.outputs['Curve'] if lh else None,
                         (base_x + 200, -500), (base_x + 400, -500), 0.35, "ornament")
    pieces.append(_move(tree, lhx, (base_x + 600, -500),
                         translation=(0, 0, H + 0.25), label="ornament"))
    # Pointed cap
    cap = _safe_node(tree, 'GeometryNodeMeshCone', (base_x, -900))
    if cap:
        cap.inputs['Radius Bottom'].default_value = 0.2
        cap.inputs['Radius Top'].default_value = 0
        cap.inputs['Depth'].default_value = 0.3
        cap.inputs['Vertices'].default_value = 8
        pieces.append(_move(tree, cap.outputs['Mesh'], (base_x + 200, -900),
                             translation=(0, 0, H + 0.75), label="ornament"))
        color_node(cap, "ornament")
    # Finial ball
    fin = _safe_node(tree, 'GeometryNodeMeshIcoSphere', (base_x, -1200))
    if fin:
        fin.inputs['Radius'].default_value = 0.07
        fin.inputs['Subdivisions'].default_value = 3
        pieces.append(_move(tree, fin.outputs['Mesh'], (base_x + 200, -1200),
                             translation=(0, 0, H + 1.0), label="ornament"))
        color_node(fin, "ornament")
    return _join_all(tree, pieces, (base_x + 1100, 0))


# ─── PUBLIC FOUNTAIN ────────────────────────────────────────────────
def build_public_fountain(tree, props, base_x=-1400):
    """Plaza fountain: large round basin + central tiered cup + finial spout."""
    R = max(1.0, getattr(props, 'base_radius', 1.0) * 1.6)
    tiers = max(2, getattr(props, 'fountain_tiers', 3))
    pieces = []
    # Outer basin (extruded circle ring — approximate with torus + disc)
    outer = _cv_circle(tree, (base_x, 200), R, 48)
    outer_m = _fill_extrude(tree, outer.outputs['Curve'] if outer else None,
                              (base_x + 200, 200), (base_x + 400, 200), 0.3, "tower")
    pieces.append(_move(tree, outer_m, (base_x + 600, 200),
                         translation=(0, 0, 0), label="tower"))
    # Basin rim torus
    rim = _safe_node(tree, 'GeometryNodeMeshTorus', (base_x, -200))
    if rim:
        try:
            rim.inputs['Major Radius'].default_value = R
            rim.inputs['Minor Radius'].default_value = 0.08
            rim.inputs['Major Segments'].default_value = 48
            rim.inputs['Minor Segments'].default_value = 8
        except Exception:
            pass
        pieces.append(_move(tree, rim.outputs['Mesh'], (base_x + 200, -200),
                             translation=(0, 0, 0.32), label="ornament"))
        color_node(rim, "ornament")
    # Central tiered cups (stacked toruses with decreasing radius)
    cz = 0.5
    for t in range(tiers):
        cup_r = R * (0.5 - t * 0.12)
        if cup_r <= 0.1: break
        cup_c = _cv_circle(tree, (base_x, -500 - t * 200), cup_r, 32)
        cup_m = _fill_extrude(tree, cup_c.outputs['Curve'] if cup_c else None,
                                (base_x + 200, -500 - t * 200),
                                (base_x + 400, -500 - t * 200), 0.18, "tower")
        pieces.append(_move(tree, cup_m, (base_x + 600, -500 - t * 200),
                             translation=(0, 0, cz), label="tower"))
        cz += 0.5
    # Central column under top cup
    col = _node(tree, 'GeometryNodeMeshCylinder', (base_x, -1300))
    col.inputs['Radius'].default_value = 0.12
    col.inputs['Depth'].default_value = cz + 0.5
    col.inputs['Vertices'].default_value = 16
    pieces.append(_move(tree, col.outputs['Mesh'], (base_x + 200, -1300),
                         translation=(0, 0, (cz + 0.5) / 2 + 0.25), label="tower"))
    color_node(col, "tower")
    # Finial spout
    fin = _safe_node(tree, 'GeometryNodeMeshIcoSphere', (base_x, -1700))
    if fin:
        fin.inputs['Radius'].default_value = 0.15
        fin.inputs['Subdivisions'].default_value = 3
        pieces.append(_move(tree, fin.outputs['Mesh'], (base_x + 200, -1700),
                             translation=(0, 0, cz + 0.6), label="ornament"))
        color_node(fin, "ornament")
    return _join_all(tree, pieces, (base_x + 1300, 0))


