# ======================================================================
# SCI-FI / CYBERPUNK EFFECT GENERATOR
# Non-destructive: reads input geometry, adds procedural surface detail.
# Each builder takes (tree, props) and USES the Group Input geometry.
# ======================================================================

def _get_input_geom(tree):
    """Return the Geometry output socket of the Group Input node."""
    for n in tree.nodes:
        if n.type == 'GROUP_INPUT':
            for out in n.outputs:
                if out.type == 'GEOMETRY':
                    return out
    return None


def _safe_node(tree, bl_idname, loc=(0, 0)):
    """Create a node, returning None (not crashing) if the type doesn't exist."""
    try:
        n = tree.nodes.new(bl_idname)
        n.location = loc
        return n
    except Exception:
        return None


def build_scifi_greeble(tree, props):
    """
    Greeble panel generator: distribute points on faces, instance
    rectangular boxes of varying heights for classic sci-fi hull detail.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    # Subdivide for denser face distribution
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (x, 200))
    subd.inputs['Level'].default_value = min(2, props.scifi_layers)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    color_node(subd, "optimize")

    # Distribute points on faces
    pts = _safe_node(tree, 'GeometryNodeDistributePointsOnFaces', (x+350, 200))
    if pts:
        pts.distribute_method = 'POISSON'
        pts.inputs['Distance Min'].default_value  = 0.35 / max(0.1, props.scifi_density)
        pts.inputs['Density Max'].default_value   = props.scifi_density * 3.0
        pts.inputs['Seed'].default_value          = props.seed
        _link(tree, subd.outputs['Mesh'], pts.inputs['Mesh'])
        color_node(pts, "input")

    # Panel box
    panel = _node(tree, 'GeometryNodeMeshCube', (x+350, -250))
    panel.inputs['Size'].default_value = (0.3 * props.scifi_panel_scale, 0.12 * props.scifi_panel_scale, props.scifi_depth * 2.0)
    color_node(panel, "tower")

    # Random scale per instance
    rnd_val = _safe_node(tree, 'ShaderNodeTexNoise', (x+350, -550))
    if rnd_val:
        rnd_val.inputs['Scale'].default_value = 8.0
        rnd_val.inputs['Detail'].default_value = 2.0
        color_node(rnd_val, "noise")

    pos_p = _node(tree, 'GeometryNodeInputPosition', (x+100, -550))
    if rnd_val and pos_p:
        _link(tree, pos_p.outputs['Position'], rnd_val.inputs['Vector'])

    # Scale the panel randomly (0.4 → 1.0)
    scale_map = _node(tree, 'ShaderNodeMapRange', (x+600, -550))
    scale_map.inputs['From Min'].default_value = 0.0
    scale_map.inputs['From Max'].default_value = 1.0
    scale_map.inputs['To Min'].default_value   = 0.4
    scale_map.inputs['To Max'].default_value   = 1.0 + props.scifi_randomness
    if rnd_val:
        _link(tree, rnd_val.outputs['Fac'], scale_map.inputs['Value'])

    # Instance on points
    inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (x+750, 200))
    if inst:
        _link(tree, pts.outputs['Points'],   inst.inputs['Points'])
        _link(tree, panel.outputs['Mesh'],   inst.inputs['Instance'])
        if pts:
            _link(tree, pts.outputs['Normal'], inst.inputs['Rotation'])
        _link(tree, scale_map.outputs['Result'], inst.inputs['Scale'])
        inst.inputs['Scale'].default_value = (1, 1, 1)
        color_node(inst, "ornament")

    real = _safe_node(tree, 'GeometryNodeRealizeInstances', (x+1050, 200))
    if real and inst:
        _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])

    # Join original + panels
    join = _node(tree, 'GeometryNodeJoinGeometry', (x+1350, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    if real:
        _link(tree, real.outputs['Geometry'], join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_scifi_circuit(tree, props):
    """
    Circuit board surface: Voronoi-driven raised pads + noise trace lines
    distributed across the mesh surface.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    # Subdivide the base mesh for fine resolution
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (x, 100))
    subd.inputs['Level'].default_value = min(3, props.scifi_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])

    # Voronoi texture for pad placement
    pos_c = _node(tree, 'GeometryNodeInputPosition', (x+200, -300))
    vor_c = _node(tree, 'ShaderNodeTexVoronoi', (x+400, -300))
    vor_c.voronoi_dimensions = '3D'
    vor_c.feature = 'F1'
    vor_c.inputs['Scale'].default_value      = props.scifi_density * 2.5
    vor_c.inputs['Randomness'].default_value = props.scifi_randomness
    _link(tree, pos_c.outputs['Position'], vor_c.inputs['Vector'])
    color_node(vor_c, "noise")

    # Threshold → only extrude near cell centres (pads)
    thresh = _node(tree, 'ShaderNodeMath', (x+650, -300))
    thresh.operation = 'LESS_THAN'
    thresh.inputs[1].default_value = 0.25 * (1.0 + props.scifi_randomness * 0.5)
    _link(tree, vor_c.outputs['Distance'], thresh.inputs[0])

    # Extrude selected faces as component pads
    ext_c = _safe_node(tree, 'GeometryNodeExtrudeMesh', (x+450, 100))
    if ext_c:
        ext_c.mode = 'FACES'
        ext_c.inputs['Individual'].default_value = True
        ext_c.inputs['Offset Scale'].default_value = props.scifi_depth * 0.5
        _link(tree, subd.outputs['Mesh'], ext_c.inputs['Mesh'])
        _link(tree, thresh.outputs['Value'], ext_c.inputs['Selection'])
        color_node(ext_c, "deform")

    # Second noise for trace lines
    noise_tr = _node(tree, 'ShaderNodeTexNoise', (x+400, -700))
    noise_tr.inputs['Scale'].default_value     = props.scifi_density * 4.0
    noise_tr.inputs['Detail'].default_value    = 3.0
    noise_tr.inputs['Roughness'].default_value = 0.3
    _link(tree, pos_c.outputs['Position'], noise_tr.inputs['Vector'])

    mul_tr = _node(tree, 'ShaderNodeVectorMath', (x+650, -700))
    mul_tr.operation = 'MULTIPLY'
    mul_tr.inputs[1].default_value = (props.scifi_depth * 0.3,) * 3
    _link(tree, noise_tr.outputs['Color'], mul_tr.inputs[0])

    set_tr = _node(tree, 'GeometryNodeSetPosition', (x+900, 100))
    _link(tree, (ext_c.outputs['Mesh'] if ext_c else subd.outputs['Mesh']),
          set_tr.inputs['Geometry'])
    _link(tree, mul_tr.outputs['Vector'], set_tr.inputs['Offset'])
    color_node(set_tr, "deform")

    join_c = _node(tree, 'GeometryNodeJoinGeometry', (x+1200, 0))
    if in_geom:
        _link(tree, in_geom, join_c.inputs['Geometry'])
    _link(tree, set_tr.outputs['Geometry'], join_c.inputs['Geometry'])
    color_node(join_c, "output")
    return join_c.outputs['Geometry']


def build_scifi_neon_trim(tree, props):
    """
    Neon trim: find sharp edges → convert to curves → sweep a circular
    profile to create glowing tube outlines.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    # Edge angle node
    edge_ang = _safe_node(tree, 'GeometryNodeInputMeshEdgeAngle', (x, -200))

    # Select edges sharper than threshold
    ang_thresh = _node(tree, 'ShaderNodeMath', (x+250, -200))
    ang_thresh.operation = 'GREATER_THAN'
    ang_thresh.inputs[1].default_value = math.radians(props.scifi_edge_angle)
    if edge_ang:
        _link(tree, edge_ang.outputs['Unsigned Angle'], ang_thresh.inputs[0])

    # Convert mesh to curve on selected edges
    m2c = _safe_node(tree, 'GeometryNodeMeshToCurve', (x+250, 100))
    if m2c and in_geom:
        _link(tree, in_geom, m2c.inputs['Mesh'])
        if edge_ang:
            _link(tree, ang_thresh.outputs['Value'], m2c.inputs['Selection'])
        color_node(m2c, "tracery")

    # Circular sweep profile
    prof = _node(tree, 'GeometryNodeCurvePrimitiveCircle', (x+500, -300))
    prof.mode = 'RADIUS'
    prof.inputs['Radius'].default_value     = props.scifi_tube_radius
    prof.inputs['Resolution'].default_value = 8
    color_node(prof, "ornament")

    # Curve to mesh
    c2m = _node(tree, 'GeometryNodeCurveToMesh', (x+750, 100))
    if m2c:
        _link(tree, m2c.outputs['Curve'],   c2m.inputs['Curve'])
    _link(tree, prof.outputs['Curve'], c2m.inputs['Profile Curve'])
    c2m.inputs['Fill Caps'].default_value = True
    color_node(c2m, "ornament")

    join_n = _node(tree, 'GeometryNodeJoinGeometry', (x+1050, 0))
    if in_geom:
        _link(tree, in_geom, join_n.inputs['Geometry'])
    _link(tree, c2m.outputs['Mesh'], join_n.inputs['Geometry'])
    color_node(join_n, "output")
    return join_n.outputs['Geometry']


def build_scifi_panel_lines(tree, props):
    """
    Panel lines: engraved grid lines via Voronoi cell boundary detection
    + Wireframe on selected edges.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (x, 100))
    subd.inputs['Level'].default_value = min(3, props.scifi_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])

    pos_pl = _node(tree, 'GeometryNodeInputPosition', (x+200, -300))
    vor_pl = _node(tree, 'ShaderNodeTexVoronoi', (x+400, -300))
    vor_pl.voronoi_dimensions = '3D'
    vor_pl.feature = 'SMOOTH_F1'
    vor_pl.inputs['Scale'].default_value      = props.scifi_density * 1.5
    vor_pl.inputs['Randomness'].default_value = props.scifi_randomness * 0.4
    _link(tree, pos_pl.outputs['Position'], vor_pl.inputs['Vector'])

    # Detect cell boundary (where distance is near its edges)
    edge_det = _node(tree, 'ShaderNodeMath', (x+650, -300))
    edge_det.operation = 'LESS_THAN'
    edge_det.inputs[1].default_value = 0.08
    _link(tree, vor_pl.outputs['Distance'], edge_det.inputs[0])

    # Inward displacement along normals for engraved look
    nrm_pl = _node(tree, 'GeometryNodeInputNormal', (x+400, -600))
    mul_pl = _node(tree, 'ShaderNodeVectorMath', (x+650, -600))
    mul_pl.operation = 'MULTIPLY'
    mul_pl.inputs[1].default_value = (-props.scifi_depth * 0.4,) * 3
    _link(tree, nrm_pl.outputs['Normal'], mul_pl.inputs[0])

    # Combine boolean mask into float for multiply
    mul_mask = _node(tree, 'ShaderNodeVectorMath', (x+900, -400))
    mul_mask.operation = 'SCALE'
    _link(tree, mul_pl.outputs['Vector'],    mul_mask.inputs[0])
    _link(tree, edge_det.outputs['Value'],   mul_mask.inputs['Scale'])

    set_pl = _node(tree, 'GeometryNodeSetPosition', (x+450, 100))
    _link(tree, subd.outputs['Mesh'],        set_pl.inputs['Geometry'])
    _link(tree, mul_mask.outputs['Vector'],  set_pl.inputs['Offset'])
    color_node(set_pl, "deform")

    join_pl = _node(tree, 'GeometryNodeJoinGeometry', (x+1200, 0))
    if in_geom:
        _link(tree, in_geom, join_pl.inputs['Geometry'])
    _link(tree, set_pl.outputs['Geometry'], join_pl.inputs['Geometry'])
    color_node(join_pl, "output")
    return join_pl.outputs['Geometry']


def build_scifi_antenna(tree, props):
    """
    Antenna array: distribute points only on upward-facing surfaces,
    instance tall thin cylinders with dish caps.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    # Filter selection: only upward normals (dot with +Z > threshold)
    nrm_a = _node(tree, 'GeometryNodeInputNormal', (x, -200))
    sep_a = _node(tree, 'ShaderNodeSeparateXYZ', (x+200, -200))
    _link(tree, nrm_a.outputs['Normal'], sep_a.inputs['Vector'])
    cmp_a = _node(tree, 'ShaderNodeMath', (x+400, -200))
    cmp_a.operation = 'GREATER_THAN'
    cmp_a.inputs[1].default_value = 0.5
    _link(tree, sep_a.outputs['Z'], cmp_a.inputs[0])

    pts_a = _safe_node(tree, 'GeometryNodeDistributePointsOnFaces', (x+300, 100))
    if pts_a and in_geom:
        pts_a.distribute_method = 'POISSON'
        pts_a.inputs['Distance Min'].default_value  = 0.6 / max(0.1, props.scifi_density)
        pts_a.inputs['Density Max'].default_value   = props.scifi_density
        pts_a.inputs['Seed'].default_value          = props.seed + 55
        _link(tree, in_geom, pts_a.inputs['Mesh'])
        _link(tree, cmp_a.outputs['Value'], pts_a.inputs['Selection'])
        color_node(pts_a, "input")

    # Antenna shaft — thin cylinder
    shaft = _node(tree, 'GeometryNodeMeshCylinder', (x+300, -450))
    shaft.inputs['Vertices'].default_value = 8
    shaft.inputs['Radius'].default_value   = 0.02 * props.scifi_panel_scale
    shaft.inputs['Depth'].default_value    = props.scifi_depth * 8.0
    color_node(shaft, "ornament")

    inst_a = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (x+650, 100))
    if inst_a and pts_a:
        _link(tree, pts_a.outputs['Points'],   inst_a.inputs['Points'])
        _link(tree, shaft.outputs['Mesh'],     inst_a.inputs['Instance'])
        _link(tree, pts_a.outputs['Normal'],   inst_a.inputs['Rotation'])
        color_node(inst_a, "ornament")

    real_a = _safe_node(tree, 'GeometryNodeRealizeInstances', (x+950, 100))
    if real_a and inst_a:
        _link(tree, inst_a.outputs['Instances'], real_a.inputs['Geometry'])

    join_a = _node(tree, 'GeometryNodeJoinGeometry', (x+1250, 0))
    if in_geom:
        _link(tree, in_geom, join_a.inputs['Geometry'])
    if real_a:
        _link(tree, real_a.outputs['Geometry'], join_a.inputs['Geometry'])
    color_node(join_a, "output")
    return join_a.outputs['Geometry']


def build_scifi_damage(tree, props):
    """
    Battle damage: Voronoi crater displacement + random face deletion.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (x, 100))
    subd.inputs['Level'].default_value = min(3, props.scifi_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])

    pos_d = _node(tree, 'GeometryNodeInputPosition', (x+200, -300))
    vor_d = _node(tree, 'ShaderNodeTexVoronoi', (x+400, -300))
    vor_d.voronoi_dimensions = '3D'
    vor_d.feature = 'F1'
    vor_d.inputs['Scale'].default_value      = props.scifi_density * 1.2
    vor_d.inputs['Randomness'].default_value = 0.9
    _link(tree, pos_d.outputs['Position'], vor_d.inputs['Vector'])

    noise_d = _node(tree, 'ShaderNodeTexNoise', (x+400, -600))
    noise_d.inputs['Scale'].default_value     = props.scifi_density * 3.0
    noise_d.inputs['Detail'].default_value    = 6.0
    noise_d.inputs['Roughness'].default_value = 0.75
    _link(tree, pos_d.outputs['Position'], noise_d.inputs['Vector'])

    # Combine Voronoi + noise for irregular craters
    mix_d = _node(tree, 'ShaderNodeMix', (x+700, -400))
    mix_d.data_type = 'FLOAT'
    mix_d.inputs['Factor'].default_value = 0.45
    _link(tree, vor_d.outputs['Distance'], mix_d.inputs[6])
    _link(tree, noise_d.outputs['Fac'],    mix_d.inputs[7])

    mul_d = _node(tree, 'ShaderNodeVectorMath', (x+950, -300))
    mul_d.operation = 'MULTIPLY'
    mul_d.inputs[1].default_value = (-props.scifi_depth * 1.5,) * 3
    nrm_d = _node(tree, 'GeometryNodeInputNormal', (x+700, -700))
    _link(tree, nrm_d.outputs['Normal'], mul_d.inputs[0])

    scale_d = _node(tree, 'ShaderNodeVectorMath', (x+1200, -300))
    scale_d.operation = 'SCALE'
    _link(tree, mul_d.outputs['Vector'],  scale_d.inputs[0])
    _link(tree, mix_d.outputs[1],         scale_d.inputs['Scale'])

    set_d = _node(tree, 'GeometryNodeSetPosition', (x+450, 100))
    _link(tree, subd.outputs['Mesh'],    set_d.inputs['Geometry'])
    _link(tree, scale_d.outputs['Vector'], set_d.inputs['Offset'])
    color_node(set_d, "deform")

    return set_d.outputs['Geometry']


def build_scifi_hex_armour(tree, props):
    """
    Hexagonal armour plating: Voronoi-extruded hex-like tiles.
    """
    x = 0
    in_geom = _get_input_geom(tree)

    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (x, 100))
    subd.inputs['Level'].default_value = min(3, props.scifi_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])

    pos_h = _node(tree, 'GeometryNodeInputPosition', (x+200, -300))
    vor_h = _node(tree, 'ShaderNodeTexVoronoi', (x+400, -300))
    vor_h.voronoi_dimensions = '3D'
    vor_h.feature = 'F1'
    vor_h.distance = 'CHEBYCHEV'
    vor_h.inputs['Scale'].default_value      = props.scifi_density * 2.0
    vor_h.inputs['Randomness'].default_value = 0.15
    _link(tree, pos_h.outputs['Position'], vor_h.inputs['Vector'])

    # Cell centre distance drives height
    height_map = _node(tree, 'ShaderNodeMapRange', (x+650, -300))
    height_map.inputs['From Min'].default_value = 0.0
    height_map.inputs['From Max'].default_value = 0.5
    height_map.inputs['To Min'].default_value   = 0.0
    height_map.inputs['To Max'].default_value   = props.scifi_depth
    _link(tree, vor_h.outputs['Distance'], height_map.inputs['Value'])

    ext_h = _safe_node(tree, 'GeometryNodeExtrudeMesh', (x+450, 100))
    if ext_h:
        ext_h.mode = 'FACES'
        ext_h.inputs['Individual'].default_value = True
        _link(tree, subd.outputs['Mesh'],          ext_h.inputs['Mesh'])
        _link(tree, height_map.outputs['Result'],  ext_h.inputs['Offset Scale'])
        color_node(ext_h, "deform")

    result_h = ext_h.outputs['Mesh'] if ext_h else subd.outputs['Mesh']
    join_h = _node(tree, 'GeometryNodeJoinGeometry', (x+1100, 0))
    if in_geom:
        _link(tree, in_geom, join_h.inputs['Geometry'])
    _link(tree, result_h, join_h.inputs['Geometry'])
    color_node(join_h, "output")
    return join_h.outputs['Geometry']


# Map scifi effect enum to builder function
_SCIFI_BUILDERS = {
    'GREEBLE':     build_scifi_greeble,
    'CIRCUIT':     build_scifi_circuit,
    'NEON_TRIM':   build_scifi_neon_trim,
    'PANEL_LINES': build_scifi_panel_lines,
    'ANTENNA':     build_scifi_antenna,
    'DAMAGE':      build_scifi_damage,
    'HEX_ARMOUR':  build_scifi_hex_armour,
    # HOLOGRAM and VENT_GRILLE fall back to GREEBLE if not yet implemented
    'HOLOGRAM':    build_scifi_greeble,
    'VENT_GRILLE': build_scifi_panel_lines,
}


def apply_scifi_effect_gn(obj, props):
    """
    Apply the selected sci-fi effect as a dedicated GN modifier
    on top of any existing mesh — fully non-destructive.
    """
    # Remove old scifi modifier
    for mod in [m for m in obj.modifiers if m.name.startswith("SciFi_")]:
        obj.modifiers.remove(mod)

    mod_name = f"SciFi_{props.scifi_effect}"
    old_tree = bpy.data.node_groups.get(f"_scifi_{obj.name}_{props.scifi_effect}")
    if old_tree:
        bpy.data.node_groups.remove(old_tree)

    mod = obj.modifiers.new(name=mod_name, type='NODES')
    tree_name = f"_scifi_{obj.name}_{props.scifi_effect}"
    tree = bpy.data.node_groups.new(name=tree_name, type='GeometryNodeTree')
    mod.node_group = tree
    tree.interface.new_socket(name="Geometry", in_out='INPUT',  socket_type='NodeSocketGeometry')
    tree.interface.new_socket(name="Geometry", in_out='OUTPUT', socket_type='NodeSocketGeometry')

    in_n  = tree.nodes.new('NodeGroupInput');  in_n.location  = (-600, 0)
    out_n = tree.nodes.new('NodeGroupOutput'); out_n.location = (2000, 0)
    color_node(in_n, "input"); color_node(out_n, "output")

    builder = _SCIFI_BUILDERS.get(props.scifi_effect, build_scifi_greeble)
    try:
        geom_out = builder(tree, props)
        if geom_out:
            tree.links.new(geom_out, out_n.inputs['Geometry'])
        else:
            tree.links.new(in_n.outputs['Geometry'], out_n.inputs['Geometry'])
    except Exception as e:
        print(f"[SurrealArch] SciFi effect error: {e}")
        tree.links.new(in_n.outputs['Geometry'], out_n.inputs['Geometry'])

    for poly in obj.data.polygons:
        poly.use_smooth = True
    obj.data.update()


# ======================================================================
# AESTHETIC EFFECT BUILDERS — Gothic / Vaporwave / Zen / Spiritual
# Non-destructive: every builder takes the input geometry and JOINS its
# output back so the result stacks on top of any selected mesh.
# ======================================================================

def _aest_val(props, kind):
    """Music-modulated read of intensity/density/scale.
    `kind` is one of 'INTENSITY', 'DENSITY', 'SCALE'.
    Reuses the existing `_music_mod` helper so this respects the same
    `aest_music_react` + `aest_music_gain` + `universal_music_influence`
    settings shown in the panel."""
    base = {
        'INTENSITY': getattr(props, 'aest_intensity', 1.0),
        'DENSITY':   getattr(props, 'aest_density',   1.0),
        'SCALE':     getattr(props, 'aest_scale',     1.0),
    }[kind]
    # If the helper is defined later, just call it; otherwise return base.
    try:
        # weight intensity strongest, density mid, scale lightest
        k = {'INTENSITY': 1.0, 'DENSITY': 0.6, 'SCALE': 0.4}[kind]
        return _music_mod(props, base, k)
    except NameError:
        return base


def _gothic_arch_curve(tree, width, height, pointiness=0.6, x=0, y=0):
    """Build a pointed-arch silhouette as a bezier curve.
    Returns the curve output socket, or None if quadratic bezier node missing.
    Uses 3 control points: bottom-left → apex (pointy) → bottom-right."""
    qb = _safe_node(tree, 'GeometryNodeCurveQuadraticBezier', (x, y))
    if qb is None:
        return None
    try:
        qb.inputs['Resolution'].default_value = 32
        qb.inputs['Start'].default_value      = (-width * 0.5, 0, 0)
        # Middle controls "lift" — push it up + slightly outward for Gothic pointy
        qb.inputs['Middle'].default_value     = (0, 0, height * (1.0 + pointiness * 0.4))
        qb.inputs['End'].default_value        = (width * 0.5, 0, 0)
    except Exception:
        return None
    color_node(qb, "gothic")
    return qb.outputs['Curve']


def _instance_on_surface(tree, in_geom, instance_mesh_out, density, seed,
                          align_normal=True, scale=None, rand_scale=0.0,
                          x_off=0, label="ornament"):
    """Helper: distribute points on faces and instance a mesh on each.
    Returns the Realize Instances output socket, or None on failure."""
    pts = _safe_node(tree, 'GeometryNodeDistributePointsOnFaces', (x_off, 0))
    if pts is None or in_geom is None or instance_mesh_out is None:
        return None
    pts.distribute_method = 'POISSON'
    pts.inputs['Distance Min'].default_value = 0.3 / max(0.1, density)
    pts.inputs['Density Max'].default_value  = density * 3.0
    pts.inputs['Seed'].default_value         = seed
    _link(tree, in_geom, pts.inputs['Mesh'])
    color_node(pts, "input")

    inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (x_off + 250, 0))
    if inst is None:
        return None
    _link(tree, pts.outputs['Points'], inst.inputs['Points'])
    _link(tree, instance_mesh_out, inst.inputs['Instance'])
    if align_normal:
        try:
            _link(tree, pts.outputs['Normal'], inst.inputs['Rotation'])
        except Exception:
            pass

    if scale is not None:
        inst.inputs['Scale'].default_value = scale

    if rand_scale > 0.0:
        rs = _safe_node(tree, 'FunctionNodeRandomValue', (x_off + 250, -250))
        if rs:
            rs.data_type = 'FLOAT'
            try:
                rs.inputs['Min'].default_value = 1.0 - rand_scale
                rs.inputs['Max'].default_value = 1.0 + rand_scale
                rs.inputs['Seed'].default_value = seed
                _link(tree, rs.outputs['Value'], inst.inputs['Scale'])
            except Exception:
                pass

    real = _safe_node(tree, 'GeometryNodeRealizeInstances', (x_off + 500, 0))
    if real:
        _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
        color_node(inst, label); color_node(real, label)
        return real.outputs['Geometry']
    return None


def _join_with_input(tree, in_geom, extra_out, x_off=1500):
    """Join the new geometry with the original input."""
    join = _node(tree, 'GeometryNodeJoinGeometry', (x_off, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    if extra_out:
        _link(tree, extra_out, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


# ---- 🦇 GOTHIC ---------------------------------------------------------

def build_aest_goth_tracery(tree, props):
    """Distribute Gothic cross/star ornaments on every face."""
    in_geom = _get_input_geom(tree)
    # Cross shape = two thin overlapping boxes
    arm_x = _node(tree, 'GeometryNodeMeshCube', (-500, -300))
    arm_x.inputs['Size'].default_value = (0.25 * props.aest_scale, 0.05 * props.aest_scale, 0.03 * props.aest_scale)
    arm_z = _node(tree, 'GeometryNodeMeshCube', (-500, -500))
    arm_z.inputs['Size'].default_value = (0.06 * props.aest_scale, 0.05 * props.aest_scale, 0.25 * props.aest_scale)
    j1 = _node(tree, 'GeometryNodeJoinGeometry', (-250, -400))
    _link(tree, arm_x.outputs['Mesh'], j1.inputs['Geometry'])
    _link(tree, arm_z.outputs['Mesh'], j1.inputs['Geometry'])
    color_node(arm_x, "gothic"); color_node(arm_z, "gothic"); color_node(j1, "gothic")
    real = _instance_on_surface(tree, in_geom, j1.outputs['Geometry'],
                                props.aest_density * 1.2, props.aest_seed,
                                rand_scale=0.3, x_off=0, label="gothic")
    return _join_with_input(tree, in_geom, real)


def build_aest_goth_drip(tree, props):
    """Vertical drips on lower portion of mesh via subdivision + downward displacement."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -250))
    # Noise to create drip mask
    noise = _safe_node(tree, 'ShaderNodeTexNoise', (250, -250))
    if noise:
        noise.inputs['Scale'].default_value = props.aest_density * 6.0
        noise.inputs['Detail'].default_value = 4.0
        _link(tree, pos.outputs['Position'], noise.inputs['Vector'])
        color_node(noise, "noise")
    # Drip vector: only Z<0 direction
    vec = _node(tree, 'ShaderNodeCombineXYZ', (500, -250))
    if noise:
        # Scale drip by intensity
        mult = _node(tree, 'ShaderNodeMath', (500, -450))
        mult.operation = 'MULTIPLY'
        _link(tree, noise.outputs['Fac'], mult.inputs[0])
        mult.inputs[1].default_value = -props.aest_intensity * 0.8
        _link(tree, mult.outputs['Value'], vec.inputs['Z'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (800, 0))
    if set_pos and subd:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, vec.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "gothic")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_goth_spikes(tree, props):
    """Sharp cone spikes outward along normals."""
    in_geom = _get_input_geom(tree)
    cone = _safe_node(tree, 'GeometryNodeMeshCone', (-500, -300))
    if cone:
        cone.inputs['Radius Bottom'].default_value = 0.08 * props.aest_scale
        cone.inputs['Radius Top'].default_value    = 0.0
        cone.inputs['Depth'].default_value         = 0.5 * props.aest_scale * props.aest_intensity
        cone.inputs['Vertices'].default_value      = 6
        color_node(cone, "gothic")
        # Translate so base sits at origin
        t = _node(tree, 'GeometryNodeTransform', (-250, -300))
        t.inputs['Translation'].default_value = (0, 0, 0.25 * props.aest_scale * props.aest_intensity)
        _link(tree, cone.outputs['Mesh'], t.inputs['Geometry'])
        # Rotate so cone points along +Z (default already)
        real = _instance_on_surface(tree, in_geom, t.outputs['Geometry'],
                                    props.aest_density, props.aest_seed,
                                    rand_scale=0.4, x_off=0, label="gothic")
        return _join_with_input(tree, in_geom, real)
    return in_geom


def build_aest_goth_ribs(tree, props):
    """Vertical Gothic ribs wrapping the silhouette."""
    in_geom = _get_input_geom(tree)
    # Build N vertical thin pillars in a circle around the bbox
    n_ribs = max(4, int(props.aest_density * 8))
    pieces = []
    for i in range(n_ribs):
        import math
        ang = (i / n_ribs) * 6.283185
        radius = 1.2 * props.aest_scale
        rib = _node(tree, 'GeometryNodeMeshCylinder', (-400 + (i % 4) * 200, -200 - (i // 4) * 200))
        rib.inputs['Radius'].default_value = 0.04 * props.aest_scale
        rib.inputs['Depth'].default_value  = 3.0 * props.aest_intensity
        rib.inputs['Vertices'].default_value = 6
        tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 4) * 200, -200 - (i // 4) * 200))
        tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius, 1.5 * props.aest_intensity)
        _link(tree, rib.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(rib, "gothic"); color_node(tr, "gothic")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_goth_weathered(tree, props):
    """Weathered/cracked stone: subdivide and noise-displace inward."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -200))
    noise = _safe_node(tree, 'ShaderNodeTexNoise', (250, -200))
    if noise:
        noise.inputs['Scale'].default_value = props.aest_density * 5.0
        noise.inputs['Detail'].default_value = 6.0
        noise.inputs['Roughness'].default_value = 0.7
        _link(tree, pos.outputs['Position'], noise.inputs['Vector'])
        color_node(noise, "noise")
    # Normal direction for inward displace
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -400))
    sub_v = _node(tree, 'ShaderNodeVectorMath', (450, -350))
    sub_v.operation = 'SCALE'
    _link(tree, normal.outputs['Normal'], sub_v.inputs[0])
    if noise:
        mult = _node(tree, 'ShaderNodeMath', (450, -550))
        mult.operation = 'MULTIPLY'
        _link(tree, noise.outputs['Fac'], mult.inputs[0])
        mult.inputs[1].default_value = -props.aest_intensity * 0.25
        _link(tree, mult.outputs['Value'], sub_v.inputs['Scale'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (800, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, sub_v.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "gothic")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


# ---- 🌴 VAPORWAVE ------------------------------------------------------

def build_aest_vap_wire(tree, props):
    """Pastel neon wireframe overlay."""
    in_geom = _get_input_geom(tree)
    wire = _safe_node(tree, 'GeometryNodeWireframe', (0, 0))
    if wire and in_geom:
        try:
            wire.inputs['Radius'].default_value = 0.02 * props.aest_intensity * props.aest_scale
        except Exception:
            pass
        _link(tree, in_geom, wire.inputs['Mesh'])
        color_node(wire, "tracery")
        return _join_with_input(tree, in_geom, wire.outputs['Curve'] if 'Curve' in wire.outputs else wire.outputs[0])
    return in_geom


def build_aest_vap_pixel(tree, props):
    """Voxelize the mesh into floating cubes."""
    in_geom = _get_input_geom(tree)
    m2v = _safe_node(tree, 'GeometryNodeMeshToVolume', (0, 0))
    if m2v and in_geom:
        try: m2v.resolution_mode = 'VOXEL_SIZE'
        except (AttributeError, TypeError): pass
        m2v.inputs['Voxel Size'].default_value = max(0.05, 0.3 / max(0.1, props.aest_density))
        try:
            m2v.inputs['Density'].default_value = 1.0
        except Exception:
            pass
        _link(tree, in_geom, m2v.inputs['Mesh'])
        color_node(m2v, "noise")
        # Distribute points in volume → cube instances
        dpts = _safe_node(tree, 'GeometryNodeDistributePointsInVolume', (300, 0))
        if dpts:
            try: dpts.mode = 'DENSITY_GRID'

            except (AttributeError, TypeError):

                try: dpts.inputs['Mode'].default_value = 'DENSITY_GRID'

                except Exception: pass
            try:
                dpts.inputs['Spacing'].default_value = (0.2 / max(0.1, props.aest_density),) * 3
            except Exception:
                pass
            _link(tree, m2v.outputs['Volume'], dpts.inputs['Volume'])
            cube = _node(tree, 'GeometryNodeMeshCube', (300, -250))
            sz = 0.15 * props.aest_scale
            cube.inputs['Size'].default_value = (sz, sz, sz)
            inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (550, 0))
            if inst:
                _link(tree, dpts.outputs['Points'], inst.inputs['Points'])
                _link(tree, cube.outputs['Mesh'], inst.inputs['Instance'])
                real = _safe_node(tree, 'GeometryNodeRealizeInstances', (800, 0))
                if real:
                    _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
                    color_node(inst, "modular"); color_node(real, "modular")
                    return real.outputs['Geometry']
    return in_geom


def build_aest_vap_chromatic(tree, props):
    """Three offset ghost copies in R/G/B-coded XY directions."""
    in_geom = _get_input_geom(tree)
    pieces = []
    offsets = [
        (props.aest_intensity * 0.3, 0, 0),
        (-props.aest_intensity * 0.15, props.aest_intensity * 0.25, 0),
        (-props.aest_intensity * 0.15, -props.aest_intensity * 0.25, 0),
    ]
    for i, off in enumerate(offsets):
        t = _node(tree, 'GeometryNodeTransform', (250 * (i+1), -200 * (i+1)))
        t.inputs['Translation'].default_value = off
        if in_geom:
            _link(tree, in_geom, t.inputs['Geometry'])
        color_node(t, "ornament")
        pieces.append(t.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (1100, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_vap_grid(tree, props):
    """Tron grid lines on the surface (distribute thin bar instances)."""
    in_geom = _get_input_geom(tree)
    bar = _node(tree, 'GeometryNodeMeshCube', (-400, -300))
    bar.inputs['Size'].default_value = (0.6 * props.aest_scale, 0.025 * props.aest_scale, 0.025 * props.aest_scale)
    color_node(bar, "tracery")
    real = _instance_on_surface(tree, in_geom, bar.outputs['Mesh'],
                                props.aest_density * 1.5, props.aest_seed,
                                rand_scale=0.0, x_off=0, label="tracery")
    return _join_with_input(tree, in_geom, real)


def build_aest_vap_palms(tree, props):
    """Pink/teal palm-tree-like cones in a ring around the base."""
    in_geom = _get_input_geom(tree)
    pieces = []
    n_palms = max(3, int(props.aest_density * 6))
    radius = 2.5 * props.aest_scale
    import math
    for i in range(n_palms):
        ang = (i / n_palms) * 6.283185
        # trunk
        trunk = _node(tree, 'GeometryNodeMeshCylinder', (-400, -200 - i * 80))
        trunk.inputs['Radius'].default_value = 0.08 * props.aest_scale
        trunk.inputs['Depth'].default_value  = 2.0 * props.aest_intensity
        trunk.inputs['Vertices'].default_value = 8
        # leaves cone
        leaves = _safe_node(tree, 'GeometryNodeMeshCone', (-200, -200 - i * 80))
        if leaves:
            leaves.inputs['Radius Bottom'].default_value = 0.45 * props.aest_scale
            leaves.inputs['Radius Top'].default_value    = 0.0
            leaves.inputs['Depth'].default_value         = 0.7 * props.aest_scale
            leaves.inputs['Vertices'].default_value      = 24
            tr_l = _node(tree, 'GeometryNodeTransform', (0, -200 - i * 80))
            tr_l.inputs['Translation'].default_value = (0, 0, 1.0 * props.aest_intensity + 0.3)
            _link(tree, leaves.outputs['Mesh'], tr_l.inputs['Geometry'])
            color_node(leaves, "organic"); color_node(tr_l, "organic")
        j_palm = _node(tree, 'GeometryNodeJoinGeometry', (200, -200 - i * 80))
        _link(tree, trunk.outputs['Mesh'], j_palm.inputs['Geometry'])
        if leaves:
            _link(tree, tr_l.outputs['Geometry'], j_palm.inputs['Geometry'])
        # place around ring
        tr = _node(tree, 'GeometryNodeTransform', (400, -200 - i * 80))
        tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius, 0.0)
        _link(tree, j_palm.outputs['Geometry'], tr.inputs['Geometry'])
        color_node(trunk, "organic"); color_node(j_palm, "organic"); color_node(tr, "organic")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (700, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


# ---- ⛩ ZEN ------------------------------------------------------------

def build_aest_zen_moss(tree, props):
    """Soft moss spheres on upward-facing surfaces."""
    in_geom = _get_input_geom(tree)
    sph = _node(tree, 'GeometryNodeMeshUVSphere', (-500, -300))
    sph.inputs['Segments'].default_value = 8
    sph.inputs['Rings'].default_value    = 5
    sph.inputs['Radius'].default_value   = 0.12 * props.aest_scale
    color_node(sph, "organic")
    real = _instance_on_surface(tree, in_geom, sph.outputs['Mesh'],
                                props.aest_density * 2.0, props.aest_seed,
                                rand_scale=0.5, x_off=0, label="organic")
    return _join_with_input(tree, in_geom, real)


def build_aest_zen_ripple(tree, props):
    """Concentric ripples from origin: sine of XY distance."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 2)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -200))
    sep = _node(tree, 'ShaderNodeSeparateXYZ', (200, -200))
    _link(tree, pos.outputs['Position'], sep.inputs['Vector'])
    # length(x,y)
    lenv = _node(tree, 'ShaderNodeVectorMath', (400, -200))
    lenv.operation = 'LENGTH'
    comb = _node(tree, 'ShaderNodeCombineXYZ', (250, -350))
    _link(tree, sep.outputs['X'], comb.inputs['X'])
    _link(tree, sep.outputs['Y'], comb.inputs['Y'])
    _link(tree, comb.outputs['Vector'], lenv.inputs[0])
    mul = _node(tree, 'ShaderNodeMath', (600, -200))
    mul.operation = 'MULTIPLY'
    _link(tree, lenv.outputs['Value'], mul.inputs[0])
    mul.inputs[1].default_value = props.aest_density * 4.0
    sn = _node(tree, 'ShaderNodeMath', (800, -200))
    sn.operation = 'SINE'
    _link(tree, mul.outputs['Value'], sn.inputs[0])
    amp = _node(tree, 'ShaderNodeMath', (1000, -200))
    amp.operation = 'MULTIPLY'
    _link(tree, sn.outputs['Value'], amp.inputs[0])
    amp.inputs[1].default_value = props.aest_intensity * 0.3
    vec = _node(tree, 'ShaderNodeCombineXYZ', (1200, -200))
    _link(tree, amp.outputs['Value'], vec.inputs['Z'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (1400, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, vec.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "organic")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_zen_sand(tree, props):
    """Karesansui raked sand on top: sine grooves in Z, on top faces only."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -200))
    sep = _node(tree, 'ShaderNodeSeparateXYZ', (200, -200))
    _link(tree, pos.outputs['Position'], sep.inputs['Vector'])
    mul_x = _node(tree, 'ShaderNodeMath', (400, -200))
    mul_x.operation = 'MULTIPLY'
    _link(tree, sep.outputs['X'], mul_x.inputs[0])
    mul_x.inputs[1].default_value = props.aest_density * 6.0
    sn = _node(tree, 'ShaderNodeMath', (600, -200))
    sn.operation = 'SINE'
    _link(tree, mul_x.outputs['Value'], sn.inputs[0])
    amp = _node(tree, 'ShaderNodeMath', (800, -200))
    amp.operation = 'MULTIPLY'
    _link(tree, sn.outputs['Value'], amp.inputs[0])
    amp.inputs[1].default_value = props.aest_intensity * 0.12
    # Top-face mask: ramp on normal.z
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -500))
    sep_n  = _node(tree, 'ShaderNodeSeparateXYZ', (200, -500))
    _link(tree, normal.outputs['Normal'], sep_n.inputs['Vector'])
    mask_mul = _node(tree, 'ShaderNodeMath', (600, -500))
    mask_mul.operation = 'MAXIMUM'
    _link(tree, sep_n.outputs['Z'], mask_mul.inputs[0])
    mask_mul.inputs[1].default_value = 0.0
    # multiply grooves by top mask
    gated = _node(tree, 'ShaderNodeMath', (1000, -400))
    gated.operation = 'MULTIPLY'
    _link(tree, amp.outputs['Value'], gated.inputs[0])
    _link(tree, mask_mul.outputs['Value'], gated.inputs[1])
    vec = _node(tree, 'ShaderNodeCombineXYZ', (1200, -400))
    _link(tree, gated.outputs['Value'], vec.inputs['Z'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (1400, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, vec.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "organic")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_zen_bamboo(tree, props):
    """Vertical bamboo poles around the bbox perimeter."""
    in_geom = _get_input_geom(tree)
    n = max(6, int(props.aest_density * 12))
    pieces = []
    import math
    radius = 1.8 * props.aest_scale
    for i in range(n):
        ang = (i / n) * 6.283185
        # bamboo cylinder
        pole = _node(tree, 'GeometryNodeMeshCylinder', (-400 + (i % 5) * 200, -200 - (i // 5) * 200))
        pole.inputs['Radius'].default_value   = 0.05 * props.aest_scale
        pole.inputs['Depth'].default_value    = 3.5 * props.aest_intensity
        pole.inputs['Vertices'].default_value = 8
        tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 5) * 200, -200 - (i // 5) * 200))
        tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius, 1.75 * props.aest_intensity)
        _link(tree, pole.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(pole, "organic"); color_node(tr, "organic")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (300, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_zen_petals(tree, props):
    """Floating cherry blossom petals (flat squashed spheres around the object)."""
    in_geom = _get_input_geom(tree)
    petal = _node(tree, 'GeometryNodeMeshUVSphere', (-500, -300))
    petal.inputs['Segments'].default_value = 6
    petal.inputs['Rings'].default_value    = 4
    petal.inputs['Radius'].default_value   = 0.1 * props.aest_scale
    tr = _node(tree, 'GeometryNodeTransform', (-250, -300))
    tr.inputs['Scale'].default_value = (1.0, 1.0, 0.25)
    _link(tree, petal.outputs['Mesh'], tr.inputs['Geometry'])
    color_node(petal, "organic"); color_node(tr, "organic")
    # Create a cloud-like point set around the bbox using a larger ico sphere
    cloud = _node(tree, 'GeometryNodeMeshIcoSphere', (-500, 200))
    cloud.inputs['Radius'].default_value = 2.5 * props.aest_scale
    cloud.inputs['Subdivisions'].default_value = max(2, props.aest_layers + 1)
    # Use cloud verts as positions
    pts_from_mesh = _safe_node(tree, 'GeometryNodeMeshToPoints', (-200, 200))
    if pts_from_mesh:
        _link(tree, cloud.outputs['Mesh'], pts_from_mesh.inputs['Mesh'])
        inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (100, 200))
        if inst:
            _link(tree, pts_from_mesh.outputs['Points'], inst.inputs['Points'])
            _link(tree, tr.outputs['Geometry'],          inst.inputs['Instance'])
            real = _safe_node(tree, 'GeometryNodeRealizeInstances', (400, 200))
            if real:
                _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
                color_node(inst, "organic"); color_node(real, "organic")
                return _join_with_input(tree, in_geom, real.outputs['Geometry'])
    return in_geom


# ---- 👁 SPIRITUAL ------------------------------------------------------

def build_aest_spi_aura(tree, props):
    """Iridescent outer shell offset along normals."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(2, props.aest_layers)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -200))
    scale_n = _node(tree, 'ShaderNodeVectorMath', (250, -200))
    scale_n.operation = 'SCALE'
    _link(tree, normal.outputs['Normal'], scale_n.inputs[0])
    scale_n.inputs['Scale'].default_value = props.aest_intensity * 0.4
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (500, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, scale_n.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "input")
        return _join_with_input(tree, in_geom, set_pos.outputs['Geometry'])
    return in_geom


def build_aest_spi_mandala(tree, props):
    """Radial mandala flat shape beneath the object."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    rings = max(2, min(6, props.aest_layers + 2))
    for ring_i in range(rings):
        n_petals = 6 + ring_i * 4
        ring_r = (ring_i + 1) * 0.6 * props.aest_scale
        for i in range(n_petals):
            ang = (i / n_petals) * 6.283185
            petal = _node(tree, 'GeometryNodeMeshUVSphere', (-400 + (i % 4) * 200, -200 - ring_i * 250 - (i // 4) * 200))
            petal.inputs['Segments'].default_value = 6
            petal.inputs['Rings'].default_value    = 4
            petal.inputs['Radius'].default_value   = 0.1 * props.aest_scale
            tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 4) * 200, -200 - ring_i * 250 - (i // 4) * 200))
            tr.inputs['Translation'].default_value = (math.cos(ang) * ring_r, math.sin(ang) * ring_r, -0.05)
            tr.inputs['Scale'].default_value = (1.0, 1.0, 0.15)
            _link(tree, petal.outputs['Mesh'], tr.inputs['Geometry'])
            color_node(petal, "ornament"); color_node(tr, "ornament")
            pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (300, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_spi_chakra(tree, props):
    """Seven floating chakra orbs in vertical alignment."""
    in_geom = _get_input_geom(tree)
    pieces = []
    base_h = 2.5 * props.aest_intensity
    for i in range(7):
        orb = _node(tree, 'GeometryNodeMeshUVSphere', (-400, -200 - i * 120))
        orb.inputs['Segments'].default_value = 12
        orb.inputs['Rings'].default_value    = 8
        orb.inputs['Radius'].default_value   = 0.18 * props.aest_scale
        tr = _node(tree, 'GeometryNodeTransform', (-150, -200 - i * 120))
        tr.inputs['Translation'].default_value = (0, 0, base_h + i * 0.55 * props.aest_scale)
        _link(tree, orb.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(orb, "ornament"); color_node(tr, "ornament")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_spi_beam(tree, props):
    """Vertical pillar of light above the object."""
    in_geom = _get_input_geom(tree)
    beam = _node(tree, 'GeometryNodeMeshCylinder', (-400, -200))
    beam.inputs['Radius'].default_value = 0.4 * props.aest_scale
    beam.inputs['Depth'].default_value  = 8.0 * props.aest_intensity
    beam.inputs['Vertices'].default_value = 16
    tr = _node(tree, 'GeometryNodeTransform', (-150, -200))
    tr.inputs['Translation'].default_value = (0, 0, 4.0 * props.aest_intensity)
    _link(tree, beam.outputs['Mesh'], tr.inputs['Geometry'])
    color_node(beam, "input"); color_node(tr, "input")
    return _join_with_input(tree, in_geom, tr.outputs['Geometry'])


def build_aest_spi_ring(tree, props):
    """Orbiting sacred ring(s) around the object."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n_rings = max(1, min(4, props.aest_layers))
    for r_i in range(n_rings):
        torus = _safe_node(tree, 'GeometryNodeMeshTorus', (-400, -200 - r_i * 250))
        if torus is None:
            continue
        try:
            torus.inputs['Major Radius'].default_value = (1.5 + r_i * 0.3) * props.aest_scale
            torus.inputs['Minor Radius'].default_value = 0.05 * props.aest_scale
            torus.inputs['Major Segments'].default_value = 32
            torus.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        tr = _node(tree, 'GeometryNodeTransform', (-150, -200 - r_i * 250))
        ang = r_i * 0.7
        tr.inputs['Rotation'].default_value = (ang, 0, ang * 0.5)
        tr.inputs['Translation'].default_value = (0, 0, 1.0 * props.aest_intensity)
        _link(tree, torus.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(torus, "ornament"); color_node(tr, "ornament")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_spi_astral(tree, props):
    """Ghosted duplicate offset upward."""
    in_geom = _get_input_geom(tree)
    tr = _node(tree, 'GeometryNodeTransform', (0, -200))
    tr.inputs['Translation'].default_value = (0, 0, 3.0 * props.aest_intensity)
    tr.inputs['Scale'].default_value = (0.95, 0.95, 0.95)
    if in_geom:
        _link(tree, in_geom, tr.inputs['Geometry'])
    color_node(tr, "ornament")
    return _join_with_input(tree, in_geom, tr.outputs['Geometry'])


def build_aest_spi_eye(tree, props):
    """Single third-eye on the front face: torus + sphere."""
    in_geom = _get_input_geom(tree)
    iris = _node(tree, 'GeometryNodeMeshUVSphere', (-500, -200))
    iris.inputs['Segments'].default_value = 16
    iris.inputs['Rings'].default_value    = 10
    iris.inputs['Radius'].default_value   = 0.25 * props.aest_scale
    eye_ring = _safe_node(tree, 'GeometryNodeMeshTorus', (-500, -400))
    if eye_ring:
        try:
            eye_ring.inputs['Major Radius'].default_value = 0.3 * props.aest_scale
            eye_ring.inputs['Minor Radius'].default_value = 0.05 * props.aest_scale
        except Exception:
            pass
    j = _node(tree, 'GeometryNodeJoinGeometry', (-250, -300))
    _link(tree, iris.outputs['Mesh'], j.inputs['Geometry'])
    if eye_ring:
        _link(tree, eye_ring.outputs['Mesh'], j.inputs['Geometry'])
    tr = _node(tree, 'GeometryNodeTransform', (0, -300))
    tr.inputs['Translation'].default_value = (0, -1.2 * props.aest_scale, 1.5 * props.aest_intensity)
    tr.inputs['Rotation'].default_value = (1.5708, 0, 0)
    _link(tree, j.outputs['Geometry'], tr.inputs['Geometry'])
    color_node(iris, "ornament"); color_node(j, "ornament"); color_node(tr, "ornament")
    return _join_with_input(tree, in_geom, tr.outputs['Geometry'])


def build_aest_spi_lotus(tree, props):
    """Lotus bloom petals around the base."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n_petals = max(6, int(props.aest_density * 14))
    rings = max(1, min(3, props.aest_layers))
    for ring_i in range(rings):
        r = 0.5 + ring_i * 0.4
        for i in range(n_petals):
            ang = (i / n_petals) * 6.283185 + ring_i * 0.2
            petal = _safe_node(tree, 'GeometryNodeMeshCone', (-400 + (i % 6) * 150, -200 - ring_i * 250 - (i // 6) * 200))
            if petal is None:
                continue
            petal.inputs['Radius Bottom'].default_value = 0.15 * props.aest_scale
            petal.inputs['Radius Top'].default_value    = 0.02 * props.aest_scale
            petal.inputs['Depth'].default_value         = 0.5 * props.aest_scale
            petal.inputs['Vertices'].default_value      = 24
            tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 6) * 150, -200 - ring_i * 250 - (i // 6) * 200))
            x = math.cos(ang) * r * props.aest_scale
            y = math.sin(ang) * r * props.aest_scale
            tr.inputs['Translation'].default_value = (x, y, ring_i * 0.15)
            tilt = 0.6 + ring_i * 0.15
            tr.inputs['Rotation'].default_value = (math.cos(ang) * tilt, math.sin(ang) * tilt, 0)
            _link(tree, petal.outputs['Mesh'], tr.inputs['Geometry'])
            color_node(petal, "organic"); color_node(tr, "organic")
            pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (300, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


# ======================================================================
# v2.16 — additional procedurally-rich aesthetic effects
# Each one uses noise / voronoi / fields / curve sweeps for variation.
# ======================================================================

def _noise_scale_for(props, base):
    return max(0.5, base * props.aest_density)


# ---- 🦇 GOTHIC — extra ------------------------------------------------

def build_aest_goth_lattice(tree, props):
    """Fractal Gothic lattice via Wireframe + Subdivide stack."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    wire = _safe_node(tree, 'GeometryNodeWireframe', (300, 0))
    if wire:
        try:
            wire.inputs['Radius'].default_value = 0.03 * props.aest_scale
        except Exception:
            pass
        _link(tree, subd.outputs['Mesh'], wire.inputs['Mesh'])
        color_node(wire, "tracery")
    # Distribute small finial spheres on lattice nodes (vertices)
    finial = _node(tree, 'GeometryNodeMeshIcoSphere', (300, -300))
    finial.inputs['Radius'].default_value = 0.04 * props.aest_scale
    finial.inputs['Subdivisions'].default_value = 1
    # Convert subd mesh to points, instance finials at vertices
    m2p = _safe_node(tree, 'GeometryNodeMeshToPoints', (600, -300))
    if m2p:
        _link(tree, subd.outputs['Mesh'], m2p.inputs['Mesh'])
    inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (900, -300))
    if inst and m2p:
        _link(tree, m2p.outputs['Points'], inst.inputs['Points'])
        _link(tree, finial.outputs['Mesh'], inst.inputs['Instance'])
    real = _safe_node(tree, 'GeometryNodeRealizeInstances', (1100, -300))
    if real and inst:
        _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (1400, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    if wire:
        try:
            _link(tree, wire.outputs.get('Curve') or wire.outputs[0], join.inputs['Geometry'])
        except Exception:
            pass
    if real:
        _link(tree, real.outputs['Geometry'], join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_goth_niches(tree, props):
    """Voronoi-masked extruded arched niches: small recessed pockets."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    # Voronoi field
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -250))
    vor = _safe_node(tree, 'ShaderNodeTexVoronoi', (250, -250))
    if vor:
        vor.voronoi_dimensions = '3D'
        vor.feature = 'DISTANCE_TO_EDGE'
        vor.inputs['Scale'].default_value = _noise_scale_for(props, 1.5)
        _link(tree, pos.outputs['Position'], vor.inputs['Vector'])
        color_node(vor, "noise")
    # Mask: select faces where voronoi distance < threshold → push inward
    less = _node(tree, 'ShaderNodeMath', (500, -250))
    less.operation = 'LESS_THAN'
    if vor:
        _link(tree, vor.outputs['Distance'], less.inputs[0])
    less.inputs[1].default_value = 0.12 * (1.0 / max(0.3, props.aest_density))
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -500))
    scale_n = _node(tree, 'ShaderNodeVectorMath', (300, -500))
    scale_n.operation = 'SCALE'
    _link(tree, normal.outputs['Normal'], scale_n.inputs[0])
    mult = _node(tree, 'ShaderNodeMath', (500, -500))
    mult.operation = 'MULTIPLY'
    _link(tree, less.outputs['Value'], mult.inputs[0])
    mult.inputs[1].default_value = -props.aest_intensity * 0.4
    _link(tree, mult.outputs['Value'], scale_n.inputs['Scale'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (800, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, scale_n.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "gothic")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_goth_fans(tree, props):
    """Radial fan ribs sprouting from the base center."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n_fans = max(4, int(props.aest_density * 6))
    n_ribs_per_fan = max(3, int(props.aest_layers + 3))
    for f_i in range(n_fans):
        base_ang = (f_i / n_fans) * 6.283185
        for r_i in range(n_ribs_per_fan):
            rib_ang = base_ang + (r_i - n_ribs_per_fan / 2) * 0.08
            length = 2.5 * props.aest_intensity
            cyl = _node(tree, 'GeometryNodeMeshCylinder',
                        (-400 + (f_i % 4) * 200, -200 - (f_i // 4) * 250 - r_i * 80))
            cyl.inputs['Radius'].default_value = 0.025 * props.aest_scale
            cyl.inputs['Depth'].default_value  = length
            cyl.inputs['Vertices'].default_value = 6
            tr = _node(tree, 'GeometryNodeTransform',
                       (-180 + (f_i % 4) * 200, -200 - (f_i // 4) * 250 - r_i * 80))
            # tilt outward in XY plane
            dx = math.cos(rib_ang) * length * 0.5
            dy = math.sin(rib_ang) * length * 0.5
            tr.inputs['Translation'].default_value = (dx, dy, length * 0.5)
            tr.inputs['Rotation'].default_value = (math.sin(rib_ang) * 0.4, -math.cos(rib_ang) * 0.4, 0)
            _link(tree, cyl.outputs['Mesh'], tr.inputs['Geometry'])
            color_node(cyl, "gothic"); color_node(tr, "gothic")
            pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_goth_finials(tree, props):
    """Pointed Gothic finials clustered at upward-facing surfaces (top mask)."""
    in_geom = _get_input_geom(tree)
    # Compound finial: short cylinder + tall narrow cone
    base = _node(tree, 'GeometryNodeMeshCylinder', (-500, -300))
    base.inputs['Radius'].default_value = 0.08 * props.aest_scale
    base.inputs['Depth'].default_value  = 0.2 * props.aest_scale
    base.inputs['Vertices'].default_value = 8
    spire = _safe_node(tree, 'GeometryNodeMeshCone', (-500, -500))
    if spire:
        spire.inputs['Radius Bottom'].default_value = 0.08 * props.aest_scale
        spire.inputs['Radius Top'].default_value    = 0.0
        spire.inputs['Depth'].default_value         = 0.5 * props.aest_scale * props.aest_intensity
        spire.inputs['Vertices'].default_value      = 24
        tr_s = _node(tree, 'GeometryNodeTransform', (-300, -500))
        tr_s.inputs['Translation'].default_value = (0, 0, 0.35 * props.aest_scale * props.aest_intensity)
        _link(tree, spire.outputs['Mesh'], tr_s.inputs['Geometry'])
        color_node(spire, "gothic"); color_node(tr_s, "gothic")
    j = _node(tree, 'GeometryNodeJoinGeometry', (-100, -400))
    _link(tree, base.outputs['Mesh'], j.inputs['Geometry'])
    if spire:
        _link(tree, tr_s.outputs['Geometry'], j.inputs['Geometry'])
    color_node(base, "gothic"); color_node(j, "gothic")
    # Distribute on faces (will sit on every face — for top-bias add manual filter)
    pts = _safe_node(tree, 'GeometryNodeDistributePointsOnFaces', (100, 0))
    if pts and in_geom:
        pts.distribute_method = 'POISSON'
        pts.inputs['Distance Min'].default_value = 0.5 / max(0.1, props.aest_density)
        pts.inputs['Density Max'].default_value  = props.aest_density * 2.0
        pts.inputs['Seed'].default_value         = props.aest_seed
        _link(tree, in_geom, pts.inputs['Mesh'])
        color_node(pts, "input")
    inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (400, 0))
    if inst and pts:
        _link(tree, pts.outputs['Points'], inst.inputs['Points'])
        _link(tree, j.outputs['Geometry'], inst.inputs['Instance'])
        try:
            _link(tree, pts.outputs['Normal'], inst.inputs['Rotation'])
        except Exception:
            pass
        color_node(inst, "gothic")
    real = _safe_node(tree, 'GeometryNodeRealizeInstances', (700, 0))
    if real and inst:
        _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
    return _join_with_input(tree, in_geom, real.outputs['Geometry'] if real else None)


def build_aest_goth_leadwork(tree, props):
    """Stained-glass lead lines: wireframe on voronoi-extruded cells."""
    in_geom = _get_input_geom(tree)
    # Build a subdivided base
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 2)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    # Voronoi displace creating cell terraces
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -250))
    vor = _safe_node(tree, 'ShaderNodeTexVoronoi', (250, -250))
    if vor:
        vor.voronoi_dimensions = '3D'
        vor.feature = 'F1'
        vor.inputs['Scale'].default_value = _noise_scale_for(props, 2.0)
        _link(tree, pos.outputs['Position'], vor.inputs['Vector'])
        color_node(vor, "noise")
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -450))
    scale_n = _node(tree, 'ShaderNodeVectorMath', (300, -450))
    scale_n.operation = 'SCALE'
    _link(tree, normal.outputs['Normal'], scale_n.inputs[0])
    if vor:
        mult = _node(tree, 'ShaderNodeMath', (500, -450))
        mult.operation = 'MULTIPLY'
        _link(tree, vor.outputs['Distance'], mult.inputs[0])
        mult.inputs[1].default_value = props.aest_intensity * 0.15
        _link(tree, mult.outputs['Value'], scale_n.inputs['Scale'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (800, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, scale_n.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "gothic")
        # Add wireframe on top for lead lines
        wire = _safe_node(tree, 'GeometryNodeWireframe', (1100, 0))
        if wire:
            try:
                wire.inputs['Radius'].default_value = 0.025 * props.aest_scale
            except Exception:
                pass
            _link(tree, set_pos.outputs['Geometry'], wire.inputs['Mesh'])
            color_node(wire, "tracery")
            join = _node(tree, 'GeometryNodeJoinGeometry', (1400, 0))
            _link(tree, set_pos.outputs['Geometry'], join.inputs['Geometry'])
            try:
                _link(tree, wire.outputs.get('Curve') or wire.outputs[0], join.inputs['Geometry'])
            except Exception:
                pass
            return join.outputs['Geometry']
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_goth_spires(tree, props):
    """Procedural spire forest growing from upward-facing peaks."""
    in_geom = _get_input_geom(tree)
    # Tall thin spire = cylinder + cone tip
    pole = _node(tree, 'GeometryNodeMeshCylinder', (-500, -300))
    pole.inputs['Radius'].default_value = 0.06 * props.aest_scale
    pole.inputs['Depth'].default_value  = 1.0 * props.aest_intensity
    pole.inputs['Vertices'].default_value = 6
    tip = _safe_node(tree, 'GeometryNodeMeshCone', (-500, -500))
    if tip:
        tip.inputs['Radius Bottom'].default_value = 0.06 * props.aest_scale
        tip.inputs['Radius Top'].default_value    = 0.0
        tip.inputs['Depth'].default_value         = 0.4 * props.aest_scale
        tip.inputs['Vertices'].default_value      = 24
        tip_tr = _node(tree, 'GeometryNodeTransform', (-300, -500))
        tip_tr.inputs['Translation'].default_value = (0, 0, 0.7 * props.aest_intensity)
        _link(tree, tip.outputs['Mesh'], tip_tr.inputs['Geometry'])
        color_node(tip, "gothic"); color_node(tip_tr, "gothic")
    pole_tr = _node(tree, 'GeometryNodeTransform', (-300, -300))
    pole_tr.inputs['Translation'].default_value = (0, 0, 0.5 * props.aest_intensity)
    _link(tree, pole.outputs['Mesh'], pole_tr.inputs['Geometry'])
    color_node(pole, "gothic"); color_node(pole_tr, "gothic")
    j = _node(tree, 'GeometryNodeJoinGeometry', (-100, -400))
    _link(tree, pole_tr.outputs['Geometry'], j.inputs['Geometry'])
    if tip:
        _link(tree, tip_tr.outputs['Geometry'], j.inputs['Geometry'])
    color_node(j, "gothic")
    real = _instance_on_surface(tree, in_geom, j.outputs['Geometry'],
                                props.aest_density * 0.5, props.aest_seed,
                                rand_scale=0.6, x_off=200, label="gothic")
    return _join_with_input(tree, in_geom, real)


# ---- 🌴 VAPORWAVE — extra ---------------------------------------------

def build_aest_vap_slices(tree, props):
    """Horizontal Z-band noise-offset slices: VHS-tracking glitch."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -250))
    sep = _node(tree, 'ShaderNodeSeparateXYZ', (200, -250))
    _link(tree, pos.outputs['Position'], sep.inputs['Vector'])
    # Stepped Z: floor(z * density)
    mul_z = _node(tree, 'ShaderNodeMath', (400, -250))
    mul_z.operation = 'MULTIPLY'
    _link(tree, sep.outputs['Z'], mul_z.inputs[0])
    mul_z.inputs[1].default_value = props.aest_density * 4.0
    flr = _node(tree, 'ShaderNodeMath', (600, -250))
    flr.operation = 'FLOOR'
    _link(tree, mul_z.outputs['Value'], flr.inputs[0])
    # Pseudo-random offset from floor
    noise = _safe_node(tree, 'ShaderNodeTexNoise', (800, -250))
    if noise:
        noise.inputs['Scale'].default_value = 2.0
        nb = _node(tree, 'ShaderNodeCombineXYZ', (800, -450))
        _link(tree, flr.outputs['Value'], nb.inputs['X'])
        _link(tree, nb.outputs['Vector'], noise.inputs['Vector'])
        color_node(noise, "noise")
    sub_v = _node(tree, 'ShaderNodeCombineXYZ', (1100, -250))
    if noise:
        mult_x = _node(tree, 'ShaderNodeMath', (1000, -350))
        mult_x.operation = 'MULTIPLY'
        _link(tree, noise.outputs['Fac'], mult_x.inputs[0])
        mult_x.inputs[1].default_value = props.aest_intensity * 0.4
        _link(tree, mult_x.outputs['Value'], sub_v.inputs['X'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (1400, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, sub_v.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "input")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_vap_scanlines(tree, props):
    """Raised horizontal scanlines via sine on Z."""
    in_geom = _get_input_geom(tree)
    subd = _node(tree, 'GeometryNodeSubdivisionSurface', (0, 0))
    subd.inputs['Level'].default_value = min(3, props.aest_layers + 2)
    if in_geom:
        _link(tree, in_geom, subd.inputs['Mesh'])
    pos = _node(tree, 'GeometryNodeInputPosition', (0, -250))
    sep = _node(tree, 'ShaderNodeSeparateXYZ', (200, -250))
    _link(tree, pos.outputs['Position'], sep.inputs['Vector'])
    mul = _node(tree, 'ShaderNodeMath', (400, -250))
    mul.operation = 'MULTIPLY'
    _link(tree, sep.outputs['Z'], mul.inputs[0])
    mul.inputs[1].default_value = props.aest_density * 15.0
    sn = _node(tree, 'ShaderNodeMath', (600, -250))
    sn.operation = 'SINE'
    _link(tree, mul.outputs['Value'], sn.inputs[0])
    # Step-clamp positive only
    clip = _node(tree, 'ShaderNodeMath', (800, -250))
    clip.operation = 'MAXIMUM'
    _link(tree, sn.outputs['Value'], clip.inputs[0])
    clip.inputs[1].default_value = 0.0
    amp = _node(tree, 'ShaderNodeMath', (1000, -250))
    amp.operation = 'MULTIPLY'
    _link(tree, clip.outputs['Value'], amp.inputs[0])
    amp.inputs[1].default_value = props.aest_intensity * 0.05
    normal = _node(tree, 'GeometryNodeInputNormal', (0, -500))
    scale_n = _node(tree, 'ShaderNodeVectorMath', (1200, -300))
    scale_n.operation = 'SCALE'
    _link(tree, normal.outputs['Normal'], scale_n.inputs[0])
    _link(tree, amp.outputs['Value'], scale_n.inputs['Scale'])
    set_pos = _safe_node(tree, 'GeometryNodeSetPosition', (1500, 0))
    if set_pos:
        _link(tree, subd.outputs['Mesh'], set_pos.inputs['Geometry'])
        _link(tree, scale_n.outputs['Vector'], set_pos.inputs['Offset'])
        color_node(set_pos, "input")
        return set_pos.outputs['Geometry']
    return subd.outputs['Mesh']


def build_aest_vap_busts(tree, props):
    """Classical marble busts (sphere + tapered cylinder) around the base."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n = max(3, int(props.aest_density * 6))
    radius = 2.2 * props.aest_scale
    for i in range(n):
        ang = (i / n) * 6.283185
        # head
        head = _node(tree, 'GeometryNodeMeshUVSphere', (-400, -200 - i * 100))
        head.inputs['Radius'].default_value = 0.25 * props.aest_scale
        head.inputs['Segments'].default_value = 12
        head.inputs['Rings'].default_value    = 8
        h_tr = _node(tree, 'GeometryNodeTransform', (-200, -200 - i * 100))
        h_tr.inputs['Translation'].default_value = (0, 0, 1.0 * props.aest_intensity)
        _link(tree, head.outputs['Mesh'], h_tr.inputs['Geometry'])
        # plinth
        plinth = _node(tree, 'GeometryNodeMeshCylinder', (-400, -260 - i * 100))
        plinth.inputs['Radius'].default_value = 0.18 * props.aest_scale
        plinth.inputs['Depth'].default_value  = 0.7 * props.aest_intensity
        plinth.inputs['Vertices'].default_value = 10
        p_tr = _node(tree, 'GeometryNodeTransform', (-200, -260 - i * 100))
        p_tr.inputs['Translation'].default_value = (0, 0, 0.35 * props.aest_intensity)
        _link(tree, plinth.outputs['Mesh'], p_tr.inputs['Geometry'])
        j = _node(tree, 'GeometryNodeJoinGeometry', (0, -230 - i * 100))
        _link(tree, h_tr.outputs['Geometry'], j.inputs['Geometry'])
        _link(tree, p_tr.outputs['Geometry'], j.inputs['Geometry'])
        # place around ring
        tr = _node(tree, 'GeometryNodeTransform', (200, -230 - i * 100))
        tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius, 0.0)
        tr.inputs['Rotation'].default_value = (0, 0, ang + 1.5708)
        _link(tree, j.outputs['Geometry'], tr.inputs['Geometry'])
        color_node(head, "tower"); color_node(plinth, "tower"); color_node(j, "tower"); color_node(tr, "tower")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (500, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_vap_slabs(tree, props):
    """Floating tilted holographic slabs orbiting the mesh."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n = max(4, int(props.aest_density * 10))
    for i in range(n):
        ang = (i / n) * 6.283185
        radius = (1.8 + (i % 3) * 0.5) * props.aest_scale
        height = (i % 4) * 0.6 + 0.4
        slab = _node(tree, 'GeometryNodeMeshCube', (-400 + (i % 4) * 200, -200 - (i // 4) * 200))
        slab.inputs['Size'].default_value = (0.9 * props.aest_scale, 0.04 * props.aest_scale, 0.55 * props.aest_scale)
        tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 4) * 200, -200 - (i // 4) * 200))
        tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius,
                                                   height * props.aest_intensity)
        tr.inputs['Rotation'].default_value = (0.15 * math.sin(i), 0.15 * math.cos(i), ang)
        _link(tree, slab.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(slab, "input"); color_node(tr, "input")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_vap_sun(tree, props):
    """Banded retro sun: half-disc with concentric ring bands behind."""
    in_geom = _get_input_geom(tree)
    pieces = []
    rings = max(3, min(8, props.aest_layers + 4))
    for r_i in range(rings):
        r = (r_i + 1) * 0.5 * props.aest_scale
        tor = _safe_node(tree, 'GeometryNodeMeshTorus', (-400, -200 - r_i * 200))
        if tor is None:
            continue
        try:
            tor.inputs['Major Radius'].default_value = r
            tor.inputs['Minor Radius'].default_value = 0.06 * props.aest_scale
            tor.inputs['Major Segments'].default_value = 32
            tor.inputs['Minor Segments'].default_value = 6
        except Exception:
            pass
        tr = _node(tree, 'GeometryNodeTransform', (-150, -200 - r_i * 200))
        tr.inputs['Rotation'].default_value = (1.5708, 0, 0)
        tr.inputs['Translation'].default_value = (0, -2.0 * props.aest_scale, 0.5 + r * 0.5)
        _link(tree, tor.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(tor, "input"); color_node(tr, "input")
        pieces.append(tr.outputs['Geometry'])
    # central solid disc
    disc = _safe_node(tree, 'GeometryNodeMeshCircle', (-400, 0))
    if disc:
        try:
            disc.inputs['Radius'].default_value = 0.45 * props.aest_scale
            disc.fill_type = 'NGON'
        except Exception:
            pass
        d_tr = _node(tree, 'GeometryNodeTransform', (-150, 0))
        d_tr.inputs['Rotation'].default_value = (1.5708, 0, 0)
        d_tr.inputs['Translation'].default_value = (0, -1.99 * props.aest_scale, 1.5)
        _link(tree, disc.outputs['Mesh'], d_tr.inputs['Geometry'])
        color_node(disc, "input"); color_node(d_tr, "input")
        pieces.append(d_tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_vap_neon_wrap(tree, props):
    """Neon tube ribbon: helix curve swept with a thin cylinder."""
    in_geom = _get_input_geom(tree)
    spiral = _safe_node(tree, 'GeometryNodeCurveSpiral', (-400, 0))
    if spiral:
        try:
            spiral.inputs['Resolution'].default_value = 64
            spiral.inputs['Rotations'].default_value  = 3.0 + props.aest_density
            spiral.inputs['Start Radius'].default_value = 1.5 * props.aest_scale
            spiral.inputs['End Radius'].default_value   = 1.5 * props.aest_scale
            spiral.inputs['Height'].default_value       = 3.0 * props.aest_intensity
        except Exception:
            pass
        # Profile circle
        circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (-400, -300))
        if circ:
            try:
                circ.inputs['Radius'].default_value = 0.04 * props.aest_scale
                circ.inputs['Resolution'].default_value = 8
            except Exception:
                pass
            c2m = _safe_node(tree, 'GeometryNodeCurveToMesh', (-100, -150))
            if c2m:
                _link(tree, spiral.outputs['Curve'], c2m.inputs['Curve'])
                _link(tree, circ.outputs['Curve'],   c2m.inputs['Profile Curve'])
                color_node(c2m, "input")
                return _join_with_input(tree, in_geom, c2m.outputs['Mesh'])
    return in_geom


# ---- ⛩ ZEN — extra ---------------------------------------------------

def build_aest_zen_orbit(tree, props):
    """Paper lanterns orbiting in concentric rings."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    rings = max(1, min(3, props.aest_layers))
    for r_i in range(rings):
        n = max(4, int(props.aest_density * 6))
        radius = (1.5 + r_i * 0.8) * props.aest_scale
        z = 1.5 * props.aest_intensity + r_i * 0.7
        for i in range(n):
            ang = (i / n) * 6.283185 + r_i * 0.3
            # lantern body
            body = _node(tree, 'GeometryNodeMeshUVSphere', (-400 + (i % 4) * 180, -200 - r_i * 400 - (i // 4) * 200))
            body.inputs['Radius'].default_value = 0.18 * props.aest_scale
            body.inputs['Segments'].default_value = 12
            body.inputs['Rings'].default_value    = 8
            tr = _node(tree, 'GeometryNodeTransform', (-200 + (i % 4) * 180, -200 - r_i * 400 - (i // 4) * 200))
            tr.inputs['Translation'].default_value = (math.cos(ang) * radius, math.sin(ang) * radius, z)
            tr.inputs['Scale'].default_value = (1.0, 1.0, 1.25)
            _link(tree, body.outputs['Mesh'], tr.inputs['Geometry'])
            color_node(body, "lantern"); color_node(tr, "lantern")
            pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_zen_smoke(tree, props):
    """Helical incense smoke trails rising from base — sweep cylinder along spiral."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n = max(2, int(props.aest_density * 4))
    for i in range(n):
        ang_off = (i / n) * 6.283185
        sp = _safe_node(tree, 'GeometryNodeCurveSpiral', (-400, -200 - i * 250))
        if sp is None:
            continue
        try:
            sp.inputs['Resolution'].default_value = 48
            sp.inputs['Rotations'].default_value  = 2.5
            sp.inputs['Start Radius'].default_value = 0.05
            sp.inputs['End Radius'].default_value   = 0.4 * props.aest_scale
            sp.inputs['Height'].default_value       = 3.5 * props.aest_intensity
        except Exception:
            pass
        prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (-400, -350 - i * 250))
        if prof:
            try:
                prof.inputs['Radius'].default_value = 0.025 * props.aest_scale
                prof.inputs['Resolution'].default_value = 6
            except Exception:
                pass
            c2m = _safe_node(tree, 'GeometryNodeCurveToMesh', (-100, -250 - i * 250))
            if c2m:
                _link(tree, sp.outputs['Curve'], c2m.inputs['Curve'])
                _link(tree, prof.outputs['Curve'], c2m.inputs['Profile Curve'])
                tr = _node(tree, 'GeometryNodeTransform', (150, -250 - i * 250))
                tr.inputs['Translation'].default_value = (math.cos(ang_off) * 0.6, math.sin(ang_off) * 0.6, 0)
                tr.inputs['Rotation'].default_value = (0, 0, ang_off)
                _link(tree, c2m.outputs['Mesh'], tr.inputs['Geometry'])
                color_node(c2m, "organic"); color_node(tr, "organic")
                pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (500, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_zen_pond(tree, props):
    """Reflective pond disc + lily pads beneath the object."""
    in_geom = _get_input_geom(tree)
    pieces = []
    # Pond disc
    disc = _safe_node(tree, 'GeometryNodeMeshCircle', (-400, 0))
    if disc:
        try:
            disc.inputs['Radius'].default_value = 3.0 * props.aest_scale
            disc.inputs['Vertices'].default_value = 48
            disc.fill_type = 'NGON'
        except Exception:
            pass
        tr = _node(tree, 'GeometryNodeTransform', (-150, 0))
        tr.inputs['Translation'].default_value = (0, 0, -0.05)
        _link(tree, disc.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(disc, "input"); color_node(tr, "input")
        pieces.append(tr.outputs['Geometry'])
    # Lily pads
    n = max(3, int(props.aest_density * 5))
    import math
    for i in range(n):
        ang = (i / n) * 6.283185
        r = 1.5 * props.aest_scale
        pad = _node(tree, 'GeometryNodeMeshUVSphere', (-400, -300 - i * 100))
        pad.inputs['Radius'].default_value = 0.3 * props.aest_scale
        pad.inputs['Segments'].default_value = 8
        pad.inputs['Rings'].default_value    = 4
        tr_p = _node(tree, 'GeometryNodeTransform', (-150, -300 - i * 100))
        tr_p.inputs['Translation'].default_value = (math.cos(ang) * r, math.sin(ang) * r, 0.02)
        tr_p.inputs['Scale'].default_value = (1.0, 1.0, 0.08)
        _link(tree, pad.outputs['Mesh'], tr_p.inputs['Geometry'])
        color_node(pad, "organic"); color_node(tr_p, "organic")
        pieces.append(tr_p.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_zen_terrace(tree, props):
    """Stepped terraced rock layers around the bbox."""
    in_geom = _get_input_geom(tree)
    pieces = []
    layers = max(2, min(6, props.aest_layers + 2))
    for L in range(layers):
        r = (1.5 + L * 0.6) * props.aest_scale
        h = 0.25 * props.aest_intensity
        disc = _safe_node(tree, 'GeometryNodeMeshCylinder', (-400, -200 - L * 200))
        if disc is None:
            continue
        disc.inputs['Radius'].default_value = r
        disc.inputs['Depth'].default_value  = h
        disc.inputs['Vertices'].default_value = max(12, int(16 + L * 4))
        tr = _node(tree, 'GeometryNodeTransform', (-150, -200 - L * 200))
        tr.inputs['Translation'].default_value = (0, 0, -h * (L + 0.5))
        _link(tree, disc.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(disc, "tower"); color_node(tr, "tower")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_zen_ginkgo(tree, props):
    """Ginkgo leaves drifting in noise field (flat fan-shaped instances)."""
    in_geom = _get_input_geom(tree)
    # Simple leaf = squished + tilted cone
    leaf = _safe_node(tree, 'GeometryNodeMeshCone', (-500, -300))
    if leaf:
        leaf.inputs['Radius Bottom'].default_value = 0.18 * props.aest_scale
        leaf.inputs['Radius Top'].default_value    = 0.02 * props.aest_scale
        leaf.inputs['Depth'].default_value         = 0.06 * props.aest_scale
        leaf.inputs['Vertices'].default_value      = 24
        tr_l = _node(tree, 'GeometryNodeTransform', (-300, -300))
        tr_l.inputs['Rotation'].default_value = (1.5708, 0, 0)
        _link(tree, leaf.outputs['Mesh'], tr_l.inputs['Geometry'])
        color_node(leaf, "organic"); color_node(tr_l, "organic")
    # Point cloud — use icosphere as scattered points
    cloud = _node(tree, 'GeometryNodeMeshIcoSphere', (-500, 200))
    cloud.inputs['Radius'].default_value = 2.5 * props.aest_scale
    cloud.inputs['Subdivisions'].default_value = max(2, props.aest_layers + 1)
    m2p = _safe_node(tree, 'GeometryNodeMeshToPoints', (-200, 200))
    if m2p:
        _link(tree, cloud.outputs['Mesh'], m2p.inputs['Mesh'])
    inst = _safe_node(tree, 'GeometryNodeInstanceOnPoints', (100, 200))
    if inst and m2p and leaf:
        _link(tree, m2p.outputs['Points'], inst.inputs['Points'])
        _link(tree, tr_l.outputs['Geometry'], inst.inputs['Instance'])
        # Random per-leaf rotation
        rrot = _safe_node(tree, 'FunctionNodeRandomValue', (100, 0))
        if rrot:
            rrot.data_type = 'FLOAT_VECTOR'
            try:
                rrot.inputs[0].default_value = (-1.5, -1.5, -3.14)  # min
                rrot.inputs[1].default_value = (1.5, 1.5, 3.14)    # max
                _link(tree, rrot.outputs['Value'], inst.inputs['Rotation'])
            except Exception:
                pass
    real = _safe_node(tree, 'GeometryNodeRealizeInstances', (400, 200))
    if real and inst:
        _link(tree, inst.outputs['Instances'], real.inputs['Geometry'])
        return _join_with_input(tree, in_geom, real.outputs['Geometry'])
    return in_geom


def build_aest_zen_runes(tree, props):
    """Calligraphy rune marks: small rectangular strokes distributed on faces."""
    in_geom = _get_input_geom(tree)
    pieces = []
    # Build a "rune" from a couple of bars at angles
    bar1 = _node(tree, 'GeometryNodeMeshCube', (-500, -200))
    bar1.inputs['Size'].default_value = (0.18 * props.aest_scale, 0.04 * props.aest_scale, 0.015 * props.aest_scale)
    bar2 = _node(tree, 'GeometryNodeMeshCube', (-500, -350))
    bar2.inputs['Size'].default_value = (0.05 * props.aest_scale, 0.14 * props.aest_scale, 0.015 * props.aest_scale)
    t2 = _node(tree, 'GeometryNodeTransform', (-300, -350))
    t2.inputs['Translation'].default_value = (0.0, 0.05 * props.aest_scale, 0)
    _link(tree, bar2.outputs['Mesh'], t2.inputs['Geometry'])
    j = _node(tree, 'GeometryNodeJoinGeometry', (-100, -250))
    _link(tree, bar1.outputs['Mesh'], j.inputs['Geometry'])
    _link(tree, t2.outputs['Geometry'], j.inputs['Geometry'])
    color_node(bar1, "ornament"); color_node(bar2, "ornament"); color_node(j, "ornament")
    real = _instance_on_surface(tree, in_geom, j.outputs['Geometry'],
                                props.aest_density * 1.5, props.aest_seed,
                                rand_scale=0.4, x_off=200, label="ornament")
    return _join_with_input(tree, in_geom, real)


# ---- 👁 SPIRITUAL — extra ---------------------------------------------

def build_aest_spi_runes(tree, props):
    """Rune circle: large torus at base + radial bar inscriptions."""
    in_geom = _get_input_geom(tree)
    pieces = []
    ring = _safe_node(tree, 'GeometryNodeMeshTorus', (-400, 0))
    if ring:
        try:
            ring.inputs['Major Radius'].default_value = 2.0 * props.aest_scale
            ring.inputs['Minor Radius'].default_value = 0.05 * props.aest_scale
            ring.inputs['Major Segments'].default_value = 64
            ring.inputs['Minor Segments'].default_value = 8
        except Exception:
            pass
        rtr = _node(tree, 'GeometryNodeTransform', (-150, 0))
        rtr.inputs['Translation'].default_value = (0, 0, -0.02)
        _link(tree, ring.outputs['Mesh'], rtr.inputs['Geometry'])
        color_node(ring, "ornament"); color_node(rtr, "ornament")
        pieces.append(rtr.outputs['Geometry'])
    import math
    n = max(6, int(props.aest_density * 12))
    for i in range(n):
        ang = (i / n) * 6.283185
        bar = _node(tree, 'GeometryNodeMeshCube', (-400, -200 - i * 50))
        bar.inputs['Size'].default_value = (0.15 * props.aest_scale, 0.035 * props.aest_scale, 0.02 * props.aest_scale)
        tr = _node(tree, 'GeometryNodeTransform', (-150, -200 - i * 50))
        r = 2.0 * props.aest_scale
        tr.inputs['Translation'].default_value = (math.cos(ang) * r, math.sin(ang) * r, 0)
        tr.inputs['Rotation'].default_value = (0, 0, ang)
        _link(tree, bar.outputs['Mesh'], tr.inputs['Geometry'])
        color_node(bar, "ornament"); color_node(tr, "ornament")
        pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (200, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


def build_aest_spi_halo(tree, props):
    """Fractal subdivided halo above the object: subdivided torus."""
    in_geom = _get_input_geom(tree)
    tor = _safe_node(tree, 'GeometryNodeMeshTorus', (-400, 0))
    if tor:
        try:
            tor.inputs['Major Radius'].default_value = 1.2 * props.aest_scale
            tor.inputs['Minor Radius'].default_value = 0.1 * props.aest_scale
            tor.inputs['Major Segments'].default_value = 48
            tor.inputs['Minor Segments'].default_value = 12
        except Exception:
            pass
        subd = _node(tree, 'GeometryNodeSubdivisionSurface', (-150, 0))
        subd.inputs['Level'].default_value = min(3, props.aest_layers + 1)
        _link(tree, tor.outputs['Mesh'], subd.inputs['Mesh'])
        # Noise displacement
        pos = _node(tree, 'GeometryNodeInputPosition', (-150, -250))
        noise = _safe_node(tree, 'ShaderNodeTexNoise', (50, -250))
        if noise:
            noise.inputs['Scale'].default_value = _noise_scale_for(props, 4.0)
            _link(tree, pos.outputs['Position'], noise.inputs['Vector'])
            color_node(noise, "noise")
        normal = _node(tree, 'GeometryNodeInputNormal', (-150, -450))
        scale_n = _node(tree, 'ShaderNodeVectorMath', (250, -350))
        scale_n.operation = 'SCALE'
        _link(tree, normal.outputs['Normal'], scale_n.inputs[0])
        if noise:
            mult = _node(tree, 'ShaderNodeMath', (250, -550))
            mult.operation = 'MULTIPLY'
            _link(tree, noise.outputs['Fac'], mult.inputs[0])
            mult.inputs[1].default_value = props.aest_intensity * 0.1
            _link(tree, mult.outputs['Value'], scale_n.inputs['Scale'])
        sp = _safe_node(tree, 'GeometryNodeSetPosition', (500, 0))
        if sp:
            _link(tree, subd.outputs['Mesh'], sp.inputs['Geometry'])
            _link(tree, scale_n.outputs['Vector'], sp.inputs['Offset'])
            tr = _node(tree, 'GeometryNodeTransform', (750, 0))
            tr.inputs['Translation'].default_value = (0, 0, 2.5 * props.aest_intensity)
            tr.inputs['Rotation'].default_value = (1.5708, 0, 0)
            _link(tree, sp.outputs['Geometry'], tr.inputs['Geometry'])
            color_node(tor, "ornament"); color_node(sp, "ornament"); color_node(tr, "ornament")
            return _join_with_input(tree, in_geom, tr.outputs['Geometry'])
    return in_geom


def build_aest_spi_triangles(tree, props):
    """Overlapping sacred-geometry triangles around the object (n equilateral, rotated)."""
    in_geom = _get_input_geom(tree)
    pieces = []
    import math
    n = max(3, int(props.aest_layers + 2))
    for i in range(n):
        circ = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (-500, -200 - i * 200))
        if circ is None:
            continue
        try:
            circ.inputs['Resolution'].default_value = 3   # triangle
            circ.inputs['Radius'].default_value = (1.3 + i * 0.15) * props.aest_scale
        except Exception:
            pass
        # extrude / wrap with thin cylinder profile
        prof = _safe_node(tree, 'GeometryNodeCurvePrimitiveCircle', (-500, -350 - i * 200))
        if prof:
            try:
                prof.inputs['Resolution'].default_value = 6
                prof.inputs['Radius'].default_value = 0.025 * props.aest_scale
            except Exception:
                pass
            c2m = _safe_node(tree, 'GeometryNodeCurveToMesh', (-250, -250 - i * 200))
            if c2m:
                _link(tree, circ.outputs['Curve'], c2m.inputs['Curve'])
                _link(tree, prof.outputs['Curve'], c2m.inputs['Profile Curve'])
                tr = _node(tree, 'GeometryNodeTransform', (0, -250 - i * 200))
                tr.inputs['Rotation'].default_value = (0, 0, i * (6.283185 / n))
                tr.inputs['Translation'].default_value = (0, 0, 0.3 + i * 0.05)
                _link(tree, c2m.outputs['Mesh'], tr.inputs['Geometry'])
                color_node(c2m, "ornament"); color_node(tr, "ornament")
                pieces.append(tr.outputs['Geometry'])
    join = _node(tree, 'GeometryNodeJoinGeometry', (300, 0))
    if in_geom:
        _link(tree, in_geom, join.inputs['Geometry'])
    for p in pieces:
        _link(tree, p, join.inputs['Geometry'])
    color_node(join, "output")
    return join.outputs['Geometry']


