_AEST_ROLE_PREFIX = {
    'BASE':     'A',
    'OVERLAY':  'B',
    'INSTANCE': 'C',
    'PROP':     'D',
    'TOP':      'E',
}


def apply_aesthetic_effect_gn(obj, props):
    """Apply the selected aesthetic effect as a dedicated GN modifier on top
    of the existing mesh. Non-destructive — multiple effects can stack, sorted
    by `aest_stack_role` so BASE displacements run before INSTANCE props etc."""
    effect = props.aesthetic_effect
    role = getattr(props, 'aest_stack_role', 'OVERLAY')
    role_prefix = _AEST_ROLE_PREFIX.get(role, 'B')
    # Remove any prior modifier for this exact effect (any role prefix)
    for mod in list(obj.modifiers):
        if mod.name.startswith("Aest_") and mod.name.endswith(f"_{effect}"):
            obj.modifiers.remove(mod)

    mod_name = f"Aest_{role_prefix}_{effect}"
    tree_name = f"_aest_{obj.name}_{role_prefix}_{effect}"
    old_tree = bpy.data.node_groups.get(tree_name)
    if old_tree:
        bpy.data.node_groups.remove(old_tree)

    mod = obj.modifiers.new(name=mod_name, type='NODES')
    tree = bpy.data.node_groups.new(name=tree_name, type='GeometryNodeTree')
    mod.node_group = tree
    tree.interface.new_socket(name="Geometry", in_out='INPUT',  socket_type='NodeSocketGeometry')
    tree.interface.new_socket(name="Geometry", in_out='OUTPUT', socket_type='NodeSocketGeometry')
    in_n  = tree.nodes.new('NodeGroupInput');  in_n.location  = (-800, 0)
    out_n = tree.nodes.new('NodeGroupOutput'); out_n.location = (2200, 0)
    color_node(in_n, "input"); color_node(out_n, "output")

    builder = _AESTHETIC_BUILDERS.get(effect)
    try:
        if builder is None:
            tree.links.new(in_n.outputs['Geometry'], out_n.inputs['Geometry'])
        else:
            geom_out = builder(tree, props)
            if geom_out is not None:
                tree.links.new(geom_out, out_n.inputs['Geometry'])
            else:
                tree.links.new(in_n.outputs['Geometry'], out_n.inputs['Geometry'])
    except Exception as e:
        print(f"[SurrealArch] Aesthetic effect error ({effect}): {e}")
        tree.links.new(in_n.outputs['Geometry'], out_n.inputs['Geometry'])


def clear_aesthetic_effects(obj):
    """Remove every Aest_* modifier from the object."""
    for mod in list(obj.modifiers):
        if mod.name.startswith("Aest_"):
            obj.modifiers.remove(mod)


def _sort_aesthetic_modifiers(obj):
    """Sort Aest_* modifiers by their role prefix (A→E) so BASE runs first."""
    aest_mods = [m for m in obj.modifiers if m.name.startswith("Aest_")]
    if len(aest_mods) <= 1:
        return
    # Build a sort key from the role prefix (Aest_A_X → 'A')
    def prefix_key(m):
        parts = m.name.split('_', 2)
        return parts[1] if len(parts) > 1 else 'B'
    sorted_names = [m.name for m in sorted(aest_mods, key=prefix_key)]
    # Use Blender's move-up/down to reorder
    for target_idx, name in enumerate(sorted_names):
        # find current idx, move it to target_idx
        idx = obj.modifiers.find(name)
        if idx < 0 or idx == target_idx:
            continue
        while idx > target_idx:
            try:
                bpy.ops.object.modifier_move_up({'object': obj}, modifier=name)
            except Exception:
                break
            idx -= 1
        while idx < target_idx:
            try:
                bpy.ops.object.modifier_move_down({'object': obj}, modifier=name)
            except Exception:
                break
            idx += 1


class SURREAL_ARCH_OT_aest_sort(bpy.types.Operator):
    """Sort Aest_* modifiers by stack role (BASE→OVERLAY→INSTANCE→PROP→TOP)."""
    bl_idname = "surreal_arch.aest_sort"
    bl_label = "Sort Stack by Role"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            return {'CANCELLED'}
        _sort_aesthetic_modifiers(obj)
        return {'FINISHED'}


def _surreal_user_presets_path():
    """Return path to the user-presets JSON file (per-user, survives sessions)."""
    import os, bpy
    dir_path = bpy.utils.user_resource('CONFIG', path='surreal_arch', create=True)
    return os.path.join(dir_path, 'user_presets.json')


def _surreal_load_user_presets():
    import json, os
    path = _surreal_user_presets_path()
    if not os.path.exists(path):
        return {}
    try:
        return json.load(open(path, encoding='utf-8'))
    except Exception:
        return {}


def _surreal_save_user_presets(data):
    import json
    path = _surreal_user_presets_path()
    try:
        json.dump(data, open(path, 'w', encoding='utf-8'), indent=2, default=str)
    except Exception as e:
        print(f"[SurrealArch] failed to save user presets: {e}")


# Properties that are NEVER captured into a preset (operational/UI state).
_PRESET_SKIP_PROPS = {
    'auto_update', 'auto_apply_material', 'apply_modifiers', 'auto_smooth',
    'sv_keep_tree', 'sv_resolution', 'sv_scale', 'sv_complexity', 'sv_seed',
    'sv_music_response', 'aest_bake_keep_original', 'aest_bake_mark_asset',
    'sv_quality_preset', 'spline_source_object', 'radial_source_object',
    'spline_target',
}


def _snapshot_props_to_dict(props):
    """Capture all simple-typed surreal_arch_props into a plain dict."""
    out = {}
    cls = type(props).bl_rna
    for prop in cls.properties:
        name = prop.identifier
        if name in ('rna_type', 'name'): continue
        if name in _PRESET_SKIP_PROPS: continue
        try:
            val = getattr(props, name)
        except Exception:
            continue
        # Skip pointer/complex
        if prop.type in ('POINTER', 'COLLECTION'): continue
        if prop.type == 'ENUM':
            out[name] = str(val)
        elif prop.type in ('FLOAT_VECTOR',):
            try: out[name] = tuple(val)
            except Exception: pass
        elif prop.type in ('FLOAT', 'INT', 'BOOLEAN', 'STRING'):
            out[name] = val
    return out


def _apply_dict_to_props(props, data):
    """Apply a saved preset dict back onto props (defensive — unknown keys ignored)."""
    global _AUTO_UPDATE_RUNNING
    _AUTO_UPDATE_RUNNING = True
    try:
        for k, v in data.items():
            if not hasattr(props, k): continue
            if k in _PRESET_SKIP_PROPS: continue
            try:
                setattr(props, k, v)
            except Exception:
                pass
    finally:
        _AUTO_UPDATE_RUNNING = False


class SURREAL_ARCH_OT_save_preset(bpy.types.Operator):
    """Save the active object's current property values as a named user preset.
    Stored in `<user-config>/surreal_arch/user_presets.json` so it persists
    across Blender sessions. Editable on the fly by re-saving."""
    bl_idname = "surreal_arch.save_preset"
    bl_label = "💾 Save Current as Preset"
    bl_options = {'REGISTER', 'UNDO'}

    preset_name: bpy.props.StringProperty(
        name="Preset Name",
        description="Identifier for this preset (overwrites if name exists)",
        default="My Preset", update=auto_update_callback)

    def invoke(self, context, event):
        # Suggest a name based on current arch_type
        obj = context.active_object
        if obj and hasattr(obj, 'surreal_arch_props'):
            self.preset_name = f"My {obj.surreal_arch_props.arch_type}"
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'preset_name')
        layout.label(text="Saves to user config — survives restarts.", icon='INFO')

    def execute(self, context):
        obj = context.active_object
        if obj is None or not hasattr(obj, 'surreal_arch_props'):
            self.report({'WARNING'}, "Select a mesh with surreal_arch_props")
            return {'CANCELLED'}
        data = _surreal_load_user_presets()
        data[self.preset_name] = _snapshot_props_to_dict(obj.surreal_arch_props)
        _surreal_save_user_presets(data)
        self.report({'INFO'}, f"💾 Saved preset '{self.preset_name}' "
                              f"({len(data[self.preset_name])} props)")
        return {'FINISHED'}


class SURREAL_ARCH_OT_load_preset(bpy.types.Operator):
    """Load a user preset onto the active object and regenerate."""
    bl_idname = "surreal_arch.load_preset"
    bl_label = "Load User Preset"
    bl_options = {'REGISTER', 'UNDO'}

    def _enum_items(self, context):
        data = _surreal_load_user_presets()
        if not data:
            return [('__none__', "(no saved presets)", "Save one first")]
        return [(k, k, f"{len(v)} props") for k, v in sorted(data.items())]

    preset_name: bpy.props.EnumProperty(name="Preset", items=_enum_items, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=300)

    def draw(self, context):
        self.layout.prop(self, 'preset_name')

    def execute(self, context):
        obj = context.active_object
        if obj is None or not hasattr(obj, 'surreal_arch_props'):
            self.report({'WARNING'}, "Select a mesh with surreal_arch_props")
            return {'CANCELLED'}
        if self.preset_name in (None, '', '__none__'):
            return {'CANCELLED'}
        data = _surreal_load_user_presets()
        if self.preset_name not in data:
            self.report({'WARNING'}, f"Preset '{self.preset_name}' not found")
            return {'CANCELLED'}
        _apply_dict_to_props(obj.surreal_arch_props, data[self.preset_name])
        try:
            bpy.ops.surreal_arch.generate()
        except Exception:
            pass
        self.report({'INFO'}, f"Loaded '{self.preset_name}'")
        return {'FINISHED'}


class SURREAL_ARCH_OT_delete_preset(bpy.types.Operator):
    """Delete a user preset from the on-disk store."""
    bl_idname = "surreal_arch.delete_preset"
    bl_label = "Delete User Preset"
    bl_options = {'REGISTER'}

    def _enum_items(self, context):
        data = _surreal_load_user_presets()
        if not data:
            return [('__none__', "(no saved presets)", "Nothing to delete")]
        return [(k, k, "") for k in sorted(data.keys())]

    preset_name: bpy.props.EnumProperty(name="Preset", items=_enum_items, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=300)

    def draw(self, context):
        self.layout.prop(self, 'preset_name')
        self.layout.label(text="This cannot be undone.", icon='ERROR')

    def execute(self, context):
        if self.preset_name in (None, '', '__none__'):
            return {'CANCELLED'}
        data = _surreal_load_user_presets()
        data.pop(self.preset_name, None)
        _surreal_save_user_presets(data)
        self.report({'INFO'}, f"Deleted '{self.preset_name}'")
        return {'FINISHED'}


class SURREAL_ARCH_OT_clamp_floating(bpy.types.Operator):
    """Detect mesh islands floating above the rest of the object and drop them
    downward until they touch the highest island below. Helpful when builders
    produce a small floating spire/finial/ornament that didn't get welded.

    Operates on the EVALUATED mesh — applies modifiers temporarily on a copy,
    finds floating islands by separate-loose-parts, snaps each down by the
    minimal Z amount needed to touch any island below it, then writes the
    repaired mesh back."""
    bl_idname = "surreal_arch.clamp_floating"
    bl_label = "🧲 Clamp Floating Pieces"
    bl_options = {'REGISTER', 'UNDO'}

    threshold: bpy.props.FloatProperty(
        name="Float Threshold",
        description="Islands whose lowest Z is more than this above the next-highest below are clamped",
        default=0.2, min=0.001, max=2.0, update=auto_update_callback)
    apply_modifiers: bpy.props.BoolProperty(
        name="Apply Modifiers First",
        description="Bake the GN modifier stack before clamping (destructive)",
        default=False, update=auto_update_callback)

    def execute(self, context):
        import bmesh
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh")
            return {'CANCELLED'}
        # Resolve the source mesh to operate on
        if self.apply_modifiers:
            # Bake modifiers in place
            for mod in list(obj.modifiers):
                try:
                    bpy.ops.object.modifier_apply(modifier=mod.name)
                except Exception:
                    pass
            me = obj.data
        else:
            # Operate on the evaluated mesh copy → writes back to obj.data
            deps = context.evaluated_depsgraph_get()
            ev = obj.evaluated_get(deps)
            try:
                me_eval = ev.to_mesh()
                # Copy evaluated mesh into a fresh mesh datablock
                new_me = bpy.data.meshes.new(obj.name + "_clamped")
                verts = [(v.co.x, v.co.y, v.co.z) for v in me_eval.vertices]
                edges = [(e.vertices[0], e.vertices[1]) for e in me_eval.edges]
                faces = [list(p.vertices) for p in me_eval.polygons]
                new_me.from_pydata(verts, edges, faces)
                new_me.update()
                old_me = obj.data
                obj.data = new_me
                if old_me.users == 0:
                    bpy.data.meshes.remove(old_me)
                # Remove modifiers since we baked
                for mod in list(obj.modifiers):
                    obj.modifiers.remove(mod)
                me = new_me
            finally:
                try: ev.to_mesh_clear()
                except Exception: pass
        # Find islands via flood fill
        bm = bmesh.new()
        bm.from_mesh(me)
        bm.verts.ensure_lookup_table()
        visited = set()
        islands = []
        for v in bm.verts:
            if v.index in visited: continue
            stack, members = [v], []
            while stack:
                cv = stack.pop()
                if cv.index in visited: continue
                visited.add(cv.index); members.append(cv)
                for e in cv.link_edges:
                    ov = e.other_vert(cv)
                    if ov and ov.index not in visited: stack.append(ov)
            if members:
                islands.append(members)
        # Compute Z-extents
        infos = []
        for isl in islands:
            zs = [v.co.z for v in isl]
            infos.append({"verts": isl, "zmin": min(zs), "zmax": max(zs)})
        infos.sort(key=lambda d: d["zmin"])
        # For each island i (top-down), find the highest zmax of any island
        # with zmin < d["zmin"] AND zmax < d["zmin"]. If the gap > threshold,
        # snap down so the gap closes (zmin = max-below).
        clamped = 0
        for i in range(len(infos)):
            d = infos[i]
            if d["zmin"] < 0.05: continue
            below = [b["zmax"] for b in infos[:i] if b["zmax"] < d["zmin"]]
            if not below: continue
            top_below = max(below)
            gap = d["zmin"] - top_below
            if gap > self.threshold:
                # Snap THIS island down by `gap` so its zmin == top_below
                for v in d["verts"]:
                    v.co.z -= gap
                d["zmin"] -= gap; d["zmax"] -= gap
                clamped += 1
        bm.to_mesh(me)
        bm.free()
        me.update()
        self.report({'INFO'}, f"Clamped {clamped} floating island(s)")
        return {'FINISHED'}


class SURREAL_ARCH_OT_aest_bake_stack(bpy.types.Operator):
    """Apply all Aest_* modifiers (sorted by role), optionally duplicating the
    source object first and optionally marking the result as an Asset."""
    bl_idname = "surreal_arch.aest_bake_stack"
    bl_label = "🥣 Bake Aesthetic Stack"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh first")
            return {'CANCELLED'}
        props = obj.surreal_arch_props
        # Optional duplicate
        target = obj
        if getattr(props, 'aest_bake_keep_original', True):
            try:
                bpy.ops.object.select_all(action='DESELECT')
                obj.select_set(True)
                context.view_layer.objects.active = obj
                bpy.ops.object.duplicate(linked=False)
                target = context.active_object
                target.name = f"{obj.name}_baked"
            except Exception as e:
                self.report({'WARNING'}, f"Duplicate failed: {e}")
        # Sort the stack so order matches role
        _sort_aesthetic_modifiers(target)
        # Apply every Aest_* modifier in order
        aest_mods = [m.name for m in target.modifiers if m.name.startswith("Aest_")]
        applied = 0
        for name in aest_mods:
            try:
                bpy.ops.object.select_all(action='DESELECT')
                target.select_set(True)
                context.view_layer.objects.active = target
                bpy.ops.object.modifier_apply(modifier=name)
                applied += 1
            except Exception as e:
                self.report({'WARNING'}, f"Apply {name} failed: {e}")
        # Optional asset mark
        if getattr(props, 'aest_bake_mark_asset', False):
            try:
                target.asset_mark()
                target.asset_generate_preview()
            except Exception:
                pass
        self.report({'INFO'}, f"Baked {applied} effects → {target.name}")
        return {'FINISHED'}


# ======================================================================
# AESTHETIC EFFECT OPERATORS — one-click buttons (work on ANY selected mesh)
# ======================================================================

def _apply_aest(context, effect_key):
    obj = context.active_object
    if obj is None or obj.type != 'MESH':
        return False
    p = obj.surreal_arch_props
    global _AUTO_UPDATE_RUNNING
    _AUTO_UPDATE_RUNNING = True
    try:
        p.aesthetic_effect = effect_key
    finally:
        _AUTO_UPDATE_RUNNING = False
    apply_aesthetic_effect_gn(obj, p)
    return True


# ══════════════════════════════════════════════════════════════════════
# LAYER 2 — Procedural City / Castle Composer (v2.27)
#
# Workflow:
#   ① Init Library     — pre-bake every Layer-1 piece into hidden assets
#   ② Spawn Plan       — generate a low-poly massing plan (castle/village/city)
#   ③ Compose World    — walk the plan's topology and instance pieces:
#                          faces → buildings (chosen by area + vertex group)
#                          boundary edges → walls
#                          3+ edge corner verts → towers
#                          gate-tagged verts → gatehouse
# Output: one joined mesh per composed world, with a back-reference to the
# plan so users can re-compose after tweaking the massing.
# ══════════════════════════════════════════════════════════════════════

# Layer 2 library — delegated to surreal_world (v2.68+)
try:
    from surreal_world.library import SURREAL_LIBRARY_SPEC as _SURREAL_LIBRARY_SPEC
except ImportError:
    _SURREAL_LIBRARY_SPEC = {}

try:
    from surreal_world.compose import COMPOSE_STYLES as _SURREAL_COMPOSE_STYLES
except ImportError:
    _SURREAL_COMPOSE_STYLES = {}


def _surreal_library_collection(create=True):
    try:
        from surreal_world import library as _wl
        return _wl.library_collection(create=create)
    except ImportError:
        coll = bpy.data.collections.get("SurrealArch_Library")
        if coll is None and create:
            coll = bpy.data.collections.new("SurrealArch_Library")
            if coll.name not in [c.name for c in bpy.context.scene.collection.children]:
                bpy.context.scene.collection.children.link(coll)
            coll.hide_viewport = True
            coll.hide_render = True
        return coll


def _bake_library_piece(arch_type, params, target_coll, force=False):
    import sys as _sys
    from surreal_world import library as _wl
    return _wl.bake_library_piece(_sys.modules[__name__], arch_type, params, target_coll, force)


class SURREAL_ARCH_OT_library_init(bpy.types.Operator):
    """Pre-bake the entire Layer-1 library into hidden SurrealArch_Library objects."""
    bl_idname = "surreal_arch.library_init"
    bl_label = "Initialize Composer Library"
    bl_options = {'REGISTER', 'UNDO'}

    force_refresh: bpy.props.BoolProperty(
        name="Force Refresh",
        description="Re-bake all pieces even if they already exist",
        default=False, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        self.layout.prop(self, 'force_refresh')
        self.layout.label(
            text=f"Will bake ~{len(_SURREAL_LIBRARY_SPEC)} pieces.",
            icon='INFO')

    def execute(self, context):
        coll = _surreal_library_collection(create=True)
        baked, skipped, failed = 0, 0, 0
        for arch_type, params in _SURREAL_LIBRARY_SPEC.items():
            obj, did_bake = _bake_library_piece(
                arch_type, params, coll, force=self.force_refresh)
            if obj is None:
                failed += 1
            elif did_bake:
                baked += 1
            else:
                skipped += 1
        self.report({'INFO'},
                    f"Library: {baked} baked, {skipped} kept, {failed} failed")
        bpy.ops.object.select_all(action='DESELECT')
        return {'FINISHED'}


class SURREAL_ARCH_OT_library_refresh_polish(bpy.types.Operator):
    """Refresh every baked library piece with smooth shading and optional Komikaze materials."""
    bl_idname = "surreal_arch.library_refresh_polish"
    bl_label = "Refresh Library Polish"
    bl_options = {'REGISTER', 'UNDO'}

    apply_komikaze: bpy.props.BoolProperty(
        name="Apply Komikaze Materials",
        description="Link Komikaze Wood material onto each library piece",
        default=True, update=auto_update_callback)
    weld_distance: bpy.props.FloatProperty(
        name="Weld Distance",
        description="Merge vertices within this distance to clean up topology",
        default=0.05, min=0.0, max=2.0, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'apply_komikaze')
        layout.prop(self, 'weld_distance')
        coll = _surreal_library_collection(create=False)
        n = len([o for o in coll.objects if o.name.startswith("_lib_")]) if coll else 0
        layout.label(text=f"Polishing {n} library piece(s).", icon='INFO')

    def execute(self, context):
        import bmesh
        coll = _surreal_library_collection(create=False)
        if coll is None:
            self.report({'WARNING'}, "Library not initialized — click Initialize first")
            return {'CANCELLED'}
        mat = None
        if self.apply_komikaze:
            mat = _komikaze_link('Wood', link=False)
            if mat is None:
                self.report({'WARNING'}, "Komikaze Wood not available — smooth-only")
        n_polished = 0
        for o in list(coll.objects):
            if not o.name.startswith("_lib_"):
                continue
            if o.type != 'MESH':
                continue
            try:
                for poly in o.data.polygons:
                    poly.use_smooth = True
            except Exception:
                pass
            if self.weld_distance > 0.0:
                try:
                    bm = bmesh.new()
                    bm.from_mesh(o.data)
                    bmesh.ops.remove_doubles(bm, verts=bm.verts, dist=self.weld_distance)
                    bmesh.ops.recalc_face_normals(bm, faces=bm.faces[:])
                    bm.to_mesh(o.data)
                    bm.free()
                except Exception as e:
                    print(f"[SurrealArch] weld {o.name}: {e}")
            if mat is not None:
                if o.data.materials:
                    o.data.materials[0] = mat
                else:
                    o.data.materials.append(mat)
            o.data.update()
            n_polished += 1
        self.report({'INFO'},
                    f"Polished {n_polished} library piece(s)"
                    + (" with Komikaze" if mat else ""))
        return {'FINISHED'}


# PLAN SPAWNERS — generate low-poly massing meshes with vertex-group tags
# ───────────────────────────────────────────────────────────────────────

def _create_plan_mesh(name, verts, edges, faces, vgroup_assignments=None,
                       location=(0, 0, 0)):
    """Create a mesh with named vertex groups for tagging.
    `vgroup_assignments` is dict { 'group_name': [vert_index, ...] }."""
    me = bpy.data.meshes.new(name)
    me.from_pydata(verts, edges, faces)
    me.update()
    obj = bpy.data.objects.new(name, me)
    bpy.context.scene.collection.objects.link(obj)
    obj.location = location
    # Vertex groups
    if vgroup_assignments:
        for gname, vids in vgroup_assignments.items():
            vg = obj.vertex_groups.new(name=gname)
            vg.add(list(vids), 1.0, 'REPLACE')
    # Custom property so we can identify it as a SurrealArch plan
    obj["surreal_plan_kind"] = name.split("_")[-1] if "_" in name else "custom"
    return obj


