def _spawn_motte_bailey_plan(location=(0, 0, 0), motte_r=3.0, bailey_r=9.0):
    from surreal_world import plans as _wp
    return _wp.spawn_motte_bailey_plan(location=location, motte_r=motte_r, bailey_r=bailey_r)


def _spawn_linear_coastal_plan(location=(0, 0, 0), length=20.0, depth=4.0, plots=8):
    """Linear coastal village: long strip of plot quads aligned along Y axis.
    Tagged for harbour-side gate cluster."""
    verts = []
    plot_len = length / plots
    for i in range(plots + 1):
        y = -length / 2 + i * plot_len
        verts.append((-depth / 2, y, 0))   # left side (coast)
        verts.append(( depth / 2, y, 0))   # right side
    faces = []
    for i in range(plots):
        a = i * 2; b = i * 2 + 1
        c = i * 2 + 3; d = i * 2 + 2
        faces.append([a, b, c, d])
    # Left edge (coast) = harbour; right edge = inland
    coast_verts = [i * 2 for i in range(plots + 1)]
    inland_verts = [i * 2 + 1 for i in range(plots + 1)]
    vgroups = {
        'is_plaza':       [coast_verts[plots // 2], coast_verts[plots // 2 + 1]],
        'is_gate':        [inland_verts[0]],   # south end = inland gate
        'is_corner_tower':[coast_verts[0], coast_verts[-1],
                           inland_verts[0], inland_verts[-1]],
    }
    return _create_plan_mesh(
        "SurrealPlan_Coastal", verts, [], faces, vgroups, location)


def _spawn_star_fort_plan(location=(0, 0, 0), n_points=5, inner_r=4.0, outer_r=8.0):
    """Star fort: N-pointed star with bastions at each star point."""
    import math
    verts = [(0.0, 0.0, 0.0)]   # 0 = center
    # 2N alternating inner/outer points
    for i in range(2 * n_points):
        ang = (i / (2 * n_points)) * math.tau - math.pi / 2   # start at top
        r = outer_r if i % 2 == 0 else inner_r
        verts.append((math.cos(ang) * r, math.sin(ang) * r, 0))
    # Star faces: center triangle for each pair of edges
    faces = []
    for i in range(2 * n_points):
        a = 1 + i
        b = 1 + (i + 1) % (2 * n_points)
        faces.append([0, a, b])
    # Tag the OUTER points (every other vert starting at 1) as bastions/towers
    bastion_verts = [1 + i * 2 for i in range(n_points)]
    vgroups = {
        'is_corner_tower': bastion_verts,
        'is_gate':         [bastion_verts[-1] - 1 if bastion_verts[-1] > 1
                            else bastion_verts[0] + 1],   # an inner point as the gate
        'is_keep':         [0],
    }
    return _create_plan_mesh(
        "SurrealPlan_StarFort", verts, [], faces, vgroups, location)


