# COMPOSER — delegated to surreal_world.compose (v2.68+)

def _compose_world(context, plan_obj, style_key='WESTERN_CASTLE',
                    detail_scale=1.0, compose_mode='COLLECTION'):
    import sys as _sys
    from surreal_world import compose as _wc
    return _wc.compose_world(_sys.modules[__name__], context, plan_obj,
                             style_key, detail_scale, compose_mode)


class SURREAL_ARCH_OT_compose_world(bpy.types.Operator):
    """Walk the active plan mesh's topology and instance Layer-1 library
    pieces into a complete world. Requires the library to be initialized."""
    bl_idname = "surreal_arch.compose_world"
    bl_label = "🏗 Compose World"
    bl_options = {'REGISTER', 'UNDO'}

    style: bpy.props.EnumProperty(
        name="Style",
        items=[
            ('WESTERN_CASTLE',  "Western Castle",  "Keep + curtain walls + watchtowers + gatehouse"),
            ('WESTERN_VILLAGE', "Western Village", "Town hall + tavern + smithy + bell tower"),
            ('ASIAN_CITY',      "Asian City",      "Hanok + pagoda + ting pavilion + pailou gate"),
            ('ZEN_SHRINE',      "Zen Shrine",      "Torii + teahouse + stone garden + lantern"),
        ],
        default='WESTERN_CASTLE', update=auto_update_callback)
    compose_mode: bpy.props.EnumProperty(
        name="Compose Mode",
        items=[
            ('COLLECTION', "Collection (AAA)", "Non-destructive instances under WorldRoot"),
            ('JOINED', "Joined Mesh", "Legacy single joined mesh"),
        ],
        default='COLLECTION',
    )
    detail_scale: bpy.props.FloatProperty(
        name="Detail Scale",
        description="Multiplier on every instanced piece's scale",
        default=1.0, min=0.2, max=4.0, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'style')
        layout.prop(self, 'compose_mode')
        layout.prop(self, 'detail_scale')
        obj = context.active_object
        if obj:
            layout.label(text=f"Plan: {obj.name}", icon='OUTLINER_OB_MESH')
            layout.label(
                text=f"Faces: {len(obj.data.polygons)}  Edges: {len(obj.data.edges)}  Verts: {len(obj.data.vertices)}",
                icon='INFO')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a plan mesh first")
            return {'CANCELLED'}
        # v2.37: Auto-init library if missing
        if _surreal_library_collection(create=False) is None:
            self.report({'INFO'}, "Library not found — auto-initializing 26 pieces…")
            try:
                bpy.ops.surreal_arch.library_init(force_refresh=False)
                # Re-select the plan since library_init switches active obj
                bpy.ops.object.select_all(action='DESELECT')
                obj.select_set(True)
                context.view_layer.objects.active = obj
            except Exception as e:
                self.report({'WARNING'}, f"Auto-init failed: {e}")
                return {'CANCELLED'}
        result, message = _compose_world(
            context, obj, self.style, self.detail_scale, self.compose_mode)
        if result is None:
            self.report({'WARNING'}, message)
            return {'CANCELLED'}
        self.report({'INFO'}, message)
        return {'FINISHED'}


# ─── v2.39: Plan-mesh editing tools — quick vertex-group tagging ──────

def _tag_selected_verts(obj, vgroup_name):
    """Add currently-selected verts (in Edit Mode) to the named vertex group.
    Creates the group if missing. Returns (count, error_msg|None).

    Mode dance: vg.add() refuses in Edit Mode and v.select is stale in Edit
    Mode, so we drop to Object Mode for both read AND write, then restore."""
    if obj is None or obj.type != 'MESH':
        return 0, "not a mesh"
    was_edit = (obj.mode == 'EDIT')
    if was_edit:
        bpy.ops.object.mode_set(mode='OBJECT')
    sel_indices = [v.index for v in obj.data.vertices if v.select]
    if not sel_indices:
        if was_edit:
            try: bpy.ops.object.mode_set(mode='EDIT')
            except Exception: pass
        return 0, "no verts selected"
    vg = obj.vertex_groups.get(vgroup_name) or obj.vertex_groups.new(name=vgroup_name)
    err = None
    try:
        vg.add(sel_indices, 1.0, 'REPLACE')
    except RuntimeError as e:
        err = str(e)
    if was_edit:
        try: bpy.ops.object.mode_set(mode='EDIT')
        except Exception: pass
    return (0 if err else len(sel_indices)), err


def _make_tag_operator(suffix, vgroup_name, label, icon):
    """Factory for plan-vertex tagging ops."""
    class _TagOp(bpy.types.Operator):
        bl_idname = f"surreal_arch.tag_{suffix}"
        bl_label = label
        bl_description = (f"Tag selected vertices of the plan mesh as "
                           f"'{vgroup_name}' so the composer treats them specially")
        bl_options = {'REGISTER', 'UNDO'}

        @classmethod
        def poll(cls, context):
            return (context.active_object is not None
                    and context.active_object.type == 'MESH')

        def execute(self, context):
            obj = context.active_object
            n, err = _tag_selected_verts(obj, vgroup_name)
            if err:
                self.report({'WARNING'}, err)
                return {'CANCELLED'}
            self.report({'INFO'}, f"{icon} Tagged {n} vert(s) as '{vgroup_name}'")
            return {'FINISHED'}
    _TagOp.__name__ = f"SURREAL_ARCH_OT_tag_{suffix}"
    return _TagOp


SURREAL_ARCH_OT_tag_keep   = _make_tag_operator('keep',   'is_keep',          "🏰 Tag as Keep",   "🏰")
SURREAL_ARCH_OT_tag_tower  = _make_tag_operator('tower',  'is_corner_tower',  "🗼 Tag as Tower",  "🗼")
SURREAL_ARCH_OT_tag_gate   = _make_tag_operator('gate',   'is_gate',          "🚪 Tag as Gate",   "🚪")
SURREAL_ARCH_OT_tag_plaza  = _make_tag_operator('plaza',  'is_plaza',         "🌳 Tag as Plaza",  "🌳")
SURREAL_ARCH_OT_tag_sacred = _make_tag_operator('sacred', 'is_sacred',        "⛪ Tag as Sacred", "⛪")


# v2.41: Plan vertex-color visualizer — paint a `surreal_plan_role` vertex
# color attribute based on each vertex's dominant tag, so the user can SEE
# which verts are tagged what while editing in Vertex Paint preview mode.

_PLAN_TAG_COLORS = {
    'is_keep':         (0.95, 0.45, 0.30, 1.0),   # warm orange-red — central/important
    'is_corner_tower': (0.40, 0.65, 0.95, 1.0),   # cool blue — defensive
    'is_gate':         (0.95, 0.85, 0.30, 1.0),   # gold-yellow — entrance
    'is_plaza':        (0.60, 0.90, 0.40, 1.0),   # green — open ground
    'is_sacred':       (0.85, 0.55, 0.95, 1.0),   # purple — sacred
}


class SURREAL_ARCH_PT_plan_edit_floating(bpy.types.Panel):
    """v2.42: Floating N-panel that only appears in 3D View Edit Mode when
    a SurrealArch plan mesh is active. Gives quick access to tagging ops
    + visualize + recompose without leaving Edit Mode."""
    bl_label = "🏰 SurrealArch Plan"
    bl_idname = "SURREAL_ARCH_PT_plan_edit_floating"
    bl_space_type = 'VIEW_3D'
    bl_region_type = 'UI'
    bl_category = "SurrealArch"

    @classmethod
    def poll(cls, context):
        obj = context.active_object
        return (obj is not None
                and obj.type == 'MESH'
                and (obj.name.startswith("SurrealPlan_")
                     or "surreal_plan_kind" in obj))

    def draw(self, context):
        layout = self.layout
        obj = context.active_object
        in_edit = (obj.mode == 'EDIT')
        # Header
        layout.label(text=f"Plan: {obj.name}", icon='OUTLINER_OB_MESH')
        if not in_edit:
            box = layout.box()
            box.label(text="Switch to Edit Mode to tag verts", icon='INFO')
        else:
            sel = sum(1 for v in obj.data.vertices if v.select)
            layout.label(text=f"Selected verts: {sel}", icon='RESTRICT_SELECT_OFF')

        # Tagging buttons
        tb = layout.box()
        tb.label(text="Tag selected as:", icon='GROUP_VERTEX')
        r1 = tb.row(align=True)
        r1.operator("surreal_arch.tag_keep",   text="🏰 Keep")
        r1.operator("surreal_arch.tag_tower",  text="🗼 Tower")
        r1.operator("surreal_arch.tag_gate",   text="🚪 Gate")
        r2 = tb.row(align=True)
        r2.operator("surreal_arch.tag_plaza",  text="🌳 Plaza")
        r2.operator("surreal_arch.tag_sacred", text="⛪ Sacred")

        # Visualize + Recompose shortcut
        vis = layout.box()
        vis.label(text="Preview", icon='HIDE_OFF')
        vis.operator("surreal_arch.visualize_plan",
                     text="🎨 Visualize Tags", icon='COLOR')

        # Recompose (only if a paired world exists)
        layout.separator()
        layout.operator("surreal_arch.recompose",
                         text="🔄 Re-Compose World",
                         icon='FILE_REFRESH')


class SURREAL_ARCH_OT_visualize_plan(bpy.types.Operator):
    """Paint a colour attribute on the active plan mesh so each tagged
    vertex gets a colour for its role. View in Material Preview or with
    a Vertex Color material to see Keep/Tower/Gate/Plaza/Sacred at a glance."""
    bl_idname = "surreal_arch.visualize_plan"
    bl_label = "🎨 Visualize Plan Tags"
    bl_options = {'REGISTER', 'UNDO'}

    untagged_color: bpy.props.FloatVectorProperty(
        name="Untagged",
        subtype='COLOR', size=4,
        default=(0.65, 0.65, 0.65, 1.0),
        min=0.0, max=1.0)
    attribute_name: bpy.props.StringProperty(
        name="Color Attribute",
        default="surreal_plan_role", update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.label(text="Tag→Color mapping:", icon='COLOR')
        for tag, col in _PLAN_TAG_COLORS.items():
            row = layout.row(align=True)
            row.label(text=f"  {tag}", icon='GROUP_VERTEX')
            sw = row.row(); sw.scale_x = 0.4
            sw.label(text=f"R{col[0]:.2f} G{col[1]:.2f} B{col[2]:.2f}")
        layout.prop(self, 'untagged_color')
        layout.prop(self, 'attribute_name')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a plan mesh first")
            return {'CANCELLED'}
        me = obj.data
        # Drop into Object Mode so attribute_create works reliably
        was_edit = (obj.mode == 'EDIT')
        if was_edit:
            bpy.ops.object.mode_set(mode='OBJECT')
        # Find or create the vertex-color attribute (POINT domain, FLOAT_COLOR)
        attr_name = self.attribute_name
        # Remove existing of same name (safe re-paint)
        existing = me.color_attributes.get(attr_name)
        if existing:
            me.color_attributes.remove(existing)
        try:
            attr = me.color_attributes.new(name=attr_name,
                                            type='FLOAT_COLOR',
                                            domain='POINT')
        except Exception as e:
            self.report({'ERROR'}, f"Could not create color attribute: {e}")
            if was_edit:
                bpy.ops.object.mode_set(mode='EDIT')
            return {'CANCELLED'}
        # For each vertex, pick a color based on dominant tag
        n_tagged = 0
        vg_idx = {name: (vg.index if vg else -1)
                  for name in _PLAN_TAG_COLORS
                  for vg in [obj.vertex_groups.get(name)]}
        for i, v in enumerate(me.vertices):
            picked = None
            for g in v.groups:
                if g.weight < 0.5:
                    continue
                for tag, gi in vg_idx.items():
                    if g.group == gi:
                        picked = tag; break
                if picked: break
            color = _PLAN_TAG_COLORS.get(picked, tuple(self.untagged_color))
            attr.data[i].color = color
            if picked:
                n_tagged += 1
        me.update()
        if was_edit:
            bpy.ops.object.mode_set(mode='EDIT')
        # Enable color overlay in the active viewport
        for area in context.screen.areas:
            if area.type == 'VIEW_3D':
                for space in area.spaces:
                    if space.type == 'VIEW_3D':
                        try:
                            space.shading.type = 'SOLID'
                            space.shading.color_type = 'VERTEX'
                        except Exception:
                            pass
                break
        self.report({'INFO'},
                    f"🎨 Painted '{attr_name}' — {n_tagged}/{len(me.vertices)} verts tagged. "
                    f"Viewport shading set to Vertex color.")
        return {'FINISHED'}


# v2.42: Asset Browser catalog auto-creation
# Blender stores catalogs in `blender_assets.cats.txt` at the asset library
# root, format: `<UUID>:<simple_name>:<display_name>`.
# We ensure a "SurrealArch" catalog exists and return its UUID so bakes
# can be assigned to it.

def _ensure_surreal_asset_catalog():
    """Find the user's primary asset library, ensure a 'SurrealArch' catalog
    exists in its blender_assets.cats.txt, return (uuid, library_path) — or
    (None, None) if there's no usable library."""
    import os, uuid as uuid_mod
    prefs = bpy.context.preferences
    libs = list(prefs.filepaths.asset_libraries) if hasattr(prefs.filepaths, 'asset_libraries') else []
    if not libs:
        return None, None
    # Prefer the first asset library that's a real directory
    lib_path = None
    for lib in libs:
        if lib.path and os.path.isdir(lib.path):
            lib_path = lib.path
            break
    if lib_path is None:
        return None, None
    cats_file = os.path.join(lib_path, "blender_assets.cats.txt")
    surreal_uuid = None
    # Read existing entries
    if os.path.exists(cats_file):
        try:
            with open(cats_file, encoding='utf-8') as f:
                for line in f:
                    line = line.strip()
                    if line.startswith('#') or not line: continue
                    if line.startswith('VERSION'): continue
                    parts = line.split(':')
                    if len(parts) >= 2 and parts[1] == 'SurrealArch':
                        surreal_uuid = parts[0]
                        break
        except Exception:
            pass
    # If not found, add it
    if surreal_uuid is None:
        surreal_uuid = str(uuid_mod.uuid4())
        try:
            existing = ""
            if os.path.exists(cats_file):
                with open(cats_file, encoding='utf-8') as f:
                    existing = f.read()
            else:
                existing = "VERSION 1\n"
            new_line = f"{surreal_uuid}:SurrealArch:SurrealArch\n"
            with open(cats_file, 'w', encoding='utf-8') as f:
                f.write(existing)
                if not existing.endswith('\n'):
                    f.write('\n')
                f.write(new_line)
        except Exception as e:
            print(f"[SurrealArch] catalog write failed: {e}")
            return None, lib_path
    return surreal_uuid, lib_path


class SURREAL_ARCH_OT_bake_world_asset(bpy.types.Operator):
    """Mark the active composed world as a Blender Asset Browser entry.
    Adds catalog metadata, auto-generates a thumbnail, and tags the asset
    with the compose style + plan source for searchability."""
    bl_idname = "surreal_arch.bake_world_asset"
    bl_label = "🏷 Bake World to Asset Browser"
    bl_options = {'REGISTER', 'UNDO'}

    asset_name: bpy.props.StringProperty(name="Asset Name", default="", update=auto_update_callback)
    asset_description: bpy.props.StringProperty(
        name="Description",
        default="Procedural world composed with Surreal Architecture Generator", update=auto_update_callback)

    def invoke(self, context, event):
        obj = context.active_object
        if obj is not None:
            self.asset_name = obj.name
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        obj = context.active_object
        if obj is None:
            layout.alert = True
            layout.label(text="Select a composed world first", icon='ERROR')
            return
        layout.label(text=f"Marking: {obj.name}", icon='OUTLINER_OB_MESH')
        layout.prop(self, 'asset_name')
        layout.prop(self, 'asset_description')
        comp_src = obj.get("surreal_composed_from")
        comp_style = obj.get("surreal_compose_style")
        if comp_src:
            layout.label(text=f"Source plan: {comp_src}", icon='LINK_BLEND')
        if comp_style:
            layout.label(text=f"Style: {comp_style}", icon='FILE_VOLUME')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh object first")
            return {'CANCELLED'}
        # Rename if changed
        if self.asset_name and self.asset_name != obj.name:
            obj.name = self.asset_name
        # Mark as asset
        try:
            obj.asset_mark()
        except Exception as e:
            self.report({'ERROR'}, f"Asset mark failed: {e}")
            return {'CANCELLED'}
        # Metadata — description + tags
        try:
            md = obj.asset_data
            md.description = self.asset_description
            # Tags: compose style + plan source + 'SurrealArch'
            for tag_name in ('SurrealArch',
                             obj.get("surreal_compose_style", "Generic"),
                             obj.get("surreal_composed_from", "Composed")):
                if tag_name and tag_name not in [t.name for t in md.tags]:
                    md.tags.new(name=tag_name)
            # Categorize under a SurrealArch catalog if asset libraries exist
            # v2.42: Auto-ensure a "SurrealArch" catalog exists in the user's
            # primary asset library and assign this bake to it.
            cat_uuid, lib_path = _ensure_surreal_asset_catalog()
            if cat_uuid:
                md.catalog_id = cat_uuid
                print(f"[SurrealArch] catalogued '{obj.name}' under SurrealArch "
                      f"(library: {lib_path})")
        except Exception as e:
            print(f"[SurrealArch] asset metadata failed: {e}")
        # Auto-generate thumbnail — needs the object selected + active in
        # the proper context. We override with a window-area-temp_override.
        try:
            bpy.ops.object.select_all(action='DESELECT')
            obj.select_set(True)
            context.view_layer.objects.active = obj
            # Get a 3D view area to provide the right context
            area_3d = next((a for a in context.screen.areas if a.type == 'VIEW_3D'), None)
            if area_3d:
                with context.temp_override(area=area_3d,
                                            active_object=obj,
                                            selected_objects=[obj]):
                    bpy.ops.ed.lib_id_generate_preview()
            else:
                bpy.ops.ed.lib_id_generate_preview()
        except Exception as e:
            print(f"[SurrealArch] preview gen skipped: {e}")
        self.report({'INFO'},
                    f"🏷 Marked '{obj.name}' as Asset Browser entry "
                    f"(open the Asset Browser to see it)")
        return {'FINISHED'}


class SURREAL_ARCH_OT_split_world(bpy.types.Operator):
    """Split a composed world (joined mesh from compose_world) back into its
    individual pieces by loose parts, so they can be edited independently.
    Pieces are dropped into a new `<world>_Pieces` collection."""
    bl_idname = "surreal_arch.split_world"
    bl_label = "🧩 Split Composed World into Pieces"
    bl_options = {'REGISTER', 'UNDO'}

    keep_original: bpy.props.BoolProperty(
        name="Keep Original Joined Mesh",
        description="Duplicate before splitting so the joined original is preserved",
        default=True, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        obj = context.active_object
        if obj is None:
            layout.label(text="Select a composed world (e.g. <Plan>_World)", icon='ERROR')
        else:
            layout.label(text=f"Splitting: {obj.name}", icon='OUTLINER_OB_MESH')
        layout.prop(self, 'keep_original')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a composed world mesh")
            return {'CANCELLED'}
        # Duplicate if requested
        target = obj
        if self.keep_original:
            try:
                bpy.ops.object.select_all(action='DESELECT')
                obj.select_set(True)
                context.view_layer.objects.active = obj
                bpy.ops.object.duplicate(linked=False)
                target = context.active_object
                target.name = f"{obj.name}_Split"
            except Exception as e:
                self.report({'WARNING'}, f"Duplicate failed: {e}")
                return {'CANCELLED'}
        # Move to a fresh collection
        pieces_coll = bpy.data.collections.new(f"{target.name}_Pieces")
        context.scene.collection.children.link(pieces_coll)
        for c in list(target.users_collection):
            c.objects.unlink(target)
        pieces_coll.objects.link(target)
        # Strip any orphan modifiers BEFORE separating (would cascade onto each piece)
        for mod in list(target.modifiers):
            try:
                target.modifiers.remove(mod)
            except Exception:
                pass
        # Separate by loose parts (must be in Edit Mode)
        try:
            bpy.ops.object.select_all(action='DESELECT')
            target.select_set(True)
            context.view_layer.objects.active = target
            bpy.ops.object.mode_set(mode='EDIT')
            bpy.ops.mesh.select_all(action='SELECT')
            bpy.ops.mesh.separate(type='LOOSE')
            bpy.ops.object.mode_set(mode='OBJECT')
        except Exception as e:
            self.report({'WARNING'}, f"Separate failed: {e}")
            return {'CANCELLED'}
        # Move all newly-spawned pieces into the same collection
        n_pieces = 0
        for o in context.selected_objects:
            if o.type != 'MESH': continue
            for c in list(o.users_collection):
                if c != pieces_coll:
                    c.objects.unlink(o)
                    if pieces_coll.name not in [cc.name for cc in o.users_collection]:
                        pieces_coll.objects.link(o)
            n_pieces += 1
        self.report({'INFO'}, f"🧩 Split into {n_pieces} pieces → {pieces_coll.name}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_one_click_castle(bpy.types.Operator):
    """One-click playable castle: Library init → Castle plan → Compose →
    Terrain → EasyTree scatter → Lighting → Make Walkable on the keep →
    Player Start. All sensible defaults."""
    bl_idname = "surreal_arch.one_click_castle"
    bl_label = "🎮 One-Click Playable Castle"
    bl_options = {'REGISTER', 'UNDO'}

    style: bpy.props.EnumProperty(
        name="Style",
        items=[
            ('WESTERN_CASTLE',  "🏰 Western Castle", ""),
            ('ASIAN_CITY',      "🏯 Asian City", ""),
            ('WESTERN_VILLAGE', "🏘 Western Village", ""),
        ],
        default='WESTERN_CASTLE', update=auto_update_callback)
    plan_size: bpy.props.FloatProperty(name="Plan Size", default=12.0, min=4.0, max=40.0, update=auto_update_callback)
    with_terrain:    bpy.props.BoolProperty(name="Add Terrain",      default=True, update=auto_update_callback)
    with_vegetation: bpy.props.BoolProperty(name="Add EasyTrees",    default=True, update=auto_update_callback)
    with_lighting:   bpy.props.BoolProperty(name="Add Lighting Rig", default=True, update=auto_update_callback)
    with_komikaze:   bpy.props.BoolProperty(name="Apply Komikaze",   default=False, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        col = layout.column(align=True)
        col.prop(self, 'style')
        col.prop(self, 'plan_size')
        col.separator()
        col.prop(self, 'with_terrain')
        col.prop(self, 'with_vegetation')
        col.prop(self, 'with_lighting')
        col.prop(self, 'with_komikaze')
        col.label(text="Will spawn full playable world.", icon='WORLD')

    def execute(self, context):
        # Ensure library exists
        if _surreal_library_collection(create=False) is None:
            try:
                bpy.ops.surreal_arch.library_init(force_refresh=False)
            except Exception as e:
                self.report({'WARNING'}, f"Library init failed: {e}")
                return {'CANCELLED'}
        # Spawn plan
        try:
            bpy.ops.surreal_arch.plan_spawn_castle(size=self.plan_size)
            plan = context.active_object
        except Exception as e:
            self.report({'WARNING'}, f"Plan spawn failed: {e}")
            return {'CANCELLED'}
        # Compose
        try:
            bpy.ops.surreal_arch.compose_world(
                style=self.style, detail_scale=0.8, compose_mode='COLLECTION')
            world = context.active_object
            root_name = plan.get("surreal_world_root") if plan else None
            if root_name:
                root = bpy.data.objects.get(root_name)
                if root is not None:
                    world = root
            elif world and world.type != 'EMPTY':
                try:
                    from surreal_world.export import find_world_root
                    wr = find_world_root(world)
                    if wr is not None:
                        world = wr
                except ImportError:
                    pass
        except Exception as e:
            self.report({'WARNING'}, f"Compose failed: {e}")
            return {'CANCELLED'}
        # Terrain
        if self.with_terrain:
            try:
                bpy.ops.surreal_arch.spawn_terrain(kind='HILL', noise_amp=1.5)
                # Re-select the world for next steps
                bpy.ops.object.select_all(action='DESELECT')
                world.select_set(True); context.view_layer.objects.active = world
            except Exception as e:
                print(f"[OneClick] terrain skipped: {e}")
        # Vegetation
        if self.with_vegetation:
            try:
                bpy.ops.surreal_arch.scatter_easytrees(
                    n=12, preset='MIXED', season='SUMMER',
                    border_only=True, seed=7)
            except Exception as e:
                print(f"[OneClick] vegetation skipped: {e}")
        # Lighting
        if self.with_lighting:
            try:
                bpy.ops.object.select_all(action='DESELECT')
                world.select_set(True); context.view_layer.objects.active = world
                bpy.ops.surreal_arch.lighting_rig(palette='WARM', count=6)
            except Exception as e:
                print(f"[OneClick] lighting skipped: {e}")
        # Komikaze
        if self.with_komikaze:
            try:
                bpy.ops.object.select_all(action='DESELECT')
                world.select_set(True); context.view_layer.objects.active = world
                bpy.ops.surreal_arch.komikaze_auto_map(apply_to_all_selected=False)
            except Exception as e:
                print(f"[OneClick] komikaze skipped: {e}")
        # Re-select world to leave a sensible active object
        bpy.ops.object.select_all(action='DESELECT')
        world.select_set(True); context.view_layer.objects.active = world
        self.report({'INFO'}, f"🎮 One-click {self.style} world ready: {world.name}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_recompose(bpy.types.Operator):
    """Re-compose a world from its source plan after editing the plan."""
    bl_idname = "surreal_arch.recompose"
    bl_label = "🔄 Re-Compose World"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None:
            self.report({'WARNING'}, "Select a composed world or its source plan")
            return {'CANCELLED'}
        # If user selected the composed world, find its source plan
        src_name = obj.get("surreal_composed_from")
        style    = obj.get("surreal_compose_style", "WESTERN_CASTLE")
        if src_name:
            plan = bpy.data.objects.get(src_name)
            if plan is None:
                self.report({'WARNING'}, f"Source plan '{src_name}' missing")
                return {'CANCELLED'}
            # Delete the old composed world
            bpy.data.objects.remove(obj, do_unlink=True)
        else:
            plan = obj
        result, message = _compose_world(context, plan, style, 1.0)
        if result is None:
            self.report({'WARNING'}, message)
            return {'CANCELLED'}
        self.report({'INFO'}, message)
        return {'FINISHED'}


