# ══════════════════════════════════════════════════════════════════════
# LAYER 3 — Bringing the World to Life (v2.29)
#
# Three first-cut deliverables:
#   ① Terrain Generator      — contextual hillside/island/cliff under a world
#   ② Vegetation Scatter     — Poisson tree/bush distribution on a target
#   ③ Lighting Rig           — auto-place point lights at strategic positions
#
# Also: 🪞 Polish All — global bevel/auto-smooth pass on selection.
# ══════════════════════════════════════════════════════════════════════


def _world_bbox(obj):
    """Return (min_co, max_co, center, size) for an object's evaluated bbox
    in world coordinates."""
    from mathutils import Vector
    deps = bpy.context.evaluated_depsgraph_get()
    ev = obj.evaluated_get(deps)
    me = ev.to_mesh() if obj.type == 'MESH' else None
    if me is None or len(me.vertices) == 0:
        if me is not None: ev.to_mesh_clear()
        return None
    mat = obj.matrix_world
    coords = [mat @ Vector(v.co) for v in me.vertices]
    ev.to_mesh_clear()
    mn = Vector((min(c.x for c in coords), min(c.y for c in coords), min(c.z for c in coords)))
    mx = Vector((max(c.x for c in coords), max(c.y for c in coords), max(c.z for c in coords)))
    return (mn, mx, (mn + mx) * 0.5, mx - mn)


# ─── ① TERRAIN GENERATOR ────────────────────────────────────────────

def _spawn_terrain(context, footprint_obj, kind='HILL', subdivisions=4,
                    noise_amp=2.0, padding=4.0, seed=1):
    """Generate a contextual terrain mesh under footprint_obj's bbox.
    `kind`: HILL, ISLAND, CLIFF, PLAIN."""
    import bmesh, math, random
    bbox = _world_bbox(footprint_obj) if footprint_obj else None
    if bbox is None:
        # Use cursor + a default 20x20 footprint
        cx, cy, cz = context.scene.cursor.location
        mn = (cx - 10, cy - 10, cz); mx = (cx + 10, cy + 10, cz); center = (cx, cy, cz); size = (20, 20, 0)
    else:
        mn, mx, center, size = bbox
    W = max(size[0], size[1]) + padding * 2
    cx, cy, cz = center[0], center[1], mn[2]
    # Build a subdivided grid as bmesh
    bm = bmesh.new()
    bmesh.ops.create_grid(bm,
                           x_segments=max(8, 2 ** subdivisions),
                           y_segments=max(8, 2 ** subdivisions),
                           size=W * 0.5)
    # Translate to footprint center
    bmesh.ops.transform(bm,
                         matrix=__import__('mathutils').Matrix.Translation((cx, cy, cz)),
                         verts=bm.verts)
    # Apply kind-specific displacement using noise
    rng = random.Random(seed)
    radius = W * 0.5
    for v in bm.verts:
        dx = v.co.x - cx; dy = v.co.y - cy
        r = math.sqrt(dx * dx + dy * dy) / radius   # 0..1+
        # Noise (cheap pseudo-Perlin via combined sines)
        nx = v.co.x * 0.3 + seed * 0.7
        ny = v.co.y * 0.3 + seed * 1.3
        noise = (math.sin(nx) + math.sin(ny * 1.6) + math.sin(nx * 1.7 + ny * 1.1)) / 3.0
        if kind == 'HILL':
            # Gentle dome — high at center, falls off
            h = (1.0 - min(1.0, r)) * noise_amp + noise * noise_amp * 0.3
            v.co.z += h
        elif kind == 'ISLAND':
            # Sharp drop at perimeter, plateau inside, irregular edges
            if r > 0.85:
                v.co.z -= max(0.5, (r - 0.85) * noise_amp * 3.0)
            else:
                v.co.z += noise * noise_amp * 0.4
        elif kind == 'CLIFF':
            # One side drops away
            if v.co.y > cy + radius * 0.2:
                v.co.z -= max(0, (v.co.y - cy - radius * 0.2) * noise_amp * 0.6)
            v.co.z += noise * noise_amp * 0.2
        elif kind == 'PLAIN':
            # Gentle rolling noise
            v.co.z += noise * noise_amp * 0.5
    # Smooth normals
    bmesh.ops.recalc_face_normals(bm, faces=bm.faces[:])
    me = bpy.data.meshes.new(f"Terrain_{kind}")
    bm.to_mesh(me)
    bm.free()
    # Smooth shading
    for p in me.polygons:
        p.use_smooth = True
    obj = bpy.data.objects.new(f"Terrain_{kind}", me)
    context.scene.collection.objects.link(obj)
    # If we have a footprint, lower the terrain so footprint sits on top
    # (subtract a small dip so the floor pieces don't z-fight)
    obj.location.z -= 0.02
    if footprint_obj:
        obj["surreal_terrain_for"] = footprint_obj.name
    return obj


class SURREAL_ARCH_OT_spawn_terrain(bpy.types.Operator):
    """Generate a contextual terrain under the selected object's footprint.
    HILL = dome under a castle; ISLAND = water-bound plateau; CLIFF = drop on
    one side; PLAIN = gently rolling base."""
    bl_idname = "surreal_arch.spawn_terrain"
    bl_label = "🌄 Spawn Terrain"
    bl_options = {'REGISTER', 'UNDO'}

    kind: bpy.props.EnumProperty(
        name="Terrain Kind",
        items=[
            ('HILL',   "🟫 Hill",   "Dome rises from center, falls off at edges"),
            ('ISLAND', "🏝 Island", "Plateau with sharp drop-off perimeter"),
            ('CLIFF',  "🪨 Cliff",  "One side drops away vertically"),
            ('PLAIN',  "🌿 Plain",  "Gentle rolling noise base"),
        ],
        default='HILL', update=auto_update_callback)
    noise_amp: bpy.props.FloatProperty(
        name="Noise Amplitude",
        description="Height variation strength", default=2.0, min=0.0, max=15.0, update=auto_update_callback)
    padding: bpy.props.FloatProperty(
        name="Padding",
        description="Extra terrain beyond the footprint's bbox",
        default=4.0, min=0.0, max=30.0, update=auto_update_callback)
    subdivisions: bpy.props.IntProperty(
        name="Subdivisions",
        description="2^N grid resolution (higher = smoother, slower)",
        default=5, min=2, max=8, update=auto_update_callback)
    seed: bpy.props.IntProperty(name="Seed", default=1, min=0, max=99999, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'kind')
        layout.prop(self, 'noise_amp')
        layout.prop(self, 'padding')
        layout.prop(self, 'subdivisions')
        layout.prop(self, 'seed')
        obj = context.active_object
        if obj is None:
            layout.label(text="No footprint selected — terrain at 3D cursor.", icon='INFO')
        else:
            layout.label(text=f"Footprint: {obj.name}", icon='OUTLINER_OB_MESH')

    def execute(self, context):
        obj = context.active_object
        terrain = _spawn_terrain(context, obj, self.kind,
                                  subdivisions=self.subdivisions,
                                  noise_amp=self.noise_amp,
                                  padding=self.padding, seed=self.seed)
        bpy.ops.object.select_all(action='DESELECT')
        terrain.select_set(True)
        context.view_layer.objects.active = terrain
        self.report({'INFO'}, f"🌄 Terrain: {terrain.name}")
        return {'FINISHED'}


# ─── ② VEGETATION SCATTER ──────────────────────────────────────────

def _scatter_vegetation(context, target_obj, n=30, scale_range=(0.6, 1.4),
                         z_jitter=0.0, library_piece='_lib_STYLIZED_TREE',
                         seed=42, avoid_existing=True):
    """Poisson-distribute instances of a library piece across a target's faces."""
    import random, math
    if target_obj is None or target_obj.type != 'MESH':
        return None, "Need a mesh target"
    src = bpy.data.objects.get(library_piece)
    if src is None:
        return None, f"Library piece '{library_piece}' missing — run 📚 Initialize"
    rng = random.Random(seed)
    target_me = target_obj.data
    if len(target_me.polygons) == 0:
        return None, "Target has no faces to scatter on"
    # Sample points on faces (weighted by face area)
    total_area = sum(p.area for p in target_me.polygons)
    cumulative = []
    s = 0.0
    for p in target_me.polygons:
        s += p.area / total_area
        cumulative.append(s)
    coll = bpy.data.collections.get(f"{target_obj.name}_Vegetation")
    if coll is None:
        coll = bpy.data.collections.new(f"{target_obj.name}_Vegetation")
        context.scene.collection.children.link(coll)
    spawned = []
    target_mat = target_obj.matrix_world
    placed_xy = []
    min_dist_sq = (1.5) ** 2  # min spacing between instances
    attempts = 0
    while len(spawned) < n and attempts < n * 5:
        attempts += 1
        # Pick a face by area-weight
        u = rng.random()
        face_idx = 0
        for i, c in enumerate(cumulative):
            if u <= c:
                face_idx = i; break
        face = target_me.polygons[face_idx]
        # Random barycentric within face center → vertex pull
        # Simpler: jitter from face center toward a random vertex
        verts = [target_me.vertices[v].co for v in face.vertices]
        w = [rng.random() for _ in verts]
        sw = sum(w) or 1.0
        local_pt = sum(((v * (wi / sw) for v, wi in zip(verts, w))),
                       __import__('mathutils').Vector((0, 0, 0)))
        world_pt = target_mat @ local_pt
        # Min-dist check
        too_close = False
        for px, py in placed_xy:
            dx = world_pt.x - px; dy = world_pt.y - py
            if dx * dx + dy * dy < min_dist_sq:
                too_close = True; break
        if too_close: continue
        placed_xy.append((world_pt.x, world_pt.y))
        # Add Z jitter (positive only, so trees lift off slopes)
        world_pt.z += rng.uniform(0, z_jitter)
        # Instance the library piece
        new_me = src.data.copy()
        new_obj = bpy.data.objects.new(f"veg_{src.name[5:]}", new_me)
        new_obj.location = world_pt
        scale = rng.uniform(*scale_range)
        new_obj.scale = (scale, scale, scale)
        new_obj.rotation_euler.z = rng.uniform(0, math.tau)
        coll.objects.link(new_obj)
        spawned.append(new_obj)
    # Join all into one
    if not spawned:
        bpy.data.collections.remove(coll)
        return None, "No instances placed (target faces too small?)"
    for o in context.view_layer.objects:
        try: o.select_set(False)
        except Exception: pass
    for o in spawned:
        try: o.select_set(True)
        except Exception: pass
    context.view_layer.objects.active = spawned[0]
    try:
        with context.temp_override(active_object=spawned[0],
                                    selected_objects=spawned,
                                    selected_editable_objects=spawned):
            bpy.ops.object.join()
        result = context.view_layer.objects.active
        result.name = f"{target_obj.name}_Vegetation"
        for c in list(result.users_collection):
            c.objects.unlink(result)
        context.scene.collection.objects.link(result)
        bpy.data.collections.remove(coll)
        return result, f"Scattered {len(spawned)} instances"
    except Exception as e:
        return spawned[0], f"Partial join ({len(spawned)} pieces): {e}"


class SURREAL_ARCH_OT_scatter_vegetation(bpy.types.Operator):
    """Scatter library pieces (default: STYLIZED_TREE) across the active
    object's faces using Poisson-like distribution. Use on terrain or
    composed worlds to fill empty space."""
    bl_idname = "surreal_arch.scatter_vegetation"
    bl_label = "🌳 Scatter Vegetation"
    bl_options = {'REGISTER', 'UNDO'}

    n: bpy.props.IntProperty(name="Count", default=40, min=1, max=500, update=auto_update_callback)
    scale_min: bpy.props.FloatProperty(name="Min Scale", default=0.6, min=0.1, max=4.0, update=auto_update_callback)
    scale_max: bpy.props.FloatProperty(name="Max Scale", default=1.4, min=0.1, max=4.0, update=auto_update_callback)
    z_jitter: bpy.props.FloatProperty(name="Z Jitter", default=0.0, min=0.0, max=5.0, update=auto_update_callback)
    library_piece: bpy.props.EnumProperty(
        name="Piece",
        items=[
            ('_lib_STYLIZED_TREE',   "🌳 Stylized Tree",   "Default tree"),
            ('_lib_BOULDER_PILE',    "🪨 Boulder Pile",   "Rock cluster"),
            ('_lib_STREET_LAMP',     "🔦 Street Lamp",   "Lamp post"),
            ('_lib_HERALDIC_BANNER', "🚩 Banner",        "Heraldic banner"),
        ],
        default='_lib_STYLIZED_TREE', update=auto_update_callback)
    seed: bpy.props.IntProperty(name="Seed", default=42, min=0, max=99999, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'library_piece')
        layout.prop(self, 'n')
        row = layout.row(align=True)
        row.prop(self, 'scale_min')
        row.prop(self, 'scale_max')
        layout.prop(self, 'z_jitter')
        layout.prop(self, 'seed')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh target first")
            return {'CANCELLED'}
        result, msg = _scatter_vegetation(context, obj, n=self.n,
                                           scale_range=(self.scale_min, self.scale_max),
                                           z_jitter=self.z_jitter,
                                           library_piece=self.library_piece,
                                           seed=self.seed)
        if result is None:
            self.report({'WARNING'}, msg)
            return {'CANCELLED'}
        self.report({'INFO'}, msg)
        return {'FINISHED'}


# ─── ③ LIGHTING RIG ────────────────────────────────────────────────

def _spawn_lighting_rig(context, target_obj, palette='WARM', count=6,
                         height_factor=0.7):
    """Auto-place point lights at strategic positions on/above the target."""
    import math
    bbox = _world_bbox(target_obj) if target_obj else None
    if bbox is None:
        return None, "Target has no geometry"
    mn, mx, center, size = bbox
    palettes = {
        'WARM':    {'color': (1.0, 0.78, 0.55), 'energy': 800,
                    'name_prefix': "WarmLight"},
        'COLD':    {'color': (0.55, 0.75, 1.0), 'energy': 600,
                    'name_prefix': "ColdLight"},
        'GOTHIC':  {'color': (0.8, 0.4, 0.3), 'energy': 500,
                    'name_prefix': "GothicLight"},
        'NEON':    {'color': (1.0, 0.3, 0.85), 'energy': 1200,
                    'name_prefix': "NeonLight"},
        'NATURAL': {'color': (1.0, 0.95, 0.85), 'energy': 1000,
                    'name_prefix': "NaturalLight"},
    }
    palette_def = palettes.get(palette, palettes['WARM'])
    # Strategic positions: top of bbox at corners + center + radial perimeter
    spawned = []
    top_z = mn.z + size.z * height_factor
    # Corner lights
    corners = [
        (mn.x, mn.y, top_z), (mx.x, mn.y, top_z),
        (mn.x, mx.y, top_z), (mx.x, mx.y, top_z),
    ]
    coll = bpy.data.collections.get(f"{target_obj.name}_Lighting")
    if coll is None:
        coll = bpy.data.collections.new(f"{target_obj.name}_Lighting")
        context.scene.collection.children.link(coll)
    n_placed = 0
    for cx, cy, cz in corners[:count]:
        light_data = bpy.data.lights.new(
            name=palette_def['name_prefix'], type='POINT')
        light_data.color = palette_def['color']
        light_data.energy = palette_def['energy']
        try: light_data.shadow_soft_size = max(0.3, min(size.x, size.y) * 0.05)
        except Exception: pass
        light_obj = bpy.data.objects.new(palette_def['name_prefix'], light_data)
        light_obj.location = (cx, cy, cz)
        coll.objects.link(light_obj)
        spawned.append(light_obj)
        n_placed += 1
    # Central "key" light above the center
    if n_placed < count:
        center_light = bpy.data.lights.new(
            name=palette_def['name_prefix'] + "_Key", type='POINT')
        center_light.color = palette_def['color']
        center_light.energy = palette_def['energy'] * 1.5
        try: center_light.shadow_soft_size = max(0.5, min(size.x, size.y) * 0.08)
        except Exception: pass
        ko = bpy.data.objects.new(center_light.name, center_light)
        ko.location = (center.x, center.y, mx.z + size.z * 0.3)
        coll.objects.link(ko)
        spawned.append(ko)
        n_placed += 1
    # Perimeter radial lights to fill remaining count
    remaining = count - n_placed
    for i in range(remaining):
        ang = (i / max(1, remaining)) * math.tau
        radius = max(size.x, size.y) * 0.6
        cx = center.x + math.cos(ang) * radius
        cy = center.y + math.sin(ang) * radius
        cz = mn.z + size.z * 0.5
        rl = bpy.data.lights.new(
            name=palette_def['name_prefix'] + f"_Ring{i}", type='POINT')
        rl.color = palette_def['color']
        rl.energy = palette_def['energy'] * 0.7
        rlo = bpy.data.objects.new(rl.name, rl)
        rlo.location = (cx, cy, cz)
        coll.objects.link(rlo)
        spawned.append(rlo)
    return spawned, f"Placed {len(spawned)} {palette} lights in {coll.name}"


class SURREAL_ARCH_OT_lighting_rig(bpy.types.Operator):
    """Auto-place strategic point lights around the active object using a
    color palette. Wraps the lights in a dedicated collection so you can
    toggle/move them as one."""
    bl_idname = "surreal_arch.lighting_rig"
    bl_label = "💡 Auto Lighting Rig"
    bl_options = {'REGISTER', 'UNDO'}

    palette: bpy.props.EnumProperty(
        name="Palette",
        items=[
            ('WARM',    "🔥 Warm",    "Torchlight (1.0, 0.78, 0.55) — castles & villages"),
            ('COLD',    "❄ Cold",    "Moonlight (0.55, 0.75, 1.0) — night scenes"),
            ('GOTHIC',  "🦇 Gothic",  "Dim red (0.8, 0.4, 0.3) — crypts & ruins"),
            ('NEON',    "💜 Neon",    "Vaporwave (1.0, 0.3, 0.85) — cyberpunk"),
            ('NATURAL', "☀ Natural", "Daylight (1.0, 0.95, 0.85) — bright outdoor"),
        ],
        default='WARM', update=auto_update_callback)
    count: bpy.props.IntProperty(name="Light Count", default=6, min=1, max=20, update=auto_update_callback)
    height_factor: bpy.props.FloatProperty(
        name="Height Factor",
        description="Where the corner lights sit (0 = floor, 1 = top of bbox)",
        default=0.7, min=0.0, max=1.5, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'palette')
        layout.prop(self, 'count')
        layout.prop(self, 'height_factor')

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh target first")
            return {'CANCELLED'}
        spawned, msg = _spawn_lighting_rig(
            context, obj, palette=self.palette, count=self.count,
            height_factor=self.height_factor)
        if spawned is None:
            self.report({'WARNING'}, msg)
            return {'CANCELLED'}
        self.report({'INFO'}, msg)
        return {'FINISHED'}


# ─── 🪞 POLISH ALL — global bevel + auto-smooth pass ───────────────

class SURREAL_ARCH_OT_polish_all(bpy.types.Operator):
    """Add a consistent SurrealArch_Bevel modifier + smooth shading to every
    selected mesh. Use this on Layer 2 composed worlds for a cohesive AAA
    rounded-edge look across all pieces."""
    bl_idname = "surreal_arch.polish_all"
    bl_label = "🪞 Polish Selected (cohesive bevel)"
    bl_options = {'REGISTER', 'UNDO'}

    bevel_width: bpy.props.FloatProperty(
        name="Bevel Width", default=0.04, min=0.0, max=0.3, update=auto_update_callback)
    bevel_segments: bpy.props.IntProperty(
        name="Segments", default=3, min=1, max=8, update=auto_update_callback)
    bevel_angle: bpy.props.FloatProperty(
        name="Angle (deg)", default=35.0, min=10.0, max=80.0, update=auto_update_callback)
    apply_modifier: bpy.props.BoolProperty(
        name="Apply (bake) Modifier",
        description="If on, the bevel modifier is applied destructively",
        default=False, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'bevel_width')
        layout.prop(self, 'bevel_segments')
        layout.prop(self, 'bevel_angle')
        layout.prop(self, 'apply_modifier')
        n = sum(1 for o in context.selected_objects if o.type == 'MESH')
        layout.label(text=f"Will polish {n} mesh(es).", icon='INFO')

    def execute(self, context):
        polished = 0
        for obj in context.selected_objects:
            if obj.type != 'MESH': continue
            # Remove old polish modifier
            for m in list(obj.modifiers):
                if m.name in ("SurrealArch_PolishBevel", "SurrealArch_Bevel"):
                    obj.modifiers.remove(m)
            # Add bevel modifier
            bv = obj.modifiers.new(name="SurrealArch_PolishBevel", type='BEVEL')
            bv.affect = 'EDGES'
            bv.limit_method = 'ANGLE'
            bv.angle_limit = math.radians(self.bevel_angle)
            bv.width = self.bevel_width
            bv.segments = self.bevel_segments
            bv.profile = 0.5
            bv.profile_type = 'SUPERELLIPSE'
            bv.miter_outer = 'MITER_SHARP'
            bv.use_clamp_overlap = True
            bv.loop_slide = True
            bv.harden_normals = True
            # Smooth shading + auto-smooth
            for p in obj.data.polygons:
                p.use_smooth = True
            obj.data.update()
            try:
                obj.data.use_auto_smooth = True
                obj.data.auto_smooth_angle = math.radians(self.bevel_angle)
            except (AttributeError, TypeError): pass
            # Optionally apply
            if self.apply_modifier:
                try:
                    bpy.context.view_layer.objects.active = obj
                    bpy.ops.object.modifier_apply(modifier=bv.name)
                except Exception: pass
            polished += 1
        self.report({'INFO'}, f"🪞 Polished {polished} mesh(es)")
        return {'FINISHED'}


# ─── PANEL ─────────────────────────────────────────────────────────

# ══════════════════════════════════════════════════════════════════════
# LAYER 3 EXTENSIONS — EasyTree integration + Komikaze shader linking
# + Walkable / hollow building post-processing (v2.29 polish)
# ══════════════════════════════════════════════════════════════════════

_KOMIKAZE_BLEND_PATH = (
    r"G:\programs\BlenderPlugins\plugins\Komikaze v2 (UNZIP ME) vfxmed\Komikaze v2.blend"
)

# Curated list of Komikaze materials that pair well with SurrealArch pieces.
# Each tuple: (display_name, komikaze_material_name)
_KOMIKAZE_PALETTE = [
    ('STONE_BASIC',   "Wood"),                       # nice carved-stone vibe
    ('TREE_LEAVES',   "Tree Shader *"),
    ('WATER_BASIC',   "Water (Basic)"),
    ('WATER_ADV',     "Water (Advance)"),
    ('VORONOI_FLAT',  "Voronoi Shader (Flat)"),
    ('VORONOI_3TONE', "Voronoi Shader (3 Tones)"),
    ('WIREFRAME',     "Wireframe"),
    ('WALL',          "The Wall (Custom Texture)"),
]


def _komikaze_link(material_name, link=True):
    """Append (or link) a single material from Komikaze v2.blend.
    Returns the material if loaded successfully (or None)."""
    import os
    if not os.path.exists(_KOMIKAZE_BLEND_PATH):
        return None
    # Check if already loaded
    existing = bpy.data.materials.get(material_name)
    if existing:
        return existing
    try:
        with bpy.data.libraries.load(_KOMIKAZE_BLEND_PATH, link=link) as (data_from, data_to):
            if material_name in data_from.materials:
                data_to.materials = [material_name]
            else:
                return None
        return bpy.data.materials.get(material_name)
    except Exception as e:
        print(f"[SurrealArch] Komikaze link failed for '{material_name}': {e}")
        return None


# Auto-mapping from SurrealArch material_choice → Komikaze material name.
# Selected to pair stylistically: stone → wood (warm bark texture), marble
# → Voronoi flat (clean cell pattern), etc.
_KOMIKAZE_AUTO_MAP = {
    'STONE':       'Wood',
    'MARBLE':      'Voronoi Shader (Flat)',
    'WATER':       'Water (Advance)',
    'STAINED':     'Voronoi Shader (3 Tones)',
    'IRIDESCENT':  'Tree Shader *',
    'GOLD':        'Wood',  # warm metallic via wood grain stand-in
    'CLEF_GLOW':   'Wireframe',
    'GOTHIC_DARK': 'The Wall (Custom Texture)',
    'GENSHIN':     'Tree Shader *',
    'AUTO':        'Wood',
}


class SURREAL_ARCH_OT_komikaze_auto_map(bpy.types.Operator):
    """Auto-apply a Komikaze material chosen to match the active object's
    `material_choice` setting. One click → coherent material across selection."""
    bl_idname = "surreal_arch.komikaze_auto_map"
    bl_label = "🎨 Auto-Map Komikaze (by material_choice)"
    bl_options = {'REGISTER', 'UNDO'}

    apply_to_all_selected: bpy.props.BoolProperty(
        name="Apply to all selected", default=True,
        description="Apply to every selected mesh (otherwise active only)", update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        obj = context.active_object
        if obj and hasattr(obj, 'surreal_arch_props'):
            mc = obj.surreal_arch_props.material_choice
            mapped = _KOMIKAZE_AUTO_MAP.get(mc, 'Wood')
            layout.label(text=f"Active material_choice: {mc}", icon='MATERIAL')
            layout.label(text=f"→ Will apply: '{mapped}'", icon='FORWARD')
        layout.prop(self, 'apply_to_all_selected')

    def execute(self, context):
        obj = context.active_object
        if obj is None or not hasattr(obj, 'surreal_arch_props'):
            self.report({'WARNING'}, "Select a mesh with surreal_arch_props")
            return {'CANCELLED'}
        mc = obj.surreal_arch_props.material_choice
        mat_name = _KOMIKAZE_AUTO_MAP.get(mc, 'Wood')
        mat = _komikaze_link(mat_name, link=False)
        if mat is None:
            self.report({'WARNING'},
                        f"Couldn't load Komikaze material '{mat_name}'")
            return {'CANCELLED'}
        targets = (context.selected_objects if self.apply_to_all_selected
                   else [obj])
        n = 0
        for o in targets:
            if o.type != 'MESH': continue
            if o.data.materials:
                o.data.materials[0] = mat
            else:
                o.data.materials.append(mat)
            n += 1
        self.report({'INFO'},
                    f"🎨 Komikaze '{mat_name}' ({mc} → auto-mapped) applied to {n} mesh(es)")
        return {'FINISHED'}


class SURREAL_ARCH_OT_komikaze_apply(bpy.types.Operator):
    """Append a curated Komikaze shader and assign it to all selected mesh
    objects. Falls back gracefully if Komikaze v2.blend isn't found at the
    expected path."""
    bl_idname = "surreal_arch.komikaze_apply"
    bl_label = "🎨 Apply Komikaze Material"
    bl_options = {'REGISTER', 'UNDO'}

    palette_key: bpy.props.EnumProperty(
        name="Material",
        items=[(k, k.replace('_', ' ').title(), n) for k, n in _KOMIKAZE_PALETTE],
        default='STONE_BASIC', update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        layout.prop(self, 'palette_key')
        import os
        if os.path.exists(_KOMIKAZE_BLEND_PATH):
            layout.label(text="✅ Komikaze v2.blend located", icon='CHECKMARK')
        else:
            layout.alert = True
            layout.label(text="⚠ Komikaze v2.blend not found at expected path", icon='ERROR')

    def execute(self, context):
        mat_name = dict(_KOMIKAZE_PALETTE).get(self.palette_key)
        if mat_name is None:
            return {'CANCELLED'}
        mat = _komikaze_link(mat_name, link=False)
        if mat is None:
            self.report({'WARNING'},
                        f"Couldn't load Komikaze material '{mat_name}' "
                        f"(file path: {_KOMIKAZE_BLEND_PATH})")
            return {'CANCELLED'}
        # Assign to every selected mesh — replace material slot 0
        n_applied = 0
        for o in context.selected_objects:
            if o.type != 'MESH': continue
            if o.data.materials:
                o.data.materials[0] = mat
            else:
                o.data.materials.append(mat)
            n_applied += 1
        self.report({'INFO'}, f"🎨 Komikaze '{mat_name}' applied to {n_applied} mesh(es)")
        return {'FINISHED'}


# ─── EasyTree-powered vegetation ──────────────────────────────────────

def _easytree_available():
    """Probe whether the EasyTree addon is enabled."""
    try:
        return hasattr(bpy.types, 'EASYTREE_PT_geo_nodes_panel') and \
               hasattr(bpy.ops.object, 'add_tree_tool')
    except Exception:
        return False


class SURREAL_ARCH_OT_scatter_easytrees(bpy.types.Operator):
    """Scatter N EasyTree trees across the active mesh's surface. Each tree
    is a real EasyTree spawn (not a duplicate) so seasons/presets vary per call.
    Trees go into a `SurrealArch_Vegetation` collection."""
    bl_idname = "surreal_arch.scatter_easytrees"
    bl_label = "🌲 Scatter EasyTrees"
    bl_options = {'REGISTER', 'UNDO'}

    n: bpy.props.IntProperty(name="Tree Count", default=12, min=1, max=80, update=auto_update_callback)
    preset: bpy.props.EnumProperty(
        name="Preset",
        items=[
            ('MIXED',  "Mixed",  "Random preset per tree"),
            ('SMALL',  "Small",  "All small trees"),
            ('TALL',   "Tall",   "All tall trees"),
            ('THIN',   "Thin",   "All thin trees"),
            ('LARGE',  "Large",  "All large trees"),
            ('DEAD',   "Dead",   "All dead trees"),
        ],
        default='MIXED', update=auto_update_callback)
    season: bpy.props.EnumProperty(
        name="Season",
        items=[
            ('SPRING', "Spring", "Spring foliage"),
            ('SUMMER', "Summer", "Summer foliage"),
            ('FALL',   "Fall",   "Fall foliage"),
        ],
        default='SUMMER', update=auto_update_callback)
    scale_min: bpy.props.FloatProperty(name="Min Scale", default=0.6, min=0.1, max=4.0, update=auto_update_callback)
    scale_max: bpy.props.FloatProperty(name="Max Scale", default=1.4, min=0.1, max=4.0, update=auto_update_callback)
    z_offset: bpy.props.FloatProperty(name="Z Offset", default=0.0, min=-5.0, max=5.0,
        description="Lift/lower trees relative to scatter surface", update=auto_update_callback)
    border_only: bpy.props.BoolProperty(
        name="Border Only",
        description="Scatter only along the surface's perimeter (not interior)",
        default=False, update=auto_update_callback)
    forest_vgroup: bpy.props.StringProperty(
        name="Forest Vertex Group",
        description="If set, only scatter on faces whose vertices belong to this "
                    "vertex group (paint 'is_forest' on terrain to cluster trees)",
        default="", update=auto_update_callback)
    seed: bpy.props.IntProperty(name="Seed", default=42, min=0, max=99999, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        if not _easytree_available():
            layout.alert = True
            layout.label(text="⚠ EasyTree addon not detected", icon='ERROR')
            layout.label(text="Enable 'Easy Tree' in Preferences → Add-ons")
        col = layout.column(align=True)
        col.prop(self, 'n')
        row = col.row(align=True)
        row.prop(self, 'preset')
        row.prop(self, 'season')
        row2 = col.row(align=True)
        row2.prop(self, 'scale_min'); row2.prop(self, 'scale_max')
        col.prop(self, 'z_offset')
        col.prop(self, 'border_only')
        col.prop_search(self, 'forest_vgroup',
                          context.active_object, 'vertex_groups',
                          text="Forest VG")
        col.prop(self, 'seed')

    def execute(self, context):
        if not _easytree_available():
            self.report({'ERROR'}, "EasyTree addon not enabled — install/enable it first")
            return {'CANCELLED'}
        target = context.active_object
        if target is None or target.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh to scatter on")
            return {'CANCELLED'}
        import random, bmesh, math
        from mathutils import Vector
        rng = random.Random(self.seed)
        # Build scatter points from face centers + jitter
        deps = bpy.context.evaluated_depsgraph_get()
        ev = target.evaluated_get(deps)
        me = ev.to_mesh()
        if me is None or len(me.polygons) == 0:
            if me is not None: ev.to_mesh_clear()
            self.report({'WARNING'}, "Target mesh has no faces")
            return {'CANCELLED'}
        mat = target.matrix_world
        # Build a vertex-group filter (if requested): a face passes only if
        # AT LEAST one of its vertices is in the named vertex group with w > 0.5.
        # The vertex group lives on the ORIGINAL (not evaluated) target.
        vg_name = (self.forest_vgroup or "").strip()
        vg_filter_set = None
        if vg_name:
            vg = target.vertex_groups.get(vg_name)
            if vg is None:
                self.report({'WARNING'},
                            f"Vertex group '{vg_name}' not found on {target.name} — scattering everywhere")
            else:
                vg_filter_set = set()
                for v in target.data.vertices:
                    for g in v.groups:
                        if g.group == vg.index and g.weight > 0.5:
                            vg_filter_set.add(v.index)
                            break
        # Build face center list, optionally gated by vg
        face_centers = []
        for p in me.polygons:
            if vg_filter_set is not None:
                if not any(vi in vg_filter_set for vi in p.vertices):
                    continue
            face_centers.append((mat @ Vector(p.center), p.area))
        ev.to_mesh_clear()
        if vg_filter_set is not None and not face_centers:
            self.report({'WARNING'},
                        f"No faces matched '{vg_name}' — paint that vgroup on at least one face")
            return {'CANCELLED'}
        if self.border_only:
            # Approximate border filter: keep faces whose center is in the
            # outer 30% of the bbox radius
            xs = [c.x for c, _ in face_centers]; ys = [c.y for c, _ in face_centers]
            cx = (min(xs) + max(xs)) / 2; cy = (min(ys) + max(ys)) / 2
            rmax = max(max(xs) - cx, max(ys) - cy)
            face_centers = [(c, a) for c, a in face_centers
                            if math.hypot(c.x - cx, c.y - cy) > rmax * 0.7]
        if not face_centers:
            self.report({'WARNING'}, "No faces matched filter")
            return {'CANCELLED'}
        # Weight by face area + sample N
        total_area = sum(a for _, a in face_centers)
        # Vegetation collection
        veg_name = "SurrealArch_Vegetation"
        coll = bpy.data.collections.get(veg_name)
        if coll is None:
            coll = bpy.data.collections.new(veg_name)
            context.scene.collection.children.link(coll)
        # Stash original scene props so we can restore
        sc = context.scene
        prev_preset = getattr(sc, 'tree_preset', 'SMALL')
        prev_season = getattr(sc, 'season', 'SPRING')
        try:
            sc.season = self.season
        except Exception: pass
        n_spawned = 0
        preset_choices = ('SMALL', 'TALL', 'THIN', 'LARGE', 'DEAD')
        for i in range(self.n):
            # Pick a face by area-weighted random
            r = rng.random() * total_area
            cum = 0.0
            chosen = face_centers[0][0]
            for c, a in face_centers:
                cum += a
                if cum >= r:
                    chosen = c; break
            # Jitter within face area's typical radius
            jitter = math.sqrt(max(0.1, a)) * 0.3
            x = chosen.x + rng.uniform(-jitter, jitter)
            y = chosen.y + rng.uniform(-jitter, jitter)
            z = chosen.z + self.z_offset
            sc.cursor.location = (x, y, z)
            # Set preset
            preset = (rng.choice(preset_choices) if self.preset == 'MIXED'
                      else self.preset)
            try:
                sc.tree_preset = preset
            except Exception: pass
            # Snapshot — find what objects get created
            pre = set(o.name for o in bpy.data.objects)
            try:
                bpy.ops.object.add_tree_tool()
            except Exception as e:
                print(f"[SurrealArch] EasyTree spawn failed: {e}")
                continue
            new_objs = [bpy.data.objects[n] for n in (set(o.name for o in bpy.data.objects) - pre)]
            for new_obj in new_objs:
                # Apply random scale within range
                s = rng.uniform(self.scale_min, self.scale_max)
                new_obj.scale = (s, s, s)
                # Move from default scene collection into our vegetation coll
                for c in list(new_obj.users_collection):
                    c.objects.unlink(new_obj)
                coll.objects.link(new_obj)
                # Tag back-reference
                new_obj["surreal_scattered_on"] = target.name
                n_spawned += 1
        # Restore prior session prefs
        try:
            sc.tree_preset = prev_preset
            sc.season = prev_season
        except Exception: pass
        self.report({'INFO'}, f"🌲 Scattered {n_spawned} EasyTrees onto {target.name}")
        return {'FINISHED'}


# ─── Hollow / Walkable building post-processor ───────────────────────

def _hollow_building_object(obj, wall_thickness=0.2, door_width=1.0,
                              door_height=2.0, keep_solid_below=0.05,
                              storey_height=0.0, stairwell_width=0.0,
                              window_grid_x=0, window_grid_per_storey=0,
                              window_width=0.7, window_height=1.1):
    """Convert a solid (closed) building mesh into a hollow shell with a door
    cutout on its front face. Uses bmesh boolean to subtract an interior box +
    a door portal.

    NEW v2.32:
      • If `storey_height > 0`, also adds thin floor planes inside at each
        storey level (1×storey_height, 2×storey_height, ...) up to ceiling.
      • If `stairwell_width > 0`, each floor gets a square hole at the back
        corner so the player can ascend through the stairwell column.

    This is intentionally a heavy operation — it APPLIES all modifiers first.
    """
    import bmesh
    from mathutils import Vector, Matrix
    # Apply modifiers so we work with the baked mesh
    bpy.context.view_layer.objects.active = obj
    for mod in list(obj.modifiers):
        try:
            bpy.ops.object.modifier_apply(modifier=mod.name)
        except Exception:
            pass
    me = obj.data
    if len(me.vertices) == 0:
        return False
    # Compute local bbox
    xs = [v.co.x for v in me.vertices]
    ys = [v.co.y for v in me.vertices]
    zs = [v.co.z for v in me.vertices]
    bbox_min = Vector((min(xs), min(ys), min(zs)))
    bbox_max = Vector((max(xs), max(ys), max(zs)))
    size = bbox_max - bbox_min
    # Skip very thin / tiny pieces (towers and such — the hollow op would just blow them up)
    if min(size.x, size.y) < wall_thickness * 4 or size.z < door_height + 0.4:
        return False
    # Build an interior subtraction cube (slightly smaller)
    bm_int = bmesh.new()
    bmesh.ops.create_cube(bm_int, size=1.0)
    # Scale to interior dimensions
    sx = max(0.1, size.x - wall_thickness * 2)
    sy = max(0.1, size.y - wall_thickness * 2)
    sz = max(0.1, size.z - wall_thickness * 2)
    bmesh.ops.scale(bm_int, vec=Vector((sx, sy, sz)),
                    verts=bm_int.verts)
    # Position the interior cube — but lift it `keep_solid_below` from the
    # floor so we don't blow through the ground plane
    cx = (bbox_min.x + bbox_max.x) / 2
    cy = (bbox_min.y + bbox_max.y) / 2
    cz_min = bbox_min.z + wall_thickness + keep_solid_below
    cz_max = bbox_max.z - wall_thickness
    cz = (cz_min + cz_max) / 2
    bmesh.ops.translate(bm_int, vec=Vector((cx, cy, cz)),
                        verts=bm_int.verts)
    # Convert interior bmesh → temp mesh + object so we can boolean it
    me_int = bpy.data.meshes.new("__hollow_int__")
    bm_int.to_mesh(me_int)
    bm_int.free()
    obj_int = bpy.data.objects.new("__hollow_int__", me_int)
    bpy.context.scene.collection.objects.link(obj_int)
    obj_int.parent = obj
    obj_int.matrix_parent_inverse = obj.matrix_world.inverted()
    # Boolean — subtract interior
    bool_mod = obj.modifiers.new("__SAhollow", 'BOOLEAN')
    bool_mod.operation = 'DIFFERENCE'
    bool_mod.solver = 'EXACT' if hasattr(bool_mod, 'solver') else 'FAST'
    bool_mod.object = obj_int
    try:
        bpy.ops.object.modifier_apply(modifier=bool_mod.name)
    except Exception as e:
        print(f"[SurrealArch] interior boolean failed: {e}")
        try: obj.modifiers.remove(bool_mod)
        except Exception: pass
    # Cut an ARCHED door on the -Y face (front) — v2.33: half-cylinder top
    # over a rectangular bottom for a proper Romanesque arch silhouette.
    bm_door = bmesh.new()
    # Rectangular bottom: rises from floor to (door_height - door_width/2)
    rect_h = max(0.4, door_height - door_width / 2)
    bmesh.ops.create_cube(bm_door, size=1.0)
    bmesh.ops.scale(bm_door,
                    vec=Vector((door_width, wall_thickness * 3.0, rect_h)),
                    verts=bm_door.verts)
    bmesh.ops.translate(bm_door,
                        vec=Vector((0, 0, rect_h / 2)),
                        verts=bm_door.verts)
    # Semi-cylinder cap on top — full cylinder, oriented along Y
    arch_verts_before = set(v for v in bm_door.verts)
    bmesh.ops.create_cone(bm_door, cap_ends=True, cap_tris=False,
                          segments=24,
                          radius1=door_width / 2, radius2=door_width / 2,
                          depth=wall_thickness * 3.0)
    # Identify the just-added cylinder verts
    cyl_verts = [v for v in bm_door.verts if v not in arch_verts_before]
    # Rotate the cylinder so its axis is Y (currently Z)
    import math
    rot = __import__('mathutils').Matrix.Rotation(math.pi / 2, 4, 'X')
    bmesh.ops.transform(bm_door, matrix=rot, verts=cyl_verts)
    # Translate the cylinder cap up to sit on top of the rectangle
    bmesh.ops.translate(bm_door, vec=Vector((0, 0, rect_h)), verts=cyl_verts)
    # Now the whole "door cutter" is centered at origin XY-wise, base at z=0.
    # Translate the whole bmesh into the building's door position
    bmesh.ops.translate(bm_door,
                        vec=Vector((cx, bbox_min.y + wall_thickness * 0.5,
                                    bbox_min.z)),
                        verts=bm_door.verts)
    # Cleanup duplicate verts where rectangle meets semi-circle
    bmesh.ops.remove_doubles(bm_door, verts=bm_door.verts, dist=0.001)
    me_door = bpy.data.meshes.new("__hollow_door__")
    bm_door.to_mesh(me_door)
    bm_door.free()
    obj_door = bpy.data.objects.new("__hollow_door__", me_door)
    bpy.context.scene.collection.objects.link(obj_door)
    obj_door.parent = obj
    obj_door.matrix_parent_inverse = obj.matrix_world.inverted()
    door_mod = obj.modifiers.new("__SAdoor", 'BOOLEAN')
    door_mod.operation = 'DIFFERENCE'
    door_mod.solver = 'EXACT' if hasattr(door_mod, 'solver') else 'FAST'
    door_mod.object = obj_door
    try:
        bpy.ops.object.modifier_apply(modifier=door_mod.name)
    except Exception as e:
        print(f"[SurrealArch] door boolean failed: {e}")
    # Cleanup helpers
    for helper in (obj_int, obj_door):
        try:
            bpy.data.objects.remove(helper, do_unlink=True)
        except Exception:
            pass

    # ── v2.32: Multi-storey interior floor planes ──────────────────────
    if storey_height > 0.5:
        floor_thk = 0.05
        # Floor planes at storey_height, 2*storey_height, ... up to ceiling
        n_floors = max(1, int((size.z - storey_height) // storey_height))
        floor_meshes = []
        for f_i in range(1, n_floors + 1):
            z = bbox_min.z + f_i * storey_height
            if z >= bbox_max.z - wall_thickness - 0.1: break
            # Build a floor plane = thin cube spanning interior
            bm_f = bmesh.new()
            bmesh.ops.create_cube(bm_f, size=1.0)
            inset = wall_thickness * 1.05  # tiny overlap into walls for welding
            bmesh.ops.scale(bm_f,
                            vec=Vector((sx + inset, sy + inset, floor_thk)),
                            verts=bm_f.verts)
            bmesh.ops.translate(bm_f, vec=Vector((cx, cy, z)),
                                verts=bm_f.verts)
            # Optional stairwell hole
            if stairwell_width > 0.1:
                # Back-right interior corner
                hole_cx = bbox_max.x - wall_thickness * 1.5 - stairwell_width / 2
                hole_cy = bbox_max.y - wall_thickness * 1.5 - stairwell_width / 2
                # Cut a hole into this floor by removing matching faces
                # Easiest: use a boolean — build hole cube, subtract from floor
                bm_h = bmesh.new()
                bmesh.ops.create_cube(bm_h, size=1.0)
                bmesh.ops.scale(bm_h,
                                vec=Vector((stairwell_width, stairwell_width, floor_thk * 4)),
                                verts=bm_h.verts)
                bmesh.ops.translate(bm_h,
                                    vec=Vector((hole_cx, hole_cy, z)),
                                    verts=bm_h.verts)
                # Convert hole to mesh + boolean against floor
                me_h = bpy.data.meshes.new(f"__hole_{f_i}__")
                bm_h.to_mesh(me_h); bm_h.free()
                obj_h = bpy.data.objects.new(f"__hole_{f_i}__", me_h)
                bpy.context.scene.collection.objects.link(obj_h)
                me_f = bpy.data.meshes.new(f"__floor_{f_i}__")
                bm_f.to_mesh(me_f); bm_f.free()
                obj_f = bpy.data.objects.new(f"__floor_{f_i}__", me_f)
                bpy.context.scene.collection.objects.link(obj_f)
                bool_h = obj_f.modifiers.new("__hole", 'BOOLEAN')
                bool_h.operation = 'DIFFERENCE'
                bool_h.solver = 'EXACT' if hasattr(bool_h, 'solver') else 'FAST'
                bool_h.object = obj_h
                bpy.context.view_layer.objects.active = obj_f
                try:
                    bpy.ops.object.modifier_apply(modifier="__hole")
                except Exception: pass
                floor_meshes.append(obj_f)
                try: bpy.data.objects.remove(obj_h, do_unlink=True)
                except Exception: pass
            else:
                me_f = bpy.data.meshes.new(f"__floor_{f_i}__")
                bm_f.to_mesh(me_f); bm_f.free()
                obj_f = bpy.data.objects.new(f"__floor_{f_i}__", me_f)
                bpy.context.scene.collection.objects.link(obj_f)
                floor_meshes.append(obj_f)
        # Join all floors INTO the hollow shell
        if floor_meshes:
            bpy.ops.object.select_all(action='DESELECT')
            obj.select_set(True)
            for f in floor_meshes:
                f.select_set(True)
            bpy.context.view_layer.objects.active = obj
            try:
                bpy.ops.object.join()
            except Exception as e:
                print(f"[SurrealArch] floor-join failed: {e}")
                for f in floor_meshes:
                    try: bpy.data.objects.remove(f, do_unlink=True)
                    except Exception: pass

        # v2.34: Cut windows along the four walls per storey
        # v2.35: Also collect window centers so we can place sills + glass
        window_specs = []   # list of (lateral_axis, face_axis_pos, lateral_pos, row_z, size_x, size_y)
        if window_grid_x >= 1 and window_grid_per_storey >= 1:
            try:
                from mathutils import Vector
                window_cutters = []
                # Compute number of storeys to give windows to
                n_storeys_w = max(1, int((size.z - storey_height * 0.3) // storey_height))
                # For each storey, cut N windows on each of the 4 walls
                for storey_i in range(n_storeys_w):
                    storey_z = bbox_min.z + storey_i * storey_height
                    for row_i in range(window_grid_per_storey):
                        row_z = storey_z + storey_height * 0.4 + \
                                row_i * (storey_height * 0.4 / max(1, window_grid_per_storey))
                        # 4 walls: -Y, +Y, -X, +X
                        wall_configs = [
                            # (face_y, axis_xy, axis_inset, n_along)
                            (bbox_min.y + wall_thickness * 0.5, 'X', cx, window_grid_x),
                            (bbox_max.y - wall_thickness * 0.5, 'X', cx, window_grid_x),
                            (bbox_min.x + wall_thickness * 0.5, 'Y', cy, window_grid_x),
                            (bbox_max.x - wall_thickness * 0.5, 'Y', cy, window_grid_x),
                        ]
                        for face_axis_pos, lateral_axis, lateral_center, n_along in wall_configs:
                            # Skip the front face for the storey with the door
                            if storey_i == 0 and face_axis_pos == wall_configs[0][0]:
                                # leave door area open
                                pass
                            # Compute window positions along this wall
                            wall_span = (size.x if lateral_axis == 'X' else size.y) - wall_thickness * 2
                            spacing = wall_span / max(1, n_along)
                            for col_i in range(n_along):
                                lateral_pos = (lateral_center - wall_span / 2
                                               + spacing * (col_i + 0.5))
                                bm_w = bmesh.new()
                                bmesh.ops.create_cube(bm_w, size=1.0)
                                # Window cutter dimensions: small along the wall plane,
                                # wall_thickness * 3 perpendicular
                                if lateral_axis == 'X':
                                    sz_x = window_width
                                    sz_y = wall_thickness * 3.0
                                else:
                                    sz_x = wall_thickness * 3.0
                                    sz_y = window_width
                                bmesh.ops.scale(bm_w,
                                                vec=Vector((sz_x, sz_y, window_height)),
                                                verts=bm_w.verts)
                                if lateral_axis == 'X':
                                    pos = Vector((lateral_pos, face_axis_pos, row_z + window_height / 2 + 0.5))
                                else:
                                    pos = Vector((face_axis_pos, lateral_pos, row_z + window_height / 2 + 0.5))
                                bmesh.ops.translate(bm_w, vec=pos, verts=bm_w.verts)
                                me_w = bpy.data.meshes.new("__win__")
                                bm_w.to_mesh(me_w); bm_w.free()
                                obj_w = bpy.data.objects.new("__win__", me_w)
                                bpy.context.scene.collection.objects.link(obj_w)
                                window_cutters.append(obj_w)
                                # Remember spec for sill + glass below
                                window_specs.append((lateral_axis, face_axis_pos,
                                                     lateral_pos, row_z,
                                                     sz_x, sz_y))
                # Single boolean per cutter — could be slow with many; OK for now
                bpy.context.view_layer.objects.active = obj
                for w_obj in window_cutters:
                    mod_w = obj.modifiers.new("__SAwin", 'BOOLEAN')
                    mod_w.operation = 'DIFFERENCE'
                    mod_w.solver = 'EXACT' if hasattr(mod_w, 'solver') else 'FAST'
                    mod_w.object = w_obj
                    try:
                        bpy.ops.object.modifier_apply(modifier=mod_w.name)
                    except Exception:
                        try: obj.modifiers.remove(mod_w)
                        except Exception: pass
                # Cleanup window cutters
                for w_obj in window_cutters:
                    try: bpy.data.objects.remove(w_obj, do_unlink=True)
                    except Exception: pass
            except Exception as e:
                print(f"[SurrealArch] window cuts failed: {e}")

            # v2.35: Add sills + glass for each window cut
            if window_specs:
                try:
                    from mathutils import Vector
                    sill_objs = []
                    glass_objs = []
                    for (lat_axis, face_pos, lat_pos, row_z, sz_x, sz_y) in window_specs:
                        win_h = window_height
                        # SILL — thin slab BELOW the window opening
                        sill = bmesh.new()
                        bmesh.ops.create_cube(sill, size=1.0)
                        if lat_axis == 'X':
                            sill_sx = window_width * 1.18
                            sill_sy = wall_thickness * 1.5
                        else:
                            sill_sx = wall_thickness * 1.5
                            sill_sy = window_width * 1.18
                        bmesh.ops.scale(sill,
                                        vec=Vector((sill_sx, sill_sy, 0.08)),
                                        verts=sill.verts)
                        if lat_axis == 'X':
                            sill_pos = Vector((lat_pos, face_pos,
                                                row_z + 0.5 - 0.04))
                        else:
                            sill_pos = Vector((face_pos, lat_pos,
                                                row_z + 0.5 - 0.04))
                        bmesh.ops.translate(sill, vec=sill_pos, verts=sill.verts)
                        me_sill = bpy.data.meshes.new("__sill__")
                        sill.to_mesh(me_sill); sill.free()
                        sill_obj = bpy.data.objects.new("__sill__", me_sill)
                        bpy.context.scene.collection.objects.link(sill_obj)
                        sill_objs.append(sill_obj)
                        # GLASS — thin plane filling the window opening
                        glass = bmesh.new()
                        bmesh.ops.create_cube(glass, size=1.0)
                        if lat_axis == 'X':
                            g_sx = window_width * 0.92
                            g_sy = 0.02
                        else:
                            g_sx = 0.02
                            g_sy = window_width * 0.92
                        bmesh.ops.scale(glass,
                                        vec=Vector((g_sx, g_sy, win_h * 0.92)),
                                        verts=glass.verts)
                        if lat_axis == 'X':
                            g_pos = Vector((lat_pos, face_pos,
                                             row_z + win_h / 2 + 0.5))
                        else:
                            g_pos = Vector((face_pos, lat_pos,
                                             row_z + win_h / 2 + 0.5))
                        bmesh.ops.translate(glass, vec=g_pos, verts=glass.verts)
                        me_g = bpy.data.meshes.new("__glass__")
                        glass.to_mesh(me_g); glass.free()
                        g_obj = bpy.data.objects.new("__glass__", me_g)
                        bpy.context.scene.collection.objects.link(g_obj)
                        glass_objs.append(g_obj)
                    # Join sills INTO the building (they become wall details)
                    bpy.ops.object.select_all(action='DESELECT')
                    obj.select_set(True)
                    for s in sill_objs: s.select_set(True)
                    bpy.context.view_layer.objects.active = obj
                    try: bpy.ops.object.join()
                    except Exception: pass
                    # Join glass into ONE separate object (different material slot ideal)
                    if glass_objs:
                        bpy.ops.object.select_all(action='DESELECT')
                        for g in glass_objs: g.select_set(True)
                        bpy.context.view_layer.objects.active = glass_objs[0]
                        try:
                            bpy.ops.object.join()
                            joined_glass = bpy.context.active_object
                            joined_glass.name = f"{obj.name}_Glass"
                            joined_glass.parent = obj
                            joined_glass.matrix_parent_inverse = obj.matrix_world.inverted()
                            # Tag for later material assignment
                            joined_glass["surreal_is_glass"] = True
                        except Exception as e:
                            print(f"[SurrealArch] glass join failed: {e}")
                            for g in glass_objs:
                                try: bpy.data.objects.remove(g, do_unlink=True)
                                except Exception: pass
                except Exception as e:
                    print(f"[SurrealArch] sill/glass spawn failed: {e}")

        # v2.33: Spawn a real spiral staircase inside the stairwell hole
        if stairwell_width > 0.1:
            try:
                stair_height = (bbox_max.z - bbox_min.z) - wall_thickness * 1.5
                stair_obj = _make_spiral_staircase_mesh(
                    f"{obj.name}_Stairs",
                    stairwell_size=stairwell_width,
                    total_height=stair_height,
                    storey_height=storey_height,
                    center_pole_radius=stairwell_width * 0.08,
                    step_thickness=0.08,
                )
                # Position at back-right interior corner (same as hole location)
                hole_cx = bbox_max.x - wall_thickness * 1.5 - stairwell_width / 2
                hole_cy = bbox_max.y - wall_thickness * 1.5 - stairwell_width / 2
                # Account for the building's world transform
                stair_obj.matrix_world = obj.matrix_world.copy()
                stair_obj.location = obj.matrix_world @ \
                    __import__('mathutils').Vector((hole_cx, hole_cy, bbox_min.z))
                # Join stairs into the building so we end with a single object
                bpy.ops.object.select_all(action='DESELECT')
                obj.select_set(True)
                stair_obj.select_set(True)
                bpy.context.view_layer.objects.active = obj
                bpy.ops.object.join()
            except Exception as e:
                print(f"[SurrealArch] spiral staircase failed: {e}")

    return True


class SURREAL_ARCH_OT_player_start(bpy.types.Operator):
    """Place a Player Start marker (Empty + Camera) at the front door of the
    active walkable building, looking inward. Optionally sets the camera as
    the scene camera so you can press F12 / Numpad-0 for an instant interior
    view."""
    bl_idname = "surreal_arch.player_start"
    bl_label = "🎮 Place Player Start (Door + Camera)"
    bl_options = {'REGISTER', 'UNDO'}

    set_active_camera: bpy.props.BoolProperty(
        name="Set as Scene Camera",
        description="Set the spawned camera as the active scene camera",
        default=True, update=auto_update_callback)
    eye_height: bpy.props.FloatProperty(
        name="Eye Height", default=1.65, min=0.5, max=3.0,
        description="Human-scale eye height for the placed camera", update=auto_update_callback)
    standoff: bpy.props.FloatProperty(
        name="Standoff", default=1.5, min=0.2, max=10.0,
        description="Distance in front of the door to place the camera", update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw(self, context):
        layout = self.layout
        col = layout.column(align=True)
        col.prop(self, 'eye_height')
        col.prop(self, 'standoff')
        col.prop(self, 'set_active_camera')

    def execute(self, context):
        from mathutils import Vector, Matrix
        import math
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a walkable building first")
            return {'CANCELLED'}
        # Compute world-bbox front-face center
        verts_world = [obj.matrix_world @ v.co for v in obj.data.vertices]
        if not verts_world:
            self.report({'WARNING'}, "Building has no geometry")
            return {'CANCELLED'}
        xs = [v.x for v in verts_world]; ys = [v.y for v in verts_world]
        zs = [v.z for v in verts_world]
        cx = (min(xs) + max(xs)) / 2
        front_y = min(ys)
        ground_z = min(zs)
        # Player start = a few meters in FRONT of the door (further along -Y)
        start_pos = Vector((cx, front_y - self.standoff, ground_z + self.eye_height))
        # Camera looks AT the door from the player start
        door_pos = Vector((cx, front_y, ground_z + self.eye_height))
        # Empty marker
        bpy.ops.object.empty_add(type='ARROWS', radius=0.4, location=start_pos)
        empty = context.active_object
        empty.name = f"{obj.name}_PlayerStart"
        # Camera
        bpy.ops.object.camera_add(location=start_pos)
        cam = context.active_object
        cam.name = f"{obj.name}_Camera"
        # Aim camera at door
        direction = door_pos - start_pos
        # Default cam faces -Z; rotate so -Z points at direction
        rot_quat = direction.to_track_quat('-Z', 'Y')
        cam.rotation_euler = rot_quat.to_euler()
        # Parent camera to the empty so the user can move both as one
        cam.parent = empty
        cam.matrix_parent_inverse = empty.matrix_world.inverted()
        # Set as scene camera
        if self.set_active_camera:
            context.scene.camera = cam
        # Tag back-reference
        empty["surreal_player_start_for"] = obj.name
        cam["surreal_player_start_for"] = obj.name
        self.report({'INFO'},
                    f"🎮 Player Start placed at door of {obj.name}"
                    + (" (set as scene camera)" if self.set_active_camera else ""))
        return {'FINISHED'}


class SURREAL_ARCH_OT_make_walkable(bpy.types.Operator):
    """Hollow out the selected building(s) — subtract an interior cavity and
    cut a door on the front face, so you can walk inside in first-person."""
    bl_idname = "surreal_arch.make_walkable"
    bl_label = "🚪 Make Walkable (Hollow + Door)"
    bl_options = {'REGISTER', 'UNDO'}

    wall_thickness: bpy.props.FloatProperty(name="Wall Thickness", default=0.25, min=0.05, max=2.0, update=auto_update_callback)
    door_width:     bpy.props.FloatProperty(name="Door Width",     default=1.2, min=0.4, max=4.0, update=auto_update_callback)
    door_height:    bpy.props.FloatProperty(name="Door Height",    default=2.4, min=1.5, max=5.0, update=auto_update_callback)
    storey_height:  bpy.props.FloatProperty(name="Storey Height",  default=0.0, min=0.0, max=8.0,
        description="If > 0, adds interior floor planes at each storey "
                    "(0 = no floors / one tall interior)", update=auto_update_callback)
    stairwell_width: bpy.props.FloatProperty(name="Stairwell Width", default=0.0, min=0.0, max=4.0,
        description="If > 0, each floor gets a square stairwell hole in the "
                    "back-right corner (0 = no holes)", update=auto_update_callback)
    window_grid_x: bpy.props.IntProperty(name="Windows per Wall", default=0, min=0, max=10,
        description="Number of windows along each wall (0 = no windows)", update=auto_update_callback)
    window_grid_per_storey: bpy.props.IntProperty(name="Window Rows / Storey", default=1, min=1, max=3,
        description="How many horizontal rows of windows per storey", update=auto_update_callback)
    window_width: bpy.props.FloatProperty(name="Window Width", default=0.7, min=0.1, max=4.0, update=auto_update_callback)
    window_height: bpy.props.FloatProperty(name="Window Height", default=1.1, min=0.2, max=4.0, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        col = layout.column(align=True)
        col.label(text="Shell", icon='HOME')
        col.prop(self, 'wall_thickness')
        col.prop(self, 'door_width')
        col.prop(self, 'door_height')
        col.separator()
        col.label(text="Interior storeys (optional)", icon='LAYER_ACTIVE')
        col.prop(self, 'storey_height')
        col.prop(self, 'stairwell_width')
        col.separator()
        col.label(text="Windows (optional)", icon='SEQ_PREVIEW')
        col.prop(self, 'window_grid_x')
        col.prop(self, 'window_grid_per_storey')
        row_w = col.row(align=True)
        row_w.prop(self, 'window_width'); row_w.prop(self, 'window_height')
        col.separator()
        col.label(text="Applies all modifiers, then booleans.", icon='INFO')
        col.label(text="Skips towers/thin pieces automatically.")

    def execute(self, context):
        targets = [o for o in context.selected_objects if o.type == 'MESH']
        if not targets:
            self.report({'WARNING'}, "Select one or more mesh buildings")
            return {'CANCELLED'}
        hollowed = 0
        skipped = 0
        for o in targets:
            bpy.ops.object.select_all(action='DESELECT')
            o.select_set(True)
            context.view_layer.objects.active = o
            try:
                if _hollow_building_object(
                        o,
                        wall_thickness=self.wall_thickness,
                        door_width=self.door_width,
                        door_height=self.door_height,
                        storey_height=self.storey_height,
                        stairwell_width=self.stairwell_width,
                        window_grid_x=self.window_grid_x,
                        window_grid_per_storey=self.window_grid_per_storey,
                        window_width=self.window_width,
                        window_height=self.window_height):
                    hollowed += 1
                else:
                    skipped += 1
            except Exception as e:
                self.report({'WARNING'}, f"{o.name}: {e}")
                skipped += 1
        self.report({'INFO'}, f"🚪 Hollowed {hollowed}, skipped {skipped} (too thin)")
        return {'FINISHED'}


class SURREAL_ARCH_PT_layer3(_SubPanelBase, bpy.types.Panel):
    bl_label  = "🌍 World Atmosphere (Layer 3)"
    bl_idname = "SURREAL_ARCH_PT_layer3"

    def draw(self, context):
        layout = self.layout
        layout.label(text="Layer 3 — bringing the world to life", icon='WORLD')

        # ① Terrain
        s1 = layout.box()
        s1.label(text="① Terrain", icon='MESH_PLANE')
        row = s1.row(align=True)
        row.scale_y = 1.25
        row.operator("surreal_arch.spawn_terrain", text="🌄 Spawn Terrain",
                     icon='MESH_GRID')

        # ② Vegetation
        s2 = layout.box()
        s2.label(text="② Vegetation / Scatter", icon='OUTLINER_OB_GREASEPENCIL')
        col = s2.column(align=True)
        col.scale_y = 1.2
        if _easytree_available():
            col.operator("surreal_arch.scatter_easytrees",
                         text="🌲 Scatter EasyTrees", icon='OUTLINER_OB_GREASEPENCIL')
            col.label(text="(uses installed Easy Tree addon)", icon='INFO')
        else:
            col.label(text="⚠ EasyTree not detected", icon='ERROR')
        col.separator()
        col.operator("surreal_arch.scatter_vegetation",
                     text="📚 Scatter Library Pieces", icon='SCULPTMODE_HLT')

        # ③ Lighting
        s3 = layout.box()
        s3.label(text="③ Lighting", icon='LIGHT')
        row = s3.row(align=True)
        row.scale_y = 1.25
        row.operator("surreal_arch.lighting_rig", text="💡 Auto Lighting Rig",
                     icon='OUTLINER_OB_LIGHT')

        # ④ Walkable buildings
        s4 = layout.box()
        s4.label(text="④ Walkable interiors", icon='HOME')
        s4.label(text="Hollows the selected buildings and cuts a front door.", icon='INFO')
        row = s4.row(align=True)
        row.scale_y = 1.25
        row.operator("surreal_arch.make_walkable",
                     text="🚪 Make Walkable", icon='OUTLINER_OB_GROUP_INSTANCE')
        row2 = s4.row(align=True)
        row2.scale_y = 1.15
        row2.operator("surreal_arch.player_start",
                       text="🎮 Place Player Start", icon='CAMERA_DATA')

        # ⑤ Komikaze shader linking
        s5 = layout.box()
        s5.label(text="⑤ Komikaze materials", icon='MATERIAL')
        import os
        if os.path.exists(_KOMIKAZE_BLEND_PATH):
            s5.label(text="✅ Komikaze v2.blend detected", icon='CHECKMARK')
        else:
            s5.alert = True
            s5.label(text="⚠ Komikaze v2.blend not found", icon='ERROR')
        row = s5.row(align=True)
        row.scale_y = 1.25
        row.operator("surreal_arch.komikaze_apply",
                     text="🎨 Apply Komikaze Shader", icon='MATERIAL_DATA')
        row2 = s5.row(align=True)
        row2.scale_y = 1.1
        row2.operator("surreal_arch.komikaze_auto_map",
                       text="✨ Auto-Map (by material_choice)", icon='LINKED')

        # ⑥ Polish
        s6 = layout.box()
        s6.label(text="⑥ Polish (cohesive bevel)", icon='MOD_BEVEL')
        s6.label(text="Run on Layer 2 worlds for AAA edges.", icon='INFO')
        row = s6.row(align=True)
        row.scale_y = 1.25
        row.operator("surreal_arch.polish_all",
                     text="🪞 Polish Selected", icon='MOD_BEVEL')


