def _make_aest_op(suffix, effect_key, label, descr):
    """Factory for one-click aesthetic effect operators."""
    class _AestOp(bpy.types.Operator):
        bl_idname = f"surreal_arch.aest_{suffix}"
        bl_label = label
        bl_description = descr
        bl_options = {'REGISTER', 'UNDO'}

        def execute(self, context):
            if _apply_aest(context, effect_key):
                self.report({'INFO'}, f"Applied {label}")
            else:
                self.report({'WARNING'}, "Select a mesh object first")
            return {'FINISHED'}

    _AestOp.__name__ = f"SURREAL_ARCH_OT_aest_{suffix}"
    return _AestOp


