class SURREAL_ARCH_OT_aest_apply(bpy.types.Operator):
    """Apply the currently selected aesthetic_effect on the active mesh."""
    bl_idname = "surreal_arch.aest_apply"
    bl_label = "Apply Aesthetic Effect"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh first")
            return {'CANCELLED'}
        apply_aesthetic_effect_gn(obj, obj.surreal_arch_props)
        return {'FINISHED'}


class SURREAL_ARCH_OT_aest_clear(bpy.types.Operator):
    """Remove every Aest_* modifier from the active object."""
    bl_idname = "surreal_arch.aest_clear"
    bl_label = "Clear All Aesthetic Effects"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            return {'CANCELLED'}
        clear_aesthetic_effects(obj)
        self.report({'INFO'}, "Cleared aesthetic effect stack")
        return {'FINISHED'}


class SURREAL_ARCH_PT_aesthetic_effects(_EffectsSubPanelBase, bpy.types.Panel):
    bl_label = "🎭 Aesthetic Effects (Any Mesh)"
    bl_idname = "SURREAL_ARCH_PT_aesthetic_effects"
    bl_order = 5

    def draw(self, context):
        layout = self.layout
        props = context.active_object.surreal_arch_props if context.active_object else None
        if not props:
            layout.label(text="Select a mesh first.", icon='INFO')
            return

        layout.label(text="One-click non-destructive overlays:", icon='SHADERFX')

        # Shared parameters
        box = layout.box()
        box.label(text="Parameters", icon='PREFERENCES')
        row = box.row(align=True)
        row.prop(props, "aest_intensity")
        row.prop(props, "aest_density")
        row = box.row(align=True)
        row.prop(props, "aest_scale")
        row.prop(props, "aest_layers")
        row = box.row(align=True)
        row.prop(props, "aest_seed")
        row = box.row(align=True)
        row.prop(props, "aest_color_a", text="A")
        row.prop(props, "aest_color_b", text="B")
