class SURREAL_ARCH_OT_auto_building(bpy.types.Operator):
    """Generate a complete parametric building from the current settings."""
    bl_idname = "surreal_arch.auto_building"
    bl_label  = "🏢 Generate Building"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if not obj or obj.type != 'MESH':
            bpy.ops.mesh.primitive_cube_add()
            obj = context.active_object
        _safe_set_arch_type(obj.surreal_arch_props, 'AUTO_BUILDING')
        bpy.ops.surreal_arch.generate()
        obj.name = f"Building_{obj.surreal_arch_props.bld_style}"
        return {'FINISHED'}


def _safe_set_arch_type(props, value, fallback='BUILDING'):
    """Set arch_type defensively — falls back when the enum doesn't include
    the requested value (e.g. when an older addon registration is cached)."""
    try:
        props.arch_type = value
    except TypeError:
        try:
            props.arch_type = fallback
        except Exception:
            pass


def _bld_one_click(style, floors=None, width=None, depth=None):
    def execute(self, context):
        bpy.ops.mesh.primitive_cube_add()
        obj = context.active_object
        p = obj.surreal_arch_props
        p.bld_style = style
        if floors: p.bld_floor_count_b = floors
        if width:  p.bld_width = width
        if depth:  p.bld_depth_b = depth
        _safe_set_arch_type(p, 'AUTO_BUILDING')
        bpy.ops.surreal_arch.generate()
        obj.name = f"Building_{style}"
        return {'FINISHED'}
    return execute

