class SURREAL_ARCH_OT_generate(bpy.types.Operator):
    bl_idname = "surreal_arch.generate"
    bl_label  = "Generate Geometry"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        return context.active_object and context.active_object.type == 'MESH'

    def execute(self, context):
        global _AUTO_UPDATE_RUNNING
        obj = context.active_object
        props = obj.surreal_arch_props
        # Block re-entrant auto_update callbacks while we mutate props internally
        was_running = _AUTO_UPDATE_RUNNING
        _AUTO_UPDATE_RUNNING = True
        try:
            apply_geometry_nodes_to_object(obj, props)
            if props.apply_modifiers:
                for mod in list(obj.modifiers):
                    if mod.name.startswith("SurrealArch"):
                        bpy.context.view_layer.objects.active = obj
                        bpy.ops.object.modifier_apply(modifier=mod.name)
                        break
                apply_smart_uv_unwrap(obj, props, context)
            self.report({'INFO'}, f"Generated {props.arch_type} architecture")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Generation failed: {e}")
            import traceback; traceback.print_exc()
            return {'CANCELLED'}
        finally:
            _AUTO_UPDATE_RUNNING = was_running


def _make_preset_op(class_name, op_id, label, params, description=None):
    """Factory for preset operators."""
    def execute(self, context):
        p = context.active_object.surreal_arch_props
        for k, v in params.items():
            setattr(p, k, v)
        return bpy.ops.surreal_arch.generate()

    cls_dict = {
        'bl_idname': op_id,
        'bl_label':  label,
        'bl_options': {'REGISTER', 'UNDO'},
        'execute':   execute,
        'poll':      classmethod(lambda c, ctx: ctx.active_object and ctx.active_object.type == 'MESH'),
    }
    if description:
        cls_dict['bl_description'] = description
    cls = type(class_name, (bpy.types.Operator,), cls_dict)
    return cls


def _make_graph_preset_op(class_name, op_id, label, research_preset_id, description=None):
    """Factory for curated presets that spawn a full OS grammar graph chain."""
    def execute(self, context):
        import sys
        monolith = sys.modules.get("surreal_architecture_gen")
        from surreal_arch.research_presets import run_research_preset
        try:
            result = run_research_preset(context, research_preset_id, monolith=monolith)
        except Exception as err:
            self.report({'ERROR'}, str(err))
            return {'CANCELLED'}
        if result.get("mode") == "graph":
            self.report(
                {'INFO'},
                f"Spawned {result['count']} modules ({result['graph_id']})",
            )
        return {'FINISHED'}

    cls_dict = {
        'bl_idname': op_id,
        'bl_label': label,
        'bl_options': {'REGISTER', 'UNDO'},
        'execute': execute,
        'poll': classmethod(lambda c, ctx: ctx.view_layer is not None),
    }
    if description:
        cls_dict['bl_description'] = description
    return type(class_name, (bpy.types.Operator,), cls_dict)


