# === Synthia presets — set the preset selection then user clicks 🧮 to spawn ===
def _make_synthia_preset(class_name, op_id, label, synthia_id, preset_type, material):
    def execute(self, context):
        obj = context.active_object
        if not (obj and hasattr(obj, 'surreal_arch_props')):
            self.report({'ERROR'}, "Need active mesh object")
            return {'CANCELLED'}
        p = obj.surreal_arch_props
        p.synthia_use_custom = False
        p.synthia_preset = synthia_id
        p.synthia_preset_type = preset_type
        p.material_choice = material
        p.bevel_mode = 'EDGE'
        p.bevel_amount = 0.04
        p.bevel_subdiv_level = 2
        p.bevel_angle_deg = 35.0
        return bpy.ops.surreal_arch.spawn_synthia()

    cls = type(class_name, (bpy.types.Operator,), {
        'bl_idname': op_id,
        'bl_label':  label,
        'bl_options': {'REGISTER', 'UNDO'},
        'execute':   execute,
        'poll':      classmethod(lambda c, ctx: ctx.active_object and ctx.active_object.type == 'MESH'),
    })
    return cls


