class SURREAL_ARCH_OT_build_shaders(bpy.types.Operator):
    """Build (or rebuild) the entire shader library + day/night world."""
    bl_idname = "surreal_arch.build_shaders"
    bl_label  = "Build Shader Library"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        try:
            mats, world = build_shader_library()
            self.report({'INFO'}, f"Built {len(mats)} materials + 1 world shader")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Build failed: {e}")
            import traceback; traceback.print_exc()
            return {'CANCELLED'}


class SURREAL_ARCH_OT_apply_world(bpy.types.Operator):
    """Set the active scene's world to the day/night sky shader."""
    bl_idname = "surreal_arch.apply_world"
    bl_label  = "Apply Day/Night World"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        try:
            world = bpy.data.worlds.get(WORLD_NAME)
            if not world:
                world = build_world_shader()
            context.scene.world = world

            obj = context.active_object
            if obj and hasattr(obj, 'surreal_arch_props'):
                sync_world_drivers(world, obj)

            self.report({'INFO'}, "Day/Night world applied + drivers wired")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"World apply failed: {e}")
            return {'CANCELLED'}


class SURREAL_ARCH_OT_create_water(bpy.types.Operator):
    """Spawn a musical water plane below the active object."""
    bl_idname = "surreal_arch.create_water"
    bl_label  = "Create Musical Water Plane"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        try:
            mat = bpy.data.materials.get(MAT_NAMES['WATER']) or build_musical_water_material()

            obj_ref = context.active_object

            # Create a plane scaled big
            bpy.ops.mesh.primitive_plane_add(size=20)
            water = context.active_object
            water.name = "MusicalWater"
            water.location.z -= 0.1

            # Add subdivision modifier to give the plane geometry
            sub = water.modifiers.new(name="Sub", type='SUBSURF')
            sub.levels = 5; sub.render_levels = 5

            # Apply material
            water.data.materials.clear()
            water.data.materials.append(mat)

            # Wire drivers to original active object's musical params
            if obj_ref and hasattr(obj_ref, 'surreal_arch_props'):
                sync_water_drivers(mat, obj_ref)

            self.report({'INFO'}, "Musical water plane created (drag harmonics → ripples animate)")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Water creation failed: {e}")
            import traceback; traceback.print_exc()
            return {'CANCELLED'}


class SURREAL_ARCH_OT_apply_material(bpy.types.Operator):
    """Apply the chosen material from the library to the active object."""
    bl_idname = "surreal_arch.apply_material"
    bl_label  = "Apply Material"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        return context.active_object and context.active_object.type == 'MESH'

    def execute(self, context):
        try:
            obj = context.active_object
            apply_material_to_object(obj, obj.surreal_arch_props)
            self.report({'INFO'}, "Material applied")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Apply failed: {e}")
            return {'CANCELLED'}


class SURREAL_ARCH_OT_organize(bpy.types.Operator):
    """Re-frame and color-code the geometry node tree of the active object."""
    bl_idname = "surreal_arch.organize_nodes"
    bl_label  = "Organize Node Tree"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        obj = context.active_object
        if not obj or obj.type != 'MESH':
            return False
        return any(m.type == 'NODES' and m.name.startswith("SurrealArch") for m in obj.modifiers)

    def execute(self, context):
        obj = context.active_object
        for mod in obj.modifiers:
            if mod.type == 'NODES' and mod.name.startswith("SurrealArch") and mod.node_group:
                organize_node_tree(mod.node_group, obj.surreal_arch_props.arch_type)
                self.report({'INFO'}, "Node tree organized with frames")
                return {'FINISHED'}
        self.report({'WARNING'}, "No SurrealArch geometry nodes modifier found")
        return {'CANCELLED'}


