def _higgsas_available():
    """Return True if the Higgsas library is accessible OR groups already loaded."""
    # Fast path: any Higgsas NT* group already in the file
    for ng in bpy.data.node_groups:
        if ng.name.startswith('NT') and len(ng.name) > 4:
            return True
    # Check the library file on disk
    import os
    return os.path.exists(_HIGGSAS_LIB_PATH)


def _higg_load(name):
    """Lazily append one Higgsas node group from the library. Returns the
    NodeGroup or None if unavailable. Idempotent — skips if already loaded."""
    ng = bpy.data.node_groups.get(name)
    if ng is not None:
        return ng
    import os
    if not os.path.exists(_HIGGSAS_LIB_PATH):
        return None
    try:
        with bpy.data.libraries.load(_HIGGSAS_LIB_PATH, link=False) as (src, dst):
            if name in src.node_groups:
                dst.node_groups = [name]
            else:
                return None
    except Exception:
        return None
    return bpy.data.node_groups.get(name)


def _higg_node(tree, name, loc, fallback_type=None):
    """Add a GeometryNodeGroup node for the named Higgsas group.
    If unavailable, creates `fallback_type` (e.g. 'GeometryNodeMeshCube') instead.
    Returns the node or None. All failure paths fall back gracefully."""
    ng = _higg_load(name)
    if ng is None:
        if fallback_type:
            return _safe_node(tree, fallback_type, loc)
        return None
    try:
        node = tree.nodes.new('GeometryNodeGroup')
        node.node_tree = ng
        node.location = loc
        color_node(node, 'ornament')
        return node
    except Exception:
        # Group loaded but node creation failed (version mismatch, corrupt group, etc.)
        if fallback_type:
            return _safe_node(tree, fallback_type, loc)
        return None


def _higg_input(node, name, value):
    """Safely set a named input on a Higgsas node group. Skips on error."""
    if node is None:
        return
    try:
        node.inputs[name].default_value = value
    except Exception:
        pass


# ==============================================================================
def _sverchok_available():
    """Sverchok ships its own node-tree type. If absent, the type fails to register."""
    try:
        # Probe by trying to create a tree
        t = bpy.data.node_groups.new(name="__sv_probe__", type='SverchCustomTreeType')
        bpy.data.node_groups.remove(t)
        return True
    except Exception:
        return False


# v2.47: Sverchok node-availability cache (Sverchok 1.4 renames a few; we probe once).
_SV_NODE_CACHE = {}


def _sv_has_node(bl_idname):
    """Cached probe: does this Sverchok node type exist in the user's install?"""
    if not _sverchok_available():
        return False
    if bl_idname in _SV_NODE_CACHE:
        return _SV_NODE_CACHE[bl_idname]
    try:
        t = bpy.data.node_groups.get("__sv_node_probe__") or \
            bpy.data.node_groups.new(name="__sv_node_probe__", type='SverchCustomTreeType')
        try:
            n = t.nodes.new(bl_idname)
            t.nodes.remove(n)
            _SV_NODE_CACHE[bl_idname] = True
        except Exception:
            _SV_NODE_CACHE[bl_idname] = False
    except Exception:
        _SV_NODE_CACHE[bl_idname] = False
    return _SV_NODE_CACHE[bl_idname]


def _sv_node_or_skip(tree, bl_idname, loc):
    """Create a Sverchok node if available, else return None.
    Use in companion-tree builders so missing-node trees skip gracefully
    instead of crashing the operator."""
    if not _sv_has_node(bl_idname):
        return None
    try:
        n = tree.nodes.new(bl_idname)
        n.location = loc
        return n
    except Exception:
        return None


class SURREAL_ARCH_OT_sv_diagnose(bpy.types.Operator):
    """v2.47: Probe the user's Sverchok install and report which preset
    node types are available. Run this when a preset's tree-building feels
    broken — it'll tell you which Sverchok nodes are missing."""
    bl_idname = "surreal_arch.sv_diagnose"
    bl_label = "🩺 Diagnose Sverchok Compatibility"
    bl_options = {'REGISTER'}

    def execute(self, context):
        if not _sverchok_available():
            self.report({'WARNING'},
                "Sverchok addon not detected — Python-only fallback is used everywhere.")
            return {'FINISHED'}
        # Probe every Sverchok node our presets reference
        probed_nodes = [
            ('SvSpiralNodeMK2',     'Spiral Tower'),
            ('SvTorusKnotNodeMK2',  'Torus Knot'),
            ('SvCylinderNodeMK2',   'Twisted Cylinder'),
            ('SvPolygonGridNode',   'Tessellation'),
            ('SvMeshViewer',        'Output (all presets)'),
            ('SvLineNodeMK4',       'Line primitive (multiple)'),
            ('SvBoxNodeMk2',        'Box primitive (multiple)'),
            ('SvPlaneNodeMk3',      'Plane primitive (multiple)'),
            ('SvNoiseNodeMK3',      'Filigree / Twisted noise'),
            ('SvIcoSphereNode',     'Recursive Portal'),
            ('SvKochCurveNode',     'Fractal Curve'),
            ('SvBezierInNode',      'Cathedral Ruin / Branching'),
        ]
        avail, missing = [], []
        for nname, descr in probed_nodes:
            if _sv_has_node(nname):
                avail.append((nname, descr))
            else:
                missing.append((nname, descr))
        # Clean up the probe tree
        for ng in list(bpy.data.node_groups):
            if ng.name == "__sv_node_probe__":
                try: bpy.data.node_groups.remove(ng)
                except: pass
        # Print to console
        print("\n══════════════════════════════════════════════════════")
        print("🩺  SVERCHOK COMPATIBILITY DIAGNOSTIC")
        print("══════════════════════════════════════════════════════")
        print(f"\n✅ Available nodes ({len(avail)}):")
        for nname, descr in avail:
            print(f"  • {nname:25s}  — {descr}")
        if missing:
            print(f"\n⚠ Missing nodes ({len(missing)}):")
            for nname, descr in missing:
                print(f"  • {nname:25s}  — {descr}")
            print("\nPresets that need missing nodes still SPAWN MESHES "
                  "(pure-Python path) — only the editable companion tree is skipped.")
        else:
            print("\n🎉 All preset nodes available!")
        print()
        self.report({'INFO'},
            f"🩺 Sverchok diagnostic: {len(avail)} nodes ok, {len(missing)} missing — see Window→Toggle System Console")
        return {'FINISHED'}


def _sv_make_tree(name):
    """Create or reset a Sverchok node tree. Uses the `_sv_` prefix so
    `sv_open_editor` / `sv_clean_trees` can locate it consistently."""
    full = f"_sv_{name}"
    old = bpy.data.node_groups.get(full)
    if old:
        bpy.data.node_groups.remove(old)
    return bpy.data.node_groups.new(name=full, type='SverchCustomTreeType'), full


def _sv_set_value(socket, val):
    """Safely set a Sverchok node-input default. Sverchok sockets often expose `prop_int`/`prop_float`."""
    try:
        socket.default_property = val
    except Exception:
        try: socket.default_value = val
        except Exception: pass


def _sverchok_force_evaluate(tree):
    """
    Force Sverchok to evaluate a tree and let SvMeshViewer bake its mesh.
    Sverchok's update needs a NODE_EDITOR area with the tree loaded as the active tree.
    We temporarily commandeer one area to provide that context, then restore it.
    """
    screen = bpy.context.screen
    if not screen or not screen.areas:
        try: tree.force_update()
        except Exception: pass
        return

    # Find an existing NODE_EDITOR first
    target_area = None
    for area in screen.areas:
        if area.type == 'NODE_EDITOR':
            target_area = area
            break

    if target_area is not None:
        # Use the existing node editor
        space = target_area.spaces.active
        old_tree_type = getattr(space, 'tree_type', None)
        old_tree = getattr(space, 'node_tree', None)
        try:
            space.tree_type = 'SverchCustomTreeType'
            space.node_tree = tree
            with bpy.context.temp_override(area=target_area):
                bpy.ops.node.sverchok_update_all()
        except Exception:
            try: tree.force_update()
            except Exception: pass
        finally:
            try:
                if old_tree_type is not None: space.tree_type = old_tree_type
                if old_tree is not None: space.node_tree = old_tree
            except Exception: pass
    else:
        # No NODE_EDITOR present — temporarily switch one area to NODE_EDITOR
        area = screen.areas[-1]  # use the last area (typically Properties / Outliner)
        old_type = area.type
        try:
            area.type = 'NODE_EDITOR'
            space = area.spaces.active
            space.tree_type = 'SverchCustomTreeType'
            space.node_tree = tree
            with bpy.context.temp_override(area=area):
                bpy.ops.node.sverchok_update_all()
        except Exception:
            try: tree.force_update()
            except Exception: pass
        finally:
            try: area.type = old_type
            except Exception: pass


def _sv_finish(tree, gen_node, name="SverchokOut"):
    """Wire a generator's verts/edges/faces into a SvMeshViewer that bakes to a mesh."""
    viewer = tree.nodes.new('SvMeshViewer')
    viewer.location = (gen_node.location[0] + 350, gen_node.location[1])
    viewer.label = name
    # Set the mesh name so the spawned object isn't called "Alpha/Beta/Gamma"
    try:
        viewer.base_data_name = name
    except Exception:
        pass
    # Wire what's available
    out_names = [s.name.lower() for s in gen_node.outputs]
    in_names_v = [s.name.lower() for s in viewer.inputs]
    pairs = [
        ('vertices', 'vertices'),
        ('verts',    'vertices'),
        ('edges',    'edges'),
        ('polygons', 'faces'),
        ('faces',    'faces'),
    ]
    for src_lower, dst_lower in pairs:
        if src_lower in out_names and dst_lower in in_names_v:
            src = gen_node.outputs[out_names.index(src_lower)]
            dst = viewer.inputs[in_names_v.index(dst_lower)]
            try: tree.links.new(src, dst)
            except Exception: pass
    return viewer


def _sverchok_spawn_via_tree(tree_builder_fn, mesh_name="SverchokEscher"):
    """
    Helper: build a Sverchok tree, trigger it to run, then find the resulting mesh.
    tree_builder_fn(tree) → builds the tree, returns the SvMeshViewer node.
    Returns the new mesh object (or None).

    NOTE: This pathway is now legacy. New Sverchok presets compute geometry
    directly in Python and create the mesh via _spawn_mesh_from_data — no tree
    evaluation happens by default, avoiding duplicate-mesh accumulation.
    """
    if not _sverchok_available():
        return None

    pre = set(bpy.data.objects.keys())

    tree, tree_name = _sv_make_tree(mesh_name)
    viewer = tree_builder_fn(tree)

    # Trigger Sverchok to evaluate the tree → SvMeshViewer bakes a real mesh.
    # Sverchok's tree.force_update() needs an active NODE_EDITOR context loaded
    # with the tree. We temporarily commandeer one area to provide that.
    _sverchok_force_evaluate(tree)

    # Find the new mesh object Sverchok created
    post = set(bpy.data.objects.keys())
    new = post - pre
    new_meshes = [bpy.data.objects[n] for n in new if bpy.data.objects[n].type == 'MESH']
    if not new_meshes:
        return None
    obj = new_meshes[0]

    # Apply our auto-align pass to ground the spawned mesh
    try:
        # Center XY, snap to ground
        verts = obj.data.vertices
        if len(verts):
            xs = [v.co.x for v in verts]
            ys = [v.co.y for v in verts]
            zs = [v.co.z for v in verts]
            cx = (min(xs) + max(xs)) / 2
            cy = (min(ys) + max(ys)) / 2
            zmin = min(zs)
            for v in verts:
                v.co.x -= cx
                v.co.y -= cy
                v.co.z -= zmin
    except Exception:
        pass

    return obj


# ===  5 ESCHER GENERATORS  ===
# Computed directly in Python (the same math Sverchok would use, but reliable & instant).
# A companion Sverchok tree is ALSO created for users who want to tweak in the editor.

def _spawn_mesh_from_data(name, verts, edges, faces, ground=True, center_xy=True):
    """Create a Blender mesh object from raw vert/edge/face lists, auto-aligned.

    Uses bbox-center (not vertex centroid) so non-uniform vert distributions
    still produce visually-centered results. Snaps zmin = 0 (ground).
    """
    if not verts:
        cx = cy = zmin = 0.0
    else:
        if center_xy:
            xmin = min(v[0] for v in verts); xmax = max(v[0] for v in verts)
            ymin = min(v[1] for v in verts); ymax = max(v[1] for v in verts)
            cx = (xmin + xmax) / 2
            cy = (ymin + ymax) / 2
        else:
            cx = cy = 0.0
        zmin = min(v[2] for v in verts) if ground else 0.0

    aligned = [(v[0] - cx, v[1] - cy, v[2] - zmin) for v in verts]

    me = bpy.data.meshes.new(name + "Mesh")
    me.from_pydata(aligned, edges or [], faces or [])
    me.update()
    obj = bpy.data.objects.new(name, me)
    bpy.context.scene.collection.objects.link(obj)
    return obj


_SV_CURRENT_PROPS = None  # captured once per operator invocation


def _spawn_companion_tree(tree_name, builder_fn):
    """
    Build a Sverchok tree (optionally for user editing).

    v2.46: Silently no-ops if Sverchok isn't available. The Python-computed
    mesh is unaffected; the user just loses the optional editable tree.

    Behavior (when Sverchok IS installed):
      • sv_keep_tree=False (default): build a tree, delete it → no scene pollution.
      • sv_keep_tree=True: build a FULL WORKING tree with SvMeshViewer
        wired in. User can open the Sverchok editor, tweak nodes, and on
        "Update All" Sverchok will spawn/refresh its own mesh (separate
        from our Python-computed one).
    """
    if not _sverchok_available():
        return None
    try:
        tree, _ = _sv_make_tree(tree_name)
        builder_fn(tree)
        global _SV_CURRENT_PROPS
        keep = bool(_SV_CURRENT_PROPS and getattr(_SV_CURRENT_PROPS, 'sv_keep_tree', False))
        if not keep:
            bpy.data.node_groups.remove(tree)
            return None

        # KEEP MODE — wire a SvMeshViewer to the first generator output we find,
        # so the user can actually EDIT and regenerate via Sverchok.
        gen_node = None
        for n in tree.nodes:
            # Find a generator (Sv* node) that has Vertices/Verts output
            if not n.bl_idname.startswith('Sv'): continue
            if 'Viewer' in n.bl_idname: continue
            out_names = [s.name.lower() for s in n.outputs]
            if any(k in out_names for k in ('vertices', 'verts')):
                gen_node = n
                break

        if gen_node is not None:
            viewer_name = f"SverchokEdit_{tree_name}"
            _sv_finish(tree, gen_node, name=viewer_name)

        return tree
    except Exception:
        return None


def _sv_params(default_resolution=1.0, default_scale=1.0, default_complexity=1.0):
    """
    Read the unified Sverchok properties from the active object's props,
    blended with the universal music influence.
    Returns (resolution, scale, complexity, music_phase) — all multiplicative factors.
    """
    import math
    global _SV_CURRENT_PROPS
    props = _SV_CURRENT_PROPS
    if not props:
        # Fallback: try active object
        obj = bpy.context.active_object
        props = obj.surreal_arch_props if (obj and hasattr(obj, 'surreal_arch_props')) else None
    if not props:
        return default_resolution, default_scale, default_complexity, 0.0

    res = getattr(props, 'sv_resolution', default_resolution) * default_resolution
    sc  = getattr(props, 'sv_scale',      default_scale)      * default_scale
    cpx = getattr(props, 'sv_complexity', default_complexity) * default_complexity

    # Music modulation
    music_inf = getattr(props, 'universal_music_influence', 0.0)
    music_resp = getattr(props, 'sv_music_response', 0.5)
    if music_inf > 0.001:
        freq_a = getattr(props, 'musical_freq_a', 0.6)
        freq_b = getattr(props, 'musical_freq_b', 1.2)
        amp = getattr(props, 'musical_amplitude', 0.4)
        tempo = getattr(props, 'tempo_factor', 1.0)
        # Harmonic phase: sin(freq_a × tempo) + 0.5 × sin(freq_b × tempo × 2)
        phase = math.sin(freq_a * tempo * math.pi) + 0.5 * math.sin(freq_b * tempo * math.pi * 2)
        music_kick = music_inf * music_resp * amp * phase
        # Music affects all 3 multiplicatively (capped to safe range)
        cpx *= max(0.3, 1.0 + music_kick * 0.8)
        res *= max(0.3, 1.0 + music_kick * 0.3)
        sc  *= max(0.3, 1.0 + music_kick * 0.4)
        music_phase = music_kick
    else:
        music_phase = 0.0

    return res, sc, cpx, music_phase


def sverchok_spiral_tower():
    """🌀 Logarithmic ascending spiral — Escher's recursive spiral towers."""
    import math
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    R, r = 2.0 * scale_mult, 0.5 * scale_mult
    turns = 5.0 * complexity_mult
    n_per_turn = max(8, int(32 * res_mult))
    rise = 0.5 * scale_mult
    n = int(turns * n_per_turn)
    verts = []
    for i in range(n + 1):
        t = i / n_per_turn
        ang = t * math.tau
        # Logarithmic radius: shrinks toward top
        radius = R - (R - r) * (t / turns)
        verts.append((radius * math.cos(ang), radius * math.sin(ang), t * rise))
    edges = [(i, i + 1) for i in range(n)]

    # Build a Sverchok tree for user editing
    def build(tree):
        spiral = tree.nodes.new('SvSpiralNodeMK2'); spiral.location = (0, 0); spiral.label = "EscherSpiral"
        try:
            for s in spiral.inputs:
                if s.name == 'R': _sv_set_value(s, R)
                elif s.name == 'r': _sv_set_value(s, r)
                elif s.name == 't': _sv_set_value(s, turns)
                elif s.name == 'n': _sv_set_value(s, n_per_turn)
                elif s.name == 's': _sv_set_value(s, rise)
        except Exception: pass
        _sv_finish(tree, spiral, name="EscherSpiralTower")
    _spawn_companion_tree("SpiralTower", build)

    return _spawn_mesh_from_data("EscherSpiralTower", verts, edges, [])


def sverchok_torus_knot():
    """🪢 (p,q) Torus Knot — Escher's interlocking ribbon. Default p=3, q=2 (trefoil)."""
    import math
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    R, r = 2.0 * scale_mult, 0.6 * scale_mult
    # Complexity influences (p, q) — higher = more knot crossings
    p = max(2, int(3 * complexity_mult))
    q = max(1, int(2 * complexity_mult))
    n = max(64, int(256 * res_mult))
    verts = []
    for i in range(n):
        t = (i / n) * math.tau
        cx = math.cos(q * t)
        sx = math.sin(q * t)
        x = (R + r * cx) * math.cos(p * t)
        y = (R + r * cx) * math.sin(p * t)
        z = r * sx
        verts.append((x, y, z))
    edges = [(i, (i + 1) % n) for i in range(n)]

    def build(tree):
        tk = tree.nodes.new('SvTorusKnotNodeMK2'); tk.location = (0, 0); tk.label = "EscherKnot"
        try:
            for s in tk.inputs:
                if s.name == 'R': _sv_set_value(s, R)
                elif s.name == 'r': _sv_set_value(s, r)
                elif s.name == 'p': _sv_set_value(s, p)
                elif s.name == 'q': _sv_set_value(s, q)
                elif s.name == 'n': _sv_set_value(s, n)
        except Exception: pass
        _sv_finish(tree, tk, name="EscherTorusKnot")
    _spawn_companion_tree("TorusKnot", build)

    return _spawn_mesh_from_data("EscherTorusKnot", verts, edges, [])


def sverchok_tessellation():
    """🐦 Hexagonal grid tessellation — Escher's reptile/fish tile patterns."""
    import math
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    cell = 0.5 * scale_mult
    nx = max(4, int(12 * complexity_mult))
    ny = max(4, int(12 * complexity_mult))
    verts = []
    faces = []
    for j in range(ny):
        for i in range(nx):
            x_off = (j % 2) * cell * 0.5  # honeycomb offset
            cx = i * cell + x_off
            cy = j * cell * 0.866   # √3/2 vertical spacing for hex
            base = len(verts)
            # Hexagon vertices at radius=cell*0.5
            for k in range(6):
                ang = k * math.pi / 3
                verts.append((cx + cell * 0.45 * math.cos(ang),
                              cy + cell * 0.45 * math.sin(ang), 0.0))
            faces.append([base, base + 1, base + 2, base + 3, base + 4, base + 5])

    def build(tree):
        grid = tree.nodes.new('SvPolygonGridNode'); grid.location = (0, 0); grid.label = "Tessellation"
        try:
            for s in grid.inputs:
                if s.name == 'Radius': _sv_set_value(s, cell * 0.45)
                elif s.name == 'NumX': _sv_set_value(s, nx)
                elif s.name == 'NumY': _sv_set_value(s, ny)
        except Exception: pass
        _sv_finish(tree, grid, name="EscherTessellation")
    _spawn_companion_tree("Tessellation", build)

    return _spawn_mesh_from_data("EscherTessellation", verts, [], faces)


def sverchok_twisted_cylinder():
    """🌪 Heavily-twisted cylinder — Escher impossible spiral architecture."""
    import math
    res_mult, scale_mult, complexity_mult, phase = _sv_params()
    radius_top = 0.3 * scale_mult
    radius_bot = 1.5 * scale_mult
    parallels = max(8, int(16 * res_mult))
    meridians = max(12, int(32 * res_mult))
    height = 6.0 * scale_mult
    # Twist is music-responsive: complexity + phase adds extra rotation
    twist = math.tau * complexity_mult * (1.0 + phase * 0.5)
    verts = []
    faces = []
    for j in range(parallels + 1):
        t = j / parallels
        r = radius_bot + (radius_top - radius_bot) * t
        ang_off = twist * t
        for i in range(meridians):
            ang = (i / meridians) * math.tau + ang_off
            verts.append((r * math.cos(ang), r * math.sin(ang), t * height))
    for j in range(parallels):
        for i in range(meridians):
            a = j * meridians + i
            b = j * meridians + (i + 1) % meridians
            c = (j + 1) * meridians + (i + 1) % meridians
            d = (j + 1) * meridians + i
            faces.append([a, b, c, d])

    def build(tree):
        cyl = tree.nodes.new('SvCylinderNodeMK2'); cyl.location = (0, 0); cyl.label = "TwistedCylinder"
        try:
            for s in cyl.inputs:
                if s.name == 'RadiusT': _sv_set_value(s, radius_top)
                elif s.name == 'RadiusB': _sv_set_value(s, radius_bot)
                elif s.name == 'Parallels': _sv_set_value(s, parallels)
                elif s.name == 'Meridians': _sv_set_value(s, meridians)
                elif s.name == 'Height': _sv_set_value(s, height)
                elif s.name == 'Twist': _sv_set_value(s, twist)
        except Exception: pass
        _sv_finish(tree, cyl, name="EscherTwistedCylinder")
    _spawn_companion_tree("TwistedCylinder", build)

    return _spawn_mesh_from_data("EscherTwistedCylinder", verts, [], faces)


def sverchok_fractal_curve():
    """❄ Koch-snowflake-style fractal curve — Escher's recursive self-similar paths."""
    import math
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    # Iterations grow with complexity — careful, each adds 4× verts
    iterations = max(1, min(5, int(round(3 * complexity_mult))))
    sides = max(3, int(6 * scale_mult / scale_mult))  # keep hex base
    radius = 1.5 * scale_mult

    # Generate initial polygon
    verts2d = [(radius * math.cos(i * math.tau / sides),
                radius * math.sin(i * math.tau / sides))
               for i in range(sides)]

    # Koch subdivision: each segment → 4 segments with a triangular bump out
    def koch(points):
        out = []
        for i in range(len(points)):
            a = points[i]
            b = points[(i + 1) % len(points)]
            # 4-point subdivision
            p0 = a
            p1 = ((2 * a[0] + b[0]) / 3, (2 * a[1] + b[1]) / 3)
            # Midpoint of segment, pushed outward
            mx = (a[0] + b[0]) / 2
            my = (a[1] + b[1]) / 2
            dx = b[0] - a[0]
            dy = b[1] - a[1]
            # Perpendicular (rotate 90° CCW)
            nx_, ny_ = -dy, dx
            seg_len = math.hypot(dx, dy)
            if seg_len > 0:
                push = seg_len * 0.288675  # √3/6 — equilateral bump height
                p2 = (mx + nx_ * push / seg_len, my + ny_ * push / seg_len)
            else:
                p2 = (mx, my)
            p3 = ((a[0] + 2 * b[0]) / 3, (a[1] + 2 * b[1]) / 3)
            out.extend([p0, p1, p2, p3])
        return out

    pts = verts2d
    for _ in range(iterations):
        pts = koch(pts)

    verts = [(p[0], p[1], 0.0) for p in pts]
    n = len(verts)
    edges = [(i, (i + 1) % n) for i in range(n)]

    def build(tree):
        circle = tree.nodes.new('SvCircleNode'); circle.location = (-300, 0)
        for s in circle.inputs:
            if s.name == 'Radius': _sv_set_value(s, radius)
            elif s.name.lower().startswith('num'): _sv_set_value(s, sides)
        fr = tree.nodes.new('SvFractalCurveNode'); fr.location = (0, 0); fr.label = "FractalCurve"
        try:
            for s in fr.inputs:
                if s.name == 'Iterations': _sv_set_value(s, iterations)
        except Exception: pass
        try: tree.links.new(circle.outputs[0], fr.inputs['Vertices'])
        except Exception: pass
        _sv_finish(tree, fr, name="EscherFractal")
    _spawn_companion_tree("FractalCurve", build)

    return _spawn_mesh_from_data("EscherFractalCurve", verts, edges, [])


# ============================================================
# ARCHITECTURAL SVERCHOK PRESETS — railings, walls, floors, gothic
# ============================================================

def _cube_face(verts, x, y, z, sx, sy, sz):
    """Append a unit-cube's verts/faces to lists, sized & translated. Returns (vert_indices, face_indices)."""
    base = len(verts)
    hx, hy, hz = sx / 2, sy / 2, sz / 2
    verts.extend([
        (x - hx, y - hy, z - hz), (x + hx, y - hy, z - hz),
        (x + hx, y + hy, z - hz), (x - hx, y + hy, z - hz),
        (x - hx, y - hy, z + hz), (x + hx, y - hy, z + hz),
        (x + hx, y + hy, z + hz), (x - hx, y + hy, z + hz),
    ])
    faces = [
        [base + 0, base + 1, base + 2, base + 3],   # bottom
        [base + 4, base + 7, base + 6, base + 5],   # top
        [base + 0, base + 4, base + 5, base + 1],   # front (-Y)
        [base + 1, base + 5, base + 6, base + 2],   # right (+X)
        [base + 2, base + 6, base + 7, base + 3],   # back (+Y)
        [base + 3, base + 7, base + 4, base + 0],   # left (-X)
    ]
    return base, faces


def _add_cylinder(verts, faces, x, y, z, radius, height, segments=12, axis='Z'):
    """Add a cylinder (axis = 'Z' default) to verts/faces lists."""
    import math
    base = len(verts)
    half = height / 2
    for j in (0, 1):  # bottom, top
        zz = z + (-half if j == 0 else half)
        for i in range(segments):
            ang = (i / segments) * math.tau
            verts.append((x + radius * math.cos(ang), y + radius * math.sin(ang), zz))
    for i in range(segments):
        a = base + i
        b = base + (i + 1) % segments
        c = base + segments + (i + 1) % segments
        d = base + segments + i
        faces.append([a, b, c, d])


def sverchok_railing():
    """🛡 Architectural railing — N balusters + top + bottom rails, grid-snappable."""
    import math
    length = 6.0
    n_balusters = 20
    rail_height = 1.0
    rail_thickness = 0.08
    baluster_radius = 0.05

    verts = []
    faces = []

    # Top rail
    _cube_face(verts, 0, 0, rail_height, length, rail_thickness * 1.2, rail_thickness)
    # Bottom rail (small lip near floor)
    _cube_face(verts, 0, 0, 0.06, length, rail_thickness, 0.08)

    # Balusters
    for i in range(n_balusters):
        x = -length / 2 + (i + 0.5) * (length / n_balusters)
        _add_cylinder(verts, faces, x, 0, rail_height / 2, baluster_radius, rail_height, segments=8)

    # Faces for top/bottom rails (cube faces from _cube_face)
    # We need to actually capture those — let me regen them via from_pydata directly
    me_verts = []
    me_faces = []
    # Top rail (cube)
    base = len(me_verts)
    hx, hy, hz = length/2, rail_thickness*0.6, rail_thickness/2
    z = rail_height
    me_verts.extend([
        (-hx,-hy,z-hz),(hx,-hy,z-hz),(hx,hy,z-hz),(-hx,hy,z-hz),
        (-hx,-hy,z+hz),(hx,-hy,z+hz),(hx,hy,z+hz),(-hx,hy,z+hz),
    ])
    me_faces.extend([
        [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
        [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
        [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
    ])
    # Bottom rail
    base = len(me_verts)
    hx, hy, hz = length/2, rail_thickness/2, 0.04
    z = 0.06
    me_verts.extend([
        (-hx,-hy,z-hz),(hx,-hy,z-hz),(hx,hy,z-hz),(-hx,hy,z-hz),
        (-hx,-hy,z+hz),(hx,-hy,z+hz),(hx,hy,z+hz),(-hx,hy,z+hz),
    ])
    me_faces.extend([
        [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
        [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
        [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
    ])
    # Balusters
    for i in range(n_balusters):
        x = -length / 2 + (i + 0.5) * (length / n_balusters)
        _add_cylinder(me_verts, me_faces, x, 0, rail_height / 2, baluster_radius, rail_height, segments=8)

    def build(tree):
        line = tree.nodes.new('SvLineNodeMK4'); line.location = (0, 0); line.label = "BalusterCount"
        try:
            for s in line.inputs:
                if s.name == 'Num': _sv_set_value(s, n_balusters)
                elif s.name == 'Size': _sv_set_value(s, length)
        except Exception: pass
        cyl = tree.nodes.new('SvCylinderNodeMK2'); cyl.location = (300, 0); cyl.label = "BalusterShape"
        try:
            for s in cyl.inputs:
                if s.name == 'RadiusT': _sv_set_value(s, baluster_radius)
                elif s.name == 'RadiusB': _sv_set_value(s, baluster_radius)
                elif s.name == 'Height': _sv_set_value(s, rail_height)
                elif s.name == 'Meridians': _sv_set_value(s, 8)
        except Exception: pass
    _spawn_companion_tree("Railing", build)

    return _spawn_mesh_from_data("EscherRailing", me_verts, [], me_faces)


def sverchok_curved_wall():
    """🌙 Curved wall section (arc-shaped) — snaps along a grid."""
    import math
    radius = 4.0
    sweep_deg = 90.0
    sweep = math.radians(sweep_deg)
    segments = 16
    height = 3.0
    thickness = 0.2

    verts = []
    faces = []
    # Generate inner and outer arc vertices at top and bottom
    for j in (0, 1):  # bottom, top
        z = j * height
        for i in range(segments + 1):
            t = i / segments
            ang = -sweep / 2 + t * sweep
            # Outer
            verts.append(((radius + thickness/2) * math.cos(ang), (radius + thickness/2) * math.sin(ang), z))
        for i in range(segments + 1):
            t = i / segments
            ang = -sweep / 2 + t * sweep
            # Inner
            verts.append(((radius - thickness/2) * math.cos(ang), (radius - thickness/2) * math.sin(ang), z))

    stride = (segments + 1) * 2  # verts per layer (outer+inner)
    # Outer face strip (bottom-outer → top-outer)
    for i in range(segments):
        a = i
        b = i + 1
        c = stride + i + 1
        d = stride + i
        faces.append([a, b, c, d])
    # Inner face strip
    inner_offset = segments + 1
    for i in range(segments):
        a = inner_offset + i + 1
        b = inner_offset + i
        c = stride + inner_offset + i
        d = stride + inner_offset + i + 1
        faces.append([a, b, c, d])
    # Top cap
    for i in range(segments):
        a = stride + i
        b = stride + i + 1
        c = stride + inner_offset + i + 1
        d = stride + inner_offset + i
        faces.append([a, b, c, d])
    # Bottom cap
    for i in range(segments):
        a = i + 1
        b = i
        c = inner_offset + i
        d = inner_offset + i + 1
        faces.append([a, b, c, d])
    # End caps (left and right)
    # Left (i=0)
    faces.append([0, inner_offset, stride + inner_offset, stride])
    # Right (i=segments)
    faces.append([segments, stride + segments, stride + inner_offset + segments, inner_offset + segments])

    def build(tree):
        cyl = tree.nodes.new('SvCylinderNodeMK2'); cyl.location = (0, 0); cyl.label = "CurvedWall"
        try:
            for s in cyl.inputs:
                if s.name == 'RadiusT': _sv_set_value(s, radius)
                elif s.name == 'RadiusB': _sv_set_value(s, radius)
                elif s.name == 'Height': _sv_set_value(s, height)
        except Exception: pass
    _spawn_companion_tree("CurvedWall", build)

    return _spawn_mesh_from_data("EscherCurvedWall", verts, [], faces)


def sverchok_floor_panel():
    """🟫 Floor panel — quad grid for game-engine snapping."""
    import math
    size = 2.0  # 2m × 2m (matches level grid)
    subdivs = 4
    thickness = 0.05

    verts = []
    faces = []
    # Top surface grid
    s = subdivs + 1
    for j in range(s):
        for i in range(s):
            x = -size / 2 + (i / subdivs) * size
            y = -size / 2 + (j / subdivs) * size
            verts.append((x, y, thickness))
    # Bottom surface grid
    bottom_off = s * s
    for j in range(s):
        for i in range(s):
            x = -size / 2 + (i / subdivs) * size
            y = -size / 2 + (j / subdivs) * size
            verts.append((x, y, 0.0))

    # Top faces
    for j in range(subdivs):
        for i in range(subdivs):
            a = j * s + i
            b = j * s + i + 1
            c = (j + 1) * s + i + 1
            d = (j + 1) * s + i
            faces.append([a, b, c, d])
    # Bottom faces (reversed)
    for j in range(subdivs):
        for i in range(subdivs):
            a = bottom_off + j * s + i
            b = bottom_off + (j + 1) * s + i
            c = bottom_off + (j + 1) * s + i + 1
            d = bottom_off + j * s + i + 1
            faces.append([a, b, c, d])
    # Edge ring faces (top to bottom)
    for i in range(subdivs):  # bottom edge (j=0)
        a = i
        b = i + 1
        c = bottom_off + i + 1
        d = bottom_off + i
        faces.append([a, d, c, b])
    for i in range(subdivs):  # top edge (j=subdivs)
        a = subdivs * s + i
        b = subdivs * s + i + 1
        c = bottom_off + subdivs * s + i + 1
        d = bottom_off + subdivs * s + i
        faces.append([a, b, c, d])
    for j in range(subdivs):  # left edge (i=0)
        a = j * s
        b = (j + 1) * s
        c = bottom_off + (j + 1) * s
        d = bottom_off + j * s
        faces.append([a, b, c, d])
    for j in range(subdivs):  # right edge (i=subdivs)
        a = j * s + subdivs
        b = bottom_off + j * s + subdivs
        c = bottom_off + (j + 1) * s + subdivs
        d = (j + 1) * s + subdivs
        faces.append([a, b, c, d])

    def build(tree):
        grid = tree.nodes.new('SvPolygonGridNode'); grid.location = (0, 0); grid.label = "FloorGrid"
        try:
            for s in grid.inputs:
                if s.name == 'Radius': _sv_set_value(s, size / 2)
                elif s.name == 'NumX': _sv_set_value(s, subdivs)
                elif s.name == 'NumY': _sv_set_value(s, subdivs)
        except Exception: pass
    _spawn_companion_tree("FloorPanel", build)

    return _spawn_mesh_from_data("EscherFloorPanel", verts, [], faces)


def sverchok_balcony():
    """🌿 Balcony — slab + railing on 3 sides."""
    import math
    W, D, T = 2.5, 0.8, 0.12
    rail_h = 0.9
    baluster_r = 0.05

    verts = []
    faces = []
    # Slab
    base = len(verts)
    hx, hy, hz = W/2, D/2, T/2
    verts.extend([
        (-hx,-hy,-hz+T/2),(hx,-hy,-hz+T/2),(hx,hy,-hz+T/2),(-hx,hy,-hz+T/2),
        (-hx,-hy,hz+T/2),(hx,-hy,hz+T/2),(hx,hy,hz+T/2),(-hx,hy,hz+T/2),
    ])
    faces.extend([
        [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
        [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
        [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
    ])
    # Front railing balusters (along +Y edge)
    n_front = 8
    for i in range(n_front):
        x = -W/2 + (i + 0.5) * (W / n_front)
        _add_cylinder(verts, faces, x, D/2 - 0.04, T + rail_h/2, baluster_r, rail_h, segments=8)
    # Front top rail
    base = len(verts)
    hx, hy, hz = W/2, 0.05, 0.04
    cx, cy, cz = 0, D/2 - 0.04, T + rail_h
    verts.extend([
        (cx-hx,cy-hy,cz-hz),(cx+hx,cy-hy,cz-hz),(cx+hx,cy+hy,cz-hz),(cx-hx,cy+hy,cz-hz),
        (cx-hx,cy-hy,cz+hz),(cx+hx,cy-hy,cz+hz),(cx+hx,cy+hy,cz+hz),(cx-hx,cy+hy,cz+hz),
    ])
    faces.extend([
        [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
        [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
        [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
    ])
    # Side railings (smaller)
    for side in (-1, 1):
        n_side = 3
        for i in range(n_side):
            y = (i + 0.5) * (D - 0.08) / n_side - (D - 0.08) / 2
            _add_cylinder(verts, faces, side * (W/2 - 0.04), y, T + rail_h/2, baluster_r, rail_h, segments=8)
        # Side top rail
        base = len(verts)
        hx, hy, hz = 0.05, (D - 0.08)/2, 0.04
        cx, cy, cz = side * (W/2 - 0.04), 0, T + rail_h
        verts.extend([
            (cx-hx,cy-hy,cz-hz),(cx+hx,cy-hy,cz-hz),(cx+hx,cy+hy,cz-hz),(cx-hx,cy+hy,cz-hz),
            (cx-hx,cy-hy,cz+hz),(cx+hx,cy-hy,cz+hz),(cx+hx,cy+hy,cz+hz),(cx-hx,cy+hy,cz+hz),
        ])
        faces.extend([
            [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
            [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
            [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
        ])

    def build(tree):
        ng = tree.nodes.new('SvNGonNode'); ng.location = (0, 0); ng.label = "BalconySlab"
        try:
            for s in ng.inputs:
                if s.name == 'Radius': _sv_set_value(s, W/2)
                elif s.name == 'N Sides': _sv_set_value(s, 4)
        except Exception: pass
    _spawn_companion_tree("Balcony", build)

    return _spawn_mesh_from_data("EscherBalcony", verts, [], faces)


def sverchok_gothic_arch():
    """✟ Gothic pointed arch — two intersecting circle arcs meeting at peak."""
    import math
    W = 2.0      # arch width
    R = 1.5      # arc radius (R > W/2 = sharper Gothic peak)
    thickness = 0.12
    segments = 24

    half_W = W / 2
    peak_angle = math.acos(min(1.0, max(-1.0, (R - half_W) / R)))

    verts = []
    edges = []
    faces = []

    # Right arc — center at (-half_W + R, 0), sweep from (half_W, 0) up to peak (0, peak_height)
    cx_r = -half_W + R
    n = segments
    right_outer_top = []
    right_inner_top = []
    for i in range(n + 1):
        t = i / n
        ang = math.pi - peak_angle * t  # from π (left of center) sweeping right to π - peak_angle (toward peak)
        # Wait — we want from (half_W, 0) to (0, peak_height)
        # Let me reparameterize: angle from -peak_angle to 0 around center (cx_r)
        # At angle 0: point is (cx_r + R, 0) = ... that's not quite right.
        # Actually: the right arc starts at (half_W, 0) which from (cx_r, 0) is at angle 0
        # and sweeps up to angle peak_angle, landing at the peak
        ang = peak_angle * t
        ox = cx_r + R * math.cos(ang)
        oy = R * math.sin(ang)
        right_outer_top.append((ox, oy))

    # Inner edge (slightly tighter radius)
    R_in = R - thickness
    for i in range(n + 1):
        t = i / n
        ang = peak_angle * t
        ix = cx_r + R_in * math.cos(ang)
        iy = R_in * math.sin(ang)
        right_inner_top.append((ix, iy))

    # Mirror for left arc — center at (half_W - R, 0)
    cx_l = half_W - R
    left_outer_top = []
    left_inner_top = []
    for i in range(n + 1):
        t = i / n
        ang = math.pi - peak_angle * t  # from π to π - peak_angle
        ox = cx_l + R * math.cos(ang)
        oy = R * math.sin(ang)
        left_outer_top.append((ox, oy))
        ix = cx_l + R_in * math.cos(ang)
        iy = R_in * math.sin(ang)
        left_inner_top.append((ix, iy))

    # Build verts in XZ plane (treat the 2D y as Z) with thickness depth in Y
    depth = 0.2  # depth of arch in Y direction

    def push_arc_band(outer_2d, inner_2d):
        """Push 4 verts per arc-segment (outer front, outer back, inner front, inner back)."""
        base = len(verts)
        for (ox, oy), (ix, iy) in zip(outer_2d, inner_2d):
            verts.append((ox, -depth/2, oy))
            verts.append((ox,  depth/2, oy))
            verts.append((ix, -depth/2, iy))
            verts.append((ix,  depth/2, iy))
        return base

    rbase = push_arc_band(right_outer_top, right_inner_top)
    lbase = push_arc_band(left_outer_top, left_inner_top)

    # Build faces — front (outer), back (outer), front (inner), back (inner), top, bottom
    def make_faces(base, n_pts):
        # Each step has 4 verts; pattern: i*4 + (0:OF, 1:OB, 2:IF, 3:IB)
        for i in range(n_pts - 1):
            v0 = base + i * 4
            v1 = base + (i + 1) * 4
            # Outer face strip (front + back)
            faces.append([v0 + 0, v1 + 0, v1 + 1, v0 + 1])  # outer side
            # Inner face strip
            faces.append([v0 + 3, v1 + 3, v1 + 2, v0 + 2])  # inner side
            # Top (outer-front to inner-front)
            faces.append([v0 + 2, v1 + 2, v1 + 0, v0 + 0])  # front cap
            # Bottom
            faces.append([v0 + 1, v1 + 1, v1 + 3, v0 + 3])  # back cap

    make_faces(rbase, n + 1)
    make_faces(lbase, n + 1)

    def build(tree):
        ngon = tree.nodes.new('SvNGonNode'); ngon.location = (0, 0); ngon.label = "GothicArch"
    _spawn_companion_tree("GothicArch", build)

    return _spawn_mesh_from_data("EscherGothicArch", verts, [], faces)


def sverchok_rose_window():
    """❀ Rose window — outer ring + N radial petals + inner circle."""
    import math
    R_outer = 1.5
    R_inner = 0.3
    petal_R = 0.4
    n_petals = 8
    thickness = 0.05

    verts = []
    edges = []

    # Build the outer ring as a closed curve
    seg_outer = 48
    for j in range(2):
        z_off = -thickness/2 if j == 0 else thickness/2
        # Outer ring outer edge
        for i in range(seg_outer):
            ang = (i / seg_outer) * math.tau
            verts.append((R_outer * math.cos(ang), z_off, R_outer * math.sin(ang)))

    seg_inner = 16
    inner_base = len(verts)
    for j in range(2):
        z_off = -thickness/2 if j == 0 else thickness/2
        for i in range(seg_inner):
            ang = (i / seg_inner) * math.tau
            verts.append((R_inner * math.cos(ang), z_off, R_inner * math.sin(ang)))

    # Petals: small circles arrayed
    petal_dist = (R_outer + R_inner) / 2 + 0.1
    seg_petal = 16
    for p in range(n_petals):
        pang = (p / n_petals) * math.tau
        cx = petal_dist * math.cos(pang)
        cz = petal_dist * math.sin(pang)
        for j in range(2):
            z_off = -thickness/2 if j == 0 else thickness/2
            for i in range(seg_petal):
                ang = (i / seg_petal) * math.tau
                verts.append((cx + petal_R * math.cos(ang), z_off, cz + petal_R * math.sin(ang)))

    # Build edges as line strips (decorative — won't fill faces for thin ring shapes)
    def add_ring_edges(start, count):
        for i in range(count):
            edges.append((start + i, start + (i + 1) % count))
            # Connect bottom to top
            edges.append((start + i, start + count + i))
            edges.append((start + count + i, start + count + (i + 1) % count))

    add_ring_edges(0, seg_outer)
    add_ring_edges(inner_base, seg_inner)
    petal_start = inner_base + seg_inner * 2
    for p in range(n_petals):
        add_ring_edges(petal_start + p * seg_petal * 2, seg_petal)

    def build(tree):
        circ = tree.nodes.new('SvCircleNode'); circ.location = (0, 0); circ.label = "OuterRing"
        try:
            for s in circ.inputs:
                if s.name == 'Radius': _sv_set_value(s, R_outer)
                elif s.name.lower().startswith('num'): _sv_set_value(s, seg_outer)
        except Exception: pass
    _spawn_companion_tree("RoseWindow", build)

    return _spawn_mesh_from_data("EscherRoseWindow", verts, edges, [])


def sverchok_spiral_staircase():
    """🪜 Spiral staircase — N steps arrayed helically around a central column."""
    import math
    n_steps = 16
    step_rise = 0.22
    step_depth = 0.4
    step_width = 1.2
    spiral_deg = 25.0  # degrees per step
    center_radius = 0.3  # central column radius

    verts = []
    faces = []

    # Central column
    _add_cylinder(verts, faces, 0, 0, n_steps * step_rise / 2,
                  center_radius, n_steps * step_rise, segments=12)

    # Step blocks arranged helically
    inner_radius = center_radius + 0.05
    outer_radius = inner_radius + step_depth
    for i in range(n_steps):
        ang = math.radians(i * spiral_deg)
        z = (i + 0.5) * step_rise
        # Step center
        cx = (inner_radius + step_depth/2) * math.cos(ang)
        cy = (inner_radius + step_depth/2) * math.sin(ang)
        # Build a small step block — rotated cube
        base = len(verts)
        hx, hy, hz = step_depth / 2, step_width / 2, step_rise * 0.45
        # 8 corners in step-local space
        local = [
            (-hx,-hy,-hz),(hx,-hy,-hz),(hx,hy,-hz),(-hx,hy,-hz),
            (-hx,-hy, hz),(hx,-hy, hz),(hx,hy, hz),(-hx,hy, hz),
        ]
        c, s = math.cos(ang), math.sin(ang)
        for lx, ly, lz in local:
            wx = cx + lx * c - ly * s
            wy = cy + lx * s + ly * c
            wz = z + lz
            verts.append((wx, wy, wz))
        faces.extend([
            [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
            [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
            [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
        ])

    def build(tree):
        sp = tree.nodes.new('SvSpiralNodeMK2'); sp.location = (0, 0); sp.label = "Helix"
        try:
            for s in sp.inputs:
                if s.name == 'R': _sv_set_value(s, outer_radius)
                elif s.name == 'r': _sv_set_value(s, inner_radius)
                elif s.name == 't': _sv_set_value(s, n_steps * spiral_deg / 360)
                elif s.name == 's': _sv_set_value(s, step_rise * 360 / spiral_deg)
        except Exception: pass
    _spawn_companion_tree("SpiralStaircase", build)

    return _spawn_mesh_from_data("EscherSpiralStaircase", verts, [], faces)


# ============================================================
# DARK SOULS × ESCHER  —  filigree, ornament, twisted spires
# ============================================================

def sverchok_filigree_scrollwork():
    """🌿 Filigree scrollwork — pair of opposing spiral curls connected by a stem.
    Classic gothic decorative band motif: ornament that tiles along edges.
    """
    import math
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    length = 4.0 * scale_mult
    n_units = max(2, int(6 * complexity_mult))
    curl_turns = 1.5 * complexity_mult
    curl_r_min, curl_r_max = 0.04, 0.20
    profile_r = 0.025            # tube thickness
    seg = 16

    verts = []
    edges = []

    def spiral_curl(cx, cy, sign, samples=48):
        """Generate a 2D log-spiral curl, sign=+1 outward, -1 inward."""
        pts = []
        for i in range(samples):
            t = (i / (samples - 1)) * curl_turns * math.tau
            r = curl_r_min + (curl_r_max - curl_r_min) * (t / (curl_turns * math.tau))
            x = cx + sign * r * math.cos(t)
            y = cy + r * math.sin(t)
            pts.append((x, y))
        return pts

    def tube_from_path(path2d, base_z=0.0):
        """Sweep a circle profile along a 2D path (in XZ plane)."""
        base_idx = len(verts)
        m = len(path2d)
        # Build cross-section rings
        for i, (px, py) in enumerate(path2d):
            # Approx tangent via neighbor
            if i < m - 1:
                nx, ny = path2d[i + 1]
                tx, ty = nx - px, ny - py
            else:
                ox, oy = path2d[i - 1]
                tx, ty = px - ox, py - oy
            tl = math.hypot(tx, ty) or 1.0
            tx, ty = tx / tl, ty / tl
            # Build 4-vert square cross-section perpendicular to tangent (in XZ)
            for k in range(seg):
                ang = (k / seg) * math.tau
                # Local profile circle in plane perpendicular to (tx, ty)
                # In our XZ context, depth is Y axis
                offx = profile_r * math.cos(ang) * (-ty)
                offy = profile_r * math.sin(ang)
                offz = profile_r * math.cos(ang) * tx
                verts.append((px + offx, offy, base_z + py + offz))
        for i in range(m - 1):
            for k in range(seg):
                a = base_idx + i * seg + k
                b = base_idx + i * seg + (k + 1) % seg
                c = base_idx + (i + 1) * seg + (k + 1) % seg
                d = base_idx + (i + 1) * seg + k
                edges.append((a, b))
                edges.append((a, d))
        return base_idx

    unit_w = length / n_units
    height_band = curl_r_max * 2 + 0.05
    for i in range(n_units):
        cx = -length / 2 + (i + 0.5) * unit_w
        # Left curl spirals inward toward unit center; right curl mirrors
        left_path = spiral_curl(cx - unit_w * 0.3, 0, +1)
        right_path = spiral_curl(cx + unit_w * 0.3, 0, -1)
        # Reverse right path so they meet
        right_path = list(reversed(right_path))
        # Combine into one S-curve path
        full_path = left_path + right_path
        tube_from_path(full_path)

    def build(tree):
        sp = tree.nodes.new('SvSpiralNodeMK2'); sp.label = "Curl"
        try:
            for s in sp.inputs:
                if s.name == 'R': _sv_set_value(s, curl_r_max)
                elif s.name == 'r': _sv_set_value(s, curl_r_min)
                elif s.name == 't': _sv_set_value(s, curl_turns)
        except Exception: pass
    _spawn_companion_tree("Filigree", build)

    return _spawn_mesh_from_data("EscherFiligree", verts, edges, [])


def sverchok_trefoil_frieze():
    """☘ Trefoil ornament frieze — repeating 3-lobed pattern band.
    Used as decoration along arches, walls, cornices.
    """
    import math
    length = 4.0
    n_trefoils = 6
    lobe_r = 0.15
    profile_r = 0.03
    seg = 20

    verts = []
    edges = []
    unit_w = length / n_trefoils

    for i in range(n_trefoils):
        cx = -length / 2 + (i + 0.5) * unit_w
        # 3 lobes arranged in a triangle pointing up
        for lobe in range(3):
            ang_offset = lobe * math.tau / 3 + math.pi / 2
            lx = cx + (lobe_r * 0.8) * math.cos(ang_offset)
            ly = (lobe_r * 0.8) * math.sin(ang_offset)
            # Build a closed circle (lobe)
            base = len(verts)
            for k in range(seg):
                ang = (k / seg) * math.tau
                # Circle in XZ plane
                px = lx + lobe_r * math.cos(ang)
                pz = ly + lobe_r * math.sin(ang)
                verts.append((px, 0.0, pz))
                verts.append((px, profile_r * 2, pz))  # thickness
            for k in range(seg):
                a = base + k * 2
                b = base + ((k + 1) % seg) * 2
                edges.append((a, b))
                edges.append((a + 1, b + 1))
                edges.append((a, a + 1))

    def build(tree):
        ng = tree.nodes.new('SvNGonNode'); ng.label = "Trefoil"
        try:
            for s in ng.inputs:
                if s.name == 'Radius': _sv_set_value(s, lobe_r)
                elif s.name == 'N Sides': _sv_set_value(s, 3)
        except Exception: pass
    _spawn_companion_tree("TrefoilFrieze", build)

    return _spawn_mesh_from_data("EscherTrefoilFrieze", verts, edges, [])


def sverchok_twisted_spire():
    """🗼 Twisted gothic spire — Dark Souls' iconic broken pinnacle.
    Multiple twisted cylinders nested with decreasing radius, gradually rotating.
    """
    import math
    res_mult, scale_mult, complexity_mult, phase = _sv_params()
    height = 6.0 * scale_mult
    rings = max(6, int(12 * res_mult))
    base_radius = 0.6 * scale_mult
    top_radius = 0.05 * scale_mult
    # Music: twist + petal count modulated
    spiral_turns = 1.5 * complexity_mult * (1.0 + phase * 0.4)
    n_around = max(8, int(16 * res_mult))
    petals = max(4, int(8 * complexity_mult))

    verts = []
    faces = []

    for r in range(rings + 1):
        t = r / rings
        radius = base_radius + (top_radius - base_radius) * (t ** 1.3)  # ease-out
        z = t * height
        rot_offset = t * spiral_turns * math.tau
        # Build N points around, with petals as radial bumps
        for k in range(n_around):
            ang = (k / n_around) * math.tau + rot_offset
            # Add petal bump using cos(petals * ang)
            petal_amt = (1.0 + 0.18 * math.cos(petals * ang)) if r < rings else 1.0
            rr = radius * petal_amt
            verts.append((rr * math.cos(ang), rr * math.sin(ang), z))

    for r in range(rings):
        for k in range(n_around):
            a = r * n_around + k
            b = r * n_around + (k + 1) % n_around
            c = (r + 1) * n_around + (k + 1) % n_around
            d = (r + 1) * n_around + k
            faces.append([a, b, c, d])

    # Crowning finial — small sphere
    top_base = len(verts)
    finial_segs = 12
    for j in range(finial_segs + 1):
        phi = j / finial_segs * math.pi
        rr = top_radius * math.sin(phi)
        zz = height + top_radius * 0.3 + top_radius * (1 - math.cos(phi))
        for k in range(8):
            ang = (k / 8) * math.tau
            verts.append((rr * math.cos(ang), rr * math.sin(ang), zz))

    def build(tree):
        sp = tree.nodes.new('SvCylinderNodeMK2'); sp.label = "TwistedSpire"
        try:
            for s in sp.inputs:
                if s.name == 'RadiusT': _sv_set_value(s, top_radius)
                elif s.name == 'RadiusB': _sv_set_value(s, base_radius)
                elif s.name == 'Height': _sv_set_value(s, height)
                elif s.name == 'Twist': _sv_set_value(s, spiral_turns * math.tau)
        except Exception: pass
    _spawn_companion_tree("TwistedSpire", build)

    return _spawn_mesh_from_data("EscherTwistedSpire", verts, [], faces)


def sverchok_cathedral_ruin():
    """🏚 Cathedral ruin — partial gothic structure with broken arches.
    Generates a sequence of pointed arches, some "broken" (missing top half),
    forming a Dark-Souls-style ruined hallway.
    """
    import math
    import random
    res_mult, scale_mult, complexity_mult, _phase = _sv_params()
    obj = bpy.context.active_object
    seed = getattr(obj.surreal_arch_props, 'sv_seed', 42) if (obj and hasattr(obj, 'surreal_arch_props')) else 42
    rng = random.Random(seed)
    n_bays = max(3, int(6 * complexity_mult))
    bay_width = 1.6 * scale_mult
    arch_R = 1.5 * scale_mult
    height = 3.5 * scale_mult

    verts = []
    faces = []

    half_W = bay_width / 2
    peak_angle = math.acos(min(1.0, max(-1.0, (arch_R - half_W) / arch_R)))

    def add_gothic_arch_at(cx, has_top=True, break_pct=1.0):
        # Right arc center at (-half_W + arch_R, 0), Left mirror
        cx_r = -half_W + arch_R
        cx_l = half_W - arch_R
        n_arc = 18
        n_used = max(2, int(n_arc * break_pct))
        thickness = 0.12

        def push_arc(center_x_local, dir_sign):
            base = len(verts)
            for i in range(n_used + 1):
                t = i / n_arc  # use full range so break_pct < 1.0 truncates
                ang = peak_angle * t
                ox = center_x_local + arch_R * math.cos(ang * dir_sign + (0 if dir_sign > 0 else math.pi))
                oz = arch_R * math.sin(ang * dir_sign + (0 if dir_sign > 0 else math.pi))
                if dir_sign < 0:
                    oz = abs(oz)
                # Build double-walled depth
                for j in (-thickness/2, thickness/2):
                    verts.append((cx + ox - center_x_local + (cx_r if dir_sign > 0 else cx_l), j, oz))
            return base

        # Simpler: just draw the right arc as a polyline
        for dir_sign in (+1, -1):
            base = len(verts)
            for i in range(n_used + 1):
                t = i / n_arc
                ang = peak_angle * t
                if dir_sign > 0:
                    px = cx + cx_r + arch_R * math.cos(math.pi - ang)
                else:
                    px = cx + cx_l + arch_R * math.cos(ang)
                pz = arch_R * math.sin(ang)
                # Front/back vertices for thickness
                verts.append((px, -0.1, pz))
                verts.append((px,  0.1, pz))
            # Build face strip
            for i in range(n_used):
                a = base + i * 2
                b = base + i * 2 + 1
                c = base + (i + 1) * 2 + 1
                d = base + (i + 1) * 2
                faces.append([a, b, c, d])

        # Vertical columns (pillars) at base
        for col_x_off in (-half_W, half_W):
            base = len(verts)
            col_w = 0.22
            verts.extend([
                (cx + col_x_off - col_w/2, -col_w/2, 0),
                (cx + col_x_off + col_w/2, -col_w/2, 0),
                (cx + col_x_off + col_w/2,  col_w/2, 0),
                (cx + col_x_off - col_w/2,  col_w/2, 0),
                (cx + col_x_off - col_w/2, -col_w/2, height),
                (cx + col_x_off + col_w/2, -col_w/2, height),
                (cx + col_x_off + col_w/2,  col_w/2, height),
                (cx + col_x_off - col_w/2,  col_w/2, height),
            ])
            faces.extend([
                [base, base+1, base+2, base+3],
                [base+4, base+7, base+6, base+5],
                [base, base+4, base+5, base+1],
                [base+1, base+5, base+6, base+2],
                [base+2, base+6, base+7, base+3],
                [base+3, base+7, base+4, base],
            ])

    for i in range(n_bays):
        cx = -n_bays * bay_width / 2 + (i + 0.5) * bay_width
        # Some bays are broken (top missing)
        break_pct = 1.0 if rng.random() > 0.4 else rng.uniform(0.3, 0.8)
        add_gothic_arch_at(cx, has_top=(break_pct > 0.7), break_pct=break_pct)

    def build(tree):
        ng = tree.nodes.new('SvNGonNode'); ng.label = "CathedralRuin"
    _spawn_companion_tree("CathedralRuin", build)

    return _spawn_mesh_from_data("EscherCathedralRuin", verts, [], faces)


def sverchok_branching_buttress():
    """🌳 Branching buttress — Y-shaped support that branches like a tree.
    Recursive branching = AAA gothic detail. Each branch can branch again.
    """
    import math
    res_mult, scale_mult, complexity_mult, phase = _sv_params()
    depth = max(1, min(4, int(round(3 * complexity_mult))))
    trunk_h = 2.0 * scale_mult
    # Music: branch angle modulated → wider/narrower spreads on the beat
    branch_angle = math.radians(35 * (1.0 + phase * 0.5))
    branch_length_ratio = 0.65
    trunk_r = 0.18 * scale_mult
    r_ratio = 0.7

    verts = []
    faces = []

    def add_segment(x0, y0, z0, x1, y1, z1, radius, segments=8):
        """Add a cylinder between two points."""
        dx, dy, dz = x1 - x0, y1 - y0, z1 - z0
        length = math.sqrt(dx*dx + dy*dy + dz*dz)
        if length < 1e-4: return
        # Direction unit vector
        ux, uy, uz = dx/length, dy/length, dz/length
        # Pick a perpendicular axis (avoid degenerate)
        if abs(uz) < 0.9:
            ax, ay, az = 0, 0, 1
        else:
            ax, ay, az = 1, 0, 0
        # Cross product for first perpendicular
        px = uy * az - uz * ay
        py = uz * ax - ux * az
        pz = ux * ay - uy * ax
        pl = math.sqrt(px*px + py*py + pz*pz) or 1
        px, py, pz = px/pl, py/pl, pz/pl
        # Second perpendicular = u × p
        qx = uy * pz - uz * py
        qy = uz * px - ux * pz
        qz = ux * py - uy * px
        base = len(verts)
        for j, (cx, cy, cz) in enumerate([(x0,y0,z0), (x1,y1,z1)]):
            for k in range(segments):
                ang = (k / segments) * math.tau
                ox = radius * (math.cos(ang) * px + math.sin(ang) * qx)
                oy = radius * (math.cos(ang) * py + math.sin(ang) * qy)
                oz = radius * (math.cos(ang) * pz + math.sin(ang) * qz)
                verts.append((cx + ox, cy + oy, cz + oz))
        for k in range(segments):
            a = base + k
            b = base + (k + 1) % segments
            c = base + segments + (k + 1) % segments
            d = base + segments + k
            faces.append([a, b, c, d])

    def grow(x, y, z, dx, dy, dz, length, radius, depth_left):
        x1 = x + dx * length
        y1 = y + dy * length
        z1 = z + dz * length
        add_segment(x, y, z, x1, y1, z1, radius)
        if depth_left <= 0: return
        # Branch into 2 sub-branches
        # Rotate direction by ±branch_angle in the XZ plane (for visual planarity)
        c, s = math.cos(branch_angle), math.sin(branch_angle)
        # Branch A: rotate around Y axis
        bdx_a = dx * c - dz * s
        bdz_a = dx * s + dz * c
        # Branch B: rotate the other way
        bdx_b = dx * c + dz * s
        bdz_b = -dx * s + dz * c
        new_len = length * branch_length_ratio
        new_r = radius * r_ratio
        grow(x1, y1, z1, bdx_a, dy, bdz_a, new_len, new_r, depth_left - 1)
        grow(x1, y1, z1, bdx_b, dy, bdz_b, new_len, new_r, depth_left - 1)

    grow(0, 0, 0, 0, 0, 1, trunk_h, trunk_r, depth)

    def build(tree):
        cyl = tree.nodes.new('SvCylinderNodeMK2'); cyl.label = "Trunk"
    _spawn_companion_tree("BranchingButtress", build)

    return _spawn_mesh_from_data("EscherBranchingButtress", verts, [], faces)


def sverchok_cascading_arches():
    """🌊 Cascading arches — Escher's stacked impossible arches descending.
    Each arch is smaller and offset, creating a "stairway in arches" feel.
    """
    import math
    n_arches = 6
    base_R = 1.5
    R_shrink = 0.82
    h_drop = 0.6        # how far each arch drops below the last
    h_offset_x = 0.45   # how far each arch shifts in X (perspective slip)
    thickness = 0.1

    verts = []
    faces = []

    def add_arch(cx, cz, R):
        """Half-circle arch."""
        n_seg = 18
        for i in range(n_seg + 1):
            t = i / n_seg
            ang = math.pi * t  # 0..π
            ox = cx + R * math.cos(ang)
            oz = cz + R * math.sin(ang)
            verts.append((ox, -thickness/2, oz))
            verts.append((ox,  thickness/2, oz))
        base = len(verts) - (n_seg + 1) * 2
        for i in range(n_seg):
            a = base + i * 2
            b = base + i * 2 + 1
            c = base + (i + 1) * 2 + 1
            d = base + (i + 1) * 2
            faces.append([a, b, c, d])

    cx, cz = 0, n_arches * h_drop
    R = base_R
    for i in range(n_arches):
        add_arch(cx, cz, R)
        cx += h_offset_x
        cz -= h_drop
        R *= R_shrink

    def build(tree):
        sp = tree.nodes.new('SvSpiralNodeMK2'); sp.label = "CascadingArches"
    _spawn_companion_tree("CascadingArches", build)

    return _spawn_mesh_from_data("EscherCascadingArches", verts, [], faces)


def sverchok_iron_gate():
    """🚪 Wrought-iron filigree gate — bars + S-curl ornaments.
    Vertical bars + horizontal cross-rails + decorative scrollwork.
    """
    import math
    W, H = 2.4, 3.0
    n_bars = 8
    bar_r = 0.025
    rail_w = 0.04

    verts = []
    faces = []

    # Frame (4 thin cubes around the perimeter)
    def push_bar(cx, cy, cz, sx, sy, sz):
        base = len(verts)
        hx, hy, hz = sx/2, sy/2, sz/2
        verts.extend([
            (cx-hx,cy-hy,cz-hz),(cx+hx,cy-hy,cz-hz),(cx+hx,cy+hy,cz-hz),(cx-hx,cy+hy,cz-hz),
            (cx-hx,cy-hy,cz+hz),(cx+hx,cy-hy,cz+hz),(cx+hx,cy+hy,cz+hz),(cx-hx,cy+hy,cz+hz),
        ])
        faces.extend([
            [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
            [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
            [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
        ])

    # Frame: top, bottom, left, right
    push_bar(0, 0, H - rail_w/2, W, rail_w, rail_w)
    push_bar(0, 0, rail_w/2, W, rail_w, rail_w)
    push_bar(-W/2 + rail_w/2, 0, H/2, rail_w, rail_w, H)
    push_bar( W/2 - rail_w/2, 0, H/2, rail_w, rail_w, H)
    # Middle cross-rail (for scrollwork to sit on)
    push_bar(0, 0, H * 0.55, W - rail_w*2, rail_w, rail_w)

    # Vertical bars
    for i in range(n_bars):
        x = -W/2 + (i + 0.5) * (W / n_bars)
        _add_cylinder(verts, faces, x, 0, H/2, bar_r, H, segments=6)

    # Decorative S-curl scrollwork in the top portion (between bars)
    def s_curl(cx, cz, scale, mirror=False):
        n_seg = 32
        sign = -1 if mirror else 1
        for i in range(n_seg):
            t = i / (n_seg - 1)
            # S-shape: two opposing curls
            ang = t * math.tau * 1.5  # 1.5 turns
            r = scale * (0.02 + 0.8 * abs(math.sin(t * math.pi)))
            px = cx + sign * r * math.cos(ang) * (1 - t * 0.5)
            pz = cz + r * math.sin(ang) - scale * 0.3
            verts.append((px, 0, pz))
            verts.append((px, rail_w, pz))
        base = len(verts) - n_seg * 2
        for i in range(n_seg - 1):
            a = base + i * 2
            b = base + i * 2 + 1
            c = base + (i + 1) * 2 + 1
            d = base + (i + 1) * 2
            faces.append([a, b, c, d])

    # Place S-curls in the top half
    for i in range(n_bars // 2):
        cx = -W/2 + (i * 2 + 1) * (W / n_bars)
        s_curl(cx, H * 0.78, 0.18, mirror=(i % 2 == 0))

    def build(tree):
        sp = tree.nodes.new('SvSpiralNodeMK2'); sp.label = "IronCurl"
    _spawn_companion_tree("IronGate", build)

    return _spawn_mesh_from_data("EscherIronGate", verts, [], faces)


def sverchok_hanging_chandelier():
    """💡 Hanging chandelier — branching arms with candle stubs.
    Dark Souls style: ring with radial arms, candles on top of each.
    """
    import math
    main_R = 1.0
    n_arms = 8
    arm_height = 0.5
    chain_length = 1.2

    verts = []
    faces = []

    # Chain (vertical rod from origin going up)
    _add_cylinder(verts, faces, 0, 0, chain_length / 2, 0.04, chain_length, segments=8)

    # Main ring (torus approximated as ring of cubes)
    z_ring = -arm_height
    for i in range(n_arms * 2):
        ang = (i / (n_arms * 2)) * math.tau
        x = main_R * math.cos(ang)
        y = main_R * math.sin(ang)
        # Small ring segment as a cylinder
        _add_cylinder(verts, faces, x, y, z_ring, 0.04, 0.25, segments=6)

    # Arms — radial small horizontal beams + vertical candle stubs at outer end
    for i in range(n_arms):
        ang = (i / n_arms) * math.tau
        # Outer point where candle sits
        ox = main_R * math.cos(ang)
        oy = main_R * math.sin(ang)
        # Candle (small cylinder pointing up)
        _add_cylinder(verts, faces, ox, oy, z_ring + 0.18, 0.05, 0.3, segments=8)
        # Flame (small cone via cylinder w/ small top)
        base = len(verts)
        for j in (0, 1):
            zz = z_ring + 0.3 + j * 0.12
            r = (0.04 if j == 0 else 0.0)
            for k in range(6):
                a = (k / 6) * math.tau
                if r < 1e-4:
                    verts.append((ox, oy, zz))
                else:
                    verts.append((ox + r * math.cos(a), oy + r * math.sin(a), zz))
        for k in range(6):
            a = base + k
            b = base + (k + 1) % 6
            faces.append([a, b, base + 6])

    def build(tree):
        ng = tree.nodes.new('SvNGonNode'); ng.label = "Chandelier"
    _spawn_companion_tree("Chandelier", build)

    return _spawn_mesh_from_data("EscherChandelier", verts, [], faces)


def sverchok_mobius_staircase():
    """♾ Möbius staircase — impossible stair that loops back on itself.
    Generates a Möbius strip parameterically with stairs sampled along it.
    """
    import math
    R = 2.0
    width = 0.6
    n_steps = 32
    step_h = 0.05

    verts = []
    faces = []

    # Möbius strip: P(u,v) = ((R + v*cos(u/2)) cos(u), (R + v*cos(u/2)) sin(u), v*sin(u/2))
    for j in range(n_steps + 1):
        u = (j / n_steps) * math.tau
        for k in range(2):
            v = (-1 + k * 2) * (width / 2)  # -w/2, +w/2
            x = (R + v * math.cos(u / 2)) * math.cos(u)
            y = (R + v * math.cos(u / 2)) * math.sin(u)
            z = v * math.sin(u / 2) + j * step_h * 0.2  # subtle stair rise
            verts.append((x, y, z))

    for j in range(n_steps):
        a = j * 2
        b = j * 2 + 1
        c = (j + 1) * 2 + 1
        d = (j + 1) * 2
        faces.append([a, b, c, d])

    # Add step blocks on the surface
    for j in range(n_steps):
        u = (j / n_steps) * math.tau
        # Centerline point
        cx = R * math.cos(u)
        cy = R * math.sin(u)
        cz = j * step_h * 0.2
        # Step block — a thin cube near the centerline
        base = len(verts)
        # Local tangent direction
        tx = -math.sin(u)
        ty = math.cos(u)
        # Radial normal
        nx = math.cos(u)
        ny = math.sin(u)
        block_w = width * 0.4
        block_l = (math.tau / n_steps) * R * 0.8
        for sz in (-step_h/2, step_h/2):
            for sw, sl in [(-1,-1),(-1,1),(1,1),(1,-1)]:
                px = cx + nx * block_w * sw / 2 + tx * block_l * sl / 2
                py = cy + ny * block_w * sw / 2 + ty * block_l * sl / 2
                pz = cz + sz + step_h * 1.2
                verts.append((px, py, pz))
        faces.extend([
            [base+0,base+1,base+2,base+3], [base+4,base+7,base+6,base+5],
            [base+0,base+4,base+5,base+1], [base+1,base+5,base+6,base+2],
            [base+2,base+6,base+7,base+3], [base+3,base+7,base+4,base+0],
        ])

    def build(tree):
        fm = tree.nodes.new('SvFormulaNodeMk5'); fm.label = "Mobius"
    _spawn_companion_tree("MobiusStaircase", build)

    return _spawn_mesh_from_data("EscherMobiusStaircase", verts, [], faces)


def sverchok_recursive_portal():
    """🌌 Recursive portal — pointed Gothic arch frame nested 3 deep (Droste effect)."""
    import math
    W_outer, H_outer = 2.0, 3.5
    thickness = 0.15
    n_levels = 3
    shrink = 0.55

    verts = []
    faces = []

    def push_arch_frame(cx, cz, W, H, thick):
        """Push a hollow Gothic-pointed arch frame around the opening."""
        # Outer profile: jambs + pointed top
        half_W = W / 2
        R = max(half_W + 0.01, half_W * 1.35)
        peak_angle = math.acos(min(1.0, max(-1.0, (R - half_W) / R)))
        n_arc = 16

        # Build closed outline points (going counterclockwise) for outer
        outer_pts = [(cx - half_W, cz)]   # bottom-left
        outer_pts.append((cx + half_W, cz))  # bottom-right
        outer_pts.append((cx + half_W, cz + H * 0.5))  # right shoulder
        # Right arc from shoulder to peak
        cx_r = -half_W + R
        for i in range(n_arc + 1):
            t = i / n_arc
            ang = peak_angle * t
            outer_pts.append((cx + cx_r + R * math.cos(math.pi - ang),
                              cz + H * 0.5 + R * math.sin(ang)))
        # Left arc back down
        cx_l = half_W - R
        for i in range(n_arc + 1):
            t = i / n_arc
            ang = peak_angle * (1 - t)
            outer_pts.append((cx + cx_l + R * math.cos(ang),
                              cz + H * 0.5 + R * math.sin(ang)))
        outer_pts.append((cx - half_W, cz + H * 0.5))  # left shoulder

        # Inner profile = outer shrunk by thick
        inner_pts = []
        for px, pz in outer_pts:
            dx = px - cx
            dz = pz - cz
            # Shrink toward center
            shrink_fac = max(0, 1 - thick / max(half_W, 0.1))
            inner_pts.append((cx + dx * shrink_fac, cz + dz * shrink_fac))

        # Build front + back faces (band geometry, double-sided depth)
        base = len(verts)
        depth = thick * 0.5
        # Outer ring x2 (front, back), inner ring x2 (front, back)
        for px, pz in outer_pts:
            verts.append((px, -depth, pz))
            verts.append((px,  depth, pz))
        outer_count = len(outer_pts)
        for px, pz in inner_pts:
            verts.append((px, -depth, pz))
            verts.append((px,  depth, pz))

        # Front face (outer-front to inner-front)
        for i in range(outer_count - 1):
            o0 = base + i * 2
            o1 = base + (i + 1) * 2
            i0 = base + (outer_count * 2) + i * 2
            i1 = base + (outer_count * 2) + (i + 1) * 2
            faces.append([o0, o1, i1, i0])  # front
            faces.append([o0 + 1, i0 + 1, i1 + 1, o1 + 1])  # back

    W, H = W_outer, H_outer
    thick = thickness
    cx, cz = 0, 0
    for lvl in range(n_levels):
        push_arch_frame(cx, cz, W, H, thick)
        W *= shrink
        H *= shrink
        thick *= 0.9
        cz += 0.1  # slight Z offset for visibility

    def build(tree):
        ng = tree.nodes.new('SvNGonNode'); ng.label = "RecursivePortal"
    _spawn_companion_tree("RecursivePortal", build)

    return _spawn_mesh_from_data("EscherRecursivePortal", verts, [], faces)


def sverchok_vault_ceiling():
    """⛪ Gothic cross-vault — 4-arch ceiling intersection."""
    import math
    span = 4.0          # ceiling square is span × span
    rise = 1.4          # vault peak height above edge
    segments = 16

    verts = []
    faces = []

    # Build as a grid; each grid vertex's Z is determined by the vault equation:
    # z = rise * min(sin(π·u), sin(π·v))  — barrel-vault intersection (cross-vault)
    n = segments
    for j in range(n + 1):
        v = j / n
        for i in range(n + 1):
            u = i / n
            x = -span / 2 + u * span
            y = -span / 2 + v * span
            # Cross-vault: take min of two perpendicular barrel vaults
            z = rise * min(math.sin(math.pi * u), math.sin(math.pi * v))
            verts.append((x, y, z))

    stride = n + 1
    for j in range(n):
        for i in range(n):
            a = j * stride + i
            b = j * stride + i + 1
            c = (j + 1) * stride + i + 1
            d = (j + 1) * stride + i
            faces.append([a, b, c, d])

    def build(tree):
        grid = tree.nodes.new('SvPolygonGridNode'); grid.location = (0, 0); grid.label = "VaultCeiling"
        try:
            for s in grid.inputs:
                if s.name == 'Radius': _sv_set_value(s, span / (2 * n))
                elif s.name == 'NumX': _sv_set_value(s, n)
                elif s.name == 'NumY': _sv_set_value(s, n)
        except Exception: pass
    _spawn_companion_tree("VaultCeiling", build)

    return _spawn_mesh_from_data("EscherVaultCeiling", verts, [], faces)


# === Sverchok Operators ===

def _make_sverchok_op(class_name, op_id, label, builder_fn):
    """Factory for Sverchok-spawning operators.

    Improvements in v2.22:
      • Per-call parameter dialog (invoke_props_dialog) so users tweak
        resolution / scale / complexity / seed BEFORE the mesh spawns.
      • Object → companion tree binding via obj["surreal_sv_tree"] custom
        property so Open Editor can jump straight to that object's tree.
      • Orphan Sverchok-bake cleanup so the kept-tree path doesn't spawn
        a duplicate object alongside the Python-computed mesh.
      • Robust error reporting with a traceback printed to console.
    """

    def invoke(self, context, event):
        # Pre-load the dialog defaults from the active object's current props
        active = context.active_object
        if active and hasattr(active, 'surreal_arch_props'):
            p = active.surreal_arch_props
            self.sv_resolution = float(getattr(p, 'sv_resolution', 1.0))
            self.sv_scale      = float(getattr(p, 'sv_scale', 1.0))
            self.sv_complexity = float(getattr(p, 'sv_complexity', 1.0))
            self.sv_seed       = int(getattr(p, 'sv_seed', 42))
            self.sv_keep_tree  = bool(getattr(p, 'sv_keep_tree', True))
        return context.window_manager.invoke_props_dialog(self, width=320)

    def draw_dialog(self, context):
        layout = self.layout
        layout.label(text=f"🌀 {label}", icon='NODETREE')
        col = layout.column(align=True)
        col.prop(self, 'sv_resolution')
        col.prop(self, 'sv_scale')
        col.prop(self, 'sv_complexity')
        col.prop(self, 'sv_seed')
        col.separator()
        col.prop(self, 'sv_keep_tree', icon='NODETREE')
        col.label(text="(Keep tree → editable Sverchok preset)", icon='INFO')
        col.separator()
        col.prop(self, 'sv_weld_after', icon='AUTOMERGE_ON')
        if getattr(self, 'sv_weld_after', True):
            col.prop(self, 'sv_weld_distance')

    def execute(self, context):
        # v2.46: Sverchok is OPTIONAL. The geometry is computed in pure Python
        # by the builder_fn. If Sverchok is missing, we skip the companion-tree
        # step and still spawn the Python-computed mesh.
        sverchok_ok = _sverchok_available()
        if not sverchok_ok:
            self.report({'INFO'},
                "Sverchok not detected — spawning Python-only (no editable tree)")
        # Snapshot pre-existing object names — used to detect orphan Sverchok
        # bakes that we should clean up after.
        pre_objs = set(bpy.data.objects.keys())
        # Resolve props source: prefer the active object's. Persist the
        # dialog values directly so the panel reflects what the user picked
        # (fixes snap-back-to-preset behavior reported in v2.22).
        global _SV_CURRENT_PROPS
        active = context.active_object
        _SV_CURRENT_PROPS = active.surreal_arch_props if (
            active and hasattr(active, 'surreal_arch_props')) else None
        if _SV_CURRENT_PROPS is not None:
            for k in ('sv_resolution', 'sv_scale', 'sv_complexity', 'sv_seed', 'sv_keep_tree'):
                try:
                    setattr(_SV_CURRENT_PROPS, k, getattr(self, k))
                except Exception:
                    pass
        try:
            obj = builder_fn()
            if obj is None:
                self.report({'WARNING'},
                            "Sverchok built tree but no mesh appeared — "
                            "open the Sverchok editor and toggle the viewer")
                return {'FINISHED'}
            # Stamp dialog params onto the spawned mesh
            if _SV_CURRENT_PROPS and hasattr(obj, 'surreal_arch_props'):
                for attr in ('sv_keep_tree', 'sv_resolution', 'sv_scale', 'sv_complexity',
                             'sv_music_response', 'sv_seed',
                             'universal_music_influence', 'musical_freq_a', 'musical_freq_b',
                             'musical_amplitude', 'tempo_factor'):
                    try:
                        setattr(obj.surreal_arch_props, attr,
                                getattr(_SV_CURRENT_PROPS, attr))
                    except Exception:
                        pass
            # Bind the companion tree to the spawned object so we can re-open it
            tree_name = f"_sv_{builder_fn.__name__.replace('sverchok_', '')}"
            tree = bpy.data.node_groups.get(tree_name)
            if tree is not None:
                obj["surreal_sv_tree"] = tree_name
                # Mirror so the tree knows which object it represents
                try:
                    tree["surreal_sv_object"] = obj.name
                except Exception:
                    pass
            # Clean up orphan Sverchok-baked meshes (Alpha/Beta/etc.) that
            # SvMeshViewer might have left when evaluating a kept tree.
            post_objs = set(bpy.data.objects.keys())
            for name in post_objs - pre_objs - {obj.name}:
                stray = bpy.data.objects.get(name)
                if stray is None or stray is obj:
                    continue
                low = stray.name.lower()
                if low.startswith(('alpha', 'beta', 'gamma', 'delta',
                                    'sverchokmesh', 'sverchokout', 'sverchokedit')):
                    try:
                        bpy.data.objects.remove(stray, do_unlink=True)
                    except Exception:
                        pass

            # v2.42: Weld + smooth-shading pass on the spawned mesh
            if getattr(self, 'sv_weld_after', True) and obj.type == 'MESH':
                try:
                    import bmesh as _bm
                    threshold = getattr(self, 'sv_weld_distance', 0.005)
                    bm_w = _bm.new()
                    bm_w.from_mesh(obj.data)
                    pre = len(bm_w.verts)
                    _bm.ops.remove_doubles(bm_w, verts=bm_w.verts, dist=threshold)
                    _bm.ops.recalc_face_normals(bm_w, faces=bm_w.faces[:])
                    bm_w.to_mesh(obj.data)
                    bm_w.free()
                    post = len(obj.data.vertices)
                    # Smooth shading
                    for poly in obj.data.polygons:
                        poly.use_smooth = True
                    obj.data.update()
                    print(f"[Sverchok] welded {obj.name}: {pre} → {post} verts")
                except Exception as e:
                    print(f"[Sverchok] weld pass failed: {e}")
            # Final selection
            bpy.ops.object.select_all(action='DESELECT')
            obj.select_set(True)
            context.view_layer.objects.active = obj
            self.report({'INFO'}, f"🌀 Sverchok created: {obj.name}")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Sverchok preset failed: {e}")
            import traceback
            traceback.print_exc()
            return {'CANCELLED'}
        finally:
            # NOTE: in v2.26 we PERSIST the dialog values (no restore) so the
            # panel reflects what the user picked. Earlier restore caused the
            # "snap back to preset" complaint.
            _SV_CURRENT_PROPS = None

    # v2.42 FIX-2: real `class` statement so Blender's metaclass picks up
    # annotations the standard way. type()+dict didn't work.
    class _SvOp(bpy.types.Operator):
        bl_idname = op_id
        bl_label = label
        bl_description = f"Spawn the {label} Sverchok preset. Opens a parameter dialog first."
        bl_options = {'REGISTER', 'UNDO'}
        sv_resolution: bpy.props.FloatProperty(name="Resolution", default=1.0, min=0.2, max=4.0,
            description="Mesh density multiplier", update=auto_update_callback)
        sv_scale: bpy.props.FloatProperty(name="Scale", default=1.0, min=0.2, max=5.0,
            description="Overall size multiplier", update=auto_update_callback)
        sv_complexity: bpy.props.FloatProperty(name="Complexity", default=1.0, min=0.3, max=3.0,
            description="Iterations / turns / tile counts", update=auto_update_callback)
        sv_seed: bpy.props.IntProperty(name="Seed", default=42, min=0, max=99999,
            description="Random seed for noisy presets", update=auto_update_callback)
        sv_keep_tree: bpy.props.BoolProperty(name="Keep editable tree", default=True,
            description="Build the Sverchok tree alongside so you can edit it after generation", update=auto_update_callback)
        sv_weld_after: bpy.props.BoolProperty(name="Weld + smooth after spawn", default=True,
            description="Run Merge By Distance + smooth shading on the spawned mesh "
                        "to fix Sverchok's wireframe-island output", update=auto_update_callback)
        sv_weld_distance: bpy.props.FloatProperty(name="Weld Distance",
            default=0.005, min=0.0, max=0.5,
            description="Merge By Distance threshold for the post-spawn weld pass", update=auto_update_callback)
    # Attach factory-closure methods after the class body
    _SvOp.invoke = invoke
    _SvOp.execute = execute
    _SvOp.draw = draw_dialog
    _SvOp.__name__ = class_name
    return _SvOp


# v2.47 NOTE: The module-scope rewrite below was based on a wrong diagnostic —
# the factory pattern ALREADY registers props correctly (verified via
# `bpy.ops.X.get_rna_type().properties`). The earlier "props missing" finding
# was caused by querying the wrong RNA struct. Keeping this class commented
# below so the diff stays visible; the canonical op uses the factory.
class _SURREAL_ARCH_OT_sv_spiral_DEFERRED(bpy.types.Operator):
    """🌀 Escher-style logarithmic ascending spiral tower.
    Computed in pure Python; companion Sverchok tree (if Sverchok installed)
    becomes editable. v2.47 — first module-scope migration."""
    bl_idname = "surreal_arch.sv_spiral"
    bl_label  = "🌀 Spiral Tower"
    bl_options = {'REGISTER', 'UNDO'}

    sv_resolution: bpy.props.FloatProperty(
        name="Resolution", default=1.0, min=0.2, max=4.0,
        description="Mesh density multiplier", update=auto_update_callback)
    sv_scale: bpy.props.FloatProperty(
        name="Scale", default=1.0, min=0.2, max=5.0,
        description="Overall size multiplier", update=auto_update_callback)
    sv_complexity: bpy.props.FloatProperty(
        name="Complexity (turns)", default=1.0, min=0.3, max=4.0,
        description="Number of full spiral turns × complexity", update=auto_update_callback)
    sv_seed: bpy.props.IntProperty(
        name="Seed", default=42, min=0, max=99999, update=auto_update_callback)
    sv_keep_tree: bpy.props.BoolProperty(
        name="Keep editable Sverchok tree", default=True,
        description="Build the Sverchok companion tree alongside so you can "
                    "open the Sverchok editor and tweak nodes after generation", update=auto_update_callback)
    sv_weld_after: bpy.props.BoolProperty(
        name="Weld + smooth after spawn", default=True,
        description="Merge By Distance + smooth shading on the spawned mesh", update=auto_update_callback)
    sv_weld_distance: bpy.props.FloatProperty(
        name="Weld Distance", default=0.005, min=0.0, max=0.5, update=auto_update_callback)

    def invoke(self, context, event):
        # Pre-load defaults from active obj
        active = context.active_object
        if active and hasattr(active, 'surreal_arch_props'):
            p = active.surreal_arch_props
            self.sv_resolution = float(getattr(p, 'sv_resolution', 1.0))
            self.sv_scale      = float(getattr(p, 'sv_scale', 1.0))
            self.sv_complexity = float(getattr(p, 'sv_complexity', 1.0))
            self.sv_seed       = int(getattr(p, 'sv_seed', 42))
            self.sv_keep_tree  = bool(getattr(p, 'sv_keep_tree', True))
        return context.window_manager.invoke_props_dialog(self, width=340)

    def draw(self, context):
        layout = self.layout
        layout.label(text="🌀 Spiral Tower", icon='NODETREE')
        if not _sverchok_available():
            layout.label(text="(Sverchok not installed — Python-only spawn)",
                          icon='INFO')
        col = layout.column(align=True)
        col.prop(self, 'sv_resolution')
        col.prop(self, 'sv_scale')
        col.prop(self, 'sv_complexity')
        col.prop(self, 'sv_seed')
        col.separator()
        col.prop(self, 'sv_keep_tree', icon='NODETREE')
        col.separator()
        col.prop(self, 'sv_weld_after', icon='AUTOMERGE_ON')
        if self.sv_weld_after:
            col.prop(self, 'sv_weld_distance')

    def execute(self, context):
        # Mirror dialog values onto active obj's surreal_arch_props so the
        # spiral generator math reads them via _sv_params().
        global _SV_CURRENT_PROPS
        active = context.active_object
        _SV_CURRENT_PROPS = active.surreal_arch_props if (
            active and hasattr(active, 'surreal_arch_props')) else None
        if _SV_CURRENT_PROPS is not None:
            for k in ('sv_resolution', 'sv_scale', 'sv_complexity',
                      'sv_seed', 'sv_keep_tree'):
                try: setattr(_SV_CURRENT_PROPS, k, getattr(self, k))
                except Exception: pass
        pre_objs = set(bpy.data.objects.keys())
        try:
            obj = sverchok_spiral_tower()
        except Exception as e:
            self.report({'ERROR'}, f"Spiral Tower failed: {e}")
            import traceback; traceback.print_exc()
            _SV_CURRENT_PROPS = None
            return {'CANCELLED'}
        finally:
            pass
        if obj is None:
            self.report({'WARNING'}, "No mesh spawned")
            _SV_CURRENT_PROPS = None
            return {'CANCELLED'}
        # Clean orphan Sverchok bakes (Alpha/Beta/etc.)
        for name in set(bpy.data.objects.keys()) - pre_objs - {obj.name}:
            stray = bpy.data.objects.get(name)
            if stray and stray.name.lower().startswith(
                    ('alpha', 'beta', 'gamma', 'delta',
                     'sverchokmesh', 'sverchokout', 'sverchokedit')):
                try: bpy.data.objects.remove(stray, do_unlink=True)
                except Exception: pass
        # Post-spawn weld + smooth pass
        if self.sv_weld_after and obj.type == 'MESH':
            try:
                import bmesh as _bm
                bm_w = _bm.new()
                bm_w.from_mesh(obj.data)
                pre = len(bm_w.verts)
                _bm.ops.remove_doubles(bm_w, verts=bm_w.verts,
                                       dist=self.sv_weld_distance)
                _bm.ops.recalc_face_normals(bm_w, faces=bm_w.faces[:])
                bm_w.to_mesh(obj.data)
                bm_w.free()
                post = len(obj.data.vertices)
                for poly in obj.data.polygons:
                    poly.use_smooth = True
                obj.data.update()
                print(f"[Sverchok] welded {obj.name}: {pre} → {post} verts")
            except Exception as e:
                print(f"[Sverchok] weld pass failed: {e}")
        # Final selection
        bpy.ops.object.select_all(action='DESELECT')
        obj.select_set(True)
        context.view_layer.objects.active = obj
        sv_note = "" if _sverchok_available() else " (Python-only)"
        self.report({'INFO'}, f"🌀 Spawned {obj.name}{sv_note}")
        _SV_CURRENT_PROPS = None
        return {'FINISHED'}


