# ============================================================
# PROCEDURAL ENVIRONMENT COMPOSER  —  full Dark-Souls/Escher scenes
# Spawns multiple presets with parametric placement & overlap rules
# ============================================================

class SURREAL_ARCH_OT_compose_scene(bpy.types.Operator):
    """Procedurally compose an entire Dark-Souls × Escher gothic ruin scene from a seed."""
    bl_idname = "surreal_arch.compose_scene"
    bl_label  = "🏚 Compose Gothic Ruin Scene"
    bl_options = {'REGISTER', 'UNDO'}

    style: bpy.props.EnumProperty(
        name="Style",
        items=[
            ('DARK_SOULS', "🏚 Dark Souls Ruin", "Crumbled cathedral with twisted spires, chandeliers, scattered tombstones"),
            ('ESCHER',     "🪜 Escher Surreal",  "Möbius staircases, cascading arches, recursive portals"),
            ('GOTHIC_CITY',"🏛 Gothic City",    "Multiple palazzo facades + bridges + radial buildings"),
        ],
        default='DARK_SOULS',
    )
    seed: bpy.props.IntProperty(name="Seed", default=42, min=0, max=9999, update=auto_update_callback)
    density: bpy.props.IntProperty(name="Piece Count", default=12, min=4, max=40, update=auto_update_callback)

    def invoke(self, context, event):
        return context.window_manager.invoke_props_dialog(self)

    def execute(self, context):
        import random, math
        rng = random.Random(self.seed)

        # Make a parent empty for the whole scene
        bpy.ops.object.empty_add(type='PLAIN_AXES', location=(0, 0, 0))
        parent = context.active_object
        parent.name = f"SurrealArch_Scene_{self.style}_{self.seed}"

        # Track placed footprints to avoid overlap
        placed = []  # list of (cx, cy, radius)

        def piece_size(obj):
            """Compute the X/Y/Z extent of an object's mesh in world space."""
            if obj.type != 'MESH' or not obj.data.vertices:
                return (1.0, 1.0, 1.0)
            xs = [v.co.x for v in obj.data.vertices]
            ys = [v.co.y for v in obj.data.vertices]
            zs = [v.co.z for v in obj.data.vertices]
            return (max(xs) - min(xs), max(ys) - min(ys), max(zs) - min(zs))

        def fits(x, y, r, min_gap=0.5):
            """Check if (x,y) with radius r fits without overlapping placed pieces."""
            for px, py, pr in placed:
                d = math.hypot(x - px, y - py)
                if d < (r + pr + min_gap):
                    return False
            return True

        def spawn_sv(op_name):
            """Run a Sverchok op, return the newly-created mesh object (or None)."""
            pre = set(bpy.data.objects.keys())
            try:
                getattr(bpy.ops.surreal_arch, op_name)()
            except Exception:
                return None
            new = list(set(bpy.data.objects.keys()) - pre)
            for n in new:
                o = bpy.data.objects[n]
                if o.type == 'MESH':
                    return o
            return None

        def spawn_gn(op_name):
            """Run a GN preset on a fresh cube. Returns the mesh object."""
            pre = set(bpy.data.objects.keys())
            bpy.ops.mesh.primitive_cube_add(location=(0, 0, 0))
            cube = context.active_object
            try:
                getattr(bpy.ops.surreal_arch, op_name)()
                return cube
            except Exception:
                bpy.data.objects.remove(cube, do_unlink=True)
                return None

        def place(obj, x, y, z, rot_z=0.0, scale=1.0):
            """Position and parent an object after computing its footprint."""
            sx, sy, sz = piece_size(obj)
            footprint_r = max(sx, sy) * scale * 0.5
            obj.location = (x, y, z)
            obj.rotation_euler.z = rot_z
            if scale != 1.0:
                obj.scale = (scale, scale, scale)
            obj.parent = parent
            placed.append((x, y, footprint_r))
            return sx, sy, sz

        if self.style == 'DARK_SOULS':
            # Central twisted spire
            o = spawn_sv("sv_twisted_spire")
            if o: place(o, 0, 0, 0)

            # Branching buttresses flanking the spire (NE/NW/SW/SE)
            for i in range(4):
                ang = i * math.tau / 4 + math.pi / 4
                dist = 4.5
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                if fits(x, y, 1.5):
                    o = spawn_sv("sv_branching_buttress")
                    if o: place(o, x, y, 0, rot_z=ang + math.pi)

            # Cathedral ruin in background — far behind
            o = spawn_sv("sv_cathedral_ruin")
            if o:
                sx, sy, sz = piece_size(o)
                place(o, 0, -12, 0)   # 12m behind, beyond buttresses

            # Tombstones — pointed gothic arches scaled small, scattered
            n_tombs = max(2, int(self.density * 0.35))
            for i in range(n_tombs):
                attempts = 0
                while attempts < 8:
                    ang = rng.uniform(0, math.tau)
                    dist = rng.uniform(6.5, 9.5)
                    x, y = math.cos(ang) * dist, math.sin(ang) * dist
                    if fits(x, y, 0.6):
                        break
                    attempts += 1
                else:
                    continue
                o = spawn_sv("sv_recursive_portal")  # nested gothic arch = stylized gravemark
                if o: place(o, x, y, 0, rot_z=rng.uniform(0, math.tau), scale=0.45)

            # Iron gates at cardinal directions (further out, perimeter)
            for i in range(4):
                ang = i * math.tau / 4 + math.pi / 8
                dist = 10.5
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                o = spawn_sv("sv_iron_gate")
                if o: place(o, x, y, 0, rot_z=ang + math.pi / 2)

            # Hanging chandeliers above the central area (up high)
            for i in range(3):
                ang = (i / 3) * math.tau
                x, y = math.cos(ang) * 2.5, math.sin(ang) * 2.5
                z = 6.5 + rng.uniform(-0.5, 0.5)  # above the spire (~6m tall)
                o = spawn_sv("sv_chandelier")
                if o: place(o, x, y, z)

            # Filigree friezes — decorative bands at ground level
            for i in range(2):
                ang = (math.tau / 2) * i + math.pi / 2
                dist = 8.0
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                o = spawn_sv("sv_trefoil_frieze")
                if o: place(o, x, y, 0.5, rot_z=ang + math.pi / 2)

        elif self.style == 'ESCHER':
            # Möbius stairs at center
            o = spawn_sv("sv_mobius_stairs")
            mobius_size = piece_size(o) if o else (4, 4, 1)
            if o: place(o, 0, 0, 0)
            outer = max(mobius_size[0], mobius_size[1]) * 0.5 + 2  # safe ring radius

            # Recursive portals around the perimeter
            for i in range(3):
                ang = i * math.tau / 3
                dist = outer + 2
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                o = spawn_sv("sv_recursive_portal")
                if o: place(o, x, y, 0, rot_z=ang + math.pi)

            # Cascading arches floating above (Escher-style)
            for i in range(2):
                ang = (math.pi / 4) + i * math.pi
                dist = 3.5
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                z = 5 + i * 1.5
                o = spawn_sv("sv_cascading_arches")
                if o: place(o, x, y, z, rot_z=ang)

            # Twisted spires in distance (outer ring)
            for i in range(4):
                ang = i * math.tau / 4 + math.pi / 4
                dist = outer + 6
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                scale_v = rng.uniform(0.7, 1.2)
                o = spawn_sv("sv_twisted_spire")
                if o: place(o, x, y, 0, scale=scale_v)

            # Möbius companion (rotated 90°, offset)
            o = spawn_sv("sv_mobius_stairs")
            if o: place(o, 0, 0, mobius_size[2] + 0.5, rot_z=math.pi / 2, scale=0.7)

        else:  # GOTHIC_CITY
            # Central rotunda — figure out its footprint first
            o = spawn_sv("sv_twisted_spire")    # central landmark — much smaller than 12m grid
            if o:
                sx, sy, sz = piece_size(o)
                place(o, 0, 0, 0)
                center_r = max(sx, sy) / 2

            # Use sv_gothic_arch or sv_cathedral_ruin as the "palazzo" facade
            # (faster + actually creates fresh mesh objects)
            block_spacing = 14
            for i in range(-1, 2):
                for j in range(-1, 2):
                    if i == 0 and j == 0: continue
                    x, y = i * block_spacing, j * block_spacing
                    o = spawn_sv("sv_cathedral_ruin")
                    if o:
                        # Rotate facades to face center
                        face_ang = math.atan2(-y, -x)
                        place(o, x, y, 0, rot_z=face_ang + math.pi / 2)

            # Bridges connecting some blocks
            for i in range(4):
                ang = i * math.tau / 4
                x = math.cos(ang) * (block_spacing / 2 + 1)
                y = math.sin(ang) * (block_spacing / 2 + 1)
                # Make a "bridge" with cascading arches
                o = spawn_sv("sv_cascading_arches")
                if o: place(o, x, y, 0, rot_z=ang + math.pi / 2)

            # Spires at each corner
            for i in range(4):
                ang = i * math.tau / 4 + math.pi / 4
                dist = block_spacing * 1.3
                x, y = math.cos(ang) * dist, math.sin(ang) * dist
                o = spawn_sv("sv_twisted_spire")
                if o: place(o, x, y, 0, scale=rng.uniform(0.8, 1.1))

        # Re-select parent
        bpy.ops.object.select_all(action='DESELECT')
        parent.select_set(True)
        context.view_layer.objects.active = parent

        n_kids = len([o for o in bpy.data.objects if o.parent == parent])
        self.report({'INFO'}, f"Scene composed: {self.style} (seed {self.seed}) — {n_kids} pieces")
        return {'FINISHED'}


class SURREAL_ARCH_OT_toggle_genshin(bpy.types.Operator):
    """Toggle Genshin-style cel-shading on whatever's currently built."""
    bl_idname = "surreal_arch.toggle_genshin"
    bl_label  = "🎀 Toggle Genshin Style"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        return context.active_object and context.active_object.type == 'MESH'

    def execute(self, context):
        p = context.active_object.surreal_arch_props
        p.genshin_style = not p.genshin_style
        bpy.ops.surreal_arch.generate()
        state = "ON 🎀" if p.genshin_style else "OFF"
        self.report({'INFO'}, f"Genshin style: {state}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_uv_unwrap(bpy.types.Operator):
    """Smart UV Project on the active mesh — use after Apply Modifiers for island unwrap."""
    bl_idname = "surreal_arch.uv_unwrap"
    bl_label  = "🗺 Smart UV Unwrap"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        obj = context.active_object
        return obj and obj.type == 'MESH' and hasattr(obj, 'surreal_arch_props')

    def execute(self, context):
        obj = context.active_object
        props = obj.surreal_arch_props
        old_mode = props.uv_unwrap_mode
        props.uv_unwrap_mode = 'SMART'
        try:
            if apply_smart_uv_unwrap(obj, props, context):
                self.report({'INFO'}, f"Smart UV unwrapped → layer '{props.uv_map_name}'")
                return {'FINISHED'}
            self.report({'WARNING'}, "Smart UV unwrap failed — try Apply Modifiers first")
            return {'CANCELLED'}
        finally:
            props.uv_unwrap_mode = old_mode


class SURREAL_ARCH_OT_export_ue5(bpy.types.Operator):
    """Bake a duplicated copy of the active object as a clean game-ready FBX for Unreal Engine 5."""
    bl_idname = "surreal_arch.export_ue5"
    bl_label  = "🎮 Bake & Export to UE5"
    bl_options = {'REGISTER', 'UNDO'}

    filepath: bpy.props.StringProperty(subtype='FILE_PATH', update=auto_update_callback)

    @classmethod
    def poll(cls, context):
        return context.active_object and context.active_object.type == 'MESH'

    def execute(self, context):
        try:
            src = context.active_object
            # Duplicate so the original keeps its modifier setup
            bpy.ops.object.select_all(action='DESELECT')
            src.select_set(True)
            context.view_layer.objects.active = src
            bpy.ops.object.duplicate(linked=False)
            baked = context.active_object
            baked.name = src.name + "_UE5"

            # Apply ALL modifiers (geometry nodes, bevel, etc.)
            for mod in list(baked.modifiers):
                try:
                    bpy.ops.object.modifier_apply(modifier=mod.name)
                except Exception:
                    baked.modifiers.remove(mod)

            # Smart UV unwrap for game-ready textures (overrides procedural if desired)
            props = src.surreal_arch_props if hasattr(src, 'surreal_arch_props') else None
            if props is not None:
                props.uv_unwrap_mode = 'SMART'
                apply_smart_uv_unwrap(baked, props, context)
            else:
                try:
                    bpy.ops.object.mode_set(mode='EDIT')
                    bpy.ops.mesh.select_all(action='SELECT')
                    bpy.ops.uv.smart_project(angle_limit=math.radians(66), island_margin=0.02)
                    bpy.ops.object.mode_set(mode='OBJECT')
                except Exception:
                    if context.active_object.mode != 'OBJECT':
                        bpy.ops.object.mode_set(mode='OBJECT')

            # Apply scale/rotation so UE5 reads transforms correctly
            try:
                bpy.ops.object.transform_apply(location=False, rotation=True, scale=True)
            except Exception:
                pass

            try:
                from surreal_arch.trim_bake import apply_trim_bake
                if props is not None:
                    import surreal_architecture_gen as _s
                    apply_trim_bake(baked, props, _s)
            except Exception:
                pass

            # Export FBX with UE5-friendly settings
            bpy.ops.export_scene.fbx(
                filepath=self.filepath,
                use_selection=True,
                global_scale=1.0,
                apply_unit_scale=True,
                apply_scale_options='FBX_SCALE_NONE',
                bake_space_transform=False,
                axis_forward='-Z',  # UE5 default
                axis_up='Y',         # UE5 default
                mesh_smooth_type='FACE',
                use_mesh_modifiers=True,
                add_leaf_bones=False,
            )
            try:
                import surreal_architecture_gen as _s
                from surreal_arch.snap_export import write_sidecar_json
                write_sidecar_json(baked, _s, self.filepath)
            except Exception:
                pass
            self.report({'INFO'}, f"UE5 export: {self.filepath} (baked + UV unwrapped + transforms applied)")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"UE5 export failed: {e}")
            import traceback; traceback.print_exc()
            return {'CANCELLED'}

    def invoke(self, context, event):
        self.filepath = (context.active_object.name or "surreal_arch") + "_UE5.fbx"
        context.window_manager.fileselect_add(self)
        return {'RUNNING_MODAL'}


class SURREAL_ARCH_OT_spawn_synthia(bpy.types.Operator):
    """Spawn a Synthia math viz, then apply our edge-bevel + material from the library."""
    bl_idname = "surreal_arch.spawn_synthia"
    bl_label  = "🧮 Spawn Synthia Viz"
    bl_options = {'REGISTER', 'UNDO'}

    @classmethod
    def poll(cls, context):
        # Synthia must be installed
        return hasattr(bpy.ops.synthia, "spawn_preset") or hasattr(bpy.ops.synthia, "custom_formula")

    def execute(self, context):
        scene_objs_before = set(o.name for o in bpy.data.objects)

        active = context.active_object
        props = active.surreal_arch_props if (active and hasattr(active, 'surreal_arch_props')) else None

        # Find a way to access props if not present (use scene's first mesh's props)
        if not props:
            for o in bpy.data.objects:
                if o.type == 'MESH' and hasattr(o, 'surreal_arch_props'):
                    props = o.surreal_arch_props
                    break

        if not props:
            self.report({'ERROR'}, "No mesh object with surreal_arch_props found")
            return {'CANCELLED'}

        try:
            if props.synthia_use_custom:
                bpy.ops.synthia.custom_formula(formula=props.synthia_custom_formula)
            else:
                # Determine preset_type: equation or geometry
                eq_ids = {p[0] for p in SYNTHIA_EQUATION_PRESETS}
                preset_type = 'EQUATION' if props.synthia_preset in eq_ids else 'GEOMETRY'
                bpy.ops.synthia.spawn_preset(preset_name=props.synthia_preset, preset_type=preset_type)
        except Exception as e:
            self.report({'ERROR'}, f"Synthia spawn failed: {e}")
            return {'CANCELLED'}

        # Find the new object Synthia created
        new_objs = [o for o in bpy.data.objects if o.name not in scene_objs_before]
        if not new_objs:
            self.report({'WARNING'}, "Synthia spawned but no new object detected")
            return {'CANCELLED'}

        new_obj = new_objs[-1]

        # Apply our edge bevel modifier on the Synthia object
        if props.synthia_apply_bevel and props.bevel_mode == 'EDGE':
            try:
                apply_edge_bevel_modifier(new_obj, props)
            except Exception:
                pass

        # Apply material
        if props.synthia_apply_material:
            try:
                # Synthia object has its own props (or we use the source props)
                if not hasattr(new_obj, 'surreal_arch_props'):
                    pass  # registration should make it exist
                # Apply material based on source props
                mat = bpy.data.materials.get(MAT_NAMES.get(
                    DEFAULT_MATERIAL_FOR_TYPE.get(props.arch_type, 'STONE')
                    if props.material_choice == 'AUTO'
                    else props.material_choice
                ))
                if not mat:
                    build_shader_library()
                    mat = bpy.data.materials.get(MAT_NAMES.get(
                        DEFAULT_MATERIAL_FOR_TYPE.get(props.arch_type, 'STONE')
                        if props.material_choice == 'AUTO'
                        else props.material_choice
                    ))
                if mat:
                    if new_obj.data.materials:
                        new_obj.data.materials[0] = mat
                    else:
                        new_obj.data.materials.append(mat)
            except Exception:
                pass

        # Make new object active
        bpy.context.view_layer.objects.active = new_obj
        bpy.ops.object.select_all(action='DESELECT')
        new_obj.select_set(True)

        self.report({'INFO'}, f"Synthia: {new_obj.name} spawned + bevel + material applied")
        return {'FINISHED'}


class SURREAL_ARCH_OT_export_fbx(bpy.types.Operator):
    bl_idname = "surreal_arch.export_fbx"
    bl_label  = "Export FBX"
    bl_options = {'REGISTER'}

    filepath: bpy.props.StringProperty(subtype='FILE_PATH', update=auto_update_callback)

    @classmethod
    def poll(cls, context):
        return context.active_object and context.active_object.type == 'MESH'

    def execute(self, context):
        obj = context.active_object
        props = getattr(obj, 'surreal_arch_props', None)
        if props and props.auto_uv_unwrap and props.uv_unwrap_mode == 'SMART':
            apply_smart_uv_unwrap(obj, props, context)
        try:
            bpy.ops.export_scene.fbx(
                filepath=self.filepath,
                use_selection=True,
                global_scale=1.0,
                apply_unit_scale=True,
                apply_scale_options='FBX_SCALE_NONE',
                axis_forward='-Y',
                axis_up='Z',
                mesh_smooth_type='FACE',
            )
            self.report({'INFO'}, f"Exported to {self.filepath}")
            return {'FINISHED'}
        except Exception as e:
            self.report({'ERROR'}, f"Export failed: {e}")
            return {'CANCELLED'}

    def invoke(self, context, event):
        self.filepath = (context.active_object.name or "surreal_arch") + ".fbx"
        context.window_manager.fileselect_add(self)
        return {'RUNNING_MODAL'}


