# v2.44: ROUTE DETECTION — show user which generation route built the object
def _route_for_object(obj):
    """Determine which generation route built the active object."""
    if obj is None: return 'NONE'
    name = obj.name
    # Direct-bmesh / specialty objects
    if name.startswith("SurrealRoof_"): return 'ROOF'
    if name.startswith("Terrain_"):     return 'TERRAIN'
    if name.startswith("SurrealPlan_"): return 'PLAN'
    if name.endswith("_World"):         return 'WORLD'
    if name.endswith("_Pieces") or name.endswith("_Split"): return 'PIECES'
    if name.startswith("_lib_"):        return 'LIBRARY'
    if name.startswith("Tree"):         return 'EASYTREE'
    if name.startswith("_sv_") or 'surreal_sv_tree' in obj.keys() or \
       name.startswith("EscherSpiral") or name.startswith("EscherKnot") or \
       name.startswith("EscherTwisted") or name.startswith("EscherTessellation") or \
       name.startswith("EscherFractal") or name.startswith("EscherTorusKnot"):
        return 'SVERCHOK'
    # Check modifier stack
    has_gn = False
    for m in obj.modifiers:
        if m.name.startswith("Aest_"):    return 'AESTHETIC'
        if m.name.startswith("SciFi_"):   return 'SCIFI'
        if m.name.startswith("SurrealArch") and m.type == 'NODES':
            has_gn = True
    if has_gn:                            return 'GN'
    return 'MESH'


