_ARCH_CATEGORIES_BY_ID = {
    cat_id: (cat_label, cat_icon, items)
    for cat_id, cat_label, cat_icon, items in _ARCH_CATEGORIES
}


def _draw_arch_presets_grouped(layout):
    """v2.60.6 — style-grouped one-click architecture presets from _ARCH_PRESETS."""
    hdr = layout.row(align=True)
    hdr.scale_y = 1.05
    hdr.label(text="Playable Architecture (metres, UE-ready)", icon='HOME')
    intro = layout.row()
    intro.scale_y = 0.92
    intro.label(
        text="Style buckets show typology hints; presets set arch_type + defaults — then Generate.",
        icon='INFO',
    )
    for group_id, group_label, group_icon in _ARCH_PRESET_GROUPS:
        entries = [
            (key, spec) for key, spec in _ARCH_PRESETS.items()
            if spec.get('group') == group_id
        ]
        if not entries:
            continue
        box = layout.box()
        ghdr = box.row(align=True)
        ghdr.scale_y = 1.02
        ghdr.label(text=group_label, icon=_sanitize_ui_icon(group_icon))
        hint = _ARCH_PRESET_GROUP_HINTS.get(group_id, '')
        if hint:
            box.label(text=hint, icon='BLANK1')
        grid = box.grid_flow(row_major=True, columns=2, even_columns=True, align=True)
        for _key, spec in entries:
            cell = grid.column(align=True)
            cell.scale_y = 0.95
            cell.operator(spec['op_id'], text=spec['label'])
            _preset_desc = spec.get('desc') or spec.get('description')
            if _preset_desc:
                desc_row = cell.row()
                desc_row.scale_y = 0.72
                desc_row.enabled = False
                desc_row.label(text=_preset_desc, icon='INFO')


def _draw_style_arch_presets(layout, style_id):
    """Quick-launch playable preset operators for the active style panel."""
    entries = [
        spec for spec in _ARCH_PRESETS.values() if spec.get('group') == style_id.upper()
    ]
    if not entries:
        return
    box = layout.box()
    hdr = box.row(align=True)
    hdr.scale_y = 1.02
    hdr.label(text="Playable presets", icon='PLAY')
    grid = box.grid_flow(row_major=True, columns=1, even_columns=True, align=True)
    for spec in entries:
        cell = grid.column(align=True)
        cell.scale_y = 0.95
        cell.operator(spec['op_id'], text=spec['label'])
        _preset_desc = spec.get('desc') or spec.get('description')
        if _preset_desc:
            desc_row = cell.row()
            desc_row.scale_y = 0.72
            desc_row.enabled = False
            desc_row.label(text=_preset_desc, icon='INFO')
    layout.separator()


class SURREAL_ARCH_OT_set_arch_type(bpy.types.Operator):
    """v2.48: Click-to-set arch_type. Used by the categorized picker so users
    don't have to navigate the 112-item flat dropdown."""
    bl_idname = "surreal_arch.set_arch_type"
    bl_label = "Set Architecture Type"
    bl_options = {'REGISTER', 'UNDO'}

    arch_type: bpy.props.StringProperty()
    auto_generate: bpy.props.BoolProperty(default=False,
        description="If True, run Generate immediately after switching type", update=auto_update_callback)

    def execute(self, context):
        obj = context.active_object
        if obj is None or not hasattr(obj, 'surreal_arch_props'):
            self.report({'WARNING'}, "Select a mesh with surreal_arch_props")
            return {'CANCELLED'}
        try:
            obj.surreal_arch_props.arch_type = self.arch_type
        except TypeError as e:
            self.report({'WARNING'}, f"Unknown arch_type '{self.arch_type}': {e}")
            return {'CANCELLED'}
        if self.auto_generate:
            try:
                bpy.ops.surreal_arch.generate()
            except Exception:
                pass
        self.report({'INFO'}, f"Set arch_type → {self.arch_type}")
        return {'FINISHED'}


class SURREAL_ARCH_PT_arch_picker(_SubPanelBase, bpy.types.Panel):
    """v2.48: Categorized arch-type picker — replaces the flat dropdown
    with style-grouped button grids."""
    bl_label = "🎯 Architecture Picker (by Style)"
    bl_idname = "SURREAL_ARCH_PT_arch_picker"
    bl_order = 1

    def draw(self, context):
        layout = self.layout
        obj = context.active_object
        props = obj.surreal_arch_props if obj else None
        current_at = props.arch_type if props else None
        # Header: current selection + the full dropdown for power users
        head = layout.box()
        head.label(text=f"Active: {current_at or '(none)'}",
                   icon='OUTLINER_OB_MESH')
        if props:
            head.prop(props, "arch_type", text="Or pick from full list")

        # Style-grouped categories (Greybox | Civic | Gothic | Asian | Castle | Experimental)
        for style_id, style_label, cat_ids in _ARCH_PICKER_STYLE_GROUPS:
            style_box = layout.box()
            style_box.label(text=style_label, icon='DOWNARROW_HLT')
            for cat_id in cat_ids:
                cat = _ARCH_CATEGORIES_BY_ID.get(cat_id)
                if not cat:
                    continue
                cat_label, cat_icon, items = cat
                box = style_box.box()
                box.label(text=cat_label, icon=_sanitize_ui_icon(cat_icon))
                grid = box.grid_flow(row_major=True, columns=3,
                                     even_columns=True, even_rows=False, align=True)
                for at_id, at_label in items:
                    is_active = (current_at == at_id)
                    op = grid.operator("surreal_arch.set_arch_type",
                                        text=at_label, depress=is_active)
                    op.arch_type = at_id
                    op.auto_generate = False

        # Quick "Generate Now" button at bottom
        layout.separator()
        gen_row = layout.row(align=True)
        gen_row.scale_y = 1.3
        gen_row.operator("surreal_arch.generate", text="✨ Generate Active Type",
                          icon='SHADERFX')


