STYLE_REGISTRY = _build_style_registry()


def _active_style_for_type(arch_type):
    """Return STYLE_REGISTRY key when arch_type has a dedicated style panel."""
    for sid, spec in STYLE_REGISTRY.items():
        if spec['match'](arch_type):
            return sid
    return None


def _geometry_panel_should_show(arch_type):
    """Hide Geometry when a style panel already owns the param spec."""
    if arch_type not in _ARCH_PARAM_SPEC:
        return True
    return _active_style_for_type(arch_type) is None


