class SURREAL_ARCH_OT_sv_reevaluate(bpy.types.Operator):
    """Force the bound Sverchok tree on the active object to re-evaluate.
    Use after manually editing the tree in the Sverchok editor."""
    bl_idname = "surreal_arch.sv_reevaluate"
    bl_label = "Re-evaluate Bound Tree"
    bl_options = {'REGISTER'}

    def execute(self, context):
        if not _sverchok_available():
            self.report({'ERROR'}, "Sverchok addon not enabled")
            return {'CANCELLED'}
        obj = context.active_object
        if obj is None:
            self.report({'WARNING'}, "No active object")
            return {'CANCELLED'}
        bound = obj.get("surreal_sv_tree")
        if not bound:
            self.report({'WARNING'},
                        "Active object has no bound Sverchok tree — run a preset first")
            return {'CANCELLED'}
        tree = bpy.data.node_groups.get(bound)
        if tree is None:
            self.report({'WARNING'}, f"Bound tree '{bound}' no longer exists in this file")
            return {'CANCELLED'}
        try:
            _sverchok_force_evaluate(tree)
        except Exception as e:
            self.report({'ERROR'}, f"Re-evaluation failed: {e}")
            return {'CANCELLED'}
        self.report({'INFO'}, f"Re-evaluated {bound}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_sv_clean_trees(bpy.types.Operator):
    """Remove `_sv_*` Sverchok node trees no longer referenced by any object,
    and clear dangling `surreal_sv_tree` bindings on objects whose tree is gone."""
    bl_idname = "surreal_arch.sv_clean_trees"
    bl_label = "Clean Stale Sverchok Trees"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        # Collect every tree name still referenced by any object's binding
        bound = set()
        for o in bpy.data.objects:
            n = o.get("surreal_sv_tree")
            if n:
                bound.add(n)
        removed_trees = 0
        for tree in list(bpy.data.node_groups):
            if not tree.name.startswith('_sv_'):
                continue
            if getattr(tree, 'bl_idname', '') != 'SverchCustomTreeType':
                continue
            # Remove if both (a) no Blender datablock users AND (b) no
            # custom-property binding points to it
            if tree.users == 0 and tree.name not in bound:
                bpy.data.node_groups.remove(tree)
                removed_trees += 1
        # Clean dangling bindings on objects whose tree is gone
        cleared = 0
        for o in bpy.data.objects:
            n = o.get("surreal_sv_tree")
            if n and n not in bpy.data.node_groups:
                try:
                    del o["surreal_sv_tree"]
                    cleared += 1
                except Exception:
                    pass
        self.report({'INFO'},
                    f"Removed {removed_trees} stale tree(s); cleared {cleared} dangling binding(s)")
        return {'FINISHED'}


