class SURREAL_ARCH_OT_higgsas_load_arch(bpy.types.Operator):
    """Pre-load the 20+ most useful Higgsas node groups for architecture.
    They get appended from the library into the current file so every
    subsequent build that supports Higgsas runs faster (no disk I/O)."""
    bl_idname  = "surreal_arch.higgsas_load_arch"
    bl_label   = "Load Architecture Nodes"
    bl_options = {'REGISTER'}

    def execute(self, context):
        import os
        if not os.path.exists(_HIGGSAS_LIB_PATH):
            self.report({'ERROR'}, f"Higgsas library not found:\n{_HIGGSAS_LIB_PATH}")
            return {'CANCELLED'}
        loaded, skipped = [], []
        for name in _HIGGSAS_ARCH_NODES:
            ng = _higg_load(name)
            if ng is not None:
                loaded.append(name)
            else:
                skipped.append(name)
        msg = f"Loaded {len(loaded)} nodes"
        if skipped:
            msg += f" | Not found: {', '.join(skipped[:3])}"
            if len(skipped) > 3: msg += f" +{len(skipped)-3}"
        self.report({'INFO'}, msg)
        return {'FINISHED'}


class SURREAL_ARCH_OT_higgsas_apply_bricks(bpy.types.Operator):
    """Add a NTBricks Grid node group to the active object's Geometry Nodes modifier.
    The brick pattern is inserted AFTER the existing GN tree output so it
    overlays surface detail without replacing the architecture geometry."""
    bl_idname  = "surreal_arch.higgsas_apply_bricks"
    bl_label   = "Add Brick Surface"
    bl_options = {'REGISTER', 'UNDO'}

    def execute(self, context):
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            self.report({'WARNING'}, "Select a mesh object first"); return {'CANCELLED'}
        ng = _higg_load('NTBricks Grid')
        if ng is None:
            self.report({'ERROR'}, "NTBricks Grid not found — load Higgsas first"); return {'CANCELLED'}
        # Add a new GN modifier on the object
        mod = obj.modifiers.new(name="SurrealBrickDetail", type='NODES')
        tree = bpy.data.node_groups.new(name="_surreal_bricks_detail",
                                        type='GeometryNodeTree')
        mod.node_group = tree
        # In/Out
        in_n  = tree.nodes.new('NodeGroupInput');  in_n.location  = (-400, 0)
        out_n = tree.nodes.new('NodeGroupOutput'); out_n.location = (800, 0)
        try:
            tree.interface.new_socket('Geometry', in_out='INPUT',  socket_type='NodeSocketGeometry')
            tree.interface.new_socket('Geometry', in_out='OUTPUT', socket_type='NodeSocketGeometry')
        except Exception:
            pass
        # NTBricks Grid node
        bricks = tree.nodes.new('GeometryNodeGroup'); bricks.node_tree = ng
        bricks.location = (0, 0)
        try:
            bricks.inputs['X Grid Size'].default_value = 4.0
            bricks.inputs['Y Grid Size'].default_value = 3.0
        except Exception: pass
        # Join with pass-through
        join = tree.nodes.new('GeometryNodeJoinGeometry'); join.location = (400, 0)
        try:
            tree.links.new(in_n.outputs['Geometry'], join.inputs['Geometry'])
            tree.links.new(bricks.outputs[0],        join.inputs['Geometry'])
            tree.links.new(join.outputs['Geometry'], out_n.inputs['Geometry'])
        except Exception: pass
        self.report({'INFO'}, "Brick surface detail added as modifier")
        return {'FINISHED'}


class SURREAL_ARCH_PT_higgsas(_SubPanelBase, bpy.types.Panel):
    """🔌 Higgsas Geo Nodes integration status + quick-load panel."""
    bl_label   = "🔌  Higgsas Geo Nodes"
    bl_idname  = "SURREAL_ARCH_PT_higgsas"

    def draw(self, context):
        layout = self.layout
        import os

        # ── Status header ───────────────────────────────────────────────
        sb = layout.box()
        row = sb.row(align=True)
        lib_exists = os.path.exists(_HIGGSAS_LIB_PATH)
        ng_loaded  = sum(1 for ng in bpy.data.node_groups
                         if ng.name.startswith('NT') and len(ng.name) > 4)

        if lib_exists:
            row.label(text=f"✅  Library found  ({ng_loaded} groups loaded)", icon='CHECKMARK')
        else:
            row.label(text="❌  Library not found at registered path", icon='ERROR')
            sb.alert = True
            sb.label(text=_HIGGSAS_LIB_PATH[:60] + "…")

        # ── Load all arch nodes ─────────────────────────────────────────
        box = layout.box(); box.label(text="⚡ Quick Load")
        col = box.column(align=True); col.scale_y = 1.3
        col.operator("surreal_arch.higgsas_load_arch",
                     text="📦  Load Architecture Nodes  (first-time setup)",
                     icon='NODETREE')
        col.label(text=f"Loads: {len(_HIGGSAS_ARCH_NODES)} node groups for architecture")

        # ── Surface detail operators ───────────────────────────────────
        box = layout.box(); box.label(text="🎨 Surface Detail (adds modifier)")
        col = box.column(align=True); col.scale_y = 1.2
        col.operator("surreal_arch.higgsas_apply_bricks",  text="🧱  Brick Surface  (NTBricks Grid)")

