class SURREAL_ARCH_OT_magic_clear(bpy.types.Operator):
    """Remove all Magic_ modifiers from active object."""
    bl_idname="surreal_arch.magic_clear"; bl_label="🗑 Clear Magic"; bl_options={'REGISTER','UNDO'}
    def execute(self,context):
        o=context.active_object
        if o and o.type=='MESH':
            for m in[mod for mod in o.modifiers if mod.name.startswith("Magic_")]:
                o.modifiers.remove(m)
        return {'FINISHED'}


# ======================================================================
# BEVEL ADD-ON INTEGRATION
# ======================================================================

def _apply_bevel_addon(obj, props):
    for m in[mod for mod in obj.modifiers if mod.name=="SurrealBevel"]:
        obj.modifiers.remove(m)
    if props.bevel_mode=='NONE': return
    if props.bevel_mode=='SUBDIV':
        mod=obj.modifiers.new(name="SurrealBevel",type='SUBSURF')
        mod.levels=max(1,props.bevel_subdiv_level); return
    mod=obj.modifiers.new(name="SurrealBevel",type='BEVEL')
    mod.width=props.bevel_amount
    mod.segments=max(1,props.bevel_subdiv_level)
    mod.limit_method='ANGLE'
    mod.angle_limit=math.radians(props.bevel_angle_deg)
    mod.loop_slide=props.bevel_loop_slide
    mod.use_clamp_overlap=props.bevel_clamp_overlap
    mod.harden_normals=props.bevel_harden_normals
    mod.material=max(-1,props.bevel_material_index)
    mod.miter_outer=props.bevel_miter_outer
    mod.miter_inner=props.bevel_miter_inner
    mod.spread=props.bevel_spread
    try:
        mod.vertex_only=props.bevel_vertex_only
    except (AttributeError, TypeError):
        pass
    ptype=props.bevel_profile_type
    try:
        if ptype=='CHAMFER':
            mod.profile_type='SUPERELLIPSE'; mod.profile=0.0
        elif ptype=='CONCAVE':
            mod.profile_type='SUPERELLIPSE'; mod.profile=props.bevel_profile_value*0.4
        elif ptype=='CONVEX':
            mod.profile_type='SUPERELLIPSE'; mod.profile=0.5+props.bevel_profile_value*0.5
        elif ptype=='CUSTOM':
            mod.profile_type='CUSTOM'
        else:
            mod.profile_type='SUPERELLIPSE'; mod.profile=props.bevel_profile_value
    except Exception:
        pass  # fallback if profile_type attr differs in this Blender build
    if props.bevel_smart_mode:
        import bmesh as _bmb
        bm3=_bmb.new(); bm3.from_mesh(obj.data)
        sharp_ang=math.radians(props.bevel_angle_deg)
        for edge in bm3.edges:
            if edge.is_manifold and len(edge.link_faces)==2:
                dot=edge.link_faces[0].normal.dot(edge.link_faces[1].normal)
                angle=math.acos(max(-1.0,min(1.0,dot)))
                edge.smooth=(angle<sharp_ang)
        bm3.to_mesh(obj.data); bm3.free(); obj.data.update()


class SURREAL_ARCH_OT_apply_bevel_addon(bpy.types.Operator):
    """Apply full-featured Bevel modifier (profile, miters, smart edge detection)."""
    bl_idname="surreal_arch.apply_bevel_addon"
    bl_label ="🔪 Apply Bevel (Full)"
    bl_options={'REGISTER','UNDO'}
    def execute(self,context):
        obj=context.active_object
        if not obj or obj.type!='MESH':
            self.report({'WARNING'},"Select a mesh object."); return {'CANCELLED'}
        _apply_bevel_addon(obj,obj.surreal_arch_props); return {'FINISHED'}


