def _apply_aesthetic_preset(context, preset_key):
    """Apply a preset dict to active object's surreal_arch_props and regenerate."""
    obj = context.active_object
    if obj is None or obj.type != 'MESH':
        # auto-create a base mesh if none selected
        bpy.ops.mesh.primitive_cube_add(size=2.0)
        obj = context.active_object
    if not hasattr(obj, 'surreal_arch_props'):
        return False
    p = obj.surreal_arch_props
    overrides = AESTHETIC_PRESETS.get(preset_key, {})
    # Suppress auto-update flood while we set many props
    global _AUTO_UPDATE_RUNNING
    _AUTO_UPDATE_RUNNING = True
    try:
        for k, v in overrides.items():
            if hasattr(p, k):
                try:
                    setattr(p, k, v)
                except Exception:
                    pass
    finally:
        _AUTO_UPDATE_RUNNING = False
    # Now regenerate explicitly
    try:
        bpy.ops.surreal_arch.generate()
    except Exception:
        pass
    # Apply sci-fi effect if preset specified one
    if 'scifi_effect' in overrides:
        try:
            bpy.ops.surreal_arch.scifi_apply()
        except Exception:
            pass
    return True


class SURREAL_ARCH_OT_aesthetic_preset(bpy.types.Operator):
    bl_idname = "surreal_arch.aesthetic_preset"
    bl_label = "Apply Aesthetic Preset"
    bl_description = "Apply a curated one-click aesthetic preset to the active object"
    bl_options = {'REGISTER', 'UNDO'}

    preset: bpy.props.StringProperty(default='MIAMI_SUNSET', update=auto_update_callback)

    def execute(self, context):
        ok = _apply_aesthetic_preset(context, self.preset)
        if ok:
            self.report({'INFO'}, f"Applied preset: {self.preset}")
        else:
            self.report({'WARNING'}, f"Could not apply preset: {self.preset}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_aesthetic_random(bpy.types.Operator):
    bl_idname = "surreal_arch.aesthetic_random"
    bl_label = "🎲 Random Aesthetic"
    bl_description = "Apply a random aesthetic preset from the entire library"
    bl_options = {'REGISTER', 'UNDO'}

    category: bpy.props.StringProperty(default='ALL', update=auto_update_callback)

    def execute(self, context):
        import random
        if self.category == 'ALL':
            keys = list(AESTHETIC_PRESETS.keys())
        else:
            keys = [k for k in AESTHETIC_PRESETS.keys()
                    if k in _AESTHETIC_GROUPS.get(self.category, [])]
        if not keys:
            return {'CANCELLED'}
        chosen = random.choice(keys)
        _apply_aesthetic_preset(context, chosen)
        self.report({'INFO'}, f"🎲 {chosen}")
        return {'FINISHED'}


