def _apply_escher_preset(context, preset_key):
    """Apply one Escher preset. Dispatches by 'route'."""
    global _AUTO_UPDATE_RUNNING
    spec = ESCHER_PRESETS.get(preset_key)
    if spec is None:
        return False, f"Unknown preset {preset_key}"
    route = spec.get('route', 'GN')
    params = spec.get('params', {})
    if route == 'GN':
        # Need an active mesh; auto-create one if none
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            bpy.ops.mesh.primitive_cube_add(size=2.0)
            obj = context.active_object
        if not hasattr(obj, 'surreal_arch_props'):
            return False, "Object missing surreal_arch_props"
        p = obj.surreal_arch_props
        _AUTO_UPDATE_RUNNING = True
        try:
            for k, v in params.items():
                try: setattr(p, k, v)
                except Exception: pass
        finally:
            _AUTO_UPDATE_RUNNING = False
        try:
            bpy.ops.surreal_arch.generate()
        except Exception as e:
            return False, f"Generate failed: {e}"
        return True, f"GN preset {preset_key} → {p.arch_type}"
    elif route == 'SV':
        # Set sv_* props on the active object FIRST so the Sverchok op picks
        # them up via _SV_CURRENT_PROPS, THEN call the op
        obj = context.active_object
        if obj is None or obj.type != 'MESH':
            bpy.ops.mesh.primitive_cube_add(size=1.0)
            obj = context.active_object
        if hasattr(obj, 'surreal_arch_props'):
            p = obj.surreal_arch_props
            _AUTO_UPDATE_RUNNING = True
            try:
                for k, v in params.items():
                    try: setattr(p, k, v)
                    except Exception: pass
            finally:
                _AUTO_UPDATE_RUNNING = False
        # Call the SV operator by id. We've already set the sv_* props on
        # the active object — the operator's execute() reads them via
        # _SV_CURRENT_PROPS, so no kwargs are needed (and the op's transient
        # dialog props are different names anyway).
        op_id = spec.get('sv_op')
        if not op_id:
            return False, f"SV preset {preset_key} missing sv_op"
        cat, opname = op_id.split('.')
        try:
            op_cat = getattr(bpy.ops, cat)
            op_fn = getattr(op_cat, opname)
            # EXEC_DEFAULT bypasses the parameter dialog
            op_fn('EXEC_DEFAULT')
        except Exception as e:
            return False, f"SV op '{op_id}' failed: {e}"
        return True, f"SV preset {preset_key}"
    return False, f"Unknown route {route}"


class SURREAL_ARCH_OT_escher_preset(bpy.types.Operator):
    """Apply one M.C. Escher preset. Dispatches between GN-arch_type and
    Sverchok-spawn routes depending on the preset definition."""
    bl_idname = "surreal_arch.escher_preset"
    bl_label = "Apply Escher Preset"
    bl_options = {'REGISTER', 'UNDO'}

    preset: bpy.props.StringProperty(default='PENROSE_STAIRS', update=auto_update_callback)

    def execute(self, context):
        ok, msg = _apply_escher_preset(context, self.preset)
        if ok:
            self.report({'INFO'}, f"🪜 {msg}")
        else:
            self.report({'WARNING'}, f"❌ {msg}")
        return {'FINISHED'}


class SURREAL_ARCH_OT_escher_random(bpy.types.Operator):
    """Pick a random Escher preset and apply it."""
    bl_idname = "surreal_arch.escher_random"
    bl_label = "🎲 Random Escher"
    bl_options = {'REGISTER', 'UNDO'}

    category: bpy.props.StringProperty(default='ALL', update=auto_update_callback)

    def execute(self, context):
        import random
        if self.category == 'ALL':
            keys = list(ESCHER_PRESETS.keys())
        else:
            keys = [k for k, _ in _ESCHER_GROUPS.get(self.category, [])]
        if not keys:
            return {'CANCELLED'}
        chosen = random.choice(keys)
        ok, msg = _apply_escher_preset(context, chosen)
        self.report({'INFO' if ok else 'WARNING'}, f"🎲 {chosen}: {msg}")
        return {'FINISHED'}


class SURREAL_ARCH_PT_escher(_EffectsSubPanelBase, bpy.types.Panel):
    """🪝 M.C. Escher Presets — impossible architecture, topology,
    tessellation, hyperbolic, and Sverchok algorithmic spawns."""
    bl_label = "🪜 M.C. Escher Presets"
    bl_idname = "SURREAL_ARCH_PT_escher"
    bl_order = 4

    def draw(self, context):
        layout = self.layout
        layout.label(text="Impossible architecture, topology,",
                     icon='SETTINGS')
        layout.label(text="tessellation, hyperbolic, Sverchok.")

        # Random row
        row = layout.row(align=True)
        row.scale_y = 1.15
        op = row.operator("surreal_arch.escher_random", text="🎲 Random Escher")
        op.category = 'ALL'

        # Category specs
        cat_specs = [
            ('IMPOSSIBLE',   "🪜 Impossible Architecture"),
            ('TOPOLOGY',     "♾ Topology / Non-Orientable"),
            ('TESSELLATION', "🐦 Tessellation"),
            ('HYPERBOLIC',   "🌐 Hyperbolic + Fractal"),
            ('SVERCHOK',     "🌀 Sverchok Algorithmic"),
        ]
        for cat_key, cat_label in cat_specs:
            box = layout.box()
            head = box.row(align=True)
            head.label(text=cat_label)
            rrand = head.operator("surreal_arch.escher_random",
                                   text="", icon='FILE_REFRESH')
            rrand.category = cat_key
            grid = box.grid_flow(row_major=True, columns=2,
                                  even_columns=True, align=True)
            for preset_key, label in _ESCHER_GROUPS[cat_key]:
                op = grid.operator("surreal_arch.escher_preset", text=label)
                op.preset = preset_key


class SURREAL_ARCH_PT_aesthetic_presets(_SubPanelBase, bpy.types.Panel):
    bl_label = "🎨 Aesthetic Presets"
    bl_idname = "SURREAL_ARCH_PT_aesthetic_presets"

    def draw(self, context):
        layout = self.layout
        layout.label(text="One-click curated vibes:", icon='COLOR')

        # Random row up top
        row = layout.row(align=True)
        op = row.operator("surreal_arch.aesthetic_random", text="🎲 Random (Any)")
        op.category = 'ALL'

        # Each category as a box of buttons
        category_specs = [
            ('VAPORWAVE', "🌴 Vaporwave",   (0.95, 0.75, 0.95)),
            ('ZEN',       "⛩ Zen",         (0.80, 0.95, 0.85)),
            ('GOTHIC',    "🦇 Gothic",      (0.55, 0.50, 0.65)),
            ('ELDRITCH',  "👁 Otherworldly",(0.75, 0.70, 0.95)),
            ('CRAZY',     "🔥 Go Crazy",    (1.00, 0.80, 0.70)),
        ]
        for cat_key, cat_label, _tint in category_specs:
            box = layout.box()
            head = box.row(align=True)
            head.label(text=cat_label)
            rop = head.operator("surreal_arch.aesthetic_random", text="", icon='FILE_REFRESH')
            rop.category = cat_key
            grid = box.grid_flow(row_major=True, columns=2, even_columns=True,
                                 even_rows=False, align=True)
            for preset_key, label in _AESTHETIC_GROUPS[cat_key]:
                op = grid.operator("surreal_arch.aesthetic_preset", text=label)
                op.preset = preset_key


