def register():
    for cls in classes:
        bpy.utils.register_class(cls)
    bpy.types.Object.surreal_arch_props = bpy.props.PointerProperty(type=SurrealArchProperties)
    try:
        from surreal_arch.integration import register_overhaul
        import sys as _sys
        register_overhaul(_sys.modules[__name__])
    except Exception as _ov_err:
        print(f"[Surreal Architecture] Overhaul package not loaded: {_ov_err}")
    # Ensure snap/trim hooks are applied even after module reloads.
    try:
        from surreal_arch.integration import patch_monolith as _patch_monolith
        _patch_monolith(_sys.modules[__name__])
    except Exception:
        pass
    print(f"[Surreal Architecture Generator {_bl_version_string()}] Registered — UI search, Gothic/Romanesque kit, snap overlay")


def unregister():
    try:
        from surreal_arch.integration import unregister_overhaul
        unregister_overhaul()
    except Exception:
        pass
    if hasattr(bpy.types.Object, 'surreal_arch_props'):
        del bpy.types.Object.surreal_arch_props
    for cls in reversed(classes):
        try:
            bpy.utils.unregister_class(cls)
        except RuntimeError:
            pass


if __name__ == "__main__":
    register()



